static bool GetQueryResult(PGconn *conn, const char *progname) {
  PGresult *result;
  SetCancelConn(conn);
  while ((result = PQgetResult(conn)) != NULL) {
    if (PQresultStatus(result) != PGRES_COMMAND_OK) {
      char *sqlState = PQresultErrorField(result, PG_DIAG_SQLSTATE);
      fprintf(stderr, _("%s: vacuuming of database \"%s\" failed: %s"),
              progname, PQdb(conn), PQerrorMessage(conn));
      if (sqlState && strcmp(sqlState, ERRCODE_UNDEFINED_TABLE) != 0) {
        PQclear(result);
        return false;
      }
    }
    PQclear(result);
  }
  ResetCancelConn();
  return true;
}

static int string_num_dots(const char *s) {
  int count = 0;
  while ((s = strchr(s, '.'))) {
    s++;
    count++;
  }
  return count;
}

static int rv30_decode_mb_info(RV34DecContext *r) {
  static const int rv30_p_types[6] = {
      RV34_MB_SKIP, RV34_MB_P_16x16,    RV34_MB_P_8x8,
      -1,           RV34_MB_TYPE_INTRA, RV34_MB_TYPE_INTRA16x16};
  static const int rv30_b_types[6] = {
      RV34_MB_SKIP,       RV34_MB_B_DIRECT,   RV34_MB_B_FORWARD,
      RV34_MB_B_BACKWARD, RV34_MB_TYPE_INTRA, RV34_MB_TYPE_INTRA16x16};
  MpegEncContext *s = &r->s;
  GetBitContext *gb = &s->gb;
  unsigned code = svq3_get_ue_golomb(gb);
  if (code > 11) {
    av_log(s->avctx, AV_LOG_ERROR, "Incorrect MB type code\n");
    return -1;
  }
  if (code > 5) {
    av_log(s->avctx, AV_LOG_ERROR, "dquant needed\n");
    code -= 6;
  }
  if (s->pict_type != AV_PICTURE_TYPE_B)
    return rv30_p_types[code];
  else
    return rv30_b_types[code];
}

static int calculate_bitrate(AVFormatContext *s) {
  AVIContext *avi = s->priv_data;
  int i, j;
  int64_t lensum = 0;
  int64_t maxpos = 0;
  for (i = 0; i < s->nb_streams; i++) {
    int64_t len = 0;
    AVStream *st = s->streams[i];
    if (!st->nb_index_entries)
      continue;
    for (j = 0; j < st->nb_index_entries; j++)
      len += st->index_entries[j].size;
    maxpos = FFMAX(maxpos, st->index_entries[j - 1].pos);
    lensum += len;
  }
  if (maxpos < avi->io_fsize * 9 / 10)
    return 0;
  if (lensum * 9 / 10 > maxpos || lensum < maxpos * 9 / 10)
    return 0;
  for (i = 0; i < s->nb_streams; i++) {
    int64_t len = 0;
    AVStream *st = s->streams[i];
    int64_t duration;
    int64_t bitrate;
    for (j = 0; j < st->nb_index_entries; j++)
      len += st->index_entries[j].size;
    if (st->nb_index_entries < 2 || st->codecpar->bit_rate > 0)
      continue;
    duration =
        st->index_entries[j - 1].timestamp - st->index_entries[0].timestamp;
    bitrate =
        av_rescale(8 * len, st->time_base.den, duration * st->time_base.num);
    if (bitrate <= INT_MAX && bitrate > 0) {
      st->codecpar->bit_rate = bitrate;
    }
  }
  return 1;
}

