  vpx_free(cpi->pc_tree);
  CHECK_MEM_ERROR(cm, cpi->pc_tree,
                  vpx_calloc(tree_nodes, sizeof(*cpi->pc_tree)));
  this_pc = &cpi->pc_tree[0];
  this_leaf = &cpi->leaf_tree[0];
  for (i = 0; i < leaf_nodes; ++i)
    alloc_mode_context(cm, 1, &cpi->leaf_tree[i]);
  for (pc_tree_index = 0; pc_tree_index < leaf_nodes; ++pc_tree_index) {
    PC_TREE *const tree = &cpi->pc_tree[pc_tree_index];
    tree->block_size = square[0];
    alloc_tree_contexts(cm, tree, 4);
    tree->leaf_split[0] = this_leaf++;
    for (j = 1; j < 4; j++)
      tree->leaf_split[j] = tree->leaf_split[0];
  }
  for (nodes = 16; nodes > 0; nodes >>= 2) {
    for (i = 0; i < nodes; ++i) {
      PC_TREE *const tree = &cpi->pc_tree[pc_tree_index];
      alloc_tree_contexts(cm, tree, 4 << (2 * square_index));
      tree->block_size = square[square_index];
      for (j = 0; j < 4; j++)
        tree->split[j] = this_pc++;
      ++pc_tree_index;
    }
    ++square_index;
  }
  cpi->pc_root = &cpi->pc_tree[tree_nodes - 1];
  cpi->pc_root[0].none.best_mode_index = 2;
}

int ehci_create_ich9_with_companions(PCIBus *bus, int slot) {
  const struct ehci_companions *comp;
  PCIDevice *ehci, *uhci;
  BusState *usbbus;
  const char *name;
  int i;
  switch (slot) {
  case 0x1d:
    name = "ich9-usb-ehci1";
    comp = ich9_1d;
    break;
  case 0x1a:
    name = "ich9-usb-ehci2";
    comp = ich9_1a;
    break;
  default:
    return -1;
  }
  ehci = pci_create_multifunction(bus, PCI_DEVFN(slot, 7), true, name);
  qdev_init_nofail(&ehci->qdev);
  usbbus = QLIST_FIRST(&ehci->qdev.child_bus);
  for (i = 0; i < 3; i++) {
    uhci = pci_create_multifunction(bus, PCI_DEVFN(slot, comp[i].func), true,
                                    comp[i].name);
    qdev_prop_set_string(&uhci->qdev, "masterbus", usbbus->name);
    qdev_prop_set_uint32(&uhci->qdev, "firstport", comp[i].port);
    qdev_init_nofail(&uhci->qdev);
  }
  return 0;
}

static void dumptype42(FILE *type42, struct alltabs *at,
                       enum fontformat format) {
  FILE *temp = tmpfile();
  struct hexout hexout;
  int i, length;
  dumpttf(temp, at);
  rewind(temp);
  hexout.type42 = type42;
  hexout.bytesout = 0;
  qsort(at->tabdir.ordered, at->tabdir.numtab, sizeof(struct taboff *), tcomp2);
  dumphex(&hexout, temp, at->tabdir.ordered[0]->offset);
  for (i = 0; i < at->tabdir.numtab; ++i) {
    if (at->tabdir.ordered[i]->length > 65534 &&
        at->tabdir.ordered[i]->tag == CHR('g', 'l', 'y', 'f')) {
      uint32 last = 0;
      int j;
      fseek(temp, at->tabdir.ordered[i]->offset, SEEK_SET);
      for (j = 0; j < at->maxp.numGlyphs; ++j) {
        if (at->gi.loca[j + 1] - last > 65534) {
          dumphex(&hexout, temp, at->gi.loca[j] - last);
          last = at->gi.loca[j];
        }
      }
      dumphex(&hexout, temp, at->gi.loca[j] - last);
    } else {
      if (i < at->tabdir.numtab - 1)
        length =
            at->tabdir.ordered[i + 1]->offset - at->tabdir.ordered[i]->offset;
      else {
        fseek(temp, 0, SEEK_END);
        length = ftell(temp) - at->tabdir.ordered[i]->offset;
      }
      fseek(temp, at->tabdir.ordered[i]->offset, SEEK_SET);
      dumphex(&hexout, temp, length);
    }
  }
  fclose(temp);
}

static TRBCCode xhci_configure_slot(XHCIState *xhci, unsigned int slotid,
                                    uint64_t pictx, bool dc) {
  dma_addr_t ictx, octx;
  uint32_t ictl_ctx[2];
  uint32_t slot_ctx[4];
  uint32_t islot_ctx[4];
  uint32_t ep_ctx[5];
  int i;
  TRBCCode res;
  trace_usb_xhci_slot_configure(slotid);
  assert(slotid >= 1 && slotid <= xhci->numslots);
  ictx = xhci_mask64(pictx);
  octx = xhci->slots[slotid - 1].ctx;
  DPRINTF("xhci: input context at " DMA_ADDR_FMT "\n", ictx);
  DPRINTF("xhci: output context at " DMA_ADDR_FMT "\n", octx);
  if (dc) {
    for (i = 2; i <= 31; i++) {
      if (xhci->slots[slotid - 1].eps[i - 1]) {
        xhci_disable_ep(xhci, slotid, i);
      }
    }
    xhci_dma_read_u32s(xhci, octx, slot_ctx, sizeof(slot_ctx));
    slot_ctx[3] &= ~(SLOT_STATE_MASK << SLOT_STATE_SHIFT);
    slot_ctx[3] |= SLOT_ADDRESSED << SLOT_STATE_SHIFT;
    DPRINTF("xhci: output slot context: %08x %08x %08x %08x\n", slot_ctx[0],
            slot_ctx[1], slot_ctx[2], slot_ctx[3]);
    xhci_dma_write_u32s(xhci, octx, slot_ctx, sizeof(slot_ctx));
    return CC_SUCCESS;
  }
  xhci_dma_read_u32s(xhci, ictx, ictl_ctx, sizeof(ictl_ctx));
  if ((ictl_ctx[0] & 0x3) != 0x0 || (ictl_ctx[1] & 0x3) != 0x1) {
    DPRINTF("xhci: invalid input context control %08x %08x\n", ictl_ctx[0],
            ictl_ctx[1]);
    return CC_TRB_ERROR;
  }
  xhci_dma_read_u32s(xhci, ictx + 32, islot_ctx, sizeof(islot_ctx));
  xhci_dma_read_u32s(xhci, octx, slot_ctx, sizeof(slot_ctx));
  if (SLOT_STATE(slot_ctx[3]) < SLOT_ADDRESSED) {
    DPRINTF("xhci: invalid slot state %08x\n", slot_ctx[3]);
    return CC_CONTEXT_STATE_ERROR;
  }
  xhci_free_device_streams(xhci, slotid, ictl_ctx[0] | ictl_ctx[1]);
  for (i = 2; i <= 31; i++) {
    if (ictl_ctx[0] & (1 << i)) {
      xhci_disable_ep(xhci, slotid, i);
    }
    if (ictl_ctx[1] & (1 << i)) {
      xhci_dma_read_u32s(xhci, ictx + 32 + (32 * i), ep_ctx, sizeof(ep_ctx));
      DPRINTF("xhci: input ep%d.%d context: %08x %08x %08x %08x %08x\n", i / 2,
              i % 2, ep_ctx[0], ep_ctx[1], ep_ctx[2], ep_ctx[3], ep_ctx[4]);
      xhci_disable_ep(xhci, slotid, i);
      res = xhci_enable_ep(xhci, slotid, i, octx + (32 * i), ep_ctx);
      if (res != CC_SUCCESS) {
        return res;
      }
      DPRINTF("xhci: output ep%d.%d context: %08x %08x %08x %08x %08x\n", i / 2,
              i % 2, ep_ctx[0], ep_ctx[1], ep_ctx[2], ep_ctx[3], ep_ctx[4]);
      xhci_dma_write_u32s(xhci, octx + (32 * i), ep_ctx, sizeof(ep_ctx));
    }
  }
  res = xhci_alloc_device_streams(xhci, slotid, ictl_ctx[1]);
  if (res != CC_SUCCESS) {
    for (i = 2; i <= 31; i++) {
      if (ictl_ctx[1] & (1u << i)) {
        xhci_disable_ep(xhci, slotid, i);
      }
    }
    return res;
  }
  slot_ctx[3] &= ~(SLOT_STATE_MASK << SLOT_STATE_SHIFT);
  slot_ctx[3] |= SLOT_CONFIGURED << SLOT_STATE_SHIFT;
  slot_ctx[0] &= ~(SLOT_CONTEXT_ENTRIES_MASK << SLOT_CONTEXT_ENTRIES_SHIFT);
  slot_ctx[0] |=
      islot_ctx[0] & (SLOT_CONTEXT_ENTRIES_MASK << SLOT_CONTEXT_ENTRIES_SHIFT);
  DPRINTF("xhci: output slot context: %08x %08x %08x %08x\n", slot_ctx[0],
          slot_ctx[1], slot_ctx[2], slot_ctx[3]);
  xhci_dma_write_u32s(xhci, octx, slot_ctx, sizeof(slot_ctx));
  return CC_SUCCESS;
}

void PNGAPI png_set_sPLT(png_structp png_ptr, png_infop info_ptr,
                         png_sPLT_tp entries, int nentries) {
  png_sPLT_tp np;
  int i;
  if (png_ptr == NULL || info_ptr == NULL)
    return;
  np = (png_sPLT_tp)png_malloc_warn(png_ptr,
                                    (info_ptr->splt_palettes_num + nentries) *
                                        (png_uint_32)png_sizeof(png_sPLT_t));
  if (np == NULL) {
    png_warning(png_ptr, "No memory for sPLT palettes.");
    return;
  }
  png_memcpy(np, info_ptr->splt_palettes,
             info_ptr->splt_palettes_num * png_sizeof(png_sPLT_t));
  png_free(png_ptr, info_ptr->splt_palettes);
  info_ptr->splt_palettes = NULL;
  for (i = 0; i < nentries; i++) {
    png_sPLT_tp to = np + info_ptr->splt_palettes_num + i;
    png_sPLT_tp from = entries + i;
    png_uint_32 length;
    length = png_strlen(from->name) + 1;
    to->name = (png_charp)png_malloc_warn(png_ptr, length);
    if (to->name == NULL) {
      png_warning(png_ptr, "Out of memory while processing sPLT chunk");
      continue;
    }
    png_memcpy(to->name, from->name, length);
    to->entries = (png_sPLT_entryp)png_malloc_warn(
        png_ptr, (png_uint_32)(from->nentries * png_sizeof(png_sPLT_entry)));
    if (to->entries == NULL) {
      png_warning(png_ptr, "Out of memory while processing sPLT chunk");
      png_free(png_ptr, to->name);
      to->name = NULL;
      continue;
    }
    png_memcpy(to->entries, from->entries,
               from->nentries * png_sizeof(png_sPLT_entry));
    to->nentries = from->nentries;
    to->depth = from->depth;
  }
  info_ptr->splt_palettes = np;
  info_ptr->splt_palettes_num += nentries;
  info_ptr->valid |= PNG_INFO_sPLT;
#ifdef PNG_FREE_ME_SUPPORTED info_ptr->free_me |= PNG_FREE_SPLT;
#endif }

static int show_bisect_vars(struct rev_list_info *info, int reaches, int all) {
  int cnt, flags = info->flags;
  char hex[GIT_SHA1_HEXSZ + 1] = "";
  struct commit_list *tried;
  struct rev_info *revs = info->revs;
  if (!revs->commits)
    return 1;
  revs->commits = filter_skipped(revs->commits, &tried, flags & BISECT_SHOW_ALL,
                                 NULL, NULL);
  cnt = all - reaches;
  if (cnt < reaches)
    cnt = reaches;
  if (revs->commits)
    sha1_to_hex_r(hex, revs->commits->item->object.oid.hash);
  if (flags & BISECT_SHOW_ALL) {
    traverse_commit_list(revs, show_commit, show_object, info);
    printf("------\n");
  }
  print_var_str("bisect_rev", hex);
  print_var_int("bisect_nr", cnt - 1);
  print_var_int("bisect_good", all - reaches - 1);
  print_var_int("bisect_bad", reaches - 1);
  print_var_int("bisect_all", all);
  print_var_int("bisect_steps", estimate_bisect_steps(all));
  return 0;
}

