static int read_argb_line(CLLCContext *ctx, GetBitContext *gb, int *top_left,
                          VLC *vlc, uint8_t *outbuf) {
  uint8_t *dst;
  int pred[4];
  int code;
  int i;
  OPEN_READER(bits, gb);
  dst = outbuf;
  pred[0] = top_left[0];
  pred[1] = top_left[1];
  pred[2] = top_left[2];
  pred[3] = top_left[3];
  for (i = 0; i < ctx->avctx->width; i++) {
    UPDATE_CACHE(bits, gb);
    GET_VLC(code, bits, gb, vlc[0].table, 7, 2);
    pred[0] += code;
    dst[0] = pred[0];
    if (dst[0]) {
      UPDATE_CACHE(bits, gb);
      GET_VLC(code, bits, gb, vlc[1].table, 7, 2);
      pred[1] += code;
      dst[1] = pred[1];
      UPDATE_CACHE(bits, gb);
      GET_VLC(code, bits, gb, vlc[2].table, 7, 2);
      pred[2] += code;
      dst[2] = pred[2];
      UPDATE_CACHE(bits, gb);
      GET_VLC(code, bits, gb, vlc[3].table, 7, 2);
      pred[3] += code;
      dst[3] = pred[3];
    } else {
      dst[1] = 0;
      dst[2] = 0;
      dst[3] = 0;
    }
    dst += 4;
  }
  CLOSE_READER(bits, gb);
  dst -= 4 * ctx->avctx->width;
  top_left[0] = dst[0];
  if (top_left[0]) {
    top_left[1] = dst[1];
    top_left[2] = dst[2];
    top_left[3] = dst[3];
  }
  return 0;
}

static time_t _warc_rdmtm(const char *buf, size_t bsz) {
  static const char _key[] = "\r\nLast-Modified:";
  const char *val, *eol;
  char *on = NULL;
  time_t res;
  if ((val = xmemmem(buf, bsz, _key, sizeof(_key) - 1U)) == NULL) {
    return (time_t)-1;
  }
  val += sizeof(_key) - 1U;
  if ((eol = _warc_find_eol(val, buf + bsz - val)) == NULL) {
    return -1;
  }
  res = xstrpisotime(val, &on);
  if (on != eol) {
    return -1;
  }
  return res;
}

static int rds_notify_cong(struct rds_sock *rs, struct msghdr *msghdr) {
  uint64_t notify = rs->rs_cong_notify;
  unsigned long flags;
  int err;
  err =
      put_cmsg(msghdr, SOL_RDS, RDS_CMSG_CONG_UPDATE, sizeof(notify), &notify);
  if (err)
    return err;
  spin_lock_irqsave(&rs->rs_lock, flags);
  rs->rs_cong_notify &= ~notify;
  spin_unlock_irqrestore(&rs->rs_lock, flags);
  return 0;
}

static inline void decode_ac_coeffs(GetBitContext *gb, int16_t *out,
                                    int blocks_per_slice, int plane_size_factor,
                                    const uint8_t *scan) {
  int pos, block_mask, run, level, sign, run_cb_index, lev_cb_index;
  int max_coeffs, bits_left;
  run = 4;
  level = 2;
  max_coeffs = blocks_per_slice << 6;
  block_mask = blocks_per_slice - 1;
  for (pos = blocks_per_slice - 1; pos < max_coeffs;) {
    run_cb_index = ff_prores_run_to_cb_index[FFMIN(run, 15)];
    lev_cb_index = ff_prores_lev_to_cb_index[FFMIN(level, 9)];
    bits_left = get_bits_left(gb);
    if (bits_left <= 0 || (bits_left <= 8 && !show_bits(gb, bits_left)))
      return;
    run = decode_vlc_codeword(gb, ff_prores_ac_codebook[run_cb_index]);
    bits_left = get_bits_left(gb);
    if (bits_left <= 0 || (bits_left <= 8 && !show_bits(gb, bits_left)))
      return;
    level = decode_vlc_codeword(gb, ff_prores_ac_codebook[lev_cb_index]) + 1;
    pos += run + 1;
    if (pos >= max_coeffs)
      break;
    sign = get_sbits(gb, 1);
    out[((pos & block_mask) << 6) + scan[pos >> plane_size_factor]] =
        (level ^ sign) - sign;
  }
}

