static int dprintf_Pass1(const char *format, va_stack_t *vto, char **endpos,
                         va_list arglist) {
  char *fmt = (char *)format;
  int param_num = 0;
  long this_param;
  long width;
  long precision;
  int flags;
  long max_param = 0;
  long i;
  while (*fmt) {
    if (*fmt++ == '%') {
      if (*fmt == '%') {
        fmt++;
        continue;
      }
      flags = FLAGS_NEW;
      param_num++;
      this_param = dprintf_DollarString(fmt, &fmt);
      if (0 == this_param)
        this_param = param_num;
      if (this_param > max_param)
        max_param = this_param;
      width = 0;
      precision = 0;
      while (dprintf_IsQualifierNoDollar(fmt)) {
#if defined(MP_HAVE_INT_EXTENSIONS) if (!strncmp(fmt, "I32", 3)) {
        flags |= FLAGS_LONG;
        fmt += 3;
      }
      else if (!strncmp(fmt, "I64", 3)) {
        flags |= FLAGS_LONGLONG;
        fmt += 3;
      }
      else #endif switch (*fmt++) {
      case ' ':
        flags |= FLAGS_SPACE;
        break;
      case '+':
        flags |= FLAGS_SHOWSIGN;
        break;
      case '-':
        flags |= FLAGS_LEFT;
        flags &= ~FLAGS_PAD_NIL;
        break;
      case '#':
        flags |= FLAGS_ALT;
        break;
      case '.':
        flags |= FLAGS_PREC;
        if ('*' == *fmt) {
          flags |= FLAGS_PRECPARAM;
          fmt++;
          param_num++;
          i = dprintf_DollarString(fmt, &fmt);
          if (i)
            precision = i;
          else
            precision = param_num;
          if (precision > max_param)
            max_param = precision;
        } else {
          flags |= FLAGS_PREC;
          precision = strtol(fmt, &fmt, 10);
        }
        break;
      case 'h':
        flags |= FLAGS_SHORT;
        break;
#if defined(MP_HAVE_INT_EXTENSIONS) case 'I'                                   \
    : #if (CURL_SIZEOF_CURL_OFF_T > CURL_SIZEOF_LONG) flags |= FLAGS_LONGLONG;
#else flags |= FLAGS_LONG;
#endif break;
#endif case 'l' : if (flags & FLAGS_LONG) flags |= FLAGS_LONGLONG;
        else flags |= FLAGS_LONG;
        break;
      case 'L':
        flags |= FLAGS_LONGDOUBLE;
        break;
      case 'q':
        flags |= FLAGS_LONGLONG;
        break;
      case 'z':
#if (SIZEOF_SIZE_T > CURL_SIZEOF_LONG) flags |= FLAGS_LONGLONG;
#else flags |= FLAGS_LONG;
#endif break;
      case 'O':
#if (CURL_SIZEOF_CURL_OFF_T > CURL_SIZEOF_LONG) flags |= FLAGS_LONGLONG;
#else flags |= FLAGS_LONG;
#endif break;
      case '0':
        if (!(flags & FLAGS_LEFT))
          flags |= FLAGS_PAD_NIL;
      case '1':
      case '2':
      case '3':
      case '4':
      case '5':
      case '6':
      case '7':
      case '8':
      case '9':
        flags |= FLAGS_WIDTH;
        width = strtol(fmt - 1, &fmt, 10);
        break;
      case '*':
        flags |= FLAGS_WIDTHPARAM;
        param_num++;
        i = dprintf_DollarString(fmt, &fmt);
        if (i)
          width = i;
        else
          width = param_num;
        if (width > max_param)
          max_param = width;
        break;
      default:
        break;
      }
    }
    i = this_param - 1;
    if ((i < 0) || (i >= MAX_PARAMETERS))
      return 1;
    switch (*fmt) {
    case 'S':
      flags |= FLAGS_ALT;
    case 's':
      vto[i].type = FORMAT_STRING;
      break;
    case 'n':
      vto[i].type = FORMAT_INTPTR;
      break;
    case 'p':
      vto[i].type = FORMAT_PTR;
      break;
    case 'd':
    case 'i':
      vto[i].type = FORMAT_INT;
      break;
    case 'u':
      vto[i].type = FORMAT_INT;
      flags |= FLAGS_UNSIGNED;
      break;
    case 'o':
      vto[i].type = FORMAT_INT;
      flags |= FLAGS_OCTAL;
      break;
    case 'x':
      vto[i].type = FORMAT_INT;
      flags |= FLAGS_HEX | FLAGS_UNSIGNED;
      break;
    case 'X':
      vto[i].type = FORMAT_INT;
      flags |= FLAGS_HEX | FLAGS_UPPER | FLAGS_UNSIGNED;
      break;
    case 'c':
      vto[i].type = FORMAT_INT;
      flags |= FLAGS_CHAR;
      break;
    case 'f':
      vto[i].type = FORMAT_DOUBLE;
      break;
    case 'e':
      vto[i].type = FORMAT_DOUBLE;
      flags |= FLAGS_FLOATE;
      break;
    case 'E':
      vto[i].type = FORMAT_DOUBLE;
      flags |= FLAGS_FLOATE | FLAGS_UPPER;
      break;
    case 'g':
      vto[i].type = FORMAT_DOUBLE;
      flags |= FLAGS_FLOATG;
      break;
    case 'G':
      vto[i].type = FORMAT_DOUBLE;
      flags |= FLAGS_FLOATG | FLAGS_UPPER;
      break;
    default:
      vto[i].type = FORMAT_UNKNOWN;
      break;
    }
    vto[i].flags = flags;
    vto[i].width = width;
    vto[i].precision = precision;
    if (flags & FLAGS_WIDTHPARAM) {
      long k = width - 1;
      vto[i].width = k;
      vto[k].type = FORMAT_WIDTH;
      vto[k].flags = FLAGS_NEW;
      vto[k].width = 0;
      vto[k].precision = 0;
    }
    if (flags & FLAGS_PRECPARAM) {
      long k = precision - 1;
      vto[i].precision = k;
      vto[k].type = FORMAT_WIDTH;
      vto[k].flags = FLAGS_NEW;
      vto[k].width = 0;
      vto[k].precision = 0;
    }
    *endpos++ = fmt + 1;
  }
}
for (i = 0; i < max_param; i++) {
  if (vto[i].flags & FLAGS_WIDTHPARAM) {
    vto[vto[i].width].data.num.as_signed = (mp_intmax_t)va_arg(arglist, int);
  }
  if (vto[i].flags & FLAGS_PRECPARAM) {
    vto[vto[i].precision].data.num.as_signed =
        (mp_intmax_t)va_arg(arglist, int);
  }
  switch (vto[i].type) {
  case FORMAT_STRING:
    vto[i].data.str = va_arg(arglist, char *);
    break;
  case FORMAT_INTPTR:
  case FORMAT_UNKNOWN:
  case FORMAT_PTR:
    vto[i].data.ptr = va_arg(arglist, void *);
    break;
  case FORMAT_INT:
#ifdef HAVE_LONG_LONG_TYPE if ((vto[i].flags & FLAGS_LONGLONG) &&
                                   (vto[i].flags & FLAGS_UNSIGNED))
        vto[i].data.num.as_unsigned =
                (mp_uintmax_t)va_arg(arglist, mp_uintmax_t);
    else if (vto[i].flags & FLAGS_LONGLONG) vto[i].data.num.as_signed =
        (mp_intmax_t)va_arg(arglist, mp_intmax_t);
    else #endif {
      if ((vto[i].flags & FLAGS_LONG) && (vto[i].flags & FLAGS_UNSIGNED))
        vto[i].data.num.as_unsigned =
            (mp_uintmax_t)va_arg(arglist, unsigned long);
      else if (vto[i].flags & FLAGS_LONG)
        vto[i].data.num.as_signed = (mp_intmax_t)va_arg(arglist, long);
      else if (vto[i].flags & FLAGS_UNSIGNED)
        vto[i].data.num.as_unsigned =
            (mp_uintmax_t)va_arg(arglist, unsigned int);
      else
        vto[i].data.num.as_signed = (mp_intmax_t)va_arg(arglist, int);
    }
    break;
  case FORMAT_DOUBLE:
    vto[i].data.dnum = va_arg(arglist, double);
    break;
  case FORMAT_WIDTH:
    vto[i].type = FORMAT_INT;
    break;
  default:
    break;
  }
}
return 0;
}

static void tcg_handle_interrupt(CPUState *cpu, int mask) {
  CPUArchState *env = cpu->env_ptr;
  int old_mask;
  old_mask = cpu->interrupt_request;
  cpu->interrupt_request |= mask;
  if (!qemu_cpu_is_self(cpu)) {
    qemu_cpu_kick(cpu);
    return;
  }
  if (use_icount) {
    env->icount_decr.u16.high = 0xffff;
    if (!can_do_io(env) && (mask & ~old_mask) != 0) {
      cpu_abort(env, "Raised interrupt while not in I/O function");
    }
  } else {
    cpu->tcg_exit_req = 1;
  }
}

static int qemuMonitorSendDiskPassphrase(qemuMonitorPtr mon,
                                         qemuMonitorMessagePtr msg,
                                         const char *data,
                                         size_t len ATTRIBUTE_UNUSED,
                                         void *opaque) {
  virConnectPtr conn = opaque;
  char *path;
  char *passphrase = NULL;
  size_t passphrase_len = 0;
  int res;
  const char *pathStart;
  const char *pathEnd;
  pathStart = strstr(data, DISK_ENCRYPTION_PREFIX);
  pathEnd = strstr(data, DISK_ENCRYPTION_POSTFIX);
  if (!pathStart || !pathEnd || pathStart >= pathEnd) {
    qemuReportError(VIR_ERR_INTERNAL_ERROR,
                    _("Unable to extract disk path from %s"), data);
    return -1;
  }
  pathStart += strlen(DISK_ENCRYPTION_PREFIX);
  if (!(path = strndup(pathStart, pathEnd - pathStart))) {
    virReportOOMError();
    return -1;
  }
  res = qemuMonitorGetDiskSecret(mon, conn, path, &passphrase, &passphrase_len);
  VIR_FREE(path);
  if (res < 0)
    return -1;
  if (VIR_REALLOC_N(msg->txBuffer, msg->txLength + passphrase_len + 1 + 1) <
      0) {
    memset(passphrase, 0, passphrase_len);
    VIR_FREE(passphrase);
    virReportOOMError();
    return -1;
  }
  memcpy(msg->txBuffer + msg->txLength, passphrase, passphrase_len);
  msg->txLength += passphrase_len;
  msg->txBuffer[msg->txLength] = '\r';
  msg->txLength++;
  msg->txBuffer[msg->txLength] = '\0';
  memset(passphrase, 0, passphrase_len);
  VIR_FREE(passphrase);
  return 0;
}

static guint32 parse_wbxml_tag_defined(proto_tree *tree, tvbuff_t *tvb,
                                       guint32 offset, guint32 str_tbl,
                                       guint8 *level, guint8 *codepage_stag,
                                       guint8 *codepage_attr,
                                       const wbxml_decoding *map) {
  guint32 tvb_len = tvb_reported_length(tvb);
  guint32 off = offset, last_off;
  guint32 len;
  guint str_len;
  guint32 ent;
  guint32 idx;
  guint8 peek;
  guint32 tag_len;
  guint8 tag_save_known = 0;
  guint8 tag_new_known = 0;
  const char *tag_save_literal;
  const char *tag_new_literal;
  guint8 parsing_tag_content = FALSE;
  tag_save_literal = NULL;
  DebugLog(
      ("parse_wbxml_tag_defined (level = %u, offset = %u)\n", *level, offset));
  last_off = off;
  while (off < tvb_len) {
    peek = tvb_get_guint8(tvb, off);
    DebugLog(("STAG: (top of while) level = %3u, peek = 0x%02X, off = %u, "
              "tvb_len = %u\n",
              *level, peek, off, tvb_len));
    if ((peek & 0x3F) < 4)
      switch (peek) {
      case 0x00:
        *codepage_stag = tvb_get_guint8(tvb, off + 1);
        proto_tree_add_text(tree, tvb, off, 2,
                            " | Tag | T -->%3d "
                            "| SWITCH_PAGE (Tag code page) "
                            "|",
                            *codepage_stag);
        off += 2;
        break;
      case 0x01:
        if (tag_save_known) {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Tag | T %3d "
                              "| END (Known Tag 0x%02X) "
                              "| %s</%s>",
                              *level, *codepage_stag, tag_save_known,
                              Indent(*level), tag_save_literal);
        } else {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Tag | T %3d "
                              "| END (Literal Tag) "
                              "| %s</%s>",
                              *level, *codepage_stag, Indent(*level),
                              tag_save_literal ? tag_save_literal : "");
        }
        (*level)--;
        off++;
        DebugLog(
            ("STAG: level = %u, Return: len = %u\n", *level, off - offset));
        return (off - offset);
      case 0x02:
        ent = tvb_get_guintvar(tvb, off + 1, &len);
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| ENTITY " "| %s'&#%u;
'" , * level , * codepage_stag , Indent ( * level ) , ent ) ;
 off += 1 + len ;
 break ;
 case 0x03 : len = tvb_strsize ( tvb , off + 1 ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| STR_I (Inline string) " "| %s\'%s\'" , * level , * codepage_stag , Indent ( * level ) , tvb_format_text ( tvb , off + 1 , len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x40 : case 0x41 : case 0x42 : len = tvb_strsize ( tvb , off + 1 ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| EXT_I_%1x (Extension Token) " "| %s(%s: \'%s\')" , * level , * codepage_stag , peek & 0x0f , Indent ( * level ) , map_token ( map -> global , 0 , peek ) , tvb_format_text ( tvb , off + 1 , len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x43 : proto_tree_add_text ( tree , tvb , off , 1 , " %3d | Tag | T %3d " "| PI (XML Processing Instruction) " "| %s<?xml" , * level , * codepage_stag , Indent ( * level ) ) ;
 len = parse_wbxml_attribute_list_defined ( tree , tvb , off , str_tbl , * level , codepage_attr , map ) ;
 off += len ;
 if ( off >= tvb_len ) {
          DebugLog(
              ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
               *level, off - offset));
          THROW(ReportedBoundsError);
 }
 proto_tree_add_text ( tree , tvb , off - 1 , 1 , " %3d | Tag | T %3d " "| END (PI) " "| %s?>" , * level , * codepage_stag , Indent ( * level ) ) ;
 break ;
 case 0x80 : case 0x81 : case 0x82 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 {
          char *s;
          if (map->ext_t[peek & 0x03])
            s = (map->ext_t[peek & 0x03])(tvb, idx, str_tbl);
          else
            s = wmem_strdup_printf(wmem_packet_scope(), "EXT_T_%1x (%s)",
                                   peek & 0x03,
                                   map_token(map->global, 0, peek));
          proto_tree_add_text(tree, tvb, off, 1 + len,
                              " %3d | Tag | T %3d "
                              "| EXT_T_%1x (Extension Token) "
                              "| %s%s",
                              *level, *codepage_stag, peek & 0x0f,
                              Indent(*level), s);
 }
 off += 1 + len ;
 break ;
 case 0x83 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 str_len = tvb_strsize ( tvb , str_tbl + idx ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| STR_T (Tableref string) " "| %s\'%s\'" , * level , * codepage_stag , Indent ( * level ) , tvb_format_text ( tvb , str_tbl + idx , str_len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0xC0 : case 0xC1 : case 0xC2 : proto_tree_add_text ( tree , tvb , off , 1 , " %3d | Tag | T %3d " "| EXT_%1x (Extension Token) " "| %s(%s)" , * level , * codepage_stag , peek & 0x0f , Indent ( * level ) , map_token ( map -> global , 0 , peek ) ) ;
 off ++ ;
 break ;
 case 0xC3 : if ( tvb_get_guint8 ( tvb , 0 ) ) {
          char *str;
          if (tag_save_known) {
            if (map->opaque_binary_tag) {
              str = map->opaque_binary_tag(tvb, off + 1, tag_save_known,
                                           *codepage_stag, &len);
            } else {
              str = default_opaque_binary_tag(tvb, off + 1, tag_save_known,
                                              *codepage_stag, &len);
            }
          } else {
            if (map->opaque_literal_tag) {
              str = map->opaque_literal_tag(tvb, off + 1, tag_save_literal,
                                            *codepage_stag, &len);
            } else {
              str = default_opaque_literal_tag(tvb, off + 1, tag_save_literal,
                                               *codepage_stag, &len);
            }
          }
          proto_tree_add_text(tree, tvb, off, 1 + len,
                              " %3d | Tag | T %3d "
                              "| OPAQUE (Opaque data) "
                              "| %s%s",
                              *level, *codepage_stag, Indent(*level), str);
          off += 1 + len;
 }
 else {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Tag | T %3d "
                              "| RESERVED_2 (Invalid Token!) "
                              "| WBXML 1.0 parsing stops here.",
                              *level, *codepage_stag);
          off = tvb_len;
          DebugLog(
              ("STAG: level = %u, Return: len = %u\n", *level, off - offset));
          return (off - offset);
 }
 break ;
      }
    else {
      tag_len = 0;
      if ((peek & 0x3F) == 4) {
        DebugLog((
            "STAG: LITERAL tag (peek = 0x%02X, off = %u) - TableRef follows!\n",
            peek, off));
        idx = tvb_get_guintvar(tvb, off + 1, &tag_len);
        str_len = tvb_strsize(tvb, str_tbl + idx);
        tag_new_literal =
            (const gchar *)tvb_get_ptr(tvb, str_tbl + idx, str_len);
        tag_new_known = 0;
      } else {
        tag_new_known = peek & 0x3F;
        tag_new_literal = map_token(map->tags, *codepage_stag, tag_new_known);
      }
      if (peek & 0x40) {
        if (parsing_tag_content) {
          DebugLog(("STAG: Tag in Tag - RECURSE! (off = %u)\n", off));
          (*level)++;
          len = parse_wbxml_tag_defined(tree, tvb, off, str_tbl, level,
                                        codepage_stag, codepage_attr, map);
          off += len;
        } else {
          if ((peek & 0x3F) == 4) {
            tag_save_literal = tag_new_literal;
            tag_save_known = 0;
          } else {
            tag_save_known = tag_new_known;
            tag_save_literal = tag_new_literal;
          }
          if (peek & 0x80) {
            if (tag_new_known) {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| Known Tag 0x%02X (AC) "
                                  "| %s<%s",
                                  *level, *codepage_stag, tag_new_known,
                                  Indent(*level), tag_new_literal);
              off++;
            } else {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| LITERAL_AC (Literal tag) (AC) "
                                  "| %s<%s",
                                  *level, *codepage_stag, Indent(*level),
                                  tag_new_literal);
              off += 1 + tag_len;
            }
            len = parse_wbxml_attribute_list_defined(
                tree, tvb, off, str_tbl, *level, codepage_attr, map);
            off += len;
            if (off >= tvb_len) {
              DebugLog(
                  ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
                   *level, off - offset));
              THROW(ReportedBoundsError);
            }
            proto_tree_add_text(tree, tvb, off - 1, 1,
                                " %3d | Tag | T %3d "
                                "| END (attribute list) "
                                "| %s>",
                                *level, *codepage_stag, Indent(*level));
          } else {
            if (tag_new_known) {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| Known Tag 0x%02X (.C) "
                                  "| %s<%s>",
                                  *level, *codepage_stag, tag_new_known,
                                  Indent(*level), tag_new_literal);
              off++;
            } else {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| LITERAL_C (Literal Tag) (.C) "
                                  "| %s<%s>",
                                  *level, *codepage_stag, Indent(*level),
                                  tag_new_literal);
              off += 1 + tag_len;
            }
          }
          parsing_tag_content = TRUE;
          DebugLog(("Tag in Tag - No recursion this time! (off = %u)\n", off));
        }
      } else {
        DebugLog(("<Tag/> in Tag - No recursion! (off = %u)\n", off));
        (*level)++;
        if (peek & 0x80) {
          if (tag_new_known) {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| Known Tag 0x%02X (A.) "
                                "| %s<%s",
                                *level, *codepage_stag, tag_new_known,
                                Indent(*level), tag_new_literal);
            off++;
            len = parse_wbxml_attribute_list_defined(
                tree, tvb, off, str_tbl, *level, codepage_attr, map);
            off += len;
            if (off > tvb_len) {
              DebugLog(
                  ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
                   *level, off - offset));
              THROW(ReportedBoundsError);
            }
            proto_tree_add_text(tree, tvb, off - 1, 1,
                                " %3d | Tag | T %3d "
                                "| END (Known Tag) "
                                "| %s/>",
                                *level, *codepage_stag, Indent(*level));
          } else {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| LITERAL_A (Literal Tag) (A.) "
                                "| %s<%s",
                                *level, *codepage_stag, Indent(*level),
                                tag_new_literal);
            off += 1 + tag_len;
            len = parse_wbxml_attribute_list_defined(
                tree, tvb, off, str_tbl, *level, codepage_attr, map);
            off += len;
            if (off >= tvb_len) {
              DebugLog(
                  ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
                   *level, off - offset));
              THROW(ReportedBoundsError);
            }
            proto_tree_add_text(tree, tvb, off - 1, 1,
                                " %3d | Tag | T %3d "
                                "| END (Literal Tag) "
                                "| %s/>",
                                *level, *codepage_stag, Indent(*level));
          }
        } else {
          if (tag_new_known) {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| Known Tag 0x%02x (..) "
                                "| %s<%s />",
                                *level, *codepage_stag, tag_new_known,
                                Indent(*level), tag_new_literal);
            off++;
          } else {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| LITERAL (Literal Tag) (..) "
                                "| %s<%s />",
                                *level, *codepage_stag, Indent(*level),
                                tag_new_literal);
            off += 1 + tag_len;
          }
        }
        (*level)--;
      }
    }
    if (off < last_off) {
      THROW(ReportedBoundsError);
    }
    last_off = off;
  }
  DebugLog(("STAG: level = %u, Return: len = %u (end of function body)\n",
            *level, off - offset));
  return (off - offset);
}

int cpu_signal_handler(int host_signum, void *pinfo, void *puc) {
  siginfo_t *info = pinfo;
  unsigned long pc;
#if defined(__NetBSD__) || defined(__FreeBSD__) ||                             \
    defined(__DragonFly__) ucontext_t *uc = puc;
#elif defined(__OpenBSD__) struct sigcontext *uc = puc;
#else struct ucontext *uc = puc;
#endif pc = PC_sig(uc);
  return handle_cpu_signal(pc, (unsigned long)info->si_addr,
                           TRAP_sig(uc) == 0xe ? (ERROR_sig(uc) >> 1) & 1 : 0,
                           &MASK_sig(uc), puc);
}

static int decode_rle(AVCodecContext *avctx, AVSubtitle *sub, int rect,
                      const uint8_t *buf, unsigned int buf_size) {
  const uint8_t *rle_bitmap_end;
  int pixel_count, line_count;
  rle_bitmap_end = buf + buf_size;
  sub->rects[rect]->pict.data[0] =
      av_malloc(sub->rects[rect]->w * sub->rects[rect]->h);
  if (!sub->rects[rect]->pict.data[0])
    return -1;
  pixel_count = 0;
  line_count = 0;
  while (buf < rle_bitmap_end && line_count < sub->rects[rect]->h) {
    uint8_t flags, color;
    int run;
    color = bytestream_get_byte(&buf);
    run = 1;
    if (color == 0x00) {
      flags = bytestream_get_byte(&buf);
      run = flags & 0x3f;
      if (flags & 0x40)
        run = (run << 8) + bytestream_get_byte(&buf);
      color = flags & 0x80 ? bytestream_get_byte(&buf) : 0;
    }
    if (run > 0 &&
        pixel_count + run <= sub->rects[rect]->w * sub->rects[rect]->h) {
      memset(sub->rects[rect]->pict.data[0] + pixel_count, color, run);
      pixel_count += run;
    } else if (!run) {
      if (pixel_count % sub->rects[rect]->w > 0)
        av_log(avctx, AV_LOG_ERROR,
               "Decoded %d pixels, when line should be %d pixels\n",
               pixel_count % sub->rects[rect]->w, sub->rects[rect]->w);
      line_count++;
    }
  }
  if (pixel_count < sub->rects[rect]->w * sub->rects[rect]->h) {
    av_log(avctx, AV_LOG_ERROR, "Insufficient RLE data for subtitle\n");
    return -1;
  }
  av_dlog(avctx, "Pixel Count = %d, Area = %d\n", pixel_count,
          sub->rects[rect]->w * sub->rects[rect]->h);
  return 0;
}

