static int collector_encode_htmlnumericentity(int c, void *data) {
  struct collector_htmlnumericentity_data *pc =
      (struct collector_htmlnumericentity_data *)data;
  int f, n, s, r, d, size, *mapelm;
  size = pc->mapsize;
  f = 0;
  n = 0;
  while (n < size) {
    mapelm = &(pc->convmap[n * 4]);
    if (c >= mapelm[0] && c <= mapelm[1]) {
      s = (c + mapelm[2]) & mapelm[3];
      if (s >= 0) {
        (*pc->decoder->filter_function)(0x26, pc->decoder);
        (*pc->decoder->filter_function)(0x23, pc->decoder);
        r = 100000000;
        s %= r;
        while (r > 0) {
          d = s / r;
          if (d || f) {
            f = 1;
            s %= r;
            (*pc->decoder->filter_function)(mbfl_hexchar_table[d], pc->decoder);
          }
          r /= 10;
        }
        if (!f) {
          f = 1;
          (*pc->decoder->filter_function)(mbfl_hexchar_table[0], pc->decoder);
        }
        (*pc->decoder->filter_function)(0x3b, pc->decoder);
      }
    }
    if (f) {
      break;
    }
    n++;
  }
  if (!f) {
    (*pc->decoder->filter_function)(c, pc->decoder);
  }
  return c;
}

void ff_h263_update_motion_val(MpegEncContext *s) {
  const int mb_xy = s->mb_y * s->mb_stride + s->mb_x;
  const int wrap = s->b8_stride;
  const int xy = s->block_index[0];
  s->current_picture.f.mbskip_table[mb_xy] = s->mb_skipped;
  if (s->mv_type != MV_TYPE_8X8) {
    int motion_x, motion_y;
    if (s->mb_intra) {
      motion_x = 0;
      motion_y = 0;
    } else if (s->mv_type == MV_TYPE_16X16) {
      motion_x = s->mv[0][0][0];
      motion_y = s->mv[0][0][1];
    } else {
      int i;
      motion_x = s->mv[0][0][0] + s->mv[0][1][0];
      motion_y = s->mv[0][0][1] + s->mv[0][1][1];
      motion_x = (motion_x >> 1) | (motion_x & 1);
      for (i = 0; i < 2; i++) {
        s->p_field_mv_table[i][0][mb_xy][0] = s->mv[0][i][0];
        s->p_field_mv_table[i][0][mb_xy][1] = s->mv[0][i][1];
      }
      s->current_picture.f.ref_index[0][4 * mb_xy] =
          s->current_picture.f.ref_index[0][4 * mb_xy + 1] =
              s->field_select[0][0];
      s->current_picture.f.ref_index[0][4 * mb_xy + 2] =
          s->current_picture.f.ref_index[0][4 * mb_xy + 3] =
              s->field_select[0][1];
    }
    s->current_picture.f.motion_val[0][xy][0] = motion_x;
    s->current_picture.f.motion_val[0][xy][1] = motion_y;
    s->current_picture.f.motion_val[0][xy + 1][0] = motion_x;
    s->current_picture.f.motion_val[0][xy + 1][1] = motion_y;
    s->current_picture.f.motion_val[0][xy + wrap][0] = motion_x;
    s->current_picture.f.motion_val[0][xy + wrap][1] = motion_y;
    s->current_picture.f.motion_val[0][xy + 1 + wrap][0] = motion_x;
    s->current_picture.f.motion_val[0][xy + 1 + wrap][1] = motion_y;
  }
  if (s->encoding) {
    if (s->mv_type == MV_TYPE_8X8)
      s->current_picture.f.mb_type[mb_xy] = MB_TYPE_L0 | MB_TYPE_8x8;
    else if (s->mb_intra)
      s->current_picture.f.mb_type[mb_xy] = MB_TYPE_INTRA;
    else
      s->current_picture.f.mb_type[mb_xy] = MB_TYPE_L0 | MB_TYPE_16x16;
  }
}

