void tb_invalidate_phys_page_range(tb_page_addr_t start, tb_page_addr_t end,
                                   int is_cpu_write_access) {
  TranslationBlock *tb, *tb_next, *saved_tb;
  CPUState *cpu = current_cpu;
#if defined(TARGET_HAS_PRECISE_SMC) || !defined(CONFIG_USER_ONLY)              \
                                           CPUArchState *env = NULL;
#endif tb_page_addr_t tb_start, tb_end;
  PageDesc *p;
  int n;
#ifdef TARGET_HAS_PRECISE_SMC int current_tb_not_found = is_cpu_write_access;
  TranslationBlock *current_tb = NULL;
  int current_tb_modified = 0;
  target_ulong current_pc = 0;
  target_ulong current_cs_base = 0;
  int current_flags = 0;
#endif p = page_find(start >> TARGET_PAGE_BITS);
  if (!p) {
    return;
  }
  if (!p->code_bitmap && ++p->code_write_count >= SMC_BITMAP_USE_THRESHOLD &&
      is_cpu_write_access) {
    build_page_bitmap(p);
  }
#if defined(TARGET_HAS_PRECISE_SMC) ||                                         \
    !defined(CONFIG_USER_ONLY) if (cpu != NULL) {
  env = cpu->env_ptr;
}
#endif tb = p->first_tb;
while (tb != NULL) {
  n = (uintptr_t)tb & 3;
  tb = (TranslationBlock *)((uintptr_t)tb & ~3);
  tb_next = tb->page_next[n];
  if (n == 0) {
    tb_start = tb->page_addr[0] + (tb->pc & ~TARGET_PAGE_MASK);
    tb_end = tb_start + tb->size;
  } else {
    tb_start = tb->page_addr[1];
    tb_end = tb_start + ((tb->pc + tb->size) & ~TARGET_PAGE_MASK);
  }
  if (!(tb_end <= start || tb_start >= end)) {
#ifdef TARGET_HAS_PRECISE_SMC if (current_tb_not_found) {
    current_tb_not_found = 0;
    current_tb = NULL;
    if (env->mem_io_pc) {
      current_tb = tb_find_pc(env->mem_io_pc);
    }
  }
  if (current_tb == tb && (current_tb->cflags & CF_COUNT_MASK) != 1) {
    current_tb_modified = 1;
    cpu_restore_state_from_tb(current_tb, env, env->mem_io_pc);
    cpu_get_tb_cpu_state(env, &current_pc, &current_cs_base, &current_flags);
  }
#endif saved_tb = NULL;
  if (cpu != NULL) {
    saved_tb = cpu->current_tb;
    cpu->current_tb = NULL;
  }
  tb_phys_invalidate(tb, -1);
  if (cpu != NULL) {
    cpu->current_tb = saved_tb;
    if (cpu->interrupt_request && cpu->current_tb) {
      cpu_interrupt(cpu, cpu->interrupt_request);
    }
  }
}
tb = tb_next;
}
#if !defined(CONFIG_USER_ONLY) if (!p->first_tb) {
invalidate_page_bitmap(p);
if (is_cpu_write_access) {
  tlb_unprotect_code_phys(env, start, env->mem_io_vaddr);
}
}
#endif #ifdef TARGET_HAS_PRECISE_SMC if (current_tb_modified) {
cpu->current_tb = NULL;
tb_gen_code(env, current_pc, current_cs_base, current_flags, 1);
cpu_resume_from_signal(env, NULL);
}
#endif }

void vp9_idct8x8_1_add_sse2(const int16_t *input, uint8_t *dest, int stride) {
  __m128i dc_value;
  const __m128i zero = _mm_setzero_si128();
  int a;
  a = dct_const_round_shift(input[0] * cospi_16_64);
  a = dct_const_round_shift(a * cospi_16_64);
  a = ROUND_POWER_OF_TWO(a, 5);
  dc_value = _mm_set1_epi16(a);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
  RECON_AND_STORE(dest, dc_value);
}

static VALUE cState_indent_set(VALUE self, VALUE indent) {
  unsigned long len;
  GET_STATE(self);
  Check_Type(indent, T_STRING);
  len = RSTRING_LEN(indent);
  if (len == 0) {
    if (state->indent) {
      ruby_xfree(state->indent);
      state->indent = NULL;
      state->indent_len = 0;
    }
  } else {
    if (state->indent)
      ruby_xfree(state->indent);
    state->indent = fstrndup(RSTRING_PTR(indent), len);
    state->indent_len = len;
  }
  return Qnil;
}

