static void check_perms_nopam(const struct passwd *pw) {
  const struct spwd *spwd = NULL;
  const char *password = pw->pw_passwd;
  RETSIGTYPE (*oldsig)(int);
  if (caller_is_root) {
    return;
  }
  if ((0 == pw->pw_uid) && getdef_bool("SU_WHEEL_ONLY") &&
      !iswheel(caller_name)) {
    fprintf(stderr, _("You are not authorized to su %s\n"), name);
    exit(1);
  }
  spwd = getspnam(name);
#ifdef SU_ACCESS if (strcmp(pw->pw_passwd, SHADOW_PASSWD_STRING) == 0) {
  if (NULL != spwd) {
    password = spwd->sp_pwdp;
  }
}
switch (check_su_auth(caller_name, name, 0 == pw->pw_uid)) {
case 0:
  break;
case 1:
  password = "";
  break;
case 2:
  (void)puts(_("(Enter your own password)"));
  password = caller_pass;
  break;
default:
  fprintf(stderr, _("You are not authorized to su %s\n"), name);
  exit(1);
}
#endif die(0);
oldsig = signal(SIGQUIT, die);
if (pw_auth(password, name, PW_SU, (char *)0) != 0) {
  SYSLOG(((pw->pw_uid != 0) ? LOG_NOTICE : LOG_WARN,
          "Authentication failed for %s", name));
  fprintf(stderr, _("%s: Authentication failure\n"), Prog);
  su_failure(caller_tty, 0 == pw->pw_uid);
}
(void)signal(SIGQUIT, oldsig);
if (NULL != spwd) {
  (void)expire(pw, spwd);
}
if (!isttytime(name, "SU", time((time_t *)0))) {
  SYSLOG(((0 != pw->pw_uid) ? LOG_WARN : LOG_CRIT,
          "SU by %s to restricted account %s", caller_name, name));
  fprintf(stderr, _("%s: You are not authorized to su at that time\n"), Prog);
  su_failure(caller_tty, 0 == pw->pw_uid);
}
}

SPL_METHOD(SplFileObject, setCsvControl) {
  spl_filesystem_object *intern =
      (spl_filesystem_object *)zend_object_store_get_object(getThis()
                                                                TSRMLS_CC);
  char delimiter = ',', enclosure = '"', escape = '\\';
  char *delim = NULL, *enclo = NULL, *esc = NULL;
  int d_len = 0, e_len = 0, esc_len = 0;
  if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "|sss", &delim, &d_len,
                            &enclo, &e_len, &esc, &esc_len) == SUCCESS) {
    switch (ZEND_NUM_ARGS()) {
    case 3:
      if (esc_len != 1) {
        php_error_docref(NULL TSRMLS_CC, E_WARNING,
                         "escape must be a character");
        RETURN_FALSE;
      }
      escape = esc[0];
    case 2:
      if (e_len != 1) {
        php_error_docref(NULL TSRMLS_CC, E_WARNING,
                         "enclosure must be a character");
        RETURN_FALSE;
      }
      enclosure = enclo[0];
    case 1:
      if (d_len != 1) {
        php_error_docref(NULL TSRMLS_CC, E_WARNING,
                         "delimiter must be a character");
        RETURN_FALSE;
      }
      delimiter = delim[0];
