static int bfi_decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                            AVPacket *avpkt) {
  AVFrame *frame = data;
  GetByteContext g;
  int buf_size = avpkt->size;
  BFIContext *bfi = avctx->priv_data;
  uint8_t *dst = bfi->dst;
  uint8_t *src, *dst_offset, colour1, colour2;
  uint8_t *frame_end = bfi->dst + avctx->width * avctx->height;
  uint32_t *pal;
  int i, j, ret, height = avctx->height;
  if ((ret = ff_get_buffer(avctx, frame, 0)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  bytestream2_init(&g, avpkt->data, buf_size);
  if (!avctx->frame_number) {
    frame->pict_type = AV_PICTURE_TYPE_I;
    frame->key_frame = 1;
    if (avctx->extradata_size > 768) {
      av_log(NULL, AV_LOG_ERROR, "Palette is too large.\n");
      return AVERROR_INVALIDDATA;
    }
    pal = (uint32_t *)frame->data[1];
    for (i = 0; i < avctx->extradata_size / 3; i++) {
      int shift = 16;
      *pal = 0;
      for (j = 0; j < 3; j++, shift -= 8)
        *pal += ((avctx->extradata[i * 3 + j] << 2) |
                 (avctx->extradata[i * 3 + j] >> 4))
                << shift;
      pal++;
    }
    frame->palette_has_changed = 1;
  } else {
    frame->pict_type = AV_PICTURE_TYPE_P;
    frame->key_frame = 0;
  }
  bytestream2_skip(&g, 4);
  while (dst != frame_end) {
    static const uint8_t lentab[4] = {0, 2, 0, 1};
    unsigned int byte = bytestream2_get_byte(&g), av_uninit(offset);
    unsigned int code = byte >> 6;
    unsigned int length = byte & ~0xC0;
    if (!bytestream2_get_bytes_left(&g)) {
      av_log(avctx, AV_LOG_ERROR,
             "Input resolution larger than actual frame.\n");
      return AVERROR_INVALIDDATA;
    }
    if (length == 0) {
      if (code == 1) {
        length = bytestream2_get_byte(&g);
        offset = bytestream2_get_le16(&g);
      } else {
        length = bytestream2_get_le16(&g);
        if (code == 2 && length == 0)
          break;
      }
    } else {
      if (code == 1)
        offset = bytestream2_get_byte(&g);
    }
    if (dst + (length << lentab[code]) > frame_end)
      break;
    switch (code) {
    case 0:
      if (length >= bytestream2_get_bytes_left(&g)) {
        av_log(avctx, AV_LOG_ERROR, "Frame larger than buffer.\n");
        return AVERROR_INVALIDDATA;
      }
      bytestream2_get_buffer(&g, dst, length);
      dst += length;
      break;
    case 1:
      dst_offset = dst - offset;
      length *= 4;
      if (dst_offset < bfi->dst)
        break;
      while (length--)
        *dst++ = *dst_offset++;
      break;
    case 2:
      dst += length;
      break;
    case 3:
      colour1 = bytestream2_get_byte(&g);
      colour2 = bytestream2_get_byte(&g);
      while (length--) {
        *dst++ = colour1;
        *dst++ = colour2;
      }
      break;
    }
  }
  src = bfi->dst;
  dst = frame->data[0];
  while (height--) {
    memcpy(dst, src, avctx->width);
    src += avctx->width;
    dst += frame->linesize[0];
  }
  *got_frame = 1;
  return buf_size;
}

static int slirp_smb(SlirpState *s, const char *exported_dir,
                     struct in_addr vserver_addr) {
  static int instance;
  char smb_conf[128];
  char smb_cmdline[128];
  struct passwd *passwd;
  FILE *f;
  passwd = getpwuid(geteuid());
  if (!passwd) {
    error_report("failed to retrieve user name");
    return -1;
  }
  if (access(CONFIG_SMBD_COMMAND, F_OK)) {
    error_report("could not find '%s', please install it", CONFIG_SMBD_COMMAND);
    return -1;
  }
  if (access(exported_dir, R_OK | X_OK)) {
    error_report("error accessing shared directory '%s': %s", exported_dir,
                 strerror(errno));
    return -1;
  }
  snprintf(s->smb_dir, sizeof(s->smb_dir), "/tmp/qemu-smb.%ld-%d",
           (long)getpid(), instance++);
  if (mkdir(s->smb_dir, 0700) < 0) {
    error_report("could not create samba server dir '%s'", s->smb_dir);
    return -1;
  }
  snprintf(smb_conf, sizeof(smb_conf), "%s/%s", s->smb_dir, "smb.conf");
  f = fopen(smb_conf, "w");
  if (!f) {
    slirp_smb_cleanup(s);
    error_report("could not create samba server configuration file '%s'",
                 smb_conf);
    return -1;
  }
  fprintf(f,
          "[global]\n"
          "private dir=%s\n"
          "interfaces=127.0.0.1\n"
          "bind interfaces only=yes\n"
          "pid directory=%s\n"
          "lock directory=%s\n"
          "state directory=%s\n"
          "cache directory=%s\n"
          "ncalrpc dir=%scalrpc\n"
          "log file=%s/log.smbd\n"
          "smb passwd file=%s/smbpasswd\n"
          "security = user\n"
          "map to guest = Bad User\n"
          "load printers = no\n"
          "printing = bsd\n"
          "disable spoolss = yes\n"
          "usershare max shares = 0\n"
          "[qemu]\n"
          "path=%s\n"
          "read only=no\n"
          "guest ok=yes\n"
          "force user=%s\n",
          s->smb_dir, s->smb_dir, s->smb_dir, s->smb_dir, s->smb_dir,
          s->smb_dir, s->smb_dir, s->smb_dir, exported_dir, passwd->pw_name);
  fclose(f);
  snprintf(smb_cmdline, sizeof(smb_cmdline), "%s -l %s -s %s",
           CONFIG_SMBD_COMMAND, s->smb_dir, smb_conf);
  if (slirp_add_exec(s->slirp, 0, smb_cmdline, &vserver_addr, 139) < 0 ||
      slirp_add_exec(s->slirp, 0, smb_cmdline, &vserver_addr, 445) < 0) {
    slirp_smb_cleanup(s);
    error_report("conflicting/invalid smbserver address");
    return -1;
  }
  return 0;
}

