static int _evdns_nameserver_add_impl(unsigned long int address, int port) {
  const struct nameserver *server = server_head, *const started_at =
                                                     server_head;
  struct nameserver *ns;
  int err = 0;
  if (server) {
    do {
      if (server->address == address)
        return 3;
      server = server->next;
    } while (server != started_at);
  }
  ns = (struct nameserver *)malloc(sizeof(struct nameserver));
  if (!ns)
    return -1;
  memset(ns, 0, sizeof(struct nameserver));
  evtimer_set(&ns->timeout_event, nameserver_prod_callback, ns);
  ns->socket = socket(PF_INET, SOCK_DGRAM, 0);
  if (ns->socket < 0) {
    err = 1;
    goto out1;
  }
  FD_CLOSEONEXEC(ns->socket);
  evutil_make_socket_nonblocking(ns->socket);
  ns->address = address;
  ns->port = htons(port);
  ns->state = 1;
  event_set(&ns->event, ns->socket, EV_READ | EV_PERSIST,
            nameserver_ready_callback, ns);
  if (event_add(&ns->event, NULL) < 0) {
    err = 2;
    goto out2;
  }
  log(EVDNS_LOG_DEBUG, "Added nameserver %s", debug_ntoa(address));
  if (!server_head) {
    ns->next = ns->prev = ns;
    server_head = ns;
  } else {
    ns->next = server_head->next;
    ns->prev = server_head;
    server_head->next = ns;
    if (server_head->prev == server_head) {
      server_head->prev = ns;
    }
  }
  global_good_nameservers++;
  return 0;
out2:
  CLOSE_SOCKET(ns->socket);
out1:
  free(ns);
  log(EVDNS_LOG_WARN, "Unable to add nameserver %s: error %d",
      debug_ntoa(address), err);
  return err;
}

int av_image_fill_pointers(uint8_t *data[4], enum PixelFormat pix_fmt,
                           int height, uint8_t *ptr, const int linesizes[4]) {
  int i, total_size, size[4], has_plane[4];
  const AVPixFmtDescriptor *desc = &av_pix_fmt_descriptors[pix_fmt];
  memset(data, 0, sizeof(data[0]) * 4);
  memset(size, 0, sizeof(size));
  memset(has_plane, 0, sizeof(has_plane));
  if ((unsigned)pix_fmt >= PIX_FMT_NB || desc->flags & PIX_FMT_HWACCEL)
    return AVERROR(EINVAL);
  data[0] = ptr;
  if (linesizes[0] > (INT_MAX - 1024) / height)
    return AVERROR(EINVAL);
  size[0] = linesizes[0] * height;
  if (desc->flags & PIX_FMT_PAL) {
    size[0] = (size[0] + 3) & ~3;
    data[1] = ptr + size[0];
    return size[0] + 256 * 4;
  }
  for (i = 0; i < 4; i++)
    has_plane[desc->comp[i].plane] = 1;
  total_size = size[0];
  for (i = 1; i < 4 && has_plane[i]; i++) {
    int h, s = (i == 1 || i == 2) ? desc->log2_chroma_h : 0;
    data[i] = data[i - 1] + size[i - 1];
    h = (height + (1 << s) - 1) >> s;
    if (linesizes[i] > INT_MAX / h)
      return AVERROR(EINVAL);
    size[i] = h * linesizes[i];
    if (total_size > INT_MAX - size[i])
      return AVERROR(EINVAL);
    total_size += size[i];
  }
  return total_size;
}

