static void set_svc_parameters(SvcContext *svc_ctx,
                               vpx_codec_ctx_t *codec_ctx) {
  int layer, layer_index;
  vpx_svc_parameters_t svc_params;
  SvcInternal *const si = get_svc_internal(svc_ctx);
  memset(&svc_params, 0, sizeof(svc_params));
  svc_params.temporal_layer = 0;
  svc_params.spatial_layer = si->layer;
  layer = si->layer;
  if (VPX_CODEC_OK != vpx_svc_get_layer_resolution(svc_ctx, layer,
                                                   &svc_params.width,
                                                   &svc_params.height)) {
    svc_log(svc_ctx, SVC_LOG_ERROR, "vpx_svc_get_layer_resolution failed\n");
  }
  layer_index = layer + VPX_SS_MAX_LAYERS - si->layers;
  if (codec_ctx->config.enc->g_pass == VPX_RC_ONE_PASS) {
    svc_params.min_quantizer = si->quantizer[layer_index];
    svc_params.max_quantizer = si->quantizer[layer_index];
  } else {
    svc_params.min_quantizer = codec_ctx->config.enc->rc_min_quantizer;
    svc_params.max_quantizer = codec_ctx->config.enc->rc_max_quantizer;
  }
  svc_params.distance_from_i_frame = si->frame_within_gop;
  vpx_codec_control(codec_ctx, VP9E_SET_SVC_PARAMETERS, &svc_params);
}

static PyObject *authGSSServerInit(PyObject *self, PyObject *args) {
  const char *service = NULL;
  gss_server_state *state;
  PyObject *pystate;
  int result = 0;
  if (!PyArg_ParseTuple(args, "s", &service))
    return NULL;
  state = (gss_server_state *)malloc(sizeof(gss_server_state));
#if PY_MAJOR_VERSION >= 3 pystate = PyCapsule_New(state, NULL, NULL);
#else pystate = PyCObject_FromVoidPtr(state, NULL);
#endif result = authenticate_gss_server_init(service, state);
  if (result == AUTH_GSS_ERROR)
    return NULL;
  return Py_BuildValue("(iO)", result, pystate);
}

static vpx_codec_err_t encoder_set_config(vpx_codec_alg_priv_t *ctx,
                                          const vpx_codec_enc_cfg_t *cfg) {
  vpx_codec_err_t res;
  if (cfg->g_w != ctx->cfg.g_w || cfg->g_h != ctx->cfg.g_h)
    ERROR("Cannot change width or height after initialization");
  if (cfg->g_lag_in_frames > ctx->cfg.g_lag_in_frames)
    ERROR("Cannot increase lag_in_frames");
  res = validate_config(ctx, cfg, &ctx->extra_cfg);
  if (res == VPX_CODEC_OK) {
    ctx->cfg = *cfg;
    set_encoder_config(&ctx->oxcf, &ctx->cfg, &ctx->extra_cfg);
    vp9_change_config(ctx->cpi, &ctx->oxcf);
  }
  return res;
}

static void parse_content_disposition(const char *content_disposition,
                                      const char **filename_r) {
  struct rfc822_parser_context parser;
  const char *const *results, *filename2;
  string_t *str;
  *filename_r = NULL;
  if (content_disposition == NULL)
    return;
  rfc822_parser_init(&parser, (const unsigned char *)content_disposition,
                     strlen(content_disposition), NULL);
  rfc822_skip_lwsp(&parser);
  str = t_str_new(32);
  if (rfc822_parse_mime_token(&parser, str) < 0) {
    rfc822_parser_deinit(&parser);
    return;
  }
  rfc2231_parse(&parser, &results);
  filename2 = NULL;
  for (; *results != NULL; results += 2) {
    if (strcasecmp(results[0], "filename") == 0) {
      *filename_r = results[1];
      break;
    }
    if (strcasecmp(results[0], "filename*") == 0)
      filename2 = results[1];
  }
  if (*filename_r == NULL) {
    *filename_r = filename2;
  }
  rfc822_parser_deinit(&parser);
}

static int header_bin_le(struct archive_read *a, struct cpio *cpio,
                         struct archive_entry *entry, size_t *namelength,
                         size_t *name_pad) {
  const void *h;
  const unsigned char *header;
  a->archive.archive_format = ARCHIVE_FORMAT_CPIO_BIN_LE;
  a->archive.archive_format_name = "cpio (little-endian binary)";
  h = __archive_read_ahead(a, bin_header_size, NULL);
  if (h == NULL) {
    archive_set_error(&a->archive, 0,
                      "End of file trying to read next cpio header");
    return (ARCHIVE_FATAL);
  }
  header = (const unsigned char *)h;
  archive_entry_set_dev(entry, header[bin_dev_offset] +
                                   header[bin_dev_offset + 1] * 256);
  archive_entry_set_ino(entry, header[bin_ino_offset] +
                                   header[bin_ino_offset + 1] * 256);
  archive_entry_set_mode(entry, header[bin_mode_offset] +
                                    header[bin_mode_offset + 1] * 256);
  archive_entry_set_uid(entry, header[bin_uid_offset] +
                                   header[bin_uid_offset + 1] * 256);
  archive_entry_set_gid(entry, header[bin_gid_offset] +
                                   header[bin_gid_offset + 1] * 256);
  archive_entry_set_nlink(entry, header[bin_nlink_offset] +
                                     header[bin_nlink_offset + 1] * 256);
  archive_entry_set_rdev(entry, header[bin_rdev_offset] +
                                    header[bin_rdev_offset + 1] * 256);
  archive_entry_set_mtime(entry, le4(header + bin_mtime_offset), 0);
  *namelength =
      header[bin_namesize_offset] + header[bin_namesize_offset + 1] * 256;
  *name_pad = *namelength & 1;
  cpio->entry_bytes_remaining = le4(header + bin_filesize_offset);
  archive_entry_set_size(entry, cpio->entry_bytes_remaining);
  cpio->entry_padding = cpio->entry_bytes_remaining & 1;
  __archive_read_consume(a, bin_header_size);
  return (ARCHIVE_OK);
}

static inline void xan_wc3_output_pixel_run(XanContext *s, AVFrame *frame,
                                            const unsigned char *pixel_buffer,
                                            int x, int y, int pixel_count) {
  int stride;
  int line_inc;
  int index;
  int current_x;
  int width = s->avctx->width;
  unsigned char *palette_plane;
  palette_plane = frame->data[0];
  stride = frame->linesize[0];
  line_inc = stride - width;
  index = y * stride + x;
  current_x = x;
  while (pixel_count && index < s->frame_size) {
    int count = FFMIN(pixel_count, width - current_x);
    memcpy(palette_plane + index, pixel_buffer, count);
    pixel_count -= count;
    index += count;
    pixel_buffer += count;
    current_x += count;
    if (current_x >= width) {
      index += line_inc;
      current_x = 0;
    }
  }
}

static Asn1Generic *DecodeAsn1DerGeneric(const unsigned char *buffer,
                                         uint32_t max_size, uint8_t depth,
                                         int seq_index, uint32_t *errcode) {
  const unsigned char *d_ptr = buffer;
  uint32_t numbytes, el_max_size;
  Asn1ElementType el;
  uint8_t c;
  uint32_t i;
  Asn1Generic *child;
  uint8_t el_type;
  el.cls = (d_ptr[0] & 0xc0) >> 6;
  el.pc = (d_ptr[0] & 0x20) >> 5;
  el.tag = (d_ptr[0] & 0x1f);
  el_type = el.tag;
  if (el.tag == 0x1f)
    return NULL;
  switch (el.cls) {
  case ASN1_CLASS_CONTEXTSPEC:
    if (depth == 2 && el.tag == 0) {
      el_type = ASN1_SEQUENCE;
      break;
    }
    if (depth == 2 && el.tag == 1) {
      el_type = ASN1_BITSTRING;
      break;
    }
    if (depth == 2 && el.tag == 2) {
      el_type = ASN1_BITSTRING;
      break;
    }
    if (depth == 2 && el.tag == 3) {
      el_type = ASN1_SEQUENCE;
      break;
    }
    break;
  };
  el_max_size = max_size - (d_ptr - buffer);
  switch (el_type) {
  case ASN1_INTEGER:
    child = DecodeAsn1DerInteger(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_BOOLEAN:
    child = DecodeAsn1DerBoolean(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_NULL:
    child = DecodeAsn1DerNull(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_BITSTRING:
    child = DecodeAsn1DerBitstring(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_OID:
    child = DecodeAsn1DerOid(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_IA5STRING:
    child = DecodeAsn1DerIA5String(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_OCTETSTRING:
    child = DecodeAsn1DerOctetString(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_UTF8STRING:
    child = DecodeAsn1DerUTF8String(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_PRINTSTRING:
    child =
        DecodeAsn1DerPrintableString(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_SEQUENCE:
    child = DecodeAsn1DerSequence(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_SET:
    child = DecodeAsn1DerSet(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_T61STRING:
    child = DecodeAsn1DerT61String(d_ptr, el_max_size, depth + 1, errcode);
    break;
  case ASN1_UTCTIME:
    child = DecodeAsn1DerUTCTime(d_ptr, el_max_size, depth + 1, errcode);
    break;
  default:
    child = NULL;
    child = Asn1GenericNew();
    if (child == NULL)
      break;
    child->type = el.tag;
    const unsigned char *save_d_ptr = d_ptr;
    d_ptr++;
    c = d_ptr[0];
    if ((c & (1 << 7)) >> 7 == 0) {
      child->length = c;
      d_ptr++;
    } else {
      numbytes = c & 0x7f;
      if (numbytes > el_max_size) {
        SCFree(child);
        if (errcode)
          *errcode = ERR_DER_ELEMENT_SIZE_TOO_BIG;
        return NULL;
      }
      child->length = 0;
      d_ptr++;
      for (i = 0; i < numbytes; i++) {
        child->length = child->length << 8 | d_ptr[0];
        d_ptr++;
      }
    }
    child->length += (d_ptr - save_d_ptr);
    break;
  };
  if (child == NULL)
    return NULL;
  child->header = el;
  return child;
}

static void log_read_interval(const ReadInterval *interval, void *log_ctx,
                              int log_level) {
  av_log(log_ctx, log_level, "id:%d", interval->id);
  if (interval->has_start) {
    av_log(log_ctx, log_level, " start:%s%s",
           interval->start_is_offset ? "+" : "",
           av_ts2timestr(interval->start, &AV_TIME_BASE_Q));
  } else {
    av_log(log_ctx, log_level, " start:N/A");
  }
  if (interval->has_end) {
    av_log(log_ctx, log_level, " end:%s", interval->end_is_offset ? "+" : "");
    if (interval->duration_frames)
      av_log(log_ctx, log_level, "#%" PRId64, interval->end);
    else
      av_log(log_ctx, log_level, "%s",
             av_ts2timestr(interval->end, &AV_TIME_BASE_Q));
  } else {
    av_log(log_ctx, log_level, " end:N/A");
  }
  av_log(log_ctx, log_level, "\n");
}

static int cmp_mpihex(gcry_mpi_t a, const char *b) {
  gcry_mpi_t bval;
  int res;
  bval = hex2mpi(b);
  res = gcry_mpi_cmp(a, bval);
  gcry_mpi_release(bval);
  return res;
}

static void mpa_packetlist(packet_info *pinfo, gint message_type) {
  col_set_str(pinfo->cinfo, COL_PROTOCOL, "MPA");
  col_add_fstr(pinfo->cinfo, COL_INFO, "%d > %d %s", pinfo->srcport,
               pinfo->destport,
               val_to_str(message_type, mpa_messages, "Unknown %d"));
}

static int init_er(MpegEncContext *s) {
  ERContext *er = &s->er;
  int mb_array_size = s->mb_height * s->mb_stride;
  int i;
  er->avctx = s->avctx;
  er->dsp = &s->dsp;
  er->mb_index2xy = s->mb_index2xy;
  er->mb_num = s->mb_num;
  er->mb_width = s->mb_width;
  er->mb_height = s->mb_height;
  er->mb_stride = s->mb_stride;
  er->b8_stride = s->b8_stride;
  er->er_temp_buffer = av_malloc(s->mb_height * s->mb_stride);
  er->error_status_table = av_mallocz(mb_array_size);
  if (!er->er_temp_buffer || !er->error_status_table)
    goto fail;
  er->mbskip_table = s->mbskip_table;
  er->mbintra_table = s->mbintra_table;
  for (i = 0; i < FF_ARRAY_ELEMS(s->dc_val); i++)
    er->dc_val[i] = s->dc_val[i];
  er->decode_mb = mpeg_er_decode_mb;
  er->opaque = s;
  return 0;
fail:
  av_freep(&er->er_temp_buffer);
  av_freep(&er->error_status_table);
  return AVERROR(ENOMEM);
}

