static void lsf2lsp_5(AMRContext *p) {
  const uint16_t *lsf_param = p->frame.lsf;
  float lsf_no_r[LP_FILTER_ORDER];
  const int16_t *lsf_quantizer[5];
  int i;
  lsf_quantizer[0] = lsf_5_1[lsf_param[0]];
  lsf_quantizer[1] = lsf_5_2[lsf_param[1]];
  lsf_quantizer[2] = lsf_5_3[lsf_param[2] >> 1];
  lsf_quantizer[3] = lsf_5_4[lsf_param[3]];
  lsf_quantizer[4] = lsf_5_5[lsf_param[4]];
  for (i = 0; i < LP_FILTER_ORDER; i++)
    lsf_no_r[i] =
        p->prev_lsf_r[i] * LSF_R_FAC * PRED_FAC_MODE_12k2 + lsf_5_mean[i];
  lsf2lsp_for_mode12k2(p, p->lsp[1], lsf_no_r, lsf_quantizer, 0,
                       lsf_param[2] & 1, 0);
  lsf2lsp_for_mode12k2(p, p->lsp[3], lsf_no_r, lsf_quantizer, 2,
                       lsf_param[2] & 1, 1);
  weighted_vector_sumd(p->lsp[0], p->prev_lsp_sub4, p->lsp[1], 0.5, 0.5,
                       LP_FILTER_ORDER);
  weighted_vector_sumd(p->lsp[2], p->lsp[1], p->lsp[3], 0.5, 0.5,
                       LP_FILTER_ORDER);
}

int ssl3_send_finished(SSL *s, int a, int b, const char *sender, int slen) {
  unsigned char *p, *d;
  int i;
  unsigned long l;
  if (s->state == a) {
    d = (unsigned char *)s->init_buf->data;
    p = &(d[4]);
    i = s->method->ssl3_enc->final_finish_mac(s, sender, slen,
                                              s->s3->tmp.finish_md);
    s->s3->tmp.finish_md_len = i;
    memcpy(p, s->s3->tmp.finish_md, i);
    p += i;
    l = i;
    if (s->type == SSL_ST_CONNECT) {
      OPENSSL_assert(i <= EVP_MAX_MD_SIZE);
      memcpy(s->s3->previous_client_finished, s->s3->tmp.finish_md, i);
      s->s3->previous_client_finished_len = i;
    } else {
      OPENSSL_assert(i <= EVP_MAX_MD_SIZE);
      memcpy(s->s3->previous_server_finished, s->s3->tmp.finish_md, i);
      s->s3->previous_server_finished_len = i;
    }
#ifdef OPENSSL_SYS_WIN16 l &= 0xffff;
#endif *(d++) = SSL3_MT_FINISHED;
    l2n3(l, d);
    s->init_num = (int)l + 4;
    s->init_off = 0;
    s->state = b;
  }
  return (ssl3_do_write(s, SSL3_RT_HANDSHAKE));
}

int DSA_verify(int type, const unsigned char *dgst, int dgst_len,
               const unsigned char *sigbuf, int siglen, DSA *dsa) {
  DSA_SIG *s;
  int ret = -1;
  s = DSA_SIG_new();
  if (s == NULL)
    return (ret);
  if (d2i_DSA_SIG(&s, &sigbuf, siglen) == NULL)
    goto err;
  ret = DSA_do_verify(dgst, dgst_len, s, dsa);
err:
  DSA_SIG_free(s);
  return (ret);
}

