static int dissect_rsl(tvbuff_t *tvb, packet_info *pinfo, proto_tree *tree,
                       void *data _U_) {
  proto_item *ti;
  proto_tree *rsl_tree;
  guint8 msg_type;
  int offset = 0;
  col_set_str(pinfo->cinfo, COL_PROTOCOL, "RSL");
  col_clear(pinfo->cinfo, COL_INFO);
  msg_type = tvb_get_guint8(tvb, offset + 1) & 0x7f;
  col_append_fstr(
      pinfo->cinfo, COL_INFO, "%s ",
      val_to_str_ext(msg_type, &rsl_msg_type_vals_ext, "unknown %u"));
  top_tree = tree;
  ti = proto_tree_add_item(tree, proto_rsl, tvb, 0, -1, ENC_NA);
  if (!global_rsl_use_nano_bts) {
    guint8 msg_disc = tvb_get_guint8(tvb, offset) >> 1;
    if (msg_disc == RSL_MSGDISC_IPACCESS)
      return 0;
  }
  rsl_tree = proto_item_add_subtree(ti, ett_rsl);
  proto_tree_add_item(rsl_tree, hf_rsl_msg_dsc, tvb, offset, 1, ENC_BIG_ENDIAN);
  proto_tree_add_item(rsl_tree, hf_rsl_T_bit, tvb, offset, 1, ENC_BIG_ENDIAN);
  offset = dissct_rsl_msg(tvb, pinfo, rsl_tree, offset);
  return offset;
}

const char *trunc_left(const char *src, size_t width) {
  size_t sl;
  char *out;
  sl = strlen(src);
  if (sl > width && LIB_BUFLENGTH - 1 > width && width > 1) {
    LIB_GETBUF(out);
    out[0] = '_';
    memcpy(&out[1], &src[sl + 1 - width], width);
    return out;
  }
  return src;
}

static int read_huffman_tree(AVCodecContext *avctx, GetBitContext *gb) {
  Vp3DecodeContext *s = avctx->priv_data;
  if (get_bits1(gb)) {
    int token;
    if (s->entries >= 32) {
      av_log(avctx, AV_LOG_ERROR, "huffman tree overflow\n");
      return -1;
    }
    token = get_bits(gb, 5);
    av_dlog(avctx, "hti %d hbits %x token %d entry : %d size %d\n", s->hti,
            s->hbits, token, s->entries, s->huff_code_size);
    s->huffman_table[s->hti][token][0] = s->hbits;
    s->huffman_table[s->hti][token][1] = s->huff_code_size;
    s->entries++;
  } else {
    if (s->huff_code_size >= 32) {
      av_log(avctx, AV_LOG_ERROR, "huffman tree overflow\n");
      return -1;
    }
    s->huff_code_size++;
    s->hbits <<= 1;
    if (read_huffman_tree(avctx, gb))
      return -1;
    s->hbits |= 1;
    if (read_huffman_tree(avctx, gb))
      return -1;
    s->hbits >>= 1;
    s->huff_code_size--;
  }
  return 0;
}

