static void dissect_rsvp_msg_tree(tvbuff_t *tvb, packet_info *pinfo,
                                  proto_tree *tree, int tree_mode,
                                  rsvp_conversation_info *rsvph,
                                  gboolean e2ei) {
  proto_tree *rsvp_tree;
  proto_tree *rsvp_header_tree;
  proto_tree *rsvp_object_tree;
  proto_tree *ti, *len_item;
  proto_item *hidden_item, *cksum_item;
  guint16 cksum, computed_cksum;
  vec_t cksum_vec[1];
  int offset = 0;
  int len;
  guint8 message_type;
  int session_off, tempfilt_off;
  int msg_length;
  int obj_length;
  gboolean have_integrity_object = FALSE;
  offset = 0;
  msg_length = tvb_get_ntohs(tvb, 6);
  message_type = tvb_get_guint8(tvb, 1);
  ti = proto_tree_add_item(tree, proto_rsvp, tvb, offset, msg_length, ENC_NA);
  rsvp_tree = proto_item_add_subtree(ti, tree_mode);
  if (e2ei)
    proto_item_append_text(rsvp_tree, " (E2E-IGNORE)");
  proto_item_append_text(rsvp_tree, ": ");
  proto_item_append_text(
      rsvp_tree, "%s",
      val_to_str_ext(message_type, &message_type_vals_ext, "Unknown (%u). "));
  find_rsvp_session_tempfilt(tvb, 0, &session_off, &tempfilt_off);
  if (session_off)
    proto_item_append_text(rsvp_tree, "%s", summary_session(tvb, session_off));
  if (tempfilt_off)
    proto_item_append_text(rsvp_tree, "%s",
                           summary_template(tvb, tempfilt_off));
  rsvp_header_tree = proto_tree_add_subtree_format(
      rsvp_tree, tvb, offset, 8, TREE(TT_HDR), &ti, "RSVP Header. %s",
      val_to_str_ext(message_type, &message_type_vals_ext,
                     "Unknown Message (%u). "));
  if (e2ei)
    proto_item_append_text(ti, " (E2E-IGNORE)");
  proto_tree_add_item(rsvp_header_tree, hf_rsvp_version, tvb, offset, 1,
                      ENC_BIG_ENDIAN);
  proto_tree_add_item(rsvp_header_tree, hf_rsvp_flags, tvb, offset, 1,
                      ENC_BIG_ENDIAN);
  proto_tree_add_uint(rsvp_header_tree, hf_rsvp_filter[RSVPF_MSG], tvb,
                      offset + 1, 1, message_type);
  switch (RSVPF_MSG + message_type) {
  case RSVPF_PATH:
  case RSVPF_RESV:
  case RSVPF_PATHERR:
  case RSVPF_RESVERR:
  case RSVPF_PATHTEAR:
  case RSVPF_RESVTEAR:
  case RSVPF_RCONFIRM:
  case RSVPF_RTEARCONFIRM:
  case RSVPF_BUNDLE:
  case RSVPF_ACK:
  case RSVPF_SREFRESH:
  case RSVPF_HELLO:
  case RSVPF_NOTIFY:
    hidden_item = proto_tree_add_boolean(
        rsvp_header_tree, hf_rsvp_filter[RSVPF_MSG + message_type], tvb,
        offset + 1, 1, 1);
    PROTO_ITEM_SET_HIDDEN(hidden_item);
    break;
  }
  cksum = tvb_get_ntohs(tvb, offset + 2);
  cksum_item = proto_tree_add_item(rsvp_header_tree, hf_rsvp_message_checksum,
                                   tvb, offset + 2, 2, ENC_BIG_ENDIAN);
  proto_tree_add_item(rsvp_header_tree, hf_rsvp_sending_ttl, tvb, offset + 4, 1,
                      ENC_BIG_ENDIAN);
  proto_tree_add_item(rsvp_header_tree, hf_rsvp_message_length, tvb, offset + 6,
                      2, ENC_BIG_ENDIAN);
  offset = 8;
  len = 8;
  if (message_type == RSVP_MSG_BUNDLE) {
    if (rsvp_bundle_dissect) {
      int len2 = 8;
      while (len2 < msg_length) {
        gint sub_len;
        tvbuff_t *tvb_sub;
        sub_len = tvb_get_ntohs(tvb, len2 + 6);
        tvb_sub = tvb_new_subset_length(tvb, len2, sub_len);
        dissect_rsvp_msg_tree(tvb_sub, pinfo, rsvp_tree,
                              TREE(TT_BUNDLE_COMPMSG), rsvph, e2ei);
        len2 += sub_len;
      }
    } else {
      proto_tree_add_expert(rsvp_tree, pinfo, &ei_rsvp_bundle_component_msg,
                            tvb, offset, msg_length - len);
    }
    return;
  }
  while (len < msg_length) {
    guint8 rsvp_class;
    guint8 type;
    obj_length = tvb_get_ntohs(tvb, offset);
    rsvp_class = tvb_get_guint8(tvb, offset + 2);
    type = tvb_get_guint8(tvb, offset + 3);
    ti = proto_tree_add_item(
        rsvp_tree, hf_rsvp_filter[rsvp_class_to_filter_num(rsvp_class)], tvb,
        offset, obj_length, ENC_BIG_ENDIAN);
    rsvp_object_tree =
        proto_item_add_subtree(ti, TREE(rsvp_class_to_tree_type(rsvp_class)));
    len_item = proto_tree_add_item(rsvp_object_tree, hf_rsvp_length, tvb,
                                   offset, 2, ENC_BIG_ENDIAN);
    if (obj_length < 4) {
      expert_add_info_format(pinfo, len_item, &ei_rsvp_invalid_length,
                             "Length: %u (bogus, must be >= 4)", obj_length);
      break;
    }
    proto_tree_add_uint(rsvp_object_tree, hf_rsvp_filter[RSVPF_OBJECT], tvb,
                        offset + 2, 1, rsvp_class);
    switch (rsvp_class) {
    case RSVP_CLASS_SESSION:
      dissect_rsvp_session(ti, rsvp_object_tree, tvb, offset, obj_length,
                           rsvp_class, type, rsvph);
      break;
    case RSVP_CLASS_HOP:
      dissect_rsvp_hop(ti, pinfo, rsvp_object_tree, tvb, offset, obj_length,
                       rsvp_class, type);
      break;
    case RSVP_CLASS_TIME_VALUES:
      dissect_rsvp_time_values(ti, rsvp_object_tree, tvb, offset, obj_length,
                               rsvp_class, type);
      break;
    case RSVP_CLASS_ERROR:
      dissect_rsvp_error(ti, pinfo, rsvp_object_tree, tvb, offset, obj_length,
                         rsvp_class, type);
      break;
    case RSVP_CLASS_SCOPE:
      dissect_rsvp_scope(ti, rsvp_object_tree, tvb, offset, obj_length,
                         rsvp_class, type);
      break;
    case RSVP_CLASS_STYLE:
      dissect_rsvp_style(ti, rsvp_object_tree, tvb, offset, obj_length,
                         rsvp_class, type);
      break;
    case RSVP_CLASS_CONFIRM:
      dissect_rsvp_confirm(ti, rsvp_object_tree, tvb, offset, obj_length,
                           rsvp_class, type);
      break;
    case RSVP_CLASS_SENDER_TEMPLATE:
    case RSVP_CLASS_FILTER_SPEC:
      dissect_rsvp_template_filter(ti, rsvp_object_tree, tvb, offset,
                                   obj_length, rsvp_class, type, rsvph);
      break;
    case RSVP_CLASS_SENDER_TSPEC:
      dissect_rsvp_tspec(ti, pinfo, rsvp_object_tree, tvb, offset, obj_length,
                         rsvp_class, type);
      break;
    case RSVP_CLASS_FLOWSPEC:
      dissect_rsvp_flowspec(ti, pinfo, rsvp_object_tree, tvb, offset,
                            obj_length, rsvp_class, type);
      break;
    case RSVP_CLASS_ADSPEC:
      dissect_rsvp_adspec(ti, pinfo, rsvp_object_tree, tvb, offset, obj_length,
                          rsvp_class, type);
      break;
    case RSVP_CLASS_INTEGRITY:
      have_integrity_object = TRUE;
