static int check_bits_for_superframe(GetBitContext *orig_gb,
                                     WMAVoiceContext *s) {
  GetBitContext s_gb, *gb = &s_gb;
  int n, need_bits, bd_idx;
  const struct frame_type_desc *frame_desc;
  init_get_bits(gb, orig_gb->buffer, orig_gb->size_in_bits);
  skip_bits_long(gb, get_bits_count(orig_gb));
  assert(get_bits_left(gb) == get_bits_left(orig_gb));
  if (get_bits_left(gb) < 14)
    return 1;
  if (!get_bits1(gb))
    return -1;
  if (get_bits1(gb))
    skip_bits(gb, 12);
  if (s->has_residual_lsps) {
    if (get_bits_left(gb) < s->sframe_lsp_bitsize)
      return 1;
    skip_bits_long(gb, s->sframe_lsp_bitsize);
  }
  for (n = 0; n < MAX_FRAMES; n++) {
    int aw_idx_is_ext = 0;
    if (!s->has_residual_lsps) {
      if (get_bits_left(gb) < s->frame_lsp_bitsize)
        return 1;
      skip_bits_long(gb, s->frame_lsp_bitsize);
    }
    bd_idx = s->vbm_tree[get_vlc2(gb, frame_type_vlc.table, 6, 3)];
    if (bd_idx < 0)
      return -1;
    frame_desc = &frame_descs[bd_idx];
    if (frame_desc->acb_type == ACB_TYPE_ASYMMETRIC) {
      if (get_bits_left(gb) < s->pitch_nbits)
        return 1;
      skip_bits_long(gb, s->pitch_nbits);
    }
    if (frame_desc->fcb_type == FCB_TYPE_SILENCE) {
      skip_bits(gb, 8);
    } else if (frame_desc->fcb_type == FCB_TYPE_AW_PULSES) {
      int tmp = get_bits(gb, 6);
      if (tmp >= 0x36) {
        skip_bits(gb, 2);
        aw_idx_is_ext = 1;
      }
    }
    if (frame_desc->acb_type == ACB_TYPE_HAMMING) {
      need_bits = s->block_pitch_nbits +
                  (frame_desc->n_blocks - 1) * s->block_delta_pitch_nbits;
    } else if (frame_desc->fcb_type == FCB_TYPE_AW_PULSES) {
      need_bits = 2 * !aw_idx_is_ext;
    } else
      need_bits = 0;
    need_bits += frame_desc->frame_size;
    if (get_bits_left(gb) < need_bits)
      return 1;
    skip_bits_long(gb, need_bits);
  }
  return 0;
}

static void dissect_glabel_g709(proto_tree *ti _U_,
                                proto_tree *rsvp_object_tree, tvbuff_t *tvb,
                                int offset) {
  guint8 t1, t2, t3;
  proto_tree *g709_tree;
  g709_tree = proto_tree_add_subtree(rsvp_object_tree, tvb, offset, 4,
                                     TREE(TT_G709), NULL, "G.709 ODUk Label");
  proto_tree_add_item(g709_tree, hf_rsvp_g709_t3, tvb, offset + 2, 2,
                      ENC_BIG_ENDIAN);
  proto_tree_add_item(g709_tree, hf_rsvp_g709_t2, tvb, offset + 3, 1,
                      ENC_BIG_ENDIAN);
  proto_tree_add_item(g709_tree, hf_rsvp_g709_t1, tvb, offset + 3, 1,
                      ENC_BIG_ENDIAN);
  t2 = ((tvb_get_guint8(tvb, offset + 3) & 0x0E) >> 1);
  t1 = ((tvb_get_guint8(tvb, offset + 3) & 0x01) >> 0);
  t3 = ((tvb_get_guint8(tvb, offset + 2) & 0x03) << 4);
  t3 |= ((tvb_get_guint8(tvb, offset + 3) & 0xF0) >> 4);
  proto_item_append_text(ti,
                         ": G.709 ODUk: "
                         "t3=%u, "
                         "t2=%u, "
                         "t1=%u",
                         t3, t2, t1);
}

