void aes_setkey_dec(aes_context *ctx, const unsigned char *key, int keysize) {
  int i, j;
  aes_context cty;
  unsigned long *RK;
  unsigned long *SK;
  switch (keysize) {
  case 128:
    ctx->nr = 10;
    break;
  case 192:
    ctx->nr = 12;
    break;
  case 256:
    ctx->nr = 14;
    break;
  default:
    return;
  }
#if defined(PADLOCK_ALIGN16) ctx->rk = RK = PADLOCK_ALIGN16(ctx->buf);
#else ctx->rk = RK = ctx->buf;
#endif aes_setkey_enc(&cty, key, keysize);
  SK = cty.rk + cty.nr * 4;
  *RK++ = *SK++;
  *RK++ = *SK++;
  *RK++ = *SK++;
  *RK++ = *SK++;
  for (i = ctx->nr - 1, SK -= 8; i > 0; i--, SK -= 8) {
    for (j = 0; j < 4; j++, SK++) {
      *RK++ = RT0[FSb[(*SK) & 0xFF]] ^ RT1[FSb[(*SK >> 8) & 0xFF]] ^
              RT2[FSb[(*SK >> 16) & 0xFF]] ^ RT3[FSb[(*SK >> 24) & 0xFF]];
    }
  }
  *RK++ = *SK++;
  *RK++ = *SK++;
  *RK++ = *SK++;
  *RK++ = *SK++;
  memset(&cty, 0, sizeof(aes_context));
}

