static void vga_draw_line16_le(VGACommonState *s1, uint8_t *d, const uint8_t *s,
                               int width) {
  int w;
  uint32_t v, r, g, b;
  w = width;
  do {
    v = lduw_le_p((void *)s);
    r = (v >> 8) & 0xf8;
    g = (v >> 3) & 0xfc;
    b = (v << 3) & 0xf8;
    ((uint32_t *)d)[0] = rgb_to_pixel32(r, g, b);
    s += 2;
    d += 4;
  } while (--w != 0);
}

static int dissect_nlm_share(tvbuff_t *tvb, int offset, packet_info *pinfo,
                             proto_tree *tree, int version _U_,
                             rpc_call_info_value *civ) {
  proto_item *lock_item = NULL;
  proto_tree *lock_tree = NULL;
  guint32 fh_hash;
  offset = dissect_rpc_data(tvb, tree, hf_nlm_cookie, offset);
  if (tree) {
    lock_item =
        proto_tree_add_item(tree, hf_nlm_share, tvb, offset, -1, ENC_NA);
    if (lock_item)
      lock_tree = proto_item_add_subtree(lock_item, ett_nlm_lock);
  }
  offset =
      dissect_rpc_string(tvb, lock_tree, hf_nlm_lock_caller_name, offset, NULL);
  offset = dissect_nfs3_fh(tvb, offset, pinfo, lock_tree, "fh", &fh_hash, civ);
  col_append_fstr(pinfo->cinfo, COL_INFO, " FH:0x%08x", fh_hash);
  offset = dissect_rpc_data(tvb, lock_tree, hf_nlm_lock_owner, offset);
  offset = dissect_rpc_uint32(tvb, lock_tree, hf_nlm_share_mode, offset);
  offset = dissect_rpc_uint32(tvb, lock_tree, hf_nlm_share_access, offset);
  offset = dissect_rpc_bool(tvb, tree, hf_nlm_reclaim, offset);
  return offset;
}

static int aes_ocb_ctrl(EVP_CIPHER_CTX *c, int type, int arg, void *ptr) {
  EVP_AES_OCB_CTX *octx = EVP_C_DATA(EVP_AES_OCB_CTX, c);
  EVP_CIPHER_CTX *newc;
  EVP_AES_OCB_CTX *new_octx;
  switch (type) {
  case EVP_CTRL_INIT:
    octx->key_set = 0;
    octx->iv_set = 0;
    octx->ivlen = EVP_CIPHER_CTX_iv_length(c);
    octx->iv = EVP_CIPHER_CTX_iv_noconst(c);
    octx->taglen = 16;
    octx->data_buf_len = 0;
    octx->aad_buf_len = 0;
    return 1;
  case EVP_CTRL_AEAD_SET_IVLEN:
    if (arg <= 0 || arg > 15)
      return 0;
    octx->ivlen = arg;
    return 1;
  case EVP_CTRL_AEAD_SET_TAG:
    if (!ptr) {
      if (arg < 0 || arg > 16)
        return 0;
      octx->taglen = arg;
      return 1;
    }
    if (arg != octx->taglen || EVP_CIPHER_CTX_encrypting(c))
      return 0;
    memcpy(octx->tag, ptr, arg);
    return 1;
  case EVP_CTRL_AEAD_GET_TAG:
    if (arg != octx->taglen || !EVP_CIPHER_CTX_encrypting(c))
      return 0;
    memcpy(ptr, octx->tag, arg);
    return 1;
  case EVP_CTRL_COPY:
    newc = (EVP_CIPHER_CTX *)ptr;
    new_octx = EVP_C_DATA(EVP_AES_OCB_CTX, newc);
    return CRYPTO_ocb128_copy_ctx(&new_octx->ocb, &octx->ocb,
                                  &new_octx->ksenc.ks, &new_octx->ksdec.ks);
  default:
    return -1;
  }
}

