void fz_set_cmm_engine(fz_context *ctx, const fz_cmm_engine *engine) {
  fz_colorspace_context *cct;
  if (!ctx)
    return;
  cct = ctx->colorspace;
  if (!cct)
    return;
#ifdef NO_ICC if (engine) fz_throw(                                            \
    ctx, FZ_ERROR_GENERIC, "ICC workflow not supported in NO_ICC build");
#else if (cct->cmm == engine) return;
  fz_drop_cmm_context(ctx);
  fz_drop_colorspace(ctx, cct->gray);
  fz_drop_colorspace(ctx, cct->rgb);
  fz_drop_colorspace(ctx, cct->bgr);
  fz_drop_colorspace(ctx, cct->cmyk);
  fz_drop_colorspace(ctx, cct->lab);
  cct->gray = NULL;
  cct->rgb = NULL;
  cct->bgr = NULL;
  cct->cmyk = NULL;
  cct->lab = NULL;
  cct->cmm = engine;
  fz_new_cmm_context(ctx);
  if (engine) {
    cct->gray = fz_new_icc_colorspace(ctx, FZ_ICC_PROFILE_GRAY, 1, NULL);
    cct->rgb = fz_new_icc_colorspace(ctx, FZ_ICC_PROFILE_RGB, 3, NULL);
    cct->bgr = fz_new_icc_colorspace(ctx, FZ_ICC_PROFILE_BGR, 3, NULL);
    cct->cmyk = fz_new_icc_colorspace(ctx, FZ_ICC_PROFILE_CMYK, 4, NULL);
    cct->lab = fz_new_icc_colorspace(ctx, FZ_ICC_PROFILE_LAB, 3, NULL);
  } else
    set_no_icc(cct);
#endif }

static void sbr_neg_odd_64_c(float *x) {
  union av_intfloat32 *xi = (union av_intfloat32 *)x;
  int i;
  for (i = 1; i < 64; i += 4) {
    xi[i + 0].i ^= 1U << 31;
    xi[i + 2].i ^= 1U << 31;
  }
}

static void tokenize_b(int plane, int block, BLOCK_SIZE plane_bsize,
                       TX_SIZE tx_size, void *arg) {
  struct tokenize_b_args *const args = arg;
  VP9_COMP *cpi = args->cpi;
  MACROBLOCKD *xd = args->xd;
  TOKENEXTRA **tp = args->tp;
  uint8_t token_cache[32 * 32];
  struct macroblock_plane *p = &cpi->mb.plane[plane];
  struct macroblockd_plane *pd = &xd->plane[plane];
  MB_MODE_INFO *mbmi = &xd->mi[0]->mbmi;
  int pt;
  int c;
  TOKENEXTRA *t = *tp;
  int eob = p->eobs[block];
  const PLANE_TYPE type = pd->plane_type;
  const int16_t *qcoeff = BLOCK_OFFSET(p->qcoeff, block);
  const int segment_id = mbmi->segment_id;
  const int16_t *scan, *nb;
  const scan_order *so;
  const int ref = is_inter_block(mbmi);
  unsigned int(*const counts)[COEFF_CONTEXTS][ENTROPY_TOKENS] =
      cpi->coef_counts[tx_size][type][ref];
  vp9_prob(*const coef_probs)[COEFF_CONTEXTS][UNCONSTRAINED_NODES] =
      cpi->common.fc.coef_probs[tx_size][type][ref];
  unsigned int(*const eob_branch)[COEFF_CONTEXTS] =
      cpi->common.counts.eob_branch[tx_size][type][ref];
  const uint8_t *const band = get_band_translate(tx_size);
  const int seg_eob = get_tx_eob(&cpi->common.seg, segment_id, tx_size);
  int aoff, loff;
  txfrm_block_to_raster_xy(plane_bsize, tx_size, block, &aoff, &loff);
  pt = get_entropy_context(tx_size, pd->above_context + aoff,
                           pd->left_context + loff);
  so = get_scan(xd, tx_size, type, block);
  scan = so->scan;
  nb = so->neighbors;
  c = 0;
  while (c < eob) {
    int v = 0;
    int skip_eob = 0;
    v = qcoeff[scan[c]];
    while (!v) {
      add_token_no_extra(&t, coef_probs[band[c]][pt], ZERO_TOKEN, skip_eob,
                         counts[band[c]][pt]);
      eob_branch[band[c]][pt] += !skip_eob;
      skip_eob = 1;
      token_cache[scan[c]] = 0;
      ++c;
      pt = get_coef_context(nb, token_cache, c);
      v = qcoeff[scan[c]];
    }
    add_token(&t, coef_probs[band[c]][pt], vp9_dct_value_tokens_ptr[v].extra,
              (uint8_t)vp9_dct_value_tokens_ptr[v].token, (uint8_t)skip_eob,
              counts[band[c]][pt]);
    eob_branch[band[c]][pt] += !skip_eob;
    token_cache[scan[c]] =
        vp9_pt_energy_class[vp9_dct_value_tokens_ptr[v].token];
    ++c;
    pt = get_coef_context(nb, token_cache, c);
  }
  if (c < seg_eob) {
    add_token_no_extra(&t, coef_probs[band[c]][pt], EOB_TOKEN, 0,
                       counts[band[c]][pt]);
    ++eob_branch[band[c]][pt];
  }
  *tp = t;
  vp9_set_contexts(xd, pd, plane_bsize, tx_size, c > 0, aoff, loff);
}

static int create_and_bind(const char *host, const char *port, int protocol) {
  struct addrinfo hints;
  struct addrinfo *result, *rp, *ipv4v6bindall;
  int s, listen_sock = -1;
  memset(&hints, 0, sizeof(struct addrinfo));
  hints.ai_family = AF_UNSPEC;
  hints.ai_socktype = protocol == IPPROTO_TCP ? SOCK_STREAM : SOCK_DGRAM;
  hints.ai_flags = AI_PASSIVE | AI_ADDRCONFIG;
  hints.ai_protocol = protocol;
  s = getaddrinfo(host, port, &hints, &result);
  if (s != 0) {
    LOGE("getaddrinfo: %s", gai_strerror(s));
    return -1;
  }
  rp = result;
  if (!host) {
    ipv4v6bindall = result;
    while (ipv4v6bindall) {
      if (ipv4v6bindall->ai_family == AF_INET6) {
        rp = ipv4v6bindall;
        break;
      }
      ipv4v6bindall = ipv4v6bindall->ai_next;
    }
  }
  for (; rp != NULL; rp = rp->ai_next) {
    listen_sock = socket(rp->ai_family, rp->ai_socktype, rp->ai_protocol);
    if (listen_sock == -1) {
      continue;
    }
    if (rp->ai_family == AF_INET6) {
      int ipv6only = host ? 1 : 0;
      setsockopt(listen_sock, IPPROTO_IPV6, IPV6_V6ONLY, &ipv6only,
                 sizeof(ipv6only));
    }
    int opt = 1;
    setsockopt(listen_sock, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
#ifdef SO_NOSIGPIPE setsockopt(listen_sock, SOL_SOCKET, SO_NOSIGPIPE, &opt,    \
                               sizeof(opt));
#endif s = bind(listen_sock, rp->ai_addr, rp->ai_addrlen);
    if (s == 0) {
      close(listen_sock);
      break;
    } else {
      ERROR("bind");
    }
  }
  if (!result) {
    freeaddrinfo(result);
  }
  if (rp == NULL) {
    LOGE("Could not bind");
    return -1;
  }
  return listen_sock;
}

static UBool isWhitespace(UChar32 c) {
  switch (c) {
  case 0x000A:
  case 0x2029:
    lineCount++;
  case 0x000D:
  case 0x0020:
  case 0x0009:
  case 0xFEFF:
    return TRUE;
  default:
    return FALSE;
  }
}

static void scalar_dequant_float(COOKContext *q, int index, int quant_index,
                                 int *subband_coef_index,
                                 int *subband_coef_sign, float *mlt_p) {
  int i;
  float f1;
  for (i = 0; i < SUBBAND_SIZE; i++) {
    if (subband_coef_index[i]) {
      f1 = quant_centroid_tab[index][subband_coef_index[i]];
      if (subband_coef_sign[i])
        f1 = -f1;
    } else {
      f1 = dither_tab[index];
      if (av_lfg_get(&q->random_state) < 0x80000000)
        f1 = -f1;
    }
    mlt_p[i] = f1 * rootpow2tab[quant_index + 63];
  }
}

static void read_and_decode_spectrum(TwinContext *tctx, GetBitContext *gb,
                                     float *out, enum FrameType ftype) {
  const ModeTab *mtab = tctx->mtab;
  int channels = tctx->avctx->channels;
  int sub = mtab->fmode[ftype].sub;
  int block_size = mtab->size / sub;
  float gain[CHANNELS_MAX * SUBBLOCKS_MAX];
  float ppc_shape[PPC_SHAPE_LEN_MAX * CHANNELS_MAX * 4];
  uint8_t bark1[CHANNELS_MAX][SUBBLOCKS_MAX][BARK_N_COEF_MAX];
  uint8_t bark_use_hist[CHANNELS_MAX][SUBBLOCKS_MAX];
  uint8_t lpc_idx1[CHANNELS_MAX];
  uint8_t lpc_idx2[CHANNELS_MAX][LSP_SPLIT_MAX];
  uint8_t lpc_hist_idx[CHANNELS_MAX];
  int i, j, k;
  dequant(tctx, gb, out, ftype, mtab->fmode[ftype].cb0, mtab->fmode[ftype].cb1,
          mtab->fmode[ftype].cb_len_read);
  for (i = 0; i < channels; i++)
    for (j = 0; j < sub; j++)
      for (k = 0; k < mtab->fmode[ftype].bark_n_coef; k++)
        bark1[i][j][k] = get_bits(gb, mtab->fmode[ftype].bark_n_bit);
  for (i = 0; i < channels; i++)
    for (j = 0; j < sub; j++)
      bark_use_hist[i][j] = get_bits1(gb);
  dec_gain(tctx, gb, ftype, gain);
  for (i = 0; i < channels; i++) {
    lpc_hist_idx[i] = get_bits(gb, tctx->mtab->lsp_bit0);
    lpc_idx1[i] = get_bits(gb, tctx->mtab->lsp_bit1);
    for (j = 0; j < tctx->mtab->lsp_split; j++)
      lpc_idx2[i][j] = get_bits(gb, tctx->mtab->lsp_bit2);
  }
  if (ftype == FT_LONG) {
    int cb_len_p =
        (tctx->n_div[3] + mtab->ppc_shape_len * channels - 1) / tctx->n_div[3];
    dequant(tctx, gb, ppc_shape, FT_PPC, mtab->ppc_shape_cb,
            mtab->ppc_shape_cb + cb_len_p * PPC_SHAPE_CB_SIZE, cb_len_p);
  }
  for (i = 0; i < channels; i++) {
    float *chunk = out + mtab->size * i;
    float lsp[LSP_COEFS_MAX];
    for (j = 0; j < sub; j++) {
      dec_bark_env(tctx, bark1[i][j], bark_use_hist[i][j], i, tctx->tmp_buf,
                   gain[sub * i + j], ftype);
      tctx->fdsp.vector_fmul(chunk + block_size * j, chunk + block_size * j,
                             tctx->tmp_buf, block_size);
    }
    if (ftype == FT_LONG) {
      float pgain_step = 25000. / ((1 << mtab->pgain_bit) - 1);
      int p_coef = get_bits(gb, tctx->mtab->ppc_period_bit);
      int g_coef = get_bits(gb, tctx->mtab->pgain_bit);
      float v =
          1. / 8192 *
          mulawinv(pgain_step * g_coef + pgain_step / 2, 25000., PGAIN_MU);
      decode_ppc(tctx, p_coef, ppc_shape + i * mtab->ppc_shape_len, v, chunk);
    }
    decode_lsp(tctx, lpc_idx1[i], lpc_idx2[i], lpc_hist_idx[i], lsp,
               tctx->lsp_hist[i]);
    dec_lpc_spectrum_inv(tctx, lsp, ftype, tctx->tmp_buf);
    for (j = 0; j < mtab->fmode[ftype].sub; j++) {
      tctx->fdsp.vector_fmul(chunk, chunk, tctx->tmp_buf, block_size);
      chunk += block_size;
    }
  }
}

static int vp3_update_thread_context(AVCodecContext *dst,
                                     const AVCodecContext *src) {
  Vp3DecodeContext *s = dst->priv_data, *s1 = src->priv_data;
  int qps_changed = 0, i, err;
#define copy_fields                                                            \
  (to, from, start_field, end_field) memcpy(                                   \
      &to->start_field, &from->start_field,                                    \
      (char *)&to->end_field -                                                 \
          (char *)&to->start_field) if (!s1->current_frame.f->data[0] ||       \
                                        s->width != s1->width ||               \
                                        s->height != s1->height) {
  if (s != s1)
    ref_frames(s, s1);
  return -1;
}
if (s != s1) {
  if (!s->current_frame.f->data[0]) {
    int y_fragment_count, c_fragment_count;
    s->avctx = dst;
    err = allocate_tables(dst);
    if (err)
      return err;
    y_fragment_count = s->fragment_width[0] * s->fragment_height[0];
    c_fragment_count = s->fragment_width[1] * s->fragment_height[1];
    memcpy(s->motion_val[0], s1->motion_val[0],
           y_fragment_count * sizeof(*s->motion_val[0]));
    memcpy(s->motion_val[1], s1->motion_val[1],
           c_fragment_count * sizeof(*s->motion_val[1]));
  }
  if ((err = ref_frames(s, s1)) < 0)
    return err;
  s->keyframe = s1->keyframe;
  for (i = 0; i < 3; i++) {
    if (s->qps[i] != s1->qps[1]) {
      qps_changed = 1;
      memcpy(&s->qmat[i], &s1->qmat[i], sizeof(s->qmat[i]));
    }
  }
  if (s->qps[0] != s1->qps[0])
    memcpy(&s->bounding_values_array, &s1->bounding_values_array,
           sizeof(s->bounding_values_array));
  if (qps_changed)
    copy_fields(s, s1, qps, superblock_count);
#undef copy_fields }
  return update_frames(dst);
}

void bn_sqr_words(BN_ULONG *r, const BN_ULONG *a, int n) {
  if (n <= 0)
    return;
  while (n & ~3) {
    sqr(r[0], r[1], a[0]);
    sqr(r[2], r[3], a[1]);
    sqr(r[4], r[5], a[2]);
    sqr(r[6], r[7], a[3]);
    a += 4;
    r += 8;
    n -= 4;
  }
  if (n) {
    sqr(r[0], r[1], a[0]);
    if (--n == 0)
      return;
    sqr(r[2], r[3], a[1]);
    if (--n == 0)
      return;
    sqr(r[4], r[5], a[2]);
  }
}

static void mark_edge_parents_uninteresting(struct commit *commit,
                                            struct rev_info *revs,
                                            show_edge_fn show_edge) {
  struct commit_list *parents;
  for (parents = commit->parents; parents; parents = parents->next) {
    struct commit *parent = parents->item;
    if (!(parent->object.flags & UNINTERESTING))
      continue;
    mark_tree_uninteresting(parent->tree);
    if (revs->edge_hint && !(parent->object.flags & SHOWN)) {
      parent->object.flags |= SHOWN;
      show_edge(parent);
    }
  }
}

static bool contain_context_dependent_node_walker(Node *node, int *flags) {
  if (node == NULL)
    return false;
  if (IsA(node, CaseTestExpr))
    return !(*flags & CCDN_IN_CASEEXPR);
  if (IsA(node, CaseExpr)) {
    CaseExpr *caseexpr = (CaseExpr *)node;
    if (caseexpr->arg) {
      int save_flags = *flags;
      bool res;
      *flags |= CCDN_IN_CASEEXPR;
      res = expression_tree_walker(node, contain_context_dependent_node_walker,
                                   (void *)flags);
      *flags = save_flags;
      return res;
    }
  }
  return expression_tree_walker(node, contain_context_dependent_node_walker,
                                (void *)flags);
}

int jbig2_immediate_generic_region(Jbig2Ctx *ctx, Jbig2Segment *segment,
                                   const byte *segment_data) {
  Jbig2RegionSegmentInfo rsi;
  byte seg_flags;
  int8_t gbat[8];
  int offset;
  int gbat_bytes = 0;
  Jbig2GenericRegionParams params;
  int code = 0;
  Jbig2Image *image = NULL;
  Jbig2WordStream *ws = NULL;
  Jbig2ArithState *as = NULL;
  Jbig2ArithCx *GB_stats = NULL;
  if (segment->data_length < 18)
    return jbig2_error(ctx, JBIG2_SEVERITY_FATAL, segment->number,
                       "Segment too short");
  jbig2_get_region_segment_info(&rsi, segment_data);
  jbig2_error(ctx, JBIG2_SEVERITY_INFO, segment->number,
              "generic region: %d x %d @ (%d, %d), flags = %02x", rsi.width,
              rsi.height, rsi.x, rsi.y, rsi.flags);
  seg_flags = segment_data[17];
  jbig2_error(ctx, JBIG2_SEVERITY_INFO, segment->number, "segment flags = %02x",
              seg_flags);
  if ((seg_flags & 1) && (seg_flags & 6))
    jbig2_error(ctx, JBIG2_SEVERITY_WARNING, segment->number,
                "MMR is 1, but GBTEMPLATE is not 0");
  if (!(seg_flags & 1)) {
    gbat_bytes = (seg_flags & 6) ? 2 : 8;
    if (18 + gbat_bytes > segment->data_length)
      return jbig2_error(ctx, JBIG2_SEVERITY_FATAL, segment->number,
                         "Segment too short");
    memcpy(gbat, segment_data + 18, gbat_bytes);
    jbig2_error(ctx, JBIG2_SEVERITY_INFO, segment->number, "gbat: %d, %d",
                gbat[0], gbat[1]);
  }
  offset = 18 + gbat_bytes;
  params.MMR = seg_flags & 1;
  params.GBTEMPLATE = (seg_flags & 6) >> 1;
  params.TPGDON = (seg_flags & 8) >> 3;
  params.USESKIP = 0;
  memcpy(params.gbat, gbat, gbat_bytes);
  image = jbig2_image_new(ctx, rsi.width, rsi.height);
  if (image == NULL)
    return jbig2_error(ctx, JBIG2_SEVERITY_FATAL, segment->number,
                       "unable to allocate generic image");
  jbig2_error(ctx, JBIG2_SEVERITY_DEBUG, segment->number,
              "allocated %d x %d image buffer for region decode results",
              rsi.width, rsi.height);
  if (params.MMR) {
    code =
        jbig2_decode_generic_mmr(ctx, segment, &params, segment_data + offset,
                                 segment->data_length - offset, image);
  } else {
    int stats_size = jbig2_generic_stats_size(ctx, params.GBTEMPLATE);
    GB_stats = jbig2_new(ctx, Jbig2ArithCx, stats_size);
    if (GB_stats == NULL) {
      code = jbig2_error(
          ctx, JBIG2_SEVERITY_FATAL, segment->number,
          "unable to allocate GB_stats in jbig2_immediate_generic_region");
      goto cleanup;
    }
    memset(GB_stats, 0, stats_size);
    ws = jbig2_word_stream_buf_new(ctx, segment_data + offset,
                                   segment->data_length - offset);
    if (ws == NULL) {
      code = jbig2_error(
          ctx, JBIG2_SEVERITY_FATAL, segment->number,
          "unable to allocate ws in jbig2_immediate_generic_region");
      goto cleanup;
    }
    as = jbig2_arith_new(ctx, ws);
    if (as == NULL) {
      code = jbig2_error(
          ctx, JBIG2_SEVERITY_FATAL, segment->number,
          "unable to allocate as in jbig2_immediate_generic_region");
      goto cleanup;
    }
    code =
        jbig2_decode_generic_region(ctx, segment, &params, as, image, GB_stats);
  }
  if (code >= 0)
    jbig2_page_add_result(ctx, &ctx->pages[ctx->current_page], image, rsi.x,
                          rsi.y, rsi.op);
  else
    jbig2_error(ctx, JBIG2_SEVERITY_FATAL, segment->number,
                "error while decoding immediate_generic_region");
cleanup:
  jbig2_free(ctx->allocator, as);
  jbig2_word_stream_buf_free(ctx, ws);
  jbig2_free(ctx->allocator, GB_stats);
  jbig2_image_release(ctx, image);
  return code;
}

static void fill_vaapi_plain_pred_weight_table(
    H264Context *h, int list, unsigned char *luma_weight_flag,
    short luma_weight[32], short luma_offset[32],
    unsigned char *chroma_weight_flag, short chroma_weight[32][2],
    short chroma_offset[32][2]) {
  unsigned int i, j;
  *luma_weight_flag = h->luma_weight_flag[list];
  *chroma_weight_flag = h->chroma_weight_flag[list];
  for (i = 0; i < h->ref_count[list]; i++) {
    if (h->luma_weight_flag[list]) {
      luma_weight[i] = h->luma_weight[i][list][0];
      luma_offset[i] = h->luma_weight[i][list][1];
    } else {
      luma_weight[i] = 1 << h->luma_log2_weight_denom;
      luma_offset[i] = 0;
    }
    for (j = 0; j < 2; j++) {
      if (h->chroma_weight_flag[list]) {
        chroma_weight[i][j] = h->chroma_weight[i][list][j][0];
        chroma_offset[i][j] = h->chroma_weight[i][list][j][1];
      } else {
        chroma_weight[i][j] = 1 << h->chroma_log2_weight_denom;
        chroma_offset[i][j] = 0;
      }
    }
  }
}

