static int dissect_NOTIFY_INFO_DATA(tvbuff_t *tvb, int offset,
                                    packet_info *pinfo, proto_tree *tree,
                                    dcerpc_info *di, guint8 *drep) {
  proto_item *item;
  proto_tree *subtree;
  guint32 count;
  guint16 type, field;
  const char *field_string;
  subtree = proto_tree_add_subtree(tree, tvb, offset, 0, ett_NOTIFY_INFO_DATA,
                                   &item, "");
  offset = dissect_ndr_uint16(tvb, offset, pinfo, subtree, di, drep,
                              hf_notify_info_data_type, &type);
  offset =
      dissect_notify_field(tvb, offset, pinfo, subtree, di, drep, type, &field);
  switch (type) {
  case PRINTER_NOTIFY_TYPE:
    field_string = val_to_str_ext(field, &printer_notify_option_data_vals_ext,
                                  "Unknown (%d)");
    break;
  case JOB_NOTIFY_TYPE:
    field_string =
        val_to_str_ext(field, &job_notify_option_data_vals_ext, "Unknown (%d)");
    break;
  default:
    field_string = "Unknown field";
    break;
  }
  proto_item_append_text(item, "%s, %s",
                         val_to_str(type, printer_notify_types, "Unknown (%d)"),
                         field_string);
  offset = dissect_ndr_uint32(tvb, offset, pinfo, subtree, di, drep,
                              hf_notify_info_data_count, &count);
  offset = dissect_ndr_uint32(tvb, offset, pinfo, subtree, di, drep,
                              hf_notify_info_data_id, NULL);
  offset = dissect_ndr_uint32(tvb, offset, pinfo, subtree, di, drep,
                              hf_notify_info_data_count, NULL);
  switch (type) {
  case PRINTER_NOTIFY_TYPE:
    offset = dissect_NOTIFY_INFO_DATA_printer(tvb, offset, pinfo, subtree, item,
                                              di, drep, field);
    break;
  case JOB_NOTIFY_TYPE:
    offset = dissect_NOTIFY_INFO_DATA_job(tvb, offset, pinfo, subtree, item, di,
                                          drep, field);
    break;
  default:
    expert_add_info(pinfo, item, &ei_notify_info_data_type);
    break;
  }
  return offset;
}

static u_short create_scan_states(char *text, u_short token, follby followedby,
                                  u_short prev_state) {
  u_short my_state;
  u_short return_state;
  u_short prev_char_s;
  u_short curr_char_s;
  return_state = prev_state;
  curr_char_s = prev_state;
  prev_char_s = 0;
  while (curr_char_s && (text[0] < sst[curr_char_s].ch)) {
    prev_char_s = curr_char_s;
    curr_char_s = sst[curr_char_s].other_next_s;
  }
  if (curr_char_s && (text[0] == sst[curr_char_s].ch)) {
    my_state = curr_char_s;
    if ('\0' == text[1]) {
      fprintf(stderr,
              "Duplicate entries for keyword '%s' in"
              " keyword_gen.c ntp_keywords[].\n",
              current_keyword);
      exit(2);
    }
  } else {
    do
      my_state = sst_highwater++;
    while (my_state < COUNTOF(sst) && sst[my_state].finishes_token);
    if (my_state >= COUNTOF(sst)) {
      fprintf(stderr,
              "fatal, keyword scanner state array "
              "sst[%d] is too small, modify\n"
              "keyword-gen.c to increase.\n",
              (int)COUNTOF(sst));
      exit(3);
    }
    sst[my_state].ch = text[0];
    sst[my_state].other_next_s = curr_char_s;
    sst[my_state].followedby = FOLLBY_NON_ACCEPTING;
    if (prev_char_s)
      sst[prev_char_s].other_next_s = my_state;
    else
      return_state = my_state;
  }
  if ('\0' == text[1]) {
    sst[my_state].finishes_token = (u_short)token;
    sst[my_state].followedby = (char)followedby;
    if (sst[token].finishes_token != (u_short)token) {
      fprintf(stderr, "fatal, sst[%d] not reserved for %s.\n", token,
              symbname(token));
      exit(6);
    }
    if (my_state != token) {
      sst[token] = sst[my_state];
      ZERO(sst[my_state]);
      do
        sst_highwater--;
      while (sst[sst_highwater].finishes_token);
      my_state = token;
      if (prev_char_s)
        sst[prev_char_s].other_next_s = my_state;
      else
        return_state = my_state;
    }
  } else
    sst[my_state].match_next_s = create_scan_states(&text[1], token, followedby,
                                                    sst[my_state].match_next_s);
  return return_state;
}

static int tscc2_decode_slice(TSCC2Context *c, int mb_y, const uint8_t *buf,
                              int buf_size) {
  int i, mb_x, q, ret;
  int off;
  init_get_bits(&c->gb, buf, buf_size * 8);
  for (mb_x = 0; mb_x < c->mb_width; mb_x++) {
    q = c->slice_quants[mb_x + c->mb_width * mb_y];
    if (q == 0 || q == 3)
      continue;
    for (i = 0; i < 3; i++) {
      off = mb_x * 16 + mb_y * 8 * c->pic.linesize[i];
      ret = tscc2_decode_mb(c, c->q[q - 1], c->quant[q - 1] - 2,
                            c->pic.data[i] + off, c->pic.linesize[i], i);
      if (ret)
        return ret;
    }
  }
  return 0;
}

