int tm_rescinfo(tm_node_id node, char *resource, int len, tm_event_t *event) {
  struct reschold *rhold;
  struct tcp_chan *chan = NULL;
  if (!init_done)
    return TM_BADINIT;
  if (resource == NULL || len == 0)
    return TM_EBADENVIRONMENT;
  *event = new_event();
  if (startcom(TM_RESOURCES, *event, &chan) != DIS_SUCCESS)
    return TM_ESYSTEM;
  if (diswsi(chan, node) != DIS_SUCCESS) {
    DIS_tcp_cleanup(chan);
    return TM_ESYSTEM;
  }
  DIS_tcp_wflush(chan);
  DIS_tcp_cleanup(chan);
  rhold = (struct reschold *)calloc(1, sizeof(struct reschold));
  assert(rhold != NULL);
  rhold->resc = resource;
  rhold->len = len;
  add_event(*event, node, TM_RESOURCES, (void *)rhold);
  return TM_SUCCESS;
}

static int dumpcidglyphs(SplineFont *sf, struct alltabs *at) {
  int i;
  struct pschars *glbls = NULL, *chrs;
  at->cfff = tmpfile();
  at->sidf = tmpfile();
  at->sidh = tmpfile();
  at->charset = tmpfile();
  at->fdselect = tmpfile();
  at->fdarray = tmpfile();
  at->globalsubrs = tmpfile();
  at->fds = calloc(sf->subfontcnt, sizeof(struct fd2data));
  for (i = 0; i < sf->subfontcnt; ++i) {
    at->fds[i].private = tmpfile();
    ATFigureDefWidth(sf->subfonts[i], at, i);
  }
  if ((chrs = CID2ChrsSubrs2(sf, at->fds, at->gi.flags, &glbls,
                             at->gi.layer)) == NULL)
    return (false);
  for (i = 0; i < sf->subfontcnt; ++i) {
    dumpcffprivate(sf->subfonts[i], at, i, at->fds[i].subrs->next);
    if (at->fds[i].subrs->next != 0)
      _dumpcffstrings(at->fds[i].private, at->fds[i].subrs);
    PSCharsFree(at->fds[i].subrs);
  }
  _dumpcffstrings(at->globalsubrs, glbls);
  PSCharsFree(glbls);
  dumpcffheader(at->cfff);
  dumpcffnames(sf, at->cfff);
  dumpcffcidset(at);
  dumpcfffdselect(sf, at);
  dumpcffdictindex(sf, at);
  if ((at->charstrings = dumpcffstrings(chrs)) == NULL)
    return (false);
  dumpcffcidtopdict(sf, at);
  finishupcid(sf, at);
  at->cfflen = ftell(at->cfff);
  if (at->cfflen & 3) {
    for (i = 4 - (at->cfflen & 3); i > 0; --i)
      putc('\0', at->cfff);
  }
  if (at->format != ff_cffcid)
    dumpcffcidhmtx(at, sf);
  return (true);
}

static int decode_cabac_mb_cbp_luma(H264Context *h) {
  int cbp_b, cbp_a, ctx, cbp = 0;
  cbp_a = h->left_cbp;
  cbp_b = h->top_cbp;
  ctx = !(cbp_a & 0x02) + 2 * !(cbp_b & 0x04);
  cbp += get_cabac_noinline(&h->cabac, &h->cabac_state[73 + ctx]);
  ctx = !(cbp & 0x01) + 2 * !(cbp_b & 0x08);
  cbp += get_cabac_noinline(&h->cabac, &h->cabac_state[73 + ctx]) << 1;
  ctx = !(cbp_a & 0x08) + 2 * !(cbp & 0x01);
  cbp += get_cabac_noinline(&h->cabac, &h->cabac_state[73 + ctx]) << 2;
  ctx = !(cbp & 0x04) + 2 * !(cbp & 0x02);
  cbp += get_cabac_noinline(&h->cabac, &h->cabac_state[73 + ctx]) << 3;
  return cbp;
}

static int nb_add_values(char **ret_buffer, size_t *ret_buffer_len,
                         const lcc_value_list_t *vl) {
  char *packet_ptr;
  size_t packet_len;
  uint16_t pkg_type;
  uint16_t pkg_length;
  uint16_t pkg_num_values;
  uint8_t pkg_values_types[vl->values_len];
  value_t pkg_values[vl->values_len];
  size_t offset;
  size_t i;
  packet_len = sizeof(pkg_type) + sizeof(pkg_length) + sizeof(pkg_num_values) +
               sizeof(pkg_values_types) + sizeof(pkg_values);
  if (*ret_buffer_len < packet_len)
    return (ENOMEM);
  pkg_type = htons(TYPE_VALUES);
  pkg_length = htons((uint16_t)packet_len);
  pkg_num_values = htons((uint16_t)vl->values_len);
  for (i = 0; i < vl->values_len; i++) {
    pkg_values_types[i] = (uint8_t)vl->values_types[i];
    switch (vl->values_types[i]) {
    case LCC_TYPE_COUNTER:
      pkg_values[i].counter = (counter_t)htonll(vl->values[i].counter);
      break;
    case LCC_TYPE_GAUGE:
      pkg_values[i].gauge = (gauge_t)htond(vl->values[i].gauge);
      break;
    case LCC_TYPE_DERIVE:
      pkg_values[i].derive = (derive_t)htonll(vl->values[i].derive);
      break;
    case LCC_TYPE_ABSOLUTE:
      pkg_values[i].absolute = (absolute_t)htonll(vl->values[i].absolute);
      break;
    default:
      return (EINVAL);
    }
  }
  packet_ptr = *ret_buffer;
  offset = 0;
  memcpy(packet_ptr + offset, &pkg_type, sizeof(pkg_type));
  offset += sizeof(pkg_type);
  memcpy(packet_ptr + offset, &pkg_length, sizeof(pkg_length));
  offset += sizeof(pkg_length);
  memcpy(packet_ptr + offset, &pkg_num_values, sizeof(pkg_num_values));
  offset += sizeof(pkg_num_values);
  memcpy(packet_ptr + offset, pkg_values_types, sizeof(pkg_values_types));
  offset += sizeof(pkg_values_types);
  memcpy(packet_ptr + offset, pkg_values, sizeof(pkg_values));
  offset += sizeof(pkg_values);
  assert(offset == packet_len);
  *ret_buffer = packet_ptr + packet_len;
  *ret_buffer_len -= packet_len;
  return (0);
}

void vp9_loop_filter_frame_init(VP9_COMMON *cm, int default_filt_lvl) {
  int seg_id;
  const int scale = 1 << (default_filt_lvl >> 5);
  loop_filter_info_n *const lfi = &cm->lf_info;
  struct loopfilter *const lf = &cm->lf;
  const struct segmentation *const seg = &cm->seg;
  if (lf->last_sharpness_level != lf->sharpness_level) {
    update_sharpness(lfi, lf->sharpness_level);
    lf->last_sharpness_level = lf->sharpness_level;
  }
  for (seg_id = 0; seg_id < MAX_SEGMENTS; seg_id++) {
    int lvl_seg = default_filt_lvl;
    if (vp9_segfeature_active(seg, seg_id, SEG_LVL_ALT_LF)) {
      const int data = vp9_get_segdata(seg, seg_id, SEG_LVL_ALT_LF);
      lvl_seg = clamp(
          seg->abs_delta == SEGMENT_ABSDATA ? data : default_filt_lvl + data, 0,
          MAX_LOOP_FILTER);
    }
    if (!lf->mode_ref_delta_enabled) {
      vpx_memset(lfi->lvl[seg_id], lvl_seg, sizeof(lfi->lvl[seg_id]));
    } else {
      int ref, mode;
      const int intra_lvl = lvl_seg + lf->ref_deltas[INTRA_FRAME] * scale;
      lfi->lvl[seg_id][INTRA_FRAME][0] = clamp(intra_lvl, 0, MAX_LOOP_FILTER);
      for (ref = LAST_FRAME; ref < MAX_REF_FRAMES; ++ref) {
        for (mode = 0; mode < MAX_MODE_LF_DELTAS; ++mode) {
          const int inter_lvl = lvl_seg + lf->ref_deltas[ref] * scale +
                                lf->mode_deltas[mode] * scale;
          lfi->lvl[seg_id][ref][mode] = clamp(inter_lvl, 0, MAX_LOOP_FILTER);
        }
      }
    }
  }
}

void vp9_fht8x8_c(const int16_t *input, tran_low_t *output, int stride,
                  int tx_type) {
  if (tx_type == DCT_DCT) {
    vp9_fdct8x8_c(input, output, stride);
  } else {
    tran_low_t out[64];
    tran_low_t *outptr = &out[0];
    int i, j;
    tran_low_t temp_in[8], temp_out[8];
    const transform_2d ht = FHT_8[tx_type];
    for (i = 0; i < 8; ++i) {
      for (j = 0; j < 8; ++j)
        temp_in[j] = input[j * stride + i] * 4;
      ht.cols(temp_in, temp_out);
      for (j = 0; j < 8; ++j)
        outptr[j * 8 + i] = temp_out[j];
    }
    for (i = 0; i < 8; ++i) {
      for (j = 0; j < 8; ++j)
        temp_in[j] = out[j + i * 8];
      ht.rows(temp_in, temp_out);
      for (j = 0; j < 8; ++j)
        output[j + i * 8] = (temp_out[j] + (temp_out[j] < 0)) >> 1;
    }
  }
}

static int parse_CBaseStorageVariant(tvbuff_t *tvb, int offset,
                                     proto_tree *parent_tree,
                                     proto_tree *pad_tree _U_,
                                     struct CBaseStorageVariant *value,
                                     const char *text) {
  int i, len;
  proto_item *ti, *ti_type, *ti_val;
  proto_tree *tree, *tr;
  enum vType highType;
  ZERO_STRUCT(*value);
  tree = proto_tree_add_subtree(parent_tree, tvb, offset, 0,
                                ett_CBaseStorageVariant, &ti, text);
  parse_vType(tvb, offset, &value->vType);
  value->type = vType_get_type(value->vType);
  DISSECTOR_ASSERT(value->type != NULL);
  ti_type = proto_tree_add_string(tree, hf_mswsp_cbasestorvariant_vtype, tvb,
                                  offset, 2, value->type->str);
  offset += 2;
  value->vData1 = tvb_get_guint8(tvb, offset);
  proto_tree_add_uint(tree, hf_mswsp_cbasestorvariant_vdata1, tvb, offset, 1,
                      value->vData1);
  offset += 1;
  value->vData2 = tvb_get_guint8(tvb, offset);
  proto_tree_add_uint(tree, hf_mswsp_cbasestorvariant_vdata2, tvb, offset, 1,
                      value->vData2);
  offset += 1;
  highType = (enum vType)(value->vType & 0xFF00);
  ti_val = proto_tree_add_string(tree, hf_mswsp_cbasestorvariant_vvalue, tvb,
                                 offset, 0, "");
  switch (highType) {
  case VT_EMPTY:
    DISSECTOR_ASSERT_HINT(value->type->tvb_get != 0,
                          "type that we don't know yet how to handle, please "
                          "submit a bug with trace");
    len = value->type->tvb_get(tvb, offset, &value->vValue.vt_single);
    offset += len;
    break;
  case VT_VECTOR:
    proto_item_append_text(ti_type, "|VT_VECTOR");
    tr = proto_item_add_subtree(ti_val, ett_CBaseStorageVariant_Vector);
    len = vvalue_tvb_vector(tvb, offset, &value->vValue.vt_vector, value->type);
    proto_tree_add_uint(tr, hf_mswsp_cbasestorvariant_num, tvb, offset, 4,
                        value->vValue.vt_vector.len);
    offset += len;
    break;
  case VT_ARRAY: {
    guint16 cDims, fFeatures;
    guint32 cbElements, cElements, lLbound;
    int num = 1;
    proto_item_append_text(ti_type, "|VT_ARRAY");
    tr = proto_item_add_subtree(ti_val, ett_CBaseStorageVariant_Array);
    cDims = tvb_get_letohs(tvb, offset);
    proto_tree_add_uint(tr, hf_mswsp_cbasestorvariant_cdims, tvb, offset, 2,
                        cDims);
    offset += 2;
    fFeatures = tvb_get_letohs(tvb, offset);
    proto_tree_add_uint(tr, hf_mswsp_cbasestorvariant_ffeatures, tvb, offset, 2,
                        fFeatures);
    offset += 2;
    cbElements = tvb_get_letohl(tvb, offset);
    proto_tree_add_uint(tr, hf_mswsp_cbasestorvariant_cbelements, tvb, offset,
                        4, cbElements);
    offset += 4;
    for (i = 0; i < cDims; i++) {
      cElements = tvb_get_letohl(tvb, offset);
      lLbound = tvb_get_letohl(tvb, offset + 4);
      proto_tree_add_string_format(tr, hf_mswsp_cbasestorvariant_rgsabound, tvb,
                                   offset, 8, "", "Rgsabound[%d]: (%d:%d)", i,
                                   cElements, lLbound);
      offset += 8;
      num *= cElements;
    }
    len = vvalue_tvb_vector_internal(tvb, offset, &value->vValue.vt_array.vData,
                                     value->type, num);
    offset += len;
    break;
  }
  default:
    proto_item_append_text(ti_type, "|0x%x", highType);
  }
  proto_item_set_end(ti, tvb, offset);
  proto_item_set_end(ti_val, tvb, offset);
  proto_item_append_text(ti_val, " %s", str_CBaseStorageVariant(value, FALSE));
  proto_item_append_text(ti, " %s", str_CBaseStorageVariant(value, TRUE));
  return offset;
}

MSG_PROCESS_RETURN tls_process_client_hello(SSL *s, PACKET *pkt) {
  int i, al = SSL_AD_INTERNAL_ERROR;
  unsigned int j, complen = 0;
  unsigned long id;
  const SSL_CIPHER *c;
#ifndef OPENSSL_NO_COMP SSL_COMP *comp = NULL;
#endif STACK_OF(SSL_CIPHER) *ciphers = NULL;
  int protverr;
  PACKET session_id, cipher_suites, compression, extensions, cookie;
  int is_v2_record;
  static const unsigned char null_compression = 0;
  is_v2_record = RECORD_LAYER_is_sslv2_record(&s->rlayer);
  PACKET_null_init(&cookie);
  if (is_v2_record) {
    unsigned int version;
    unsigned int mt;
    if (!PACKET_get_1(pkt, &mt) || mt != SSL2_MT_CLIENT_HELLO) {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, ERR_R_INTERNAL_ERROR);
      goto err;
    }
    if (!PACKET_get_net_2(pkt, &version)) {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_UNKNOWN_PROTOCOL);
      goto err;
    }
    if (version == 0x0002) {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_UNKNOWN_PROTOCOL);
      goto err;
    } else if ((version & 0xff00) == (SSL3_VERSION_MAJOR << 8)) {
      s->client_version = version;
    } else {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_UNKNOWN_PROTOCOL);
      goto err;
    }
  } else {
    if (!PACKET_get_net_2(pkt, (unsigned int *)&s->client_version)) {
      al = SSL_AD_DECODE_ERROR;
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_LENGTH_TOO_SHORT);
      goto f_err;
    }
  }
  if (!SSL_IS_DTLS(s)) {
    protverr = ssl_choose_server_version(s);
  } else if (s->method->version != DTLS_ANY_VERSION &&
             DTLS_VERSION_LT(s->client_version, s->version)) {
    protverr = SSL_R_VERSION_TOO_LOW;
  } else {
    protverr = 0;
  }
  if (protverr) {
    SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, protverr);
    if ((!s->enc_write_ctx && !s->write_hash)) {
      s->version = s->client_version;
    }
    al = SSL_AD_PROTOCOL_VERSION;
    goto f_err;
  }
  if (is_v2_record) {
    unsigned int cipher_len, session_id_len, challenge_len;
    PACKET challenge;
    if (!PACKET_get_net_2(pkt, &cipher_len) ||
        !PACKET_get_net_2(pkt, &session_id_len) ||
        !PACKET_get_net_2(pkt, &challenge_len)) {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_RECORD_LENGTH_MISMATCH);
      al = SSL_AD_DECODE_ERROR;
      goto f_err;
    }
    if (session_id_len > SSL_MAX_SSL_SESSION_ID_LENGTH) {
      al = SSL_AD_DECODE_ERROR;
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_LENGTH_MISMATCH);
      goto f_err;
    }
    if (!PACKET_get_sub_packet(pkt, &cipher_suites, cipher_len) ||
        !PACKET_get_sub_packet(pkt, &session_id, session_id_len) ||
        !PACKET_get_sub_packet(pkt, &challenge, challenge_len) ||
        PACKET_remaining(pkt) != 0) {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_RECORD_LENGTH_MISMATCH);
      al = SSL_AD_DECODE_ERROR;
      goto f_err;
    }
    challenge_len =
        challenge_len > SSL3_RANDOM_SIZE ? SSL3_RANDOM_SIZE : challenge_len;
    memset(s->s3->client_random, 0, SSL3_RANDOM_SIZE);
    if (!PACKET_copy_bytes(
            &challenge, s->s3->client_random + SSL3_RANDOM_SIZE - challenge_len,
            challenge_len) ||
        !PACKET_buf_init(&compression, &null_compression, 1)) {
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, ERR_R_INTERNAL_ERROR);
      al = SSL_AD_INTERNAL_ERROR;
      goto f_err;
    }
    PACKET_null_init(&extensions);
  } else {
    if (!PACKET_copy_bytes(pkt, s->s3->client_random, SSL3_RANDOM_SIZE) ||
        !PACKET_get_length_prefixed_1(pkt, &session_id)) {
      al = SSL_AD_DECODE_ERROR;
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_LENGTH_MISMATCH);
      goto f_err;
    }
    if (PACKET_remaining(&session_id) > SSL_MAX_SSL_SESSION_ID_LENGTH) {
      al = SSL_AD_DECODE_ERROR;
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_LENGTH_MISMATCH);
      goto f_err;
    }
    if (SSL_IS_DTLS(s)) {
      if (!PACKET_get_length_prefixed_1(pkt, &cookie)) {
        al = SSL_AD_DECODE_ERROR;
        SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_LENGTH_MISMATCH);
        goto f_err;
      }
      if (SSL_get_options(s) & SSL_OP_COOKIE_EXCHANGE) {
        if (PACKET_remaining(&cookie) == 0)
          return 1;
      }
    }
    if (!PACKET_get_length_prefixed_2(pkt, &cipher_suites) ||
        !PACKET_get_length_prefixed_1(pkt, &compression)) {
      al = SSL_AD_DECODE_ERROR;
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_LENGTH_MISMATCH);
      goto f_err;
    }
    extensions = *pkt;
  }
  if (SSL_IS_DTLS(s)) {
    if (SSL_get_options(s) & SSL_OP_COOKIE_EXCHANGE) {
      if (s->ctx->app_verify_cookie_cb != NULL) {
        if (s->ctx->app_verify_cookie_cb(s, PACKET_data(&cookie),
                                         PACKET_remaining(&cookie)) == 0) {
          al = SSL_AD_HANDSHAKE_FAILURE;
          SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_COOKIE_MISMATCH);
          goto f_err;
        }
      } else if (!PACKET_equal(&cookie, s->d1->cookie, s->d1->cookie_len)) {
        al = SSL_AD_HANDSHAKE_FAILURE;
        SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_COOKIE_MISMATCH);
        goto f_err;
      }
      s->d1->cookie_verified = 1;
    }
    if (s->method->version == DTLS_ANY_VERSION) {
      protverr = ssl_choose_server_version(s);
      if (protverr != 0) {
        SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, protverr);
        s->version = s->client_version;
        al = SSL_AD_PROTOCOL_VERSION;
        goto f_err;
      }
    }
  }
  s->hit = 0;
  if (is_v2_record ||
      (s->new_session &&
       (s->options & SSL_OP_NO_SESSION_RESUMPTION_ON_RENEGOTIATION))) {
    if (!ssl_get_new_session(s, 1))
      goto err;
  } else {
    i = ssl_get_prev_session(s, &extensions, &session_id);
    if (i == 1 && s->version == s->session->ssl_version) {
      s->hit = 1;
    } else if (i == -1) {
      goto err;
    } else {
      if (!ssl_get_new_session(s, 1))
        goto err;
    }
  }
  if (ssl_bytes_to_cipher_list(s, &cipher_suites, &(ciphers), is_v2_record,
                               &al) == NULL) {
    goto f_err;
  }
  if (s->hit) {
    j = 0;
    id = s->session->cipher->id;
#ifdef CIPHER_DEBUG fprintf(stderr, "client sent %d ciphers\n",                \
                            sk_SSL_CIPHER_num(ciphers));
#endif for (i = 0;
    i < sk_SSL_CIPHER_num(ciphers);
 i ++ ) {
   c = sk_SSL_CIPHER_value(ciphers, i);
#ifdef CIPHER_DEBUG fprintf(stderr, "client [%2d of %2d]:%s\n", i,             \
                            sk_SSL_CIPHER_num(ciphers),                        \
                            SSL_CIPHER_get_name(c));
#endif if (c->id == id) {
   j = 1;
   break;
 }
  }
  if (j == 0) {
    al = SSL_AD_ILLEGAL_PARAMETER;
    SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_REQUIRED_CIPHER_MISSING);
    goto f_err;
  }
}
complen = PACKET_remaining(&compression);
for (j = 0; j < complen; j++) {
  if (PACKET_data(&compression)[j] == 0)
    break;
}
if (j >= complen) {
  al = SSL_AD_DECODE_ERROR;
  SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_NO_COMPRESSION_SPECIFIED);
  goto f_err;
}
if (s->version >= SSL3_VERSION) {
  if (!ssl_parse_clienthello_tlsext(s, &extensions)) {
    SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_PARSE_TLSEXT);
    goto err;
  }
}
{
  unsigned char *pos;
  pos = s->s3->server_random;
  if (ssl_fill_hello_random(s, 1, pos, SSL3_RANDOM_SIZE) <= 0) {
    goto f_err;
  }
}
if (!s->hit && s->version >= TLS1_VERSION && s->tls_session_secret_cb) {
  const SSL_CIPHER *pref_cipher = NULL;
  s->session->master_key_length = sizeof(s->session->master_key);
  if (s->tls_session_secret_cb(s, s->session->master_key,
                               &s->session->master_key_length, ciphers,
                               &pref_cipher, s->tls_session_secret_cb_arg)) {
    s->hit = 1;
    s->session->ciphers = ciphers;
    s->session->verify_result = X509_V_OK;
    ciphers = NULL;
    pref_cipher = pref_cipher ? pref_cipher
                              : ssl3_choose_cipher(s, s->session->ciphers,
                                                   SSL_get_ciphers(s));
    if (pref_cipher == NULL) {
      al = SSL_AD_HANDSHAKE_FAILURE;
      SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_NO_SHARED_CIPHER);
      goto f_err;
    }
    s->session->cipher = pref_cipher;
    sk_SSL_CIPHER_free(s->cipher_list);
    s->cipher_list = sk_SSL_CIPHER_dup(s->session->ciphers);
    sk_SSL_CIPHER_free(s->cipher_list_by_id);
    s->cipher_list_by_id = sk_SSL_CIPHER_dup(s->session->ciphers);
  }
}
s->s3->tmp.new_compression = NULL;
#ifndef OPENSSL_NO_COMP if (s->session->compress_meth != 0) {
int m, comp_id = s->session->compress_meth;
unsigned int k;
if (!ssl_allow_compression(s)) {
  SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_INCONSISTENT_COMPRESSION);
  goto f_err;
}
for (m = 0; m < sk_SSL_COMP_num(s->ctx->comp_methods); m++) {
  comp = sk_SSL_COMP_value(s->ctx->comp_methods, m);
  if (comp_id == comp->id) {
    s->s3->tmp.new_compression = comp;
    break;
  }
}
if (s->s3->tmp.new_compression == NULL) {
  SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_INVALID_COMPRESSION_ALGORITHM);
  goto f_err;
}
for (k = 0; k < complen; k++) {
  if (PACKET_data(&compression)[k] == comp_id)
    break;
}
if (k >= complen) {
  al = SSL_AD_ILLEGAL_PARAMETER;
  SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO,
         SSL_R_REQUIRED_COMPRESSION_ALGORITHM_MISSING);
  goto f_err;
}
}
else if (s->hit) comp = NULL;
else if (ssl_allow_compression(s) && s->ctx->comp_methods) {
  int m, nn, v, done = 0;
  unsigned int o;
  nn = sk_SSL_COMP_num(s->ctx->comp_methods);
  for (m = 0; m < nn; m++) {
    comp = sk_SSL_COMP_value(s->ctx->comp_methods, m);
    v = comp->id;
    for (o = 0; o < complen; o++) {
      if (v == PACKET_data(&compression)[o]) {
        done = 1;
        break;
      }
    }
    if (done)
      break;
  }
  if (done)
    s->s3->tmp.new_compression = comp;
  else
    comp = NULL;
}
#else if (s->session->compress_meth != 0) {
SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_INCONSISTENT_COMPRESSION);
goto f_err;
}
#endif if (!s->hit) {
#ifdef OPENSSL_NO_COMP s->session->compress_meth = 0;
#else s->session->compress_meth = (comp == NULL) ? 0 : comp->id;
#endif sk_SSL_CIPHER_free(s->session->ciphers);
s->session->ciphers = ciphers;
if (ciphers == NULL) {
  al = SSL_AD_INTERNAL_ERROR;
  SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, ERR_R_INTERNAL_ERROR);
  goto f_err;
}
ciphers = NULL;
if (!tls1_set_server_sigalgs(s)) {
  SSLerr(SSL_F_TLS_PROCESS_CLIENT_HELLO, SSL_R_CLIENTHELLO_TLSEXT);
  goto err;
}
}
sk_SSL_CIPHER_free(ciphers);
return MSG_PROCESS_CONTINUE_PROCESSING;
f_err : ssl3_send_alert(s, SSL3_AL_FATAL, al);
err : ossl_statem_set_error(s);
sk_SSL_CIPHER_free(ciphers);
return MSG_PROCESS_ERROR;
}

void PrintTOCSummary(Archive *AHX) {
  ArchiveHandle *AH = (ArchiveHandle *)AHX;
  RestoreOptions *ropt = AH->public.ropt;
  TocEntry *te;
  teSection curSection;
  OutputContext sav;
  const char *fmtName;
  char stamp_str[64];
  sav = SaveOutput(AH);
  if (ropt->filename)
    SetOutput(AH, ropt->filename, 0);
  if (strftime(stamp_str, sizeof(stamp_str), PGDUMP_STRFTIME_FMT,
               localtime(&AH->createDate)) == 0)
    strcpy(stamp_str, "[unknown]");
 ahprintf ( AH , ";
\n;
 Archive created at %s\n" , stamp_str ) ;
 ahprintf ( AH , ";
 dbname: %s\n;
 TOC Entries: %d\n;
 Compression: %d\n" , AH -> archdbname , AH -> tocCount , AH -> compression ) ;
 switch ( AH -> format ) {
  case archCustom:
    fmtName = "CUSTOM";
    break;
  case archDirectory:
    fmtName = "DIRECTORY";
    break;
  case archTar:
    fmtName = "TAR";
    break;
  default:
    fmtName = "UNKNOWN";
 }
 ahprintf ( AH , ";
 Dump Version: %d.%d-%d\n" , AH -> vmaj , AH -> vmin , AH -> vrev ) ;
 ahprintf ( AH , ";
 Format: %s\n" , fmtName ) ;
 ahprintf ( AH , ";
 Integer: %d bytes\n" , ( int ) AH -> intSize ) ;
 ahprintf ( AH , ";
 Offset: %d bytes\n" , ( int ) AH -> offSize ) ;
 if ( AH -> archiveRemoteVersion ) ahprintf ( AH , ";
 Dumped from database version: %s\n" , AH -> archiveRemoteVersion ) ;
 if ( AH -> archiveDumpVersion ) ahprintf ( AH , ";
 Dumped by pg_dump version: %s\n" , AH -> archiveDumpVersion ) ;
 ahprintf ( AH , ";
\n;
\n;
 Selected TOC Entries:\n;
\n" ) ;
 curSection = SECTION_PRE_DATA ;
 for ( te = AH -> toc -> next ;
 te != AH -> toc ;
 te = te -> next ) {
    if (te->section != SECTION_NONE)
      curSection = te->section;
    if (ropt->verbose || (_tocEntryRequired(te, curSection, ropt) &
                          (REQ_SCHEMA | REQ_DATA)) != 0) ahprintf ( AH , "%d;
 %u %u %s %s %s %s\n" , te -> dumpId , te -> catalogId . tableoid , te -> catalogId . oid , te -> desc , te -> namespace ? te -> namespace : "-" , te -> tag , te -> owner ) ;
 if ( ropt -> verbose && te -> nDeps > 0 ) {
        int i;
 ahprintf ( AH , ";
\tdepends on:" ) ;
 for ( i = 0 ;
 i < te -> nDeps ;
 i ++ ) ahprintf ( AH , " %d" , te -> dependencies [ i ] ) ;
 ahprintf ( AH , "\n" ) ;
 }
 }
 if ( ropt -> strict_names ) StrictNamesCheck ( ropt ) ;
 if ( ropt -> filename ) RestoreOutput ( AH , sav ) ;
}

int y4m_input_fetch_frame(y4m_input *_y4m, FILE *_fin, vpx_image_t *_img) {
  char frame[6];
  int pic_sz;
  int c_w;
  int c_h;
  int c_sz;
  int bytes_per_sample = _y4m->bit_depth > 8 ? 2 : 1;
  if (!file_read(frame, 6, _fin))
    return 0;
  if (memcmp(frame, "FRAME", 5)) {
    fprintf(stderr, "Loss of framing in Y4M input data\n");
    return -1;
  }
  if (frame[5] != '\n') {
    char c;
    int j;
    for (j = 0; j < 79 && file_read(&c, 1, _fin) && c != '\n'; j++) {
    }
    if (j == 79) {
      fprintf(stderr, "Error parsing Y4M frame header\n");
      return -1;
    }
  }
  if (!file_read(_y4m->dst_buf, _y4m->dst_buf_read_sz, _fin)) {
    fprintf(stderr, "Error reading Y4M frame data.\n");
    return -1;
  }
  if (!file_read(_y4m->aux_buf, _y4m->aux_buf_read_sz, _fin)) {
    fprintf(stderr, "Error reading Y4M frame data.\n");
    return -1;
  }
  (*_y4m->convert)(_y4m, _y4m->dst_buf, _y4m->aux_buf);
  memset(_img, 0, sizeof(*_img));
  _img->fmt = _y4m->vpx_fmt;
  _img->w = _img->d_w = _y4m->pic_w;
  _img->h = _img->d_h = _y4m->pic_h;
  _img->x_chroma_shift = _y4m->dst_c_dec_h >> 1;
  _img->y_chroma_shift = _y4m->dst_c_dec_v >> 1;
  _img->bps = _y4m->bps;
  pic_sz = _y4m->pic_w * _y4m->pic_h * bytes_per_sample;
  c_w = (_y4m->pic_w + _y4m->dst_c_dec_h - 1) / _y4m->dst_c_dec_h;
  c_w *= bytes_per_sample;
  c_h = (_y4m->pic_h + _y4m->dst_c_dec_v - 1) / _y4m->dst_c_dec_v;
  c_sz = c_w * c_h;
  _img->stride[VPX_PLANE_Y] = _img->stride[VPX_PLANE_ALPHA] =
      _y4m->pic_w * bytes_per_sample;
  _img->stride[VPX_PLANE_U] = _img->stride[VPX_PLANE_V] = c_w;
  _img->planes[VPX_PLANE_Y] = _y4m->dst_buf;
  _img->planes[VPX_PLANE_U] = _y4m->dst_buf + pic_sz;
  _img->planes[VPX_PLANE_V] = _y4m->dst_buf + pic_sz + c_sz;
  _img->planes[VPX_PLANE_ALPHA] = _y4m->dst_buf + pic_sz + 2 * c_sz;
  return 1;
}

