void ff_sbr_apply(AACContext *ac, SpectralBandReplication *sbr, int id_aac,
                  float *L, float *R) {
  int downsampled = ac->oc[1].m4ac.ext_sample_rate < sbr->sample_rate;
  int ch;
  int nch = (id_aac == TYPE_CPE) ? 2 : 1;
  int err;
  if (id_aac != sbr->id_aac) {
    av_log(ac->avctx, AV_LOG_ERROR, "element type mismatch %d != %d\n", id_aac,
           sbr->id_aac);
    sbr_turnoff(sbr);
  }
  if (!sbr->kx_and_m_pushed) {
    sbr->kx[0] = sbr->kx[1];
    sbr->m[0] = sbr->m[1];
  } else {
    sbr->kx_and_m_pushed = 0;
  }
  if (sbr->start) {
    sbr_dequant(sbr, id_aac);
  }
  for (ch = 0; ch < nch; ch++) {
    sbr_qmf_analysis(ac->fdsp, &sbr->mdct_ana, &sbr->dsp, ch ? R : L,
                     sbr->data[ch].analysis_filterbank_samples,
                     (float *)sbr->qmf_filter_scratch, sbr->data[ch].W,
                     sbr->data[ch].Ypos);
    sbr->c.sbr_lf_gen(ac, sbr, sbr->X_low,
                      (const float(*)[32][32][2])sbr->data[ch].W,
                      sbr->data[ch].Ypos);
    sbr->data[ch].Ypos ^= 1;
    if (sbr->start) {
      sbr->c.sbr_hf_inverse_filter(&sbr->dsp, sbr->alpha0, sbr->alpha1,
                                   (const float(*)[40][2])sbr->X_low,
                                   sbr->k[0]);
      sbr_chirp(sbr, &sbr->data[ch]);
      av_assert0(sbr->data[ch].bs_num_env > 0);
      sbr_hf_gen(ac, sbr, sbr->X_high, (const float(*)[40][2])sbr->X_low,
                 (const float(*)[2])sbr->alpha0, (const float(*)[2])sbr->alpha1,
                 sbr->data[ch].bw_array, sbr->data[ch].t_env,
                 sbr->data[ch].bs_num_env);
      err = sbr_mapping(ac, sbr, &sbr->data[ch], sbr->data[ch].e_a);
      if (!err) {
        sbr_env_estimate(sbr->e_curr, sbr->X_high, sbr, &sbr->data[ch]);
        sbr_gain_calc(ac, sbr, &sbr->data[ch], sbr->data[ch].e_a);
        sbr->c.sbr_hf_assemble(sbr->data[ch].Y[sbr->data[ch].Ypos],
                               (const float(*)[40][2])sbr->X_high, sbr,
                               &sbr->data[ch], sbr->data[ch].e_a);
      }
    }
    sbr->c.sbr_x_gen(
        sbr, sbr->X[ch],
        (const float(*)[64][2])sbr->data[ch].Y[1 - sbr->data[ch].Ypos],
        (const float(*)[64][2])sbr->data[ch].Y[sbr->data[ch].Ypos],
        (const float(*)[40][2])sbr->X_low, ch);
  }
  if (ac->oc[1].m4ac.ps == 1) {
    if (sbr->ps.start) {
      ff_ps_apply(ac->avctx, &sbr->ps, sbr->X[0], sbr->X[1],
                  sbr->kx[1] + sbr->m[1]);
    } else {
      memcpy(sbr->X[1], sbr->X[0], sizeof(sbr->X[0]));
    }
    nch = 2;
  }
  sbr_qmf_synthesis(
      &sbr->mdct, &sbr->dsp, ac->fdsp, L, sbr->X[0], sbr->qmf_filter_scratch,
      sbr->data[0].synthesis_filterbank_samples,
      &sbr->data[0].synthesis_filterbank_samples_offset, downsampled);
  if (nch == 2)
    sbr_qmf_synthesis(
        &sbr->mdct, &sbr->dsp, ac->fdsp, R, sbr->X[1], sbr->qmf_filter_scratch,
        sbr->data[1].synthesis_filterbank_samples,
        &sbr->data[1].synthesis_filterbank_samples_offset, downsampled);
}

u_long leap_month(u_long sec) {
  int leap;
  int32 year, month;
  u_int32 ndays;
  ntpcal_split tmp;
  vint64 tvl;
  tvl = ntpcal_ntp_to_ntp(sec, NULL);
  tmp = ntpcal_daysplit(&tvl);
  tmp = ntpcal_split_eradays(tmp.hi + DAY_NTP_STARTS - 1, &leap);
  year = tmp.hi;
  tmp = ntpcal_split_yeardays(tmp.lo, leap);
  month = tmp.hi;
  ndays = ntpcal_edate_to_eradays(year, month + 1, 0) + 1 - DAY_NTP_STARTS;
  return (u_int32)(ndays * SECSPERDAY - sec);
}

bool mysql_drop_user(THD *thd, List<LEX_USER> &list) {
  int result;
  String wrong_users;
  LEX_USER *user_name, *tmp_user_name;
  List_iterator<LEX_USER> user_list(list);
  TABLE_LIST tables[GRANT_TABLES];
  bool some_users_deleted = FALSE;
  ulong old_sql_mode = thd->variables.sql_mode;
  bool save_binlog_row_based;
  DBUG_ENTER("mysql_drop_user");
  save_binlog_row_based = thd->current_stmt_binlog_row_based;
  thd->clear_current_stmt_binlog_row_based();
  if ((result = open_grant_tables(thd, tables))) {
    thd->current_stmt_binlog_row_based = save_binlog_row_based;
    DBUG_RETURN(result != 1);
  }
  thd->variables.sql_mode &= ~MODE_PAD_CHAR_TO_FULL_LENGTH;
  rw_wrlock(&LOCK_grant);
  VOID(pthread_mutex_lock(&acl_cache->lock));
  while ((tmp_user_name = user_list++)) {
    if (!(user_name = get_current_user(thd, tmp_user_name))) {
      result = TRUE;
      continue;
    }
    if (handle_grant_data(tables, 1, user_name, NULL) <= 0) {
      append_user(&wrong_users, user_name);
      result = TRUE;
      continue;
    }
    some_users_deleted = TRUE;
  }
  rebuild_check_host();
  VOID(pthread_mutex_unlock(&acl_cache->lock));
  if (result)
    my_error(ER_CANNOT_USER, MYF(0), "DROP USER", wrong_users.c_ptr_safe());
  if (some_users_deleted)
    result |= write_bin_log(thd, FALSE, thd->query(), thd->query_length());
  rw_unlock(&LOCK_grant);
  close_thread_tables(thd);
  thd->variables.sql_mode = old_sql_mode;
  thd->current_stmt_binlog_row_based = save_binlog_row_based;
  DBUG_RETURN(result);
}

