              high_d207_predictor(uint16_t *dst, ptrdiff_t stride, int bs,     \
                                  const uint16_t *above, const uint16_t *left, \
                                  int bd) {
int r, c;
(void)above;
(void)bd;
for (r = 0; r < bs - 1; ++r) {
  dst[r * stride] = ROUND_POWER_OF_TWO(left[r] + left[r + 1], 1);
}
dst[(bs - 1) * stride] = left[bs - 1];
dst++;
for (r = 0; r < bs - 2; ++r) {
  dst[r * stride] =
      ROUND_POWER_OF_TWO(left[r] + left[r + 1] * 2 + left[r + 2], 2);
}
dst[(bs - 2) * stride] = ROUND_POWER_OF_TWO(left[bs - 2] + left[bs - 1] * 3, 2);
dst[(bs - 1) * stride] = left[bs - 1];
dst++;
for (c = 0; c < bs - 2; ++c)
  dst[(bs - 1) * stride + c] = left[bs - 1];
for (r = bs - 2; r >= 0; --r) {
  for (c = 0; c < bs - 2; ++c)
    dst[r * stride + c] = dst[(r + 1) * stride + c - 2];
}
}
static INLINE void high_d63_predictor(uint16_t *dst, ptrdiff_t stride, int bs,
                                      const uint16_t *above,
                                      const uint16_t *left, int bd) {
  int r, c;
  (void)left;
  (void)bd;
  for (r = 0; r < bs; ++r) {
    for (c = 0; c < bs; ++c) {
      dst[c] =
          r & 1
              ? ROUND_POWER_OF_TWO(above[r / 2 + c] + above[r / 2 + c + 1] * 2 +
                                       above[r / 2 + c + 2],
                                   2)
              : ROUND_POWER_OF_TWO(above[r / 2 + c] + above[r / 2 + c + 1], 1);
    }
    dst += stride;
  }
}
static INLINE void high_d45_predictor(uint16_t *dst, ptrdiff_t stride, int bs,
                                      const uint16_t *above,
                                      const uint16_t *left, int bd) {
  int r, c;
  (void)left;
  (void)bd;
  for (r = 0; r < bs; ++r) {
    for (c = 0; c < bs; ++c) {
      dst[c] =
          r + c + 2 < bs * 2
              ? ROUND_POWER_OF_TWO(
                    above[r + c] + above[r + c + 1] * 2 + above[r + c + 2], 2)
              : above[bs * 2 - 1];
    }
    dst += stride;
  }
}
static INLINE void high_d117_predictor(uint16_t *dst, ptrdiff_t stride, int bs,
                                       const uint16_t *above,
                                       const uint16_t *left, int bd) {
  int r, c;
  (void)bd;
  for (c = 0; c < bs; c++)
    dst[c] = ROUND_POWER_OF_TWO(above[c - 1] + above[c], 1);
  dst += stride;
  dst[0] = ROUND_POWER_OF_TWO(left[0] + above[-1] * 2 + above[0], 2);
  for (c = 1; c < bs; c++)
    dst[c] = ROUND_POWER_OF_TWO(above[c - 2] + above[c - 1] * 2 + above[c], 2);
  dst += stride;
  dst[0] = ROUND_POWER_OF_TWO(above[-1] + left[0] * 2 + left[1], 2);
  for (r = 3; r < bs; ++r)
    dst[(r - 2) * stride] =
        ROUND_POWER_OF_TWO(left[r - 3] + left[r - 2] * 2 + left[r - 1], 2);
  for (r = 2; r < bs; ++r) {
    for (c = 1; c < bs; c++)
      dst[c] = dst[-2 * stride + c - 1];
    dst += stride;
  }
}
static INLINE void high_d135_predictor(uint16_t *dst, ptrdiff_t stride, int bs,
