static INLINE void high_tm_predictor(uint16_t *dst, ptrdiff_t stride, int bs,
                                     const uint16_t *above,
                                     const uint16_t *left, int bd) {
  int r, c;
  int ytop_left = above[-1];
  (void)bd;
  for (r = 0; r < bs; r++) {
    for (c = 0; c < bs; c++)
      dst[c] = clip_pixel_high(left[r] + above[c] - ytop_left, bd);
