void gs_make_mem_device(gx_device_memory *dev, const gx_device_memory *mdproto,
                        gs_memory_t *mem, int page_device, gx_device *target) {
  gx_device_init((gx_device *)dev, (const gx_device *)mdproto, mem, true);
  dev->stype = &st_device_memory;
  switch (page_device) {
  case -1:
    set_dev_proc(dev, get_page_device, gx_default_get_page_device);
    break;
  case 1:
    set_dev_proc(dev, get_page_device, gx_page_device_get_page_device);
    break;
  }
  if (target == 0) {
    if (dev->color_info.depth == 1) {
      dev->cached_colors.black = 1;
      dev->cached_colors.white = 0;
    } else {
      dev->cached_colors.black = 0;
      dev->cached_colors.white = (1 << dev->color_info.depth) - 1;
    }
    dev->graphics_type_tag = GS_UNKNOWN_TAG;
  } else {
    gx_device_set_target((gx_device_forward *)dev, target);
    gx_device_forward_color_procs((gx_device_forward *)dev);
    gx_device_copy_color_procs((gx_device *)dev, target);
    dev->color_info.separable_and_linear =
        target->color_info.separable_and_linear;
    dev->cached_colors = target->cached_colors;
    dev->graphics_type_tag = target->graphics_type_tag;
#define COPY_PROC                                                              \
  (p) set_dev_proc(dev, p, target->procs.p) COPY_PROC(put_image);
#undef COPY_PROC }
    if (dev->color_info.depth == 1) {
      gx_color_value cv[GX_DEVICE_COLOR_MAX_COMPONENTS];
      uchar k;
      if (target != 0) {
        for (k = 0; k < target->color_info.num_components; k++) {
          cv[k] = 0;
        }
      }
      gdev_mem_mono_set_inverted(
          dev, (target == 0 ||
                (*dev_proc(dev, encode_color))((gx_device *)dev, cv) != 0));
    }
    check_device_separable((gx_device *)dev);
    gx_device_fill_in_procs((gx_device *)dev);
    dev->band_y = 0;
  }

static void ucnv_UTF8FromUTF8(UConverterFromUnicodeArgs *pFromUArgs,
                              UConverterToUnicodeArgs *pToUArgs,
                              UErrorCode *pErrorCode) {
  UConverter *utf8;
  const uint8_t *source, *sourceLimit;
  uint8_t *target;
  int32_t targetCapacity;
  int32_t count;
  int8_t oldToULength, toULength, toULimit;
  UChar32 c;
  uint8_t b, t1, t2;
  utf8 = pToUArgs->converter;
  source = (uint8_t *)pToUArgs->source;
  sourceLimit = (uint8_t *)pToUArgs->sourceLimit;
  target = (uint8_t *)pFromUArgs->target;
  targetCapacity = (int32_t)(pFromUArgs->targetLimit - pFromUArgs->target);
  c = (UChar32)utf8->toUnicodeStatus;
  if (c != 0) {
    toULength = oldToULength = utf8->toULength;
    toULimit = (int8_t)utf8->mode;
  } else {
    toULength = oldToULength = toULimit = 0;
  }
  count = (int32_t)(sourceLimit - source) + oldToULength;
  if (count < toULimit) {
  } else if (targetCapacity < toULimit) {
    *pErrorCode = U_USING_DEFAULT_WARNING;
    return;
  } else {
    int32_t i;
    if (count > targetCapacity) {
      count = targetCapacity;
    }
    i = 0;
    while (i < 3 && i < (count - toULimit)) {
      b = source[count - oldToULength - i - 1];
      if (U8_IS_TRAIL(b)) {
        ++i;
      } else {
        if (i < U8_COUNT_TRAIL_BYTES(b)) {
          count -= i + 1;
        }
        break;
      }
    }
  }
  if (c != 0) {
    utf8->toUnicodeStatus = 0;
    utf8->toULength = 0;
    goto moreBytes;
  }
  while (count > 0) {
    b = *source++;
    if ((int8_t)b >= 0) {
      *target++ = b;
      --count;
      continue;
    } else {
      if (b > 0xe0) {
        if ((t1 = source[0]) >= 0x80 &&
            ((b < 0xed && (t1 <= 0xbf)) || (b == 0xed && (t1 <= 0x9f))) &&
            (t2 = source[1]) >= 0x80 && t2 <= 0xbf) {
          source += 2;
          *target++ = b;
          *target++ = t1;
          *target++ = t2;
          count -= 3;
          continue;
        }
      } else if (b < 0xe0) {
        if (b >= 0xc2 && (t1 = *source) >= 0x80 && t1 <= 0xbf) {
          ++source;
          *target++ = b;
          *target++ = t1;
          count -= 2;
          continue;
        }
      } else if (b == 0xe0) {
        if ((t1 = source[0]) >= 0xa0 && t1 <= 0xbf &&
            (t2 = source[1]) >= 0x80 && t2 <= 0xbf) {
          source += 2;
          *target++ = b;
          *target++ = t1;
          *target++ = t2;
          count -= 3;
          continue;
        }
      }
      oldToULength = 0;
      toULength = 1;
      toULimit = U8_COUNT_TRAIL_BYTES(b) + 1;
      c = b;
    moreBytes:
      while (toULength < toULimit) {
        if (source < sourceLimit) {
          b = *source;
          if (U8_IS_TRAIL(b)) {
            ++source;
            ++toULength;
            c = (c << 6) + b;
          } else {
            break;
          }
        } else {
          source -= (toULength - oldToULength);
          while (oldToULength < toULength) {
            utf8->toUBytes[oldToULength++] = *source++;
          }
          utf8->toUnicodeStatus = c;
          utf8->toULength = toULength;
          utf8->mode = toULimit;
          pToUArgs->source = (char *)source;
          pFromUArgs->target = (char *)target;
          return;
        }
      }
      if (toULength == toULimit && (toULength == 3 || toULength == 2) &&
          (c -= utf8_offsets[toULength]) >= utf8_minLegal[toULength] &&
          (c <= 0xd7ff || 0xe000 <= c)) {
      } else if (toULength == toULimit && toULength == 4 &&
                 (0x10000 <= (c -= utf8_offsets[4]) && c <= 0x10ffff)) {
      } else {
        source -= (toULength - oldToULength);
        while (oldToULength < toULength) {
          utf8->toUBytes[oldToULength++] = *source++;
        }
        utf8->toULength = toULength;
        pToUArgs->source = (char *)source;
        pFromUArgs->target = (char *)target;
        *pErrorCode = U_ILLEGAL_CHAR_FOUND;
        return;
      }
      {
        int8_t i;
        for (i = 0; i < oldToULength; ++i) {
          *target++ = utf8->toUBytes[i];
        }
        source -= (toULength - oldToULength);
        for (; i < toULength; ++i) {
          *target++ = *source++;
        }
        count -= toULength;
      }
    }
  }
  if (U_SUCCESS(*pErrorCode) && source < sourceLimit) {
    if (target == (const uint8_t *)pFromUArgs->targetLimit) {
      *pErrorCode = U_BUFFER_OVERFLOW_ERROR;
    } else {
      b = *source;
      toULimit = U8_COUNT_TRAIL_BYTES(b) + 1;
      if (toULimit > (sourceLimit - source)) {
        toULength = 0;
        c = b;
        for (;;) {
          utf8->toUBytes[toULength++] = b;
          if (++source == sourceLimit) {
            utf8->toUnicodeStatus = c;
            utf8->toULength = toULength;
            utf8->mode = toULimit;
            break;
          } else if (!U8_IS_TRAIL(b = *source)) {
            utf8->toULength = toULength;
            *pErrorCode = U_ILLEGAL_CHAR_FOUND;
            break;
          }
          c = (c << 6) + b;
        }
      } else {
        *pErrorCode = U_USING_DEFAULT_WARNING;
      }
    }
  }
  pToUArgs->source = (char *)source;
  pFromUArgs->target = (char *)target;
}

const char *evdns_err_to_string(int err) {
