static const char *map_data_enc(gpgme_data_t d) {
  switch (gpgme_data_get_encoding(d)) {
  case GPGME_DATA_ENCODING_NONE:
    break;
  case GPGME_DATA_ENCODING_BINARY:
    return "--binary";
  case GPGME_DATA_ENCODING_BASE64:
    return "--base64";
  case GPGME_DATA_ENCODING_ARMOR:
    return "--armor";
  default:
    break;
  }
  return NULL;
}

static guint get_mtu(packet_info *pinfo, bluetooth_data_t *bluetooth_data) {
  wmem_tree_key_t key[3];
  guint32 frame_number;
  mtu_data_t *mtu_data;
  wmem_tree_t *sub_wmemtree;
  guint mtu = 23;
  frame_number = pinfo->num;
  key[0].length = 1;
  key[0].key = &bluetooth_data->interface_id;
  key[1].length = 1;
  key[1].key = &bluetooth_data->adapter_id;
  key[2].length = 0;
  key[2].key = NULL;
  sub_wmemtree = (wmem_tree_t *)wmem_tree_lookup32_array(mtus, key);
  mtu_data = (sub_wmemtree) ? (mtu_data_t *)wmem_tree_lookup32_le(sub_wmemtree,
                                                                  frame_number)
                            : NULL;
  if (mtu_data)
    mtu = mtu_data->mtu;
  return mtu;
}

static uint16_t *build_pow_table(float gamma, int length) {
  int i;
  uint16_t *output = malloc(sizeof(uint16_t) * length);
  if (!output)
    return NULL;
  for (i = 0; i < length; i++) {
    uint16_fract_t result;
    double x = ((double)i) / (double)(length - 1);
    x = pow(x, gamma);
    result = floor(x * 65535. + .5);
    output[i] = result;
  }
  return output;
}

static int dvvideo_decode_frame(AVCodecContext *avctx, void *data,
                                int *got_frame, AVPacket *avpkt) {
  uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  DVVideoContext *s = avctx->priv_data;
  const uint8_t *vsc_pack;
  int apt, is16_9;
  s->sys = avpriv_dv_frame_profile(s->sys, buf, buf_size);
  if (!s->sys || buf_size < s->sys->frame_size ||
      ff_dv_init_dynamic_tables(s->sys)) {
    av_log(avctx, AV_LOG_ERROR, "could not find dv frame profile\n");
    return -1;
  }
  s->picture.key_frame = 1;
  s->picture.pict_type = AV_PICTURE_TYPE_I;
  avctx->pix_fmt = s->sys->pix_fmt;
  avctx->time_base = s->sys->time_base;
  avcodec_set_dimensions(avctx, s->sys->width, s->sys->height);
  if (ff_get_buffer(avctx, &s->picture, 0) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return -1;
  }
  s->picture.interlaced_frame = 1;
  s->picture.top_field_first = 0;
  s->buf = buf;
  avctx->execute(avctx, dv_decode_video_segment, s->sys->work_chunks, NULL,
                 dv_work_pool_size(s->sys), sizeof(DVwork_chunk));
  emms_c();
  *got_frame = 1;
  av_frame_move_ref(data, &s->picture);
  vsc_pack = buf + 80 * 5 + 48 + 5;
  if (*vsc_pack == dv_video_control) {
    apt = buf[4] & 0x07;
    is16_9 = (vsc_pack && ((vsc_pack[2] & 0x07) == 0x02 ||
                           (!apt && (vsc_pack[2] & 0x07) == 0x07)));
    avctx->sample_aspect_ratio = s->sys->sar[is16_9];
  }
  return s->sys->frame_size;
}

