static void sbr_qmf_pre_shuffle_c(float *z) {
  union av_intfloat32 *zi = (union av_intfloat32 *)z;
  int k;
  zi[64].i = zi[0].i;
  zi[65].i = zi[1].i;
  for (k = 1; k < 31; k += 2) {
    zi[64 + 2 * k + 0].i = zi[64 - k].i ^ (1U << 31);
    zi[64 + 2 * k + 1].i = zi[k + 1].i;
    zi[64 + 2 * k + 2].i = zi[63 - k].i ^ (1U << 31);
    zi[64 + 2 * k + 3].i = zi[k + 2].i;
  }
  zi[64 + 2 * 31 + 0].i = zi[64 - 31].i ^ (1U << 31);
  zi[64 + 2 * 31 + 1].i = zi[31 + 1].i;
}

static void vc2_subband_dwt_97(VC2TransformContext *t, dwtcoef *data,
                               ptrdiff_t stride, int width, int height) {
  int x, y;
  dwtcoef *datal = data, *synth = t->buffer, *synthl = synth;
  const ptrdiff_t synth_width = width << 1;
  const ptrdiff_t synth_height = height << 1;
  for (y = 0; y < synth_height; y++) {
    for (x = 0; x < synth_width; x++)
      synthl[x] = datal[x] << 1;
    synthl += synth_width;
    datal += stride;
  }
  synthl = synth;
  for (y = 0; y < synth_height; y++) {
    synthl[1] -= (8 * synthl[0] + 9 * synthl[2] - synthl[4] + 8) >> 4;
    for (x = 1; x < width - 2; x++)
      synthl[2 * x + 1] -= (9 * synthl[2 * x] + 9 * synthl[2 * x + 2] -
                            synthl[2 * x + 4] - synthl[2 * x - 2] + 8) >>
                           4;
    synthl[synth_width - 1] -=
        (17 * synthl[synth_width - 2] - synthl[synth_width - 4] + 8) >> 4;
    synthl[synth_width - 3] -=
        (8 * synthl[synth_width - 2] + 9 * synthl[synth_width - 4] -
         synthl[synth_width - 6] + 8) >>
        4;
    synthl[0] += (synthl[1] + synthl[1] + 2) >> 2;
    for (x = 1; x < width - 1; x++)
      synthl[2 * x] += (synthl[2 * x - 1] + synthl[2 * x + 1] + 2) >> 2;
    synthl[synth_width - 2] +=
        (synthl[synth_width - 3] + synthl[synth_width - 1] + 2) >> 2;
    synthl += synth_width;
  }
  synthl = synth + synth_width;
  for (x = 0; x < synth_width; x++)
    synthl[x] -= (8 * synthl[x - synth_width] + 9 * synthl[x + synth_width] -
                  synthl[x + 3 * synth_width] + 8) >>
                 4;
  synthl = synth + (synth_width << 1);
  for (y = 1; y < height - 2; y++) {
    for (x = 0; x < synth_width; x++)
      synthl[x + synth_width] -=
          (9 * synthl[x] + 9 * synthl[x + 2 * synth_width] -
           synthl[x - 2 * synth_width] - synthl[x + 4 * synth_width] + 8) >>
          4;
    synthl += synth_width << 1;
  }
  synthl = synth + (synth_height - 1) * synth_width;
  for (x = 0; x < synth_width; x++) {
    synthl[x] -=
        (17 * synthl[x - synth_width] - synthl[x - 3 * synth_width] + 8) >> 4;
    synthl[x - 2 * synth_width] -=
        (9 * synthl[x - 3 * synth_width] + 8 * synthl[x - 1 * synth_width] -
         synthl[x - 5 * synth_width] + 8) >>
        4;
  }
  synthl = synth;
  for (x = 0; x < synth_width; x++)
    synthl[x] += (synthl[x + synth_width] + synthl[x + synth_width] + 2) >> 2;
  synthl = synth + (synth_width << 1);
  for (y = 1; y < height - 1; y++) {
    for (x = 0; x < synth_width; x++)
      synthl[x] += (synthl[x - synth_width] + synthl[x + synth_width] + 2) >> 2;
    synthl += synth_width << 1;
  }
  synthl = synth + (synth_height - 2) * synth_width;
  for (x = 0; x < synth_width; x++)
    synthl[x] += (synthl[x - synth_width] + synthl[x + synth_width] + 2) >> 2;
  deinterleave(data, stride, width, height, synth);
}

static int decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                        AVPacket *pkt) {
  BMVDecContext *const c = avctx->priv_data;
  int type, scr_off;
  int i, ret;
  uint8_t *srcptr, *outptr;
  c->stream = pkt->data;
  type = bytestream_get_byte(&c->stream);
  if (type & BMV_AUDIO) {
    int blobs = bytestream_get_byte(&c->stream);
    if (pkt->size < blobs * 65 + 2) {
      av_log(avctx, AV_LOG_ERROR, "Audio data doesn't fit in frame\n");
      return AVERROR_INVALIDDATA;
    }
    c->stream += blobs * 65;
  }
  if (type & BMV_COMMAND) {
    int command_size = (type & BMV_PRINT) ? 8 : 10;
    if (c->stream - pkt->data + command_size > pkt->size) {
      av_log(avctx, AV_LOG_ERROR, "Command data doesn't fit in frame\n");
      return AVERROR_INVALIDDATA;
    }
    c->stream += command_size;
  }
  if (type & BMV_PALETTE) {
    if (c->stream - pkt->data > pkt->size - 768) {
      av_log(avctx, AV_LOG_ERROR, "Palette data doesn't fit in frame\n");
      return AVERROR_INVALIDDATA;
    }
    for (i = 0; i < 256; i++)
      c->pal[i] = bytestream_get_be24(&c->stream);
  }
  if (type & BMV_SCROLL) {
    if (c->stream - pkt->data > pkt->size - 2) {
      av_log(avctx, AV_LOG_ERROR, "Screen offset data doesn't fit in frame\n");
      return AVERROR_INVALIDDATA;
    }
    scr_off = (int16_t)bytestream_get_le16(&c->stream);
  } else if ((type & BMV_INTRA) == BMV_INTRA) {
    scr_off = -640;
  } else {
    scr_off = 0;
  }
  if (c->pic.data[0])
    avctx->release_buffer(avctx, &c->pic);
  c->pic.reference = 3;
  if ((ret = ff_get_buffer(avctx, &c->pic)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  if (decode_bmv_frame(c->stream, pkt->size - (c->stream - pkt->data), c->frame,
                       scr_off)) {
    av_log(avctx, AV_LOG_ERROR, "Error decoding frame data\n");
    return AVERROR_INVALIDDATA;
  }
  memcpy(c->pic.data[1], c->pal, AVPALETTE_SIZE);
  c->pic.palette_has_changed = type & BMV_PALETTE;
  outptr = c->pic.data[0];
  srcptr = c->frame;
  for (i = 0; i < avctx->height; i++) {
    memcpy(outptr, srcptr, avctx->width);
    srcptr += avctx->width;
    outptr += c->pic.linesize[0];
  }
  *got_frame = 1;
  *(AVFrame *)data = c->pic;
  return pkt->size;
}

static Selectivity prefix_selectivity(PlannerInfo *root,
                                      VariableStatData *vardata, Oid vartype,
                                      Oid opfamily, Const *prefixcon) {
  Selectivity prefixsel;
  Oid cmpopr;
  FmgrInfo opproc;
  Const *greaterstrcon;
  Selectivity eq_sel;
  cmpopr = get_opfamily_member(opfamily, vartype, vartype,
                               BTGreaterEqualStrategyNumber);
  if (cmpopr == InvalidOid)
    elog(ERROR, "no >= operator for opfamily %u", opfamily);
  fmgr_info(get_opcode(cmpopr), &opproc);
  prefixsel =
      ineq_histogram_selectivity(root, vardata, &opproc, true,
                                 prefixcon->constvalue, prefixcon->consttype);
  if (prefixsel < 0.0) {
    return DEFAULT_MATCH_SEL;
  }
  cmpopr =
      get_opfamily_member(opfamily, vartype, vartype, BTLessStrategyNumber);
  if (cmpopr == InvalidOid)
    elog(ERROR, "no < operator for opfamily %u", opfamily);
  fmgr_info(get_opcode(cmpopr), &opproc);
  greaterstrcon =
      make_greater_string(prefixcon, &opproc, DEFAULT_COLLATION_OID);
  if (greaterstrcon) {
    Selectivity topsel;
    topsel = ineq_histogram_selectivity(root, vardata, &opproc, false,
                                        greaterstrcon->constvalue,
                                        greaterstrcon->consttype);
    Assert(topsel >= 0.0);
    prefixsel = topsel + prefixsel - 1.0;
  }
  cmpopr =
      get_opfamily_member(opfamily, vartype, vartype, BTEqualStrategyNumber);
  if (cmpopr == InvalidOid)
    elog(ERROR, "no = operator for opfamily %u", opfamily);
  eq_sel = var_eq_const(vardata, cmpopr, prefixcon->constvalue, false, true);
  prefixsel = Max(prefixsel, eq_sel);
  return prefixsel;
}

