static int is_afio_large(const char *h, size_t len) {
  if (len < afiol_header_size)
    return (0);
  if (h[afiol_ino_m_offset] != 'm' || h[afiol_mtime_n_offset] != 'n' ||
      h[afiol_xsize_s_offset] != 's' || h[afiol_filesize_c_offset] != ':')
    return (0);
  if (!is_hex(h + afiol_dev_offset, afiol_ino_m_offset - afiol_dev_offset))
    return (0);
  if (!is_hex(h + afiol_mode_offset, afiol_mtime_n_offset - afiol_mode_offset))
    return (0);
  if (!is_hex(h + afiol_namesize_offset,
              afiol_xsize_s_offset - afiol_namesize_offset))
    return (0);
  if (!is_hex(h + afiol_filesize_offset, afiol_filesize_size))
    return (0);
  return (1);
}

static void pk_transaction_get_repo_list(PkTransaction *transaction,
                                         GVariant *params,
                                         GDBusMethodInvocation *context) {
  PkBitfield filter;
  g_autoptr(GError) error = NULL;
  g_return_if_fail(PK_IS_TRANSACTION(transaction));
  g_return_if_fail(transaction->priv->tid != NULL);
  g_variant_get(params, "(t)", &filter);
  g_debug("GetRepoList method called");
  if (!pk_backend_is_implemented(transaction->priv->backend,
                                 PK_ROLE_ENUM_GET_REPO_LIST)) {
    g_set_error(&error, PK_TRANSACTION_ERROR,
                PK_TRANSACTION_ERROR_NOT_SUPPORTED,
                "GetRepoList not supported by backend");
    pk_transaction_set_state(transaction, PK_TRANSACTION_STATE_ERROR);
    goto out;
  }
  transaction->priv->cached_filters = filter;
  pk_transaction_set_role(transaction, PK_ROLE_ENUM_GET_REPO_LIST);
  pk_transaction_set_state(transaction, PK_TRANSACTION_STATE_READY);
out:
  pk_transaction_dbus_return(context, error);
}

static inline krb5_error_code data_to_gss(krb5_data *input_k5data,
                                          gss_buffer_t output_buffer) {
  krb5_error_code code = 0;
  output_buffer->length = input_k5data->length;
#if defined(_WIN32) || defined(DEBUG_GSSALLOC) if (output_buffer->length > 0) {
  output_buffer->value = gssalloc_malloc(output_buffer->length);
  if (output_buffer->value)
    memcpy(output_buffer->value, input_k5data->data, output_buffer->length);
