WORK_STATE ossl_statem_server_pre_work(SSL *s, WORK_STATE wst) {
  OSSL_STATEM *st = &s->statem;
  switch (st->hand_state) {
  case TLS_ST_SW_HELLO_REQ:
    s->shutdown = 0;
    if (SSL_IS_DTLS(s))
      dtls1_clear_sent_buffer(s);
    break;
  case DTLS_ST_SW_HELLO_VERIFY_REQUEST:
    s->shutdown = 0;
    if (SSL_IS_DTLS(s)) {
      dtls1_clear_sent_buffer(s);
      st->use_timer = 0;
    }
    break;
  case TLS_ST_SW_SRVR_HELLO:
    if (SSL_IS_DTLS(s)) {
      st->use_timer = 1;
    }
    break;
  case TLS_ST_SW_SRVR_DONE:
#ifndef OPENSSL_NO_SCTP if (SSL_IS_DTLS(s) &&
                                BIO_dgram_is_sctp(SSL_get_wbio(
                                    s))) return dtls_wait_for_dry(s);
#endif return WORK_FINISHED_CONTINUE;
  case TLS_ST_SW_SESSION_TICKET:
    if (SSL_IS_DTLS(s)) {
      st->use_timer = 0;
    }
    break;
  case TLS_ST_SW_CHANGE:
    s->session->cipher = s->s3->tmp.new_cipher;
    if (!s->method->ssl3_enc->setup_key_block(s)) {
      ossl_statem_set_error(s);
      return WORK_ERROR;
    }
    if (SSL_IS_DTLS(s)) {
      st->use_timer = 0;
    }
    return WORK_FINISHED_CONTINUE;
  case TLS_ST_OK:
    return tls_finish_handshake(s, wst);
  default:
    break;
  }
  return WORK_FINISHED_CONTINUE;
}

static void sipr_decode_lp(float *lsfnew, const float *lsfold, float *Az,
                           int num_subfr) {
  double lsfint[LP_FILTER_ORDER];
  int i, j;
  float t, t0 = 1.0 / num_subfr;
  t = t0 * 0.5;
  for (i = 0; i < num_subfr; i++) {
    for (j = 0; j < LP_FILTER_ORDER; j++)
      lsfint[j] = lsfold[j] * (1 - t) + t * lsfnew[j];
    ff_amrwb_lsp2lpc(lsfint, Az, LP_FILTER_ORDER);
    Az += LP_FILTER_ORDER;
    t += t0;
  }
}

static void _slurm_rpc_node_registration(slurm_msg_t *msg,
                                         bool running_composite) {
  DEF_TIMERS;
  int error_code = SLURM_SUCCESS;
  bool newly_up = false;
  slurm_node_registration_status_msg_t *node_reg_stat_msg =
      (slurm_node_registration_status_msg_t *)msg->data;
  slurmctld_lock_t job_write_lock = {READ_LOCK, WRITE_LOCK, WRITE_LOCK, NO_LOCK,
                                     READ_LOCK};
  uid_t uid = g_slurm_auth_get_uid(msg->auth_cred, slurmctld_config.auth_info);
  START_TIMER;
  debug2("Processing RPC: MESSAGE_NODE_REGISTRATION_STATUS from uid=%d", uid);
  if (!validate_slurm_user(uid)) {
    error_code = ESLURM_USER_ID_MISSING;
    error("Security violation, NODE_REGISTER RPC from uid=%d", uid);
  }
  if (msg->protocol_version != SLURM_PROTOCOL_VERSION)
    info("Node %s appears to have a different version "
         "of Slurm than ours. Please update at your earliest "
         "convenience.",
         node_reg_stat_msg->node_name);
  if (error_code == SLURM_SUCCESS) {
    if (!(slurmctld_conf.debug_flags & DEBUG_FLAG_NO_CONF_HASH) &&
        (node_reg_stat_msg->hash_val != NO_VAL) &&
        (node_reg_stat_msg->hash_val != slurm_get_hash_val())) {
      error("Node %s appears to have a different slurm.conf "
            "than the slurmctld. This could cause issues "
            "with communication and functionality. "
            "Please review both files and make sure they "
            "are the same. If this is expected ignore, and "
            "set DebugFlags=NO_CONF_HASH in your slurm.conf.",
            node_reg_stat_msg->node_name);
    }
    if (!running_composite)
      lock_slurmctld(job_write_lock);
#ifdef HAVE_FRONT_END error_code = validate_nodes_via_front_end(               \
    node_reg_stat_msg, msg->protocol_version, &newly_up);
#else validate_jobs_on_node(node_reg_stat_msg);
    error_code = validate_node_specs(node_reg_stat_msg, msg->protocol_version,
                                     &newly_up);
#endif if (!running_composite) unlock_slurmctld(job_write_lock);
    END_TIMER2("_slurm_rpc_node_registration");
    if (newly_up) {
      queue_job_scheduler();
    }
  }
  if (error_code) {
    error("_slurm_rpc_node_registration node=%s: %s",
          node_reg_stat_msg->node_name, slurm_strerror(error_code));
    slurm_send_rc_msg(msg, error_code);
  } else {
    debug2("_slurm_rpc_node_registration complete for %s %s",
           node_reg_stat_msg->node_name, TIME_STR);
    slurm_send_rc_msg(msg, SLURM_SUCCESS);
  }
}

