        verbose_print("VERBOSE: Command line: ");
        while (j < argc) {
          verbose_print("%s ", argv[j]);
          j += 1;
        }
        verbose_print("\n");
      }
      break;
    case OPT_HELP:
      help();
      return EXIT_CODE_SUCCESS;
