hb_bool_t hb_shape_plan_execute(hb_shape_plan_t *shape_plan, hb_font_t *font,
                                hb_buffer_t *buffer,
                                const hb_feature_t *features,
                                unsigned int num_features) {
  DEBUG_MSG_FUNC(SHAPE_PLAN, shape_plan, "num_features=%d shaper_func=%p",
                 num_features, shape_plan->shaper_func);
  if (unlikely(hb_object_is_inert(shape_plan) || hb_object_is_inert(font) ||
               hb_object_is_inert(buffer)))
    return false;
  assert(shape_plan->face_unsafe == font->face);
  assert(hb_segment_properties_equal(&shape_plan->props, &buffer->props));
#define HB_SHAPER_EXECUTE (shaper) HB_STMT_START {
  return HB_SHAPER_DATA(shaper, shape_plan) &&
         hb_##shaper##_shaper_font_data_ensure(font) &&
         _hb_##shaper##_shape(shape_plan, font, buffer, features, num_features);
}
HB_STMT_END if (0);
#define HB_SHAPER_IMPLEMENT                                                    \
  (shaper) else if (shape_plan->shaper_func == _hb_##shaper##_shape)           \
      HB_SHAPER_EXECUTE(shaper);
#include "hb-shaper-list.hh" #undef HB_SHAPER_IMPLEMENT #undef HB_SHAPER_EXECUTE return false;
}

xmlListPtr xmlListCreate(xmlListDeallocator deallocator,
                         xmlListDataCompare compare) {
  xmlListPtr l;
  if (NULL == (l = (xmlListPtr)xmlMalloc(sizeof(xmlList)))) {
    xmlGenericError(xmlGenericErrorContext,
                    "Cannot initialize memory for list");
    return (NULL);
  }
  memset(l, 0, sizeof(xmlList));
  if (NULL == (l->sentinel = (xmlLinkPtr)xmlMalloc(sizeof(xmlLink)))) {
    xmlGenericError(xmlGenericErrorContext,
                    "Cannot initialize memory for sentinel");
    xmlFree(l);
    return (NULL);
  }
  l->sentinel->next = l->sentinel;
  l->sentinel->prev = l->sentinel;
  l->sentinel->data = NULL;
  if (deallocator != NULL)
    l->linkDeallocator = deallocator;
  if (compare != NULL)
    l->linkCompare = compare;
  else
    l->linkCompare = xmlLinkCompare;
  return l;
}

static int selinux_tun_dev_open(void *security) {
  struct tun_security_struct *tunsec = security;
  u32 sid = current_sid();
  int err;
  err = avc_has_perm(sid, tunsec->sid, SECCLASS_TUN_SOCKET,
                     TUN_SOCKET__RELABELFROM, NULL);
  if (err)
    return err;
  err =
      avc_has_perm(sid, sid, SECCLASS_TUN_SOCKET, TUN_SOCKET__RELABELTO, NULL);
