void evsignal_dealloc(struct event_base *base) {
  int i = 0;
  if (base->sig.ev_signal_added) {
    event_del(&base->sig.ev_signal);
    base->sig.ev_signal_added = 0;
  }
  for (i = 0; i < NSIG; ++i) {
    if (i < base->sig.sh_old_max && base->sig.sh_old[i] != NULL)
      _evsignal_restore_handler(base, i);
  }
  EVUTIL_CLOSESOCKET(base->sig.ev_signal_pair[0]);
  base->sig.ev_signal_pair[0] = -1;
  EVUTIL_CLOSESOCKET(base->sig.ev_signal_pair[1]);
  base->sig.ev_signal_pair[1] = -1;
  base->sig.sh_old_max = 0;
  free(base->sig.sh_old);
}

static gboolean logcat_dump_text(wtap_dumper *wdh,
                                 const struct wtap_pkthdr *phdr,
                                 const guint8 *pd, int *err) {
  gchar *buf;
  gint length;
  gchar priority;
  const struct logger_entry *log_entry = (struct logger_entry *)pd;
  const struct logger_entry_v2 *log_entry_v2 = (struct logger_entry_v2 *)pd;
  gint payload_length;
  const gchar *tag;
  gint32 pid;
  gint32 tid;
  gint32 seconds;
  gint32 milliseconds;
  const gchar *msg_begin;
  gint msg_pre_skip;
  gchar *log;
  gchar *log_part;
  gchar *log_next;
  const union wtap_pseudo_header *pseudo_header = &phdr->pseudo_header;
  const struct dumper_t *dumper = (const struct dumper_t *)wdh->priv;
  if (phdr->rec_type != REC_TYPE_PACKET) {
    *err = WTAP_ERR_REC_TYPE_UNSUPPORTED;
    return FALSE;
  }
  payload_length = GINT32_FROM_LE(log_entry->len);
  pid = GINT32_FROM_LE(log_entry->pid);
  tid = GINT32_FROM_LE(log_entry->tid);
  seconds = GINT32_FROM_LE(log_entry->sec);
  milliseconds = GINT32_FROM_LE(log_entry->nsec) / 1000000;
  if (pseudo_header->logcat.version == 1) {
    priority = get_priority(log_entry->msg[0]);
    tag = log_entry->msg + 1;
    msg_pre_skip = 1 + strlen(tag) + 1;
    msg_begin = log_entry->msg + msg_pre_skip;
  } else if (pseudo_header->logcat.version == 2) {
    priority = get_priority(log_entry_v2->msg[0]);
    tag = log_entry_v2->msg + 1;
    msg_pre_skip = 1 + strlen(tag) + 1;
    msg_begin = log_entry_v2->msg + msg_pre_skip;
  } else {
    *err = WTAP_ERR_UNSUPPORTED;
    return FALSE;
  }
  log = g_strndup(msg_begin, payload_length - msg_pre_skip);
  log_next = log;
  do {
    log_part = log_next;
    if (dumper->type == DUMP_LONG) {
      log_next = NULL;
    } else {
      log_next = strchr(log_part, '\n');
      if (log_next != NULL) {
        *log_next = '\0';
        ++log_next;
        if (*log_next == '\0') {
          log_next = NULL;
        }
      }
    }
    buf = logcat_log(dumper, seconds, milliseconds, pid, tid, priority, tag,
                     log_part);
    if (!buf) {
      g_free(log);
      return FALSE;
    }
    length = (guint32)strlen(buf);
    if (!wtap_dump_file_write(wdh, buf, length, err)) {
      g_free(log);
      return FALSE;
    }
    wdh->bytes_dumped += length;
  } while (log_next != NULL);
  g_free(log);
  return TRUE;
}

static void link_info_done(NautilusDirectory *directory, NautilusFile *file,
                           const char *uri, const char *name, GIcon *icon,
                           gboolean is_launcher, gboolean is_foreign) {
  gboolean is_trusted;
  file->details->link_info_is_up_to_date = TRUE;
  is_trusted = is_link_trusted(file, is_launcher);
  if (is_trusted) {
    nautilus_file_set_display_name(file, name, name, TRUE);
  } else {
    nautilus_file_set_display_name(file, NULL, NULL, TRUE);
  }
  file->details->got_link_info = TRUE;
  g_clear_object(&file->details->custom_icon);
  if (uri) {
    g_free(file->details->activation_uri);
    file->details->activation_uri = NULL;
    file->details->got_custom_activation_uri = TRUE;
    file->details->activation_uri = g_strdup(uri);
  }
  if (is_trusted && (icon != NULL)) {
    file->details->custom_icon = g_object_ref(icon);
  }
  file->details->is_launcher = is_launcher;
  file->details->is_foreign_link = is_foreign;
  file->details->is_trusted_link = is_trusted;
  nautilus_directory_async_state_changed(directory);
}

static void s390_init(ram_addr_t ram_size, const char *boot_device,
                      const char *kernel_filename, const char *kernel_cmdline,
                      const char *initrd_filename, const char *cpu_model) {
  CPUState *env = NULL;
  ram_addr_t ram_addr;
  ram_addr_t kernel_size = 0;
  ram_addr_t initrd_offset;
  ram_addr_t initrd_size = 0;
  int i;
  if (!kvm_enabled()) {
    fprintf(stderr, "The S390 target only works with KVM enabled\n");
    exit(1);
  }
  s390_bus = s390_virtio_bus_init(&ram_size);
  ram_addr = qemu_ram_alloc(ram_size);
  cpu_register_physical_memory(0, ram_size, ram_addr);
  if (cpu_model == NULL) {
    cpu_model = "host";
  }
  ipi_states = qemu_malloc(sizeof(CPUState *) * smp_cpus);
  for (i = 0; i < smp_cpus; i++) {
    CPUState *tmp_env;
    tmp_env = cpu_init(cpu_model);
    if (!env) {
      env = tmp_env;
    }
    ipi_states[i] = tmp_env;
    tmp_env->halted = 1;
    tmp_env->exception_index = EXCP_HLT;
  }
  env->halted = 0;
  env->exception_index = 0;
  if (kernel_filename) {
    kernel_size = load_image(kernel_filename, qemu_get_ram_ptr(0));
    if (lduw_phys(KERN_IMAGE_START) != 0x0dd0) {
      fprintf(stderr, "Specified image is not an s390 boot image\n");
      exit(1);
    }
    cpu_synchronize_state(env);
    env->psw.addr = KERN_IMAGE_START;
    env->psw.mask = 0x0000000180000000ULL;
  }
  if (initrd_filename) {
    initrd_offset = INITRD_START;
    while (kernel_size + 0x100000 > initrd_offset) {
      initrd_offset += 0x100000;
    }
    initrd_size = load_image(initrd_filename, qemu_get_ram_ptr(initrd_offset));
    stq_phys(INITRD_PARM_START, initrd_offset);
    stq_phys(INITRD_PARM_SIZE, initrd_size);
  }
  if (kernel_cmdline) {
    cpu_physical_memory_rw(KERN_PARM_AREA, (uint8_t *)kernel_cmdline,
                           strlen(kernel_cmdline), 1);
  }
  for (i = 0; i < MAX_VIRTIO_CONSOLES; i++) {
    if (virtcon_hds[i]) {
      qdev_init_nofail(
          qdev_create((BusState *)s390_bus, "virtio-console-s390"));
    }
  }
  for (i = 0; i < nb_nics; i++) {
    NICInfo *nd = &nd_table[i];
    DeviceState *dev;
    if (!nd->model) {
      nd->model = qemu_strdup("virtio");
    }
    if (strcmp(nd->model, "virtio")) {
      fprintf(stderr, "S390 only supports VirtIO nics\n");
      exit(1);
    }
    dev = qdev_create((BusState *)s390_bus, "virtio-net-s390");
    qdev_set_nic_properties(dev, nd);
    qdev_init_nofail(dev);
  }
  for (i = 0; i < MAX_BLK_DEVS; i++) {
    DriveInfo *dinfo;
    DeviceState *dev;
    dinfo = drive_get(IF_IDE, 0, i);
    if (!dinfo) {
      continue;
    }
    dev = qdev_create((BusState *)s390_bus, "virtio-blk-s390");
    qdev_prop_set_drive(dev, "drive", dinfo);
    qdev_init_nofail(dev);
  }
}

