static void main_get_appheader_params(main_file *file, char **parsed,
                                      int output, const char *type,
                                      main_file *other) {
  if (file->filename == NULL && !(output && option_stdout) &&
      strcmp(parsed[0], "-") != 0) {
    file->filename = parsed[0];
    if (other->filename != NULL) {
      const char *last_slash = strrchr(other->filename, '/');
      if (last_slash != NULL) {
        usize_t dlen = (usize_t)(last_slash - other->filename);
        XD3_ASSERT(file->filename_copy == NULL);
        file->filename_copy =
            (char *)main_malloc(dlen + 2 + (usize_t)strlen(file->filename));
        strncpy(file->filename_copy, other->filename, dlen);
        file->filename_copy[dlen] = '/';
        strcpy(file->filename_copy + dlen + 1, parsed[0]);
        file->filename = file->filename_copy;
      }
    }
    if (!option_quiet) {
      XPR(NT "using default %s filename: %s\n", type, file->filename);
    }
  }
  if (file->compressor == NULL && *parsed[1] != 0) {
    file->flags |= RD_DECOMPSET;
    file->compressor = main_get_compressor(parsed[1]);
  }
}

static void parse_previous_duplicate_name(const char *name, char **name_base,
                                          const char **suffix, int *count) {
  const char *tag;
  g_assert(name[0] != '\0');
  *suffix = eel_filename_get_extension_offset(name);
  if (*suffix == NULL || (*suffix)[1] == '\0') {
    *suffix = "";
  }
  tag = strstr(name, COPY_DUPLICATE_TAG);
  if (tag != NULL) {
    if (tag > *suffix) {
      *suffix = "";
    }
    *name_base = extract_string_until(name, tag);
    *count = 1;
    return;
  }
  tag = strstr(name, ANOTHER_COPY_DUPLICATE_TAG);
  if (tag != NULL) {
    if (tag > *suffix) {
      *suffix = "";
    }
    *name_base = extract_string_until(name, tag);
    *count = 2;
    return;
  }
  tag = strstr(name, X11TH_COPY_DUPLICATE_TAG);
  if (tag == NULL) {
    tag = strstr(name, X12TH_COPY_DUPLICATE_TAG);
  }
  if (tag == NULL) {
    tag = strstr(name, X13TH_COPY_DUPLICATE_TAG);
  }
  if (tag == NULL) {
    tag = strstr(name, ST_COPY_DUPLICATE_TAG);
  }
  if (tag == NULL) {
    tag = strstr(name, ND_COPY_DUPLICATE_TAG);
  }
  if (tag == NULL) {
    tag = strstr(name, RD_COPY_DUPLICATE_TAG);
  }
  if (tag == NULL) {
    tag = strstr(name, TH_COPY_DUPLICATE_TAG);
  }
  if (tag != NULL) {
    tag = strstr(name, _(" ("));
    if (tag != NULL) {
      if (tag > *suffix) {
        *suffix = "";
      }
      *name_base = extract_string_until(name, tag);
      if (sscanf(tag, _(" (%'d"), count) == 1) {
        if (*count < 1 || *count > 1000000) {
          *count = 0;
        }
        return;
      }
      *count = 0;
      return;
    }
  }
  *count = 0;
  if (**suffix != '\0') {
    *name_base = extract_string_until(name, *suffix);
  } else {
    *name_base = g_strdup(name);
  }
}

static guint find_head(body_parts **body_parts_array, guint16 *tsn) {
  guint length = 0;
  *tsn = (*tsn == 0) ? (guint16)(MAX_TSN - 1) : (*tsn) - 1;
  for (; body_parts_array[*tsn]->middle != NULL;
       *tsn = (*tsn == 0) ? (guint16)(MAX_TSN - 1) : (*tsn) - 1)
    length += body_parts_array[*tsn]->middle->length;
  if (body_parts_array[*tsn]->head != NULL)
    return length + body_parts_array[*tsn]->head->length;
  return 0;
}

