xmlAttrPtr xsltAttrListTemplateProcess(xsltTransformContextPtr ctxt,
                                       xmlNodePtr target, xmlAttrPtr attrs) {
  xmlAttrPtr attr, copy, last;
  xmlNodePtr oldInsert, text;
  xmlNsPtr origNs = NULL, copyNs = NULL;
  const xmlChar *value;
  xmlChar *valueAVT;
  if ((ctxt == NULL) || (target == NULL) || (attrs == NULL))
    return (NULL);
  oldInsert = ctxt->insert;
  ctxt->insert = target;
  if (target->properties) {
    last = target->properties;
    while (last->next != NULL)
      last = last->next;
  } else {
    last = NULL;
  }
  attr = attrs;
  do {
#ifdef XSLT_REFACTORED if (attr->psvi == xsltXSLTAttrMarker) {
    goto next_attribute;
  }
#else if ((attr->ns != NULL) && xmlStrEqual(attr->ns->href, XSLT_NAMESPACE)) {
    goto next_attribute;
  }
#endif if (attr->children != NULL) {
  if ((attr->children->type != XML_TEXT_NODE) ||
      (attr->children->next != NULL)) {
    xsltTransformError(
        ctxt, NULL, attr->parent,
        "Internal error: The children of an attribute node of a "
        "literal result element are not in the expected form.\n");
    goto error;
  }
  value = attr->children->content;
  if (value == NULL)
    value = xmlDictLookup(ctxt->dict, BAD_CAST "", 0);
}
else value = xmlDictLookup(ctxt->dict, BAD_CAST "", 0);
copy = xmlNewDocProp(target->doc, attr->name, NULL);
if (copy == NULL) {
  if (attr->ns) {
 xsltTransformError ( ctxt , NULL , attr -> parent , "Internal error: Failed to create attribute '{
%s
  }
  % s'.\n" , attr -> ns -> href , attr -> name ) ;
} else {
  xsltTransformError(ctxt, NULL, attr->parent,
                     "Internal error: Failed to create attribute '%s'.\n",
                     attr->name);
}
goto error;
}
copy->parent = target;
if (last == NULL) {
  target->properties = copy;
  last = copy;
} else {
  last->next = copy;
  copy->prev = last;
  last = copy;
}
if (attr->ns != origNs) {
  origNs = attr->ns;
  if (attr->ns != NULL) {
#ifdef XSLT_REFACTORED copyNs = xsltGetSpecialNamespace(                       \
    ctxt, attr->parent, attr->ns->href, attr->ns->prefix, target);
#else copyNs = xsltGetNamespace(ctxt, attr->parent, attr->ns, target);
#endif if (copyNs == NULL) goto error;
  } else
    copyNs = NULL;
}
copy->ns = copyNs;
text = xmlNewText(NULL);
if (text != NULL) {
  copy->last = copy->children = text;
  text->parent = (xmlNodePtr)copy;
  text->doc = copy->doc;
  if (attr->psvi != NULL) {
    valueAVT = xsltEvalAVT(ctxt, attr->psvi, attr->parent);
    if (valueAVT == NULL) {
      if (attr->ns) {
 xsltTransformError ( ctxt , NULL , attr -> parent , "Internal error: Failed to evaluate the AVT " "of attribute '{
%s
      }
      % s'.\n" , attr -> ns -> href , attr -> name ) ;
    } else {
      xsltTransformError(ctxt, NULL, attr->parent,
                         "Internal error: Failed to evaluate the AVT "
                         "of attribute '%s'.\n",
                         attr->name);
    }
    text->content = xmlStrdup(BAD_CAST "");
    goto error;
  } else {
    text->content = valueAVT;
  }
} else if ((ctxt->internalized) && (target->doc != NULL) &&
           (target->doc->dict == ctxt->dict) &&
           xmlDictOwns(ctxt->dict, value)) {
  text->content = (xmlChar *)value;
} else {
  text->content = xmlStrdup(value);
}
if ((copy != NULL) && (text != NULL) &&
    (xmlIsID(copy->doc, copy->parent, copy)))
  xmlAddID(NULL, copy->doc, text->content, copy);
}
next_attribute : attr = attr->next;
}
while (attr != NULL)
  ;
attr = attrs;
do {
#ifdef XSLT_REFACTORED if ((attr->psvi == xsltXSLTAttrMarker) &&               \
                           xmlStrEqual(                                        \
                               attr->name,                                     \
                               (const xmlChar *)"use-attribute-sets")) {
  xsltApplyAttributeSet(ctxt, ctxt->node, (xmlNodePtr)attr, NULL);
}
#else if ((attr->ns != NULL) &&                                                \
          xmlStrEqual(attr->name, (const xmlChar *)"use-attribute-sets") &&    \
          xmlStrEqual(attr->ns->href, XSLT_NAMESPACE)) {
  xsltApplyAttributeSet(ctxt, ctxt->node, (xmlNodePtr)attr, NULL);
}
#endif attr = attr->next;
}
while (attr != NULL)
  ;
ctxt->insert = oldInsert;
return (target->properties);
error : ctxt->insert = oldInsert;
return (NULL);
}

static inline void write_IRQreg_ivpr(OpenPICState *opp, int n_IRQ,
                                     uint32_t val) {
  uint32_t mask;
  mask = IVPR_MASK_MASK | IVPR_PRIORITY_MASK | IVPR_SENSE_MASK |
         IVPR_POLARITY_MASK | opp->vector_mask;
  opp->src[n_IRQ].ivpr =
      (opp->src[n_IRQ].ivpr & IVPR_ACTIVITY_MASK) | (val & mask);
  switch (opp->src[n_IRQ].type) {
  case IRQ_TYPE_NORMAL:
    opp->src[n_IRQ].level = !!(opp->src[n_IRQ].ivpr & IVPR_SENSE_MASK);
    break;
  case IRQ_TYPE_FSLINT:
    opp->src[n_IRQ].ivpr &= ~IVPR_SENSE_MASK;
    break;
  case IRQ_TYPE_FSLSPECIAL:
    opp->src[n_IRQ].ivpr &= ~(IVPR_POLARITY_MASK | IVPR_SENSE_MASK);
    break;
  }
  openpic_update_irq(opp, n_IRQ);
  DPRINTF("Set IVPR %d to 0x%08x -> 0x%08x\n", n_IRQ, val,
          opp->src[n_IRQ].ivpr);
}

