static uint64_t pxa2xx_pm_read(void *opaque, hwaddr addr, unsigned size) {
  PXA2xxState *s = (PXA2xxState *)opaque;
  switch (addr) {
  case PMCR ... PCMD31:
    if (addr & 3)
      goto fail;
    return s->pm_regs[addr >> 2];
  default:
  fail:
    printf("%s: Bad register " REG_FMT "\n", __FUNCTION__, addr);
    break;
  }
  return 0;
}

static void sigcomp_init_udvm(void) {
  gchar *partial_state_str;
  guint8 *sip_sdp_buff, *presence_buff;
  state_buffer_table =
      g_hash_table_new_full(g_str_hash, g_str_equal, g_free, g_free);
  sip_sdp_buff = (guint8 *)g_malloc(SIP_SDP_STATE_LENGTH + 8);
  partial_state_str = bytes_to_str(NULL, sip_sdp_state_identifier, 6);
  memset(sip_sdp_buff, 0, 8);
  sip_sdp_buff[0] = SIP_SDP_STATE_LENGTH >> 8;
  sip_sdp_buff[1] = SIP_SDP_STATE_LENGTH & 0xff;
  memcpy(sip_sdp_buff + 8, sip_sdp_static_dictionaty_for_sigcomp,
         SIP_SDP_STATE_LENGTH);
  g_hash_table_insert(state_buffer_table, g_strdup(partial_state_str),
                      sip_sdp_buff);
  wmem_free(NULL, partial_state_str);
  presence_buff = (guint8 *)g_malloc(PRESENCE_STATE_LENGTH + 8);
  partial_state_str = bytes_to_str(NULL, presence_state_identifier, 6);
  memset(presence_buff, 0, 8);
  presence_buff[0] = PRESENCE_STATE_LENGTH >> 8;
  presence_buff[1] = PRESENCE_STATE_LENGTH & 0xff;
  memcpy(presence_buff + 8, presence_static_dictionary_for_sigcomp,
         PRESENCE_STATE_LENGTH);
  g_hash_table_insert(state_buffer_table, g_strdup(partial_state_str),
                      presence_buff);
  wmem_free(NULL, partial_state_str);
}

static int ebml_read_uint(AVIOContext *pb, int size, uint64_t *num) {
  int n = 0;
  if (size > 8)
    return AVERROR_INVALIDDATA;
  *num = 0;
  while (n++ < size)
    *num = (*num << 8) | avio_r8(pb);
  return 0;
}

static void build_y_mask(const loop_filter_info_n *const lfi_n,
                         const MODE_INFO *mi, const int shift_y,
                         LOOP_FILTER_MASK *lfm) {
  const MB_MODE_INFO *mbmi = &mi->mbmi;
  const BLOCK_SIZE block_size = mbmi->sb_type;
  const TX_SIZE tx_size_y = mbmi->tx_size;
  const int filter_level = get_filter_level(lfi_n, mbmi);
  uint64_t *const left_y = &lfm->left_y[tx_size_y];
  uint64_t *const above_y = &lfm->above_y[tx_size_y];
  uint64_t *const int_4x4_y = &lfm->int_4x4_y;
  int i;
  if (!filter_level) {
    return;
  } else {
    const int w = num_8x8_blocks_wide_lookup[block_size];
    const int h = num_8x8_blocks_high_lookup[block_size];
    int index = shift_y;
    for (i = 0; i < h; i++) {
      vpx_memset(&lfm->lfl_y[index], filter_level, w);
      index += 8;
    }
  }
  *above_y |= above_prediction_mask[block_size] << shift_y;
  *left_y |= left_prediction_mask[block_size] << shift_y;
  if (mbmi->skip && is_inter_block(mbmi))
    return;
  *above_y |= (size_mask[block_size] & above_64x64_txform_mask[tx_size_y])
              << shift_y;
  *left_y |= (size_mask[block_size] & left_64x64_txform_mask[tx_size_y])
             << shift_y;
  if (tx_size_y == TX_4X4)
    *int_4x4_y |= (size_mask[block_size] & 0xffffffffffffffff) << shift_y;
}

