static uint64_t openpic_gbl_read(void *opaque, hwaddr addr, unsigned len) {
  OpenPICState *opp = opaque;
  uint32_t retval;
  DPRINTF("%s: addr %#" HWADDR_PRIx "\n", __func__, addr);
  retval = 0xFFFFFFFF;
  if (addr & 0xF) {
    return retval;
  }
  switch (addr) {
  case 0x1000:
    retval = opp->frr;
    break;
  case 0x1020:
    retval = opp->gcr;
    break;
  case 0x1080:
    retval = opp->vir;
    break;
  case 0x1090:
    retval = 0x00000000;
    break;
  case 0x00:
    retval = opp->brr1;
    break;
  case 0x40:
  case 0x50:
  case 0x60:
  case 0x70:
  case 0x80:
  case 0x90:
  case 0xA0:
  case 0xB0:
    retval = openpic_cpu_read_internal(opp, addr, get_current_cpu());
    break;
  case 0x10A0:
  case 0x10B0:
  case 0x10C0:
  case 0x10D0: {
    int idx;
    idx = (addr - 0x10A0) >> 4;
    retval = read_IRQreg_ivpr(opp, opp->irq_ipi0 + idx);
  } break;
  case 0x10E0:
    retval = opp->spve;
    break;
  default:
    break;
  }
  DPRINTF("%s: => 0x%08x\n", __func__, retval);
  return retval;
}

