                  NVRAM_END - NVRAM_OSAREA_SIZE - NVRAM_CONFSIZE - 0x0100);
  NVRAM_set_lword(nvram, 0xD4, NVRAM_END - NVRAM_CONFSIZE);
  NVRAM_set_lword(nvram, 0xD8, NVRAM_CONFSIZE);
