int qemuMonitorTextSendKey(qemuMonitorPtr mon, unsigned int holdtime,
                           unsigned int *keycodes, unsigned int nkeycodes) {
  int i;
  virBuffer buf = VIR_BUFFER_INITIALIZER;
  char *cmd, *reply = NULL;
  int ret = -1;
  if (nkeycodes > VIR_DOMAIN_SEND_KEY_MAX_KEYS || nkeycodes == 0)
    return -1;
  virBufferAddLit(&buf, "sendkey ");
  for (i = 0; i < nkeycodes; i++) {
    if (keycodes[i] > 0xffff) {
      qemuReportError(VIR_ERR_OPERATION_FAILED,
                      _("keycode %d is invalid: 0x%X"), i, keycodes[i]);
      virBufferFreeAndReset(&buf);
      return -1;
    }
    if (i)
      virBufferAddChar(&buf, '-');
    virBufferAsprintf(&buf, "0x%02X", keycodes[i]);
  }
  if (holdtime)
    virBufferAsprintf(&buf, " %u", holdtime);
  if (virBufferError(&buf)) {
    virReportOOMError();
    return -1;
  }
  cmd = virBufferContentAndReset(&buf);
  if (qemuMonitorHMPCommand(mon, cmd, &reply) < 0) {
    qemuReportError(VIR_ERR_OPERATION_FAILED,
                    _("failed to send key using command '%s'"), cmd);
    goto cleanup;
  }
  if (STRNEQ(reply, "")) {
    qemuReportError(VIR_ERR_OPERATION_FAILED, _("failed to send key '%s'"),
                    reply);
    goto cleanup;
  }
  ret = 0;
cleanup:
  VIR_FREE(cmd);
  VIR_FREE(reply);
  return ret;
}

void PNGAPI png_set_iCCP(png_structp png_ptr, png_infop info_ptr,
                         png_charp name, int compression_type,
                         png_charp profile, png_uint_32 proflen) {
  png_charp new_iccp_name;
  png_charp new_iccp_profile;
  png_uint_32 length;
  png_debug1(1, "in %s storage function", "iCCP");
  if (png_ptr == NULL || info_ptr == NULL || name == NULL || profile == NULL)
    return;
  length = png_strlen(name) + 1;
  new_iccp_name = (png_charp)png_malloc_warn(png_ptr, length);
  if (new_iccp_name == NULL) {
    png_warning(png_ptr, "Insufficient memory to process iCCP chunk.");
    return;
  }
  png_memcpy(new_iccp_name, name, length);
  new_iccp_profile = (png_charp)png_malloc_warn(png_ptr, proflen);
  if (new_iccp_profile == NULL) {
    png_free(png_ptr, new_iccp_name);
    png_warning(png_ptr, "Insufficient memory to process iCCP profile.");
    return;
  }
  png_memcpy(new_iccp_profile, profile, (png_size_t)proflen);
  png_free_data(png_ptr, info_ptr, PNG_FREE_ICCP, 0);
  info_ptr->iccp_proflen = proflen;
  info_ptr->iccp_name = new_iccp_name;
  info_ptr->iccp_profile = new_iccp_profile;
  info_ptr->iccp_compression = (png_byte)compression_type;
#ifdef PNG_FREE_ME_SUPPORTED info_ptr->free_me |= PNG_FREE_ICCP;
#endif info_ptr->valid |= PNG_INFO_iCCP;
}

