static int _warc_read(struct archive_read *a, const void **buf, size_t *bsz,
                      int64_t *off) {
  struct warc_s *w = a->format->data;
  const char *rab;
  ssize_t nrd;
  if (w->cntoff >= w->cntlen) {
  eof:
    *buf = NULL;
    *bsz = 0U;
    *off = w->cntoff + 4U;
    w->unconsumed = 0U;
    return (ARCHIVE_EOF);
  }
  if (w->unconsumed) {
    __archive_read_consume(a, w->unconsumed);
    w->unconsumed = 0U;
  }
  rab = __archive_read_ahead(a, 1U, &nrd);
  if (nrd < 0) {
    *bsz = 0U;
    return (int)nrd;
  } else if (nrd == 0) {
    goto eof;
  } else if ((size_t)nrd > w->cntlen - w->cntoff) {
    nrd = w->cntlen - w->cntoff;
  }
  *off = w->cntoff;
  *bsz = nrd;
  *buf = rab;
  w->cntoff += nrd;
  w->unconsumed = (size_t)nrd;
  return (ARCHIVE_OK);
}

static struct passwd *check_perms(void) {
#ifdef USE_PAM const char *tmp_name;
  int ret;
#endif struct passwd *pw = xgetpwnam(name);
  if (NULL == pw) {
    (void)fprintf(stderr, _("No passwd entry for user '%s'\n"), name);
    SYSLOG((LOG_NOTICE, "No passwd entry for user '%s'", name));
    su_failure(caller_tty, true);
  }
  (void)signal(SIGINT, SIG_IGN);
  (void)signal(SIGQUIT, SIG_IGN);
#ifdef USE_PAM check_perms_pam(pw);
  ret = pam_get_item(pamh, PAM_USER, (const void **)&tmp_name);
  if (ret != PAM_SUCCESS) {
    SYSLOG((LOG_ERR, "pam_get_item: internal PAM error\n"));
    (void)fprintf(stderr, "%s: Internal PAM error retrieving username\n", Prog);
    (void)pam_end(pamh, ret);
    su_failure(caller_tty, 0 == pw->pw_uid);
  }
  if (strcmp(name, tmp_name) != 0) {
    SYSLOG((LOG_INFO, "Change user from '%s' to '%s' as requested by PAM", name,
            tmp_name));
    strncpy(name, tmp_name, sizeof(name) - 1);
    name[sizeof(name) - 1] = '\0';
    pw = xgetpwnam(name);
    if (NULL == pw) {
      (void)fprintf(stderr, _("No passwd entry for user '%s'\n"), name);
      SYSLOG((LOG_NOTICE, "No passwd entry for user '%s'", name));
      su_failure(caller_tty, true);
    }
  }
#else check_perms_nopam(pw);
#endif(void) signal(SIGINT, SIG_DFL);
  (void)signal(SIGQUIT, SIG_DFL);
  if ('*' == pw->pw_shell[0]) {
    subsystem(pw);
    endpwent();
    endspent();
    pw_free(pw);
    return check_perms();
  }
  return pw;
}

