  VAR *v;
  DBUG_ENTER("var_get");
  DBUG_PRINT("enter", ("var_name: %s", var_name));
  if (*var_name != '$')
    goto err;
  digit = *++var_name - '0';
  if (digit < 0 || digit >= 10) {
    const char *save_var_name = var_name, *end;
    uint length;
    end = (var_name_end) ? *var_name_end : 0;
    while (my_isvar(charset_info, *var_name) && var_name != end)
      var_name++;
    if (var_name == save_var_name) {
      if (ignore_not_existing)
        DBUG_RETURN(0);
      die("Empty variable");
    }
    length = (uint)(var_name - save_var_name);
    if (length >= MAX_VAR_NAME_LENGTH)
      die("Too long variable name: %s", save_var_name);
    if (!(v = (VAR *)my_hash_search(&var_hash, (const uchar *)save_var_name,
                                    length))) {
      char buff[MAX_VAR_NAME_LENGTH + 1];
      strmake(buff, save_var_name, length);
      v = var_from_env(buff, "");
    }
    var_name--;
  } else
    v = var_reg + digit;
  if (!raw && v->int_dirty) {
    sprintf(v->str_val, "%d", v->int_val);
    v->int_dirty = false;
    v->str_val_len = strlen(v->str_val);
  }
  if (var_name_end)
    *var_name_end = var_name;
  DBUG_RETURN(v);
err:
  if (var_name_end)
    *var_name_end = 0;
  die("Unsupported variable name: %s", var_name);
  DBUG_RETURN(0);
}

static void decode_pitch_vector(AMRContext *p,
                                const AMRNBSubframe *amr_subframe,
                                const int subframe) {
  int pitch_lag_int, pitch_lag_frac;
  enum Mode mode = p->cur_frame_mode;
  if (p->cur_frame_mode == MODE_12k2) {
    decode_pitch_lag_1_6(&pitch_lag_int, &pitch_lag_frac, amr_subframe->p_lag,
                         p->pitch_lag_int, subframe);
  } else
    ff_decode_pitch_lag(&pitch_lag_int, &pitch_lag_frac, amr_subframe->p_lag,
                        p->pitch_lag_int, subframe,
                        mode != MODE_4k75 && mode != MODE_5k15,
                        mode <= MODE_6k7 ? 4 : (mode == MODE_7k95 ? 5 : 6));
  p->pitch_lag_int = pitch_lag_int;
  pitch_lag_frac <<= (p->cur_frame_mode != MODE_12k2);
  pitch_lag_int += pitch_lag_frac > 0;
  ff_acelp_interpolatef(
      p->excitation, p->excitation + 1 - pitch_lag_int, ff_b60_sinc, 6,
      pitch_lag_frac + 6 - 6 * (pitch_lag_frac > 0), 10, AMR_SUBFRAME_SIZE);
  memcpy(p->pitch_vector, p->excitation, AMR_SUBFRAME_SIZE * sizeof(float));
}

