char get_rel_persistence(Oid relid) {
  HeapTuple tp;
  Form_pg_class reltup;
  char result;
  tp = SearchSysCache1(RELOID, ObjectIdGetDatum(relid));
  if (!HeapTupleIsValid(tp))
    elog(ERROR, "cache lookup failed for relation %u", relid);
  reltup = (Form_pg_class)GETSTRUCT(tp);
  result = reltup->relpersistence;
  ReleaseSysCache(tp);
  return result;
}

static guint32 number_of_markers(mpa_state_t *state, struct tcpinfo *tcpinfo,
                                 guint8 endpoint) {
  guint32 size;
  guint32 offset;
  size = fpdu_total_length(tcpinfo);
  offset = get_first_marker_offset(state, tcpinfo, endpoint);
  if (offset < size) {
    return ((size - offset) / MPA_MARKER_INTERVAL) + 1;
  } else {
    return 0;
  }
}

void compute_curve_gamma_table_type2(float gamma_table[256], uint16_t *table,
                                     size_t length) {
  unsigned int i;
  for (i = 0; i < 256; i++) {
    gamma_table[i] = lut_interp_linear(i / 255., table, length);
  }
}

