static zval *row_prop_read(zval *object, zval *member, int type,
                           const zend_literal *key TSRMLS_DC) {
  zval *return_value;
  pdo_stmt_t *stmt =
      (pdo_stmt_t *)zend_object_store_get_object(object TSRMLS_CC);
  int colno = -1;
  MAKE_STD_ZVAL(return_value);
  RETVAL_NULL();
  if (stmt) {
    if (Z_TYPE_P(member) == IS_LONG) {
      if (Z_LVAL_P(member) >= 0 && Z_LVAL_P(member) < stmt->column_count) {
        fetch_value(stmt, return_value, Z_LVAL_P(member), NULL TSRMLS_CC);
      }
    } else {
      convert_to_string(member);
      for (colno = 0; colno < stmt->column_count; colno++) {
        if (strcmp(stmt->columns[colno].name, Z_STRVAL_P(member)) == 0) {
          fetch_value(stmt, return_value, colno, NULL TSRMLS_CC);
          Z_SET_REFCOUNT_P(return_value, 0);
          Z_UNSET_ISREF_P(return_value);
          return return_value;
        }
      }
      if (strcmp(Z_STRVAL_P(member), "queryString") == 0) {
        zval_ptr_dtor(&return_value);
        return std_object_handlers.read_property(object, member, type,
                                                 key TSRMLS_CC);
      }
    }
  }
  Z_SET_REFCOUNT_P(return_value, 0);
  Z_UNSET_ISREF_P(return_value);
  return return_value;
}

static int mpeg_decode_frame(AVCodecContext *avctx, void *data, int *got_output,
                             AVPacket *avpkt) {
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  Mpeg1Context *s = avctx->priv_data;
  AVFrame *picture = data;
  MpegEncContext *s2 = &s->mpeg_enc_ctx;
  av_dlog(avctx, "fill_buffer\n");
  if (buf_size == 0 || (buf_size == 4 && AV_RB32(buf) == SEQ_END_CODE)) {
    if (s2->low_delay == 0 && s2->next_picture_ptr) {
      int ret = av_frame_ref(picture, &s2->next_picture_ptr->f);
      if (ret < 0)
        return ret;
      s2->next_picture_ptr = NULL;
      *got_output = 1;
    }
    return buf_size;
  }
  if (s2->flags & CODEC_FLAG_TRUNCATED) {
    int next = ff_mpeg1_find_frame_end(&s2->parse_context, buf, buf_size, NULL);
    if (ff_combine_frame(&s2->parse_context, next, (const uint8_t **)&buf,
                         &buf_size) < 0)
      return buf_size;
  }
  if (s->mpeg_enc_ctx_allocated == 0 && avctx->codec_tag == AV_RL32("VCR2"))
    vcr2_init_sequence(avctx);
  s->slice_count = 0;
  if (avctx->extradata && !s->extradata_decoded) {
    int ret = decode_chunks(avctx, picture, got_output, avctx->extradata,
                            avctx->extradata_size);
    s->extradata_decoded = 1;
    if (ret < 0 && (avctx->err_recognition & AV_EF_EXPLODE))
      return ret;
  }
  return decode_chunks(avctx, picture, got_output, buf, buf_size);
}

static void swap_block_ptr(MACROBLOCK *x, PICK_MODE_CONTEXT *ctx, int m, int n,
                           int min_plane, int max_plane) {
  int i;
  for (i = min_plane; i < max_plane; ++i) {
    struct macroblock_plane *const p = &x->plane[i];
    struct macroblockd_plane *const pd = &x->e_mbd.plane[i];
    p->coeff = ctx->coeff_pbuf[i][m];
    p->qcoeff = ctx->qcoeff_pbuf[i][m];
    pd->dqcoeff = ctx->dqcoeff_pbuf[i][m];
    p->eobs = ctx->eobs_pbuf[i][m];
    ctx->coeff_pbuf[i][m] = ctx->coeff_pbuf[i][n];
    ctx->qcoeff_pbuf[i][m] = ctx->qcoeff_pbuf[i][n];
    ctx->dqcoeff_pbuf[i][m] = ctx->dqcoeff_pbuf[i][n];
    ctx->eobs_pbuf[i][m] = ctx->eobs_pbuf[i][n];
    ctx->coeff_pbuf[i][n] = p->coeff;
    ctx->qcoeff_pbuf[i][n] = p->qcoeff;
    ctx->dqcoeff_pbuf[i][n] = pd->dqcoeff;
    ctx->eobs_pbuf[i][n] = p->eobs;
  }
}

