static void compress_task_thread_func(GTask *task, gpointer source_object,
                                      gpointer task_data,
                                      GCancellable *cancellable) {
  CompressJob *compress_job = task_data;
  SourceInfo source_info;
  g_autoptr(AutoarCompressor) compressor = NULL;
  g_timer_start(compress_job->common.time);
  nautilus_progress_info_start(compress_job->common.progress);
  scan_sources(compress_job->source_files, &source_info,
               (CommonJob *)compress_job, OP_KIND_COMPRESS);
  compress_job->total_files = source_info.num_files;
  compress_job->total_size = source_info.num_bytes;
  compressor = autoar_compressor_new(
      compress_job->source_files, compress_job->output_file,
      compress_job->format, compress_job->filter, FALSE);
  autoar_compressor_set_output_is_dest(compressor, TRUE);
  autoar_compressor_set_notify_interval(compressor, PROGRESS_NOTIFY_INTERVAL);
  g_signal_connect(compressor, "progress", G_CALLBACK(compress_job_on_progress),
                   compress_job);
  g_signal_connect(compressor, "error", G_CALLBACK(compress_job_on_error),
                   compress_job);
  g_signal_connect(compressor, "completed",
                   G_CALLBACK(compress_job_on_completed), compress_job);
  autoar_compressor_start(compressor, compress_job->common.cancellable);
  compress_job->success = g_file_query_exists(compress_job->output_file, NULL);
  if (compress_job->common.undo_info != NULL && !compress_job->success) {
    g_clear_object(&compress_job->common.undo_info);
  }
}

static Image *ReadARTImage(const ImageInfo *image_info,
                           ExceptionInfo *exception) {
  const unsigned char *pixels;
  Image *image;
  QuantumInfo *quantum_info;
  QuantumType quantum_type;
  MagickBooleanType status;
  size_t length;
  ssize_t count, y;
  assert(image_info != (const ImageInfo *)NULL);
  assert(image_info->signature == MagickSignature);
  if (image_info->debug != MagickFalse)
    (void)LogMagickEvent(TraceEvent, GetMagickModule(), "%s",
                         image_info->filename);
  assert(exception != (ExceptionInfo *)NULL);
  assert(exception->signature == MagickSignature);
  image = AcquireImage(image_info);
  status = OpenBlob(image_info, image, ReadBinaryBlobMode, exception);
  if (status == MagickFalse) {
    image = DestroyImageList(image);
    return ((Image *)NULL);
  }
  image->depth = 1;
  image->endian = MSBEndian;
  (void)ReadBlobLSBShort(image);
  image->columns = (size_t)ReadBlobLSBShort(image);
  (void)ReadBlobLSBShort(image);
  image->rows = (size_t)ReadBlobLSBShort(image);
  if ((image->columns == 0) || (image->rows == 0))
    ThrowReaderException(CorruptImageError, "ImproperImageHeader");
  if (AcquireImageColormap(image, 2) == MagickFalse)
    ThrowReaderException(ResourceLimitError, "MemoryAllocationFailed");
  if (image_info->ping != MagickFalse) {
    (void)CloseBlob(image);
    return (GetFirstImageInList(image));
  }
  status = SetImageExtent(image, image->columns, image->rows);
  if (status == MagickFalse) {
    InheritException(exception, &image->exception);
    return (DestroyImageList(image));
  }
  SetImageColorspace(image, GRAYColorspace);
  quantum_type = IndexQuantum;
  quantum_info = AcquireQuantumInfo(image_info, image);
  if (quantum_info == (QuantumInfo *)NULL)
    ThrowReaderException(ResourceLimitError, "MemoryAllocationFailed");
  length = GetQuantumExtent(image, quantum_info, quantum_type);
  for (y = 0; y < (ssize_t)image->rows; y++) {
    register PixelPacket *magick_restrict q;
    q = QueueAuthenticPixels(image, 0, y, image->columns, 1, exception);
    if (q == (PixelPacket *)NULL)
      break;
    pixels = (const unsigned char *)ReadBlobStream(
        image, length, GetQuantumPixels(quantum_info), &count);
    if (count != (ssize_t)length)
      ThrowReaderException(CorruptImageError, "UnableToReadImageData");
    (void)ImportQuantumPixels(image, (CacheView *)NULL, quantum_info,
                              quantum_type, pixels, exception);
    (void)ReadBlobStream(image, (size_t)(-(ssize_t)length) & 0x01,
                         GetQuantumPixels(quantum_info), &count);
    if (SyncAuthenticPixels(image, exception) == MagickFalse)
      break;
    status =
        SetImageProgress(image, LoadImageTag, (MagickOffsetType)y, image->rows);
    if (status == MagickFalse)
      break;
  }
  SetQuantumImageType(image, quantum_type);
  quantum_info = DestroyQuantumInfo(quantum_info);
  if (EOFBlob(image) != MagickFalse)
    ThrowFileException(exception, CorruptImageError, "UnexpectedEndOfFile",
                       image->filename);
  (void)CloseBlob(image);
  return (GetFirstImageInList(image));
}

int udp_v6_get_port(struct sock *sk, unsigned short snum) {
  unsigned int hash2_nulladdr =
      udp6_portaddr_hash(sock_net(sk), &in6addr_any, snum);
  unsigned int hash2_partial =
      udp6_portaddr_hash(sock_net(sk), &inet6_sk(sk)->rcv_saddr, 0);
  udp_sk(sk)->udp_portaddr_hash = hash2_partial;
  return udp_lib_get_port(sk, snum, ipv6_rcv_saddr_equal, hash2_nulladdr);
}

int ff_intrax8_decode_picture(IntraX8Context *const w, int dquant,
                              int quant_offset) {
  MpegEncContext *const s = w->s;
  int mb_xy;
  assert(s);
  w->use_quant_matrix = get_bits1(&s->gb);
  w->dquant = dquant;
  w->quant = dquant >> 1;
  w->qsum = quant_offset;
  w->divide_quant_dc_luma = ((1 << 16) + (w->quant >> 1)) / w->quant;
  if (w->quant < 5) {
    w->quant_dc_chroma = w->quant;
    w->divide_quant_dc_chroma = w->divide_quant_dc_luma;
  } else {
    w->quant_dc_chroma = w->quant + ((w->quant + 3) >> 3);
    w->divide_quant_dc_chroma =
        ((1 << 16) + (w->quant_dc_chroma >> 1)) / w->quant_dc_chroma;
  }
  x8_reset_vlc_tables(w);
  s->resync_mb_x = 0;
  s->resync_mb_y = 0;
  for (s->mb_y = 0; s->mb_y < s->mb_height * 2; s->mb_y++) {
    x8_init_block_index(s);
    mb_xy = (s->mb_y >> 1) * s->mb_stride;
    for (s->mb_x = 0; s->mb_x < s->mb_width * 2; s->mb_x++) {
      x8_get_prediction(w);
      if (x8_setup_spatial_predictor(w, 0))
        goto error;
      if (x8_decode_intra_mb(w, 0))
        goto error;
      if (s->mb_x & s->mb_y & 1) {
        x8_get_prediction_chroma(w);
        x8_setup_spatial_predictor(w, 1);
        if (x8_decode_intra_mb(w, 1))
          goto error;
        x8_setup_spatial_predictor(w, 2);
        if (x8_decode_intra_mb(w, 2))
          goto error;
        s->dest[1] += 8;
        s->dest[2] += 8;
        s->mbskip_table[mb_xy] = 0;
        s->mbintra_table[mb_xy] = 1;
        s->current_picture.f.qscale_table[mb_xy] = w->quant;
        mb_xy++;
      }
      s->dest[0] += 8;
    }
    if (s->mb_y & 1) {
      ff_mpeg_draw_horiz_band(s, (s->mb_y - 1) * 8, 16);
    }
  }
error:
  ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, (s->mb_x >> 1) - 1,
                  (s->mb_y >> 1) - 1, ER_MB_END);
  return 0;
}

static int64_t get_sse(const uint8_t *a, int a_stride, const uint8_t *b,
                       int b_stride, int width, int height) {
  const int dw = width % 16;
  const int dh = height % 16;
  int64_t total_sse = 0;
  unsigned int sse = 0;
  int sum = 0;
  int x, y;
  if (dw > 0) {
    variance(&a[width - dw], a_stride, &b[width - dw], b_stride, dw, height,
             &sse, &sum);
    total_sse += sse;
  }
  if (dh > 0) {
    variance(&a[(height - dh) * a_stride], a_stride,
             &b[(height - dh) * b_stride], b_stride, width - dw, dh, &sse,
             &sum);
    total_sse += sse;
  }
  for (y = 0; y < height / 16; ++y) {
    const uint8_t *pa = a;
    const uint8_t *pb = b;
    for (x = 0; x < width / 16; ++x) {
      vp9_mse16x16(pa, a_stride, pb, b_stride, &sse);
      total_sse += sse;
      pa += 16;
      pb += 16;
    }
    a += 16 * a_stride;
    b += 16 * b_stride;
  }
  return total_sse;
}

