  (void)left;
  for (r = 0; r < bs; ++r) {
    for (c = 0; c < bs; ++c)
      dst[c] =
          r + c + 2 < bs * 2
              ? ROUND_POWER_OF_TWO(
                    above[r + c] + above[r + c + 1] * 2 + above[r + c + 2], 2)
              : above[bs * 2 - 1];
