static int decode_slice(MpegEncContext *s) {
  const int part_mask = s->partitioned_frame ? (ER_AC_END | ER_AC_ERROR) : 0x7F;
  const int mb_size = 16;
  s->last_resync_gb = s->gb;
  s->first_slice_line = 1;
  s->resync_mb_x = s->mb_x;
  s->resync_mb_y = s->mb_y;
  ff_set_qscale(s, s->qscale);
  if (s->avctx->hwaccel) {
    const uint8_t *start = s->gb.buffer + get_bits_count(&s->gb) / 8;
    const uint8_t *end =
        ff_h263_find_resync_marker(start + 1, s->gb.buffer_end);
    skip_bits_long(&s->gb, 8 * (end - start));
    return s->avctx->hwaccel->decode_slice(s->avctx, start, end - start);
  }
  if (s->partitioned_frame) {
    const int qscale = s->qscale;
    if (CONFIG_MPEG4_DECODER && s->codec_id == AV_CODEC_ID_MPEG4) {
      if (ff_mpeg4_decode_partitions(s) < 0)
        return -1;
    }
    s->first_slice_line = 1;
    s->mb_x = s->resync_mb_x;
    s->mb_y = s->resync_mb_y;
    ff_set_qscale(s, qscale);
  }
  for (; s->mb_y < s->mb_height; s->mb_y++) {
    if (s->msmpeg4_version) {
      if (s->resync_mb_y + s->slice_height == s->mb_y) {
        ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x - 1,
                        s->mb_y, ER_MB_END);
        return 0;
      }
    }
    if (s->msmpeg4_version == 1) {
      s->last_dc[0] = s->last_dc[1] = s->last_dc[2] = 128;
    }
    ff_init_block_index(s);
    for (; s->mb_x < s->mb_width; s->mb_x++) {
      int ret;
      ff_update_block_index(s);
      if (s->resync_mb_x == s->mb_x && s->resync_mb_y + 1 == s->mb_y) {
        s->first_slice_line = 0;
      }
      s->mv_dir = MV_DIR_FORWARD;
      s->mv_type = MV_TYPE_16X16;
      av_dlog(s, "%d %d %06X\n", ret, get_bits_count(&s->gb),
              show_bits(&s->gb, 24));
      ret = s->decode_mb(s, s->block);
      if (s->pict_type != AV_PICTURE_TYPE_B)
        ff_h263_update_motion_val(s);
      if (ret < 0) {
        const int xy = s->mb_x + s->mb_y * s->mb_stride;
        if (ret == SLICE_END) {
          ff_MPV_decode_mb(s, s->block);
          if (s->loop_filter)
            ff_h263_loop_filter(s);
          ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x,
                          s->mb_y, ER_MB_END & part_mask);
          s->padding_bug_score--;
          if (++s->mb_x >= s->mb_width) {
            s->mb_x = 0;
            ff_mpeg_draw_horiz_band(s, s->mb_y * mb_size, mb_size);
            ff_MPV_report_decode_progress(s);
            s->mb_y++;
          }
          return 0;
        } else if (ret == SLICE_NOEND) {
          av_log(s->avctx, AV_LOG_ERROR, "Slice mismatch at MB: %d\n", xy);
          ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x + 1,
                          s->mb_y, ER_MB_END & part_mask);
          return -1;
        }
        av_log(s->avctx, AV_LOG_ERROR, "Error at MB: %d\n", xy);
        ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x,
                        s->mb_y, ER_MB_ERROR & part_mask);
        return -1;
      }
      ff_MPV_decode_mb(s, s->block);
      if (s->loop_filter)
        ff_h263_loop_filter(s);
    }
    ff_mpeg_draw_horiz_band(s, s->mb_y * mb_size, mb_size);
    ff_MPV_report_decode_progress(s);
    s->mb_x = 0;
  }
  assert(s->mb_x == 0 && s->mb_y == s->mb_height);
  if (s->codec_id == AV_CODEC_ID_MPEG4 &&
      (s->workaround_bugs & FF_BUG_AUTODETECT) && get_bits_left(&s->gb) >= 48 &&
      show_bits(&s->gb, 24) == 0x4010 && !s->data_partitioning)
    s->padding_bug_score += 32;
  if (s->codec_id == AV_CODEC_ID_MPEG4 &&
      (s->workaround_bugs & FF_BUG_AUTODETECT) && get_bits_left(&s->gb) >= 0 &&
      get_bits_left(&s->gb) < 48 && !s->data_partitioning) {
    const int bits_count = get_bits_count(&s->gb);
    const int bits_left = s->gb.size_in_bits - bits_count;
    if (bits_left == 0) {
      s->padding_bug_score += 16;
    } else if (bits_left != 1) {
      int v = show_bits(&s->gb, 8);
      v |= 0x7F >> (7 - (bits_count & 7));
      if (v == 0x7F && bits_left <= 8)
        s->padding_bug_score--;
      else if (v == 0x7F && ((get_bits_count(&s->gb) + 8) & 8) &&
               bits_left <= 16)
        s->padding_bug_score += 4;
      else
        s->padding_bug_score++;
    }
  }
  if (s->workaround_bugs & FF_BUG_AUTODETECT) {
    if (s->padding_bug_score > -2 && !s->data_partitioning)
      s->workaround_bugs |= FF_BUG_NO_PADDING;
    else
      s->workaround_bugs &= ~FF_BUG_NO_PADDING;
  }
  if (s->msmpeg4_version || (s->workaround_bugs & FF_BUG_NO_PADDING)) {
    int left = get_bits_left(&s->gb);
    int max_extra = 7;
    if (s->msmpeg4_version && s->pict_type == AV_PICTURE_TYPE_I)
      max_extra += 17;
    if ((s->workaround_bugs & FF_BUG_NO_PADDING) &&
        (s->err_recognition & AV_EF_BUFFER))
      max_extra += 48;
    else if ((s->workaround_bugs & FF_BUG_NO_PADDING))
      max_extra += 256 * 256 * 256 * 64;
    if (left > max_extra) {
      av_log(s->avctx, AV_LOG_ERROR,
             "discarding %d junk bits at end, next would be %X\n", left,
             show_bits(&s->gb, 24));
    } else if (left < 0) {
      av_log(s->avctx, AV_LOG_ERROR, "overreading %d bits\n", -left);
    } else
      ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x - 1,
                      s->mb_y, ER_MB_END);
    return 0;
  }
  av_log(
      s->avctx, AV_LOG_ERROR,
      "slice end not reached but screenspace end (%d left %06X, score= %d)\n",
      get_bits_left(&s->gb), show_bits(&s->gb, 24), s->padding_bug_score);
  ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x, s->mb_y,
                  ER_MB_END & part_mask);
  return -1;
}

void open_input_file(struct VpxInputContext *input) {
  input->file = strcmp(input->filename, "-") ? fopen(input->filename, "rb")
                                             : set_binary_mode(stdin);
  if (!input->file)
    fatal("Failed to open input file");
  if (!fseeko(input->file, 0, SEEK_END)) {
    input->length = ftello(input->file);
    rewind(input->file);
  }
  input->detect.buf_read = fread(input->detect.buf, 1, 4, input->file);
  input->detect.position = 0;
  if (input->detect.buf_read == 4 && file_is_y4m(input->detect.buf)) {
    if (y4m_input_open(&input->y4m, input->file, input->detect.buf, 4,
                       input->only_i420) >= 0) {
      input->file_type = FILE_TYPE_Y4M;
      input->width = input->y4m.pic_w;
      input->height = input->y4m.pic_h;
      input->framerate.numerator = input->y4m.fps_n;
      input->framerate.denominator = input->y4m.fps_d;
      input->fmt = input->y4m.vpx_fmt;
      input->bit_depth = input->y4m.bit_depth;
    } else
      fatal("Unsupported Y4M stream.");
  } else if (input->detect.buf_read == 4 && fourcc_is_ivf(input->detect.buf)) {
    fatal("IVF is not supported as input.");
  } else {
    input->file_type = FILE_TYPE_RAW;
  }
}

static int mpeg4_decode_mb(MpegEncContext *s, int16_t block[6][64]) {
  int cbpc, cbpy, i, cbp, pred_x, pred_y, mx, my, dquant;
  int16_t *mot_val;
  static int8_t quant_tab[4] = {-1, -2, 1, 2};
  const int xy = s->mb_x + s->mb_y * s->mb_stride;
  assert(s->h263_pred);
  if (s->pict_type == AV_PICTURE_TYPE_P || s->pict_type == AV_PICTURE_TYPE_S) {
    do {
      if (get_bits1(&s->gb)) {
        s->mb_intra = 0;
        for (i = 0; i < 6; i++)
          s->block_last_index[i] = -1;
        s->mv_dir = MV_DIR_FORWARD;
        s->mv_type = MV_TYPE_16X16;
        if (s->pict_type == AV_PICTURE_TYPE_S &&
            s->vol_sprite_usage == GMC_SPRITE) {
          s->current_picture.mb_type[xy] =
              MB_TYPE_SKIP | MB_TYPE_GMC | MB_TYPE_16x16 | MB_TYPE_L0;
          s->mcsel = 1;
          s->mv[0][0][0] = get_amv(s, 0);
          s->mv[0][0][1] = get_amv(s, 1);
          s->mb_skipped = 0;
        } else {
          s->current_picture.mb_type[xy] =
              MB_TYPE_SKIP | MB_TYPE_16x16 | MB_TYPE_L0;
          s->mcsel = 0;
          s->mv[0][0][0] = 0;
          s->mv[0][0][1] = 0;
          s->mb_skipped = 1;
        }
        goto end;
      }
      cbpc = get_vlc2(&s->gb, ff_h263_inter_MCBPC_vlc.table,
                      INTER_MCBPC_VLC_BITS, 2);
      if (cbpc < 0) {
        av_log(s->avctx, AV_LOG_ERROR, "cbpc damaged at %d %d\n", s->mb_x,
               s->mb_y);
        return -1;
      }
    } while (cbpc == 20);
    s->dsp.clear_blocks(s->block[0]);
    dquant = cbpc & 8;
    s->mb_intra = ((cbpc & 4) != 0);
    if (s->mb_intra)
      goto intra;
    if (s->pict_type == AV_PICTURE_TYPE_S &&
        s->vol_sprite_usage == GMC_SPRITE && (cbpc & 16) == 0)
      s->mcsel = get_bits1(&s->gb);
    else
      s->mcsel = 0;
    cbpy = get_vlc2(&s->gb, ff_h263_cbpy_vlc.table, CBPY_VLC_BITS, 1) ^ 0x0F;
    cbp = (cbpc & 3) | (cbpy << 2);
    if (dquant) {
      ff_set_qscale(s, s->qscale + quant_tab[get_bits(&s->gb, 2)]);
    }
    if ((!s->progressive_sequence) &&
        (cbp || (s->workaround_bugs & FF_BUG_XVID_ILACE)))
      s->interlaced_dct = get_bits1(&s->gb);
    s->mv_dir = MV_DIR_FORWARD;
    if ((cbpc & 16) == 0) {
      if (s->mcsel) {
        s->current_picture.mb_type[xy] =
            MB_TYPE_GMC | MB_TYPE_16x16 | MB_TYPE_L0;
        s->mv_type = MV_TYPE_16X16;
        mx = get_amv(s, 0);
        my = get_amv(s, 1);
        s->mv[0][0][0] = mx;
        s->mv[0][0][1] = my;
      } else if ((!s->progressive_sequence) && get_bits1(&s->gb)) {
        s->current_picture.mb_type[xy] =
            MB_TYPE_16x8 | MB_TYPE_L0 | MB_TYPE_INTERLACED;
        s->mv_type = MV_TYPE_FIELD;
        s->field_select[0][0] = get_bits1(&s->gb);
        s->field_select[0][1] = get_bits1(&s->gb);
        ff_h263_pred_motion(s, 0, 0, &pred_x, &pred_y);
        for (i = 0; i < 2; i++) {
          mx = ff_h263_decode_motion(s, pred_x, s->f_code);
          if (mx >= 0xffff)
            return -1;
          my = ff_h263_decode_motion(s, pred_y / 2, s->f_code);
          if (my >= 0xffff)
            return -1;
          s->mv[0][i][0] = mx;
          s->mv[0][i][1] = my;
        }
      } else {
        s->current_picture.mb_type[xy] = MB_TYPE_16x16 | MB_TYPE_L0;
        s->mv_type = MV_TYPE_16X16;
        ff_h263_pred_motion(s, 0, 0, &pred_x, &pred_y);
        mx = ff_h263_decode_motion(s, pred_x, s->f_code);
        if (mx >= 0xffff)
          return -1;
        my = ff_h263_decode_motion(s, pred_y, s->f_code);
        if (my >= 0xffff)
          return -1;
        s->mv[0][0][0] = mx;
        s->mv[0][0][1] = my;
      }
    } else {
      s->current_picture.mb_type[xy] = MB_TYPE_8x8 | MB_TYPE_L0;
      s->mv_type = MV_TYPE_8X8;
      for (i = 0; i < 4; i++) {
        mot_val = ff_h263_pred_motion(s, i, 0, &pred_x, &pred_y);
        mx = ff_h263_decode_motion(s, pred_x, s->f_code);
        if (mx >= 0xffff)
          return -1;
        my = ff_h263_decode_motion(s, pred_y, s->f_code);
        if (my >= 0xffff)
          return -1;
        s->mv[0][i][0] = mx;
        s->mv[0][i][1] = my;
        mot_val[0] = mx;
        mot_val[1] = my;
      }
    }
  } else if (s->pict_type == AV_PICTURE_TYPE_B) {
    int modb1;
    int modb2;
    int mb_type;
    s->mb_intra = 0;
    s->mcsel = 0;
    if (s->mb_x == 0) {
      for (i = 0; i < 2; i++) {
        s->last_mv[i][0][0] = s->last_mv[i][0][1] = s->last_mv[i][1][0] =
            s->last_mv[i][1][1] = 0;
      }
      ff_thread_await_progress(&s->next_picture_ptr->tf, s->mb_y, 0);
    }
    s->mb_skipped =
        s->next_picture.mbskip_table[s->mb_y * s->mb_stride + s->mb_x];
    if (s->mb_skipped) {
      for (i = 0; i < 6; i++)
        s->block_last_index[i] = -1;
      s->mv_dir = MV_DIR_FORWARD;
      s->mv_type = MV_TYPE_16X16;
      s->mv[0][0][0] = 0;
      s->mv[0][0][1] = 0;
      s->mv[1][0][0] = 0;
      s->mv[1][0][1] = 0;
      s->current_picture.mb_type[xy] =
          MB_TYPE_SKIP | MB_TYPE_16x16 | MB_TYPE_L0;
      goto end;
    }
    modb1 = get_bits1(&s->gb);
    if (modb1) {
      mb_type = MB_TYPE_DIRECT2 | MB_TYPE_SKIP | MB_TYPE_L0L1;
      cbp = 0;
    } else {
      modb2 = get_bits1(&s->gb);
      mb_type = get_vlc2(&s->gb, mb_type_b_vlc.table, MB_TYPE_B_VLC_BITS, 1);
      if (mb_type < 0) {
        av_log(s->avctx, AV_LOG_ERROR, "illegal MB_type\n");
        return -1;
      }
      mb_type = mb_type_b_map[mb_type];
      if (modb2)
        cbp = 0;
      else {
        s->dsp.clear_blocks(s->block[0]);
        cbp = get_bits(&s->gb, 6);
      }
      if ((!IS_DIRECT(mb_type)) && cbp) {
        if (get_bits1(&s->gb)) {
          ff_set_qscale(s, s->qscale + get_bits1(&s->gb) * 4 - 2);
        }
      }
      if (!s->progressive_sequence) {
        if (cbp)
          s->interlaced_dct = get_bits1(&s->gb);
        if (!IS_DIRECT(mb_type) && get_bits1(&s->gb)) {
          mb_type |= MB_TYPE_16x8 | MB_TYPE_INTERLACED;
          mb_type &= ~MB_TYPE_16x16;
          if (USES_LIST(mb_type, 0)) {
            s->field_select[0][0] = get_bits1(&s->gb);
            s->field_select[0][1] = get_bits1(&s->gb);
          }
          if (USES_LIST(mb_type, 1)) {
            s->field_select[1][0] = get_bits1(&s->gb);
            s->field_select[1][1] = get_bits1(&s->gb);
          }
        }
      }
      s->mv_dir = 0;
      if ((mb_type & (MB_TYPE_DIRECT2 | MB_TYPE_INTERLACED)) == 0) {
        s->mv_type = MV_TYPE_16X16;
        if (USES_LIST(mb_type, 0)) {
          s->mv_dir = MV_DIR_FORWARD;
          mx = ff_h263_decode_motion(s, s->last_mv[0][0][0], s->f_code);
          my = ff_h263_decode_motion(s, s->last_mv[0][0][1], s->f_code);
          s->last_mv[0][1][0] = s->last_mv[0][0][0] = s->mv[0][0][0] = mx;
          s->last_mv[0][1][1] = s->last_mv[0][0][1] = s->mv[0][0][1] = my;
        }
        if (USES_LIST(mb_type, 1)) {
          s->mv_dir |= MV_DIR_BACKWARD;
          mx = ff_h263_decode_motion(s, s->last_mv[1][0][0], s->b_code);
          my = ff_h263_decode_motion(s, s->last_mv[1][0][1], s->b_code);
          s->last_mv[1][1][0] = s->last_mv[1][0][0] = s->mv[1][0][0] = mx;
          s->last_mv[1][1][1] = s->last_mv[1][0][1] = s->mv[1][0][1] = my;
        }
      } else if (!IS_DIRECT(mb_type)) {
        s->mv_type = MV_TYPE_FIELD;
        if (USES_LIST(mb_type, 0)) {
          s->mv_dir = MV_DIR_FORWARD;
          for (i = 0; i < 2; i++) {
            mx = ff_h263_decode_motion(s, s->last_mv[0][i][0], s->f_code);
            my = ff_h263_decode_motion(s, s->last_mv[0][i][1] / 2, s->f_code);
            s->last_mv[0][i][0] = s->mv[0][i][0] = mx;
            s->last_mv[0][i][1] = (s->mv[0][i][1] = my) * 2;
          }
        }
        if (USES_LIST(mb_type, 1)) {
          s->mv_dir |= MV_DIR_BACKWARD;
          for (i = 0; i < 2; i++) {
            mx = ff_h263_decode_motion(s, s->last_mv[1][i][0], s->b_code);
            my = ff_h263_decode_motion(s, s->last_mv[1][i][1] / 2, s->b_code);
            s->last_mv[1][i][0] = s->mv[1][i][0] = mx;
            s->last_mv[1][i][1] = (s->mv[1][i][1] = my) * 2;
          }
        }
      }
    }
    if (IS_DIRECT(mb_type)) {
      if (IS_SKIP(mb_type))
        mx = my = 0;
      else {
        mx = ff_h263_decode_motion(s, 0, 1);
        my = ff_h263_decode_motion(s, 0, 1);
      }
      s->mv_dir = MV_DIR_FORWARD | MV_DIR_BACKWARD | MV_DIRECT;
      mb_type |= ff_mpeg4_set_direct_mv(s, mx, my);
    }
    s->current_picture.mb_type[xy] = mb_type;
  } else {
    do {
      cbpc = get_vlc2(&s->gb, ff_h263_intra_MCBPC_vlc.table,
                      INTRA_MCBPC_VLC_BITS, 2);
      if (cbpc < 0) {
        av_log(s->avctx, AV_LOG_ERROR, "I cbpc damaged at %d %d\n", s->mb_x,
               s->mb_y);
        return -1;
      }
    } while (cbpc == 8);
    dquant = cbpc & 4;
    s->mb_intra = 1;
  intra:
    s->ac_pred = get_bits1(&s->gb);
    if (s->ac_pred)
      s->current_picture.mb_type[xy] = MB_TYPE_INTRA | MB_TYPE_ACPRED;
    else
      s->current_picture.mb_type[xy] = MB_TYPE_INTRA;
    cbpy = get_vlc2(&s->gb, ff_h263_cbpy_vlc.table, CBPY_VLC_BITS, 1);
    if (cbpy < 0) {
      av_log(s->avctx, AV_LOG_ERROR, "I cbpy damaged at %d %d\n", s->mb_x,
             s->mb_y);
      return -1;
    }
    cbp = (cbpc & 3) | (cbpy << 2);
    s->use_intra_dc_vlc = s->qscale < s->intra_dc_threshold;
    if (dquant) {
      ff_set_qscale(s, s->qscale + quant_tab[get_bits(&s->gb, 2)]);
    }
    if (!s->progressive_sequence)
      s->interlaced_dct = get_bits1(&s->gb);
    s->dsp.clear_blocks(s->block[0]);
    for (i = 0; i < 6; i++) {
      if (mpeg4_decode_block(s, block[i], i, cbp & 32, 1, 0) < 0)
        return -1;
      cbp += cbp;
    }
    goto end;
  }
  for (i = 0; i < 6; i++) {
    if (mpeg4_decode_block(s, block[i], i, cbp & 32, 0, 0) < 0)
      return -1;
    cbp += cbp;
  }
end:
  if (s->codec_id == AV_CODEC_ID_MPEG4) {
    if (mpeg4_is_resync(s)) {
      const int delta = s->mb_x + 1 == s->mb_width ? 2 : 1;
      if (s->pict_type == AV_PICTURE_TYPE_B &&
          s->next_picture.mbskip_table[xy + delta]) {
        ff_thread_await_progress(&s->next_picture_ptr->tf,
                                 (s->mb_x + delta >= s->mb_width)
                                     ? FFMIN(s->mb_y + 1, s->mb_height - 1)
                                     : s->mb_y,
                                 0);
      }
      if (s->pict_type == AV_PICTURE_TYPE_B &&
          s->next_picture.mbskip_table[xy + delta])
        return SLICE_OK;
      return SLICE_END;
    }
  }
  return SLICE_OK;
}

