static int rtp_packetize_vp8(sout_stream_id_sys_t *id, block_t *in) {
  int i_max = rtp_mtu(id) - RTP_VP8_HEADER_SIZE;
  int i_count = (in->i_buffer + i_max - 1) / i_max;
  uint8_t *p_data = in->p_buffer;
  int i_data = in->i_buffer;
  if (i_max <= 0) {
    block_Release(in);
    return VLC_EGENERIC;
  }
  for (int i = 0; i < i_count; i++) {
    int i_payload = __MIN(i_max, i_data);
    block_t *out = block_Alloc(RTP_VP8_PAYLOAD_START + i_payload);
    if (out == NULL) {
      block_Release(in);
      return VLC_ENOMEM;
    }
    if (i == 0)
      out->p_buffer[12] = 0x10;
    else
      out->p_buffer[12] = 0;
    rtp_packetize_common(id, out, (i == i_count - 1),
                         (in->i_pts > VLC_TS_INVALID ? in->i_pts : in->i_dts));
    memcpy(&out->p_buffer[RTP_VP8_PAYLOAD_START], p_data, i_payload);
    out->i_dts = in->i_dts + i * in->i_length / i_count;
    out->i_length = in->i_length / i_count;
    rtp_packetize_send(id, out);
    p_data += i_payload;
    i_data -= i_payload;
  }
  block_Release(in);
  return VLC_SUCCESS;
}

static void dissect_zcl_pwr_prof_attr_data(proto_tree *tree, tvbuff_t *tvb,
                                           guint *offset, guint16 attr_id,
                                           guint data_type) {
  static const int *format_fields[] = {
      &hf_zbee_zcl_pwr_prof_energy_format_rdigit,
      &hf_zbee_zcl_pwr_prof_energy_format_ldigit,
      &hf_zbee_zcl_pwr_prof_energy_format_noleadingzero, NULL};
  static const int *modes[] = {&hf_zbee_zcl_pwr_prof_sched_mode_cheapest,
                               &hf_zbee_zcl_pwr_prof_sched_mode_greenest,
                               &hf_zbee_zcl_pwr_prof_sched_mode_reserved, NULL};
  switch (attr_id) {
  case ZBEE_ZCL_ATTR_ID_PWR_PROF_TOT_PROF_NUM:
    proto_tree_add_item(tree, hf_zbee_zcl_pwr_prof_tot_prof_num, tvb, *offset,
                        1, ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_PWR_PROF_MULTIPLE_SCHED:
    proto_tree_add_item(tree, hf_zbee_zcl_pwr_prof_multiple_sched, tvb, *offset,
                        1, ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_PWR_PROF_ENERGY_FORMAT:
    proto_tree_add_bitmask(
        tree, tvb, *offset, hf_zbee_zcl_pwr_prof_energy_format,
        ett_zbee_zcl_pwr_prof_en_format, format_fields, ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_PWR_PROF_ENERGY_REMOTE:
    proto_tree_add_item(tree, hf_zbee_zcl_pwr_prof_energy_remote, tvb, *offset,
                        1, ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_PWR_PROF_SCHED_MODE:
    proto_tree_add_bitmask(tree, tvb, *offset, hf_zbee_zcl_pwr_prof_sched_mode,
                           ett_zbee_zcl_pwr_prof_sched_mode, modes, ENC_NA);
    *offset += 1;
    break;
  default:
    dissect_zcl_attr_data(tvb, tree, offset, data_type);
    break;
  }
}

static inline void e1000e_read_rx_descr(E1000ECore *core, uint8_t *desc,
                                        hwaddr (*buff_addr)[MAX_PS_BUFFERS]) {
  if (e1000e_rx_use_legacy_descriptor(core)) {
    e1000e_read_lgcy_rx_descr(core, desc, &(*buff_addr)[0]);
    (*buff_addr)[1] = (*buff_addr)[2] = (*buff_addr)[3] = 0;
  } else {
    if (core->mac[RCTL] & E1000_RCTL_DTYP_PS) {
      e1000e_read_ps_rx_descr(core, desc, buff_addr);
    } else {
      e1000e_read_ext_rx_descr(core, desc, &(*buff_addr)[0]);
      (*buff_addr)[1] = (*buff_addr)[2] = (*buff_addr)[3] = 0;
    }
  }
}

