}
#endif if (out_tvb) *out_tvb = NULL;
if (!implicit_tag) {
  hoffset = offset;
  offset = dissect_ber_identifier(actx->pinfo, tree, tvb, offset, &ber_class,
                                  &pc, &tag);
  offset = dissect_ber_length(actx->pinfo, tree, tvb, offset, &len, &ind);
  end_offset = offset + len;
  if ((ber_class != BER_CLASS_APP) && (ber_class != BER_CLASS_PRI)) {
    if ((ber_class != BER_CLASS_UNI) ||
        ((tag < BER_UNI_TAG_NumericString) &&
         (tag != BER_UNI_TAG_OCTETSTRING) && (tag != BER_UNI_TAG_UTF8String))) {
      tvb_ensure_bytes_exist(tvb, hoffset, 2);
      cause = proto_tree_add_string_format_value(
          tree, hf_ber_error, tvb, offset, len, "octetstring_expected",
          "OctetString expected but class:%s(%d) %s tag:%d was unexpected",
          val_to_str_const(ber_class, ber_class_codes, "Unknown"), ber_class,
          pc ? ber_pc_codes_short.true_string : ber_pc_codes_short.false_string,
          tag);
      expert_add_info(actx->pinfo, cause, &ei_ber_expected_octet_string);
      if (decode_unexpected) {
        proto_tree *unknown_tree =
            proto_item_add_subtree(cause, ett_ber_unknown);
        dissect_unknown_ber(actx->pinfo, tvb, hoffset, unknown_tree);
      }
      return end_offset;
    }
  }
} else {
  get_last_ber_identifier(&ber_class, &pc, &tag);
  get_last_ber_length(&len, &ind);
  end_offset = offset + len;
  len_remain = (guint32)tvb_reported_length_remaining(tvb, offset);
  if (ind && (len_remain == (len - 2))) {
    len -= 2;
    end_offset -= 2;
    ind = FALSE;
  } else if (len_remain < len) {
    cause = proto_tree_add_string_format_value(
        tree, hf_ber_error, tvb, offset, len, "illegal_length",
        "length:%u longer than tvb_reported_length_remaining:%d", len,
        len_remain);
    expert_add_info(actx->pinfo, cause, &ei_ber_error_length);
    return end_offset;
  }
}
actx->created_item = NULL;
if (pc) {
  end_offset = reassemble_octet_string(actx, tree, hf_id, tvb, offset, len, ind,
                                       out_tvb);
} else {
  gint length_remaining;
  length_remaining = tvb_reported_length_remaining(tvb, offset);
#if 0 if (length_remaining < 1) {
 return end_offset ;
 }
#endif if (len <= (guint32)length_remaining) {
  length_remaining = len;
}
if (hf_id >= 0) {
  switch (tag) {
  case BER_UNI_TAG_UTF8String:
    encoding = ENC_UTF_8 | ENC_NA;
    break;
  case BER_UNI_TAG_NumericString:
  case BER_UNI_TAG_PrintableString:
  case BER_UNI_TAG_VisibleString:
  case BER_UNI_TAG_IA5String:
    encoding = ENC_ASCII | ENC_NA;
    break;
  case BER_UNI_TAG_TeletexString:
    encoding = ENC_ASCII | ENC_NA;
    break;
  case BER_UNI_TAG_VideotexString:
    encoding = ENC_ASCII | ENC_NA;
    break;
  case BER_UNI_TAG_GraphicString:
  case BER_UNI_TAG_GeneralString:
    encoding = ENC_ASCII | ENC_NA;
    break;
  case BER_UNI_TAG_UniversalString:
    encoding = ENC_UCS_4 | ENC_BIG_ENDIAN;
    break;
  case BER_UNI_TAG_CHARACTERSTRING:
    encoding = ENC_ASCII | ENC_NA;
    break;
  case BER_UNI_TAG_BMPString:
    encoding = ENC_UCS_2 | ENC_BIG_ENDIAN;
    break;
  default:
    encoding = ENC_BIG_ENDIAN;
    break;
  }
  it = ber_proto_tree_add_item(actx->pinfo, tree, hf_id, tvb, offset,
                               length_remaining, encoding);
  actx->created_item = it;
  ber_check_length(length_remaining, min_len, max_len, actx, it, FALSE);
} else {
  proto_tree_add_item(tree, hf_ber_unknown_octetstring, tvb, offset, len,
                      ENC_NA);
}
if (out_tvb) {
  *out_tvb = ber_tvb_new_subset_length(tvb, offset, len);
}
}
return end_offset;
}

static void xps_draw_radial_gradient(xps_document *doc, const fz_matrix *ctm,
                                     const fz_rect *area, struct stop *stops,
                                     int count, fz_xml *root, int spread) {
  float x0, y0, r0;
  float x1, y1, r1;
  float xrad = 1;
  float yrad = 1;
  float invscale;
  int i, ma = 1;
  fz_matrix local_ctm = *ctm;
  fz_matrix inv;
  fz_rect local_area = *area;
  char *center_att = fz_xml_att(root, "Center");
  char *origin_att = fz_xml_att(root, "GradientOrigin");
  char *radius_x_att = fz_xml_att(root, "RadiusX");
  char *radius_y_att = fz_xml_att(root, "RadiusY");
  x0 = y0 = 0.0;
  x1 = y1 = 1.0;
  xrad = 1.0;
  yrad = 1.0;
  if (origin_att)
    xps_parse_point(origin_att, &x0, &y0);
  if (center_att)
    xps_parse_point(center_att, &x1, &y1);
  if (radius_x_att)
    xrad = fz_atof(radius_x_att);
  if (radius_y_att)
    yrad = fz_atof(radius_y_att);
  xrad = fz_max(0.01f, xrad);
  yrad = fz_max(0.01f, yrad);
  if (fz_abs(xrad) > FLT_EPSILON) {
    fz_pre_scale(&local_ctm, 1, yrad / xrad);
  }
  if (yrad != 0.0) {
    invscale = xrad / yrad;
    y0 = y0 * invscale;
    y1 = y1 * invscale;
  }
  r0 = 0;
  r1 = xrad;
  fz_transform_rect(&local_area, fz_invert_matrix(&inv, &local_ctm));
  ma =
      fz_maxi(ma, ceilf(hypotf(local_area.x0 - x0, local_area.y0 - y0) / xrad));
  ma =
      fz_maxi(ma, ceilf(hypotf(local_area.x1 - x0, local_area.y0 - y0) / xrad));
  ma =
      fz_maxi(ma, ceilf(hypotf(local_area.x0 - x0, local_area.y1 - y0) / xrad));
  ma =
      fz_maxi(ma, ceilf(hypotf(local_area.x1 - x0, local_area.y1 - y0) / xrad));
  if (spread == SPREAD_REPEAT) {
    for (i = ma - 1; i >= 0; i--)
      xps_draw_one_radial_gradient(doc, &local_ctm, stops, count, 0, x0, y0,
                                   r0 + i * xrad, x1, y1, r1 + i * xrad);
  } else if (spread == SPREAD_REFLECT) {
    if ((ma % 2) != 0)
      ma++;
    for (i = ma - 2; i >= 0; i -= 2) {
      xps_draw_one_radial_gradient(doc, &local_ctm, stops, count, 0, x0, y0,
                                   r0 + i * xrad, x1, y1, r1 + i * xrad);
      xps_draw_one_radial_gradient(doc, &local_ctm, stops, count, 0, x0, y0,
                                   r0 + (i + 2) * xrad, x1, y1, r1 + i * xrad);
    }
  } else {
    xps_draw_one_radial_gradient(doc, &local_ctm, stops, count, 1, x0, y0, r0,
                                 x1, y1, r1);
  }
}

