int rebuild_existing_bitmaps(struct packing_data *mapping,
                             khash_sha1 *reused_bitmaps, int show_progress) {
  uint32_t i, num_objects;
  uint32_t *reposition;
  struct bitmap *rebuild;
  struct stored_bitmap *stored;
  struct progress *progress = NULL;
  khiter_t hash_pos;
  int hash_ret;
  if (prepare_bitmap_git() < 0)
    return -1;
  num_objects = bitmap_git.pack->num_objects;
  reposition = xcalloc(num_objects, sizeof(uint32_t));
  for (i = 0; i < num_objects; ++i) {
    const unsigned char *sha1;
    struct revindex_entry *entry;
    struct object_entry *oe;
    entry = &bitmap_git.pack->revindex[i];
    sha1 = nth_packed_object_sha1(bitmap_git.pack, entry->nr);
    oe = packlist_find(mapping, sha1, NULL);
    if (oe)
      reposition[i] = oe->in_pack_pos + 1;
  }
  rebuild = bitmap_new();
  i = 0;
  if (show_progress)
    progress = start_progress("Reusing bitmaps", 0);
  kh_foreach_value(bitmap_git.bitmaps, stored, {
    if (stored->flags & BITMAP_FLAG_REUSE) {
      if (!rebuild_bitmap(reposition, lookup_stored_bitmap(stored), rebuild)) {
        hash_pos = kh_put_sha1(reused_bitmaps, stored->sha1, &hash_ret);
        kh_value(reused_bitmaps, hash_pos) = bitmap_to_ewah(rebuild);
      }
      bitmap_reset(rebuild);
      display_progress(progress, ++i);
    }
  });
  stop_progress(&progress);
  free(reposition);
  bitmap_free(rebuild);
  return 0;
}

void spgcostestimate(PlannerInfo *root, IndexPath *path, double loop_count,
                     Cost *indexStartupCost, Cost *indexTotalCost,
                     Selectivity *indexSelectivity, double *indexCorrelation) {
  IndexOptInfo *index = path->indexinfo;
  List *qinfos;
  GenericCosts costs;
  Cost descentCost;
  qinfos = deconstruct_indexquals(path);
  MemSet(&costs, 0, sizeof(costs));
  genericcostestimate(root, path, loop_count, qinfos, &costs);
  if (index->tree_height < 0) {
    if (index->pages > 1)
      index->tree_height = (int)(log(index->pages) / log(100.0));
    else
      index->tree_height = 0;
  }
  if (index->tuples > 1) {
    descentCost = ceil(log(index->tuples)) * cpu_operator_cost;
    costs.indexStartupCost += descentCost;
    costs.indexTotalCost += costs.num_sa_scans * descentCost;
  }
  descentCost = (index->tree_height + 1) * 50.0 * cpu_operator_cost;
  costs.indexStartupCost += descentCost;
  costs.indexTotalCost += costs.num_sa_scans * descentCost;
  *indexStartupCost = costs.indexStartupCost;
  *indexTotalCost = costs.indexTotalCost;
  *indexSelectivity = costs.indexSelectivity;
  *indexCorrelation = costs.indexCorrelation;
}

static int __tipc_nl_compat_link_set(struct sk_buff *skb,
                                     struct tipc_nl_compat_msg *msg) {
  struct nlattr *prop;
  struct nlattr *link;
  struct tipc_link_config *lc;
  lc = (struct tipc_link_config *)TLV_DATA(msg->req);
  link = nla_nest_start(skb, TIPC_NLA_LINK);
  if (!link)
    return -EMSGSIZE;
  if (nla_put_string(skb, TIPC_NLA_LINK_NAME, lc->name))
    return -EMSGSIZE;
  prop = nla_nest_start(skb, TIPC_NLA_LINK_PROP);
  if (!prop)
    return -EMSGSIZE;
  __tipc_add_link_prop(skb, msg, lc);
  nla_nest_end(skb, prop);
  nla_nest_end(skb, link);
  return 0;
}

static void iax2_add_ts_fields(packet_info *pinfo, proto_tree *iax2_tree,
                               tvbuff_t *tvb, iax_packet_data *iax_packet,
                               guint16 shortts) {
  guint longts = shortts;
  nstime_t ts;
  proto_item *item;
  if (iax_packet->call_data == NULL) {
    return;
  }
  if (iax_packet->abstime.secs == -1) {
    time_t start_secs = iax_packet->call_data->start_time.secs;
    time_t abs_secs = start_secs + longts / 1000;
    if (pinfo->abs_ts.secs - abs_secs > MAX_SECS_DIFF) {
      proto_tree_add_expert(iax2_tree, pinfo, &ei_iax_invalid_ts, tvb, 0, 0);
    } else {
      while (abs_secs < pinfo->fd->abs_ts.secs - 16) {
        longts += 32768;
        abs_secs = start_secs + longts / 1000;
      }
    }
    iax_packet->abstime.secs = abs_secs;
    iax_packet->abstime.nsecs =
        iax_packet->call_data->start_time.nsecs + (longts % 1000) * 1000000;
    if (iax_packet->abstime.nsecs >= 1000000000) {
      iax_packet->abstime.nsecs -= 1000000000;
      iax_packet->abstime.secs++;
    }
  }
  iax2_info->timestamp = longts;
  if (iax2_tree) {
    item = proto_tree_add_time(iax2_tree, hf_iax2_absts, tvb, 0, 0,
                               &iax_packet->abstime);
    PROTO_ITEM_SET_GENERATED(item);
    ts = pinfo->fd->abs_ts;
    nstime_delta(&ts, &ts, &iax_packet->abstime);
    item = proto_tree_add_time(iax2_tree, hf_iax2_lateness, tvb, 0, 0, &ts);
    PROTO_ITEM_SET_GENERATED(item);
  }
}

