static int mpeg_decode_frame(AVCodecContext *avctx, void *data, int *got_output,
                             AVPacket *avpkt) {
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  Mpeg1Context *s = avctx->priv_data;
  AVFrame *picture = data;
  MpegEncContext *s2 = &s->mpeg_enc_ctx;
  av_dlog(avctx, "fill_buffer\n");
  if (buf_size == 0 || (buf_size == 4 && AV_RB32(buf) == SEQ_END_CODE)) {
    if (s2->low_delay == 0 && s2->next_picture_ptr) {
      *picture = s2->next_picture_ptr->f;
      s2->next_picture_ptr = NULL;
      *got_output = 1;
    }
    return buf_size;
  }
  if (s2->flags & CODEC_FLAG_TRUNCATED) {
    int next = ff_mpeg1_find_frame_end(&s2->parse_context, buf, buf_size, NULL);
    if (ff_combine_frame(&s2->parse_context, next, (const uint8_t **)&buf,
                         &buf_size) < 0)
      return buf_size;
  }
  if (s->mpeg_enc_ctx_allocated == 0 && avctx->codec_tag == AV_RL32("VCR2"))
    vcr2_init_sequence(avctx);
  s->slice_count = 0;
  if (avctx->extradata && !s->extradata_decoded) {
    int ret = decode_chunks(avctx, picture, got_output, avctx->extradata,
                            avctx->extradata_size);
    s->extradata_decoded = 1;
    if (ret < 0 && (avctx->err_recognition & AV_EF_EXPLODE))
      return ret;
  }
  return decode_chunks(avctx, picture, got_output, buf, buf_size);
}

static Datum ExecEvalCoerceViaIO(CoerceViaIOState *iostate,
                                 ExprContext *econtext, bool *isNull,
                                 ExprDoneCond *isDone) {
  Datum result;
  Datum inputval;
  char *string;
  inputval = ExecEvalExpr(iostate->arg, econtext, isNull, isDone);
  if (isDone && *isDone == ExprEndResult)
    return inputval;
  if (*isNull)
    string = NULL;
  else
    string = OutputFunctionCall(&iostate->outfunc, inputval);
  result =
      InputFunctionCall(&iostate->infunc, string, iostate->intypioparam, -1);
  return result;
}

