        FT_DOUBLE, BASE_NONE | BASE_UNIT_STRING, &units_milliseconds, 0x00,
        NULL, HFILL}},
      {&hf_aptx_cumulative_duration,
       {"Cumulative Music Duration", "aptx.cumulative_music_duration",
        FT_DOUBLE, BASE_NONE | BASE_UNIT_STRING, &units_milliseconds, 0x00,
        NULL, HFILL}},
      {&hf_aptx_diff,
       {"Diff", "aptx.diff", FT_DOUBLE, BASE_NONE | BASE_UNIT_STRING,
        &units_milliseconds, 0x00, NULL, HFILL}},
  };
  static gint *ett[] = {&ett_aptx};
  proto_aptx = proto_register_protocol("APT-X Codec", "APT-X", "aptx");
  proto_register_field_array(proto_aptx, hf, array_length(hf));
  proto_register_subtree_array(ett, array_length(ett));
  aptx_handle = register_dissector("aptx", dissect_aptx, proto_aptx);
}

static int auth_server_input_done(struct auth_server_connection *conn) {
  if (array_count(&conn->available_auth_mechs) == 0) {
    i_error("BUG: Authentication server returned no mechanisms");
    return -1;
  }
  if (conn->cookie == NULL) {
    i_error("BUG: Authentication server didn't send a cookie");
    return -1;
  }
  timeout_remove(&conn->to);
  conn->handshake_received = TRUE;
  if (conn->client->connect_notify_callback != NULL) {
    conn->client->connect_notify_callback(conn->client, TRUE,
                                          conn->client->connect_notify_context);
  }
  return 0;
}

const char *mime_field_value_get_comma_val(const MIMEField *field, int *length,
                                           int idx) {
  if (!field->supports_commas()) {
    if (idx == 0) {
      return mime_field_value_get(field, length);
    } else {
      return nullptr;
    }
  } else {
    Str *str;
    StrList list(false);
    mime_field_value_get_comma_list(field, &list);
    str = list.get_idx(idx);
    if (str != nullptr) {
      *length = (int)(str->len);
      return str->str;
    } else {
      *length = 0;
      return nullptr;
    }
  }
}

