static void read_vec_pos(GetBitContext *gb, int *vec_pos, int *sel_flag,
                         int *sel_len, int *prev) {
  int i, y_flag = 0;
  for (i = 2; i >= 0; i--) {
    if (!sel_flag[i]) {
      vec_pos[i] = 0;
      continue;
    }
    if ((!i && !y_flag) || get_bits1(gb)) {
      if (sel_len[i] > 0) {
        int pval = prev[i];
        vec_pos[i] = get_bits(gb, sel_len[i]);
        if (vec_pos[i] >= pval)
          vec_pos[i]++;
      } else {
        vec_pos[i] = !prev[i];
      }
      y_flag = 1;
    } else {
      vec_pos[i] = prev[i];
    }
  }
}

int chk_status(MI_CHECK *param, register MI_INFO *info) {
  MYISAM_SHARE *share = info->s;
  if (mi_is_crashed_on_repair(info))
    mi_check_print_warning(param,
                           "Table is marked as crashed and last repair failed");
  else if (mi_is_crashed(info))
    mi_check_print_warning(param, "Table is marked as crashed");
  if (share->state.open_count != (uint)(info->s->global_changed ? 1 : 0)) {
    uint save = param->warning_printed;
    mi_check_print_warning(
        param,
        share->state.open_count == 1
            ? "%d client is using or hasn't closed the table properly"
            : "%d clients are using or haven't closed the table properly",
        share->state.open_count);
    if (param->testflag & T_UPDATE_STATE)
      param->warning_printed = save;
  }
  return 0;
}

