  if (val & E1000_RCTL_EN) {
    e1000e_parse_rxbufsize(core);
    e1000e_calc_rxdesclen(core);
    core->rxbuf_min_shift =
        ((val / E1000_RCTL_RDMTS_QUAT) & 3) + 1 + E1000_RING_DESC_LEN_SHIFT;
    e1000e_start_recv(core);
  }
}

static spl_filesystem_object *spl_filesystem_object_create_info(
    spl_filesystem_object *source, char *file_path, int file_path_len,
    int use_copy, zend_class_entry *ce, zval *return_value TSRMLS_DC) {
  spl_filesystem_object *intern;
  zval *arg1;
  zend_error_handling error_handling;
  if (!file_path || !file_path_len) {
#if defined(PHP_WIN32)                                                         \
    zend_throw_exception_ex(spl_ce_RuntimeException, 0 TSRMLS_CC,              \
                            "Cannot create SplFileInfo for empty path");
    if (file_path && !use_copy) {
      efree(file_path);
    }
#else if (file_path && !use_copy) {
    efree(file_path);
  }
  file_path_len = 1;
  file_path = "/";
#endif return NULL;
  }
  zend_replace_error_handling(EH_THROW, spl_ce_RuntimeException,
                              &error_handling TSRMLS_CC);
  ce = ce ? ce : source->info_class;
  zend_update_class_constants(ce TSRMLS_CC);
  return_value->value.obj = spl_filesystem_object_new_ex(ce, &intern TSRMLS_CC);
  Z_TYPE_P(return_value) = IS_OBJECT;
  if (ce->constructor->common.scope != spl_ce_SplFileInfo) {
    MAKE_STD_ZVAL(arg1);
    ZVAL_STRINGL(arg1, file_path, file_path_len, use_copy);
    zend_call_method_with_1_params(&return_value, ce, &ce->constructor,
                                   "__construct", NULL, arg1);
    zval_ptr_dtor(&arg1);
  } else {
    spl_filesystem_info_set_filename(intern, file_path, file_path_len,
                                     use_copy TSRMLS_CC);
  }
  zend_restore_error_handling(&error_handling TSRMLS_CC);
  return intern;
}

static int qemuMonitorJSONIOProcessLine(qemuMonitorPtr mon, const char *line,
                                        qemuMonitorMessagePtr msg) {
  virJSONValuePtr obj = NULL;
  int ret = -1;
  VIR_DEBUG("Line [%s]", line);
  if (!(obj = virJSONValueFromString(line)))
    goto cleanup;
  if (obj->type != VIR_JSON_TYPE_OBJECT) {
    qemuReportError(VIR_ERR_INTERNAL_ERROR,
                    _("Parsed JSON reply '%s' isn't an object"), line);
    goto cleanup;
  }
  if (virJSONValueObjectHasKey(obj, "QMP") == 1) {
    ret = 0;
  } else if (virJSONValueObjectHasKey(obj, "event") == 1) {
    PROBE(QEMU_MONITOR_RECV_EVENT, "mon=%p event=%s", mon, line);
    ret = qemuMonitorJSONIOProcessEvent(mon, obj);
  } else if (virJSONValueObjectHasKey(obj, "error") == 1 ||
             virJSONValueObjectHasKey(obj, "return") == 1) {
    PROBE(QEMU_MONITOR_RECV_REPLY, "mon=%p reply=%s", mon, line);
    if (msg) {
      msg->rxObject = obj;
      msg->finished = 1;
      obj = NULL;
      ret = 0;
    } else {
      qemuReportError(VIR_ERR_INTERNAL_ERROR, _("Unexpected JSON reply '%s'"),
                      line);
    }
  } else {
    qemuReportError(VIR_ERR_INTERNAL_ERROR, _("Unknown JSON reply '%s'"), line);
  }
cleanup:
  virJSONValueFree(obj);
  return ret;
}

static void dissect_zcl_appl_ctrl_signal_state_rsp(tvbuff_t *tvb,
