static void file_info_start(NautilusDirectory *directory, NautilusFile *file,
                            gboolean *doing_io) {
  GFile *location;
  GetInfoState *state;
  file_info_stop(directory);
  if (directory->details->get_info_in_progress != NULL) {
    *doing_io = TRUE;
    return;
  }
  if (!is_needy(file, lacks_info, REQUEST_FILE_INFO)) {
    return;
  }
  *doing_io = TRUE;
  if (!async_job_start(directory, "file info")) {
    return;
  }
  directory->details->get_info_file = file;
  file->details->get_info_failed = FALSE;
  if (file->details->get_info_error) {
    g_error_free(file->details->get_info_error);
    file->details->get_info_error = NULL;
  }
  state = g_new(GetInfoState, 1);
  state->directory = directory;
  state->cancellable = g_cancellable_new();
  directory->details->get_info_in_progress = state;
  location = nautilus_file_get_location(file);
  g_file_query_info_async(location, NAUTILUS_FILE_DEFAULT_ATTRIBUTES, 0,
                          G_PRIORITY_DEFAULT, state->cancellable,
                          query_info_callback, state);
  g_object_unref(location);
}

static void ras_call_matching(tvbuff_t *tvb, packet_info *pinfo,
                              proto_tree *tree, h225_packet_info *pi) {
  proto_item *hidden_item;
  conversation_t *conversation = NULL;
  h225ras_call_info_key h225ras_call_key;
  h225ras_call_t *h225ras_call = NULL;
  nstime_t delta;
  guint msg_category;
  if (pi->msg_type == H225_RAS && pi->msg_tag < 21) {
    msg_category = pi->msg_tag / 3;
    if (pi->msg_tag % 3 == 0) {
      conversation = find_or_create_conversation(pinfo);
      h225ras_call_key.reqSeqNum = pi->requestSeqNum;
      h225ras_call_key.conversation = conversation;
      h225ras_call = find_h225ras_call(&h225ras_call_key, msg_category);
      if (h225ras_call != NULL) {
        do {
          if (pinfo->num == h225ras_call->req_num) {
            break;
          }
          if (h225ras_call->next_call == NULL) {
            if ((pinfo->num > h225ras_call->rsp_num &&
                 h225ras_call->rsp_num != 0 &&
                 pinfo->abs_ts.secs > (h225ras_call->req_time.secs +
                                       THRESHOLD_REPEATED_RESPONDED_CALL)) ||
                (pinfo->num > h225ras_call->req_num &&
                 h225ras_call->rsp_num == 0 &&
                 pinfo->abs_ts.secs >
                     (h225ras_call->req_time.secs +
                      THRESHOLD_REPEATED_NOT_RESPONDED_CALL))) {
              h225ras_call = append_h225ras_call(h225ras_call, pinfo, &pi->guid,
                                                 msg_category);
            } else {
              pi->is_duplicate = TRUE;
              hidden_item = proto_tree_add_uint(tree, hf_h225_ras_dup, tvb, 0,
                                                0, pi->requestSeqNum);
              PROTO_ITEM_SET_HIDDEN(hidden_item);
            }
            break;
          }
          h225ras_call = h225ras_call->next_call;
        } while (h225ras_call != NULL);
      } else {
        h225ras_call =
            new_h225ras_call(&h225ras_call_key, pinfo, &pi->guid, msg_category);
      }
      if (h225ras_call && h225ras_call->rsp_num != 0) {
        proto_item *ti = proto_tree_add_uint_format(
            tree, hf_h225_ras_rsp_frame, tvb, 0, 0, h225ras_call->rsp_num,
            "The response to this request is in frame %u",
            h225ras_call->rsp_num);
        PROTO_ITEM_SET_GENERATED(ti);
      }
    } else {
      conversation =
          find_conversation(pinfo->num, &pinfo->src, &pinfo->dst, pinfo->ptype,
                            pinfo->srcport, pinfo->destport, 0);
      if (conversation != NULL) {
        h225ras_call_key.reqSeqNum = pi->requestSeqNum;
        h225ras_call_key.conversation = conversation;
        h225ras_call = find_h225ras_call(&h225ras_call_key, msg_category);
        if (h225ras_call) {
          do {
            if (pinfo->num == h225ras_call->rsp_num) {
              break;
            }
            if (h225ras_call->next_call == NULL) {
              break;
            }
            h225ras_call = h225ras_call->next_call;
          } while (h225ras_call != NULL);
          if (!h225ras_call) {
            return;
          }
          if (msg_category == 3 || msg_category == 5) {
            pi->guid = h225ras_call->guid;
            hidden_item = proto_tree_add_guid(tree, hf_h225_guid, tvb, 0,
                                              GUID_LEN, &pi->guid);
            PROTO_ITEM_SET_HIDDEN(hidden_item);
          }
          if (h225ras_call->rsp_num == 0) {
            h225ras_call->rsp_num = pinfo->num;
          } else {
            if (h225ras_call->rsp_num != pinfo->num) {
              pi->is_duplicate = TRUE;
              hidden_item = proto_tree_add_uint(tree, hf_h225_ras_dup, tvb, 0,
                                                0, pi->requestSeqNum);
              PROTO_ITEM_SET_HIDDEN(hidden_item);
            }
          }
          if (h225ras_call->req_num != 0) {
            proto_item *ti;
            h225ras_call->responded = TRUE;
            pi->request_available = TRUE;
            ti = proto_tree_add_uint_format(
                tree, hf_h225_ras_req_frame, tvb, 0, 0, h225ras_call->req_num,
                "This is a response to a request in frame %u",
                h225ras_call->req_num);
            PROTO_ITEM_SET_GENERATED(ti);
            nstime_delta(&delta, &pinfo->abs_ts, &h225ras_call->req_time);
            pi->delta_time = delta;
            ti = proto_tree_add_time(tree, hf_h225_ras_deltatime, tvb, 0, 0,
                                     &(pi->delta_time));
            PROTO_ITEM_SET_GENERATED(ti);
          }
        }
      }
    }
  }
}

static void restore_fix_stack(i_ctx_t *i_ctx_p, ref_stack_t *pstack,
                              const alloc_save_t *asave, bool is_estack) {
  ref_stack_enum_t rsenum;
  ref_stack_enum_begin(&rsenum, pstack);
  do {
    ref *stkp = rsenum.ptr;
    uint size = rsenum.size;
    for (; size; stkp++, size--) {
      r_clear_attrs(stkp, l_new);
      if (is_estack) {
        ref ofile;
        ref_assign(&ofile, stkp);
        switch (r_type(stkp)) {
        case t_string:
          if (r_size(stkp) == 0 &&
              alloc_is_since_save(stkp->value.bytes, asave)) {
            make_empty_const_string(stkp, avm_foreign);
            break;
          }
          continue;
        case t_file:
          if (alloc_is_since_save(stkp->value.pfile, asave)) {
            make_invalid_file(i_ctx_p, stkp);
            break;
          }
          continue;
        default:
          continue;
        }
        r_copy_attrs(stkp, a_all | a_executable, &ofile);
      }
    }
  } while (ref_stack_enum_next(&rsenum));
}

static guint32 parse_wbxml_attribute_list(proto_tree *tree, tvbuff_t *tvb,
                                          guint32 offset, guint32 str_tbl,
                                          guint8 level, guint8 *codepage_attr) {
  guint32 tvb_len = tvb_reported_length(tvb);
  guint32 off = offset;
  guint32 len;
  guint str_len;
  guint32 ent;
  guint32 idx;
  guint8 peek;
  DebugLog(("parse_wbxml_attr (level = %u, offset = %u)\n", level, offset));
  while (off < tvb_len) {
    peek = tvb_get_guint8(tvb, off);
    DebugLog(("ATTR: (top of while) level = %3u, peek = 0x%02X, "
              "off = %u, tvb_len = %u\n",
              level, peek, off, tvb_len));
    if ((peek & 0x3F) < 5)
      switch (peek) {
      case 0x00:
        *codepage_attr = tvb_get_guint8(tvb, off + 1);
        proto_tree_add_text(tree, tvb, off, 2,
                            " | Attr | A -->%3d "
                            "| SWITCH_PAGE (Attr code page) |",
                            *codepage_attr);
        off += 2;
        break;
      case 0x01:
        off++;
        DebugLog(("ATTR: level = %u, Return: len = %u\n", level, off - offset));
        return (off - offset);
      case 0x02:
        ent = tvb_get_guintvar(tvb, off + 1, &len);
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Attr | A %3d " "| ENTITY " "| %s'&#%u;
'" , level , * codepage_attr , Indent ( level ) , ent ) ;
 off += 1 + len ;
 break ;
 case 0x03 : len = tvb_strsize ( tvb , off + 1 ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Attr | A %3d " "| STR_I (Inline string) " "| %s\'%s\'" , level , * codepage_attr , Indent ( level ) , tvb_format_text ( tvb , off + 1 , len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x04 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 str_len = tvb_strsize ( tvb , str_tbl + idx ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Attr | A %3d " "| LITERAL (Literal Attribute) " "| %s<%s />" , level , * codepage_attr , Indent ( level ) , tvb_format_text ( tvb , str_tbl + idx , str_len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x40 : case 0x41 : case 0x42 : len = tvb_strsize ( tvb , off + 1 ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Attr | A %3d " "| EXT_I_%1x (Extension Token) " "| %s(Inline string extension: \'%s\')" , level , * codepage_attr , peek & 0x0f , Indent ( level ) , tvb_format_text ( tvb , off + 1 , len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x80 : case 0x81 : case 0x82 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Attr | A %3d " "| EXT_T_%1x (Extension Token) " "| %s(Extension Token, integer value: %u)" , level , * codepage_attr , peek & 0x0f , Indent ( level ) , idx ) ;
 off += 1 + len ;
 break ;
 case 0x83 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 str_len = tvb_strsize ( tvb , str_tbl + idx ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Attr | A %3d " "| STR_T (Tableref string) " "| %s\'%s\'" , level , * codepage_attr , Indent ( level ) , tvb_format_text ( tvb , str_tbl + idx , str_len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0xC0 : case 0xC1 : case 0xC2 : proto_tree_add_text ( tree , tvb , off , 1 , " %3d | Attr | A %3d " "| EXT_%1x (Extension Token) " "| %s(Single-byte extension)" , level , * codepage_attr , peek & 0x0f , Indent ( level ) ) ;
 off ++ ;
 break ;
 case 0xC3 : if ( tvb_get_guint8 ( tvb , 0 ) ) {
          idx = tvb_get_guintvar(tvb, off + 1, &len);
          proto_tree_add_text(tree, tvb, off, 1 + len + idx,
                              " %3d | Attr | A %3d "
                              "| OPAQUE (Opaque data) "
                              "| %s(%d bytes of opaque data)",
                              level, *codepage_attr, Indent(level), idx);
          off += 1 + len + idx;
 }
 else {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Attr | A %3d "
                              "| RESERVED_2 (Invalid Token!) "
                              "| WBXML 1.0 parsing stops here.",
                              level, *codepage_attr);
          off = tvb_len;
          DebugLog(
              ("ATTR: level = %u, Return: len = %u\n", level, off - offset));
          return (off - offset);
 }
 break ;
 default : proto_tree_add_text ( tree , tvb , off , 1 , " %3d | Attr | A %3d " "| %-10s (Invalid Token!) " "| WBXML parsing stops here." , level , * codepage_attr , val_to_str_ext ( peek , & vals_wbxml1x_global_tokens_ext , "(unknown 0x%x)" ) ) ;
 off = tvb_len ;
 break ;
      }
    else {
      if (peek & 0x80) {
        proto_tree_add_text(tree, tvb, off, 1,
                            " %3d | Attr | A %3d "
                            "| Known attrValue 0x%02X "
                            "| %sattrValue_0x%02X",
                            level, *codepage_attr, peek & 0x7f, Indent(level),
                            peek);
        off++;
      } else {
        proto_tree_add_text(tree, tvb, off, 1,
                            " %3d | Attr | A %3d "
                            "| Known attrStart 0x%02X "
                            "| %sattrStart_0x%02X",
                            level, *codepage_attr, peek & 0x7f, Indent(level),
                            peek);
        off++;
      }
    }
  }
  DebugLog(("ATTR: level = %u, Return: len = %u (end of function body)\n",
            level, off - offset));
  return (off - offset);
}

