static void cb_notify_str_postprocess(packet_info *pinfo _U_,
                                      proto_tree *tree _U_, proto_item *item,
                                      dcerpc_info *di _U_, tvbuff_t *tvb,
                                      int start_offset, int end_offset,
                                      void *callback_args) {
  gint levels, hf_index = GPOINTER_TO_INT(callback_args);
  guint32 len;
  char *s;
  proto_item *hidden_item;
  if (start_offset % 4)
    start_offset += 4 - (start_offset % 4);
  len = tvb_get_letohl(tvb, start_offset);
  s = tvb_get_string_enc(NULL, tvb, start_offset + 4,
                         (end_offset - start_offset - 4),
                         ENC_UTF_16 | ENC_LITTLE_ENDIAN);
  levels = 2;
  if (levels > 0 && item && s && s[0]) {
    proto_item_append_text(item, ": %s", s);
    item = item->parent;
    levels--;
    if (levels > 0) {
      proto_item_append_text(item, ": %s", s);
      item = item->parent;
      levels--;
      while (levels > 0) {
        proto_item_append_text(item, " %s", s);
        item = item->parent;
        levels--;
      }
    }
  }
  if (hf_index != -1) {
    hidden_item =
        proto_tree_add_string(tree, hf_index, tvb, start_offset, len, s);
    PROTO_ITEM_SET_HIDDEN(hidden_item);
  }
  g_free(s);
}

static int init_block_mapping(Vp3DecodeContext *s) {
  int sb_x, sb_y, plane;
  int x, y, i, j = 0;
  for (plane = 0; plane < 3; plane++) {
    int sb_width = plane ? s->c_superblock_width : s->y_superblock_width;
    int sb_height = plane ? s->c_superblock_height : s->y_superblock_height;
    int frag_width = s->fragment_width[!!plane];
    int frag_height = s->fragment_height[!!plane];
    for (sb_y = 0; sb_y < sb_height; sb_y++)
      for (sb_x = 0; sb_x < sb_width; sb_x++)
        for (i = 0; i < 16; i++) {
          x = 4 * sb_x + hilbert_offset[i][0];
          y = 4 * sb_y + hilbert_offset[i][1];
          if (x < frag_width && y < frag_height)
            s->superblock_fragments[j++] =
                s->fragment_start[plane] + y * frag_width + x;
          else
            s->superblock_fragments[j++] = -1;
        }
  }
  return 0;
}

static char *wv_csp11_opaque_binary_tag(tvbuff_t *tvb, guint32 offset,
                                        guint8 token, guint8 codepage,
                                        guint32 *length) {
  guint32 data_len = tvb_get_guintvar(tvb, offset, length);
  char *str = NULL;
  switch (codepage) {
  case 0:
    switch (token) {
    case 0x0B:
    case 0x0F:
    case 0x1A:
    case 0x3C:
      str = wv_integer_from_opaque(tvb, offset + *length, data_len);
      break;
    case 0x11:
      str = wv_datetime_from_opaque(tvb, offset + *length, data_len);
      break;
    default:
      break;
    }
    break;
  case 1:
    switch (token) {
    case 0x1C:
    case 0x32:
      str = wv_integer_from_opaque(tvb, offset + *length, data_len);
      break;
    default:
      break;
    }
    break;
  case 3:
    switch (token) {
    case 0x06:
    case 0x0C:
    case 0x0D:
    case 0x0E:
    case 0x12:
    case 0x13:
      str = wv_integer_from_opaque(tvb, offset + *length, data_len);
      break;
    default:
      break;
    }
    break;
  case 6:
    switch (token) {
    case 0x1A:
      str = wv_datetime_from_opaque(tvb, offset + *length, data_len);
      break;
    default:
      break;
    }
    break;
  default:
    break;
  }
  if (str == NULL) {
    str = wmem_strdup_printf(wmem_packet_scope(),
                             "(%d bytes of unparsed opaque data)", data_len);
  }
  *length += data_len;
  return str;
}

static int at1_parse_bsm(GetBitContext *gb, int log2_block_cnt[AT1_QMF_BANDS]) {
  int log2_block_count_tmp, i;
  for (i = 0; i < 2; i++) {
    log2_block_count_tmp = get_bits(gb, 2);
    if (log2_block_count_tmp & 1)
      return AVERROR_INVALIDDATA;
    log2_block_cnt[i] = 2 - log2_block_count_tmp;
  }
  log2_block_count_tmp = get_bits(gb, 2);
  if (log2_block_count_tmp != 0 && log2_block_count_tmp != 3)
    return AVERROR_INVALIDDATA;
  log2_block_cnt[IDX_HIGH_BAND] = 3 - log2_block_count_tmp;
  skip_bits(gb, 2);
  return 0;
}

static int server_request_free(struct server_request *req) {
  int i, rc = 1;
  if (req->base.questions) {
    for (i = 0; i < req->base.nquestions; ++i)
      free(req->base.questions[i]);
    free(req->base.questions);
  }
  if (req->port) {
    if (req->port->pending_replies == req) {
      if (req->next_pending)
        req->port->pending_replies = req->next_pending;
      else
        req->port->pending_replies = NULL;
    }
    rc = --req->port->refcnt;
  }
  if (req->response) {
    free(req->response);
  }
  server_request_free_answers(req);
  if (req->next_pending && req->next_pending != req) {
    req->next_pending->prev_pending = req->prev_pending;
    req->prev_pending->next_pending = req->next_pending;
  }
  if (rc == 0) {
    server_port_free(req->port);
    free(req);
    return (1);
  }
  free(req);
  return (0);
}

static void ppp_hdlc(netdissect_options *ndo, const u_char *p, int length) {
  u_char *b, *t, c;
  const u_char *s;
  int i, proto;
  const void *se;
  if (length <= 0)
    return;
  b = (u_char *)malloc(length);
  if (b == NULL)
    return;
  for (s = p, t = b, i = length; i > 0 && ND_TTEST(*s); i--) {
    c = *s++;
    if (c == 0x7d) {
      if (i <= 1 || !ND_TTEST(*s))
        break;
      i--;
      c = *s++ ^ 0x20;
    }
    *t++ = c;
  }
  se = ndo->ndo_snapend;
  ndo->ndo_snapend = t;
  length = t - b;
  if (length < 1)
    goto trunc;
  proto = *b;
  switch (proto) {
  case PPP_IP:
    ip_print(ndo, b + 1, length - 1);
    goto cleanup;
  case PPP_IPV6:
    ip6_print(ndo, b + 1, length - 1);
    goto cleanup;
  default:
    break;
  }
  if (length < 2)
    goto trunc;
  proto = EXTRACT_16BITS(b);
  switch (proto) {
  case (PPP_ADDRESS << 8 | PPP_CONTROL):
    if (length < 4)
      goto trunc;
    proto = EXTRACT_16BITS(b + 2);
    handle_ppp(ndo, proto, b + 4, length - 4);
    break;
  default:
    handle_ppp(ndo, proto, b + 2, length - 2);
    break;
  }
cleanup:
  ndo->ndo_snapend = se;
  free(b);
  return;
trunc:
  ndo->ndo_snapend = se;
  free(b);
  ND_PRINT((ndo, "[|ppp]"));
}

