        "ngsniffer: WAN capture protocol string %.*s unknown", length, buffer);
    return -1;
  }
  return 0;
}

static void cleanup_preferred_base(void) {
  struct pbase_tree *it;
  unsigned i;
  it = pbase_tree;
  pbase_tree = NULL;
  while (it) {
    struct pbase_tree *this = it;
    it = this->next;
    free(this->pcache.tree_data);
    free(this);
  }
  for (i = 0; i < ARRAY_SIZE(pbase_tree_cache); i++) {
    if (!pbase_tree_cache[i])
      continue;
    free(pbase_tree_cache[i]->tree_data);
    free(pbase_tree_cache[i]);
    pbase_tree_cache[i] = NULL;
  }
  free(done_pbase_paths);
  done_pbase_paths = NULL;
  done_pbase_paths_num = done_pbase_paths_alloc = 0;
}

static int evhttp_parse_response_line(struct evhttp_request *req, char *line) {
  char *protocol;
  char *number;
  const char *readable = "";
  protocol = strsep(&line, " ");
  if (line == NULL)
    return (-1);
  number = strsep(&line, " ");
  if (line != NULL)
    readable = line;
  if (strcmp(protocol, "HTTP/1.0") == 0) {
    req->major = 1;
    req->minor = 0;
  } else if (strcmp(protocol, "HTTP/1.1") == 0) {
    req->major = 1;
    req->minor = 1;
  } else {
    event_debug(("%s: bad protocol \"%s\"", __func__, protocol));
    return (-1);
  }
  req->response_code = atoi(number);
  if (!evhttp_valid_response_code(req->response_code)) {
    event_debug(("%s: bad response code \"%s\"", __func__, number));
    return (-1);
  }
  if ((req->response_code_line = strdup(readable)) == NULL)
    event_err(1, "%s: strdup", __func__);
  return (0);
}

