static void ctr64_inc(unsigned char *counter) {
  int n = 8;
  unsigned char c;
  do {
    --n;
    c = counter[n];
    ++c;
    counter[n] = c;
    if (c)
      return;
  } while (n);
}
static int aes_gcm_ctrl(EVP_CIPHER_CTX *c, int type, int arg, void *ptr) {
  EVP_AES_GCM_CTX *gctx = EVP_C_DATA(EVP_AES_GCM_CTX, c);
  switch (type) {
  case EVP_CTRL_INIT:
    gctx->key_set = 0;
    gctx->iv_set = 0;
    gctx->ivlen = EVP_CIPHER_CTX_iv_length(c);
    gctx->iv = EVP_CIPHER_CTX_iv_noconst(c);
    gctx->taglen = -1;
    gctx->iv_gen = 0;
    gctx->tls_aad_len = -1;
    return 1;
  case EVP_CTRL_AEAD_SET_IVLEN:
    if (arg <= 0)
      return 0;
    if ((arg > EVP_MAX_IV_LENGTH) && (arg > gctx->ivlen)) {
      if (gctx->iv != EVP_CIPHER_CTX_iv_noconst(c))
        OPENSSL_free(gctx->iv);
      gctx->iv = OPENSSL_malloc(arg);
      if (gctx->iv == NULL)
        return 0;
    }
    gctx->ivlen = arg;
    return 1;
  case EVP_CTRL_AEAD_SET_TAG:
    if (arg <= 0 || arg > 16 || EVP_CIPHER_CTX_encrypting(c))
      return 0;
    memcpy(EVP_CIPHER_CTX_buf_noconst(c), ptr, arg);
    gctx->taglen = arg;
    return 1;
  case EVP_CTRL_AEAD_GET_TAG:
    if (arg <= 0 || arg > 16 || !EVP_CIPHER_CTX_encrypting(c) ||
        gctx->taglen < 0)
      return 0;
    memcpy(ptr, EVP_CIPHER_CTX_buf_noconst(c), arg);
    return 1;
  case EVP_CTRL_GCM_SET_IV_FIXED:
    if (arg == -1) {
      memcpy(gctx->iv, ptr, gctx->ivlen);
      gctx->iv_gen = 1;
      return 1;
    }
    if ((arg < 4) || (gctx->ivlen - arg) < 8)
      return 0;
    if (arg)
      memcpy(gctx->iv, ptr, arg);
    if (EVP_CIPHER_CTX_encrypting(c) &&
        RAND_bytes(gctx->iv + arg, gctx->ivlen - arg) <= 0)
      return 0;
    gctx->iv_gen = 1;
    return 1;
  case EVP_CTRL_GCM_IV_GEN:
    if (gctx->iv_gen == 0 || gctx->key_set == 0)
      return 0;
    CRYPTO_gcm128_setiv(&gctx->gcm, gctx->iv, gctx->ivlen);
    if (arg <= 0 || arg > gctx->ivlen)
      arg = gctx->ivlen;
    memcpy(ptr, gctx->iv + gctx->ivlen - arg, arg);
    ctr64_inc(gctx->iv + gctx->ivlen - 8);
    gctx->iv_set = 1;
    return 1;
  case EVP_CTRL_GCM_SET_IV_INV:
    if (gctx->iv_gen == 0 || gctx->key_set == 0 || EVP_CIPHER_CTX_encrypting(c))
      return 0;
    memcpy(gctx->iv + gctx->ivlen - arg, ptr, arg);
    CRYPTO_gcm128_setiv(&gctx->gcm, gctx->iv, gctx->ivlen);
    gctx->iv_set = 1;
    return 1;
  case EVP_CTRL_AEAD_TLS1_AAD:
    if (arg != EVP_AEAD_TLS1_AAD_LEN)
      return 0;
    memcpy(EVP_CIPHER_CTX_buf_noconst(c), ptr, arg);
    gctx->tls_aad_len = arg;
    {
      unsigned int len = EVP_CIPHER_CTX_buf_noconst(c)[arg - 2] << 8 |
                         EVP_CIPHER_CTX_buf_noconst(c)[arg - 1];
      if (len < EVP_GCM_TLS_EXPLICIT_IV_LEN)
        return 0;
      len -= EVP_GCM_TLS_EXPLICIT_IV_LEN;
      if (!EVP_CIPHER_CTX_encrypting(c)) {
        if (len < EVP_GCM_TLS_TAG_LEN)
          return 0;
        len -= EVP_GCM_TLS_TAG_LEN;
      }
      EVP_CIPHER_CTX_buf_noconst(c)[arg - 2] = len >> 8;
      EVP_CIPHER_CTX_buf_noconst(c)[arg - 1] = len & 0xff;
    }
    return EVP_GCM_TLS_TAG_LEN;
  case EVP_CTRL_COPY: {
    EVP_CIPHER_CTX *out = ptr;
    EVP_AES_GCM_CTX *gctx_out = EVP_C_DATA(EVP_AES_GCM_CTX, out);
    if (gctx->gcm.key) {
      if (gctx->gcm.key != &gctx->ks)
        return 0;
      gctx_out->gcm.key = &gctx_out->ks;
    }
    if (gctx->iv == EVP_CIPHER_CTX_iv_noconst(c))
      gctx_out->iv = EVP_CIPHER_CTX_iv_noconst(out);
    else {
      gctx_out->iv = OPENSSL_malloc(gctx->ivlen);
      if (gctx_out->iv == NULL)
        return 0;
      memcpy(gctx_out->iv, gctx->iv, gctx->ivlen);
    }
    return 1;
  }
  default:
    return -1;
  }
}
static int aes_gcm_init_key(EVP_CIPHER_CTX *ctx, const unsigned char *key,
                            const unsigned char *iv, int enc) {
  EVP_AES_GCM_CTX *gctx = EVP_C_DATA(EVP_AES_GCM_CTX, ctx);
  if (!iv && !key)
    return 1;
  if (key) {
    do {
#ifdef HWAES_CAPABLE if (HWAES_CAPABLE) {
      HWAES_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 8,
                            &gctx->ks.ks);
      CRYPTO_gcm128_init(&gctx->gcm, &gctx->ks, (block128_f)HWAES_encrypt);
#ifdef HWAES_ctr32_encrypt_blocks gctx->ctr =                                  \
    (ctr128_f)HWAES_ctr32_encrypt_blocks;
#else gctx->ctr = NULL;
#endif break;
    }
    else #endif #ifdef BSAES_CAPABLE if (BSAES_CAPABLE) {
      AES_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 8,
                          &gctx->ks.ks);
      CRYPTO_gcm128_init(&gctx->gcm, &gctx->ks, (block128_f)AES_encrypt);
      gctx->ctr = (ctr128_f)bsaes_ctr32_encrypt_blocks;
      break;
    }
    else #endif #ifdef VPAES_CAPABLE if (VPAES_CAPABLE) {
      vpaes_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 8,
                            &gctx->ks.ks);
      CRYPTO_gcm128_init(&gctx->gcm, &gctx->ks, (block128_f)vpaes_encrypt);
      gctx->ctr = NULL;
      break;
    }
    else #endif(void) 0;
    AES_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 8, &gctx->ks.ks);
    CRYPTO_gcm128_init(&gctx->gcm, &gctx->ks, (block128_f)AES_encrypt);
#ifdef AES_CTR_ASM gctx->ctr = (ctr128_f)AES_ctr32_encrypt;
#else gctx->ctr = NULL;
#endif }
    while (0)
      ;
    if (iv == NULL && gctx->iv_set)
      iv = gctx->iv;
    if (iv) {
      CRYPTO_gcm128_setiv(&gctx->gcm, iv, gctx->ivlen);
      gctx->iv_set = 1;
    }
    gctx->key_set = 1;
  } else {
    if (gctx->key_set)
      CRYPTO_gcm128_setiv(&gctx->gcm, iv, gctx->ivlen);
    else
      memcpy(gctx->iv, iv, gctx->ivlen);
    gctx->iv_set = 1;
    gctx->iv_gen = 0;
  }
  return 1;
}
static int aes_gcm_tls_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                              const unsigned char *in, size_t len) {
  EVP_AES_GCM_CTX *gctx = EVP_C_DATA(EVP_AES_GCM_CTX, ctx);
  int rv = -1;
  if (out != in || len < (EVP_GCM_TLS_EXPLICIT_IV_LEN + EVP_GCM_TLS_TAG_LEN))
    return -1;
  if (EVP_CIPHER_CTX_ctrl(ctx,
                          EVP_CIPHER_CTX_encrypting(ctx)
                              ? EVP_CTRL_GCM_IV_GEN
                              : EVP_CTRL_GCM_SET_IV_INV,
                          EVP_GCM_TLS_EXPLICIT_IV_LEN, out) <= 0)
    goto err;
  if (CRYPTO_gcm128_aad(&gctx->gcm, EVP_CIPHER_CTX_buf_noconst(ctx),
                        gctx->tls_aad_len))
    goto err;
  in += EVP_GCM_TLS_EXPLICIT_IV_LEN;
  out += EVP_GCM_TLS_EXPLICIT_IV_LEN;
  len -= EVP_GCM_TLS_EXPLICIT_IV_LEN + EVP_GCM_TLS_TAG_LEN;
  if (EVP_CIPHER_CTX_encrypting(ctx)) {
    if (gctx->ctr) {
      size_t bulk = 0;
#if defined(AES_GCM_ASM) if (len >= 32 && AES_GCM_ASM(gctx)) {
      if (CRYPTO_gcm128_encrypt(&gctx->gcm, NULL, NULL, 0))
        return -1;
      bulk = AES_gcm_encrypt(in, out, len, gctx->gcm.key, gctx->gcm.Yi.c,
                             gctx->gcm.Xi.u);
      gctx->gcm.len.u[1] += bulk;
    }
#endif if (CRYPTO_gcm128_encrypt_ctr32(&gctx->gcm, in + bulk, out + bulk,      \
                                       len - bulk, gctx->ctr)) goto err;
  } else {
    size_t bulk = 0;
#if defined(AES_GCM_ASM2) if (len >= 32 && AES_GCM_ASM2(gctx)) {
    if (CRYPTO_gcm128_encrypt(&gctx->gcm, NULL, NULL, 0))
      return -1;
    bulk = AES_gcm_encrypt(in, out, len, gctx->gcm.key, gctx->gcm.Yi.c,
                           gctx->gcm.Xi.u);
    gctx->gcm.len.u[1] += bulk;
  }
#endif if (CRYPTO_gcm128_encrypt(&gctx->gcm, in + bulk, out + bulk,            \
                                 len - bulk)) goto err;
}
out += len;
CRYPTO_gcm128_tag(&gctx->gcm, out, EVP_GCM_TLS_TAG_LEN);
rv = len + EVP_GCM_TLS_EXPLICIT_IV_LEN + EVP_GCM_TLS_TAG_LEN;
}
else {
  if (gctx->ctr) {
    size_t bulk = 0;
#if defined(AES_GCM_ASM) if (len >= 16 && AES_GCM_ASM(gctx)) {
    if (CRYPTO_gcm128_decrypt(&gctx->gcm, NULL, NULL, 0))
      return -1;
    bulk = AES_gcm_decrypt(in, out, len, gctx->gcm.key, gctx->gcm.Yi.c,
                           gctx->gcm.Xi.u);
    gctx->gcm.len.u[1] += bulk;
  }
#endif if (CRYPTO_gcm128_decrypt_ctr32(&gctx->gcm, in + bulk, out + bulk,      \
                                       len - bulk, gctx->ctr)) goto err;
}
else {
  size_t bulk = 0;
#if defined(AES_GCM_ASM2) if (len >= 16 && AES_GCM_ASM2(gctx)) {
  if (CRYPTO_gcm128_decrypt(&gctx->gcm, NULL, NULL, 0))
    return -1;
  bulk = AES_gcm_decrypt(in, out, len, gctx->gcm.key, gctx->gcm.Yi.c,
                         gctx->gcm.Xi.u);
  gctx->gcm.len.u[1] += bulk;
}
#endif if (CRYPTO_gcm128_decrypt(&gctx->gcm, in + bulk, out + bulk,            \
                                 len - bulk)) goto err;
}
CRYPTO_gcm128_tag(&gctx->gcm, EVP_CIPHER_CTX_buf_noconst(ctx),
                  EVP_GCM_TLS_TAG_LEN);
if (CRYPTO_memcmp(EVP_CIPHER_CTX_buf_noconst(ctx), in + len,
                  EVP_GCM_TLS_TAG_LEN)) {
  OPENSSL_cleanse(out, len);
  goto err;
}
rv = len;
}
err : gctx->iv_set = 0;
gctx->tls_aad_len = -1;
return rv;
}
static int aes_gcm_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                          const unsigned char *in, size_t len) {
  EVP_AES_GCM_CTX *gctx = EVP_C_DATA(EVP_AES_GCM_CTX, ctx);
  if (!gctx->key_set)
    return -1;
  if (gctx->tls_aad_len >= 0)
    return aes_gcm_tls_cipher(ctx, out, in, len);
  if (!gctx->iv_set)
    return -1;
  if (in) {
    if (out == NULL) {
      if (CRYPTO_gcm128_aad(&gctx->gcm, in, len))
        return -1;
    } else if (EVP_CIPHER_CTX_encrypting(ctx)) {
      if (gctx->ctr) {
        size_t bulk = 0;
#if defined(AES_GCM_ASM) if (len >= 32 && AES_GCM_ASM(gctx)) {
        size_t res = (16 - gctx->gcm.mres) % 16;
        if (CRYPTO_gcm128_encrypt(&gctx->gcm, in, out, res))
          return -1;
        bulk = AES_gcm_encrypt(in + res, out + res, len - res, gctx->gcm.key,
                               gctx->gcm.Yi.c, gctx->gcm.Xi.u);
        gctx->gcm.len.u[1] += bulk;
        bulk += res;
      }
#endif if (CRYPTO_gcm128_encrypt_ctr32(&gctx->gcm, in + bulk, out + bulk,      \
                                       len - bulk, gctx->ctr)) return -1;
    } else {
      size_t bulk = 0;
#if defined(AES_GCM_ASM2) if (len >= 32 && AES_GCM_ASM2(gctx)) {
      size_t res = (16 - gctx->gcm.mres) % 16;
      if (CRYPTO_gcm128_encrypt(&gctx->gcm, in, out, res))
        return -1;
      bulk = AES_gcm_encrypt(in + res, out + res, len - res, gctx->gcm.key,
                             gctx->gcm.Yi.c, gctx->gcm.Xi.u);
      gctx->gcm.len.u[1] += bulk;
      bulk += res;
    }
#endif if (CRYPTO_gcm128_encrypt(&gctx->gcm, in + bulk, out + bulk,            \
                                 len - bulk)) return -1;
  }
}
else {
  if (gctx->ctr) {
    size_t bulk = 0;
#if defined(AES_GCM_ASM) if (len >= 16 && AES_GCM_ASM(gctx)) {
    size_t res = (16 - gctx->gcm.mres) % 16;
    if (CRYPTO_gcm128_decrypt(&gctx->gcm, in, out, res))
      return -1;
    bulk = AES_gcm_decrypt(in + res, out + res, len - res, gctx->gcm.key,
                           gctx->gcm.Yi.c, gctx->gcm.Xi.u);
    gctx->gcm.len.u[1] += bulk;
    bulk += res;
  }
#endif if (CRYPTO_gcm128_decrypt_ctr32(&gctx->gcm, in + bulk, out + bulk,      \
                                       len - bulk, gctx->ctr)) return -1;
}
else {
  size_t bulk = 0;
#if defined(AES_GCM_ASM2) if (len >= 16 && AES_GCM_ASM2(gctx)) {
  size_t res = (16 - gctx->gcm.mres) % 16;
  if (CRYPTO_gcm128_decrypt(&gctx->gcm, in, out, res))
    return -1;
  bulk = AES_gcm_decrypt(in + res, out + res, len - res, gctx->gcm.key,
                         gctx->gcm.Yi.c, gctx->gcm.Xi.u);
  gctx->gcm.len.u[1] += bulk;
  bulk += res;
}
#endif if (CRYPTO_gcm128_decrypt(&gctx->gcm, in + bulk, out + bulk,            \
                                 len - bulk)) return -1;
}
}
return len;
}
else {
  if (!EVP_CIPHER_CTX_encrypting(ctx)) {
    if (gctx->taglen < 0)
      return -1;
    if (CRYPTO_gcm128_finish(&gctx->gcm, EVP_CIPHER_CTX_buf_noconst(ctx),
                             gctx->taglen) != 0)
      return -1;
    gctx->iv_set = 0;
    return 0;
  }
  CRYPTO_gcm128_tag(&gctx->gcm, EVP_CIPHER_CTX_buf_noconst(ctx), 16);
  gctx->taglen = 16;
  gctx->iv_set = 0;
  return 0;
}
}
#define CUSTOM_FLAGS                                                           \
  (EVP_CIPH_FLAG_DEFAULT_ASN1 \ | EVP_CIPH_CUSTOM_IV |                         \
   EVP_CIPH_FLAG_CUSTOM_CIPHER \ | EVP_CIPH_ALWAYS_CALL_INIT |                 \
   EVP_CIPH_CTRL_INIT \ | EVP_CIPH_CUSTOM_COPY)                                \
      BLOCK_CIPHER_custom(NID_aes, 128, 1, 12, gcm, GCM,                       \
                          EVP_CIPH_FLAG_AEAD_CIPHER | CUSTOM_FLAGS)            \
          BLOCK_CIPHER_custom(NID_aes, 192, 1, 12, gcm, GCM,                   \
                              EVP_CIPH_FLAG_AEAD_CIPHER | CUSTOM_FLAGS)        \
              BLOCK_CIPHER_custom(NID_aes, 256, 1, 12, gcm, GCM,               \
                                  EVP_CIPH_FLAG_AEAD_CIPHER |                  \
                                      CUSTOM_FLAGS) static int                 \
              aes_xts_ctrl(EVP_CIPHER_CTX *c, int type, int arg, void *ptr) {
EVP_AES_XTS_CTX *xctx = EVP_C_DATA(EVP_AES_XTS_CTX, c);
if (type == EVP_CTRL_COPY) {
  EVP_CIPHER_CTX *out = ptr;
  EVP_AES_XTS_CTX *xctx_out = EVP_C_DATA(EVP_AES_XTS_CTX, out);
  if (xctx->xts.key1) {
    if (xctx->xts.key1 != &xctx->ks1)
      return 0;
    xctx_out->xts.key1 = &xctx_out->ks1;
  }
  if (xctx->xts.key2) {
    if (xctx->xts.key2 != &xctx->ks2)
      return 0;
    xctx_out->xts.key2 = &xctx_out->ks2;
  }
  return 1;
} else if (type != EVP_CTRL_INIT)
  return -1;
xctx->xts.key1 = NULL;
xctx->xts.key2 = NULL;
return 1;
}
static int aes_xts_init_key(EVP_CIPHER_CTX *ctx, const unsigned char *key,
                            const unsigned char *iv, int enc) {
  EVP_AES_XTS_CTX *xctx = EVP_C_DATA(EVP_AES_XTS_CTX, ctx);
  if (!iv && !key)
    return 1;
  if (key)
    do {
#ifdef AES_XTS_ASM xctx->stream = enc ? AES_xts_encrypt : AES_xts_decrypt;
#else xctx->stream = NULL;
#endif #ifdef HWAES_CAPABLE if (HWAES_CAPABLE) {
      if (enc) {
        HWAES_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 4,
                              &xctx->ks1.ks);
        xctx->xts.block1 = (block128_f)HWAES_encrypt;
#ifdef HWAES_xts_encrypt xctx->stream = HWAES_xts_encrypt;
#endif }
        else {
          HWAES_set_decrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 4,
                                &xctx->ks1.ks);
          xctx->xts.block1 = (block128_f)HWAES_decrypt;
#ifdef HWAES_xts_decrypt xctx->stream = HWAES_xts_decrypt;
#endif }
          HWAES_set_encrypt_key(key + EVP_CIPHER_CTX_key_length(ctx) / 2,
                                EVP_CIPHER_CTX_key_length(ctx) * 4,
                                &xctx->ks2.ks);
          xctx->xts.block2 = (block128_f)HWAES_encrypt;
          xctx->xts.key1 = &xctx->ks1;
          break;
        }
        else #endif #ifdef BSAES_CAPABLE if (BSAES_CAPABLE) xctx->stream =
            enc ? bsaes_xts_encrypt : bsaes_xts_decrypt;
        else #endif #ifdef VPAES_CAPABLE if (VPAES_CAPABLE) {
          if (enc) {
            vpaes_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 4,
                                  &xctx->ks1.ks);
            xctx->xts.block1 = (block128_f)vpaes_encrypt;
          } else {
            vpaes_set_decrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 4,
                                  &xctx->ks1.ks);
            xctx->xts.block1 = (block128_f)vpaes_decrypt;
          }
          vpaes_set_encrypt_key(key + EVP_CIPHER_CTX_key_length(ctx) / 2,
                                EVP_CIPHER_CTX_key_length(ctx) * 4,
                                &xctx->ks2.ks);
          xctx->xts.block2 = (block128_f)vpaes_encrypt;
          xctx->xts.key1 = &xctx->ks1;
          break;
        }
        else #endif(void) 0;
        if (enc) {
          AES_set_encrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 4,
                              &xctx->ks1.ks);
          xctx->xts.block1 = (block128_f)AES_encrypt;
        } else {
          AES_set_decrypt_key(key, EVP_CIPHER_CTX_key_length(ctx) * 4,
                              &xctx->ks1.ks);
          xctx->xts.block1 = (block128_f)AES_decrypt;
        }
        AES_set_encrypt_key(key + EVP_CIPHER_CTX_key_length(ctx) / 2,
                            EVP_CIPHER_CTX_key_length(ctx) * 4, &xctx->ks2.ks);
        xctx->xts.block2 = (block128_f)AES_encrypt;
        xctx->xts.key1 = &xctx->ks1;
      }
      while (0)
        ;
      if (iv) {
        xctx->xts.key2 = &xctx->ks2;
        memcpy(EVP_CIPHER_CTX_iv_noconst(ctx), iv, 16);
      }
      return 1;
    }
  static int aes_xts_cipher(EVP_CIPHER_CTX * ctx, unsigned char *out,
                            const unsigned char *in, size_t len) {
    EVP_AES_XTS_CTX *xctx = EVP_C_DATA(EVP_AES_XTS_CTX, ctx);
    if (!xctx->xts.key1 || !xctx->xts.key2)
      return 0;
    if (!out || !in || len < AES_BLOCK_SIZE)
      return 0;
    if (xctx->stream)
      (*xctx->stream)(in, out, len, xctx->xts.key1, xctx->xts.key2,
                      EVP_CIPHER_CTX_iv_noconst(ctx));
    else if (CRYPTO_xts128_encrypt(&xctx->xts, EVP_CIPHER_CTX_iv_noconst(ctx),
                                   in, out, len,
                                   EVP_CIPHER_CTX_encrypting(ctx)))
      return 0;
    return 1;
  }
