  NULL #define XTS_FLAGS(EVP_CIPH_FLAG_DEFAULT_ASN1 | EVP_CIPH_CUSTOM_IV \ |   \
                         EVP_CIPH_ALWAYS_CALL_INIT | EVP_CIPH_CTRL_INIT \ |    \
                         EVP_CIPH_CUSTOM_COPY)                                 \
      BLOCK_CIPHER_custom(NID_aes, 128, 1, 16, xts, XTS, XTS_FLAGS)

static YYSIZE_T yysyntax_error(char *yyresult, int yystate, int yychar) {
  int yyn = yypact[yystate];
  if (!(YYPACT_NINF < yyn && yyn <= YYLAST))
    return 0;
  else {
    int yytype = YYTRANSLATE(yychar);
    YYSIZE_T yysize0 = yytnamerr(0, yytname[yytype]);
    YYSIZE_T yysize = yysize0;
    YYSIZE_T yysize1;
    int yysize_overflow = 0;
    enum { YYERROR_VERBOSE_ARGS_MAXIMUM = 5 };
    char const *yyarg[YYERROR_VERBOSE_ARGS_MAXIMUM];
    int yyx;
#if 0 YY_("syntax error, unexpected %s");
 YY_ ( "syntax error, unexpected %s, expecting %s" ) ;
 YY_ ( "syntax error, unexpected %s, expecting %s or %s" ) ;
 YY_ ( "syntax error, unexpected %s, expecting %s or %s or %s" ) ;
 YY_ ( "syntax error, unexpected %s, expecting %s or %s or %s or %s" ) ;
#endif char *yyfmt;
    char const *yyf;
    static char const yyunexpected[] = "syntax error, unexpected %s";
    static char const yyexpecting[] = ", expecting %s";
    static char const yyor[] = " or %s";
    char yyformat[sizeof yyunexpected + sizeof yyexpecting - 1 +
                  ((YYERROR_VERBOSE_ARGS_MAXIMUM - 2) * (sizeof yyor - 1))];
    char const *yyprefix = yyexpecting;
    int yyxbegin = yyn < 0 ? -yyn : 0;
    int yychecklim = YYLAST - yyn + 1;
    int yyxend = yychecklim < YYNTOKENS ? yychecklim : YYNTOKENS;
    int yycount = 1;
    yyarg[0] = yytname[yytype];
    yyfmt = yystpcpy(yyformat, yyunexpected);
    for (yyx = yyxbegin; yyx < yyxend; ++yyx)
      if (yycheck[yyx + yyn] == yyx && yyx != YYTERROR) {
        if (yycount == YYERROR_VERBOSE_ARGS_MAXIMUM) {
          yycount = 1;
          yysize = yysize0;
          yyformat[sizeof yyunexpected - 1] = '\0';
          break;
        }
        yyarg[yycount++] = yytname[yyx];
        yysize1 = yysize + yytnamerr(0, yytname[yyx]);
        yysize_overflow |= (yysize1 < yysize);
        yysize = yysize1;
        yyfmt = yystpcpy(yyfmt, yyprefix);
        yyprefix = yyor;
      }
    yyf = YY_(yyformat);
    yysize1 = yysize + yystrlen(yyf);
    yysize_overflow |= (yysize1 < yysize);
    yysize = yysize1;
    if (yysize_overflow)
      return YYSIZE_MAXIMUM;
    if (yyresult) {
      char *yyp = yyresult;
      int yyi = 0;
      while ((*yyp = *yyf) != '\0') {
        if (*yyp == '%' && yyf[1] == 's' && yyi < yycount) {
          yyp += yytnamerr(yyp, yyarg[yyi++]);
          yyf += 2;
        } else {
          yyp++;
          yyf++;
        }
      }
    }
    return yysize;
  }
}

static inline const unsigned char *
PushDoublePixel(QuantumInfo *quantum_info,
                const unsigned char *magick_restrict pixels, double *pixel) {
  double *p;
  unsigned char quantum[8];
  if (quantum_info->endian == LSBEndian) {
    quantum[0] = (*pixels++);
    quantum[1] = (*pixels++);
    quantum[2] = (*pixels++);
    quantum[3] = (*pixels++);
    quantum[4] = (*pixels++);
    quantum[5] = (*pixels++);
    quantum[6] = (*pixels++);
    quantum[7] = (*pixels++);
    p = (double *)quantum;
    *pixel = (*p);
    *pixel -= quantum_info->minimum;
    *pixel *= quantum_info->scale;
    return (pixels);
  }
  quantum[7] = (*pixels++);
  quantum[6] = (*pixels++);
  quantum[5] = (*pixels++);
  quantum[4] = (*pixels++);
  quantum[3] = (*pixels++);
  quantum[2] = (*pixels++);
  quantum[1] = (*pixels++);
  quantum[0] = (*pixels++);
  p = (double *)quantum;
  *pixel = (*p);
  *pixel -= quantum_info->minimum;
  *pixel *= quantum_info->scale;
  return (pixels);
}

static void test_ushort_bug() {
  MYSQL_STMT *stmt;
  MYSQL_BIND my_bind[4];
  ushort short_value;
  uint32 long_value;
  ulong s_length, l_length, ll_length, t_length;
  ulonglong longlong_value;
  int rc;
  uchar tiny_value;
  char llbuf[22];
  myheader("test_ushort_bug");
  rc = mysql_query(mysql, "DROP TABLE IF EXISTS test_ushort");
  myquery(rc);
  rc = mysql_query(mysql,
                   "CREATE TABLE test_ushort(a smallint unsigned, \ b smallint "
                   "unsigned, \ c smallint unsigned, \ d smallint unsigned)");
  myquery(rc);
  rc = mysql_query(mysql,
                   "INSERT INTO test_ushort VALUES(35999, 35999, 35999, 200)");
  myquery(rc);
  stmt = mysql_simple_prepare(mysql, "SELECT * FROM test_ushort");
  check_stmt(stmt);
  rc = mysql_stmt_execute(stmt);
  check_execute(stmt, rc);
  memset(my_bind, 0, sizeof(my_bind));
  my_bind[0].buffer_type = MYSQL_TYPE_SHORT;
  my_bind[0].buffer = (void *)&short_value;
  my_bind[0].is_unsigned = TRUE;
  my_bind[0].length = &s_length;
  my_bind[1].buffer_type = MYSQL_TYPE_LONG;
  my_bind[1].buffer = (void *)&long_value;
  my_bind[1].length = &l_length;
  my_bind[2].buffer_type = MYSQL_TYPE_LONGLONG;
  my_bind[2].buffer = (void *)&longlong_value;
  my_bind[2].length = &ll_length;
  my_bind[3].buffer_type = MYSQL_TYPE_TINY;
  my_bind[3].buffer = (void *)&tiny_value;
  my_bind[3].is_unsigned = TRUE;
  my_bind[3].length = &t_length;
  rc = mysql_stmt_bind_result(stmt, my_bind);
  check_execute(stmt, rc);
  rc = mysql_stmt_fetch(stmt);
  check_execute(stmt, rc);
  if (!opt_silent) {
    fprintf(stdout, "\n ushort : %d (%ld)", short_value, s_length);
    fprintf(stdout, "\n ulong : %lu (%ld)", (ulong)long_value, l_length);
    fprintf(stdout, "\n longlong : %s (%ld)", llstr(longlong_value, llbuf),
            ll_length);
    fprintf(stdout, "\n tinyint : %d (%ld)", tiny_value, t_length);
  }
  DIE_UNLESS(short_value == 35999);
  DIE_UNLESS(s_length == 2);
  DIE_UNLESS(long_value == 35999);
  DIE_UNLESS(l_length == 4);
  DIE_UNLESS(longlong_value == 35999);
  DIE_UNLESS(ll_length == 8);
  DIE_UNLESS(tiny_value == 200);
  DIE_UNLESS(t_length == 1);
  rc = mysql_stmt_fetch(stmt);
  DIE_UNLESS(rc == MYSQL_NO_DATA);
  mysql_stmt_close(stmt);
}

OFCondition parseAssociate(unsigned char *buf, unsigned long pduLength,
                           PRV_ASSOCIATEPDU *assoc) {
  OFCondition cond = EC_Normal;
  unsigned char type;
  unsigned long itemLength;
  PRV_PRESENTATIONCONTEXTITEM *context;
  (void)memset(assoc, 0, sizeof(*assoc));
  if ((assoc->presentationContextList = LST_Create()) == NULL)
    return EC_MemoryExhausted;
  if ((assoc->userInfo.SCUSCPRoleList = LST_Create()) == NULL)
    return EC_MemoryExhausted;
  if (pduLength < 2 + 2 + 16 + 16 + 32)
    return makeLengthError("associate PDU", pduLength, 2 + 2 + 16 + 16 + 32);
  assoc->type = *buf++;
  assoc->rsv1 = *buf++;
  EXTRACT_LONG_BIG(buf, assoc->length);
  buf += 4;
  EXTRACT_SHORT_BIG(buf, assoc->protocol);
  buf += 2;
  pduLength -= 2;
  if ((assoc->protocol & DUL_PROTOCOL) == 0) {
    char buffer[256];
 sprintf ( buffer , "DUL Unsupported peer protocol %04x;
 expected %04x in %s" , assoc -> protocol , DUL_PROTOCOL , "parseAssociate" ) ;
 return makeDcmnetCondition ( DULC_UNSUPPORTEDPEERPROTOCOL , OF_error , buffer ) ;
  }
  assoc->rsv2[0] = *buf++;
  pduLength--;
  assoc->rsv2[1] = *buf++;
  pduLength--;
  (void)strncpy(assoc->calledAPTitle, (char *)buf, 16);
  assoc->calledAPTitle[16] = '\0';
  trim_trailing_spaces(assoc->calledAPTitle);
  buf += 16;
  pduLength -= 16;
  (void)strncpy(assoc->callingAPTitle, (char *)buf, 16);
  assoc->callingAPTitle[16] = '\0';
  trim_trailing_spaces(assoc->callingAPTitle);
  buf += 16;
  pduLength -= 16;
  (void)memcpy(assoc->rsv3, buf, 32);
  buf += 32;
  pduLength -= 32;
  if (DCM_dcmnetLogger.isEnabledFor(OFLogger : : DEBUG_LOG_LEVEL)) {
    const char *s;
    DCMNET_DEBUG("Parsing an A-ASSOCIATE PDU");
    if (assoc->type == DUL_TYPEASSOCIATERQ)
      s = "A-ASSOCIATE RQ";
    else if (assoc->type == DUL_TYPEASSOCIATEAC)
      s = "A-ASSOCIATE AC";
    else
      s = "Unknown: Programming bug in parseAssociate";
    DCMNET_TRACE("PDU type: "
                 << STD_NAMESPACE hex << ((unsigned int)assoc->type)
                 << STD_NAMESPACE dec << " (" << s
                 << "), PDU Length: " << assoc->length << OFendl
                 << "DICOM Protocol: " << STD_NAMESPACE hex << assoc->protocol
                 << STD_NAMESPACE dec << OFendl
                 << "Called AP Title: " << assoc->calledAPTitle << OFendl
                 << "Calling AP Title: " << assoc->callingAPTitle);
  }
  while ((cond.good()) && (pduLength > 0)) {
    type = *buf;
    DCMNET_TRACE("Parsing remaining "
                 << pduLength << " bytes of A-ASSOCIATE PDU" << OFendl
                 << "Next item type: " << STD_NAMESPACE hex
                 << STD_NAMESPACE setfill('0') << STD_NAMESPACE setw(2)
                 << ((unsigned int)type));
    switch (type) {
    case DUL_TYPEAPPLICATIONCONTEXT:
      cond =
          parseSubItem(&assoc->applicationContext, buf, &itemLength, pduLength);
      if (cond.good()) {
        buf += itemLength;
        pduLength -= itemLength;
        DCMNET_TRACE("Successfully parsed Application Context");
      }
      break;
    case DUL_TYPEPRESENTATIONCONTEXTRQ:
    case DUL_TYPEPRESENTATIONCONTEXTAC:
      context = (PRV_PRESENTATIONCONTEXTITEM *)malloc(
          sizeof(PRV_PRESENTATIONCONTEXTITEM));
      if (context == NULL)
        return EC_MemoryExhausted;
      (void)memset(context, 0, sizeof(*context));
      cond =
          parsePresentationContext(type, context, buf, &itemLength, pduLength);
      if (cond.bad())
        return cond;
      buf += itemLength;
      pduLength -= itemLength;
      LST_Enqueue(&assoc->presentationContextList, (LST_NODE *)context);
      DCMNET_TRACE("Successfully parsed Presentation Context");
      break;
    case DUL_TYPEUSERINFO:
      cond = parseUserInfo(&assoc->userInfo, buf, &itemLength, assoc->type,
                           pduLength);
      if (cond.bad())
        return cond;
      buf += itemLength;
      pduLength -= itemLength;
      DCMNET_TRACE("Successfully parsed User Information");
      break;
    default:
      cond = parseDummy(buf, &itemLength, pduLength);
      buf += itemLength;
      pduLength -= itemLength;
      break;
    }
  }
  return cond;
}

static int frame_max_bits(const RATE_CONTROL *rc,
                          const VP9EncoderConfig *oxcf) {
  int64_t max_bits = ((int64_t)rc->avg_frame_bandwidth *
                      (int64_t)oxcf->two_pass_vbrmax_section) /
                     100;
  if (max_bits < 0)
    max_bits = 0;
  else if (max_bits > rc->max_frame_bandwidth)
    max_bits = rc->max_frame_bandwidth;
  return (int)max_bits;
}

static void dissect_q931_IEs(tvbuff_t *tvb, packet_info *pinfo,
                             proto_tree *root_tree, proto_tree *q931_tree,
                             gboolean is_over_ip, int offset,
                             int initial_codeset) {
  proto_item *ti;
  proto_tree *ie_tree = NULL;
  guint8 info_element;
  guint8 dummy;
  guint16 info_element_len;
  int codeset, locked_codeset;
  gboolean non_locking_shift, first_segment;
  tvbuff_t *h225_tvb, *next_tvb;
  e164_info_t e164_info;
  e164_info.e164_number_type = NONE;
  e164_info.nature_of_address = NONE;
  e164_info.E164_number_str = "";
  e164_info.E164_number_length = NONE;
  codeset = locked_codeset = initial_codeset;
  first_segment = FALSE;
  while (tvb_reported_length_remaining(tvb, offset) > 0) {
    info_element = tvb_get_guint8(tvb, offset);
    if ((info_element & Q931_IE_SO_MASK) &&
        ((info_element & Q931_IE_SO_IDENTIFIER_MASK) == Q931_IE_SHIFT)) {
      non_locking_shift = info_element & Q931_IE_SHIFT_NON_LOCKING;
      codeset = info_element & Q931_IE_SHIFT_CODESET;
      if (!non_locking_shift)
        locked_codeset = codeset;
      if (q931_tree != NULL) {
        proto_tree_add_uint_format(
            q931_tree, hf_q931_locking_codeset, tvb, offset, 1, codeset,
            "%s shift to codeset %u: %s",
            (non_locking_shift ? "Non-locking" : "Locking"), codeset,
            val_to_str(codeset, q931_codeset_vals, "Unknown (0x%02X)"));
      }
      offset += 1;
      continue;
    }
    if (info_element & Q931_IE_SO_MASK) {
      if (dissector_get_uint_handle(codeset_dissector_table, codeset) ||
          dissector_get_uint_handle(
              ie_dissector_table,
              (codeset << 8) | (info_element & Q931_IE_SO_IDENTIFIER_MASK))) {
        next_tvb = tvb_new_subset_length(tvb, offset, 1);
        if (dissector_try_uint(ie_dissector_table,
                               (codeset << 8) |
                                   (info_element & Q931_IE_SO_IDENTIFIER_MASK),
                               next_tvb, pinfo, q931_tree) ||
            dissector_try_uint(codeset_dissector_table, codeset, next_tvb,
                               pinfo, q931_tree)) {
          offset += 1;
          codeset = locked_codeset;
          continue;
        }
      }
      switch ((codeset << 8) | (info_element & Q931_IE_SO_IDENTIFIER_MASK)) {
      case CS0 | Q931_IE_MORE_DATA_OR_SEND_COMP:
        switch (info_element) {
        case Q931_IE_MORE_DATA:
          proto_tree_add_item(q931_tree, hf_q931_more_data, tvb, offset, 1,
                              ENC_NA);
          break;
        case Q931_IE_SENDING_COMPLETE:
          proto_tree_add_item(q931_tree, hf_q931_sending_complete, tvb, offset,
                              1, ENC_NA);
          break;
        default:
          proto_tree_add_expert_format(
              q931_tree, pinfo, &ei_q931_information_element, tvb, offset, 1,
              "Unknown information element (0x%02X)", info_element);
          break;
        }
        break;
      case CS0 | Q931_IE_CONGESTION_LEVEL:
        proto_tree_add_item(q931_tree, hf_q931_congestion_level, tvb, offset, 1,
                            ENC_BIG_ENDIAN);
        break;
      case CS0 | Q931_IE_REPEAT_INDICATOR:
        proto_tree_add_item(q931_tree, hf_q931_repeat_indicator, tvb, offset, 1,
                            ENC_BIG_ENDIAN);
        break;
      default:
        proto_tree_add_expert_format(
            q931_tree, pinfo, &ei_q931_information_element, tvb, offset, 1,
            "Unknown information element (0x%02X)", info_element);
        break;
      }
      offset += 1;
      codeset = locked_codeset;
      continue;
    }
    if (is_over_ip && tvb_bytes_exist(tvb, offset, 4) && codeset == 0 &&
        tvb_get_guint8(tvb, offset) == Q931_IE_USER_USER &&
        tvb_get_guint8(tvb, offset + 3) == Q931_PROTOCOL_DISCRIMINATOR_ASN1) {
      info_element_len = tvb_get_ntohs(tvb, offset + 1);
      if (q931_tree != NULL) {
        ie_tree = proto_tree_add_subtree(
            q931_tree, tvb, offset, 1 + 2 + info_element_len,
            ett_q931_ie[info_element], NULL,
            val_to_str(info_element, q931_info_element_vals[codeset],
                       "Unknown information element (0x%02X)"));
        proto_tree_add_uint_format_value(
            ie_tree, hf_q931_information_element, tvb, offset, 1, info_element,
            "%s",
            val_to_str(info_element, q931_info_element_vals[codeset],
                       "Unknown (0x%02X)"));
        proto_tree_add_item(ie_tree, hf_q931_information_element_len, tvb,
                            offset + 1, 2, ENC_BIG_ENDIAN);
        proto_tree_add_item(ie_tree, hf_q931_user_protocol_discriminator, tvb,
                            offset + 3, 1, ENC_NA);
      }
      if (info_element_len > 1) {
        if (!pinfo->can_desegment) {
          info_element_len = MIN(
              info_element_len, tvb_captured_length_remaining(tvb, offset + 3));
        }
        if (h225_handle != NULL) {
          h225_tvb =
              tvb_new_subset_length(tvb, offset + 4, info_element_len - 1);
          call_dissector(h225_handle, h225_tvb, pinfo, root_tree);
        } else {
          proto_tree_add_item(ie_tree, hf_q931_user_information_bytes, tvb,
                              offset + 4, info_element_len - 1, ENC_NA);
        }
      }
      offset += 1 + 2 + info_element_len;
    } else {
      info_element_len = tvb_get_guint8(tvb, offset + 1);
      if (first_segment &&
          (tvb_reported_length_remaining(tvb, offset + 2) < info_element_len)) {
        proto_tree_add_expert(q931_tree, pinfo, &ei_q931_incomplete_ie, tvb,
                              offset, -1);
        break;
      }
      if (dissector_get_uint_handle(codeset_dissector_table, codeset) ||
          dissector_get_uint_handle(ie_dissector_table,
                                    (codeset << 8) | info_element)) {
        next_tvb = tvb_new_subset_length(tvb, offset, info_element_len + 2);
        if (dissector_try_uint(ie_dissector_table,
                               (codeset << 8) | info_element, next_tvb, pinfo,
                               q931_tree) ||
            dissector_try_uint(codeset_dissector_table, codeset, next_tvb,
                               pinfo, q931_tree)) {
          offset += 2 + info_element_len;
          codeset = locked_codeset;
          continue;
        }
      }
      ie_tree = proto_tree_add_subtree(
          q931_tree, tvb, offset, 1 + 1 + info_element_len,
          ett_q931_ie[info_element], &ti,
          val_to_str(info_element, q931_info_element_vals[codeset],
                     "Unknown information element (0x%02X)"));
      proto_tree_add_uint_format_value(
          ie_tree, hf_q931_information_element, tvb, offset, 1, info_element,
          "%s",
          val_to_str(info_element, q931_info_element_vals[codeset],
                     "Unknown (0x%02X)"));
      proto_tree_add_uint(ie_tree, hf_q931_information_element_len, tvb,
                          offset + 1, 1, info_element_len);
      if (((codeset << 8) | info_element) ==
          (CS0 | Q931_IE_SEGMENTED_MESSAGE)) {
        dissect_q931_segmented_message_ie(tvb, pinfo, offset + 2,
                                          info_element_len, ie_tree, ti);
        col_append_fstr(pinfo->cinfo, COL_INFO, " of %s",
                        val_to_str_ext(tvb_get_guint8(tvb, offset + 3),
                                       &q931_message_type_vals_ext,
                                       "Unknown message type (0x%02X)"));
        if (tvb_get_guint8(tvb, offset + 2) & 0x80) {
          first_segment = TRUE;
        } else {
          proto_tree_add_item(q931_tree, hf_q931_message_segment, tvb,
                              offset + 4, -1, ENC_NA);
          info_element_len += tvb_reported_length_remaining(tvb, offset + 4);
        }
      } else {
        switch ((codeset << 8) | info_element) {
        case CS0 | Q931_IE_BEARER_CAPABILITY:
        case CS0 | Q931_IE_LOW_LAYER_COMPAT:
          if (q931_tree != NULL) {
            dissect_q931_bearer_capability_ie(tvb, offset + 2, info_element_len,
                                              ie_tree);
          }
          break;
        case CS0 | Q931_IE_CAUSE:
          dissect_q931_cause_ie_unsafe(tvb, offset + 2, info_element_len,
                                       ie_tree, hf_q931_cause_value, &dummy,
                                       q931_info_element_vals0);
          break;
        case CS0 | Q931_IE_CHANGE_STATUS:
          if (q931_tree != NULL) {
            dissect_q931_change_status_ie(tvb, offset + 2, info_element_len,
                                          ie_tree);
          }
          break;
        case CS0 | Q931_IE_CALL_STATE:
          if (q931_tree != NULL) {
            dissect_q931_call_state_ie(tvb, offset + 2, info_element_len,
                                       ie_tree);
          }
          break;
        case CS0 | Q931_IE_CHANNEL_IDENTIFICATION:
          if (q931_tree != NULL) {
            dissect_q931_channel_identification_ie(tvb, offset + 2,
                                                   info_element_len, ie_tree);
          }
          break;
        case CS0 | Q931_IE_PROGRESS_INDICATOR:
          if (q931_tree != NULL) {
            dissect_q931_progress_indicator_ie(tvb, offset + 2,
                                               info_element_len, ie_tree);
          }
          break;
        case CS0 | Q931_IE_NETWORK_SPECIFIC_FACIL:
        case CS0 | Q931_IE_TRANSIT_NETWORK_SEL:
          if (q931_tree != NULL) {
            dissect_q931_ns_facilities_ie(tvb, offset + 2, info_element_len,
                                          ie_tree);
          }
          break;
        case CS0 | Q931_IE_NOTIFICATION_INDICATOR:
          if (q931_tree != NULL) {
            dissect_q931_notification_indicator_ie(tvb, offset + 2,
                                                   info_element_len, ie_tree);
          }
          break;
        case CS0 | Q931_IE_DISPLAY:
          if (q931_tree != NULL) {
            dissect_q931_ia5_ie(tvb, offset + 2, info_element_len, ie_tree,
                                hf_q931_display_information);
          }
          break;
        case CS0 | Q931_IE_DATE_TIME:
          dissect_q931_date_time_ie(tvb, pinfo, offset + 2, info_element_len,
                                    ie_tree);
          break;
        case CS0 | Q931_IE_KEYPAD_FACILITY:
          if (q931_tree != NULL) {
            dissect_q931_ia5_ie(tvb, offset + 2, info_element_len, ie_tree,
                                hf_q931_keypad_facility);
          }
          break;
        case CS0 | Q931_IE_SIGNAL:
          dissect_q931_signal_ie(tvb, pinfo, offset + 2, info_element_len,
                                 ie_tree, ti);
          break;
        case CS0 | Q931_IE_INFORMATION_RATE:
          dissect_q931_information_rate_ie(tvb, pinfo, offset + 2,
                                           info_element_len, ie_tree, ti);
          break;
        case CS0 | Q931_IE_E2E_TRANSIT_DELAY:
          dissect_q931_e2e_transit_delay_ie(tvb, pinfo, offset + 2,
                                            info_element_len, ie_tree, ti);
          break;
        case CS0 | Q931_IE_TD_SELECTION_AND_INT:
          dissect_q931_td_selection_and_int_ie(tvb, pinfo, offset + 2,
                                               info_element_len, ie_tree, ti);
          break;
        case CS0 | Q931_IE_PL_BINARY_PARAMETERS:
          if (q931_tree != NULL) {
            dissect_q931_pl_binary_parameters_ie(tvb, offset + 2,
                                                 info_element_len, ie_tree);
          }
          break;
        case CS0 | Q931_IE_PL_WINDOW_SIZE:
          if (q931_tree != NULL) {
            dissect_q931_pl_window_size_ie(tvb, offset + 2, info_element_len,
                                           ie_tree);
          }
          break;
        case CS0 | Q931_IE_PACKET_SIZE:
          if (q931_tree != NULL) {
            dissect_q931_packet_size_ie(tvb, offset + 2, info_element_len,
                                        ie_tree);
          }
          break;
        case CS0 | Q931_IE_CUG:
          if (q931_tree != NULL) {
            dissect_q931_cug_ie(tvb, offset + 2, info_element_len, ie_tree);
          }
          break;
        case CS0 | Q931_IE_REVERSE_CHARGE_IND:
          if (q931_tree != NULL) {
            dissect_q931_reverse_charge_ind_ie(tvb, offset + 2,
                                               info_element_len, ie_tree);
          }
          break;
        case CS0 | Q931_IE_CONNECTED_NUMBER_DEFAULT:
          if (q931_tree != NULL) {
            dissect_q931_number_ie(tvb, offset + 2, info_element_len, ie_tree,
                                   hf_q931_connected_number, e164_info);
          }
          break;
        case CS0 | Q931_IE_CALLING_PARTY_NUMBER:
          e164_info.e164_number_type = CALLING_PARTY_NUMBER;
          dissect_q931_number_ie(tvb, offset + 2, info_element_len, ie_tree,
                                 hf_q931_calling_party_number, e164_info);
          break;
        case CS0 | Q931_IE_CALLED_PARTY_NUMBER:
          e164_info.e164_number_type = CALLED_PARTY_NUMBER;
          dissect_q931_number_ie(tvb, offset + 2, info_element_len, ie_tree,
                                 hf_q931_called_party_number, e164_info);
          break;
        case CS0 | Q931_IE_CALLING_PARTY_SUBADDR:
        case CS0 | Q931_IE_CALLED_PARTY_SUBADDR:
          if (q931_tree != NULL) {
            dissect_q931_party_subaddr_ie(tvb, offset + 2, info_element_len,
                                          ie_tree);
          }
          break;
        case CS0 | Q931_IE_REDIRECTING_NUMBER:
          if (q931_tree != NULL) {
            dissect_q931_number_ie(tvb, offset + 2, info_element_len, ie_tree,
                                   hf_q931_redirecting_number, e164_info);
          }
          break;
        case CS0 | Q931_IE_RESTART_INDICATOR:
          dissect_q931_restart_indicator_ie(tvb, pinfo, offset + 2,
                                            info_element_len, ie_tree, ti);
          break;
        case CS0 | Q931_IE_HIGH_LAYER_COMPAT:
          if (q931_tree != NULL) {
            dissect_q931_high_layer_compat_ie(tvb, offset + 2, info_element_len,
                                              ie_tree);
          }
          break;
        case CS0 | Q931_IE_USER_USER:
          if (q931_tree != NULL) {
            dissect_q931_user_user_ie(tvb, pinfo, offset + 2, info_element_len,
                                      ie_tree);
          }
          break;
        case CS5 | Q931_IE_PARTY_CATEGORY:
          if (q931_tree != NULL) {
            dissect_q931_party_category_ie(tvb, offset + 2, info_element_len,
                                           ie_tree);
          }
          break;
        case CS6 | Q931_IE_DISPLAY:
          if (q931_tree != NULL) {
            dissect_q931_ia5_ie(tvb, offset + 2, info_element_len, ie_tree,
                                hf_q931_avaya_display);
          }
          break;
        default:
          if (q931_tree != NULL) {
            proto_tree_add_item(ie_tree, hf_q931_data, tvb, offset + 2,
                                info_element_len, ENC_NA);
          }
          break;
        }
      }
      offset += 1 + 1 + info_element_len;
    }
    codeset = locked_codeset;
  }
  if (have_valid_q931_pi) {
    tap_queue_packet(q931_tap, pinfo, q931_pi);
  }
  have_valid_q931_pi = FALSE;
}

static int pxa2xx_i2c_rx(I2CSlave *i2c) {
  PXA2xxI2CSlaveState *slave = FROM_I2C_SLAVE(PXA2xxI2CSlaveState, i2c);
  PXA2xxI2CState *s = slave->host;
  if ((s->control & (1 << 14)) || !(s->control & (1 << 6)))
    return 0;
  if (s->status & (1 << 0)) {
    s->status |= 1 << 6;
  }
  pxa2xx_i2c_update(s);
  return s->data;
}

