static ssize_t virtio_net_receive(VLANClientState *nc, const uint8_t *buf,
                                  size_t size) {
  VirtIONet *n = DO_UPCAST(NICState, nc, nc)->opaque;
  struct virtio_net_hdr_mrg_rxbuf *mhdr = NULL;
  size_t guest_hdr_len, offset, i, host_hdr_len;
  if (!virtio_net_can_receive(&n->nic->nc))
    return -1;
  guest_hdr_len = n->mergeable_rx_bufs ? sizeof(struct virtio_net_hdr_mrg_rxbuf)
                                       : sizeof(struct virtio_net_hdr);
  host_hdr_len = n->has_vnet_hdr ? sizeof(struct virtio_net_hdr) : 0;
  if (!virtio_net_has_buffers(n, size + guest_hdr_len - host_hdr_len))
    return 0;
  if (!receive_filter(n, buf, size))
    return size;
  offset = i = 0;
  while (offset < size) {
    VirtQueueElement elem;
    int len, total;
    struct iovec sg[VIRTQUEUE_MAX_SIZE];
    total = 0;
    if (virtqueue_pop(n->rx_vq, &elem) == 0) {
      if (i == 0)
        return -1;
      error_report("virtio-net unexpected empty queue: "
                   "i %zd mergeable %d offset %zd, size %zd, "
                   "guest hdr len %zd, host hdr len %zd guest features 0x%x",
                   i, n->mergeable_rx_bufs, offset, size, guest_hdr_len,
                   host_hdr_len, n->vdev.guest_features);
      exit(1);
    }
    if (elem.in_num < 1) {
      error_report("virtio-net receive queue contains no in buffers");
      exit(1);
    }
    if (!n->mergeable_rx_bufs && elem.in_sg[0].iov_len != guest_hdr_len) {
      error_report("virtio-net header not in first element");
      exit(1);
    }
    memcpy(&sg, &elem.in_sg[0], sizeof(sg[0]) * elem.in_num);
    if (i == 0) {
      if (n->mergeable_rx_bufs)
        mhdr = (struct virtio_net_hdr_mrg_rxbuf *)sg[0].iov_base;
      offset += receive_header(n, sg, elem.in_num, buf + offset, size - offset,
                               guest_hdr_len);
      total += guest_hdr_len;
    }
    len = iov_from_buf(sg, elem.in_num, 0, buf + offset, size - offset);
    total += len;
    offset += len;
    if (!n->mergeable_rx_bufs && offset < size) {
#if 0 error_report("virtio-net truncated non-mergeable packet: "               \
                   "i %zd mergeable %d offset %zd, size %zd, "                 \
                   "guest hdr len %zd, host hdr len %zd",                      \
                   i, n->mergeable_rx_bufs, offset, size, guest_hdr_len,       \
                   host_hdr_len);
#endif return size;
    }
    virtqueue_fill(n->rx_vq, &elem, total, i++);
  }
  if (mhdr) {
    stw_p(&mhdr->num_buffers, i);
  }
  virtqueue_flush(n->rx_vq, i);
  virtio_notify(&n->vdev, n->rx_vq);
  return size;
}

static void dissect_rsvp_association(proto_tree *ti,
                                     proto_tree *rsvp_object_tree,
                                     tvbuff_t *tvb, int offset, int obj_length,
                                     int rsvp_class _U_, int type) {
  guint16 association_type;
  guint16 association_id;
  proto_item_set_text(ti, "ASSOCIATION ");
  association_type = tvb_get_ntohs(tvb, offset + 4);
  association_id = tvb_get_ntohs(tvb, offset + 6);
  switch (type) {
  case 1:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "1 (IPv4)");
    proto_item_append_text(ti, "(IPv4): ");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_type, tvb,
                        offset + 4, 2, ENC_BIG_ENDIAN);
    proto_item_append_text(
        ti, "%s. ",
        val_to_str(association_type, association_type_vals, "Unknown (%u)"));
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_id, tvb,
                        offset + 6, 2, ENC_BIG_ENDIAN);
    proto_item_append_text(ti, "ID: %u. ", association_id);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_source_ipv4, tvb,
                        offset + 8, 4, ENC_BIG_ENDIAN);
    proto_item_append_text(ti, "Src: %s", tvb_ip_to_str(tvb, offset + 8));
    break;
  case 2:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "2 (IPv6)");
    proto_item_append_text(ti, "(IPv6): ");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_type, tvb,
                        offset + 4, 2, ENC_BIG_ENDIAN);
    proto_item_append_text(
        ti, "%s. ",
        val_to_str(association_type, association_type_vals, "Unknown (%u)"));
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_id, tvb,
                        offset + 6, 2, ENC_BIG_ENDIAN);
    proto_item_append_text(ti, "ID: %u. ", association_id);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_source_ipv6, tvb,
                        offset + 8, 16, ENC_NA);
    proto_item_append_text(ti, "Src: %s", tvb_ip6_to_str(tvb, offset + 8));
    break;
  case 4:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "4 (Routing Area)");
    proto_item_append_text(ti, "(Routing Area): ");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_type, tvb,
                        offset + 4, 2, ENC_BIG_ENDIAN);
    proto_item_append_text(
        ti, "%s. ",
        val_to_str(association_type, association_type_vals, "Unknown (%u)"));
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_id, tvb,
                        offset + 6, 2, ENC_BIG_ENDIAN);
    proto_item_append_text(ti, "Association ID: %u, ", association_id);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_routing_area_id,
                        tvb, offset + 8, 4, ENC_BIG_ENDIAN);
    proto_item_append_text(ti, "Routing Area ID: %u, ",
                           tvb_get_ntohl(tvb, offset + 8));
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_node_id, tvb,
                        offset + 12, 4, ENC_BIG_ENDIAN);
    proto_item_append_text(ti, "Node ID: %s", tvb_ip_to_str(tvb, offset + 12));
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_padding, tvb,
                        offset + 8, 16, ENC_NA);
    break;
  default:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "Unknown (%u)", type);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_association_data, tvb,
                        offset + 4, obj_length - 4, ENC_NA);
    break;
  }
}

static cmsBool SaveDescription(struct _cms_typehandler_struct *self,
                               cmsIOHANDLER *io, cmsMLU *Text) {
  if (self->ICCVersion < 0x4000000) {
    if (!_cmsWriteTypeBase(io, cmsSigTextDescriptionType))
      return FALSE;
    return Type_Text_Description_Write(self, io, Text, 1);
  } else {
    if (!_cmsWriteTypeBase(io, cmsSigMultiLocalizedUnicodeType))
      return FALSE;
    return Type_MLU_Write(self, io, Text, 1);
  }
}

int32 get_attavgwidth(Oid relid, AttrNumber attnum) {
  HeapTuple tp;
  int32 stawidth;
  if (get_attavgwidth_hook) {
    stawidth = (*get_attavgwidth_hook)(relid, attnum);
    if (stawidth > 0)
      return stawidth;
  }
  tp = SearchSysCache3(STATRELATTINH, ObjectIdGetDatum(relid),
                       Int16GetDatum(attnum), BoolGetDatum(false));
  if (HeapTupleIsValid(tp)) {
    stawidth = ((Form_pg_statistic)GETSTRUCT(tp))->stawidth;
    ReleaseSysCache(tp);
    if (stawidth > 0)
      return stawidth;
  }
  return 0;
}

