static void f_parser(lua_State *L, void *ud) {
  int i;
  Proto *tf;
  Closure *cl;
  struct SParser *p = cast(struct SParser *, ud);
  int c = luaZ_lookahead(p->z);
  luaC_checkGC(L);
  tf = (luaY_parser)(L, p->z, &p->buff, p->name);
  cl = luaF_newLclosure(L, tf->nups, hvalue(gt(L)));
  cl->l.p = tf;
  for (i = 0; i < tf->nups; i++)
    cl->l.upvals[i] = luaF_newupval(L);
  setclvalue(L, L->top, cl);
  incr_top(L);
}

static USBDevice *ohci_find_device(OHCIState *ohci, uint8_t addr) {
  USBDevice *dev;
  int i;
  for (i = 0; i < ohci->num_ports; i++) {
    if ((ohci->rhport[i].ctrl & OHCI_PORT_PES) == 0) {
      continue;
    }
    dev = usb_find_device(&ohci->rhport[i].port, addr);
    if (dev != NULL) {
      return dev;
    }
  }
  return NULL;
}

static inline int svq3_mc_dir(SVQ3Context *s, int size, int mode, int dir,
                              int avg) {
  int i, j, k, mx, my, dx, dy, x, y;
  H264Context *h = &s->h;
  const int part_width = ((size & 5) == 4) ? 4 : 16 >> (size & 1);
  const int part_height = 16 >> ((unsigned)(size + 1) / 3);
  const int extra_width = (mode == PREDICT_MODE) ? -16 * 6 : 0;
  const int h_edge_pos = 6 * (s->h_edge_pos - part_width) - extra_width;
  const int v_edge_pos = 6 * (s->v_edge_pos - part_height) - extra_width;
  for (i = 0; i < 16; i += part_height)
    for (j = 0; j < 16; j += part_width) {
      const int b_xy =
          (4 * h->mb_x + (j >> 2)) + (4 * h->mb_y + (i >> 2)) * h->b_stride;
      int dxy;
      x = 16 * h->mb_x + j;
      y = 16 * h->mb_y + i;
      k = (j >> 2 & 1) + (i >> 1 & 2) + (j >> 1 & 4) + (i & 8);
      if (mode != PREDICT_MODE) {
        pred_motion(h, k, part_width >> 2, dir, 1, &mx, &my);
      } else {
        mx = s->next_pic->motion_val[0][b_xy][0] << 1;
        my = s->next_pic->motion_val[0][b_xy][1] << 1;
        if (dir == 0) {
          mx = mx * h->frame_num_offset / h->prev_frame_num_offset + 1 >> 1;
          my = my * h->frame_num_offset / h->prev_frame_num_offset + 1 >> 1;
        } else {
          mx = mx * (h->frame_num_offset - h->prev_frame_num_offset) /
                       h->prev_frame_num_offset +
                   1 >>
               1;
          my = my * (h->frame_num_offset - h->prev_frame_num_offset) /
                       h->prev_frame_num_offset +
                   1 >>
               1;
        }
      }
      mx = av_clip(mx, extra_width - 6 * x, h_edge_pos - 6 * x);
      my = av_clip(my, extra_width - 6 * y, v_edge_pos - 6 * y);
      if (mode == PREDICT_MODE) {
        dx = dy = 0;
      } else {
        dy = svq3_get_se_golomb(&h->gb);
        dx = svq3_get_se_golomb(&h->gb);
        if (dx == INVALID_VLC || dy == INVALID_VLC) {
          av_log(h->avctx, AV_LOG_ERROR, "invalid MV vlc\n");
          return -1;
        }
      }
      if (mode == THIRDPEL_MODE) {
        int fx, fy;
        mx = (mx + 1 >> 1) + dx;
        my = (my + 1 >> 1) + dy;
        fx = (unsigned)(mx + 0x3000) / 3 - 0x1000;
        fy = (unsigned)(my + 0x3000) / 3 - 0x1000;
        dxy = (mx - 3 * fx) + 4 * (my - 3 * fy);
        svq3_mc_dir_part(s, x, y, part_width, part_height, fx, fy, dxy, 1, dir,
                         avg);
        mx += mx;
        my += my;
      } else if (mode == HALFPEL_MODE || mode == PREDICT_MODE) {
        mx = (unsigned)(mx + 1 + 0x3000) / 3 + dx - 0x1000;
        my = (unsigned)(my + 1 + 0x3000) / 3 + dy - 0x1000;
        dxy = (mx & 1) + 2 * (my & 1);
        svq3_mc_dir_part(s, x, y, part_width, part_height, mx >> 1, my >> 1,
                         dxy, 0, dir, avg);
        mx *= 3;
        my *= 3;
      } else {
        mx = (unsigned)(mx + 3 + 0x6000) / 6 + dx - 0x1000;
        my = (unsigned)(my + 3 + 0x6000) / 6 + dy - 0x1000;
        svq3_mc_dir_part(s, x, y, part_width, part_height, mx, my, 0, 0, dir,
                         avg);
        mx *= 6;
        my *= 6;
      }
      if (mode != PREDICT_MODE) {
        int32_t mv = pack16to32(mx, my);
        if (part_height == 8 && i < 8) {
          AV_WN32A(h->mv_cache[dir][scan8[k] + 1 * 8], mv);
          if (part_width == 8 && j < 8)
            AV_WN32A(h->mv_cache[dir][scan8[k] + 1 + 1 * 8], mv);
        }
        if (part_width == 8 && j < 8)
          AV_WN32A(h->mv_cache[dir][scan8[k] + 1], mv);
        if (part_width == 4 || part_height == 4)
          AV_WN32A(h->mv_cache[dir][scan8[k]], mv);
      }
      fill_rectangle(h->cur_pic.motion_val[dir][b_xy], part_width >> 2,
                     part_height >> 2, h->b_stride, pack16to32(mx, my), 4);
    }
  return 0;
}

static void basic_ec_math_simplified(void) {
  gpg_error_t err;
  gcry_ctx_t ctx;
  gcry_mpi_point_t G, Q;
  gcry_mpi_t d;
  gcry_mpi_t x, y, z;
  gcry_sexp_t sexp;
  wherestr = "basic_ec_math_simplified";
  show("checking basic math functions for EC (variant)\n");
  d = hex2mpi("D4EF27E32F8AD8E2A1C6DDEBB1D235A69E3CEF9BCE90273D");
  Q = gcry_mpi_point_new(0);
  err = gcry_mpi_ec_new(&ctx, NULL, "NIST P-192");
  if (err)
    die("gcry_mpi_ec_new failed: %s\n", gpg_strerror(err));
  G = gcry_mpi_ec_get_point("g", ctx, 1);
  if (!G)
    die("gcry_mpi_ec_get_point(G) failed\n");
  gcry_mpi_ec_mul(Q, d, G, ctx);
  x = gcry_mpi_new(0);
  y = gcry_mpi_new(0);
  z = gcry_mpi_new(0);
  gcry_mpi_point_get(x, y, z, Q);
  if (cmp_mpihex(x, "222D9EC717C89D047E0898C9185B033CD11C0A981EE6DC66") ||
      cmp_mpihex(y, "605DE0A82D70D3E0F84A127D0739ED33D657DF0D054BFDE8") ||
      cmp_mpihex(z, "00B06B519071BC536999AC8F2D3934B3C1FC9EACCD0A31F88F"))
    fail("computed public key does not match\n");
  if (debug) {
    print_mpi("Q.x", x);
    print_mpi("Q.y", y);
    print_mpi("Q.z", z);
  }
  if (gcry_mpi_ec_get_affine(x, y, Q, ctx))
    fail("failed to get affine coordinates\n");
  if (cmp_mpihex(x, "008532093BA023F4D55C0424FA3AF9367E05F309DC34CDC3FE") ||
      cmp_mpihex(y, "00C13CA9E617C6C8487BFF6A726E3C4F277913D97117939966"))
    fail("computed affine coordinates of public key do not match\n");
  if (debug) {
    print_mpi("q.x", x);
    print_mpi("q.y", y);
  }
  gcry_mpi_release(z);
  gcry_mpi_release(y);
  gcry_mpi_release(x);
  err = gcry_mpi_ec_set_point("g", G, ctx);
  if (err)
    die("gcry_mpi_ec_set_point(G) failed\n");
  err = gcry_mpi_ec_set_mpi("d", d, ctx);
  if (err)
    die("gcry_mpi_ec_set_mpi(d) failed\n");
  err = gcry_pubkey_get_sexp(&sexp, 0, ctx);
  if (err)
    fail("gcry_pubkey_get_sexp(0) failed: %s\n", gpg_strerror(err));
  else if (verbose)
    print_sexp("Result of gcry_pubkey_get_sexp (0):\n", sexp);
  gcry_sexp_release(sexp);
  err = gcry_pubkey_get_sexp(&sexp, GCRY_PK_GET_PUBKEY, ctx);
  if (err)
    fail("gcry_pubkey_get_sexp(GET_PUBKEY) failed: %s\n", gpg_strerror(err));
  else if (verbose)
    print_sexp("Result of gcry_pubkey_get_sexp (GET_PUBKEY):\n", sexp);
  gcry_sexp_release(sexp);
  err = gcry_mpi_ec_set_mpi("d", NULL, ctx);
  if (err)
    die("gcry_mpi_ec_set_mpi(d=NULL) failed\n");
  err = gcry_pubkey_get_sexp(&sexp, 0, ctx);
  if (err)
    fail("gcry_pubkey_get_sexp(0 w/o d) failed: %s\n", gpg_strerror(err));
  else if (verbose)
    print_sexp("Result of gcry_pubkey_get_sexp (0 w/o d):\n", sexp);
  gcry_sexp_release(sexp);
  err = gcry_pubkey_get_sexp(&sexp, GCRY_PK_GET_SECKEY, ctx);
  if (gpg_err_code(err) != GPG_ERR_NO_SECKEY)
    fail("gcry_pubkey_get_sexp(GET_SECKEY) returned wrong error: %s\n",
         gpg_strerror(err));
  gcry_sexp_release(sexp);
  err = gcry_mpi_ec_set_point("q", NULL, ctx);
  if (err)
    die("gcry_mpi_ec_set_point(q=NULL) failed\n");
  err = gcry_pubkey_get_sexp(&sexp, 0, ctx);
  if (gpg_err_code(err) != GPG_ERR_BAD_CRYPT_CTX)
    fail("gcry_pubkey_get_sexp(0 w/o Q,d) returned wrong error: %s\n",
         gpg_strerror(err));
  gcry_sexp_release(sexp);
  gcry_mpi_point_release(Q);
  gcry_mpi_release(d);
  gcry_mpi_point_release(G);
  gcry_ctx_release(ctx);
}

static void decode_pitch_lag_high(int *lag_int, int *lag_frac, int pitch_index,
                                  uint8_t *base_lag_int, int subframe) {
  if (subframe == 0 || subframe == 2) {
    if (pitch_index < 376) {
      *lag_int = (pitch_index + 137) >> 2;
      *lag_frac = pitch_index - (*lag_int << 2) + 136;
    } else if (pitch_index < 440) {
      *lag_int = (pitch_index + 257 - 376) >> 1;
      *lag_frac = (pitch_index - (*lag_int << 1) + 256 - 376) << 1;
    } else {
      *lag_int = pitch_index - 280;
      *lag_frac = 0;
    }
    *base_lag_int = av_clip(*lag_int - 8 - (*lag_frac < 0), AMRWB_P_DELAY_MIN,
                            AMRWB_P_DELAY_MAX - 15);
  } else {
    *lag_int = (pitch_index + 1) >> 2;
    *lag_frac = pitch_index - (*lag_int << 2);
    *lag_int += *base_lag_int;
  }
}

static int virtio_net_init_pci(PCIDevice *pci_dev) {
