static int lag_decode_zero_run_line(LagarithContext *l, uint8_t *dst,
                                    const uint8_t *src, const uint8_t *src_end,
                                    int width, int esc_count) {
  int i = 0;
  int count;
  uint8_t zero_run = 0;
  const uint8_t *src_start = src;
