      av_log(l->avctx, AV_LOG_ERROR, "Too many zeros remaining.\n");
      return AVERROR_INVALIDDATA;
    }
    memset(dst, 0, count);
    l->zeros_rem -= count;
    dst += count;
  }
  while (dst < end) {
    i = 0;
    while (!zero_run && dst + i < end) {
      i++;
      if (src + i >= src_end)
        return AVERROR_INVALIDDATA;
      zero_run = !(src[i] | (src[i + 1] & mask1) | (src[i + 2] & mask2));
    }
    if (zero_run) {
      zero_run = 0;
      i += esc_count;
      memcpy(dst, src, i);
      dst += i;
      l->zeros_rem = lag_calc_zero_run(src[i]);
      src += i + 1;
      goto output_zeros;
    } else {
      memcpy(dst, src, i);
      src += i;
      dst += i;
    }
  }
  return src_start - src;
}

