static uint64_t pxa2xx_i2s_read(void *opaque, hwaddr addr, unsigned size) {
  PXA2xxI2SState *s = (PXA2xxI2SState *)opaque;
  switch (addr) {
  case SACR0:
    return s->control[0];
  case SACR1:
    return s->control[1];
  case SASR0:
    return s->status;
  case SAIMR:
    return s->mask;
  case SAICR:
    return 0;
  case SADIV:
    return s->clk;
  case SADR:
    if (s->rx_len > 0) {
      s->rx_len--;
      pxa2xx_i2s_update(s);
      return s->codec_in(s->opaque);
    }
    return 0;
  default:
    printf("%s: Bad register " REG_FMT "\n", __FUNCTION__, addr);
    break;
  }
  return 0;
}

static void NVRAM_set_crc(m48t59_t *nvram, uint32_t addr, uint32_t start,
                          uint32_t count) {
  uint32_t i;
  uint16_t crc = 0xFFFF;
  int odd = 0;
  if (count & 1)
    odd = 1;
  count &= ~1;
  for (i = 0; i != count; i++) {
    crc = NVRAM_crc_update(crc, NVRAM_get_word(nvram, start + i));
  }
  if (odd) {
    crc = NVRAM_crc_update(crc, NVRAM_get_byte(nvram, start + i) << 8);
  }
  NVRAM_set_word(nvram, addr, crc);
}

static int dissect_SPOOL_PRINTER_INFO(tvbuff_t *tvb, int offset,
                                      packet_info *pinfo, proto_tree *tree,
                                      dcerpc_info *di, guint8 *drep) {
  proto_tree *subtree;
  guint32 level;
  proto_tree *item;
  subtree =
      proto_tree_add_subtree(tree, tvb, offset, 0, ett_SPOOL_PRINTER_INFO_LEVEL,
                             &item, "Spool printer info level");
  offset = dissect_ndr_uint32(tvb, offset, pinfo, subtree, di, drep, hf_level,
                              &level);
  switch (level) {
  case 3: {
    guint32 devmode_ptr, secdesc_ptr;
    offset =
        dissect_ndr_uint32(tvb, offset, pinfo, subtree, di, drep,
                           hf_spool_printer_info_devmode_ptr, &devmode_ptr);
    offset =
        dissect_ndr_uint32(tvb, offset, pinfo, subtree, di, drep,
                           hf_spool_printer_info_secdesc_ptr, &secdesc_ptr);
    if (devmode_ptr)
      offset = dissect_DEVMODE_CTR(tvb, offset, pinfo, subtree, di, drep);
    if (secdesc_ptr)
      offset = dissect_SEC_DESC_BUF(tvb, offset, pinfo, subtree, di, drep);
