}

static int slice_decode_thread(AVCodecContext *c, void *arg) {
  MpegEncContext *s = *(void **)arg;
  const uint8_t *buf = s->gb.buffer;
  int mb_y = s->start_mb_y;
  const int field_pic = s->picture_structure != PICT_FRAME;
  s->er.error_count =
      (3 * (s->end_mb_y - s->start_mb_y) * s->mb_width) >> field_pic;
  for (;;) {
    uint32_t start_code;
    int ret;
    ret = mpeg_decode_slice(s, mb_y, &buf, s->gb.buffer_end - buf);
    emms_c();
    av_dlog(c, "ret:%d resync:%d/%d mb:%d/%d ts:%d/%d ec:%d\n", ret,
            s->resync_mb_x, s->resync_mb_y, s->mb_x, s->mb_y, s->start_mb_y,
            s->end_mb_y, s->er.error_count);
    if (ret < 0) {
      if (c->err_recognition & AV_EF_EXPLODE)
        return ret;
      if (s->resync_mb_x >= 0 && s->resync_mb_y >= 0)
        ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x,
                        s->mb_y, ER_AC_ERROR | ER_DC_ERROR | ER_MV_ERROR);
    } else {
      ff_er_add_slice(&s->er, s->resync_mb_x, s->resync_mb_y, s->mb_x - 1,
                      s->mb_y, ER_AC_END | ER_DC_END | ER_MV_END);
    }
    if (s->mb_y == s->end_mb_y)
      return 0;
    start_code = -1;
    buf = avpriv_mpv_find_start_code(buf, s->gb.buffer_end, &start_code);
    mb_y = (start_code - SLICE_MIN_START_CODE) << field_pic;
    if (s->picture_structure == PICT_BOTTOM_FIELD)
      mb_y++;
    if (mb_y < 0 || mb_y >= s->end_mb_y)
      return -1;
  }
}

static int zrsdparams(i_ctx_t *i_ctx_p) {
  os_ptr op = osp;
  ref *pFilter;
  ref *pDecodeParms;
  int Intent = 0;
  bool AsyncRead;
  ref empty_array, filter1_array, parms1_array;
  uint i;
  int code;
  make_empty_array(&empty_array, a_readonly);
  if (dict_find_string(op, "Filter", &pFilter) > 0) {
    if (!r_is_array(pFilter)) {
      if (!r_has_type(pFilter, t_name))
        return_error(gs_error_typecheck);
      make_array(&filter1_array, a_readonly, 1, pFilter);
      pFilter = &filter1_array;
    }
  } else
    pFilter = &empty_array;
  if (pFilter != &empty_array &&
      dict_find_string(op, "DecodeParms", &pDecodeParms) > 0) {
    if (pFilter == &filter1_array) {
      make_array(&parms1_array, a_readonly, 1, pDecodeParms);
      pDecodeParms = &parms1_array;
    } else if (!r_is_array(pDecodeParms))
      return_error(gs_error_typecheck);
    else if (r_size(pFilter) != r_size(pDecodeParms))
      return_error(gs_error_rangecheck);
  } else
    pDecodeParms = 0;
  for (i = 0; i < r_size(pFilter); ++i) {
    ref f, fname, dp;
    array_get(imemory, pFilter, (long)i, &f);
    if (!r_has_type(&f, t_name))
      return_error(gs_error_typecheck);
    name_string_ref(imemory, &f, &fname);
    if (r_size(&fname) < 6 ||
        memcmp(fname.value.bytes + r_size(&fname) - 6, "Decode", 6))
      return_error(gs_error_rangecheck);
    if (pDecodeParms) {
      array_get(imemory, pDecodeParms, (long)i, &dp);
      if (!(r_has_type(&dp, t_dictionary) || r_has_type(&dp, t_null)))
        return_error(gs_error_typecheck);
    }
  }
  code = dict_int_param(op, "Intent", 0, 3, 0, &Intent);
  if (code < 0 && code != gs_error_rangecheck)
    return code;
  if ((code = dict_bool_param(op, "AsyncRead", false, &AsyncRead)) < 0)
    return code;
  push(1);
  op[-1] = *pFilter;
  if (pDecodeParms)
    *op = *pDecodeParms;
  else
    make_null(op);
  return 0;
}

