static int isoent_traverse_tree(struct archive_write *a, struct vdd *vdd) {
  struct iso9660 *iso9660 = a->format_data;
  struct isoent *np;
  struct idr idr;
  int depth;
  int r;
  int (*genid)(struct archive_write *, struct isoent *, struct idr *);
  idr_init(iso9660, vdd, &idr);
  np = vdd->rootent;
  depth = 0;
  if (vdd->vdd_type == VDD_JOLIET)
    genid = isoent_gen_joliet_identifier;
  else
    genid = isoent_gen_iso9660_identifier;
  do {
    if (np->virtual && !archive_entry_mtime_is_set(np->file->entry)) {
      archive_entry_set_mtime(np->file->entry, iso9660->birth_time, 0);
      archive_entry_set_atime(np->file->entry, iso9660->birth_time, 0);
      archive_entry_set_ctime(np->file->entry, iso9660->birth_time, 0);
    }
    if (np->children.first != NULL) {
      if (vdd->vdd_type != VDD_JOLIET && !iso9660->opt.rr &&
          depth + 1 >= vdd->max_depth) {
        if (np->children.cnt > 0)
          iso9660->directories_too_deep = np;
      } else {
        r = genid(a, np, &idr);
        if (r < 0)
          goto exit_traverse_tree;
        r = isoent_make_sorted_files(a, np, &idr);
        if (r < 0)
          goto exit_traverse_tree;
        if (np->subdirs.first != NULL && depth + 1 < vdd->max_depth) {
          np = np->subdirs.first;
          depth++;
          continue;
        }
      }
    }
    while (np != np->parent) {
      if (np->drnext == NULL) {
        np = np->parent;
        depth--;
      } else {
        np = np->drnext;
        break;
      }
    }
  } while (np != np->parent);
  r = ARCHIVE_OK;
exit_traverse_tree:
  idr_cleanup(&idr);
  return (r);
}

