static int ogg_read_packet(AVFormatContext *s, AVPacket *pkt) {
  struct ogg *ogg;
  struct ogg_stream *os;
  int idx, ret;
  int pstart, psize;
  int64_t fpos, pts, dts;
  if (s->io_repositioned) {
    ogg_reset(s);
    s->io_repositioned = 0;
  }
retry:
  do {
    ret = ogg_packet(s, &idx, &pstart, &psize, &fpos);
    if (ret < 0)
      return ret;
  } while (idx < 0 || !s->streams[idx]);
  ogg = s->priv_data;
  os = ogg->streams + idx;
  pts = ogg_calc_pts(s, idx, &dts);
  ogg_validate_keyframe(s, idx, pstart, psize);
  if (os->keyframe_seek && !(os->pflags & AV_PKT_FLAG_KEY))
    goto retry;
  os->keyframe_seek = 0;
  ret = av_new_packet(pkt, psize);
  if (ret < 0)
    return ret;
  pkt->stream_index = idx;
  memcpy(pkt->data, os->buf + pstart, psize);
  pkt->pts = pts;
  pkt->dts = dts;
  pkt->flags = os->pflags;
  pkt->duration = os->pduration;
  pkt->pos = fpos;
  if (os->end_trimming) {
    uint8_t *side_data =
        av_packet_new_side_data(pkt, AV_PKT_DATA_SKIP_SAMPLES, 10);
    if (!side_data)
      goto fail;
    AV_WL32(side_data + 4, os->end_trimming);
    os->end_trimming = 0;
  }
  if (os->new_metadata) {
    uint8_t *side_data = av_packet_new_side_data(
        pkt, AV_PKT_DATA_METADATA_UPDATE, os->new_metadata_size);
    if (!side_data)
      goto fail;
    memcpy(side_data, os->new_metadata, os->new_metadata_size);
    av_freep(&os->new_metadata);
    os->new_metadata_size = 0;
  }
  return psize;
fail:
  av_packet_unref(pkt);
  return AVERROR(ENOMEM);
}

static int ivr_read_header(AVFormatContext *s) {
  unsigned tag, type, len, tlen, value;
  int i, j, n, count, nb_streams = 0, ret;
  uint8_t key[256], val[256];
  AVIOContext *pb = s->pb;
  AVStream *st;
  int64_t pos, offset, temp;
  pos = avio_tell(pb);
  tag = avio_rl32(pb);
  if (tag == MKTAG('.', 'R', '1', 'M')) {
    if (avio_rb16(pb) != 1)
      return AVERROR_INVALIDDATA;
    if (avio_r8(pb) != 1)
      return AVERROR_INVALIDDATA;
    len = avio_rb32(pb);
    avio_skip(pb, len);
    avio_skip(pb, 5);
    temp = avio_rb64(pb);
    while (!avio_feof(pb) && temp) {
      offset = temp;
      temp = avio_rb64(pb);
    }
    avio_skip(pb, offset - avio_tell(pb));
    if (avio_r8(pb) != 1)
      return AVERROR_INVALIDDATA;
    len = avio_rb32(pb);
    avio_skip(pb, len);
    if (avio_r8(pb) != 2)
      return AVERROR_INVALIDDATA;
    avio_skip(pb, 16);
    pos = avio_tell(pb);
    tag = avio_rl32(pb);
  }
  if (tag != MKTAG('.', 'R', 'E', 'C'))
    return AVERROR_INVALIDDATA;
  if (avio_r8(pb) != 0)
    return AVERROR_INVALIDDATA;
  count = avio_rb32(pb);
  for (i = 0; i < count; i++) {
    if (avio_feof(pb))
      return AVERROR_INVALIDDATA;
    type = avio_r8(pb);
    tlen = avio_rb32(pb);
    avio_get_str(pb, tlen, key, sizeof(key));
    len = avio_rb32(pb);
    if (type == 5) {
      avio_get_str(pb, len, val, sizeof(val));
      av_log(s, AV_LOG_DEBUG, "%s = '%s'\n", key, val);
    } else if (type == 4) {
      av_log(s, AV_LOG_DEBUG, "%s = '0x", key);
      for (j = 0; j < len; j++)
        av_log(s, AV_LOG_DEBUG, "%X", avio_r8(pb));
      av_log(s, AV_LOG_DEBUG, "'\n");
    } else if (len == 4 && type == 3 && !strncmp(key, "StreamCount", tlen)) {
      nb_streams = value = avio_rb32(pb);
    } else if (len == 4 && type == 3) {
      value = avio_rb32(pb);
      av_log(s, AV_LOG_DEBUG, "%s = %d\n", key, value);
    } else {
      av_log(s, AV_LOG_DEBUG, "Skipping unsupported key: %s\n", key);
      avio_skip(pb, len);
    }
  }
  for (n = 0; n < nb_streams; n++) {
    st = avformat_new_stream(s, NULL);
    if (!st)
      return AVERROR(ENOMEM);
    st->priv_data = ff_rm_alloc_rmstream();
    if (!st->priv_data)
      return AVERROR(ENOMEM);
    if (avio_r8(pb) != 1)
      return AVERROR_INVALIDDATA;
    count = avio_rb32(pb);
    for (i = 0; i < count; i++) {
      if (avio_feof(pb))
        return AVERROR_INVALIDDATA;
      type = avio_r8(pb);
      tlen = avio_rb32(pb);
      avio_get_str(pb, tlen, key, sizeof(key));
      len = avio_rb32(pb);
      if (type == 5) {
        avio_get_str(pb, len, val, sizeof(val));
        av_log(s, AV_LOG_DEBUG, "%s = '%s'\n", key, val);
      } else if (type == 4 && !strncmp(key, "OpaqueData", tlen)) {
        ret = ffio_ensure_seekback(pb, 4);
        if (ret < 0)
          return ret;
        if (avio_rb32(pb) == MKBETAG('M', 'L', 'T', 'I')) {
          ret = rm_read_multi(s, pb, st, NULL);
        } else {
          avio_seek(pb, -4, SEEK_CUR);
          ret = ff_rm_read_mdpr_codecdata(s, pb, st, st->priv_data, len, NULL);
        }
        if (ret < 0)
          return ret;
      } else if (type == 4) {
        int j;
        av_log(s, AV_LOG_DEBUG, "%s = '0x", key);
        for (j = 0; j < len; j++)
          av_log(s, AV_LOG_DEBUG, "%X", avio_r8(pb));
        av_log(s, AV_LOG_DEBUG, "'\n");
      } else if (len == 4 && type == 3 && !strncmp(key, "Duration", tlen)) {
        st->duration = avio_rb32(pb);
      } else if (len == 4 && type == 3) {
        value = avio_rb32(pb);
        av_log(s, AV_LOG_DEBUG, "%s = %d\n", key, value);
      } else {
        av_log(s, AV_LOG_DEBUG, "Skipping unsupported key: %s\n", key);
        avio_skip(pb, len);
      }
    }
  }
  if (avio_r8(pb) != 6)
    return AVERROR_INVALIDDATA;
  avio_skip(pb, 12);
  avio_skip(pb, avio_rb64(pb) + pos - avio_tell(s->pb));
  if (avio_r8(pb) != 8)
    return AVERROR_INVALIDDATA;
  avio_skip(pb, 8);
  return 0;
}

static void dumpcfffdselect(SplineFont *sf, struct alltabs *at) {
  int cid, k, lastfd, cnt;
  int gid;
  putc(3, at->fdselect);
  putshort(at->fdselect, 0);
  for (k = 0; k < sf->subfontcnt; ++k)
    if (SCWorthOutputting(sf->subfonts[k]->glyphs[0]))
      break;
  if (k == sf->subfontcnt)
    --k;
  putshort(at->fdselect, 0);
  putc(k, at->fdselect);
  lastfd = k;
  cnt = 1;
  for (gid = 1; gid < at->gi.gcnt; ++gid) {
    cid = at->gi.bygid[gid];
    for (k = 0; k < sf->subfontcnt; ++k) {
      if (cid < sf->subfonts[k]->glyphcnt &&
          SCWorthOutputting(sf->subfonts[k]->glyphs[cid]))
        break;
    }
    if (k == sf->subfontcnt)
      ;
    else {
      if (k != lastfd) {
        putshort(at->fdselect, gid);
        putc(k, at->fdselect);
        lastfd = k;
        ++cnt;
      }
    }
  }
  putshort(at->fdselect, gid);
  fseek(at->fdselect, 1, SEEK_SET);
  putshort(at->fdselect, cnt);
  fseek(at->fdselect, 0, SEEK_END);
}

int EVP_DecodeBlock(unsigned char *t, const unsigned char *f, int n) {
  int i, ret = 0, a, b, c, d;
  unsigned long l;
  while ((conv_ascii2bin(*f) == B64_WS) && (n > 0)) {
    f++;
    n--;
  }
  while ((n > 3) && (B64_NOT_BASE64(conv_ascii2bin(f[n - 1]))))
    n--;
  if (n % 4 != 0)
    return (-1);
  for (i = 0; i < n; i += 4) {
    a = conv_ascii2bin(*(f++));
    b = conv_ascii2bin(*(f++));
    c = conv_ascii2bin(*(f++));
    d = conv_ascii2bin(*(f++));
    if ((a & 0x80) || (b & 0x80) || (c & 0x80) || (d & 0x80))
      return (-1);
    l = ((((unsigned long)a) << 18L) | (((unsigned long)b) << 12L) |
         (((unsigned long)c) << 6L) | (((unsigned long)d)));
    *(t++) = (unsigned char)(l >> 16L) & 0xff;
    *(t++) = (unsigned char)(l >> 8L) & 0xff;
    *(t++) = (unsigned char)(l)&0xff;
    ret += 3;
  }
  return (ret);
}

int qemuAgentSetVCPUs(qemuAgentPtr mon, qemuAgentCPUInfoPtr info,
                      size_t ninfo) {
  int rv;
  int nmodified;
  size_t i;
  do {
    if ((rv = qemuAgentSetVCPUsCommand(mon, info, ninfo, &nmodified)) < 0)
      return -1;
    if (rv == nmodified)
      return 0;
    for (i = 0; i < ninfo && rv > 0; i++) {
      if (!info[i].modified)
        continue;
      info[i].modified = false;
      rv--;
    }
  } while (1);
  return 0;
}

