static void page_init(void) {
#ifdef _WIN32 {
  SYSTEM_INFO system_info;
  GetSystemInfo(&system_info);
  qemu_real_host_page_size = system_info.dwPageSize;
}
#else qemu_real_host_page_size = getpagesize();
#endif if (qemu_host_page_size == 0) {
qemu_host_page_size = qemu_real_host_page_size;
}
if (qemu_host_page_size < TARGET_PAGE_SIZE) {
  qemu_host_page_size = TARGET_PAGE_SIZE;
}
qemu_host_page_mask = ~(qemu_host_page_size - 1);
#if defined(CONFIG_BSD) && defined(CONFIG_USER_ONLY) {
#ifdef HAVE_KINFO_GETVMMAP struct kinfo_vmentry *freep;
int i, cnt;
freep = kinfo_getvmmap(getpid(), &cnt);
if (freep) {
  mmap_lock();
  for (i = 0; i < cnt; i++) {
    unsigned long startaddr, endaddr;
    startaddr = freep[i].kve_start;
    endaddr = freep[i].kve_end;
    if (h2g_valid(startaddr)) {
      startaddr = h2g(startaddr) & TARGET_PAGE_MASK;
      if (h2g_valid(endaddr)) {
        endaddr = h2g(endaddr);
        page_set_flags(startaddr, endaddr, PAGE_RESERVED);
      } else {
#if TARGET_ABI_BITS <= L1_MAP_ADDR_SPACE_BITS endaddr = ~0ul;
        page_set_flags(startaddr, endaddr, PAGE_RESERVED);
#endif }
      }
    }
    free(freep);
    mmap_unlock();
  }
#else FILE *f;
last_brk = (unsigned long)sbrk(0);
f = fopen("/compat/linux/proc/self/maps", "r");
if (f) {
  mmap_lock();
  do {
    unsigned long startaddr, endaddr;
    int n;
    n = fscanf(f, "%lx-%lx %*[^\n]\n", &startaddr, &endaddr);
    if (n == 2 && h2g_valid(startaddr)) {
      startaddr = h2g(startaddr) & TARGET_PAGE_MASK;
      if (h2g_valid(endaddr)) {
        endaddr = h2g(endaddr);
      } else {
        endaddr = ~0ul;
      }
      page_set_flags(startaddr, endaddr, PAGE_RESERVED);
    }
  } while (!feof(f));
  fclose(f);
  mmap_unlock();
}
#endif }
#endif }

TEST_F(WebFrameSimTest, DisplayNoneIFramePrints) {
  SimRequest main_resource("https://example.com/test.html", "text/html");
  SimRequest frame_resource("https://example.com/frame.html", "text/html");
  LoadURL("https://example.com/test.html");
  main_resource.Complete(
      "<!DOCTYPE html>"
      "<iframe src=frame.html style='display: none'></iframe>");
  frame_resource.Complete(
      "<!DOCTYPE html>"
      "<html><body>This is a visible iframe.</body></html>");
  Element *element = GetDocument().QuerySelector("iframe");
  HTMLFrameOwnerElement *frame_owner_element = ToHTMLFrameOwnerElement(element);
  Document *iframe_doc = frame_owner_element->contentDocument();
  EXPECT_FALSE(iframe_doc->documentElement()->GetLayoutObject());
  FloatSize page_size(400, 400);
  float maximum_shrink_ratio = 1.0;
  iframe_doc->GetFrame()->StartPrinting(page_size, page_size,
                                        maximum_shrink_ratio);
  EXPECT_TRUE(iframe_doc->documentElement()->GetLayoutObject());
  iframe_doc->GetFrame()->EndPrinting();
  EXPECT_FALSE(iframe_doc->documentElement()->GetLayoutObject());
}

static Asn1Generic *DecodeAsn1DerBoolean(const unsigned char *buffer,
                                         uint32_t size, uint8_t depth,
                                         uint32_t *errcode) {
  const unsigned char *d_ptr = buffer;
  uint8_t numbytes;
  uint32_t value;
  Asn1Generic *a;
  numbytes = d_ptr[1];
  d_ptr += 2;
  if (DecodeAsn1BuildValue(&d_ptr, &value, numbytes, errcode) == -1) {
    return NULL;
  }
  a = Asn1GenericNew();
  if (a == NULL)
    return NULL;
  a->type = ASN1_BOOLEAN;
  a->length = (d_ptr - buffer);
  a->value = value;
  return a;
}

int ssl_verify_alarm_type(long type) {
  int al;
  switch (type) {
  case X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT:
  case X509_V_ERR_UNABLE_TO_GET_CRL:
  case X509_V_ERR_UNABLE_TO_GET_CRL_ISSUER:
    al = SSL_AD_UNKNOWN_CA;
    break;
  case X509_V_ERR_UNABLE_TO_DECRYPT_CERT_SIGNATURE:
  case X509_V_ERR_UNABLE_TO_DECRYPT_CRL_SIGNATURE:
  case X509_V_ERR_UNABLE_TO_DECODE_ISSUER_PUBLIC_KEY:
  case X509_V_ERR_ERROR_IN_CERT_NOT_BEFORE_FIELD:
  case X509_V_ERR_ERROR_IN_CERT_NOT_AFTER_FIELD:
  case X509_V_ERR_ERROR_IN_CRL_LAST_UPDATE_FIELD:
  case X509_V_ERR_ERROR_IN_CRL_NEXT_UPDATE_FIELD:
  case X509_V_ERR_CERT_NOT_YET_VALID:
  case X509_V_ERR_CRL_NOT_YET_VALID:
  case X509_V_ERR_CERT_UNTRUSTED:
  case X509_V_ERR_CERT_REJECTED:
    al = SSL_AD_BAD_CERTIFICATE;
    break;
  case X509_V_ERR_CERT_SIGNATURE_FAILURE:
  case X509_V_ERR_CRL_SIGNATURE_FAILURE:
    al = SSL_AD_DECRYPT_ERROR;
    break;
  case X509_V_ERR_CERT_HAS_EXPIRED:
  case X509_V_ERR_CRL_HAS_EXPIRED:
    al = SSL_AD_CERTIFICATE_EXPIRED;
    break;
  case X509_V_ERR_CERT_REVOKED:
    al = SSL_AD_CERTIFICATE_REVOKED;
    break;
  case X509_V_ERR_OUT_OF_MEM:
    al = SSL_AD_INTERNAL_ERROR;
    break;
  case X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT:
  case X509_V_ERR_SELF_SIGNED_CERT_IN_CHAIN:
  case X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY:
  case X509_V_ERR_UNABLE_TO_VERIFY_LEAF_SIGNATURE:
  case X509_V_ERR_CERT_CHAIN_TOO_LONG:
  case X509_V_ERR_PATH_LENGTH_EXCEEDED:
  case X509_V_ERR_INVALID_CA:
    al = SSL_AD_UNKNOWN_CA;
    break;
  case X509_V_ERR_APPLICATION_VERIFICATION:
    al = SSL_AD_HANDSHAKE_FAILURE;
    break;
  case X509_V_ERR_INVALID_PURPOSE:
    al = SSL_AD_UNSUPPORTED_CERTIFICATE;
    break;
  default:
    al = SSL_AD_CERTIFICATE_UNKNOWN;
    break;
  }
  return (al);
}

