static void send_restrict_entry(restrict_u *pres, int ipv6, u_int idx) {
  const char addr_fmtu[] = "addr.%u";
  const char mask_fmtu[] = "mask.%u";
  const char hits_fmt[] = "hits.%u";
  const char flags_fmt[] = "flags.%u";
  char tag[32];
  u_char sent[RESLIST_FIELDS];
  int noisebits;
  u_int32 noise;
  u_int which;
  u_int remaining;
  sockaddr_u addr;
  sockaddr_u mask;
  const char *pch;
  char *buf;
  const char *match_str;
  const char *access_str;
  sockaddrs_from_restrict_u(&addr, &mask, pres, ipv6);
  remaining = COUNTOF(sent);
  ZERO(sent);
  noise = 0;
  noisebits = 0;
  while (remaining > 0) {
    if (noisebits < 2) {
      noise = rand() ^ (rand() << 16);
      noisebits = 31;
    }
    which = (noise & 0x3) % COUNTOF(sent);
    noise >>= 2;
    noisebits -= 2;
    while (sent[which])
      which = (which + 1) % COUNTOF(sent);
    switch (which) {
    case 0:
      snprintf(tag, sizeof(tag), addr_fmtu, idx);
      pch = stoa(&addr);
      ctl_putunqstr(tag, pch, strlen(pch));
      break;
    case 1:
      snprintf(tag, sizeof(tag), mask_fmtu, idx);
      pch = stoa(&mask);
      ctl_putunqstr(tag, pch, strlen(pch));
      break;
    case 2:
      snprintf(tag, sizeof(tag), hits_fmt, idx);
      ctl_putuint(tag, pres->count);
      break;
    case 3:
      snprintf(tag, sizeof(tag), flags_fmt, idx);
      match_str = res_match_flags(pres->mflags);
      access_str = res_access_flags(pres->flags);
      if ('\0' == match_str[0]) {
        pch = access_str;
      } else {
        LIB_GETBUF(buf);
        snprintf(buf, LIB_BUFLENGTH, "%s %s", match_str, access_str);
        pch = buf;
      }
      ctl_putunqstr(tag, pch, strlen(pch));
      break;
    }
    sent[which] = TRUE;
    remaining--;
  }
  send_random_tag_value((int)idx);
}

static bfd_boolean srec_set_section_contents(bfd *abfd, sec_ptr section,
                                             const void *location,
                                             file_ptr offset,
                                             bfd_size_type bytes_to_do) {
  int opb = bfd_octets_per_byte(abfd);
  tdata_type *tdata = abfd->tdata.srec_data;
  srec_data_list_type *entry;
  entry = (srec_data_list_type *)bfd_alloc(abfd, sizeof(*entry));
  if (entry == NULL)
    return FALSE;
  if (bytes_to_do && (section->flags & SEC_ALLOC) &&
      (section->flags & SEC_LOAD)) {
    bfd_byte *data;
    data = (bfd_byte *)bfd_alloc(abfd, bytes_to_do);
    if (data == NULL)
      return FALSE;
    memcpy((void *)data, location, (size_t)bytes_to_do);
    if (S3Forced)
      tdata->type = 3;
    else if ((section->lma + (offset + bytes_to_do) / opb - 1) <= 0xffff)
      ;
    else if ((section->lma + (offset + bytes_to_do) / opb - 1) <= 0xffffff &&
             tdata->type <= 2)
      tdata->type = 2;
    else
      tdata->type = 3;
    entry->data = data;
    entry->where = section->lma + offset / opb;
    entry->size = bytes_to_do;
    if (tdata->tail != NULL && entry->where >= tdata->tail->where) {
      tdata->tail->next = entry;
      entry->next = NULL;
      tdata->tail = entry;
    } else {
      srec_data_list_type **look;
      for (look = &tdata->head; *look != NULL && (*look)->where < entry->where;
           look = &(*look)->next)
        ;
      entry->next = *look;
      *look = entry;
      if (entry->next == NULL)
        tdata->tail = entry;
    }
  }
  return TRUE;
}

static void parse_new_tag(const char *arg) {
  static struct strbuf msg = STRBUF_INIT;
  const char *from;
  char *tagger;
  struct branch *s;
  struct tag *t;
  uintmax_t from_mark = 0;
  unsigned char sha1[20];
  enum object_type type;
  const char *v;
  t = pool_alloc(sizeof(struct tag));
  memset(t, 0, sizeof(struct tag));
  t->name = pool_strdup(arg);
  if (last_tag)
    last_tag->next_tag = t;
  else
    first_tag = t;
  last_tag = t;
  read_next_command();
  if (!skip_prefix(command_buf.buf, "from ", &from))
    die("Expected from command, got %s", command_buf.buf);
  s = lookup_branch(from);
  if (s) {
    if (is_null_sha1(s->sha1))
      die("Can't tag an empty branch.");
    hashcpy(sha1, s->sha1);
    type = OBJ_COMMIT;
  } else if (*from == ':') {
    struct object_entry *oe;
    from_mark = parse_mark_ref_eol(from);
    oe = find_mark(from_mark);
    type = oe->type;
    hashcpy(sha1, oe->idx.sha1);
  } else if (!get_sha1(from, sha1)) {
    struct object_entry *oe = find_object(sha1);
    if (!oe) {
      type = sha1_object_info(sha1, NULL);
      if (type < 0)
        die("Not a valid object: %s", from);
    } else
      type = oe->type;
  } else
    die("Invalid ref name or SHA1 expression: %s", from);
  read_next_command();
  if (skip_prefix(command_buf.buf, "tagger ", &v)) {
    tagger = parse_ident(v);
    read_next_command();
  } else
    tagger = NULL;
  parse_data(&msg, 0, NULL);
  strbuf_reset(&new_data);
  strbuf_addf(&new_data,
              "object %s\n"
              "type %s\n"
              "tag %s\n",
              sha1_to_hex(sha1), typename(type), t->name);
  if (tagger)
    strbuf_addf(&new_data, "tagger %s\n", tagger);
  strbuf_addch(&new_data, '\n');
  strbuf_addbuf(&new_data, &msg);
  free(tagger);
  if (store_object(OBJ_TAG, &new_data, NULL, t->sha1, 0))
    t->pack_id = MAX_PACK_ID;
  else
    t->pack_id = pack_id;
}

