  ttfOutliner__init(&o, ttf, &r->super, &e.super, true, false,
                    pfont->WMode != 0);
  switch (ttfOutliner__Outline(&o, glyph_index, subpix_origin.x,
                               subpix_origin.y, &m1)) {
  case fBadInstruction:
    WarnBadInstruction(pfont, glyph_index);
    goto recover;
  case fPatented:
    if (!auth)
      WarnPatented(pfont, ttf, "Some glyphs of the font");
  recover:
    if (!design_grid && auth)
      return grid_fit(pfont->dir->san, path, pfont, pscale, &e, &o);
  case fNoError:
    if (!design_grid && !ttin && auth)
      return grid_fit(pfont->dir->san, path, pfont, pscale, &e, &o);
    ttfOutliner__DrawGlyphOutline(&o);
    if (e.error)
      return e.error;
    return 0;
  case fMemoryError:
    return_error(gs_error_VMerror);
  case fUnimplemented:
    return_error(gs_error_unregistered);
  default: {
    int code = r->super.Error(&r->super);
    if (code < 0)
      return code;
    return_error(gs_error_invalidfont);
  }
  }
}

static bool astream_want_attachment(struct attachment_istream *astream,
                                    struct message_part *part) {
  struct istream_attachment_header ahdr;
  if ((part->flags & MESSAGE_PART_FLAG_MULTIPART) != 0) {
    return FALSE;
  }
  if (astream->set.want_attachment == NULL)
    return TRUE;
  i_zero(&ahdr);
  ahdr.part = part;
  ahdr.content_type = astream->part.content_type;
  ahdr.content_disposition = astream->part.content_disposition;
  return astream->set.want_attachment(&ahdr, astream->context);
}

struct key_user *key_user_lookup(kuid_t uid) {
  struct key_user *candidate = NULL, *user;
  struct rb_node *parent = NULL;
  struct rb_node **p;
try_again:
  p = &key_user_tree.rb_node;
  spin_lock(&key_user_lock);
  while (*p) {
    parent = *p;
    user = rb_entry(parent, struct key_user, node);
    if (uid_lt(uid, user->uid))
      p = &(*p)->rb_left;
    else if (uid_gt(uid, user->uid))
      p = &(*p)->rb_right;
    else
      goto found;
  }
  if (!candidate) {
    spin_unlock(&key_user_lock);
    user = NULL;
    candidate = kmalloc(sizeof(struct key_user), GFP_KERNEL);
    if (unlikely(!candidate))
      goto out;
    goto try_again;
  }
  atomic_set(&candidate->usage, 1);
  atomic_set(&candidate->nkeys, 0);
  atomic_set(&candidate->nikeys, 0);
  candidate->uid = uid;
  candidate->qnkeys = 0;
  candidate->qnbytes = 0;
  spin_lock_init(&candidate->lock);
  mutex_init(&candidate->cons_lock);
  rb_link_node(&candidate->node, parent, p);
  rb_insert_color(&candidate->node, &key_user_tree);
  spin_unlock(&key_user_lock);
  user = candidate;
  goto out;
found:
  atomic_inc(&user->usage);
  spin_unlock(&key_user_lock);
  kfree(candidate);
out:
  return user;
}

static int dissect_usb_ms_bulk(tvbuff_t *tvb, packet_info *pinfo,
                               proto_tree *parent_tree, void *data) {
  usb_conv_info_t *usb_conv_info;
  usb_ms_conv_info_t *usb_ms_conv_info;
  proto_tree *tree;
  proto_item *ti;
  guint32 signature = 0;
  int offset = 0;
  gboolean is_request;
  itl_nexus_t *itl;
  itlq_nexus_t *itlq;
  if (data == NULL)
    return 0;
  usb_conv_info = (usb_conv_info_t *)data;
  usb_ms_conv_info = (usb_ms_conv_info_t *)usb_conv_info->class_data;
  if (!usb_ms_conv_info) {
    usb_ms_conv_info = wmem_new(wmem_file_scope(), usb_ms_conv_info_t);
    usb_ms_conv_info->itl = wmem_tree_new(wmem_file_scope());
    usb_ms_conv_info->itlq = wmem_tree_new(wmem_file_scope());
    usb_conv_info->class_data = usb_ms_conv_info;
    usb_conv_info->class_data_type = USB_CONV_MASS_STORAGE;
  } else if (usb_conv_info->class_data_type != USB_CONV_MASS_STORAGE) {
    return 0;
  }
  is_request = (pinfo->srcport == NO_ENDPOINT);
  col_set_str(pinfo->cinfo, COL_PROTOCOL, "USBMS");
  col_clear(pinfo->cinfo, COL_INFO);
  ti = proto_tree_add_protocol_format(parent_tree, proto_usb_ms, tvb, 0, -1,
                                      "USB Mass Storage");
  tree = proto_item_add_subtree(ti, ett_usb_ms);
  signature = tvb_get_letohl(tvb, offset);
  if (is_request && (signature == 0x43425355) &&
      (tvb_reported_length(tvb) == 31)) {
    tvbuff_t *cdb_tvb;
    int cdbrlen, cdblen;
    guint8 lun, flags;
    guint32 datalen;
    proto_tree_add_item(tree, hf_usb_ms_dCBWSignature, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_usb_ms_dCBWTag, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_usb_ms_dCBWDataTransferLength, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
    datalen = tvb_get_letohl(tvb, offset);
    offset += 4;
    proto_tree_add_item(tree, hf_usb_ms_dCBWFlags, tvb, offset, 1,
                        ENC_LITTLE_ENDIAN);
    flags = tvb_get_guint8(tvb, offset);
    offset += 1;
    proto_tree_add_item(tree, hf_usb_ms_dCBWTarget, tvb, offset, 1,
                        ENC_LITTLE_ENDIAN);
    proto_tree_add_item(tree, hf_usb_ms_dCBWLUN, tvb, offset, 1,
                        ENC_LITTLE_ENDIAN);
    lun = tvb_get_guint8(tvb, offset) & 0x0f;
    offset += 1;
    itl = (itl_nexus_t *)wmem_tree_lookup32(usb_ms_conv_info->itl, lun);
    if (!itl) {
      itl = wmem_new(wmem_file_scope(), itl_nexus_t);
      itl->cmdset = 0xff;
      itl->conversation = NULL;
      wmem_tree_insert32(usb_ms_conv_info->itl, lun, itl);
    }
    itlq =
        (itlq_nexus_t *)wmem_tree_lookup32(usb_ms_conv_info->itlq, pinfo->num);
    if (!itlq) {
      itlq = wmem_new(wmem_file_scope(), itlq_nexus_t);
      itlq->lun = lun;
      itlq->scsi_opcode = 0xffff;
      itlq->task_flags = 0;
      if (datalen) {
        if (flags & 0x80) {
          itlq->task_flags |= SCSI_DATA_READ;
        } else {
          itlq->task_flags |= SCSI_DATA_WRITE;
        }
      }
      itlq->data_length = datalen;
      itlq->bidir_data_length = 0;
      itlq->fc_time = pinfo->abs_ts;
      itlq->first_exchange_frame = pinfo->num;
      itlq->last_exchange_frame = 0;
      itlq->flags = 0;
      itlq->alloc_len = 0;
      itlq->extra_data = NULL;
      wmem_tree_insert32(usb_ms_conv_info->itlq, pinfo->num, itlq);
    }
    proto_tree_add_item(tree, hf_usb_ms_dCBWCBLength, tvb, offset, 1,
                        ENC_LITTLE_ENDIAN);
    cdbrlen = tvb_get_guint8(tvb, offset) & 0x1f;
    offset += 1;
    cdblen = cdbrlen;
    if (cdblen > tvb_captured_length_remaining(tvb, offset)) {
      cdblen = tvb_captured_length_remaining(tvb, offset);
    }
    if (cdblen) {
      cdb_tvb = tvb_new_subset(tvb, offset, cdblen, cdbrlen);
      dissect_scsi_cdb(cdb_tvb, pinfo, parent_tree, SCSI_DEV_UNKNOWN, itlq,
                       itl);
    }
    return tvb_captured_length(tvb);
  }
  if ((!is_request) && (signature == 0x53425355) &&
      (tvb_reported_length(tvb) == 13)) {
    guint8 status;
    proto_tree_add_item(tree, hf_usb_ms_dCSWSignature, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_usb_ms_dCBWTag, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_usb_ms_dCSWDataResidue, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_usb_ms_dCSWStatus, tvb, offset, 1,
                        ENC_LITTLE_ENDIAN);
    status = tvb_get_guint8(tvb, offset);
    itlq = (itlq_nexus_t *)wmem_tree_lookup32_le(usb_ms_conv_info->itlq,
                                                 pinfo->num);
    if (!itlq) {
      return tvb_captured_length(tvb);
    }
    itlq->last_exchange_frame = pinfo->num;
    itl = (itl_nexus_t *)wmem_tree_lookup32(usb_ms_conv_info->itl, itlq->lun);
    if (!itl) {
      return tvb_captured_length(tvb);
    }
    if (!status) {
      dissect_scsi_rsp(tvb, pinfo, parent_tree, itlq, itl, 0);
    } else {
      dissect_scsi_rsp(tvb, pinfo, parent_tree, itlq, itl, 0x02);
    }
    return tvb_captured_length(tvb);
  }
  itlq =
      (itlq_nexus_t *)wmem_tree_lookup32_le(usb_ms_conv_info->itlq, pinfo->num);
  if (!itlq) {
    return tvb_captured_length(tvb);
  }
  itl = (itl_nexus_t *)wmem_tree_lookup32(usb_ms_conv_info->itl, itlq->lun);
  if (!itl) {
    return tvb_captured_length(tvb);
  }
  dissect_scsi_payload(tvb, pinfo, parent_tree, is_request, itlq, itl, 0);
  return tvb_captured_length(tvb);
}

