static int lexescape(struct vars *v) {
  chr c;
  static const chr alert[] = {CHR('a'), CHR('l'), CHR('e'), CHR('r'), CHR('t')};
  static const chr esc[] = {CHR('E'), CHR('S'), CHR('C')};
  const chr *save;
  assert(v->cflags & REG_ADVF);
  assert(!ATEOS());
  c = *v->now++;
  if (!iscalnum(c))
    RETV(PLAIN, c);
  NOTE(REG_UNONPOSIX);
  switch (c) {
  case CHR('a'):
    RETV(PLAIN, chrnamed(v, alert, ENDOF(alert), CHR('\007')));
    break;
  case CHR('A'):
    RETV(SBEGIN, 0);
    break;
  case CHR('b'):
    RETV(PLAIN, CHR('\b'));
    break;
  case CHR('B'):
    RETV(PLAIN, CHR('\\'));
    break;
  case CHR('c'):
    NOTE(REG_UUNPORT);
    if (ATEOS())
      FAILW(REG_EESCAPE);
    RETV(PLAIN, (chr)(*v->now++ & 037));
    break;
  case CHR('d'):
    NOTE(REG_ULOCALE);
    RETV(CCLASS, 'd');
    break;
  case CHR('D'):
    NOTE(REG_ULOCALE);
    RETV(CCLASS, 'D');
    break;
  case CHR('e'):
    NOTE(REG_UUNPORT);
    RETV(PLAIN, chrnamed(v, esc, ENDOF(esc), CHR('\033')));
    break;
  case CHR('f'):
    RETV(PLAIN, CHR('\f'));
    break;
  case CHR('m'):
    RET('<');
    break;
  case CHR('M'):
    RET('>');
    break;
  case CHR('n'):
    RETV(PLAIN, CHR('\n'));
    break;
  case CHR('r'):
    RETV(PLAIN, CHR('\r'));
    break;
  case CHR('s'):
    NOTE(REG_ULOCALE);
    RETV(CCLASS, 's');
    break;
  case CHR('S'):
    NOTE(REG_ULOCALE);
    RETV(CCLASS, 'S');
    break;
  case CHR('t'):
    RETV(PLAIN, CHR('\t'));
    break;
  case CHR('u'):
    c = lexdigits(v, 16, 4, 4);
    if (ISERR() || c < CHR_MIN || c > CHR_MAX)
      FAILW(REG_EESCAPE);
    RETV(PLAIN, c);
    break;
  case CHR('U'):
    c = lexdigits(v, 16, 8, 8);
    if (ISERR() || c < CHR_MIN || c > CHR_MAX)
      FAILW(REG_EESCAPE);
    RETV(PLAIN, c);
    break;
  case CHR('v'):
    RETV(PLAIN, CHR('\v'));
    break;
  case CHR('w'):
    NOTE(REG_ULOCALE);
    RETV(CCLASS, 'w');
    break;
  case CHR('W'):
    NOTE(REG_ULOCALE);
    RETV(CCLASS, 'W');
    break;
  case CHR('x'):
    NOTE(REG_UUNPORT);
    c = lexdigits(v, 16, 1, 255);
    if (ISERR() || c < CHR_MIN || c > CHR_MAX)
      FAILW(REG_EESCAPE);
    RETV(PLAIN, c);
    break;
  case CHR('y'):
    NOTE(REG_ULOCALE);
    RETV(WBDRY, 0);
    break;
  case CHR('Y'):
    NOTE(REG_ULOCALE);
    RETV(NWBDRY, 0);
    break;
  case CHR('Z'):
    RETV(SEND, 0);
    break;
  case CHR('1'):
  case CHR('2'):
  case CHR('3'):
  case CHR('4'):
  case CHR('5'):
  case CHR('6'):
  case CHR('7'):
  case CHR('8'):
  case CHR('9'):
    save = v->now;
    v->now--;
    c = lexdigits(v, 10, 1, 255);
    if (ISERR())
      FAILW(REG_EESCAPE);
    if (v->now == save || ((int)c > 0 && (int)c <= v->nsubexp)) {
      NOTE(REG_UBACKREF);
      RETV(BACKREF, (chr)c);
    }
    v->now = save;
  case CHR('0'):
    NOTE(REG_UUNPORT);
    v->now--;
    c = lexdigits(v, 8, 1, 3);
    if (ISERR())
      FAILW(REG_EESCAPE);
    if (c > 0xff) {
      v->now--;
      c >>= 3;
    }
    RETV(PLAIN, c);
    break;
  default:
    assert(iscalpha(c));
    FAILW(REG_EESCAPE);
    break;
  }
  assert(NOTREACHED);
}

int ber_flatten2(BerElement *ber, struct berval *bv, int alloc) {
  assert(bv != NULL);
  if (bv == NULL) {
    return -1;
  }
  if (ber == NULL) {
    bv->bv_val = NULL;
    bv->bv_len = 0;
  } else if (ber->ber_sos_ptr != NULL) {
    return -1;
  } else {
    ber_len_t len = ber_pvt_ber_write(ber);
    if (alloc) {
      bv->bv_val = (char *)ber_memalloc_x(len + 1, ber->ber_memctx);
      if (bv->bv_val == NULL) {
        return -1;
      }
      AC_MEMCPY(bv->bv_val, ber->ber_buf, len);
      bv->bv_val[len] = '\0';
    } else if (ber->ber_buf != NULL) {
      bv->bv_val = ber->ber_buf;
      bv->bv_val[len] = '\0';
    } else {
      bv->bv_val = "";
    }
    bv->bv_len = len;
  }
  return 0;
}

int jpc_ns_analyze(jpc_fix_t *a, int xstart, int ystart, int width, int height,
                   int stride) {
  int numrows = height;
  int numcols = width;
  int rowparity = ystart & 1;
  int colparity = xstart & 1;
  int i;
  jpc_fix_t *startptr;
  int maxcols;
  maxcols = (numcols / JPC_QMFB_COLGRPSIZE) * JPC_QMFB_COLGRPSIZE;
  startptr = &a[0];
  for (i = 0; i < maxcols; i += JPC_QMFB_COLGRPSIZE) {
    jpc_qmfb_split_colgrp(startptr, numrows, stride, rowparity);
    jpc_ns_fwdlift_colgrp(startptr, numrows, stride, rowparity);
    startptr += JPC_QMFB_COLGRPSIZE;
  }
  if (maxcols < numcols) {
    jpc_qmfb_split_colres(startptr, numrows, numcols - maxcols, stride,
                          rowparity);
    jpc_ns_fwdlift_colres(startptr, numrows, numcols - maxcols, stride,
                          rowparity);
  }
  startptr = &a[0];
  for (i = 0; i < numrows; ++i) {
    jpc_qmfb_split_row(startptr, numcols, colparity);
    jpc_ns_fwdlift_row(startptr, numcols, colparity);
    startptr += stride;
  }
  return 0;
}

Jbig2Ctx *jbig2_ctx_new(Jbig2Allocator *allocator, Jbig2Options options,
                        Jbig2GlobalCtx *global_ctx,
                        Jbig2ErrorCallback error_callback,
                        void *error_callback_data) {
  Jbig2Ctx *result;
  if (allocator == NULL)
    allocator = &jbig2_default_allocator;
  if (error_callback == NULL)
    error_callback = &jbig2_default_error;
  result = (Jbig2Ctx *)jbig2_alloc(allocator, sizeof(Jbig2Ctx), 1);
  if (result == NULL) {
    error_callback(error_callback_data, "initial context allocation failed!",
                   JBIG2_SEVERITY_FATAL, -1);
    return result;
  }
  result->allocator = allocator;
  result->options = options;
  result->global_ctx = (const Jbig2Ctx *)global_ctx;
  result->error_callback = error_callback;
  result->error_callback_data = error_callback_data;
  result->state = (options & JBIG2_OPTIONS_EMBEDDED)
                      ? JBIG2_FILE_SEQUENTIAL_HEADER
                      : JBIG2_FILE_HEADER;
  result->buf = NULL;
  result->n_segments = 0;
  result->n_segments_max = 16;
  result->segments = jbig2_new(result, Jbig2Segment *, result->n_segments_max);
  if (result->segments == NULL) {
    error_callback(error_callback_data, "initial segments allocation failed!",
                   JBIG2_SEVERITY_FATAL, -1);
    jbig2_free(allocator, result);
    return result;
  }
  result->segment_index = 0;
  result->current_page = 0;
  result->max_page_index = 4;
  result->pages = jbig2_new(result, Jbig2Page, result->max_page_index);
  if (result->pages == NULL) {
    error_callback(error_callback_data, "initial pages allocation failed!",
                   JBIG2_SEVERITY_FATAL, -1);
    jbig2_free(allocator, result->segments);
    jbig2_free(allocator, result);
    return result;
  }
  {
    int index;
    for (index = 0; index < result->max_page_index; index++) {
      result->pages[index].state = JBIG2_PAGE_FREE;
      result->pages[index].number = 0;
      result->pages[index].image = NULL;
    }
  }
  return result;
}

