static int get_active_quality(int q, int gfu_boost, int low, int high,
                              int *low_motion_minq, int *high_motion_minq) {
  if (gfu_boost > high) {
    return low_motion_minq[q];
  } else if (gfu_boost < low) {
    return high_motion_minq[q];
  } else {
    const int gap = high - low;
    const int offset = high - gfu_boost;
    const int qdiff = high_motion_minq[q] - low_motion_minq[q];
    const int adjustment = ((offset * qdiff) + (gap >> 1)) / gap;
    return low_motion_minq[q] + adjustment;
  }
}

static guint16 de_tp_epc_horizontal_velocity(tvbuff_t *tvb, proto_tree *tree,
                                             packet_info *pinfo _U_,
                                             guint32 offset, guint len _U_,
                                             gchar *add_string _U_,
                                             int string_len _U_) {
  guint32 curr_offset;
  curr_offset = offset;
  proto_tree_add_bits_item(tree, hf_gsm_a_dtap_epc_bearing, tvb,
                           curr_offset << 3, 9, ENC_BIG_ENDIAN);
  proto_tree_add_bits_item(tree, hf_gsm_a_dtap_epc_horizontal_speed, tvb,
                           (curr_offset << 3) + 9, 11, ENC_BIG_ENDIAN);
  curr_offset += 3;
  return (curr_offset - offset);
}

