int ff_msmpeg4_decode_block(MpegEncContext *s, int16_t *block, int n, int coded,
                            const uint8_t *scan_table) {
  int level, i, last, run, run_diff;
  int av_uninit(dc_pred_dir);
  RLTable *rl;
  RL_VLC_ELEM *rl_vlc;
  int qmul, qadd;
  if (s->mb_intra) {
    qmul = 1;
    qadd = 0;
    level = msmpeg4_decode_dc(s, n, &dc_pred_dir);
    if (level < 0) {
      av_log(s->avctx, AV_LOG_ERROR, "dc overflow- block: %d qscale: %d//\n", n,
             s->qscale);
      if (s->inter_intra_pred)
        level = 0;
      else
        return -1;
    }
    if (n < 4) {
      rl = &ff_rl_table[s->rl_table_index];
      if (level > 256 * s->y_dc_scale) {
        av_log(s->avctx, AV_LOG_ERROR, "dc overflow+ L qscale: %d//\n",
               s->qscale);
        if (!s->inter_intra_pred)
          return -1;
      }
    } else {
      rl = &ff_rl_table[3 + s->rl_chroma_table_index];
      if (level > 256 * s->c_dc_scale) {
        av_log(s->avctx, AV_LOG_ERROR, "dc overflow+ C qscale: %d//\n",
               s->qscale);
        if (!s->inter_intra_pred)
          return -1;
      }
    }
    block[0] = level;
    run_diff = s->msmpeg4_version >= 4;
    i = 0;
    if (!coded) {
      goto not_coded;
    }
    if (s->ac_pred) {
      if (dc_pred_dir == 0)
        scan_table = s->intra_v_scantable.permutated;
      else
        scan_table = s->intra_h_scantable.permutated;
    } else {
      scan_table = s->intra_scantable.permutated;
    }
    rl_vlc = rl->rl_vlc[0];
  } else {
    qmul = s->qscale << 1;
    qadd = (s->qscale - 1) | 1;
    i = -1;
    rl = &ff_rl_table[3 + s->rl_table_index];
    if (s->msmpeg4_version == 2)
      run_diff = 0;
    else
      run_diff = 1;
    if (!coded) {
      s->block_last_index[n] = i;
      return 0;
    }
    if (!scan_table)
      scan_table = s->inter_scantable.permutated;
    rl_vlc = rl->rl_vlc[s->qscale];
  }
  {
    OPEN_READER(re, &s->gb);
    for (;;) {
      UPDATE_CACHE(re, &s->gb);
      GET_RL_VLC(level, run, re, &s->gb, rl_vlc, TEX_VLC_BITS, 2, 0);
      if (level == 0) {
        int cache;
        cache = GET_CACHE(re, &s->gb);
        if (s->msmpeg4_version == 1 || (cache & 0x80000000) == 0) {
          if (s->msmpeg4_version == 1 || (cache & 0x40000000) == 0) {
            if (s->msmpeg4_version != 1)
              LAST_SKIP_BITS(re, &s->gb, 2);
            UPDATE_CACHE(re, &s->gb);
            if (s->msmpeg4_version <= 3) {
              last = SHOW_UBITS(re, &s->gb, 1);
              SKIP_CACHE(re, &s->gb, 1);
              run = SHOW_UBITS(re, &s->gb, 6);
              SKIP_CACHE(re, &s->gb, 6);
              level = SHOW_SBITS(re, &s->gb, 8);
              SKIP_COUNTER(re, &s->gb, 1 + 6 + 8);
            } else {
              int sign;
              last = SHOW_UBITS(re, &s->gb, 1);
              SKIP_BITS(re, &s->gb, 1);
              if (!s->esc3_level_length) {
                int ll;
                av_dlog(s->avctx, "ESC-3 %X at %d %d\n", show_bits(&s->gb, 24),
                        s->mb_x, s->mb_y);
                if (s->qscale < 8) {
                  ll = SHOW_UBITS(re, &s->gb, 3);
                  SKIP_BITS(re, &s->gb, 3);
                  if (ll == 0) {
                    ll = 8 + SHOW_UBITS(re, &s->gb, 1);
                    SKIP_BITS(re, &s->gb, 1);
                  }
                } else {
                  ll = 2;
                  while (ll < 8 && SHOW_UBITS(re, &s->gb, 1) == 0) {
                    ll++;
                    SKIP_BITS(re, &s->gb, 1);
                  }
                  if (ll < 8)
                    SKIP_BITS(re, &s->gb, 1);
                }
                s->esc3_level_length = ll;
                s->esc3_run_length = SHOW_UBITS(re, &s->gb, 2) + 3;
                SKIP_BITS(re, &s->gb, 2);
                UPDATE_CACHE(re, &s->gb);
