            else {
              i += run;
              level = (level ^ SHOW_SBITS(re, &s->gb, 1)) -
                      SHOW_SBITS(re, &s->gb, 1);
              LAST_SKIP_BITS(re, &s->gb, 1);
#ifdef ERROR_DETAILS if (run == 66)                                            \
    av_log(s->avctx, AV_LOG_ERROR, "illegal vlc code level=%d\n", level);
              else if ((i > 62 && i < 192) || i > 192 + 63)
                  av_log(s->avctx, AV_LOG_ERROR,
                         "run overflow i=%d run=%d level=%d\n", i, run, level);
#endif }
              if (i > 62) {
                i -= 192;
                if (i & (~63)) {
                  const int left = get_bits_left(&s->gb);
                  if (((i + 192 == 64 && level / qmul == -1) ||
                       !(s->err_recognition & AV_EF_BITSTREAM)) &&
                      left >= 0) {
                    av_log(s->avctx, AV_LOG_ERROR,
                           "ignoring overflow at %d %d\n", s->mb_x, s->mb_y);
                    break;
                  } else {
                    av_log(s->avctx, AV_LOG_ERROR, "ac-tex damaged at %d %d\n",
                           s->mb_x, s->mb_y);
                    return -1;
                  }
                }
                block[scan_table[i]] = level;
                break;
              }
              block[scan_table[i]] = level;
            }
            CLOSE_READER(re, &s->gb);
          }
        not_coded:
          if (s->mb_intra) {
            ff_mpeg4_pred_ac(s, block, n, dc_pred_dir);
            if (s->ac_pred) {
              i = 63;
            }
          }
          if (s->msmpeg4_version >= 4 && i > 0)
            i = 63;
          s->block_last_index[n] = i;
          return 0;
        }

static inline void tm2_motion_block(TM2Context *ctx, AVFrame *pic, int bx,
                                    int by) {
  int i, j;
  int mx, my;
  TM2_INIT_POINTERS_2();
  mx = GET_TOK(ctx, TM2_MOT);
  my = GET_TOK(ctx, TM2_MOT);
  mx = av_clip(mx, -(bx * 4 + 4), ctx->avctx->width - bx * 4);
  my = av_clip(my, -(by * 4 + 4), ctx->avctx->height - by * 4);
  Yo += my * oYstride + mx;
  Uo += (my >> 1) * oUstride + (mx >> 1);
  Vo += (my >> 1) * oVstride + (mx >> 1);
  for (j = 0; j < 2; j++) {
    for (i = 0; i < 2; i++) {
      U[i] = Uo[i];
      V[i] = Vo[i];
    }
    U += Ustride;
    V += Vstride;
    Uo += oUstride;
    Vo += oVstride;
  }
  U -= Ustride * 2;
  V -= Vstride * 2;
  TM2_RECALC_BLOCK(U, Ustride, clast, ctx->CD);
  TM2_RECALC_BLOCK(V, Vstride, (clast + 2), (ctx->CD + 2));
  for (j = 0; j < 4; j++) {
    for (i = 0; i < 4; i++) {
      Y[i] = Yo[i];
    }
    Y += Ystride;
    Yo += oYstride;
  }
  Y -= Ystride * 4;
  ctx->D[0] = Y[3] - last[3];
  ctx->D[1] = Y[3 + Ystride] - Y[3];
  ctx->D[2] = Y[3 + Ystride * 2] - Y[3 + Ystride];
  ctx->D[3] = Y[3 + Ystride * 3] - Y[3 + Ystride * 2];
  for (i = 0; i < 4; i++)
    last[i] = Y[i + Ystride * 3];
}

