static void pdf_set_pattern(fz_context *ctx, pdf_run_processor *pr, int what,
                            pdf_pattern *pat, float *v) {
  pdf_gstate *gs;
  pdf_material *mat;
  gs = pdf_flush_text(ctx, pr);
  mat = what == PDF_FILL ? &gs->fill : &gs->stroke;
  pdf_drop_pattern(ctx, mat->pattern);
  mat->pattern = NULL;
  mat->kind = PDF_MAT_PATTERN;
  if (pat)
    mat->pattern = pdf_keep_pattern(ctx, pat);
  if (v)
    pdf_set_color(ctx, pr, what, v);
  mat->gstate_num = pr->gparent;
}

int curl_mvsnprintf(char *buffer, size_t maxlength, const char *format,
                    va_list ap_save) {
  int retcode;
  struct nsprintf info;
  info.buffer = buffer;
  info.length = 0;
  info.max = maxlength;
  retcode = dprintf_formatf(&info, addbyter, format, ap_save);
  if ((retcode != -1) && info.max) {
    if (info.max == info.length)
      info.buffer[-1] = 0;
    else
      info.buffer[0] = 0;
  }
  return retcode;
}

static char *convert_mime_hdr_to_string(TSMBuffer bufp, TSMLoc hdr_loc) {
  TSIOBuffer output_buffer;
  TSIOBufferReader reader;
  int64_t total_avail;
  TSIOBufferBlock block;
  const char *block_start;
  int64_t block_avail;
  char *output_string;
  int output_len;
  output_buffer = TSIOBufferCreate();
  if (!output_buffer) {
    TSError("[InkAPITest] couldn't allocate IOBuffer");
  }
  reader = TSIOBufferReaderAlloc(output_buffer);
  TSMimeHdrPrint(bufp, hdr_loc, output_buffer);
  total_avail = TSIOBufferReaderAvail(reader);
  output_string = (char *)TSmalloc(total_avail + 1);
  output_len = 0;
  block = TSIOBufferReaderStart(reader);
  while (block) {
    block_start = TSIOBufferBlockReadStart(block, reader, &block_avail);
    if (block_avail == 0) {
      break;
    }
    memcpy(output_string + output_len, block_start, block_avail);
    output_len += block_avail;
    TSIOBufferReaderConsume(reader, block_avail);
    block = TSIOBufferReaderStart(reader);
  }
  output_string[output_len] = '\0';
  output_len++;
  TSIOBufferReaderFree(reader);
  TSIOBufferDestroy(output_buffer);
  return output_string;
}

