static List *simplify_or_arguments(List *args,
                                   eval_const_expressions_context *context,
                                   bool *haveNull, bool *forceTrue) {
  List *newargs = NIL;
  List *unprocessed_args;
  unprocessed_args = list_copy(args);
  while (unprocessed_args) {
    Node *arg = (Node *)linitial(unprocessed_args);
    unprocessed_args = list_delete_first(unprocessed_args);
    if (or_clause(arg)) {
      List *subargs = list_copy(((BoolExpr *)arg)->args);
      if (!unprocessed_args)
        unprocessed_args = subargs;
      else {
        List *oldhdr = unprocessed_args;
        unprocessed_args = list_concat(subargs, unprocessed_args);
        pfree(oldhdr);
      }
      continue;
    }
    arg = eval_const_expressions_mutator(arg, context);
    if (or_clause(arg)) {
      List *subargs = list_copy(((BoolExpr *)arg)->args);
      unprocessed_args = list_concat(subargs, unprocessed_args);
      continue;
    }
    if (IsA(arg, Const)) {
      Const *const_input = (Const *)arg;
      if (const_input->constisnull)
        *haveNull = true;
      else if (DatumGetBool(const_input->constvalue)) {
        *forceTrue = true;
        return NIL;
      }
      continue;
    }
    newargs = lappend(newargs, arg);
  }
  return newargs;
}

static void ctl_putarray(const char *tag, double *arr, int start) {
  register char *cp;
  register const char *cq;
  char buffer[200];
  int i;
  cp = buffer;
  cq = tag;
  while (*cq != '\0')
    *cp++ = *cq++;
  *cp++ = '=';
  i = start;
  do {
    if (i == 0)
      i = NTP_SHIFT;
    i--;
    INSIST((cp - buffer) < (int)sizeof(buffer));
    snprintf(cp, sizeof(buffer) - (cp - buffer), " %.2f", arr[i] * 1e3);
    cp += strlen(cp);
  } while (i != start);
  ctl_putdata(buffer, (unsigned)(cp - buffer), 0);
}

static int parse_RowsBufferCol(tvbuff_t *tvb, packet_info *pinfo, int offset,
                               guint32 row, guint32 col,
                               struct CPMSetBindingsIn *bindingsin,
                               struct rows_data *rowsin, gboolean b_is_64bit,
                               proto_tree *parent_tree, const char *fmt, ...) {
  proto_tree *tree;
  proto_item *item;
  guint32 buf_start = offset;
  guint32 buf_offset = buf_start + (row * bindingsin->brow);
  struct CTableColumn *pcol = &bindingsin->acolumns[col];
  static const value_string STATUS[] = {{0, "StoreStatusOk"},
                                        {1, "StoreStatusDeferred"},
                                        {2, "StoreStatusNull"},
                                        {0, NULL}};
  const char *txt;
  va_list ap;
  va_start(ap, fmt);
  txt = wmem_strdup_vprintf(wmem_packet_scope(), fmt, ap);
  va_end(ap);
  tree = proto_tree_add_subtree(parent_tree, tvb, offset, 0, ett_GetRowsColumn,
                                &item, txt);
  proto_item_append_text(item, " (%s)", pcol->name);
  if (pcol->statusused) {
    int tmp_offset = buf_offset + pcol->statusoffset;
    proto_tree_add_string(
        tree, hf_mswsp_ctablecolumn_status, tvb, tmp_offset, 1,
        val_to_str(tvb_get_guint8(tvb, tmp_offset), STATUS, "(Invalid: 0x%x)"));
  }
  if (pcol->lengthused) {
    int tmp_offset = buf_offset + pcol->lengthoffset;
    proto_tree_add_item(tree, hf_mswsp_ctablecolumn_length, tvb, tmp_offset, 1,
                        ENC_LITTLE_ENDIAN);
  }
  if (pcol->valueused) {
    int tmp_offset = buf_offset + pcol->valueoffset;
    struct CRowVariant variant;
    guint32 len = pcol->valuesize;
    guint64 base_address = rowsin->ulclientbase;
    ZERO_STRUCT(variant);
    if (pcol->lengthused) {
      len = tvb_get_letohs(tvb, buf_offset + pcol->lengthoffset) -
            pcol->valuesize;
    }
    if (pcol->vtype == VT_VARIANT) {
      parse_VariantCol(tvb, pinfo, tmp_offset, tree, base_address, len,
                       b_is_64bit, &variant, "CRowVariant");
    }
  }
  return offset;
}

void evhttp_make_header(struct evhttp_connection *evcon,
                        struct evhttp_request *req) {
  struct evkeyval *header;
  if (req->kind == EVHTTP_REQUEST) {
    evhttp_make_header_request(evcon, req);
  } else {
    evhttp_make_header_response(evcon, req);
  }
  TAILQ_FOREACH(header, req->output_headers, next) {
    evbuffer_add_printf(evcon->output_buffer, "%s: %s\r\n", header->key,
                        header->value);
  }
  evbuffer_add(evcon->output_buffer, "\r\n", 2);
  if (EVBUFFER_LENGTH(req->output_buffer) > 0) {
    evbuffer_add_buffer(evcon->output_buffer, req->output_buffer);
  }
}

