static void dissect_rsvp_template_filter(proto_item *ti,
                                         proto_tree *rsvp_object_tree,
                                         tvbuff_t *tvb, int offset,
                                         int obj_length, int rsvp_class _U_,
                                         int type,
                                         rsvp_conversation_info *rsvph) {
  int offset2 = offset + 4;
  proto_item_set_text(ti, "%s", summary_template(tvb, offset));
  switch (type) {
  case 1:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "1 - IPv4");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_IP], tvb,
                        offset2, 4, ENC_BIG_ENDIAN);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_PORT],
                        tvb, offset2 + 6, 2, ENC_BIG_ENDIAN);
    set_address_tvb(&rsvph->source, AT_IPv4, 4, tvb, offset2);
    rsvph->udp_source_port = tvb_get_ntohs(tvb, offset2 + 6);
    break;
  case 2:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "2 - IPv6");
    proto_tree_add_item(rsvp_object_tree,
                        hf_rsvp_template_filter_source_address_ipv6, tvb,
                        offset2, 16, ENC_NA);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_template_filter_source_port,
                        tvb, offset2 + 18, 2, ENC_BIG_ENDIAN);
    break;
  case 7:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "7 - IPv4 LSP");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_IP], tvb,
                        offset2, 4, ENC_BIG_ENDIAN);
    if (rsvp_class == RSVP_CLASS_SENDER_TEMPLATE) {
      proto_tree_add_item(rsvp_object_tree,
                          hf_rsvp_filter[RSVPF_SENDER_SHORT_CALL_ID], tvb,
                          offset2 + 4, 2, ENC_BIG_ENDIAN);
    }
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_LSP_ID],
                        tvb, offset2 + 6, 2, ENC_BIG_ENDIAN);
    set_address_tvb(&rsvph->source, AT_IPv4, 4, tvb, offset2);
    rsvph->udp_source_port = tvb_get_ntohs(tvb, offset2 + 6);
    break;
  case 8:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "8 - IPv6 LSP");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_IP], tvb,
                        offset2, 16, ENC_BIG_ENDIAN);
    if (rsvp_class == RSVP_CLASS_SENDER_TEMPLATE) {
      proto_tree_add_item(rsvp_object_tree,
                          hf_rsvp_filter[RSVPF_SENDER_SHORT_CALL_ID], tvb,
                          offset2 + 16, 2, ENC_BIG_ENDIAN);
    }
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_LSP_ID],
                        tvb, offset2 + 18, 2, ENC_BIG_ENDIAN);
    set_address_tvb(&rsvph->source, AT_IPv6, 16, tvb, offset2);
    rsvph->udp_source_port = tvb_get_ntohs(tvb, offset2 + 18);
    break;
  case 9:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "9 - IPv4 Aggregate");
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_SENDER_IP], tvb,
                        offset2, 4, ENC_BIG_ENDIAN);
    set_address_tvb(&rsvph->source, AT_IPv4, 4, tvb, offset2);
    break;
  default:
    proto_tree_add_uint_format_value(rsvp_object_tree, hf_rsvp_ctype, tvb,
                                     offset + 3, 1, type, "Unknown (%u)", type);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_template_filter_data, tvb,
                        offset2, obj_length - 4, ENC_NA);
    break;
  }
}

void xmlrpc_char_encode(char *outbuffer, const char *s1) {
  long unsigned int i;
  unsigned char c;
  char buf2[15];
  mowgli_string_t *s = mowgli_string_create();
  *buf2 = '\0';
  *outbuffer = '\0';
  if ((!(s1) || (*(s1) == '\0'))) {
    return;
  }
  for (i = 0; s1[i] != '\0'; i++) {
    c = s1[i];
    if (c > 127) {
 snprintf ( buf2 , sizeof buf2 , "&#%d;
" , c ) ;
 s -> append ( s , buf2 , strlen ( buf2 ) ) ;
    } else if (c == '&') {
 s -> append ( s , "&amp;
" , 5 ) ;
    } else if (c == '<') {
 s -> append ( s , "&lt;
" , 4 ) ;
    } else if (c == '>') {
 s -> append ( s , "&gt;
" , 4 ) ;
    } else if (c == '"') {
 s -> append ( s , "&quot;
" , 6 ) ;
    } else {
      s->append_char(s, c);
    }
  }
  memcpy(outbuffer, s->str, XMLRPC_BUFSIZE);
}

static struct sk_buff *compose_sadb_supported(const struct sadb_msg *orig,
                                              gfp_t allocation) {
  struct sk_buff *skb;
  struct sadb_msg *hdr;
  int len, auth_len, enc_len, i;
  auth_len = xfrm_count_pfkey_auth_supported();
  if (auth_len) {
    auth_len *= sizeof(struct sadb_alg);
    auth_len += sizeof(struct sadb_supported);
  }
  enc_len = xfrm_count_pfkey_enc_supported();
  if (enc_len) {
    enc_len *= sizeof(struct sadb_alg);
    enc_len += sizeof(struct sadb_supported);
  }
  len = enc_len + auth_len + sizeof(struct sadb_msg);
  skb = alloc_skb(len + 16, allocation);
  if (!skb)
    goto out_put_algs;
  hdr = (struct sadb_msg *)skb_put(skb, sizeof(*hdr));
  pfkey_hdr_dup(hdr, orig);
  hdr->sadb_msg_errno = 0;
  hdr->sadb_msg_len = len / sizeof(uint64_t);
  if (auth_len) {
    struct sadb_supported *sp;
    struct sadb_alg *ap;
    sp = (struct sadb_supported *)skb_put(skb, auth_len);
    ap = (struct sadb_alg *)(sp + 1);
    sp->sadb_supported_len = auth_len / sizeof(uint64_t);
    sp->sadb_supported_exttype = SADB_EXT_SUPPORTED_AUTH;
    for (i = 0;; i++) {
      struct xfrm_algo_desc *aalg = xfrm_aalg_get_byidx(i);
      if (!aalg)
        break;
      if (!aalg->pfkey_supported)
        continue;
      if (aalg->available)
        *ap++ = aalg->desc;
    }
  }
  if (enc_len) {
    struct sadb_supported *sp;
    struct sadb_alg *ap;
    sp = (struct sadb_supported *)skb_put(skb, enc_len);
    ap = (struct sadb_alg *)(sp + 1);
    sp->sadb_supported_len = enc_len / sizeof(uint64_t);
    sp->sadb_supported_exttype = SADB_EXT_SUPPORTED_ENCRYPT;
    for (i = 0;; i++) {
      struct xfrm_algo_desc *ealg = xfrm_ealg_get_byidx(i);
      if (!ealg)
        break;
      if (!ealg->pfkey_supported)
        continue;
      if (ealg->available)
        *ap++ = ealg->desc;
    }
  }
out_put_algs:
  return skb;
}

