static int decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                        AVPacket *avpkt) {
  Indeo3DecodeContext *ctx = avctx->priv_data;
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  int res;
  res = decode_frame_headers(ctx, avctx, buf, buf_size);
  if (res < 0)
    return res;
  if (res) {
    *got_frame = 0;
    return buf_size;
  }
  if (ctx->frame_flags & BS_NONREF && (avctx->skip_frame >= AVDISCARD_NONREF))
    return 0;
  if (!(ctx->frame_flags & BS_KEYFRAME) &&
      avctx->skip_frame >= AVDISCARD_NONKEY)
    return 0;
  ctx->buf_sel = (ctx->frame_flags >> BS_BUFFER) & 1;
  if ((res = decode_plane(ctx, avctx, ctx->planes, ctx->y_data_ptr,
                          ctx->y_data_size, 40)))
    return res;
  if ((res = decode_plane(ctx, avctx, &ctx->planes[1], ctx->u_data_ptr,
                          ctx->u_data_size, 10)))
    return res;
  if ((res = decode_plane(ctx, avctx, &ctx->planes[2], ctx->v_data_ptr,
                          ctx->v_data_size, 10)))
    return res;
  if (ctx->frame.data[0])
    avctx->release_buffer(avctx, &ctx->frame);
  ctx->frame.reference = 0;
  if ((res = ff_get_buffer(avctx, &ctx->frame)) < 0) {
    av_log(ctx->avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return res;
  }
  output_plane(&ctx->planes[0], ctx->buf_sel, ctx->frame.data[0],
               ctx->frame.linesize[0], avctx->height);
  output_plane(&ctx->planes[1], ctx->buf_sel, ctx->frame.data[1],
               ctx->frame.linesize[1], (avctx->height + 3) >> 2);
  output_plane(&ctx->planes[2], ctx->buf_sel, ctx->frame.data[2],
               ctx->frame.linesize[2], (avctx->height + 3) >> 2);
  *got_frame = 1;
  *(AVFrame *)data = ctx->frame;
  return buf_size;
}

static void eeprom24c0x_write(int scl, int sda) {
  if (eeprom.scl && scl && (eeprom.sda != sda)) {
    logout("%u: scl = %u->%u, sda = %u->%u i2c %s\n", eeprom.tick, eeprom.scl,
           scl, eeprom.sda, sda, sda ? "stop" : "start");
    if (!sda) {
      eeprom.tick = 1;
      eeprom.command = 0;
    }
  } else if (eeprom.tick == 0 && !eeprom.ack) {
    logout("%u: scl = %u->%u, sda = %u->%u wait for i2c start\n", eeprom.tick,
           eeprom.scl, scl, eeprom.sda, sda);
  } else if (!eeprom.scl && scl) {
    logout("%u: scl = %u->%u, sda = %u->%u trigger bit\n", eeprom.tick,
           eeprom.scl, scl, eeprom.sda, sda);
    if (eeprom.ack) {
      logout("\ti2c ack bit = 0\n");
      sda = 0;
      eeprom.ack = 0;
    } else if (eeprom.sda == sda) {
      uint8_t bit = (sda != 0);
      logout("\ti2c bit = %d\n", bit);
      if (eeprom.tick < 9) {
        eeprom.command <<= 1;
        eeprom.command += bit;
        eeprom.tick++;
        if (eeprom.tick == 9) {
          logout("\tcommand 0x%04x, %s\n", eeprom.command,
                 bit ? "read" : "write");
          eeprom.ack = 1;
        }
      } else if (eeprom.tick < 17) {
        if (eeprom.command & 1) {
          sda = ((eeprom.data & 0x80) != 0);
        }
        eeprom.address <<= 1;
        eeprom.address += bit;
        eeprom.tick++;
        eeprom.data <<= 1;
        if (eeprom.tick == 17) {
          eeprom.data = eeprom.contents[eeprom.address];
          logout("\taddress 0x%04x, data 0x%02x\n", eeprom.address,
                 eeprom.data);
          eeprom.ack = 1;
          eeprom.tick = 0;
        }
      } else if (eeprom.tick >= 17) {
        sda = 0;
      }
    } else {
      logout("\tsda changed with raising scl\n");
    }
  } else {
    logout("%u: scl = %u->%u, sda = %u->%u\n", eeprom.tick, eeprom.scl, scl,
           eeprom.sda, sda);
  }
  eeprom.scl = scl;
  eeprom.sda = sda;
}

