static int proc_ioctl(struct usb_dev_state *ps, struct usbdevfs_ioctl *ctl) {
  int size;
  void *buf = NULL;
  int retval = 0;
  struct usb_interface *intf = NULL;
  struct usb_driver *driver = NULL;
  if (ps->privileges_dropped)
    return -EACCES;
  size = _IOC_SIZE(ctl->ioctl_code);
  if (size > 0) {
    buf = kmalloc(size, GFP_KERNEL);
    if (buf == NULL)
      return -ENOMEM;
    if ((_IOC_DIR(ctl->ioctl_code) & _IOC_WRITE)) {
      if (copy_from_user(buf, ctl->data, size)) {
        kfree(buf);
        return -EFAULT;
      }
    } else {
      memset(buf, 0, size);
    }
  }
  if (!connected(ps)) {
    kfree(buf);
    return -ENODEV;
  }
  if (ps->dev->state != USB_STATE_CONFIGURED)
    retval = -EHOSTUNREACH;
  else if (!(intf = usb_ifnum_to_if(ps->dev, ctl->ifno)))
    retval = -EINVAL;
  else
    switch (ctl->ioctl_code) {
    case USBDEVFS_DISCONNECT:
      if (intf->dev.driver) {
        driver = to_usb_driver(intf->dev.driver);
        dev_dbg(&intf->dev, "disconnect by usbfs\n");
        usb_driver_release_interface(driver, intf);
      } else
        retval = -ENODATA;
      break;
    case USBDEVFS_CONNECT:
      if (!intf->dev.driver)
        retval = device_attach(&intf->dev);
      else
        retval = -EBUSY;
      break;
    default:
      if (intf->dev.driver)
        driver = to_usb_driver(intf->dev.driver);
      if (driver == NULL || driver->unlocked_ioctl == NULL) {
        retval = -ENOTTY;
      } else {
        retval = driver->unlocked_ioctl(intf, ctl->ioctl_code, buf);
        if (retval == -ENOIOCTLCMD)
          retval = -ENOTTY;
      }
    }
  if (retval >= 0 && (_IOC_DIR(ctl->ioctl_code) & _IOC_READ) != 0 && size > 0 &&
      copy_to_user(ctl->data, buf, size) != 0)
    retval = -EFAULT;
  kfree(buf);
  return retval;
}

proto_item *proto_tree_add_ipv6_format_value(proto_tree *tree, int hfindex,
                                             tvbuff_t *tvb, gint start,
                                             gint length,
                                             const struct e_in6_addr *value_ptr,
                                             const char *format, ...) {
  proto_item *pi;
  va_list ap;
  pi = proto_tree_add_ipv6(tree, hfindex, tvb, start, length, value_ptr);
  if (pi != tree) {
    va_start(ap, format);
    proto_tree_set_representation_value(pi, format, ap);
    va_end(ap);
  }
  return pi;
}

void vp9_vaq_frame_setup(VP9_COMP *cpi) {
  VP9_COMMON *cm = &cpi->common;
  struct segmentation *seg = &cm->seg;
  const double base_q = vp9_convert_qindex_to_q(cm->base_qindex, cm->bit_depth);
  const int base_rdmult =
      vp9_compute_rd_mult(cpi, cm->base_qindex + cm->y_dc_delta_q);
  int i;
  if (cm->frame_type == KEY_FRAME || cpi->refresh_alt_ref_frame ||
      (cpi->refresh_golden_frame && !cpi->rc.is_src_frame_alt_ref)) {
    vp9_enable_segmentation(seg);
    vp9_clearall_segfeatures(seg);
    seg->abs_delta = SEGMENT_DELTADATA;
    vp9_clear_system_state();
    for (i = ENERGY_MIN; i <= ENERGY_MAX; i++) {
      int qindex_delta, segment_rdmult;
      if (Q_RATIO(i) == 1) {
        RDMULT_RATIO(i) = 1;
        continue;
      }
      qindex_delta = vp9_compute_qdelta(&cpi->rc, base_q, base_q * Q_RATIO(i),
                                        cm->bit_depth);
      vp9_set_segdata(seg, SEGMENT_ID(i), SEG_LVL_ALT_Q, qindex_delta);
      vp9_enable_segfeature(seg, SEGMENT_ID(i), SEG_LVL_ALT_Q);
      segment_rdmult = vp9_compute_rd_mult(cpi, cm->base_qindex + qindex_delta +
                                                    cm->y_dc_delta_q);
      RDMULT_RATIO(i) = (double)segment_rdmult / base_rdmult;
    }
  }
}

int authreadkeys(const char *file) {
  FILE *fp;
  char *line;
  char *token;
  keyid_t keyno;
  int keytype;
  char buf[512];
  u_char keystr[32];
  size_t len;
  size_t j;
  size_t nerr;
  fp = fopen(file, "r");
  if (fp == NULL) {
    msyslog(LOG_ERR, "authreadkeys: file %s: %m", file);
    return (0);
  }
  INIT_SSL();
  auth_delkeys();
  nerr = 0;
  while ((line = fgets(buf, sizeof buf, fp)) != NULL) {
    if (nerr > nerr_maxlimit)
      break;
    token = nexttok(&line);
    if (token == NULL)
      continue;
    keyno = atoi(token);
    if (keyno == 0) {
      log_maybe(&nerr, "authreadkeys: cannot change key %s", token);
      continue;
    }
    if (keyno > NTP_MAXKEY) {
      log_maybe(&nerr, "authreadkeys: key %s > %d reserved for Autokey", token,
                NTP_MAXKEY);
      continue;
    }
    token = nexttok(&line);
    if (token == NULL) {
      log_maybe(&nerr, "authreadkeys: no key type for key %d", keyno);
      continue;
    }
#ifdef OPENSSL keytype = keytype_from_text(token, NULL);
    if (keytype == 0) {
      log_maybe(&nerr, "authreadkeys: invalid type for key %d", keyno);
      continue;
    }
    if (EVP_get_digestbynid(keytype) == NULL) {
      log_maybe(&nerr, "authreadkeys: no algorithm for key %d", keyno);
      continue;
    }
#else if (!(*token == 'M' || *token == 'm')) {
    log_maybe(&nerr, "authreadkeys: invalid type for key %d", keyno);
    continue;
  }
  keytype = KEY_TYPE_MD5;
#endif token = nexttok(&line);
    if (token == NULL) {
      log_maybe(&nerr, "authreadkeys: no key for key %d", keyno);
      continue;
    }
    len = strlen(token);
    if (len <= 20) {
      MD5auth_setkey(keyno, keytype, (u_char *)token, len);
    } else {
      char hex[] = "0123456789abcdef";
      u_char temp;
      char *ptr;
      size_t jlim;
      jlim = min(len, 2 * sizeof(keystr));
      for (j = 0; j < jlim; j++) {
        ptr = strchr(hex, tolower((unsigned char)token[j]));
        if (ptr == NULL)
          break;
        temp = (u_char)(ptr - hex);
        if (j & 1)
          keystr[j / 2] |= temp;
        else
          keystr[j / 2] = temp << 4;
      }
      if (j < jlim) {
        log_maybe(&nerr, "authreadkeys: invalid hex digit for key %d", keyno);
        continue;
      }
      MD5auth_setkey(keyno, keytype, keystr, jlim / 2);
    }
  }
  fclose(fp);
  if (nerr > nerr_maxlimit) {
    msyslog(LOG_ERR, "authreadkeys: emergeny break after %u errors", nerr);
    return (0);
  } else if (nerr > nerr_loglimit) {
    msyslog(LOG_ERR, "authreadkeys: found %u more error(s)",
            nerr - nerr_loglimit);
  }
  return (1);
}

void parseDiagnosticInfo(proto_tree *tree, tvbuff_t *tvb, packet_info *pinfo,
                         gint *pOffset, const char *szFieldName) {
  static const int *diag_mask[] = {&hf_opcua_diag_mask_symbolicflag,
                                   &hf_opcua_diag_mask_namespaceflag,
                                   &hf_opcua_diag_mask_localizedtextflag,
                                   &hf_opcua_diag_mask_localeflag,
                                   &hf_opcua_diag_mask_additionalinfoflag,
                                   &hf_opcua_diag_mask_innerstatuscodeflag,
                                   &hf_opcua_diag_mask_innerdiaginfoflag,
                                   NULL};
  gint iOffset = *pOffset;
  guint8 EncodingMask;
  proto_tree *subtree;
  proto_item *ti;
  subtree = proto_tree_add_subtree_format(tree, tvb, *pOffset, -1,
                                          ett_opcua_diagnosticinfo, &ti,
                                          "%s: DiagnosticInfo", szFieldName);
  EncodingMask = tvb_get_guint8(tvb, iOffset);
  proto_tree_add_bitmask(subtree, tvb, iOffset, hf_opcua_diag_mask,
                         ett_opcua_diagnosticinfo_encodingmask, diag_mask,
                         ENC_LITTLE_ENDIAN);
  iOffset++;
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_SYMBOLICID_FLAG) {
    parseInt32(subtree, tvb, pinfo, &iOffset, hf_opcua_diag_symbolicid);
  }
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_NAMESPACE_FLAG) {
    parseInt32(subtree, tvb, pinfo, &iOffset, hf_opcua_diag_namespace);
  }
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_LOCALIZEDTEXT_FLAG) {
    parseInt32(subtree, tvb, pinfo, &iOffset, hf_opcua_diag_localizedtext);
  }
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_LOCALE_FLAG) {
    parseInt32(subtree, tvb, pinfo, &iOffset, hf_opcua_diag_locale);
  }
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_ADDITIONALINFO_FLAG) {
    parseString(subtree, tvb, pinfo, &iOffset, hf_opcua_diag_additionalinfo);
  }
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_INNERSTATUSCODE_FLAG) {
    parseStatusCode(subtree, tvb, pinfo, &iOffset,
                    hf_opcua_diag_innerstatuscode);
  }
  if (EncodingMask & DIAGNOSTICINFO_ENCODINGMASK_INNERDIAGNOSTICINFO_FLAG) {
    parseDiagnosticInfo(subtree, tvb, pinfo, &iOffset, "Inner DiagnosticInfo");
  }
  proto_item_set_end(ti, tvb, iOffset);
  *pOffset = iOffset;
}

