static int for_samples_continue(i_ctx_t *i_ctx_p) {
  os_ptr op = osp;
  es_ptr ep = esp;
  int var = ep[-4].value.intval;
  float a = ep[-3].value.realval;
  int n = ep[-2].value.intval;
  float b = ep[-1].value.realval;
  if (var > n) {
    esp -= 6;
    return o_pop_estack;
  }
  push(1);
  make_real(op, ((n - var) * a + var * b) / n);
  ep[-4].value.intval = var + 1;
  ref_assign_inline(ep + 2, ep);
  esp = ep + 2;
  return o_push_estack;
}

int qemuMonitorJSONHumanCommandWithFd(qemuMonitorPtr mon, const char *cmd_str,
                                      int scm_fd, char **reply_str) {
  virJSONValuePtr cmd = NULL;
  virJSONValuePtr reply = NULL;
  virJSONValuePtr obj;
  int ret = -1;
  cmd = qemuMonitorJSONMakeCommand("human-monitor-command", "s:command-line",
                                   cmd_str, NULL);
  if (!cmd || qemuMonitorJSONCommandWithFd(mon, cmd, scm_fd, &reply) < 0)
    goto cleanup;
  if (qemuMonitorJSONCheckError(cmd, reply))
    goto cleanup;
  if (!(obj = virJSONValueObjectGet(reply, "return"))) {
    qemuReportError(VIR_ERR_INTERNAL_ERROR, "%s",
                    _("human monitor command was missing return data"));
    goto cleanup;
  }
  if (reply_str) {
    const char *data;
    if ((data = virJSONValueGetString(obj)))
      *reply_str = strdup(data);
    else
      *reply_str = strdup("");
    if (!*reply_str) {
      virReportOOMError();
      goto cleanup;
    }
  }
  ret = 0;
cleanup:
  virJSONValueFree(cmd);
  virJSONValueFree(reply);
  return ret;
}

