static int dtls1_retrieve_buffered_fragment(SSL *s, int *ok) {
  pitem *item;
  hm_fragment *frag;
  int al;
  *ok = 0;
  item = pqueue_peek(s->d1->buffered_messages);
  if (item == NULL)
    return 0;
  frag = (hm_fragment *)item->data;
  if (frag->reassembly != NULL)
    return 0;
  if (s->d1->handshake_read_seq == frag->msg_header.seq) {
    unsigned long frag_len = frag->msg_header.frag_len;
    pqueue_pop(s->d1->buffered_messages);
    al = dtls1_preprocess_fragment(s, &frag->msg_header);
    if (al == 0) {
      unsigned char *p =
          (unsigned char *)s->init_buf->data + DTLS1_HM_HEADER_LENGTH;
      memcpy(&p[frag->msg_header.frag_off], frag->fragment,
             frag->msg_header.frag_len);
    }
    dtls1_hm_fragment_free(frag);
    pitem_free(item);
    if (al == 0) {
      *ok = 1;
      return frag_len;
    }
    ssl3_send_alert(s, SSL3_AL_FATAL, al);
    s->init_num = 0;
    *ok = 0;
    return -1;
  } else
    return 0;
}

static unsigned int hc_str(const char *s, size_t len) {
  unsigned int r = 0;
  while (len-- > 0)
    r = r * 31 + *s++;
  return r;
}

static void garbagefree(struct garbage *all) {
  struct garbage *junk, *next;
  int i, j;
  for (junk = all; junk != NULL; junk = next) {
    next = junk->next;
    for (j = 0; j < junk->cnt; ++j) {
      for (i = 0; i < junk->cnts[j]; ++i) {
        if (junk->entries[j][i].type == ps_string ||
            junk->entries[j][i].type == ps_instr ||
            junk->entries[j][i].type == ps_lit)
          free(junk->entries[j][i].u.str);
      }
      free(junk->entries[j]);
    }
    if (junk != all)
      chunkfree(junk, sizeof(struct garbage));
  }
}

static int32_t ucnv_internalConvert(UConverter *outConverter,
                                    UConverter *inConverter, char *target,
                                    int32_t targetCapacity, const char *source,
                                    int32_t sourceLength,
                                    UErrorCode *pErrorCode) {
  UChar pivotBuffer[CHUNK_SIZE];
  UChar *pivot, *pivot2;
  char *myTarget;
  const char *sourceLimit;
  const char *targetLimit;
  int32_t targetLength = 0;
  if (sourceLength < 0) {
    sourceLimit = uprv_strchr(source, 0);
  } else {
    sourceLimit = source + sourceLength;
  }
  if (source == sourceLimit) {
    return u_terminateChars(target, targetCapacity, 0, pErrorCode);
  }
  pivot = pivot2 = pivotBuffer;
  myTarget = target;
  targetLength = 0;
  if (targetCapacity > 0) {
    targetLimit = target + targetCapacity;
    ucnv_convertEx(outConverter, inConverter, &myTarget, targetLimit, &source,
                   sourceLimit, pivotBuffer, &pivot, &pivot2,
                   pivotBuffer + CHUNK_SIZE, FALSE, TRUE, pErrorCode);
    targetLength = (int32_t)(myTarget - target);
  }
  if (*pErrorCode == U_BUFFER_OVERFLOW_ERROR || targetCapacity == 0) {
    char targetBuffer[CHUNK_SIZE];
    targetLimit = targetBuffer + CHUNK_SIZE;
    do {
      *pErrorCode = U_ZERO_ERROR;
      myTarget = targetBuffer;
      ucnv_convertEx(outConverter, inConverter, &myTarget, targetLimit, &source,
                     sourceLimit, pivotBuffer, &pivot, &pivot2,
