static int rv34_decode_inter_mb_header(RV34DecContext *r, int8_t *intra_types) {
  MpegEncContext *s = &r->s;
  GetBitContext *gb = &s->gb;
  int mb_pos = s->mb_x + s->mb_y * s->mb_stride;
  int i, t;
  r->block_type = r->decode_mb_info(r);
  if (r->block_type == -1)
    return -1;
  s->current_picture_ptr->f.mb_type[mb_pos] =
      rv34_mb_type_to_lavc[r->block_type];
  r->mb_type[mb_pos] = r->block_type;
  if (r->block_type == RV34_MB_SKIP) {
    if (s->pict_type == AV_PICTURE_TYPE_P)
      r->mb_type[mb_pos] = RV34_MB_P_16x16;
    if (s->pict_type == AV_PICTURE_TYPE_B)
      r->mb_type[mb_pos] = RV34_MB_B_DIRECT;
  }
  r->is16 = !!IS_INTRA16x16(s->current_picture_ptr->f.mb_type[mb_pos]);
  rv34_decode_mv(r, r->block_type);
  if (r->block_type == RV34_MB_SKIP) {
    fill_rectangle(intra_types, 4, 4, r->intra_types_stride, 0,
                   sizeof(intra_types[0]));
    return 0;
  }
  r->chroma_vlc = 1;
  r->luma_vlc = 0;
  if (IS_INTRA(s->current_picture_ptr->f.mb_type[mb_pos])) {
    if (r->is16) {
      t = get_bits(gb, 2);
      fill_rectangle(intra_types, 4, 4, r->intra_types_stride, t,
                     sizeof(intra_types[0]));
      r->luma_vlc = 2;
    } else {
      if (r->decode_intra_types(r, gb, intra_types) < 0)
        return -1;
      r->luma_vlc = 1;
    }
    r->chroma_vlc = 0;
    r->cur_vlcs = choose_vlc_set(r->si.quant, r->si.vlc_set, 0);
  } else {
    for (i = 0; i < 16; i++)
      intra_types[(i & 3) + (i >> 2) * r->intra_types_stride] = 0;
    r->cur_vlcs = choose_vlc_set(r->si.quant, r->si.vlc_set, 1);
    if (r->mb_type[mb_pos] == RV34_MB_P_MIX16x16) {
      r->is16 = 1;
      r->chroma_vlc = 1;
      r->luma_vlc = 2;
      r->cur_vlcs = choose_vlc_set(r->si.quant, r->si.vlc_set, 0);
    }
  }
  return rv34_decode_cbp(gb, r->cur_vlcs, r->is16);
}

static int xps_parse_gradient_stops(xps_document *doc, char *base_uri,
                                    fz_xml *node, struct stop *stops,
                                    int maxcount) {
  fz_colorspace *colorspace;
  float sample[8];
  float rgb[3];
  int before, after;
  int count;
  int i;
  maxcount -= 2;
  count = 0;
  while (node && count < maxcount) {
    if (!strcmp(fz_xml_tag(node), "GradientStop")) {
      char *offset = fz_xml_att(node, "Offset");
      char *color = fz_xml_att(node, "Color");
      if (offset && color) {
        stops[count].offset = fz_atof(offset);
        stops[count].index = count;
        xps_parse_color(doc, base_uri, color, &colorspace, sample);
        fz_convert_color(doc->ctx, fz_device_rgb(doc->ctx), rgb, colorspace,
                         sample + 1);
        stops[count].r = rgb[0];
        stops[count].g = rgb[1];
        stops[count].b = rgb[2];
        stops[count].a = sample[0];
        count++;
      }
    }
    node = fz_xml_next(node);
  }
  if (count == 0) {
    fz_warn(doc->ctx, "gradient brush has no gradient stops");
    stops[0].offset = 0;
    stops[0].r = 0;
    stops[0].g = 0;
    stops[0].b = 0;
    stops[0].a = 1;
    stops[1].offset = 1;
    stops[1].r = 1;
    stops[1].g = 1;
    stops[1].b = 1;
    stops[1].a = 1;
    return 2;
  }
  if (count == maxcount)
    fz_warn(doc->ctx,
            "gradient brush exceeded maximum number of gradient stops");
  qsort(stops, count, sizeof(struct stop), cmp_stop);
  before = -1;
  after = -1;
  for (i = 0; i < count; i++) {
    if (stops[i].offset < 0)
      before = i;
    if (stops[i].offset > 1) {
      after = i;
      break;
    }
  }
  if (before > 0) {
    memmove(stops, stops + before, (count - before) * sizeof(struct stop));
    count -= before;
  }
  if (after >= 0)
    count = after + 1;
  if (count == 1) {
    stops[1] = stops[0];
    stops[0].offset = 0;
    stops[1].offset = 1;
    return 2;
  }
  if (stops[0].offset < 0) {
    float d = -stops[0].offset / (stops[1].offset - stops[0].offset);
    stops[0].offset = 0;
    stops[0].r = lerp(stops[0].r, stops[1].r, d);
    stops[0].g = lerp(stops[0].g, stops[1].g, d);
    stops[0].b = lerp(stops[0].b, stops[1].b, d);
    stops[0].a = lerp(stops[0].a, stops[1].a, d);
  }
  if (stops[count - 1].offset > 1) {
    float d = (1 - stops[count - 2].offset) /
              (stops[count - 1].offset - stops[count - 2].offset);
    stops[count - 1].offset = 1;
    stops[count - 1].r = lerp(stops[count - 2].r, stops[count - 1].r, d);
    stops[count - 1].g = lerp(stops[count - 2].g, stops[count - 1].g, d);
    stops[count - 1].b = lerp(stops[count - 2].b, stops[count - 1].b, d);
    stops[count - 1].a = lerp(stops[count - 2].a, stops[count - 1].a, d);
  }
  if (stops[0].offset > 0) {
    memmove(stops + 1, stops, count * sizeof(struct stop));
    stops[0] = stops[1];
    stops[0].offset = 0;
    count++;
  }
  if (stops[count - 1].offset < 1) {
    stops[count] = stops[count - 1];
    stops[count].offset = 1;
    count++;
  }
  return count;
}

