static void dissect_rsvp_juniper(proto_tree *ti _U_,
                                 proto_tree *rsvp_object_tree, tvbuff_t *tvb,
                                 int offset, int obj_length, int rsvp_class _U_,
                                 int type) {
  proto_item *hidden_item;
  hidden_item =
      proto_tree_add_item(rsvp_object_tree, hf_rsvp_filter[RSVPF_JUNIPER], tvb,
                          offset, obj_length, ENC_NA);
  PROTO_ITEM_SET_HIDDEN(hidden_item);
  proto_tree_add_uint(rsvp_object_tree, hf_rsvp_ctype, tvb, offset + 3, 1,
                      type);
  offset += 4;
  if (type == 1) {
    guint tlvs, pad;
    tlvs = tvb_get_ntohs(tvb, offset);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_numtlvs, tvb, offset,
                        2, ENC_BIG_ENDIAN);
    offset += 2;
    pad = tvb_get_ntohs(tvb, offset);
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_padlength, tvb,
                        offset, 2, ENC_BIG_ENDIAN);
    offset += 2;
    while (tlvs > 0) {
      guint8 t, l;
      t = tvb_get_guint8(tvb, offset);
      proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_type, tvb, offset,
                          1, ENC_BIG_ENDIAN);
      offset += 1;
      l = tvb_get_guint8(tvb, offset);
      proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_length, tvb, offset,
                          1, ENC_BIG_ENDIAN);
      offset += 1;
      switch (t) {
      case 0x01:
        proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_attrib_cos, tvb,
                            offset, l - 2, ENC_BIG_ENDIAN);
        offset += (l - 2);
        break;
      case 0x02:
        proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_attrib_metric1,
                            tvb, offset, l - 2, ENC_BIG_ENDIAN);
        offset += (l - 2);
        break;
      case 0x04:
        proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_attrib_metric2,
                            tvb, offset, l - 2, ENC_BIG_ENDIAN);
        offset += (l - 2);
        break;
      case 0x08:
        proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_attrib_ccc_status,
                            tvb, offset, l - 2, ENC_BIG_ENDIAN);
        offset += (l - 2);
        break;
      case 0x10:
        proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_attrib_path, tvb,
                            offset, l - 2, ENC_BIG_ENDIAN);
        offset += (l - 2);
        break;
      default:
        proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_attrib_unknown,
                            tvb, offset, l - 2, ENC_NA);
        offset += (l - 2);
        break;
      }
      tlvs--;
    }
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_pad, tvb, offset, pad,
                        ENC_NA);
  } else if (obj_length > 4) {
    proto_tree_add_item(rsvp_object_tree, hf_rsvp_juniper_unknown, tvb, offset,
                        obj_length, ENC_NA);
  }
}

static char *w_addchar(char *buffer, size_t *actlen, size_t *maxlen, char ch) {
  if (*actlen == *maxlen) {
    char *old_buffer = buffer;
    assert(buffer == NULL || *maxlen != 0);
    *maxlen += W_CHUNK;
    buffer = (char *)realloc(buffer, 1 + *maxlen);
    if (buffer == NULL)
      free(old_buffer);
  }
  if (buffer != NULL) {
    buffer[*actlen] = ch;
    buffer[++(*actlen)] = '\0';
  }
  return buffer;
}

static void var_filter_block2d_bil_second_pass(const uint16_t *src_ptr,
                                               uint8_t *output_ptr,
                                               unsigned int src_pixels_per_line,
                                               unsigned int pixel_step,
                                               unsigned int output_height,
                                               unsigned int output_width,
                                               const int16_t *vp9_filter) {
  unsigned int i, j;
  for (i = 0; i < output_height; i++) {
    for (j = 0; j < output_width; j++) {
      output_ptr[j] =
          ROUND_POWER_OF_TWO((int)src_ptr[0] * vp9_filter[0] +
                                 (int)src_ptr[pixel_step] * vp9_filter[1],
                             FILTER_BITS);
      src_ptr++;
    }
    src_ptr += src_pixels_per_line - output_width;
    output_ptr += output_width;
  }
}

static int write_VD_boot_record(struct archive_write *a) {
  struct iso9660 *iso9660;
  unsigned char *bp;
  iso9660 = a->format_data;
  bp = wb_buffptr(a) - 1;
  set_VD_bp(bp, VDT_BOOT_RECORD, 1);
  memcpy(bp + 8, "EL TORITO SPECIFICATION", 23);
  set_unused_field_bp(bp, 8 + 23, 39);
  set_unused_field_bp(bp, 40, 71);
  set_num_731(bp + 72, iso9660->el_torito.catalog->file->content.location);
  set_unused_field_bp(bp, 76, LOGICAL_BLOCK_SIZE);
  return (wb_consume(a, LOGICAL_BLOCK_SIZE));
}

static int32_t u_scanf_count_handler(UFILE *input, u_scanf_spec_info *info,
                                     ufmt_args *args, const UChar *fmt,
                                     int32_t *fmtConsumed,
                                     int32_t *argConverted) {
  (void)input;
  (void)fmt;
  (void)fmtConsumed;
  if (!info->fSkipArg) {
    if (info->fIsShort)
      *(int16_t *)(args[0].ptrValue) = (int16_t)(UINT16_MAX & info->fWidth);
    else if (info->fIsLongLong)
      *(int64_t *)(args[0].ptrValue) = info->fWidth;
    else
      *(int32_t *)(args[0].ptrValue) = (int32_t)(UINT32_MAX & info->fWidth);
  }
  *argConverted = 0;
  return 0;
}

