static void HCLComposite(const MagickRealType hue, const MagickRealType chroma,
                         const MagickRealType luma, MagickRealType *red,
                         MagickRealType *green, MagickRealType *blue) {
  MagickRealType b, c, g, h, m, r, x;
  assert(red != (MagickRealType *)NULL);
  assert(green != (MagickRealType *)NULL);
  assert(blue != (MagickRealType *)NULL);
  h = 6.0 * hue;
  c = chroma;
  x = c * (1.0 - fabs(fmod(h, 2.0) - 1.0));
  r = 0.0;
  g = 0.0;
  b = 0.0;
  if ((0.0 <= h) && (h < 1.0)) {
    r = c;
    g = x;
  } else if ((1.0 <= h) && (h < 2.0)) {
    r = x;
    g = c;
  } else if ((2.0 <= h) && (h < 3.0)) {
    g = c;
    b = x;
  } else if ((3.0 <= h) && (h < 4.0)) {
    g = x;
    b = c;
  } else if ((4.0 <= h) && (h < 5.0)) {
    r = x;
    b = c;
  } else if ((5.0 <= h) && (h < 6.0)) {
    r = c;
    b = x;
  }
  m = luma - (0.298839 * r + 0.586811 * g + 0.114350 * b);
  *red = QuantumRange * (r + m);
  *green = QuantumRange * (g + m);
  *blue = QuantumRange * (b + m);
}

static void create_new_objects(void) {
  int dbnum;
  prep_status("Restoring database schemas in the new cluster\n");
  for (dbnum = 0; dbnum < old_cluster.dbarr.ndbs; dbnum++) {
    char sql_file_name[MAXPGPATH], log_file_name[MAXPGPATH];
    DbInfo *old_db = &old_cluster.dbarr.dbs[dbnum];
    pg_log(PG_STATUS, "%s", old_db->db_name);
    snprintf(sql_file_name, sizeof(sql_file_name), DB_DUMP_FILE_MASK,
             old_db->db_oid);
    snprintf(log_file_name, sizeof(log_file_name), DB_DUMP_LOG_FILE_MASK,
             old_db->db_oid);
    parallel_exec_prog(
        log_file_name, NULL,
        "\"%s/pg_restore\" %s --exit-on-error --verbose --dbname \"%s\" \"%s\"",
        new_cluster.bindir, cluster_conn_opts(&new_cluster), old_db->db_name,
        sql_file_name);
  }
  while (reap_child(true) == true)
    ;
  end_progress_output();
  check_ok();
  if (GET_MAJOR_VERSION(old_cluster.major_version) < 903)
    set_frozenxids(true);
  get_db_and_rel_infos(&new_cluster);
}

