  DIE_UNLESS(rc);
  reconnect(&l_mysql);
  buff[LARGE_BUFFER_SIZE - 1] = 'c';
  db[NAME_CHAR_LEN - 1] = 'e';
  rc = mysql_change_user(l_mysql, user, buff, db);
  DIE_UNLESS(rc);
  reconnect(&l_mysql);
  db[NAME_CHAR_LEN - 1] = 'a';
  rc = mysql_change_user(l_mysql, user, buff, db);
  DIE_UNLESS(!rc);
  rc = mysql_change_user(l_mysql, user + 1, buff + 1, db + 1);
  DIE_UNLESS(rc);
  reconnect(&l_mysql);
  rc = mysql_change_user(mysql, opt_user, opt_password, current_db);
  DIE_UNLESS(!rc);
  strxmov(query, "DROP DATABASE ", db, NullS);
  rc = mysql_query(mysql, query);
  myquery(rc);
  strxmov(query, "DELETE FROM mysql.user WHERE User='", user, "'", NullS);
  rc = mysql_query(mysql, query);
  myquery(rc);
  DIE_UNLESS(mysql_affected_rows(mysql) == 2);
  mysql_close(l_mysql);
#endif DBUG_VOID_RETURN;
}

static void cirrus_mem_writeb_mode4and5_8bpp(CirrusVGAState *s, unsigned mode,
                                             unsigned offset,
                                             uint32_t mem_value) {
  int x;
  unsigned val = mem_value;
  uint8_t *dst;
  for (x = 0; x < 8; x++) {
    dst = s->vga.vram_ptr + ((offset + x) & s->cirrus_addr_mask);
    if (val & 0x80) {
      *dst = s->cirrus_shadow_gr1;
    } else if (mode == 5) {
      *dst = s->cirrus_shadow_gr0;
    }
    val <<= 1;
  }
  memory_region_set_dirty(&s->vga.vram, offset, 8);
}

static void pdf_run_d1(fz_context *ctx, pdf_processor *proc, float wx, float wy,
                       float llx, float lly, float urx, float ury) {
  pdf_run_processor *pr = (pdf_run_processor *)proc;
  if (pr->nested_depth > 1)
    return;
  pr->dev->flags |= FZ_DEVFLAG_MASK | FZ_DEVFLAG_BBOX_DEFINED;
  pr->dev->flags &=
      ~(FZ_DEVFLAG_FILLCOLOR_UNDEFINED | FZ_DEVFLAG_STROKECOLOR_UNDEFINED |
        FZ_DEVFLAG_STARTCAP_UNDEFINED | FZ_DEVFLAG_DASHCAP_UNDEFINED |
        FZ_DEVFLAG_ENDCAP_UNDEFINED | FZ_DEVFLAG_LINEJOIN_UNDEFINED |
        FZ_DEVFLAG_MITERLIMIT_UNDEFINED | FZ_DEVFLAG_LINEWIDTH_UNDEFINED);
  pr->dev->d1_rect.x0 = fz_min(llx, urx);
  pr->dev->d1_rect.y0 = fz_min(lly, ury);
  pr->dev->d1_rect.x1 = fz_max(llx, urx);
  pr->dev->d1_rect.y1 = fz_max(lly, ury);
}

static void *init_tls(void) {
  GL(dl_tls_static_nelem) = GL(dl_tls_max_dtv_idx);
  if (GL(dl_initial_dtv) != NULL)
    return NULL;
  size_t nelem = GL(dl_tls_max_dtv_idx) + 1 + TLS_SLOTINFO_SURPLUS;
  GL(dl_tls_dtv_slotinfo_list) = (struct dtv_slotinfo_list *)calloc(
      sizeof(struct dtv_slotinfo_list) + nelem * sizeof(struct dtv_slotinfo),
      1);
  struct dtv_slotinfo *slotinfo = GL(dl_tls_dtv_slotinfo_list)->slotinfo;
  GL(dl_tls_dtv_slotinfo_list)->len = nelem;
  GL(dl_tls_dtv_slotinfo_list)->next = NULL;
  assert(GL(dl_ns)[LM_ID_BASE + 1]._ns_loaded == NULL);
  int i = 0;
  for (struct link_map *l = GL(dl_ns)[LM_ID_BASE]._ns_loaded; l != NULL;
       l = l->l_next)
    if (l->l_tls_blocksize != 0) {
      slotinfo[i].map = l;
      ++i;
    }
  assert(i == GL(dl_tls_max_dtv_idx));
  _dl_determine_tlsoffset();
  void *tcbp = _dl_allocate_tls_storage();
  if (tcbp == NULL)
    _dl_fatal_printf(
        "\ cannot allocate TLS data structures for initial thread");
  GL(dl_initial_dtv) = GET_DTV(tcbp);
  const char *lossage = TLS_INIT_TP(tcbp);
  if (__glibc_unlikely(lossage != NULL))
    _dl_fatal_printf("cannot set up thread-local storage: %s\n", lossage);
  tls_init_tp_called = true;
  return tcbp;
}

