    if (strcmp("GenericMessage/0.0.8.239.2", gefx->key) == 0) {
      hf_index = hf_h245_subMessageIdentifier_standard;
    }
  }
  offset = dissect_per_constrained_integer(
      tvb, offset, actx, tree, hf_index, 0U, 127U, &subMessageIdentifer, FALSE);
  if (gefx) {
    gefx->subid =
        wmem_strdup_printf(wmem_packet_scope(), "%u", subMessageIdentifer);
    gef_ctx_update_key(gef_ctx_get(actx->private_data));
  }
  if (hf_index == hf_h245_subMessageIdentifier_standard) {
    col_append_fstr(actx->pinfo->cinfo, COL_INFO, "%s",
                    val_to_str(subMessageIdentifer,
                               h245_h239subMessageIdentifier_vals,
                               "<unknown>"));
    g_snprintf(h245_pi->frame_label, 50, "%s",
               val_to_str(subMessageIdentifer,
                          h245_h239subMessageIdentifier_vals, "<unknown>"));
  }
  return offset;
}

