static void convolve_avg_horiz(const uint8_t *src, ptrdiff_t src_stride,
                               uint8_t *dst, ptrdiff_t dst_stride,
                               const InterpKernel *x_filters, int x0_q4,
                               int x_step_q4, int w, int h) {
  int x, y;
  src -= SUBPEL_TAPS / 2 - 1;
  for (y = 0; y < h; ++y) {
    int x_q4 = x0_q4;
    for (x = 0; x < w; ++x) {
      const uint8_t *const src_x = &src[x_q4 >> SUBPEL_BITS];
      const int16_t *const x_filter = x_filters[x_q4 & SUBPEL_MASK];
      int k, sum = 0;
      for (k = 0; k < SUBPEL_TAPS; ++k)
        sum += src_x[k] * x_filter[k];
      dst[x] = ROUND_POWER_OF_TWO(
          dst[x] + clip_pixel(ROUND_POWER_OF_TWO(sum, FILTER_BITS)), 1);
      x_q4 += x_step_q4;
    }
    src += src_stride;
    dst += dst_stride;
  }
}

static int nntp_fetch_headers(struct Context *ctx, void *hc, anum_t first,
                              anum_t last, int restore) {
  struct NntpData *nntp_data = ctx->data;
  struct FetchCtx fc;
  struct Header *hdr = NULL;
  char buf[HUGE_STRING];
  int rc = 0;
  int oldmsgcount = ctx->msgcount;
  anum_t current;
  anum_t first_over = first;
#ifdef USE_HCACHE void *hdata = NULL;
#endif if (!last || first > last) return 0;
  fc.ctx = ctx;
  fc.first = first;
  fc.last = last;
  fc.restore = restore;
  fc.messages = mutt_mem_calloc(last - first + 1, sizeof(unsigned char));
#ifdef USE_HCACHE fc.hc = hc;
#endif if (NntpListgroup && nntp_data->nserv->hasLISTGROUP &&                  \
           !nntp_data->deleted) {
  if (!ctx->quiet)
    mutt_message(_("Fetching list of articles..."));
  if (nntp_data->nserv->hasLISTGROUPrange)
    snprintf(buf, sizeof(buf), "LISTGROUP %s %u-%u\r\n", nntp_data->group,
             first, last);
  else
    snprintf(buf, sizeof(buf), "LISTGROUP %s\r\n", nntp_data->group);
  rc = nntp_fetch_lines(nntp_data, buf, sizeof(buf), NULL, fetch_numbers, &fc);
  if (rc > 0) {
    mutt_error("LISTGROUP: %s", buf);
  }
  if (rc == 0) {
    for (current = first; current <= last && rc == 0; current++) {
      if (fc.messages[current - first])
        continue;
      snprintf(buf, sizeof(buf), "%u", current);
      if (nntp_data->bcache) {
        mutt_debug(2, "#1 mutt_bcache_del %s\n", buf);
        mutt_bcache_del(nntp_data->bcache, buf);
      }
#ifdef USE_HCACHE if (fc.hc) {
      mutt_debug(2, "mutt_hcache_delete %s\n", buf);
      mutt_hcache_delete(fc.hc, buf, strlen(buf));
    }
#endif }
  }
}
else {
  for (current = first; current <= last; current++)
    fc.messages[current - first] = 1;
}
if (!ctx->quiet) {
  mutt_progress_init(&fc.progress, _("Fetching message headers..."),
                     MUTT_PROGRESS_MSG, ReadInc, last - first + 1);
}
for (current = first; current <= last && rc == 0; current++) {
  if (!ctx->quiet)
    mutt_progress_update(&fc.progress, current - first + 1, -1);
#ifdef USE_HCACHE snprintf(buf, sizeof(buf), "%u", current);
#endif if (!fc.messages[current - first]) continue;
  if (ctx->msgcount >= ctx->hdrmax)
    mx_alloc_memory(ctx);
#ifdef USE_HCACHE hdata = mutt_hcache_fetch(fc.hc, buf, strlen(buf));
  if (hdata) {
    mutt_debug(2, "mutt_hcache_fetch %s\n", buf);
    ctx->hdrs[ctx->msgcount] = hdr = mutt_hcache_restore(hdata);
    mutt_hcache_free(fc.hc, &hdata);
    hdr->data = 0;
    if (hdr->deleted && !restore) {
      mutt_header_free(&hdr);
      if (nntp_data->bcache) {
        mutt_debug(2, "#2 mutt_bcache_del %s\n", buf);
        mutt_bcache_del(nntp_data->bcache, buf);
      }
      continue;
    }
    hdr->read = false;
    hdr->old = false;
  } else
#endif if (nntp_data->deleted) continue;
  else if (nntp_data->nserv->hasOVER || nntp_data->nserv->hasXOVER) {
    if (NntpListgroup && nntp_data->nserv->hasLISTGROUP)
      break;
    else
      continue;
  }
  else {
    FILE *fp = mutt_file_mkstemp();
    if (!fp) {
      mutt_perror("mutt_file_mkstemp() failed!");
      rc = -1;
      break;
    }
    snprintf(buf, sizeof(buf), "HEAD %u\r\n", current);
    rc =
        nntp_fetch_lines(nntp_data, buf, sizeof(buf), NULL, fetch_tempfile, fp);
    if (rc) {
      mutt_file_fclose(&fp);
      if (rc < 0)
        break;
      if (mutt_str_strncmp("423", buf, 3) != 0) {
        mutt_error("HEAD: %s", buf);
        break;
      }
      if (nntp_data->bcache) {
        snprintf(buf, sizeof(buf), "%u", current);
        mutt_debug(2, "#3 mutt_bcache_del %s\n", buf);
        mutt_bcache_del(nntp_data->bcache, buf);
      }
      rc = 0;
      continue;
    }
    hdr = ctx->hdrs[ctx->msgcount] = mutt_header_new();
    hdr->env = mutt_rfc822_read_header(fp, hdr, 0, 0);
    hdr->received = hdr->date_sent;
    mutt_file_fclose(&fp);
  }
  hdr->index = ctx->msgcount++;
  hdr->read = false;
  hdr->old = false;
  hdr->deleted = false;
  hdr->data = mutt_mem_calloc(1, sizeof(struct NntpHeaderData));
  NHDR(hdr)->article_num = current;
  if (restore)
    hdr->changed = true;
  else {
    nntp_article_status(ctx, hdr, NULL, NHDR(hdr)->article_num);
    if (!hdr->read)
      nntp_parse_xref(ctx, hdr);
  }
  if (current > nntp_data->last_loaded)
    nntp_data->last_loaded = current;
  first_over = current + 1;
}
if (!NntpListgroup || !nntp_data->nserv->hasLISTGROUP)
  current = first_over;
if (current <= last && rc == 0 && !nntp_data->deleted) {
  char *cmd = nntp_data->nserv->hasOVER ? "OVER" : "XOVER";
  snprintf(buf, sizeof(buf), "%s %u-%u\r\n", cmd, current, last);
  rc = nntp_fetch_lines(nntp_data, buf, sizeof(buf), NULL, parse_overview_line,
                        &fc);
  if (rc > 0) {
    mutt_error("%s: %s", cmd, buf);
  }
}
if (ctx->msgcount > oldmsgcount)
  mx_update_context(ctx, ctx->msgcount - oldmsgcount);
FREE(&fc.messages);
if (rc != 0)
  return -1;
mutt_clear_error();
return 0;
}

void kadmin_getprivs(int argc, char *argv[]) {
  static char *privs[] = {"INQUIRE", "ADD", "MODIFY", "DELETE"};
  krb5_error_code retval;
  size_t i;
  long plist;
  if (argc != 1) {
    fprintf(stderr, _("usage: get_privs\n"));
    return;
  }
  retval = kadm5_get_privs(handle, &plist);
  if (retval) {
    com_err("get_privs", retval, _("while retrieving privileges"));
    return;
  }
  printf(_("current privileges:"));
  for (i = 0; i < sizeof(privs) / sizeof(char *); i++) {
    if (plist & 1 << i)
      printf(" %s", privs[i]);
  }
  printf("\n");
}

static void ohci_process_lists(OHCIState *ohci, int completion) {
  if ((ohci->ctl & OHCI_CTL_CLE) && (ohci->status & OHCI_STATUS_CLF)) {
    if (ohci->ctrl_cur && ohci->ctrl_cur != ohci->ctrl_head) {
      trace_usb_ohci_process_lists(ohci->ctrl_head, ohci->ctrl_cur);
    }
    if (!ohci_service_ed_list(ohci, ohci->ctrl_head, completion)) {
      ohci->ctrl_cur = 0;
      ohci->status &= ~OHCI_STATUS_CLF;
    }
  }
  if ((ohci->ctl & OHCI_CTL_BLE) && (ohci->status & OHCI_STATUS_BLF)) {
    if (!ohci_service_ed_list(ohci, ohci->bulk_head, completion)) {
      ohci->bulk_cur = 0;
      ohci->status &= ~OHCI_STATUS_BLF;
    }
  }
}

