static SchroBuffer *find_next_parse_unit(SchroParseUnitContext *parse_ctx) {
  SchroBuffer *enc_buf = NULL;
  int next_pu_offset = 0;
  unsigned char *in_buf;
  if (parse_ctx->buf_size < 13 || parse_ctx->buf[0] != 'B' ||
      parse_ctx->buf[1] != 'B' || parse_ctx->buf[2] != 'C' ||
      parse_ctx->buf[3] != 'D')
    return NULL;
  next_pu_offset = (parse_ctx->buf[5] << 24) + (parse_ctx->buf[6] << 16) +
                   (parse_ctx->buf[7] << 8) + parse_ctx->buf[8];
  if (next_pu_offset == 0 &&
      SCHRO_PARSE_CODE_IS_END_OF_SEQUENCE(parse_ctx->buf[4]))
    next_pu_offset = 13;
  if (next_pu_offset <= 0 || parse_ctx->buf_size < next_pu_offset)
    return NULL;
  in_buf = av_malloc(next_pu_offset);
  if (!in_buf) {
    av_log(parse_ctx, AV_LOG_ERROR, "Unable to allocate input buffer\n");
    return NULL;
  }
  memcpy(in_buf, parse_ctx->buf, next_pu_offset);
  enc_buf = schro_buffer_new_with_data(in_buf, next_pu_offset);
  enc_buf->free = libschroedinger_decode_buffer_free;
  enc_buf->priv = in_buf;
  parse_ctx->buf += next_pu_offset;
  parse_ctx->buf_size -= next_pu_offset;
  return enc_buf;
}

static GList *make_activation_parameters(GList *uris, GList **unhandled_uris) {
  GList *ret, *l, *app_uris;
  NautilusFile *file;
  GAppInfo *app, *old_app;
  GHashTable *app_table;
  char *uri;
  ret = NULL;
  *unhandled_uris = NULL;
  app_table = g_hash_table_new_full(
      (GHashFunc)mime_application_hash, (GEqualFunc)g_app_info_equal,
      (GDestroyNotify)g_object_unref, (GDestroyNotify)g_list_free);
  for (l = uris; l != NULL; l = l->next) {
    uri = l->data;
    file = nautilus_file_get_by_uri(uri);
    app = nautilus_mime_get_default_application_for_file(file);
    if (app != NULL) {
      app_uris = NULL;
      if (g_hash_table_lookup_extended(app_table, app, (gpointer *)&old_app,
                                       (gpointer *)&app_uris)) {
        g_hash_table_steal(app_table, old_app);
        app_uris = g_list_prepend(app_uris, uri);
        g_object_unref(app);
        app = old_app;
      } else {
        app_uris = g_list_prepend(NULL, uri);
      }
      g_hash_table_insert(app_table, app, app_uris);
    } else {
      *unhandled_uris = g_list_prepend(*unhandled_uris, uri);
    }
    nautilus_file_unref(file);
  }
  g_hash_table_foreach(app_table, (GHFunc)list_to_parameters_foreach, &ret);
  g_hash_table_destroy(app_table);
  *unhandled_uris = g_list_reverse(*unhandled_uris);
  return g_list_reverse(ret);
}

