TSAction TSContSchedule(TSCont contp, ink_hrtime timeout, TSThreadPool tp) {
  sdk_assert(sdk_sanity_check_iocore_structure(contp) == TS_SUCCESS);
  FORCE_PLUGIN_SCOPED_MUTEX(contp);
  INKContInternal *i = (INKContInternal *)contp;
  TSAction action;
  if (ink_atomic_increment((int *)&i->m_event_count, 1) < 0) {
    ink_assert(!"not reached");
  }
  EventType etype;
  switch (tp) {
  case TS_THREAD_POOL_NET:
  case TS_THREAD_POOL_DEFAULT:
    etype = ET_NET;
    break;
  case TS_THREAD_POOL_TASK:
    etype = ET_TASK;
    break;
  case TS_THREAD_POOL_SSL:
    etype = ET_TASK;
    break;
  case TS_THREAD_POOL_DNS:
    etype = ET_DNS;
    break;
  case TS_THREAD_POOL_REMAP:
    etype = ET_TASK;
    break;
  case TS_THREAD_POOL_CLUSTER:
    etype = ET_CLUSTER;
    break;
  case TS_THREAD_POOL_UDP:
    etype = ET_UDP;
    break;
  default:
    etype = ET_TASK;
    break;
  }
  if (timeout == 0) {
    action = reinterpret_cast<TSAction>(eventProcessor.schedule_imm(i, etype));
  } else {
    action = reinterpret_cast<TSAction>(
        eventProcessor.schedule_in(i, HRTIME_MSECONDS(timeout), etype));
  }
  action = (TSAction)((uintptr_t)action | 0x1);
  return action;
}

static void import_palette(CDXLVideoContext *c, uint32_t *new_palette) {
  int i;
  for (i = 0; i < c->palette_size / 2; i++) {
    unsigned rgb = AV_RB16(&c->palette[i * 2]);
    unsigned r = ((rgb >> 8) & 0xF) * 0x11;
    unsigned g = ((rgb >> 4) & 0xF) * 0x11;
    unsigned b = (rgb & 0xF) * 0x11;
    AV_WN32(&new_palette[i], (r << 16) | (g << 8) | b);
  }
}

