static cmsBool Read16bitTables(cmsContext ContextID, cmsIOHANDLER *io,
                               cmsPipeline *lut, int nChannels, int nEntries) {
  int i;
  cmsToneCurve *Tables[cmsMAXCHANNELS];
  if (nEntries <= 0)
    return TRUE;
  if (nEntries < 2)
    return FALSE;
  if (nChannels > cmsMAXCHANNELS)
    return FALSE;
  memset(Tables, 0, sizeof(Tables));
  for (i = 0; i < nChannels; i++) {
    Tables[i] = cmsBuildTabulatedToneCurve16(ContextID, nEntries, NULL);
    if (Tables[i] == NULL)
      goto Error;
    if (!_cmsReadUInt16Array(io, nEntries, Tables[i]->Table16))
      goto Error;
  }
  if (!cmsPipelineInsertStage(
          lut, cmsAT_END,
          cmsStageAllocToneCurves(ContextID, nChannels, Tables)))
    goto Error;
  for (i = 0; i < nChannels; i++)
    cmsFreeToneCurve(Tables[i]);
  return TRUE;
Error:
  for (i = 0; i < nChannels; i++) {
    if (Tables[i])
      cmsFreeToneCurve(Tables[i]);
  }
  return FALSE;
}

const char *keydb_get_resource_name(KEYDB_HANDLE hd) {
  int idx;
  const char *s = NULL;
  if (!hd)
    return NULL;
  if (hd->found >= 0 && hd->found < hd->used)
    idx = hd->found;
  else if (hd->current >= 0 && hd->current < hd->used)
    idx = hd->current;
  else
    idx = 0;
  switch (hd->active[idx].type) {
  case KEYDB_RESOURCE_TYPE_NONE:
    s = NULL;
    break;
  case KEYDB_RESOURCE_TYPE_KEYRING:
    s = keyring_get_resource_name(hd->active[idx].u.kr);
    break;
  case KEYDB_RESOURCE_TYPE_KEYBOX:
    s = keybox_get_resource_name(hd->active[idx].u.kb);
    break;
  }
  return s ? s : "";
}

