static int dissect_udvm_literal_operand(tvbuff_t *udvm_tvb,
                                        proto_tree *sigcomp_udvm_tree,
                                        gint offset, gint *start_offset,
                                        guint16 *value) {
  guint bytecode;
  guint16 operand;
  guint test_bits;
  guint display_bytecode;
  bytecode = tvb_get_guint8(udvm_tvb, offset);
  test_bits = bytecode >> 7;
  if (test_bits == 1) {
    test_bits = bytecode >> 6;
    if (test_bits == 2) {
      display_bytecode = bytecode & 0xc0;
      if (display_udvm_bytecode)
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_literal_bytecode,
                            udvm_tvb, offset, 1, display_bytecode);
      operand = tvb_get_ntohs(udvm_tvb, offset) & 0x3fff;
      *value = operand;
      *start_offset = offset;
      offset = offset + 2;
    } else {
      display_bytecode = bytecode & 0xc0;
      if (display_udvm_bytecode)
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_literal_bytecode,
                            udvm_tvb, offset, 1, display_bytecode);
      offset++;
      operand = tvb_get_ntohs(udvm_tvb, offset);
      *value = operand;
      *start_offset = offset;
      offset = offset + 2;
    }
  } else {
    display_bytecode = bytecode & 0xc0;
    if (display_udvm_bytecode)
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_literal_bytecode, udvm_tvb,
                          offset, 1, display_bytecode);
    operand = (bytecode & 0x7f);
    *value = operand;
    *start_offset = offset;
    offset++;
  }
  return offset;
}

int uwsgi_php_init(void) {
  struct uwsgi_string_list *pset = uphp.set;
  struct uwsgi_string_list *append_config = uphp.append_config;
#ifdef ZTS tsrm_startup(1, 1, 0, NULL);
#endif sapi_startup(&uwsgi_sapi_module);
  while (append_config) {
    uwsgi_php_append_config(append_config->value);
    append_config = append_config->next;
  }
  while (pset) {
    uwsgi_php_set(pset->value);
    pset = pset->next;
  }
  if (uphp.dump_config) {
    uwsgi_log("--- PHP custom config ---\n\n");
    uwsgi_log("%s\n", uwsgi_sapi_module.ini_entries);
    uwsgi_log("--- end of PHP custom config ---\n");
  }
  if (uphp.docroot) {
    char *orig_docroot = uphp.docroot;
    uphp.docroot = uwsgi_expand_path(uphp.docroot, strlen(uphp.docroot), NULL);
    if (!uphp.docroot) {
      uwsgi_log("unable to set php docroot to %s\n", orig_docroot);
      exit(1);
    }
    uwsgi_log("PHP document root set to %s\n", uphp.docroot);
    uphp.docroot_len = strlen(uphp.docroot);
  }
  if (uphp.sapi_name) {
    uwsgi_sapi_module.name = uphp.sapi_name;
  }
  uwsgi_sapi_module.startup(&uwsgi_sapi_module);
  uwsgi_log("PHP %s initialized\n", PHP_VERSION);
  return 0;
}

static void kq_dealloc(struct event_base *base, void *arg) {
  struct kqop *kqop = arg;
  if (kqop->changes)
    free(kqop->changes);
  if (kqop->events)
    free(kqop->events);
  if (kqop->kq >= 0 && kqop->pid == getpid())
    close(kqop->kq);
  memset(kqop, 0, sizeof(struct kqop));
  free(kqop);
}

