static void icc_base_conv_pixmap(fz_context *ctx, fz_pixmap *dst,
                                 fz_pixmap *src, fz_colorspace *prf,
                                 const fz_default_colorspaces *default_cs,
                                 const fz_color_params *color_params,
                                 int copy_spots) {
  fz_colorspace *srcs = src->colorspace;
  fz_colorspace *base_cs = get_base_icc_space(ctx, srcs);
  int i, j;
  unsigned char *inputpos, *outputpos;
  fz_pixmap *base;
  fz_irect bbox;
  int h, len;
  float src_f[FZ_MAX_COLORS], des_f[FZ_MAX_COLORS];
  int sn = src->n;
  int sc = sn - src->alpha - src->s;
  int stride_src = src->stride - src->w * sn;
  int stride_base;
  int bn, bc;
  base = fz_new_pixmap_with_bbox(ctx, base_cs, fz_pixmap_bbox(ctx, src, &bbox),
                                 src->seps, src->alpha);
  bn = base->n;
  bc = base->n - base->alpha - base->s;
  stride_base = base->stride - base->w * bn;
  inputpos = src->samples;
  outputpos = base->samples;
  h = src->h;
  while (h--) {
    len = src->w;
    while (len--) {
      for (i = 0; i < sc; i++)
        src_f[i] = (float)inputpos[i] / 255.0f;
      convert_to_icc_base(ctx, srcs, src_f, des_f);
      base_cs->clamp(base_cs, des_f, des_f);
      for (j = 0; j < bc; j++)
        outputpos[j] = des_f[j] * 255.0f;
      for (; i < sn; i++, j++)
        outputpos[j] = inputpos[i];
      outputpos += bn;
      inputpos += sn;
    }
    outputpos += stride_base;
    inputpos += stride_src;
  }
  fz_try(ctx) icc_conv_pixmap(ctx, dst, base, prf, default_cs, color_params,
                              copy_spots);
  fz_always(ctx) fz_drop_pixmap(ctx, base);
  fz_catch(ctx) fz_rethrow(ctx);
}

static int g722_decode_frame(AVCodecContext *avctx, void *data,
                             int *got_frame_ptr, AVPacket *avpkt) {
  G722Context *c = avctx->priv_data;
  AVFrame *frame = data;
  int16_t *out_buf;
  int j, ret;
  const int skip = 8 - c->bits_per_codeword;
  const int16_t *quantizer_table = low_inv_quants[skip];
  GetBitContext gb;
  frame->nb_samples = avpkt->size * 2;
  if ((ret = ff_get_buffer(avctx, frame)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  out_buf = (int16_t *)frame->data[0];
  init_get_bits(&gb, avpkt->data, avpkt->size * 8);
  for (j = 0; j < avpkt->size; j++) {
    int ilow, ihigh, rlow, rhigh, dhigh;
    int xout1, xout2;
    ihigh = get_bits(&gb, 2);
    ilow = get_bits(&gb, 6 - skip);
    skip_bits(&gb, skip);
    rlow = av_clip((c->band[0].scale_factor * quantizer_table[ilow] >> 10) +
                       c->band[0].s_predictor,
                   -16384, 16383);
    ff_g722_update_low_predictor(&c->band[0], ilow >> (2 - skip));
    dhigh = c->band[1].scale_factor * ff_g722_high_inv_quant[ihigh] >> 10;
    rhigh = av_clip(dhigh + c->band[1].s_predictor, -16384, 16383);
    ff_g722_update_high_predictor(&c->band[1], dhigh, ihigh);
    c->prev_samples[c->prev_samples_pos++] = rlow + rhigh;
    c->prev_samples[c->prev_samples_pos++] = rlow - rhigh;
    ff_g722_apply_qmf(c->prev_samples + c->prev_samples_pos - 24, &xout1,
                      &xout2);
    *out_buf++ = av_clip_int16(xout1 >> 11);
    *out_buf++ = av_clip_int16(xout2 >> 11);
    if (c->prev_samples_pos >= PREV_SAMPLES_BUF_SIZE) {
      memmove(c->prev_samples, c->prev_samples + c->prev_samples_pos - 22,
              22 * sizeof(c->prev_samples[0]));
      c->prev_samples_pos = 22;
    }
  }
  *got_frame_ptr = 1;
  return avpkt->size;
}

