}

static void synthesis(AMRWBContext *ctx, float *lpc, float *excitation,
                      float fixed_gain, const float *fixed_vector,
                      float *samples) {
  ff_weighted_vector_sumf(excitation, ctx->pitch_vector, fixed_vector,
                          ctx->pitch_gain[0], fixed_gain, AMRWB_SFR_SIZE);
  if (ctx->pitch_gain[0] > 0.5 && ctx->fr_cur_mode <= MODE_8k85) {
    int i;
    float energy =
        avpriv_scalarproduct_float_c(excitation, excitation, AMRWB_SFR_SIZE);
    float pitch_factor = 0.25 * ctx->pitch_gain[0] * ctx->pitch_gain[0];
    for (i = 0; i < AMRWB_SFR_SIZE; i++)
      excitation[i] += pitch_factor * ctx->pitch_vector[i];
    ff_scale_vector_to_given_sum_of_squares(excitation, excitation, energy,
                                            AMRWB_SFR_SIZE);
  }
  ff_celp_lp_synthesis_filterf(samples, lpc, excitation, AMRWB_SFR_SIZE,
                               LP_ORDER);
}

afs_int32 listOwned(struct rx_call *call, afs_int32 aid, prlist *alist,
                    afs_int32 *lastP, afs_int32 *cid) {
  afs_int32 code;
  struct ubik_trans *tt;
  struct prentry tentry;
  afs_int32 head = 0;
  afs_int32 start;
  alist->prlist_len = 0;
  alist->prlist_val = NULL;
  if (!lastP)
    return PRBADARG;
  start = *lastP;
  *lastP = 0;
  code = Initdb();
  if (code != PRSUCCESS)
    return code;
  code = ubik_BeginTransReadAny(dbase, UBIK_READTRANS, &tt);
  if (code)
    return code;
  code = ubik_SetLock(tt, 1, 1, LOCKREAD);
  if (code)
    ABORT_WITH(tt, code);
  code = read_DbHeader(tt);
  if (code)
    ABORT_WITH(tt, code);
  code = WhoIsThis(call, tt, cid);
  if (code)
    ABORT_WITH(tt, PRPERM);
  if (start) {
    code = pr_ReadEntry(tt, 0, start, &tentry);
    if (!code && (tentry.owner == aid))
      head = start;
  }
  if (!head) {
    if (aid) {
      afs_int32 loc = FindByID(tt, aid);
      if (loc == 0)
        ABORT_WITH(tt, PRNOENT);
      code = pr_ReadEntry(tt, 0, loc, &tentry);
      if (code)
        ABORT_WITH(tt, code);
      if (!AccessOK(tt, *cid, &tentry, -1, PRP_OWNED_ANY))
        ABORT_WITH(tt, PRPERM);
      head = tentry.owned;
    } else {
      if (!AccessOK(tt, *cid, 0, 0, 0))
        ABORT_WITH(tt, PRPERM);
      head = ntohl(cheader.orphan);
    }
  }
  code = GetOwnedChain(tt, &head, alist);
  if (code) {
    if (code == PRTOOMANY)
      *lastP = head;
    else
      ABORT_WITH(tt, code);
  }
  code = ubik_EndTrans(tt);
  return code;
}

static bool check_grant_db_routine(THD *thd, const char *db, HASH *hash) {
  Security_context *sctx = thd->security_ctx;
  for (uint idx = 0; idx < hash->records; ++idx) {
    GRANT_NAME *item = (GRANT_NAME *)hash_element(hash, idx);
    if (strcmp(item->user, sctx->priv_user) == 0 && strcmp(item->db, db) == 0 &&
        compare_hostname(&item->host, sctx->host, sctx->ip)) {
      return FALSE;
    }
  }
  return TRUE;
}

static void sig_message_own_public(SERVER_REC *server, const char *msg,
                                   const char *target, const char *origtarget) {
  CHANNEL_REC *channel;
  NICK_REC *nick;
  char *p, *msgnick;
  g_return_if_fail(server != NULL);
  g_return_if_fail(msg != NULL);
  if (target == NULL)
    return;
  channel = channel_find(server, target);
  if (channel == NULL)
    return;
  p = strchr(msg, ' ');
  if (p != NULL && p != msg) {
    msgnick = g_strndup(msg, (int)(p - msg));
    nick = nicklist_find(channel, msgnick);
    if (nick == NULL && msgnick[1] != '\0') {
      msgnick[strlen(msgnick) - 1] = '\0';
      nick = nicklist_find(channel, msgnick);
    }
    g_free(msgnick);
    if (nick != NULL && nick != channel->ownnick)
      CHANNEL_LAST_MSG_ADD(channel, nick->nick, TRUE);
  }
}

