static void pk_transaction_search_files(PkTransaction *transaction,
                                        GVariant *params,
                                        GDBusMethodInvocation *context) {
  gboolean ret;
  guint i;
  PkBitfield filter;
  g_autofree gchar **values = NULL;
  g_autoptr(GError) error = NULL;
  g_return_if_fail(PK_IS_TRANSACTION(transaction));
  g_return_if_fail(transaction->priv->tid != NULL);
  g_variant_get(params, "(t^a&s)", &filter, &values);
  g_debug("SearchFiles method called: %" G_GUINT64_FORMAT ", %s", filter,
          values[0]);
  if (!pk_backend_is_implemented(transaction->priv->backend,
                                 PK_ROLE_ENUM_SEARCH_FILE)) {
    g_set_error(&error, PK_TRANSACTION_ERROR,
                PK_TRANSACTION_ERROR_NOT_SUPPORTED,
                "SearchFiles not supported by backend");
    pk_transaction_set_state(transaction, PK_TRANSACTION_STATE_ERROR);
    goto out;
  }
  ret = pk_transaction_search_check(values, &error);
  if (!ret) {
    pk_transaction_set_state(transaction, PK_TRANSACTION_STATE_ERROR);
    goto out;
  }
  for (i = 0; values[i] != NULL; i++) {
    if (values[i][0] != '/' && strstr(values[i], "/") != NULL) {
      g_set_error(&error, PK_TRANSACTION_ERROR,
                  PK_TRANSACTION_ERROR_SEARCH_PATH_INVALID,
                  "Invalid search path");
      pk_transaction_set_state(transaction, PK_TRANSACTION_STATE_ERROR);
      goto out;
    }
  }
  transaction->priv->cached_filters = filter;
  transaction->priv->cached_values = g_strdupv(values);
  pk_transaction_set_role(transaction, PK_ROLE_ENUM_SEARCH_FILE);
  pk_transaction_set_state(transaction, PK_TRANSACTION_STATE_READY);
out:
  pk_transaction_dbus_return(context, error);
}

static int bfi_decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                            AVPacket *avpkt) {
  GetByteContext g;
  int buf_size = avpkt->size;
  BFIContext *bfi = avctx->priv_data;
  uint8_t *dst = bfi->dst;
  uint8_t *src, *dst_offset, colour1, colour2;
  uint8_t *frame_end = bfi->dst + avctx->width * avctx->height;
  uint32_t *pal;
  int i, j, ret, height = avctx->height;
  if (bfi->frame.data[0])
    avctx->release_buffer(avctx, &bfi->frame);
  bfi->frame.reference = 1;
  if ((ret = ff_get_buffer(avctx, &bfi->frame)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  bytestream2_init(&g, avpkt->data, buf_size);
  if (!avctx->frame_number) {
    bfi->frame.pict_type = AV_PICTURE_TYPE_I;
    bfi->frame.key_frame = 1;
    if (avctx->extradata_size > 768) {
      av_log(NULL, AV_LOG_ERROR, "Palette is too large.\n");
      return AVERROR_INVALIDDATA;
    }
    pal = (uint32_t *)bfi->frame.data[1];
    for (i = 0; i < avctx->extradata_size / 3; i++) {
      int shift = 16;
      *pal = 0;
      for (j = 0; j < 3; j++, shift -= 8)
        *pal += ((avctx->extradata[i * 3 + j] << 2) |
                 (avctx->extradata[i * 3 + j] >> 4))
                << shift;
      pal++;
    }
    bfi->frame.palette_has_changed = 1;
  } else {
    bfi->frame.pict_type = AV_PICTURE_TYPE_P;
    bfi->frame.key_frame = 0;
  }
  bytestream2_skip(&g, 4);
  while (dst != frame_end) {
    static const uint8_t lentab[4] = {0, 2, 0, 1};
    unsigned int byte = bytestream2_get_byte(&g), av_uninit(offset);
    unsigned int code = byte >> 6;
    unsigned int length = byte & ~0xC0;
    if (!bytestream2_get_bytes_left(&g)) {
      av_log(avctx, AV_LOG_ERROR,
             "Input resolution larger than actual frame.\n");
      return AVERROR_INVALIDDATA;
    }
    if (length == 0) {
      if (code == 1) {
        length = bytestream2_get_byte(&g);
        offset = bytestream2_get_le16(&g);
      } else {
        length = bytestream2_get_le16(&g);
        if (code == 2 && length == 0)
          break;
      }
    } else {
      if (code == 1)
        offset = bytestream2_get_byte(&g);
    }
    if (dst + (length << lentab[code]) > frame_end)
      break;
    switch (code) {
    case 0:
      if (length >= bytestream2_get_bytes_left(&g)) {
        av_log(avctx, AV_LOG_ERROR, "Frame larger than buffer.\n");
        return AVERROR_INVALIDDATA;
      }
      bytestream2_get_buffer(&g, dst, length);
      dst += length;
      break;
    case 1:
      dst_offset = dst - offset;
      length *= 4;
      if (dst_offset < bfi->dst)
        break;
      while (length--)
        *dst++ = *dst_offset++;
      break;
    case 2:
      dst += length;
      break;
    case 3:
      colour1 = bytestream2_get_byte(&g);
      colour2 = bytestream2_get_byte(&g);
      while (length--) {
        *dst++ = colour1;
        *dst++ = colour2;
      }
      break;
    }
  }
  src = bfi->dst;
  dst = bfi->frame.data[0];
  while (height--) {
    memcpy(dst, src, avctx->width);
    src += avctx->width;
    dst += bfi->frame.linesize[0];
  }
  *got_frame = 1;
  *(AVFrame *)data = bfi->frame;
  return buf_size;
}

static void UConverter_toUnicode_HZ_OFFSETS_LOGIC(UConverterToUnicodeArgs *args,
                                                  UErrorCode *err) {
  char tempBuf[2];
  const char *mySource = (char *)args->source;
  UChar *myTarget = args->target;
  const char *mySourceLimit = args->sourceLimit;
  UChar32 targetUniChar = 0x0000;
  int32_t mySourceChar = 0x0000;
  UConverterDataHZ *myData = (UConverterDataHZ *)(args->converter->extraInfo);
  tempBuf[0] = 0;
  tempBuf[1] = 0;
  while (mySource < mySourceLimit) {
    if (myTarget < args->targetLimit) {
      mySourceChar = (unsigned char)*mySource++;
      if (args->converter->mode == UCNV_TILDE) {
        args->converter->mode = 0;
        switch (mySourceChar) {
        case 0x0A:
          continue;
        case UCNV_TILDE:
          if (args->offsets) {
            args->offsets[myTarget - args->target] =
                (int32_t)(mySource - args->source - 2);
          }
          *(myTarget++) = (UChar)mySourceChar;
          myData->isEmptySegment = FALSE;
          continue;
        case UCNV_OPEN_BRACE:
        case UCNV_CLOSE_BRACE:
          myData->isStateDBCS = (mySourceChar == UCNV_OPEN_BRACE);
          if (myData->isEmptySegment) {
            myData->isEmptySegment = FALSE;
            *err = U_ILLEGAL_ESCAPE_SEQUENCE;
            args->converter->toUCallbackReason = UCNV_IRREGULAR;
            args->converter->toUBytes[0] = UCNV_TILDE;
            args->converter->toUBytes[1] = mySourceChar;
            args->converter->toULength = 2;
            args->target = myTarget;
            args->source = mySource;
            return;
          }
          myData->isEmptySegment = TRUE;
          continue;
        default:
          myData->isEmptySegment = FALSE;
          *err = U_ILLEGAL_ESCAPE_SEQUENCE;
          args->converter->toUBytes[0] = UCNV_TILDE;
          if (myData->isStateDBCS
                  ? (0x21 <= mySourceChar && mySourceChar <= 0x7e)
                  : mySourceChar <= 0x7f) {
            args->converter->toULength = 1;
            --mySource;
          } else {
            args->converter->toUBytes[1] = mySourceChar;
            args->converter->toULength = 2;
          }
          args->target = myTarget;
          args->source = mySource;
          return;
        }
      } else if (myData->isStateDBCS) {
        if (args->converter->toUnicodeStatus == 0x00) {
          if (mySourceChar == UCNV_TILDE) {
            args->converter->mode = UCNV_TILDE;
          } else {
            args->converter->toUnicodeStatus = (uint32_t)(mySourceChar | 0x100);
            myData->isEmptySegment = FALSE;
          }
          continue;
        } else {
          int leadIsOk, trailIsOk;
          uint32_t leadByte = args->converter->toUnicodeStatus & 0xff;
          targetUniChar = 0xffff;
          leadIsOk = (uint8_t)(leadByte - 0x21) <= (0x7d - 0x21);
          trailIsOk = (uint8_t)(mySourceChar - 0x21) <= (0x7e - 0x21);
          if (leadIsOk && trailIsOk) {
            tempBuf[0] = (char)(leadByte + 0x80);
            tempBuf[1] = (char)(mySourceChar + 0x80);
            targetUniChar = ucnv_MBCSSimpleGetNextUChar(
                myData->gbConverter->sharedData, tempBuf, 2,
                args->converter->useFallback);
            mySourceChar = (leadByte << 8) | mySourceChar;
          } else if (trailIsOk) {
            --mySource;
            mySourceChar = (int32_t)leadByte;
          } else {
            mySourceChar = 0x10000 | (leadByte << 8) | mySourceChar;
          }
          args->converter->toUnicodeStatus = 0x00;
        }
      } else {
        if (mySourceChar == UCNV_TILDE) {
          args->converter->mode = UCNV_TILDE;
          continue;
        } else if (mySourceChar <= 0x7f) {
          targetUniChar = (UChar)mySourceChar;
          myData->isEmptySegment = FALSE;
        } else {
          targetUniChar = 0xffff;
          myData->isEmptySegment = FALSE;
        }
      }
      if (targetUniChar < 0xfffe) {
        if (args->offsets) {
          args->offsets[myTarget - args->target] =
              (int32_t)(mySource - args->source - 1 - (myData->isStateDBCS));
        }
        *(myTarget++) = (UChar)targetUniChar;
      } else {
        if (targetUniChar == 0xfffe) {
          *err = U_INVALID_CHAR_FOUND;
        } else {
          *err = U_ILLEGAL_CHAR_FOUND;
        }
        if (mySourceChar > 0xff) {
          args->converter->toUBytes[0] = (uint8_t)(mySourceChar >> 8);
          args->converter->toUBytes[1] = (uint8_t)mySourceChar;
          args->converter->toULength = 2;
        } else {
          args->converter->toUBytes[0] = (uint8_t)mySourceChar;
          args->converter->toULength = 1;
        }
        break;
      }
    } else {
      *err = U_BUFFER_OVERFLOW_ERROR;
      break;
    }
  }
  args->target = myTarget;
  args->source = mySource;
}

static int sort_delete_record(MI_SORT_PARAM *sort_param) {
  uint i;
  int old_file, error;
  uchar *key;
  SORT_INFO *sort_info = sort_param->sort_info;
  MI_CHECK *param = sort_info->param;
  MI_INFO *info = sort_info->info;
  DBUG_ENTER("sort_delete_record");
  if ((param->testflag & (T_FORCE_UNIQUENESS | T_QUICK)) == T_QUICK) {
 mi_check_print_error ( param , "Quick-recover aborted;
 Run recovery without switch -q or with switch -qq" ) ;
 DBUG_RETURN ( 1 ) ;
  }
  if (info->s->options & HA_OPTION_COMPRESS_RECORD) {
 mi_check_print_error ( param , "Recover aborted;
 Can't run standard recovery on compressed tables with errors in data-file. Use switch 'myisamchk --safe-recover' to fix it\n" , stderr ) ;
 ;
 DBUG_RETURN ( 1 ) ;
  }
  old_file = info->dfile;
  info->dfile = info->rec_cache.file;
  if (sort_info->current_key) {
    key = info->lastkey + info->s->base.max_key_length;
    if ((error = (*info->s->read_rnd)(info, sort_param->record, info->lastpos,
                                      0)) &&
        error != HA_ERR_RECORD_DELETED) {
      mi_check_print_error(param, "Can't read record to be removed");
      info->dfile = old_file;
      DBUG_RETURN(1);
    }
    for (i = 0; i < sort_info->current_key; i++) {
      uint key_length =
          _mi_make_key(info, i, key, sort_param->record, info->lastpos);
      if (_mi_ck_delete(info, i, key, key_length)) {
        mi_check_print_error(
            param, "Can't delete key %d from record to be removed", i + 1);
        info->dfile = old_file;
        DBUG_RETURN(1);
      }
    }
    if (sort_param->calc_checksum)
      param->glob_crc -= (*info->s->calc_checksum)(info, sort_param->record);
  }
  error = flush_io_cache(&info->rec_cache) || (*info->s->delete_record)(info);
  info->dfile = old_file;
  info->state->records--;
  DBUG_RETURN(error);
}

