static void truespeech_synth(TSContext *dec, int16_t *out, int quart) {
  int i, k;
  int t[8];
  int16_t *ptr0, *ptr1;
  ptr0 = dec->tmp1;
  ptr1 = dec->filters + quart * 8;
  for (i = 0; i < 60; i++) {
    int sum = 0;
    for (k = 0; k < 8; k++)
      sum += ptr0[k] * ptr1[k];
    sum = (sum + (out[i] << 12) + 0x800) >> 12;
    out[i] = av_clip(sum, -0x7FFE, 0x7FFE);
    for (k = 7; k > 0; k--)
      ptr0[k] = ptr0[k - 1];
    ptr0[0] = out[i];
  }
  for (i = 0; i < 8; i++)
    t[i] = (ts_decay_35_64[i] * ptr1[i]) >> 15;
  ptr0 = dec->tmp2;
  for (i = 0; i < 60; i++) {
    int sum = 0;
    for (k = 0; k < 8; k++)
      sum += ptr0[k] * t[k];
    for (k = 7; k > 0; k--)
      ptr0[k] = ptr0[k - 1];
    ptr0[0] = out[i];
    out[i] = ((out[i] << 12) - sum) >> 12;
  }
  for (i = 0; i < 8; i++)
    t[i] = (ts_decay_3_4[i] * ptr1[i]) >> 15;
  ptr0 = dec->tmp3;
  for (i = 0; i < 60; i++) {
    int sum = out[i] << 12;
    for (k = 0; k < 8; k++)
      sum += ptr0[k] * t[k];
    for (k = 7; k > 0; k--)
      ptr0[k] = ptr0[k - 1];
    ptr0[0] = av_clip((sum + 0x800) >> 12, -0x7FFE, 0x7FFE);
    sum = ((ptr0[1] * (dec->filtval - (dec->filtval >> 2))) >> 4) + sum;
    sum = sum - (sum >> 3);
    out[i] = av_clip((sum + 0x800) >> 12, -0x7FFE, 0x7FFE);
  }
}

static void decode_6p_track(int *out, int code, int m, int off) {
  int b_offset = 1 << (m - 1);
  int half_more = BIT_POS(code, 6 * m - 5) << (m - 1);
  int half_other = b_offset - half_more;
  switch (BIT_STR(code, 6 * m - 4, 2)) {
  case 0:
    decode_1p_track(out, BIT_STR(code, 0, m), m - 1, off + half_more);
    decode_5p_track(out + 1, BIT_STR(code, m, 5 * m - 5), m - 1,
                    off + half_more);
    break;
  case 1:
    decode_1p_track(out, BIT_STR(code, 0, m), m - 1, off + half_other);
    decode_5p_track(out + 1, BIT_STR(code, m, 5 * m - 5), m - 1,
                    off + half_more);
    break;
  case 2:
    decode_2p_track(out, BIT_STR(code, 0, 2 * m - 1), m - 1, off + half_other);
    decode_4p_track(out + 2, BIT_STR(code, 2 * m - 1, 4 * m - 4), m - 1,
                    off + half_more);
    break;
  case 3:
    decode_3p_track(out, BIT_STR(code, 3 * m - 2, 3 * m - 2), m - 1, off);
    decode_3p_track(out + 3, BIT_STR(code, 0, 3 * m - 2), m - 1,
                    off + b_offset);
    break;
  }
}

static int SRP_user_pwd_set_sv(SRP_user_pwd *vinfo, const char *s,
                               const char *v) {
  unsigned char tmp[MAX_LEN];
