void jpc_ft_fwdlift_col(jpc_fix_t *a, int numrows, int stride, int parity) {
  jpc_fix_t *lptr;
  jpc_fix_t *hptr;
#if 0 register jpc_fix_t * lptr2;
 register jpc_fix_t * hptr2 ;
 register int i ;
#endif register int n;
  int llen;
  llen = (numrows + 1 - parity) >> 1;
  if (numrows > 1) {
    lptr = &a[0];
    hptr = &a[llen * stride];
    if (parity) {
      hptr[0] -= lptr[0];
      hptr += stride;
    }
    n = numrows - llen - parity - (parity == (numrows & 1));
    while (n-- > 0) {
      hptr[0] -= jpc_fix_asr(lptr[0] + lptr[stride], 1);
      hptr += stride;
      lptr += stride;
    }
    if (parity == (numrows & 1)) {
      hptr[0] -= lptr[0];
    }
    lptr = &a[0];
    hptr = &a[llen * stride];
    if (!parity) {
      lptr[0] += jpc_fix_asr(hptr[0] + 1, 1);
      lptr += stride;
    }
    n = llen - (!parity) - (parity != (numrows & 1));
    while (n-- > 0) {
      lptr[0] += jpc_fix_asr(hptr[0] + hptr[stride] + 2, 2);
      lptr += stride;
      hptr += stride;
    }
    if (parity != (numrows & 1)) {
      lptr[0] += jpc_fix_asr(hptr[0] + 1, 1);
    }
  } else {
    if (parity) {
      lptr = &a[0];
      lptr[0] = jpc_fix_asl(lptr[0], 1);
    }
  }
}

static cmsBool WriteOneWChar(cmsIOHANDLER *io, _cmsDICelem *e,
                             cmsUInt32Number i, const wchar_t *wcstr,
                             cmsUInt32Number BaseOffset) {
  cmsUInt32Number Before = io->Tell(io);
  cmsUInt32Number n;
  e->Offsets[i] = Before - BaseOffset;
  if (wcstr == NULL) {
    e->Sizes[i] = 0;
    e->Offsets[i] = 0;
    return TRUE;
  }
  n = mywcslen(wcstr);
  if (!_cmsWriteWCharArray(io, n, wcstr))
    return FALSE;
  e->Sizes[i] = io->Tell(io) - Before;
  return TRUE;
}

static void loosen_unused_packed_objects(struct rev_info *revs) {
  struct packed_git *p;
  uint32_t i;
  const unsigned char *sha1;
  for (p = packed_git; p; p = p->next) {
    if (!p->pack_local || p->pack_keep)
      continue;
    if (open_pack_index(p))
      die("cannot open pack index");
    for (i = 0; i < p->num_objects; i++) {
      sha1 = nth_packed_object_sha1(p, i);
      if (!packlist_find(&to_pack, sha1, NULL) &&
          !has_sha1_pack_kept_or_nonlocal(sha1) &&
          !loosened_object_can_be_discarded(sha1, p->mtime))
        if (force_object_loose(sha1, p->mtime))
          die("unable to force loose object");
    }
  }
}

