static void set_ref(VP9_COMMON *const cm, MACROBLOCKD *const xd, int idx,
                    int mi_row, int mi_col) {
  MB_MODE_INFO *const mbmi = &xd->mi[0].src_mi->mbmi;
  RefBuffer *ref_buffer = &cm->frame_refs[mbmi->ref_frame[idx] - LAST_FRAME];
  xd->block_refs[idx] = ref_buffer;
  if (!vp9_is_valid_scale(&ref_buffer->sf))
    vpx_internal_error(&cm->error, VPX_CODEC_UNSUP_BITSTREAM,
                       "Invalid scale factors");
  if (ref_buffer->buf->corrupted)
    vpx_internal_error(&cm->error, VPX_CODEC_CORRUPT_FRAME,
                       "Block reference is corrupt");
  vp9_setup_pre_planes(xd, idx, ref_buffer->buf, mi_row, mi_col,
                       &ref_buffer->sf);
  xd->corrupted |= ref_buffer->buf->corrupted;
}

static int decode_cabac_intra_mb_type(H264Context *h, int ctx_base,
                                      int intra_slice) {
  uint8_t *state = &h->cabac_state[ctx_base];
  int mb_type;
  if (intra_slice) {
    int ctx = 0;
    if (h->left_type[LTOP] & (MB_TYPE_INTRA16x16 | MB_TYPE_INTRA_PCM))
      ctx++;
    if (h->top_type & (MB_TYPE_INTRA16x16 | MB_TYPE_INTRA_PCM))
      ctx++;
    if (get_cabac_noinline(&h->cabac, &state[ctx]) == 0)
      return 0;
    state += 2;
  } else {
    if (get_cabac_noinline(&h->cabac, state) == 0)
      return 0;
  }
  if (get_cabac_terminate(&h->cabac))
    return 25;
  mb_type = 1;
  mb_type += 12 * get_cabac_noinline(&h->cabac, &state[1]);
  if (get_cabac_noinline(&h->cabac, &state[2]))
    mb_type += 4 + 4 * get_cabac_noinline(&h->cabac, &state[2 + intra_slice]);
  mb_type += 2 * get_cabac_noinline(&h->cabac, &state[3 + intra_slice]);
  mb_type += 1 * get_cabac_noinline(&h->cabac, &state[3 + 2 * intra_slice]);
  return mb_type;
}

