void populate_symb(char *header_file) {
  FILE *yh;
  char line[2 * MAX_TOK_LEN];
  char name[2 * MAX_TOK_LEN];
  int token;
  yh = fopen(header_file, "r");
  if (NULL == yh) {
    perror("unable to open yacc/bison header file");
    exit(4);
  }
  while (NULL != fgets(line, sizeof(line), yh))
    if (2 == sscanf(line, "#define %s %d", name, &token) && 'T' == name[0] &&
        '_' == name[1] && token >= 0 && token < COUNTOF(symb)) {
      symb[token] = estrdup(name);
      if (strlen(name) > MAX_TOK_LEN) {
        fprintf(stderr,
                "MAX_TOK_LEN %d too small for '%s'\n"
                "Edit keyword-gen.c to raise.\n",
                MAX_TOK_LEN, name);
        exit(10);
      }
    }
  fclose(yh);
}

static int32_t findUnassigned(UCMStates *states, uint16_t *unicodeCodeUnits,
                              _MBCSToUFallback *toUFallbacks,
                              int32_t countToUFallbacks, int32_t state,
                              int32_t offset, uint32_t b) {
  int32_t i, entry, savings, localSavings, belowSavings;
  UBool haveAssigned;
  localSavings = belowSavings = 0;
  haveAssigned = FALSE;
  for (i = 0; i < 256; ++i) {
    entry = states->stateTable[state][i];
    if (MBCS_ENTRY_IS_TRANSITION(entry)) {
      savings = findUnassigned(
          states, unicodeCodeUnits, toUFallbacks, countToUFallbacks,
          MBCS_ENTRY_TRANSITION_STATE(entry),
          offset + MBCS_ENTRY_TRANSITION_OFFSET(entry), (b << 8) | (uint32_t)i);
      if (savings < 0) {
        haveAssigned = TRUE;
      } else if (savings > 0) {
        printf(" all-unassigned sequences from prefix 0x%02lx state %ld use "
               "%ld bytes\n",
               (unsigned long)((b << 8) | i), (long)state, (long)savings);
        belowSavings += savings;
      }
    } else if (!haveAssigned) {
      switch (MBCS_ENTRY_FINAL_ACTION(entry)) {
      case MBCS_STATE_VALID_16:
        entry = offset + MBCS_ENTRY_FINAL_VALUE_16(entry);
        if (unicodeCodeUnits[entry] == 0xfffe &&
            ucm_findFallback(toUFallbacks, countToUFallbacks, entry) < 0) {
          localSavings += 2;
        } else {
          haveAssigned = TRUE;
        }
        break;
      case MBCS_STATE_VALID_16_PAIR:
        entry = offset + MBCS_ENTRY_FINAL_VALUE_16(entry);
        if (unicodeCodeUnits[entry] == 0xfffe) {
          localSavings += 4;
        } else {
          haveAssigned = TRUE;
        }
        break;
      default:
        break;
      }
    }
  }
  if (haveAssigned) {
    return -1;
  } else {
    return localSavings + belowSavings;
  }
}

