static void e1000e_build_rx_metadata(E1000ECore *core, struct NetRxPkt *pkt,
                                     bool is_eop,
                                     const E1000E_RSSInfo *rss_info,
                                     uint32_t *rss, uint32_t *mrq,
                                     uint32_t *status_flags, uint16_t *ip_id,
                                     uint16_t *vlan_tag) {
  struct virtio_net_hdr *vhdr;
  bool isip4, isip6, istcp, isudp;
  uint32_t pkt_type;
  *status_flags = E1000_RXD_STAT_DD;
  if (!is_eop) {
    goto func_exit;
  }
  *status_flags |= E1000_RXD_STAT_EOP;
  net_rx_pkt_get_protocols(pkt, &isip4, &isip6, &isudp, &istcp);
  trace_e1000e_rx_metadata_protocols(isip4, isip6, isudp, istcp);
  if (net_rx_pkt_is_vlan_stripped(pkt)) {
    *status_flags |= E1000_RXD_STAT_VP;
    *vlan_tag = cpu_to_le16(net_rx_pkt_get_vlan_tag(pkt));
    trace_e1000e_rx_metadata_vlan(*vlan_tag);
  }
  if ((core->mac[RXCSUM] & E1000_RXCSUM_PCSD) != 0) {
    if (rss_info->enabled) {
      *rss = cpu_to_le32(rss_info->hash);
      *mrq = cpu_to_le32(rss_info->type | (rss_info->queue << 8));
      trace_e1000e_rx_metadata_rss(*rss, *mrq);
    }
  } else if (isip4) {
    *status_flags |= E1000_RXD_STAT_IPIDV;
    *ip_id = cpu_to_le16(net_rx_pkt_get_ip_id(pkt));
    trace_e1000e_rx_metadata_ip_id(*ip_id);
  }
  if (istcp && e1000e_is_tcp_ack(core, pkt)) {
    *status_flags |= E1000_RXD_STAT_ACK;
    trace_e1000e_rx_metadata_ack();
  }
  if (isip6 && (core->mac[RFCTL] & E1000_RFCTL_IPV6_DIS)) {
    trace_e1000e_rx_metadata_ipv6_filtering_disabled();
    pkt_type = E1000_RXD_PKT_MAC;
  } else if (istcp || isudp) {
    pkt_type = isip4 ? E1000_RXD_PKT_IP4_XDP : E1000_RXD_PKT_IP6_XDP;
  } else if (isip4 || isip6) {
    pkt_type = isip4 ? E1000_RXD_PKT_IP4 : E1000_RXD_PKT_IP6;
  } else {
    pkt_type = E1000_RXD_PKT_MAC;
  }
  *status_flags |= E1000_RXD_PKT_TYPE(pkt_type);
  trace_e1000e_rx_metadata_pkt_type(pkt_type);
  if (isip6 && (core->mac[RFCTL] & E1000_RFCTL_IPV6_XSUM_DIS)) {
    trace_e1000e_rx_metadata_ipv6_sum_disabled();
    goto func_exit;
  }
  if (!net_rx_pkt_has_virt_hdr(pkt)) {
    trace_e1000e_rx_metadata_no_virthdr();
    e1000e_verify_csum_in_sw(core, pkt, status_flags, istcp, isudp);
    goto func_exit;
  }
  vhdr = net_rx_pkt_get_vhdr(pkt);
  if (!(vhdr->flags & VIRTIO_NET_HDR_F_DATA_VALID) &&
      !(vhdr->flags & VIRTIO_NET_HDR_F_NEEDS_CSUM)) {
    trace_e1000e_rx_metadata_virthdr_no_csum_info();
    e1000e_verify_csum_in_sw(core, pkt, status_flags, istcp, isudp);
    goto func_exit;
  }
  if (e1000e_rx_l3_cso_enabled(core)) {
    *status_flags |= isip4 ? E1000_RXD_STAT_IPCS : 0;
  } else {
    trace_e1000e_rx_metadata_l3_cso_disabled();
  }
  if (e1000e_rx_l4_cso_enabled(core)) {
    if (istcp) {
      *status_flags |= E1000_RXD_STAT_TCPCS;
    } else if (isudp) {
      *status_flags |= E1000_RXD_STAT_TCPCS | E1000_RXD_STAT_UDPCS;
    }
  } else {
    trace_e1000e_rx_metadata_l4_cso_disabled();
  }
  trace_e1000e_rx_metadata_status_flags(*status_flags);
func_exit:
  *status_flags = cpu_to_le32(*status_flags);
}

static hb_bool_t hb_icu_unicode_compose(hb_unicode_funcs_t *ufuncs HB_UNUSED,
                                        hb_codepoint_t a, hb_codepoint_t b,
                                        hb_codepoint_t *ab,
                                        void *user_data HB_UNUSED) {
#if U_ICU_VERSION_MAJOR_NUM >= 49 {
  UChar32 ret = unorm2_composePair(normalizer, a, b);
  if (ret < 0)
    return false;
  *ab = ret;
  return true;
}
#endif UChar utf16[4], normalized[5];
unsigned int len;
hb_bool_t ret, err;
UErrorCode icu_err;
len = 0;
err = false;
U16_APPEND(utf16, len, ARRAY_LENGTH(utf16), a, err);
if (err)
  return false;
U16_APPEND(utf16, len, ARRAY_LENGTH(utf16), b, err);
if (err)
  return false;
icu_err = U_ZERO_ERROR;
len = unorm_normalize(utf16, len, UNORM_NFC, 0, normalized,
                      ARRAY_LENGTH(normalized), &icu_err);
if (U_FAILURE(icu_err))
  return false;
if (u_countChar32(normalized, len) == 1) {
  U16_GET_UNSAFE(normalized, 0, *ab);
  ret = true;
} else {
  ret = false;
}
return ret;
}

void vp8_fast_quantize_b_c(BLOCK *b, BLOCKD *d) {
  int i, rc, eob;
  int x, y, z, sz;
  short *coeff_ptr = b->coeff;
  short *round_ptr = b->round;
  short *quant_ptr = b->quant_fast;
  short *qcoeff_ptr = d->qcoeff;
  short *dqcoeff_ptr = d->dqcoeff;
  short *dequant_ptr = d->dequant;
  eob = -1;
  for (i = 0; i < 16; i++) {
    rc = vp8_default_zig_zag1d[i];
    z = coeff_ptr[rc];
    sz = (z >> 31);
    x = (z ^ sz) - sz;
    y = ((x + round_ptr[rc]) * quant_ptr[rc]) >> 16;
    x = (y ^ sz) - sz;
    qcoeff_ptr[rc] = x;
    dqcoeff_ptr[rc] = x * dequant_ptr[rc];
    if (y) {
      eob = i;
    }
  }
  *d->eob = (char)(eob + 1);
}

static int64_t rd_pick_intra_sby_mode(VP9_COMP *cpi, MACROBLOCK *x, int *rate,
                                      int *rate_tokenonly, int64_t *distortion,
                                      int *skippable, BLOCK_SIZE bsize,
                                      int64_t tx_cache[TX_MODES],
                                      int64_t best_rd) {
  PREDICTION_MODE mode;
  PREDICTION_MODE mode_selected = DC_PRED;
  MACROBLOCKD *const xd = &x->e_mbd;
  MODE_INFO *const mic = xd->mi[0].src_mi;
  int this_rate, this_rate_tokenonly, s;
  int64_t this_distortion, this_rd;
  TX_SIZE best_tx = TX_4X4;
  int i;
  int *bmode_costs = cpi->mbmode_cost;
  if (cpi->sf.tx_size_search_method == USE_FULL_RD)
    for (i = 0; i < TX_MODES; i++)
      tx_cache[i] = INT64_MAX;
  for (mode = DC_PRED; mode <= TM_PRED; mode++) {
    int64_t local_tx_cache[TX_MODES];
    MODE_INFO *above_mi = xd->mi[-xd->mi_stride].src_mi;
    MODE_INFO *left_mi = xd->left_available ? xd->mi[-1].src_mi : NULL;
    if (cpi->common.frame_type == KEY_FRAME) {
      const PREDICTION_MODE A = vp9_above_block_mode(mic, above_mi, 0);
      const PREDICTION_MODE L = vp9_left_block_mode(mic, left_mi, 0);
      bmode_costs = cpi->y_mode_costs[A][L];
    }
    mic->mbmi.mode = mode;
    super_block_yrd(cpi, x, &this_rate_tokenonly, &this_distortion, &s, NULL,
                    bsize, local_tx_cache, best_rd);
    if (this_rate_tokenonly == INT_MAX)
      continue;
    this_rate = this_rate_tokenonly + bmode_costs[mode];
    this_rd = RDCOST(x->rdmult, x->rddiv, this_rate, this_distortion);
    if (this_rd < best_rd) {
      mode_selected = mode;
      best_rd = this_rd;
      best_tx = mic->mbmi.tx_size;
      *rate = this_rate;
      *rate_tokenonly = this_rate_tokenonly;
      *distortion = this_distortion;
      *skippable = s;
    }
    if (cpi->sf.tx_size_search_method == USE_FULL_RD && this_rd < INT64_MAX) {
      for (i = 0; i < TX_MODES && local_tx_cache[i] < INT64_MAX; i++) {
        const int64_t adj_rd =
            this_rd + local_tx_cache[i] - local_tx_cache[cpi->common.tx_mode];
        if (adj_rd < tx_cache[i]) {
          tx_cache[i] = adj_rd;
        }
      }
    }
  }
  mic->mbmi.mode = mode_selected;
  mic->mbmi.tx_size = best_tx;
  return best_rd;
}

static int selinux_msg_queue_associate(struct msg_queue *msq, int msqflg) {
  struct ipc_security_struct *isec;
  struct common_audit_data ad;
  u32 sid = current_sid();
  isec = msq->q_perm.security;
  ad.type = LSM_AUDIT_DATA_IPC;
  ad.u.ipc_id = msq->q_perm.key;
  return avc_has_perm(sid, isec->sid, SECCLASS_MSGQ, MSGQ__ASSOCIATE, &ad);
}

static struct async *reap_as(struct usb_dev_state *ps) {
  DECLARE_WAITQUEUE(wait, current);
  struct async *as = NULL;
  struct usb_device *dev = ps->dev;
  add_wait_queue(&ps->wait, &wait);
  for (;;) {
    __set_current_state(TASK_INTERRUPTIBLE);
    as = async_getcompleted(ps);
    if (as || !connected(ps))
      break;
    if (signal_pending(current))
      break;
    usb_unlock_device(dev);
    schedule();
    usb_lock_device(dev);
  }
  remove_wait_queue(&ps->wait, &wait);
  set_current_state(TASK_RUNNING);
  return as;
}

int vp9_qindex_to_quantizer(int qindex) {
  int quantizer;
  for (quantizer = 0; quantizer < 64; ++quantizer)
    if (quantizer_to_qindex[quantizer] >= qindex)
      return quantizer;
  return 63;
}

int mime_hdr_print(HdrHeap *, MIMEHdrImpl *mh, char *buf_start, int buf_length,
                   int *buf_index_inout, int *buf_chars_to_skip_inout) {
  MIMEFieldBlockImpl *fblock;
  MIMEField *field;
  uint32_t index;
#define SIMPLE_MIME_HDR_PRINT                                                  \
#ifdef SIMPLE_MIME_HDR_PRINT for (fblock = &(mh->m_first_fblock);
  fblock != nullptr;
 fblock = fblock -> m_next ) {
   for (index = 0; index < fblock->m_freetop; index++) {
     field = &(fblock->m_field_slots[index]);
     if (field->is_live()) {
       if (!mime_field_print(field, buf_start, buf_length, buf_index_inout,
                             buf_chars_to_skip_inout)) {
         return 0;
       }
     }
   }
 }
#else for (fblock = &(mh->m_first_fblock);
 fblock != NULL;
 fblock = fblock -> m_next ) {
   const char *contig_start = NULL;
   int this_length, contig_length = 0;
   for (index = 0; index < fblock->m_freetop; index++) {
     field = &(fblock->m_field_slots[index]);
     this_length = field->m_len_name + field->m_len_value +
                   field->m_n_v_raw_printable_pad;
     if (field->is_live()) {
       if ((field->m_ptr_name == contig_start + contig_length) &&
           field->m_n_v_raw_printable &&
           ((buf_index_inout == NULL) ||
            (contig_length + this_length <= buf_length - *buf_index_inout))) {
         contig_length += this_length;
       } else {
         if (contig_length > 0) {
           if (!mime_mem_print(contig_start, contig_length, buf_start,
                               buf_length, buf_index_inout,
                               buf_chars_to_skip_inout))
             return 0;
         }
         contig_start = field->m_ptr_name;
         contig_length = this_length;
       }
     }
   }
   if (contig_length > 0) {
     if (!mime_mem_print(contig_start, contig_length, buf_start, buf_length,
                         buf_index_inout, buf_chars_to_skip_inout))
       return 0;
   }
 }
#endif if (!mime_mem_print("\r\n", 2, buf_start, buf_length, buf_index_inout,  \
                           buf_chars_to_skip_inout)) {
 return 0;
}
return 1;
}

static int mxpeg_decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                              AVPacket *avpkt) {
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  MXpegDecodeContext *s = avctx->priv_data;
  MJpegDecodeContext *jpg = &s->jpg;
  const uint8_t *buf_end, *buf_ptr;
  const uint8_t *unescaped_buf_ptr;
  int unescaped_buf_size;
  int start_code;
  int ret;
  buf_ptr = buf;
  buf_end = buf + buf_size;
  jpg->got_picture = 0;
  s->got_mxm_bitmask = 0;
  while (buf_ptr < buf_end) {
    start_code = ff_mjpeg_find_marker(jpg, &buf_ptr, buf_end,
                                      &unescaped_buf_ptr, &unescaped_buf_size);
    if (start_code < 0)
      goto the_end;
    {
      init_get_bits(&jpg->gb, unescaped_buf_ptr, unescaped_buf_size * 8);
      if (start_code >= APP0 && start_code <= APP15) {
        mxpeg_decode_app(s, unescaped_buf_ptr, unescaped_buf_size);
      }
      switch (start_code) {
      case SOI:
        if (jpg->got_picture)
          goto the_end;
        break;
      case EOI:
        goto the_end;
      case DQT:
        ret = ff_mjpeg_decode_dqt(jpg);
        if (ret < 0) {
          av_log(avctx, AV_LOG_ERROR, "quantization table decode error\n");
          return ret;
        }
        break;
      case DHT:
        ret = ff_mjpeg_decode_dht(jpg);
        if (ret < 0) {
          av_log(avctx, AV_LOG_ERROR, "huffman table decode error\n");
          return ret;
        }
        break;
      case COM:
        ret = mxpeg_decode_com(s, unescaped_buf_ptr, unescaped_buf_size);
        if (ret < 0)
          return ret;
        break;
      case SOF0:
        s->got_sof_data = 0;
        ret = ff_mjpeg_decode_sof(jpg);
        if (ret < 0) {
          av_log(avctx, AV_LOG_ERROR, "SOF data decode error\n");
          return ret;
        }
        if (jpg->interlaced) {
          av_log(avctx, AV_LOG_ERROR,
                 "Interlaced mode not supported in MxPEG\n");
          return AVERROR(EINVAL);
        }
        s->got_sof_data = 1;
        break;
      case SOS:
        if (!s->got_sof_data) {
          av_log(avctx, AV_LOG_WARNING,
                 "Can not process SOS without SOF data, skipping\n");
          break;
        }
        if (!jpg->got_picture) {
          if (jpg->first_picture) {
            av_log(avctx, AV_LOG_WARNING,
                   "First picture has no SOF, skipping\n");
            break;
          }
          if (!s->got_mxm_bitmask) {
            av_log(avctx, AV_LOG_WARNING,
                   "Non-key frame has no MXM, skipping\n");
            break;
          }
          av_frame_unref(jpg->picture_ptr);
          if (ff_get_buffer(avctx, jpg->picture_ptr, AV_GET_BUFFER_FLAG_REF) <
              0) {
            av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
            return AVERROR(ENOMEM);
          }
          jpg->picture_ptr->pict_type = AV_PICTURE_TYPE_P;
          jpg->picture_ptr->key_frame = 0;
          jpg->got_picture = 1;
        } else {
          jpg->picture_ptr->pict_type = AV_PICTURE_TYPE_I;
          jpg->picture_ptr->key_frame = 1;
        }
        if (s->got_mxm_bitmask) {
          AVFrame *reference_ptr = &s->picture[s->picture_index ^ 1];
          if (mxpeg_check_dimensions(s, jpg, reference_ptr) < 0)
            break;
          if (!reference_ptr->data[0] &&
              ff_get_buffer(avctx, reference_ptr, AV_GET_BUFFER_FLAG_REF) < 0) {
            av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
            return AVERROR(ENOMEM);
          }
          ret = ff_mjpeg_decode_sos(jpg, s->mxm_bitmask, reference_ptr);
          if (ret < 0 && (avctx->err_recognition & AV_EF_EXPLODE))
            return ret;
        } else {
          ret = ff_mjpeg_decode_sos(jpg, NULL, NULL);
          if (ret < 0 && (avctx->err_recognition & AV_EF_EXPLODE))
            return ret;
        }
        break;
      }
      buf_ptr += (get_bits_count(&jpg->gb) + 7) >> 3;
    }
  }
the_end:
  if (jpg->got_picture) {
    int ret = av_frame_ref(data, jpg->picture_ptr);
    if (ret < 0)
      return ret;
    *got_frame = 1;
    s->picture_index ^= 1;
    jpg->picture_ptr = &s->picture[s->picture_index];
    if (!s->has_complete_frame) {
      if (!s->got_mxm_bitmask)
        s->has_complete_frame = 1;
      else
        *got_frame = 0;
    }
  }
  return buf_ptr - buf;
}

static cmsBool WriteCLUT(struct _cms_typehandler_struct *self, cmsIOHANDLER *io,
                         cmsUInt8Number Precision, cmsStage *mpe) {
  cmsUInt8Number gridPoints[cmsMAXCHANNELS];
  cmsUInt32Number i;
  _cmsStageCLutData *CLUT = (_cmsStageCLutData *)mpe->Data;
  if (CLUT->HasFloatValues) {
    cmsSignalError(
        self->ContextID, cmsERROR_NOT_SUITABLE,
        "Cannot save floating point data, CLUT are 8 or 16 bit only");
    return FALSE;
  }
  memset(gridPoints, 0, sizeof(gridPoints));
  for (i = 0; i < (cmsUInt32Number)CLUT->Params->nInputs; i++)
    gridPoints[i] = (cmsUInt8Number)CLUT->Params->nSamples[i];
  if (!io->Write(io, cmsMAXCHANNELS * sizeof(cmsUInt8Number), gridPoints))
    return FALSE;
  if (!_cmsWriteUInt8Number(io, (cmsUInt8Number)Precision))
    return FALSE;
  if (!_cmsWriteUInt8Number(io, 0))
    return FALSE;
  if (!_cmsWriteUInt8Number(io, 0))
    return FALSE;
  if (!_cmsWriteUInt8Number(io, 0))
    return FALSE;
  if (Precision == 1) {
    for (i = 0; i < CLUT->nEntries; i++) {
      if (!_cmsWriteUInt8Number(io, FROM_16_TO_8(CLUT->Tab.T[i])))
        return FALSE;
    }
  } else if (Precision == 2) {
    if (!_cmsWriteUInt16Array(io, CLUT->nEntries, CLUT->Tab.T))
      return FALSE;
  } else {
    cmsSignalError(self->ContextID, cmsERROR_UNKNOWN_EXTENSION,
                   "Unknown precision of '%d'", Precision);
    return FALSE;
  }
  if (!_cmsWriteAlignment(io))
    return FALSE;
  return TRUE;
}

void web_server_destroy(void) {
  if (bWebServerState == WEB_SERVER_ENABLED) {
    membuffer_destroy(&gDocumentRootDir);
    alias_release(&gAliasDoc);
    ithread_mutex_lock(&gWebMutex);
    memset(&gAliasDoc, 0, sizeof(struct xml_alias_t));
    ithread_mutex_unlock(&gWebMutex);
    ithread_mutex_destroy(&gWebMutex);
    bWebServerState = WEB_SERVER_DISABLED;
  }
}

rfbBool rfbSendCopyRegion(rfbClientPtr cl, sraRegionPtr reg, int dx, int dy) {
  int x, y, w, h;
  rfbFramebufferUpdateRectHeader rect;
  rfbCopyRect cr;
  sraRectangleIterator *i;
  sraRect rect1;
  i = sraRgnGetReverseIterator(reg, dx > 0, dy > 0);
  dx = ScaleX(cl->screen, cl->scaledScreen, dx);
  dy = ScaleX(cl->screen, cl->scaledScreen, dy);
  while (sraRgnIteratorNext(i, &rect1)) {
    x = rect1.x1;
    y = rect1.y1;
    w = rect1.x2 - x;
    h = rect1.y2 - y;
    rfbScaledCorrection(cl->screen, cl->scaledScreen, &x, &y, &w, &h,
                        "copyrect");
    rect.r.x = Swap16IfLE(x);
    rect.r.y = Swap16IfLE(y);
    rect.r.w = Swap16IfLE(w);
    rect.r.h = Swap16IfLE(h);
    rect.encoding = Swap32IfLE(rfbEncodingCopyRect);
    memcpy(&cl->updateBuf[cl->ublen], (char *)&rect,
           sz_rfbFramebufferUpdateRectHeader);
    cl->ublen += sz_rfbFramebufferUpdateRectHeader;
    cr.srcX = Swap16IfLE(x - dx);
    cr.srcY = Swap16IfLE(y - dy);
    memcpy(&cl->updateBuf[cl->ublen], (char *)&cr, sz_rfbCopyRect);
    cl->ublen += sz_rfbCopyRect;
    rfbStatRecordEncodingSent(cl, rfbEncodingCopyRect,
                              sz_rfbFramebufferUpdateRectHeader +
                                  sz_rfbCopyRect,
                              w * h * (cl->scaledScreen->bitsPerPixel / 8));
  }
  sraRgnReleaseIterator(i);
  return TRUE;
}

static int dissect_usb_video_control_interface_descriptor(
    proto_tree *parent_tree, tvbuff_t *tvb, guint8 descriptor_len,
    packet_info *pinfo, usb_conv_info_t *usb_conv_info) {
  video_conv_info_t *video_conv_info = NULL;
  video_entity_t *entity = NULL;
  proto_item *item = NULL;
  proto_item *subtype_item = NULL;
  proto_tree *tree = NULL;
  guint8 entity_id = 0;
  guint16 terminal_type = 0;
  int offset = 0;
  guint8 subtype;
  subtype = tvb_get_guint8(tvb, offset + 2);
  if (parent_tree) {
    const gchar *subtype_str;
    subtype_str = val_to_str_ext(subtype, &vc_if_descriptor_subtypes_ext,
                                 "Unknown (0x%x)");
    tree = proto_tree_add_subtree_format(
        parent_tree, tvb, offset, descriptor_len, ett_descriptor_video_control,
        &item, "VIDEO CONTROL INTERFACE DESCRIPTOR [%s]", subtype_str);
  }
  dissect_usb_descriptor_header(tree, tvb, offset,
                                &vid_descriptor_type_vals_ext);
  subtype_item = proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_subtype,
                                     tvb, offset + 2, 1, ENC_LITTLE_ENDIAN);
  offset += 3;
  if (subtype == VC_HEADER) {
    guint8 num_vs_interfaces;
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_bcdUVC, tvb, offset, 2,
                        ENC_LITTLE_ENDIAN);
    proto_tree_add_item(tree, hf_usb_vid_ifdesc_wTotalLength, tvb, offset + 2,
                        2, ENC_LITTLE_ENDIAN);
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_dwClockFrequency, tvb,
                        offset + 4, 4, ENC_LITTLE_ENDIAN);
    num_vs_interfaces = tvb_get_guint8(tvb, offset + 8);
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_bInCollection, tvb,
                        offset + 8, 1, ENC_LITTLE_ENDIAN);
    if (num_vs_interfaces > 0) {
      proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_baInterfaceNr, tvb,
                          offset + 9, num_vs_interfaces, ENC_NA);
    }
    offset += 9 + num_vs_interfaces;
  } else if ((subtype == VC_INPUT_TERMINAL) ||
             (subtype == VC_OUTPUT_TERMINAL)) {
    entity_id = tvb_get_guint8(tvb, offset);
    terminal_type = tvb_get_letohs(tvb, offset + 1);
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_terminal_id, tvb,
                        offset, 1, ENC_LITTLE_ENDIAN);
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_terminal_type, tvb,
                        offset + 1, 2, ENC_LITTLE_ENDIAN);
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_assoc_terminal, tvb,
                        offset + 3, 1, ENC_LITTLE_ENDIAN);
    offset += 4;
    if (subtype == VC_OUTPUT_TERMINAL) {
      proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_src_id, tvb, offset,
                          1, ENC_LITTLE_ENDIAN);
      ++offset;
    }
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_iTerminal, tvb, offset,
                        1, ENC_LITTLE_ENDIAN);
    ++offset;
    if (subtype == VC_INPUT_TERMINAL) {
      if (terminal_type == ITT_CAMERA) {
        offset = dissect_usb_video_camera_terminal(tree, tvb, offset);
      } else if (terminal_type == ITT_MEDIA_TRANSPORT_INPUT) {
      }
    }
    if (subtype == VC_OUTPUT_TERMINAL) {
      if (terminal_type == OTT_MEDIA_TRANSPORT_OUTPUT) {
      }
    }
  } else {
    entity_id = tvb_get_guint8(tvb, offset);
    proto_tree_add_item(tree, hf_usb_vid_control_ifdesc_unit_id, tvb, offset, 1,
                        ENC_LITTLE_ENDIAN);
    ++offset;
    if (subtype == VC_PROCESSING_UNIT) {
      offset = dissect_usb_video_processing_unit(tree, tvb, offset);
    } else if (subtype == VC_SELECTOR_UNIT) {
      offset = dissect_usb_video_selector_unit(tree, tvb, offset);
    } else if (subtype == VC_EXTENSION_UNIT) {
      offset = dissect_usb_video_extension_unit(tree, tvb, offset);
    } else if (subtype == VC_ENCODING_UNIT) {
    } else {
      expert_add_info_format(pinfo, subtype_item, &ei_usb_vid_subtype_unknown,
                             "Unknown VC subtype %u", subtype);
    }
  }
  if (offset < descriptor_len) {
    proto_tree_add_item(tree, hf_usb_vid_descriptor_data, tvb, offset,
                        descriptor_len - offset, ENC_NA);
  }
  if (entity_id != 0)
    proto_item_append_text(item, " (Entity %d)", entity_id);
  if (subtype != VC_HEADER && usb_conv_info) {
    usb_conv_info = get_usb_iface_conv_info(pinfo, usb_conv_info->interfaceNum);
    video_conv_info = (video_conv_info_t *)usb_conv_info->class_data;
    if (!video_conv_info) {
      video_conv_info = wmem_new(wmem_file_scope(), video_conv_info_t);
      video_conv_info->entities = wmem_tree_new(wmem_file_scope());
      usb_conv_info->class_data = video_conv_info;
      usb_conv_info->class_data_type = USB_CONV_VIDEO;
    } else if (usb_conv_info->class_data_type != USB_CONV_VIDEO) {
      return descriptor_len;
    }
    entity = (video_entity_t *)wmem_tree_lookup32(video_conv_info->entities,
                                                  entity_id);
    if (!entity) {
      entity = wmem_new(wmem_file_scope(), video_entity_t);
      entity->entityID = entity_id;
      entity->subtype = subtype;
      entity->terminalType = terminal_type;
      wmem_tree_insert32(video_conv_info->entities, entity_id, entity);
    }
  }
  return descriptor_len;
}

