static void sbr_chirp(SpectralBandReplication *sbr, SBRData *ch_data) {
  int i;
  float new_bw;
  static const float bw_tab[] = {0.0f, 0.75f, 0.9f, 0.98f};
  for (i = 0; i < sbr->n_q; i++) {
    if (ch_data->bs_invf_mode[0][i] + ch_data->bs_invf_mode[1][i] == 1) {
      new_bw = 0.6f;
    } else
      new_bw = bw_tab[ch_data->bs_invf_mode[0][i]];
    if (new_bw < ch_data->bw_array[i]) {
      new_bw = 0.75f * new_bw + 0.25f * ch_data->bw_array[i];
    } else
      new_bw = 0.90625f * new_bw + 0.09375f * ch_data->bw_array[i];
    ch_data->bw_array[i] = new_bw < 0.015625f ? 0.0f : new_bw;
  }
}

int remoteDispatchClientRequest(struct qemud_server *server,
                                struct qemud_client *client,
                                struct qemud_client_message *msg) {
  int ret;
  remote_error rerr;
  bool qemu_call;
  VIR_DEBUG("prog=%d ver=%d type=%d status=%d serial=%d proc=%d", msg->hdr.prog,
            msg->hdr.vers, msg->hdr.type, msg->hdr.status, msg->hdr.serial,
            msg->hdr.proc);
  memset(&rerr, 0, sizeof rerr);
  if (msg->hdr.prog == REMOTE_PROGRAM)
    qemu_call = false;
  else if (msg->hdr.prog == QEMU_PROGRAM)
    qemu_call = true;
  else {
    remoteDispatchFormatError(
        &rerr, _("program mismatch (actual %x, expected %x or %x)"),
        msg->hdr.prog, REMOTE_PROGRAM, QEMU_PROGRAM);
    goto error;
  }
  if (!qemu_call && msg->hdr.vers != REMOTE_PROTOCOL_VERSION) {
    remoteDispatchFormatError(&rerr,
                              _("version mismatch (actual %x, expected %x)"),
                              msg->hdr.vers, REMOTE_PROTOCOL_VERSION);
    goto error;
  } else if (qemu_call && msg->hdr.vers != QEMU_PROTOCOL_VERSION) {
    remoteDispatchFormatError(&rerr,
                              _("version mismatch (actual %x, expected %x)"),
                              msg->hdr.vers, QEMU_PROTOCOL_VERSION);
    goto error;
  }
  switch (msg->hdr.type) {
  case REMOTE_CALL:
    return remoteDispatchClientCall(server, client, msg, qemu_call);
  case REMOTE_STREAM:
    VIR_INFO("Ignoring unexpected stream data serial=%d proc=%d status=%d",
             msg->hdr.serial, msg->hdr.proc, msg->hdr.status);
    qemudClientMessageRelease(client, msg);
    break;
  default:
    remoteDispatchFormatError(&rerr, _("type (%d) != REMOTE_CALL"),
                              (int)msg->hdr.type);
    goto error;
  }
  return 0;
error:
  ret = remoteSerializeReplyError(client, &rerr, &msg->hdr);
  if (ret >= 0)
    VIR_FREE(msg);
  return ret;
}

