        print_comment(sql_file, 0, "-- Dump completed on %s\n", time_str);
 }
 else print_comment ( sql_file , 0 , "-- Dump completed\n" ) ;
 check_io ( sql_file ) ;
  }
}

static void parse_ls(const char *p, struct branch *b) {
  struct tree_entry *root = NULL;
  struct tree_entry leaf = {NULL};
  if (*p == '"') {
    if (!b)
      die("Not in a commit: %s", command_buf.buf);
    root = &b->branch_tree;
  } else {
    struct object_entry *e = parse_treeish_dataref(&p);
    root = new_tree_entry();
    hashcpy(root->versions[1].sha1, e->idx.sha1);
    if (!is_null_sha1(root->versions[1].sha1))
      root->versions[1].mode = S_IFDIR;
    load_tree(root);
  }
  if (*p == '"') {
    static struct strbuf uq = STRBUF_INIT;
    const char *endp;
    strbuf_reset(&uq);
    if (unquote_c_style(&uq, p, &endp))
      die("Invalid path: %s", command_buf.buf);
    if (*endp)
      die("Garbage after path in: %s", command_buf.buf);
    p = uq.buf;
  }
  tree_content_get(root, p, &leaf, 1);
  if (S_ISDIR(leaf.versions[1].mode))
    store_tree(&leaf);
  print_ls(leaf.versions[1].mode, leaf.versions[1].sha1, p);
  if (leaf.tree)
    release_tree_content_recursive(leaf.tree);
  if (!b || root != &b->branch_tree)
    release_tree_entry(root);
}

static void restore_time_zone(FILE *sql_file, const char *delimiter) {
  fprintf(sql_file, "/*!50003 SET time_zone = @saved_time_zone */ %s\n",
          (const char *)delimiter);
}

static guint32 parse_wbxml_tag_defined(proto_tree *tree, tvbuff_t *tvb,
                                       guint32 offset, guint32 str_tbl,
                                       guint8 *level, guint8 *codepage_stag,
                                       guint8 *codepage_attr,
                                       const wbxml_decoding *map) {
  guint32 tvb_len = tvb_reported_length(tvb);
  guint32 off = offset;
  guint32 len;
  guint str_len;
  guint32 ent;
  guint32 idx;
  guint8 peek;
  guint32 tag_len;
  guint8 tag_save_known = 0;
  guint8 tag_new_known = 0;
  const char *tag_save_literal;
  const char *tag_new_literal;
  guint8 parsing_tag_content = FALSE;
  tag_save_literal = NULL;
  DebugLog(
      ("parse_wbxml_tag_defined (level = %u, offset = %u)\n", *level, offset));
  while (off < tvb_len) {
    peek = tvb_get_guint8(tvb, off);
    DebugLog(("STAG: (top of while) level = %3u, peek = 0x%02X, off = %u, "
              "tvb_len = %u\n",
              *level, peek, off, tvb_len));
    if ((peek & 0x3F) < 4)
      switch (peek) {
      case 0x00:
        *codepage_stag = tvb_get_guint8(tvb, off + 1);
        proto_tree_add_text(tree, tvb, off, 2,
                            " | Tag | T -->%3d "
                            "| SWITCH_PAGE (Tag code page) "
                            "|",
                            *codepage_stag);
        off += 2;
        break;
      case 0x01:
        if (tag_save_known) {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Tag | T %3d "
                              "| END (Known Tag 0x%02X) "
                              "| %s</%s>",
                              *level, *codepage_stag, tag_save_known,
                              Indent(*level), tag_save_literal);
        } else {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Tag | T %3d "
                              "| END (Literal Tag) "
                              "| %s</%s>",
                              *level, *codepage_stag, Indent(*level),
                              tag_save_literal ? tag_save_literal : "");
        }
        (*level)--;
        off++;
        DebugLog(
            ("STAG: level = %u, Return: len = %u\n", *level, off - offset));
        return (off - offset);
      case 0x02:
        ent = tvb_get_guintvar(tvb, off + 1, &len);
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| ENTITY " "| %s'&#%u;
'" , * level , * codepage_stag , Indent ( * level ) , ent ) ;
 off += 1 + len ;
 break ;
 case 0x03 : len = tvb_strsize ( tvb , off + 1 ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| STR_I (Inline string) " "| %s\'%s\'" , * level , * codepage_stag , Indent ( * level ) , tvb_format_text ( tvb , off + 1 , len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x40 : case 0x41 : case 0x42 : len = tvb_strsize ( tvb , off + 1 ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| EXT_I_%1x (Extension Token) " "| %s(%s: \'%s\')" , * level , * codepage_stag , peek & 0x0f , Indent ( * level ) , map_token ( map -> global , 0 , peek ) , tvb_format_text ( tvb , off + 1 , len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0x43 : proto_tree_add_text ( tree , tvb , off , 1 , " %3d | Tag | T %3d " "| PI (XML Processing Instruction) " "| %s<?xml" , * level , * codepage_stag , Indent ( * level ) ) ;
 len = parse_wbxml_attribute_list_defined ( tree , tvb , off , str_tbl , * level , codepage_attr , map ) ;
 off += len ;
 if ( off >= tvb_len ) {
          DebugLog(
              ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
               *level, off - offset));
          THROW(ReportedBoundsError);
 }
 proto_tree_add_text ( tree , tvb , off - 1 , 1 , " %3d | Tag | T %3d " "| END (PI) " "| %s?>" , * level , * codepage_stag , Indent ( * level ) ) ;
 break ;
 case 0x80 : case 0x81 : case 0x82 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 {
          char *s;
          if (map->ext_t[peek & 0x03])
            s = (map->ext_t[peek & 0x03])(tvb, idx, str_tbl);
          else
            s = wmem_strdup_printf(wmem_packet_scope(), "EXT_T_%1x (%s)",
                                   peek & 0x03,
                                   map_token(map->global, 0, peek));
          proto_tree_add_text(tree, tvb, off, 1 + len,
                              " %3d | Tag | T %3d "
                              "| EXT_T_%1x (Extension Token) "
                              "| %s%s",
                              *level, *codepage_stag, peek & 0x0f,
                              Indent(*level), s);
 }
 off += 1 + len ;
 break ;
 case 0x83 : idx = tvb_get_guintvar ( tvb , off + 1 , & len ) ;
 str_len = tvb_strsize ( tvb , str_tbl + idx ) ;
 proto_tree_add_text ( tree , tvb , off , 1 + len , " %3d | Tag | T %3d " "| STR_T (Tableref string) " "| %s\'%s\'" , * level , * codepage_stag , Indent ( * level ) , tvb_format_text ( tvb , str_tbl + idx , str_len - 1 ) ) ;
 off += 1 + len ;
 break ;
 case 0xC0 : case 0xC1 : case 0xC2 : proto_tree_add_text ( tree , tvb , off , 1 , " %3d | Tag | T %3d " "| EXT_%1x (Extension Token) " "| %s(%s)" , * level , * codepage_stag , peek & 0x0f , Indent ( * level ) , map_token ( map -> global , 0 , peek ) ) ;
 off ++ ;
 break ;
 case 0xC3 : if ( tvb_get_guint8 ( tvb , 0 ) ) {
          char *str;
          if (tag_save_known) {
            if (map->opaque_binary_tag) {
              str = map->opaque_binary_tag(tvb, off + 1, tag_save_known,
                                           *codepage_stag, &len);
            } else {
              str = default_opaque_binary_tag(tvb, off + 1, tag_save_known,
                                              *codepage_stag, &len);
            }
          } else {
            if (map->opaque_literal_tag) {
              str = map->opaque_literal_tag(tvb, off + 1, tag_save_literal,
                                            *codepage_stag, &len);
            } else {
              str = default_opaque_literal_tag(tvb, off + 1, tag_save_literal,
                                               *codepage_stag, &len);
            }
          }
          proto_tree_add_text(tree, tvb, off, 1 + len,
                              " %3d | Tag | T %3d "
                              "| OPAQUE (Opaque data) "
                              "| %s%s",
                              *level, *codepage_stag, Indent(*level), str);
          off += 1 + len;
 }
 else {
          proto_tree_add_text(tree, tvb, off, 1,
                              " %3d | Tag | T %3d "
                              "| RESERVED_2 (Invalid Token!) "
                              "| WBXML 1.0 parsing stops here.",
                              *level, *codepage_stag);
          off = tvb_len;
          DebugLog(
              ("STAG: level = %u, Return: len = %u\n", *level, off - offset));
          return (off - offset);
 }
 break ;
      }
    else {
      tag_len = 0;
      if ((peek & 0x3F) == 4) {
        DebugLog((
            "STAG: LITERAL tag (peek = 0x%02X, off = %u) - TableRef follows!\n",
            peek, off));
        idx = tvb_get_guintvar(tvb, off + 1, &tag_len);
        str_len = tvb_strsize(tvb, str_tbl + idx);
        tag_new_literal =
            (const gchar *)tvb_get_ptr(tvb, str_tbl + idx, str_len);
        tag_new_known = 0;
      } else {
        tag_new_known = peek & 0x3F;
        tag_new_literal = map_token(map->tags, *codepage_stag, tag_new_known);
      }
      if (peek & 0x40) {
        if (parsing_tag_content) {
          DebugLog(("STAG: Tag in Tag - RECURSE! (off = %u)\n", off));
          (*level)++;
          len = parse_wbxml_tag_defined(tree, tvb, off, str_tbl, level,
                                        codepage_stag, codepage_attr, map);
          off += len;
        } else {
          if ((peek & 0x3F) == 4) {
            tag_save_literal = tag_new_literal;
            tag_save_known = 0;
          } else {
            tag_save_known = tag_new_known;
            tag_save_literal = tag_new_literal;
          }
          if (peek & 0x80) {
            if (tag_new_known) {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| Known Tag 0x%02X (AC) "
                                  "| %s<%s",
                                  *level, *codepage_stag, tag_new_known,
                                  Indent(*level), tag_new_literal);
              off++;
            } else {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| LITERAL_AC (Literal tag) (AC) "
                                  "| %s<%s",
                                  *level, *codepage_stag, Indent(*level),
                                  tag_new_literal);
              off += 1 + tag_len;
            }
            len = parse_wbxml_attribute_list_defined(
                tree, tvb, off, str_tbl, *level, codepage_attr, map);
            off += len;
            if (off >= tvb_len) {
              DebugLog(
                  ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
                   *level, off - offset));
              THROW(ReportedBoundsError);
            }
            proto_tree_add_text(tree, tvb, off - 1, 1,
                                " %3d | Tag | T %3d "
                                "| END (attribute list) "
                                "| %s>",
                                *level, *codepage_stag, Indent(*level));
          } else {
            if (tag_new_known) {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| Known Tag 0x%02X (.C) "
                                  "| %s<%s>",
                                  *level, *codepage_stag, tag_new_known,
                                  Indent(*level), tag_new_literal);
              off++;
            } else {
              proto_tree_add_text(tree, tvb, off, 1,
                                  " %3d | Tag | T %3d "
                                  "| LITERAL_C (Literal Tag) (.C) "
                                  "| %s<%s>",
                                  *level, *codepage_stag, Indent(*level),
                                  tag_new_literal);
              off += 1 + tag_len;
            }
          }
          parsing_tag_content = TRUE;
          DebugLog(("Tag in Tag - No recursion this time! (off = %u)\n", off));
        }
      } else {
        DebugLog(("<Tag/> in Tag - No recursion! (off = %u)\n", off));
        (*level)++;
        if (peek & 0x80) {
          if (tag_new_known) {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| Known Tag 0x%02X (A.) "
                                "| %s<%s",
                                *level, *codepage_stag, tag_new_known,
                                Indent(*level), tag_new_literal);
            off++;
            len = parse_wbxml_attribute_list_defined(
                tree, tvb, off, str_tbl, *level, codepage_attr, map);
            off += len;
            if (off > tvb_len) {
              DebugLog(
                  ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
                   *level, off - offset));
              THROW(ReportedBoundsError);
            }
            proto_tree_add_text(tree, tvb, off - 1, 1,
                                " %3d | Tag | T %3d "
                                "| END (Known Tag) "
                                "| %s/>",
                                *level, *codepage_stag, Indent(*level));
          } else {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| LITERAL_A (Literal Tag) (A.) "
                                "| %s<%s",
                                *level, *codepage_stag, Indent(*level),
                                tag_new_literal);
            off += 1 + tag_len;
            len = parse_wbxml_attribute_list_defined(
                tree, tvb, off, str_tbl, *level, codepage_attr, map);
            off += len;
            if (off >= tvb_len) {
              DebugLog(
                  ("STAG: level = %u, ThrowException: len = %u (short frame)\n",
                   *level, off - offset));
              THROW(ReportedBoundsError);
            }
            proto_tree_add_text(tree, tvb, off - 1, 1,
                                " %3d | Tag | T %3d "
                                "| END (Literal Tag) "
                                "| %s/>",
                                *level, *codepage_stag, Indent(*level));
          }
        } else {
          if (tag_new_known) {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| Known Tag 0x%02x (..) "
                                "| %s<%s />",
                                *level, *codepage_stag, tag_new_known,
                                Indent(*level), tag_new_literal);
            off++;
          } else {
            proto_tree_add_text(tree, tvb, off, 1,
                                " %3d | Tag | T %3d "
                                "| LITERAL (Literal Tag) (..) "
                                "| %s<%s />",
                                *level, *codepage_stag, Indent(*level),
                                tag_new_literal);
            off += 1 + tag_len;
          }
        }
        (*level)--;
      }
    }
  }
  DebugLog(("STAG: level = %u, Return: len = %u (end of function body)\n",
            *level, off - offset));
  return (off - offset);
}

void ufmt_64tou(UChar *buffer, int32_t *len, uint64_t value, uint8_t radix,
                UBool uselower, int32_t minDigits) {
  int32_t length = 0;
  uint32_t digit;
  UChar *left, *right, temp;
  do {
    digit = (uint32_t)(value % radix);
    value = value / radix;
    buffer[length++] =
        (UChar)(uselower ? TO_LC_DIGIT(digit) : TO_UC_DIGIT(digit));
  } while (value);
  if (minDigits != -1 && length < minDigits) {
    while (length < minDigits && length < *len)
      buffer[length++] = DIGIT_0;
  }
  left = buffer;
  right = buffer + length;
  while (left < --right) {
    temp = *left;
    *left++ = *right;
    *right = temp;
  }
  *len = length;
}

static int parent_proxy_fail(TSCont contp, TSEvent event, void *edata) {
  ParentTest *ptest = (ParentTest *)TSContDataGet(contp);
  TSHttpTxn txnp = (TSHttpTxn)edata;
  TSMBuffer mbuf;
  TSMLoc hdr;
  TSHttpStatus expected = TS_HTTP_STATUS_BAD_GATEWAY;
  TSHttpStatus received;
  int status;
  switch (event) {
  case TS_EVENT_HTTP_SEND_RESPONSE_HDR:
    ink_release_assert(TSHttpTxnClientRespGet(txnp, &mbuf, &hdr) == TS_SUCCESS);
    received = TSHttpHdrStatusGet(mbuf, hdr);
    if (expected != received) {
      status = REGRESSION_TEST_FAILED;
      SDK_RPRINT(ptest->regtest, "TSHttpTxnParentProxySet", "TestCase", TC_FAIL,
                 "Expected response status %d, received %d", expected,
                 received);
    } else {
      status = REGRESSION_TEST_PASSED;
      SDK_RPRINT(ptest->regtest, "TSHttpTxnParentProxySet", "TestCase", TC_PASS,
                 "Received expected response status %d", expected);
    }
    TSHandleMLocRelease(mbuf, TS_NULL_MLOC, hdr);
    return status;
  default:
    SDK_RPRINT(ptest->regtest, "TSHttpTxnParentProxySet", ptest->testcase,
               TC_FAIL, "Unexpected event %d", event);
    return REGRESSION_TEST_FAILED;
  }
}

void vp9_print_modes_and_motion_vectors(VP9_COMMON *cm, const char *file) {
  int mi_row;
  int mi_col;
  int mi_index = 0;
  FILE *mvs = fopen(file, "a");
  MODE_INFO **mi = NULL;
  int rows = cm->mi_rows;
  int cols = cm->mi_cols;
  print_mi_data(cm, mvs, "Partitions:", offsetof(MB_MODE_INFO, sb_type));
  print_mi_data(cm, mvs, "Modes:", offsetof(MB_MODE_INFO, mode));
  print_mi_data(cm, mvs, "Skips:", offsetof(MB_MODE_INFO, skip));
  print_mi_data(cm, mvs, "Ref frame:", offsetof(MB_MODE_INFO, ref_frame[0]));
  print_mi_data(cm, mvs, "Transform:", offsetof(MB_MODE_INFO, tx_size));
  print_mi_data(cm, mvs, "UV Modes:", offsetof(MB_MODE_INFO, uv_mode));
  log_frame_info(cm, "Vectors ", mvs);
  for (mi_row = 0; mi_row < rows; mi_row++) {
    fprintf(mvs, "V ");
    for (mi_col = 0; mi_col < cols; mi_col++) {
      fprintf(mvs, "%4d:%4d ", mi[mi_index]->mbmi.mv[0].as_mv.row,
              mi[mi_index]->mbmi.mv[0].as_mv.col);
      mi_index++;
    }
    fprintf(mvs, "\n");
    mi_index += 8;
  }
  fprintf(mvs, "\n");
  fclose(mvs);
}

static int decode_bmv_frame(const uint8_t *source, int src_len, uint8_t *frame,
                            int frame_off) {
  unsigned val, saved_val = 0;
  int tmplen = src_len;
  const uint8_t *src, *source_end = source + src_len;
  uint8_t *frame_end = frame + SCREEN_WIDE * SCREEN_HIGH;
  uint8_t *dst, *dst_end;
  int len, mask;
  int forward = (frame_off <= -SCREEN_WIDE) || (frame_off >= 0);
  int read_two_nibbles, flag;
  int advance_mode;
  int mode = 0;
  int i;
  if (src_len <= 0)
    return AVERROR_INVALIDDATA;
  if (forward) {
    src = source;
    dst = frame;
    dst_end = frame_end;
  } else {
    src = source + src_len - 1;
    dst = frame_end - 1;
    dst_end = frame - 1;
  }
  for (;;) {
    int shift = 0;
    flag = 0;
    if (!mode || (tmplen == 4)) {
      if (src < source || src >= source_end)
        return AVERROR_INVALIDDATA;
      val = *src;
      read_two_nibbles = 1;
    } else {
      val = saved_val;
      read_two_nibbles = 0;
    }
    if (!(val & 0xC)) {
      for (;;) {
        if (!read_two_nibbles) {
          if (src < source || src >= source_end)
            return AVERROR_INVALIDDATA;
          shift += 2;
          val |= *src << shift;
          if (*src & 0xC)
            break;
        }
        read_two_nibbles = 0;
        shift += 2;
        mask = (1 << shift) - 1;
        val = ((val >> 2) & ~mask) | (val & mask);
        NEXT_BYTE(src);
        if ((val & (0xC << shift))) {
          flag = 1;
          break;
        }
      }
    } else if (mode) {
      flag = tmplen != 4;
    }
    if (flag) {
      tmplen = 4;
    } else {
      saved_val = val >> (4 + shift);
      tmplen = 0;
      val &= (1 << (shift + 4)) - 1;
      NEXT_BYTE(src);
    }
    advance_mode = val & 1;
    len = (val >> 1) - 1;
    mode += 1 + advance_mode;
    if (mode >= 4)
      mode -= 3;
    if (FFABS(dst_end - dst) < len)
      return AVERROR_INVALIDDATA;
    switch (mode) {
    case 1:
      if (forward) {
        if (dst - frame + SCREEN_WIDE < frame_off ||
            dst - frame + SCREEN_WIDE + frame_off < 0 ||
            frame_end - dst < frame_off + len || frame_end - dst < len)
          return AVERROR_INVALIDDATA;
        for (i = 0; i < len; i++)
          dst[i] = dst[frame_off + i];
        dst += len;
      } else {
        dst -= len;
        if (dst - frame + SCREEN_WIDE < frame_off ||
            dst - frame + SCREEN_WIDE + frame_off < 0 ||
            frame_end - dst < frame_off + len || frame_end - dst < len)
          return AVERROR_INVALIDDATA;
        for (i = len - 1; i >= 0; i--)
          dst[i] = dst[frame_off + i];
      }
      break;
    case 2:
      if (forward) {
        if (source + src_len - src < len)
          return AVERROR_INVALIDDATA;
        memcpy(dst, src, len);
        dst += len;
        src += len;
      } else {
        if (src - source < len)
          return AVERROR_INVALIDDATA;
        dst -= len;
        src -= len;
        memcpy(dst, src, len);
      }
      break;
    case 3:
      val = forward ? dst[-1] : dst[1];
      if (forward) {
        memset(dst, val, len);
        dst += len;
      } else {
        dst -= len;
        memset(dst, val, len);
      }
      break;
    default:
      break;
    }
    if (dst == dst_end)
      return 0;
  }
  return 0;
}

