  if (lv_tpkt_len == -1) {
    return FALSE;
  }
  if (tvb_reported_length(tvb) == 4) {
    dissect_tpkt_encap(tvb, pinfo, tree, q931_desegment, q931_tpkt_pdu_handle);
    return TRUE;
  }
  if (!tvb_bytes_exist(tvb, 4, 3))
