  if ((tvb_get_guint8(tvb, 4) != NLPID_Q_931) &&
      (tvb_get_guint8(tvb, 4) != 0x03)) {
    return FALSE;
  }
  dissect_tpkt_encap(tvb, pinfo, tree, q931_desegment, q931_tpkt_pdu_handle);
  return TRUE;
}

