static int selinux_inode_permission(struct inode *inode, int mask) {
  const struct cred *cred = current_cred();
  u32 perms;
  bool from_access;
  unsigned flags = mask & MAY_NOT_BLOCK;
  struct inode_security_struct *isec;
  u32 sid;
  struct av_decision avd;
  int rc, rc2;
  u32 audited, denied;
  from_access = mask & MAY_ACCESS;
  mask &= (MAY_READ | MAY_WRITE | MAY_EXEC | MAY_APPEND);
  if (!mask)
    return 0;
  validate_creds(cred);
  if (unlikely(IS_PRIVATE(inode)))
    return 0;
  perms = file_mask_to_av(inode->i_mode, mask);
  sid = cred_sid(cred);
  isec = inode_security_rcu(inode, flags & MAY_NOT_BLOCK);
  if (IS_ERR(isec))
    return PTR_ERR(isec);
  rc = avc_has_perm_noaudit(sid, isec->sid, isec->sclass, perms, 0, &avd);
  audited = avc_audit_required(perms, &avd, rc,
                               from_access ? FILE__AUDIT_ACCESS : 0, &denied);
  if (likely(!audited))
    return rc;
  rc2 = audit_inode_permission(inode, perms, audited, denied, rc, flags);
  if (rc2)
    return rc2;
  return rc;
}

static void fmtfp(char **sbuffer, char **buffer, size_t *currlen,
                  size_t *maxlen, LDOUBLE fvalue, int min, int max, int flags) {
  int signvalue = 0;
  LDOUBLE ufvalue;
  char iconvert[20];
  char fconvert[20];
  int iplace = 0;
  int fplace = 0;
  int padlen = 0;
  int zpadlen = 0;
  long intpart;
  long fracpart;
  long max10;
  if (max < 0)
    max = 6;
  ufvalue = abs_val(fvalue);
  if (fvalue < 0)
    signvalue = '-';
  else if (flags & DP_F_PLUS)
    signvalue = '+';
  else if (flags & DP_F_SPACE)
    signvalue = ' ';
  intpart = (long)ufvalue;
  if (max > 9)
    max = 9;
  max10 = roundv(pow_10(max));
  fracpart = roundv(pow_10(max) * (ufvalue - intpart));
  if (fracpart >= max10) {
    intpart++;
    fracpart -= max10;
  }
  do {
    iconvert[iplace++] = "0123456789"[intpart % 10];
    intpart = (intpart / 10);
  } while (intpart && (iplace < (int)sizeof(iconvert)));
  if (iplace == sizeof iconvert)
    iplace--;
  iconvert[iplace] = 0;
  do {
    fconvert[fplace++] = "0123456789"[fracpart % 10];
    fracpart = (fracpart / 10);
  } while (fplace < max);
  if (fplace == sizeof fconvert)
    fplace--;
  fconvert[fplace] = 0;
  padlen = min - iplace - max - 1 - ((signvalue) ? 1 : 0);
  zpadlen = max - fplace;
  if (zpadlen < 0)
    zpadlen = 0;
  if (padlen < 0)
    padlen = 0;
  if (flags & DP_F_MINUS)
    padlen = -padlen;
  if ((flags & DP_F_ZERO) && (padlen > 0)) {
    if (signvalue) {
      doapr_outch(sbuffer, buffer, currlen, maxlen, signvalue);
      --padlen;
      signvalue = 0;
    }
    while (padlen > 0) {
      doapr_outch(sbuffer, buffer, currlen, maxlen, '0');
      --padlen;
    }
  }
  while (padlen > 0) {
    doapr_outch(sbuffer, buffer, currlen, maxlen, ' ');
    --padlen;
  }
  if (signvalue)
    doapr_outch(sbuffer, buffer, currlen, maxlen, signvalue);
  while (iplace > 0)
    doapr_outch(sbuffer, buffer, currlen, maxlen, iconvert[--iplace]);
  if (max > 0 || (flags & DP_F_NUM)) {
    doapr_outch(sbuffer, buffer, currlen, maxlen, '.');
    while (fplace > 0)
      doapr_outch(sbuffer, buffer, currlen, maxlen, fconvert[--fplace]);
  }
  while (zpadlen > 0) {
    doapr_outch(sbuffer, buffer, currlen, maxlen, '0');
    --zpadlen;
  }
  while (padlen < 0) {
    doapr_outch(sbuffer, buffer, currlen, maxlen, ' ');
    ++padlen;
  }
}

static void show_frame(WriterContext *w, AVFrame *frame, AVStream *stream,
                       AVFormatContext *fmt_ctx) {
  AVBPrint pbuf;
  char val_str[128];
  const char *s;
  int i;
  av_bprint_init(&pbuf, 1, AV_BPRINT_SIZE_UNLIMITED);
  writer_print_section_header(w, SECTION_ID_FRAME);
  s = av_get_media_type_string(stream->codecpar->codec_type);
  if (s)
    print_str("media_type", s);
  else
    print_str_opt("media_type", "unknown");
  print_int("stream_index", stream->index);
  print_int("key_frame", frame->key_frame);
  print_ts("pkt_pts", frame->pts);
  print_time("pkt_pts_time", frame->pts, &stream->time_base);
  print_ts("pkt_dts", frame->pkt_dts);
  print_time("pkt_dts_time", frame->pkt_dts, &stream->time_base);
  print_ts("best_effort_timestamp", frame->best_effort_timestamp);
  print_time("best_effort_timestamp_time", frame->best_effort_timestamp,
             &stream->time_base);
  print_duration_ts("pkt_duration", frame->pkt_duration);
  print_duration_time("pkt_duration_time", frame->pkt_duration,
                      &stream->time_base);
  if (frame->pkt_pos != -1)
    print_fmt("pkt_pos", "%" PRId64, frame->pkt_pos);
  else
    print_str_opt("pkt_pos", "N/A");
  if (frame->pkt_size != -1)
    print_val("pkt_size", frame->pkt_size, unit_byte_str);
  else
    print_str_opt("pkt_size", "N/A");
  switch (stream->codecpar->codec_type) {
    AVRational sar;
  case AVMEDIA_TYPE_VIDEO:
    print_int("width", frame->width);
    print_int("height", frame->height);
    s = av_get_pix_fmt_name(frame->format);
    if (s)
      print_str("pix_fmt", s);
    else
      print_str_opt("pix_fmt", "unknown");
    sar = av_guess_sample_aspect_ratio(fmt_ctx, stream, frame);
    if (sar.num) {
      print_q("sample_aspect_ratio", sar, ':');
    } else {
      print_str_opt("sample_aspect_ratio", "N/A");
    }
    print_fmt("pict_type", "%c", av_get_picture_type_char(frame->pict_type));
    print_int("coded_picture_number", frame->coded_picture_number);
    print_int("display_picture_number", frame->display_picture_number);
    print_int("interlaced_frame", frame->interlaced_frame);
    print_int("top_field_first", frame->top_field_first);
    print_int("repeat_pict", frame->repeat_pict);
    if (frame->color_range != AVCOL_RANGE_UNSPECIFIED)
      print_str("color_range", av_color_range_name(frame->color_range));
    else
      print_str_opt("color_range", av_color_range_name(frame->color_range));
    if (frame->colorspace != AVCOL_SPC_UNSPECIFIED)
      print_str("color_space", av_color_space_name(frame->colorspace));
    else
      print_str_opt("color_space", av_color_space_name(frame->colorspace));
    if (frame->color_primaries != AVCOL_PRI_UNSPECIFIED)
      print_str("color_primaries",
                av_color_primaries_name(frame->color_primaries));
    else
      print_str_opt("color_primaries",
                    av_color_primaries_name(frame->color_primaries));
    if (frame->color_trc != AVCOL_TRC_UNSPECIFIED)
      print_str("color_transfer", av_color_transfer_name(frame->color_trc));
    else
      print_str_opt("color_transfer", av_color_transfer_name(frame->color_trc));
    if (frame->chroma_location != AVCHROMA_LOC_UNSPECIFIED)
      print_str("chroma_location",
                av_chroma_location_name(frame->chroma_location));
    else
      print_str_opt("chroma_location",
                    av_chroma_location_name(frame->chroma_location));
    break;
  case AVMEDIA_TYPE_AUDIO:
    s = av_get_sample_fmt_name(frame->format);
    if (s)
      print_str("sample_fmt", s);
    else
      print_str_opt("sample_fmt", "unknown");
    print_int("nb_samples", frame->nb_samples);
    print_int("channels", frame->channels);
    if (frame->channel_layout) {
      av_bprint_clear(&pbuf);
      av_bprint_channel_layout(&pbuf, frame->channels, frame->channel_layout);
      print_str("channel_layout", pbuf.str);
    } else
      print_str_opt("channel_layout", "unknown");
    break;
  }
  if (do_show_frame_tags)
    show_tags(w, frame->metadata, SECTION_ID_FRAME_TAGS);
  if (do_show_log)
    show_log(w, SECTION_ID_FRAME_LOGS, SECTION_ID_FRAME_LOG, do_show_log);
  if (frame->nb_side_data) {
    writer_print_section_header(w, SECTION_ID_FRAME_SIDE_DATA_LIST);
    for (i = 0; i < frame->nb_side_data; i++) {
      AVFrameSideData *sd = frame->side_data[i];
      const char *name;
      writer_print_section_header(w, SECTION_ID_FRAME_SIDE_DATA);
      name = av_frame_side_data_name(sd->type);
      print_str("side_data_type", name ? name : "unknown");
      if (sd->type == AV_FRAME_DATA_DISPLAYMATRIX && sd->size >= 9 * 4) {
        writer_print_integers(w, "displaymatrix", sd->data, 9, " %11d", 3, 4,
                              1);
        print_int("rotation", av_display_rotation_get((int32_t *)sd->data));
      } else if (sd->type == AV_FRAME_DATA_GOP_TIMECODE && sd->size >= 8) {
        char tcbuf[AV_TIMECODE_STR_SIZE];
        av_timecode_make_mpeg_tc_string(tcbuf, *(int64_t *)(sd->data));
        print_str("timecode", tcbuf);
      } else if (sd->type == AV_FRAME_DATA_MASTERING_DISPLAY_METADATA) {
        AVMasteringDisplayMetadata *metadata =
            (AVMasteringDisplayMetadata *)sd->data;
        if (metadata->has_primaries) {
          print_q("red_x", metadata->display_primaries[0][0], '/');
          print_q("red_y", metadata->display_primaries[0][1], '/');
          print_q("green_x", metadata->display_primaries[1][0], '/');
          print_q("green_y", metadata->display_primaries[1][1], '/');
          print_q("blue_x", metadata->display_primaries[2][0], '/');
          print_q("blue_y", metadata->display_primaries[2][1], '/');
          print_q("white_point_x", metadata->white_point[0], '/');
          print_q("white_point_y", metadata->white_point[1], '/');
        }
        if (metadata->has_luminance) {
          print_q("min_luminance", metadata->min_luminance, '/');
          print_q("max_luminance", metadata->max_luminance, '/');
        }
      } else if (sd->type == AV_FRAME_DATA_CONTENT_LIGHT_LEVEL) {
        AVContentLightMetadata *metadata = (AVContentLightMetadata *)sd->data;
        print_int("max_content", metadata->MaxCLL);
        print_int("max_average", metadata->MaxFALL);
      } else if (sd->type == AV_FRAME_DATA_ICC_PROFILE) {
        AVDictionaryEntry *tag =
            av_dict_get(sd->metadata, "name", NULL, AV_DICT_MATCH_CASE);
        if (tag)
          print_str(tag->key, tag->value);
        print_int("size", sd->size);
      }
      writer_print_section_footer(w);
    }
    writer_print_section_footer(w);
  }
  writer_print_section_footer(w);
  av_bprint_finalize(&pbuf, NULL);
  fflush(stdout);
}

static ECPARAMETERS *ec_asn1_group2parameters(const EC_GROUP *group,
                                              ECPARAMETERS *param) {
  int ok = 0;
  size_t len = 0;
  ECPARAMETERS *ret = NULL;
  BIGNUM *tmp = NULL;
  unsigned char *buffer = NULL;
  const EC_POINT *point = NULL;
  point_conversion_form_t form;
  if ((tmp = BN_new()) == NULL) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_MALLOC_FAILURE);
    goto err;
  }
  if (param == NULL) {
    if ((ret = ECPARAMETERS_new()) == NULL) {
      ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_MALLOC_FAILURE);
      goto err;
    }
  } else
    ret = param;
  ret->version = (long)0x1;
  if (!ec_asn1_group2fieldid(group, ret->fieldID)) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_EC_LIB);
    goto err;
  }
  if (!ec_asn1_group2curve(group, ret->curve)) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_EC_LIB);
    goto err;
  }
  if ((point = EC_GROUP_get0_generator(group)) == NULL) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, EC_R_UNDEFINED_GENERATOR);
    goto err;
  }
  form = EC_GROUP_get_point_conversion_form(group);
  len = EC_POINT_point2oct(group, point, form, NULL, len, NULL);
  if (len == 0) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_EC_LIB);
    goto err;
  }
  if ((buffer = OPENSSL_malloc(len)) == NULL) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_MALLOC_FAILURE);
    goto err;
  }
  if (!EC_POINT_point2oct(group, point, form, buffer, len, NULL)) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_EC_LIB);
    goto err;
  }
  if (ret->base == NULL && (ret->base = ASN1_OCTET_STRING_new()) == NULL) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_MALLOC_FAILURE);
    goto err;
  }
  if (!ASN1_OCTET_STRING_set(ret->base, buffer, len)) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_ASN1_LIB);
    goto err;
  }
  if (!EC_GROUP_get_order(group, tmp, NULL)) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_EC_LIB);
    goto err;
  }
  ret->order = BN_to_ASN1_INTEGER(tmp, ret->order);
  if (ret->order == NULL) {
    ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_ASN1_LIB);
    goto err;
  }
  if (EC_GROUP_get_cofactor(group, tmp, NULL)) {
    ret->cofactor = BN_to_ASN1_INTEGER(tmp, ret->cofactor);
    if (ret->cofactor == NULL) {
      ECerr(EC_F_EC_ASN1_GROUP2PARAMETERS, ERR_R_ASN1_LIB);
      goto err;
    }
  }
  ok = 1;
err:
  if (!ok) {
    if (ret && !param)
      ECPARAMETERS_free(ret);
    ret = NULL;
  }
  if (tmp)
    BN_free(tmp);
  if (buffer)
    OPENSSL_free(buffer);
  return (ret);
}

