int _zip_dirent_write(struct zip_dirent *zde, FILE *fp, int localp,
                      struct zip_error *error) {
  unsigned short dostime, dosdate;
  fwrite(localp ? LOCAL_MAGIC : CENTRAL_MAGIC, 1, 4, fp);
  if (!localp)
    _zip_write2(zde->version_madeby, fp);
  _zip_write2(zde->version_needed, fp);
  _zip_write2(zde->bitflags, fp);
  _zip_write2(zde->comp_method, fp);
  _zip_u2d_time(zde->last_mod, &dostime, &dosdate);
  _zip_write2(dostime, fp);
  _zip_write2(dosdate, fp);
  _zip_write4(zde->crc, fp);
  _zip_write4(zde->comp_size, fp);
  _zip_write4(zde->uncomp_size, fp);
  _zip_write2(zde->filename_len, fp);
  _zip_write2(zde->extrafield_len, fp);
  if (!localp) {
    _zip_write2(zde->comment_len, fp);
    _zip_write2(zde->disk_number, fp);
    _zip_write2(zde->int_attrib, fp);
    _zip_write4(zde->ext_attrib, fp);
    _zip_write4(zde->offset, fp);
  }
  if (zde->filename_len)
    fwrite(zde->filename, 1, zde->filename_len, fp);
  if (zde->extrafield_len)
    fwrite(zde->extrafield, 1, zde->extrafield_len, fp);
  if (!localp) {
    if (zde->comment_len)
      fwrite(zde->comment, 1, zde->comment_len, fp);
  }
  if (ferror(fp)) {
    _zip_error_set(error, ZIP_ER_WRITE, errno);
    return -1;
  }
  return 0;
}

static void aw_pulse_set2(WMAVoiceContext *s, GetBitContext *gb, int block_idx,
                          AMRFixed *fcb) {
  uint16_t use_mask_mem[9];
  uint16_t *use_mask = use_mask_mem + 2;
  int pulse_off = s->aw_first_pulse_off[block_idx], pulse_start, n, idx, range,
      aidx, start_off = 0;
  if (s->aw_n_pulses[block_idx] > 0)
    while (pulse_off + s->aw_pulse_range < 1)
      pulse_off += fcb->pitch_lag;
  if (s->aw_n_pulses[0] > 0) {
    if (block_idx == 0) {
      range = 32;
    } else {
      range = 8;
      if (s->aw_n_pulses[block_idx] > 0)
        pulse_off = s->aw_next_pulse_off_cache;
    }
  } else
    range = 16;
  pulse_start = s->aw_n_pulses[block_idx] > 0 ? pulse_off - range / 2 : 0;
  memset(&use_mask[-2], 0, 2 * sizeof(use_mask[0]));
  memset(use_mask, -1, 5 * sizeof(use_mask[0]));
  memset(&use_mask[5], 0, 2 * sizeof(use_mask[0]));
  if (s->aw_n_pulses[block_idx] > 0)
    for (idx = pulse_off; idx < MAX_FRAMESIZE / 2; idx += fcb->pitch_lag) {
      int excl_range = s->aw_pulse_range;
      uint16_t *use_mask_ptr = &use_mask[idx >> 4];
      int first_sh = 16 - (idx & 15);
      *use_mask_ptr++ &= 0xFFFFu << first_sh;
      excl_range -= first_sh;
      if (excl_range >= 16) {
        *use_mask_ptr++ = 0;
        *use_mask_ptr &= 0xFFFF >> (excl_range - 16);
      } else
        *use_mask_ptr &= 0xFFFF >> excl_range;
    }
  aidx = get_bits(gb, s->aw_n_pulses[0] > 0 ? 5 - 2 * block_idx : 4);
  for (n = 0; n <= aidx; pulse_start++) {
    for (idx = pulse_start; idx < 0; idx += fcb->pitch_lag)
      ;
    if (idx >= MAX_FRAMESIZE / 2) {
      if (use_mask[0])
        idx = 0x0F;
      else if (use_mask[1])
        idx = 0x1F;
      else if (use_mask[2])
        idx = 0x2F;
      else if (use_mask[3])
        idx = 0x3F;
      else if (use_mask[4])
        idx = 0x4F;
      else
        return;
      idx -= av_log2_16bit(use_mask[idx >> 4]);
    }
    if (use_mask[idx >> 4] & (0x8000 >> (idx & 15))) {
      use_mask[idx >> 4] &= ~(0x8000 >> (idx & 15));
      n++;
      start_off = idx;
    }
  }
  fcb->x[fcb->n] = start_off;
  fcb->y[fcb->n] = get_bits1(gb) ? -1.0 : 1.0;
  fcb->n++;
  n = (MAX_FRAMESIZE / 2 - start_off) % fcb->pitch_lag;
  s->aw_next_pulse_off_cache = n ? fcb->pitch_lag - n : 0;
}

static void imc_calculate_coeffs(IMCContext *q, float *flcoeffs1,
                                 float *flcoeffs2, int *bandWidthT,
                                 float *flcoeffs3, float *flcoeffs5) {
  float workT1[BANDS];
  float workT2[BANDS];
  float workT3[BANDS];
  float snr_limit = 1.e-30;
  float accum = 0.0;
  int i, cnt2;
  for (i = 0; i < BANDS; i++) {
    flcoeffs5[i] = workT2[i] = 0.0;
    if (bandWidthT[i]) {
      workT1[i] = flcoeffs1[i] * flcoeffs1[i];
      flcoeffs3[i] = 2.0 * flcoeffs2[i];
    } else {
      workT1[i] = 0.0;
      flcoeffs3[i] = -30000.0;
    }
    workT3[i] = bandWidthT[i] * workT1[i] * 0.01;
    if (workT3[i] <= snr_limit)
      workT3[i] = 0.0;
  }
  for (i = 0; i < BANDS; i++) {
    for (cnt2 = i; cnt2 < q->cyclTab[i]; cnt2++)
      flcoeffs5[cnt2] = flcoeffs5[cnt2] + workT3[i];
    workT2[cnt2 - 1] = workT2[cnt2 - 1] + workT3[i];
  }
  for (i = 1; i < BANDS; i++) {
    accum = (workT2[i - 1] + accum) * q->weights1[i - 1];
    flcoeffs5[i] += accum;
  }
  for (i = 0; i < BANDS; i++)
    workT2[i] = 0.0;
  for (i = 0; i < BANDS; i++) {
    for (cnt2 = i - 1; cnt2 > q->cyclTab2[i]; cnt2--)
      flcoeffs5[cnt2] += workT3[i];
    workT2[cnt2 + 1] += workT3[i];
  }
  accum = 0.0;
  for (i = BANDS - 2; i >= 0; i--) {
    accum = (workT2[i + 1] + accum) * q->weights2[i];
    flcoeffs5[i] += accum;
  }
}

static void SetupOutput(decoder_t *p_dec, block_t *p_block) {
  decoder_sys_t *p_sys = p_dec->p_sys;
  if (p_dec->fmt_out.audio.i_rate != p_sys->i_rate) {
    msg_Info(p_dec, "AAC channels: %d samplerate: %d", p_sys->i_channels,
             p_sys->i_rate);
    const mtime_t i_end_date = date_Get(&p_sys->end_date);
    date_Init(&p_sys->end_date, p_sys->i_rate, 1);
    date_Set(&p_sys->end_date, i_end_date);
  }
  p_dec->fmt_out.audio.i_rate = p_sys->i_rate;
  p_dec->fmt_out.audio.i_channels = p_sys->i_channels;
  p_dec->fmt_out.audio.i_bytes_per_frame = p_sys->i_frame_size;
  p_dec->fmt_out.audio.i_frame_length = p_sys->i_frame_length;
#if 0 p_dec->fmt_out.audio.i_original_channels = p_sys->i_channels_conf;
 p_dec -> fmt_out . audio . i_physical_channels = p_sys -> i_channels_conf ;
#endif p_block->i_pts = p_block->i_dts = date_Get(&p_sys->end_date);
  p_block->i_length =
      date_Increment(&p_sys->end_date, p_sys->i_frame_length) - p_block->i_pts;
}

static int get_current_cpu(void) {
  CPUState *cpu_single_cpu;
  if (!cpu_single_env) {
    return -1;
  }
  cpu_single_cpu = ENV_GET_CPU(cpu_single_env);
  return cpu_single_cpu->cpu_index;
}

static void copy_sbr_grid(SBRData *dst, const SBRData *src) {
  dst->bs_freq_res[0] = dst->bs_freq_res[dst->bs_num_env];
  dst->t_env_num_env_old = dst->t_env[dst->bs_num_env];
  dst->e_a[0] = -(dst->e_a[1] != dst->bs_num_env);
  memcpy(dst->bs_freq_res + 1, src->bs_freq_res + 1,
         sizeof(dst->bs_freq_res) - sizeof(*dst->bs_freq_res));
  memcpy(dst->t_env, src->t_env, sizeof(dst->t_env));
  memcpy(dst->t_q, src->t_q, sizeof(dst->t_q));
  dst->bs_num_env = src->bs_num_env;
  dst->bs_amp_res = src->bs_amp_res;
  dst->bs_num_noise = src->bs_num_noise;
  dst->bs_frame_class = src->bs_frame_class;
  dst->e_a[1] = src->e_a[1];
}

