static int aes_cbc_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                          const unsigned char *in, size_t len) {
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  if (dat->stream.cbc)
    (*dat->stream.cbc)(in, out, len, &dat->ks, EVP_CIPHER_CTX_iv_noconst(ctx),
                       EVP_CIPHER_CTX_encrypting(ctx));
  else if (EVP_CIPHER_CTX_encrypting(ctx))
    CRYPTO_cbc128_encrypt(in, out, len, &dat->ks,
                          EVP_CIPHER_CTX_iv_noconst(ctx), dat->block);
  else
    CRYPTO_cbc128_decrypt(in, out, len, &dat->ks,
                          EVP_CIPHER_CTX_iv_noconst(ctx), dat->block);
  return 1;
}
static int aes_ecb_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                          const unsigned char *in, size_t len) {
  size_t bl = EVP_CIPHER_CTX_block_size(ctx);
  size_t i;
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  if (len < bl)
    return 1;
  for (i = 0, len -= bl; i <= len; i += bl)
    (*dat->block)(in + i, out + i, &dat->ks);
  return 1;
}
static int aes_ofb_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                          const unsigned char *in, size_t len) {
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  int num = EVP_CIPHER_CTX_num(ctx);
  CRYPTO_ofb128_encrypt(in, out, len, &dat->ks, EVP_CIPHER_CTX_iv_noconst(ctx),
                        &num, dat->block);
  EVP_CIPHER_CTX_set_num(ctx, num);
  return 1;
}
static int aes_cfb_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                          const unsigned char *in, size_t len) {
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  int num = EVP_CIPHER_CTX_num(ctx);
  CRYPTO_cfb128_encrypt(in, out, len, &dat->ks, EVP_CIPHER_CTX_iv_noconst(ctx),
                        &num, EVP_CIPHER_CTX_encrypting(ctx), dat->block);
  EVP_CIPHER_CTX_set_num(ctx, num);
  return 1;
}
static int aes_cfb8_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                           const unsigned char *in, size_t len) {
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  int num = EVP_CIPHER_CTX_num(ctx);
  CRYPTO_cfb128_8_encrypt(in, out, len, &dat->ks,
                          EVP_CIPHER_CTX_iv_noconst(ctx), &num,
                          EVP_CIPHER_CTX_encrypting(ctx), dat->block);
  EVP_CIPHER_CTX_set_num(ctx, num);
  return 1;
}
static int aes_cfb1_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                           const unsigned char *in, size_t len) {
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  if (EVP_CIPHER_CTX_test_flags(ctx, EVP_CIPH_FLAG_LENGTH_BITS)) {
    int num = EVP_CIPHER_CTX_num(ctx);
    CRYPTO_cfb128_1_encrypt(in, out, len, &dat->ks,
                            EVP_CIPHER_CTX_iv_noconst(ctx), &num,
                            EVP_CIPHER_CTX_encrypting(ctx), dat->block);
    EVP_CIPHER_CTX_set_num(ctx, num);
    return 1;
  }
  while (len >= MAXBITCHUNK) {
    int num = EVP_CIPHER_CTX_num(ctx);
    CRYPTO_cfb128_1_encrypt(in, out, MAXBITCHUNK * 8, &dat->ks,
                            EVP_CIPHER_CTX_iv_noconst(ctx), &num,
                            EVP_CIPHER_CTX_encrypting(ctx), dat->block);
    EVP_CIPHER_CTX_set_num(ctx, num);
    len -= MAXBITCHUNK;
  }
  if (len) {
    int num = EVP_CIPHER_CTX_num(ctx);
    CRYPTO_cfb128_1_encrypt(in, out, len * 8, &dat->ks,
                            EVP_CIPHER_CTX_iv_noconst(ctx), &num,
                            EVP_CIPHER_CTX_encrypting(ctx), dat->block);
    EVP_CIPHER_CTX_set_num(ctx, num);
  }
  return 1;
}
static int aes_ctr_cipher(EVP_CIPHER_CTX *ctx, unsigned char *out,
                          const unsigned char *in, size_t len) {
  unsigned int num = EVP_CIPHER_CTX_num(ctx);
  EVP_AES_KEY *dat = EVP_C_DATA(EVP_AES_KEY, ctx);
  if (dat->stream.ctr)
    CRYPTO_ctr128_encrypt_ctr32(
        in, out, len, &dat->ks, EVP_CIPHER_CTX_iv_noconst(ctx),
        EVP_CIPHER_CTX_buf_noconst(ctx), &num, dat->stream.ctr);
  else
    CRYPTO_ctr128_encrypt(in, out, len, &dat->ks,
                          EVP_CIPHER_CTX_iv_noconst(ctx),
                          EVP_CIPHER_CTX_buf_noconst(ctx), &num, dat->block);
  EVP_CIPHER_CTX_set_num(ctx, num);
  return 1;
}
