      assert(use_16bit_internal);
      if (!allocated_raw_shift) {
        vpx_img_alloc(&raw_shift, raw.fmt | VPX_IMG_FMT_HIGHBITDEPTH,
                      input.width, input.height, 32);
        allocated_raw_shift = 1;
      }
      img_upshift(&raw_shift, &raw, input_shift);
      frame_to_encode = &raw_shift;
    } else {
      frame_to_encode = &raw;
    }
    vpx_usec_timer_start(&timer);
    if (use_16bit_internal) {
      assert(frame_to_encode->fmt & VPX_IMG_FMT_HIGHBITDEPTH);
      FOREACH_STREAM({
        if (stream->config.use_16bit_internal)
          encode_frame(stream, &global, frame_avail ? frame_to_encode : NULL,
                       frames_in);
        else
          assert(0);
      });
    } else {
      assert((frame_to_encode->fmt & VPX_IMG_FMT_HIGHBITDEPTH) == 0);
      FOREACH_STREAM(encode_frame(
          stream, &global, frame_avail ? frame_to_encode : NULL, frames_in));
    }
#else vpx_usec_timer_start(&timer);
      FOREACH_STREAM(
          encode_frame(stream, &global, frame_avail ? &raw : NULL, frames_in));
#endif vpx_usec_timer_mark(&timer);
    cx_time += vpx_usec_timer_elapsed(&timer);
    FOREACH_STREAM(update_quantizer_histogram(stream));
    got_data = 0;
    FOREACH_STREAM(get_cx_data(stream, &global, &got_data));
    if (!got_data && input.length && streams != NULL && !streams->frames_out) {
      lagged_count = global.limit ? seen_frames : ftello(input.file);
    } else if (input.length) {
      int64_t remaining;
      int64_t rate;
      if (global.limit) {
        const int64_t frame_in_lagged = (seen_frames - lagged_count) * 1000;
        rate = cx_time ? frame_in_lagged * (int64_t)1000000 / cx_time : 0;
        remaining = 1000 * (global.limit - global.skip_frames - seen_frames +
                            lagged_count);
      } else {
        const int64_t input_pos = ftello(input.file);
        const int64_t input_pos_lagged = input_pos - lagged_count;
        const int64_t limit = input.length;
        rate = cx_time ? input_pos_lagged * (int64_t)1000000 / cx_time : 0;
        remaining = limit - input_pos + lagged_count;
      }
      average_rate = (average_rate <= 0) ? rate : (average_rate * 7 + rate) / 8;
      estimated_time_left = average_rate ? remaining / average_rate : -1;
    }
    if (got_data && global.test_decode != TEST_DECODE_OFF)
      FOREACH_STREAM(test_decode(stream, global.test_decode, global.codec));
  }
  fflush(stdout);
  if (!global.quiet)
    fprintf(stderr, "\033[K");
}
if (stream_cnt > 1)
  fprintf(stderr, "\n");
if (!global.quiet)
  FOREACH_STREAM(fprintf(stderr,
                         "\rPass %d/%d frame %4d/%-4d %7" PRId64
                         "B %7lub/f %7" PRId64 "b/s"
                         " %7" PRId64 " %s (%.2f fps)\033[K\n",
                         pass + 1, global.passes, frames_in, stream->frames_out,
                         (int64_t)stream->nbytes,
                         seen_frames
                             ? (unsigned long)(stream->nbytes * 8 / seen_frames)
                             : 0,
                         seen_frames ? (int64_t)stream->nbytes * 8 *
                                           (int64_t)global.framerate.num /
                                           global.framerate.den / seen_frames
                                     : 0,
                         stream->cx_time > 9999999 ? stream->cx_time / 1000
                                                   : stream->cx_time,
                         stream->cx_time > 9999999 ? "ms" : "us",
                         usec_to_fps(stream->cx_time, seen_frames)););
if (global.show_psnr)
  FOREACH_STREAM(show_psnr(stream));
FOREACH_STREAM(vpx_codec_destroy(&stream->encoder));
if (global.test_decode != TEST_DECODE_OFF) {
  FOREACH_STREAM(vpx_codec_destroy(&stream->decoder));
}
close_input_file(&input);
if (global.test_decode == TEST_DECODE_FATAL) {
  FOREACH_STREAM(res |= stream->mismatch_seen);
}
FOREACH_STREAM(close_output_file(stream, global.codec->fourcc));
FOREACH_STREAM(stats_close(&stream->stats, global.passes - 1));
#if CONFIG_FP_MB_STATS FOREACH_STREAM(                                         \
    stats_close(&stream->fpmb_stats, global.passes - 1));
#endif if (global.pass) break;
}
if (global.show_q_hist_buckets)
  FOREACH_STREAM(show_q_histogram(stream->counts, global.show_q_hist_buckets));
if (global.show_rate_hist_buckets)
  FOREACH_STREAM(show_rate_histogram(stream->rate_hist, &stream->config.cfg,
                                     global.show_rate_hist_buckets));
FOREACH_STREAM(destroy_rate_histogram(stream->rate_hist));
#if CONFIG_INTERNAL_STATS if (!(global.pass == 1 && global.passes == 2))       \
    FOREACH_STREAM({
FILE *f = fopen("opsnr.stt", "a");
if (stream->mismatch_seen) {
  fprintf(f, "First mismatch occurred in frame %d\n", stream->mismatch_seen);
} else {
  fprintf(f, "No mismatch detected in recon buffers\n");
}
fclose(f);
}
 ) ;
#endif #if CONFIG_VP9 &&CONFIG_VP9_HIGHBITDEPTH if (allocated_raw_shift)       \
    vpx_img_free(&raw_shift);
#endif vpx_img_free(&raw);
 free(argv);
 free(streams);
 return res ? EXIT_FAILURE : EXIT_SUCCESS;
 }

