void nautilus_directory_cancel_callback_internal(
    NautilusDirectory *directory, NautilusFile *file,
    NautilusDirectoryCallback directory_callback,
    NautilusFileCallback file_callback, gpointer callback_data) {
  ReadyCallback callback;
  GList *node;
  if (directory == NULL) {
    return;
  }
  g_assert(NAUTILUS_IS_DIRECTORY(directory));
  g_assert(file == NULL || NAUTILUS_IS_FILE(file));
  g_assert(file != NULL || directory_callback != NULL);
  g_assert(file == NULL || file_callback != NULL);
  callback.file = file;
  if (file == NULL) {
    callback.callback.directory = directory_callback;
  } else {
    callback.callback.file = file_callback;
  }
  callback.callback_data = callback_data;
  do {
    node = g_list_find_custom(directory->details->call_when_ready_list,
                              &callback, ready_callback_key_compare);
    if (node != NULL) {
      remove_callback_link(directory, node);
      nautilus_directory_async_state_changed(directory);
    }
  } while (node != NULL);
}

void mark_progress(struct st_command *command __attribute__((unused)),
                   int line) {
  static ulonglong progress_start = 0;
  DYNAMIC_STRING ds_progress;
  char buf[32], *end;
  ulonglong timer = timer_now();
  if (!progress_start)
    progress_start = timer;
  timer -= progress_start;
  if (init_dynamic_string(&ds_progress, "", 256, 256))
    die("Out of memory");
  end = longlong10_to_str(timer, buf, 10);
  dynstr_append_mem(&ds_progress, buf, (int)(end - buf));
  dynstr_append_mem(&ds_progress, "\t", 1);
  end = int10_to_str(line, buf, 10);
  dynstr_append_mem(&ds_progress, buf, (int)(end - buf));
  dynstr_append_mem(&ds_progress, "\t", 1);
  dynstr_append(&ds_progress, cur_file->file_name);
  dynstr_append_mem(&ds_progress, ":", 1);
  end = int10_to_str(cur_file->lineno, buf, 10);
  dynstr_append_mem(&ds_progress, buf, (int)(end - buf));
  dynstr_append_mem(&ds_progress, "\n", 1);
  progress_file.write(&ds_progress);
  dynstr_free(&ds_progress);
}

