void ssl3_free(SSL *s) {
  if (s == NULL)
    return;
#ifdef TLSEXT_TYPE_opaque_prf_input if (s->s3->client_opaque_prf_input !=      \
                                        NULL)                                  \
    OPENSSL_free(s->s3->client_opaque_prf_input);
  if (s->s3->server_opaque_prf_input != NULL)
    OPENSSL_free(s->s3->server_opaque_prf_input);
#endif ssl3_cleanup_key_block(s);
  if (s->s3->rbuf.buf != NULL)
    ssl3_release_read_buffer(s);
  if (s->s3->wbuf.buf != NULL)
    ssl3_release_write_buffer(s);
  if (s->s3->rrec.comp != NULL)
    OPENSSL_free(s->s3->rrec.comp);
#ifndef OPENSSL_NO_DH if (s->s3->tmp.dh != NULL) DH_free(s->s3->tmp.dh);
#endif #ifndef OPENSSL_NO_ECDH if (s->s3->tmp.ecdh != NULL)                    \
    EC_KEY_free(s->s3->tmp.ecdh);
#endif if (s->s3->tmp.ca_names != NULL)                                        \
    sk_X509_NAME_pop_free(s->s3->tmp.ca_names, X509_NAME_free);
  if (s->s3->handshake_buffer) {
    BIO_free(s->s3->handshake_buffer);
  }
  if (s->s3->handshake_dgst)
    ssl3_free_digest_list(s);
#ifndef OPENSSL_NO_SRP SSL_SRP_CTX_free(s);
#endif OPENSSL_cleanse(s->s3, sizeof *s->s3);
  OPENSSL_free(s->s3);
  s->s3 = NULL;
}

int vp9_receive_raw_frame(VP9_COMP *cpi, unsigned int frame_flags,
                          YV12_BUFFER_CONFIG *sd, int64_t time_stamp,
                          int64_t end_time) {
  VP9_COMMON *cm = &cpi->common;
  struct vpx_usec_timer timer;
  int res = 0;
  const int subsampling_x = sd->uv_width < sd->y_width;
  const int subsampling_y = sd->uv_height < sd->y_height;
  check_initial_width(cpi, subsampling_x, subsampling_y);
  vpx_usec_timer_start(&timer);
#if CONFIG_SPATIAL_SVC if (is_two_pass_svc(cpi)) res = vp9_svc_lookahead_push( \
    cpi, cpi->lookahead, sd, time_stamp, end_time, frame_flags);
  else #endif res =
      vp9_lookahead_push(cpi->lookahead, sd, time_stamp, end_time, frame_flags);
  if (res)
    res = -1;
  vpx_usec_timer_mark(&timer);
  cpi->time_receive_data += vpx_usec_timer_elapsed(&timer);
  if ((cm->profile == PROFILE_0 || cm->profile == PROFILE_2) &&
      (subsampling_x != 1 || subsampling_y != 1)) {
    vpx_internal_error(&cm->error, VPX_CODEC_INVALID_PARAM,
                       "Non-4:2:0 color space requires profile 1 or 3");
    res = -1;
  }
  if ((cm->profile == PROFILE_1 || cm->profile == PROFILE_3) &&
      (subsampling_x == 1 && subsampling_y == 1)) {
    vpx_internal_error(&cm->error, VPX_CODEC_INVALID_PARAM,
                       "4:2:0 color space requires profile 0 or 2");
    res = -1;
  }
  return res;
}

