static bool parse_ipAddrBlocks(chunk_t blob, int level0,
                               private_x509_cert_t *this) {
  asn1_parser_t *parser;
  chunk_t object, min_object;
  ts_type_t ts_type = 0;
  traffic_selector_t *ts;
  int objectID;
  bool success = FALSE;
  parser = asn1_parser_create(ipAddrBlocksObjects, blob);
  parser->set_top_level(parser, level0);
  while (parser->iterate(parser, &objectID, &object)) {
    switch (objectID) {
    case IP_ADDR_BLOCKS_FAMILY:
      ts_type = 0;
      if (object.len == 2 && object.ptr[0] == 0) {
        if (object.ptr[1] == 1) {
          ts_type = TS_IPV4_ADDR_RANGE;
        } else if (object.ptr[1] == 2) {
          ts_type = TS_IPV6_ADDR_RANGE;
        } else {
          break;
        }
        DBG2(DBG_ASN, " %N", ts_type_name, ts_type);
      }
      break;
    case IP_ADDR_BLOCKS_INHERIT:
      DBG1(DBG_ASN, "inherit choice is not supported");
      break;
    case IP_ADDR_BLOCKS_PREFIX:
      if (!check_address_object(ts_type, object)) {
        goto end;
      }
      ts = traffic_selector_create_from_rfc3779_format(ts_type, object, object);
      DBG2(DBG_ASN, " %R", ts);
      this->ipAddrBlocks->insert_last(this->ipAddrBlocks, ts);
      break;
    case IP_ADDR_BLOCKS_MIN:
      if (!check_address_object(ts_type, object)) {
        goto end;
      }
      min_object = object;
      break;
    case IP_ADDR_BLOCKS_MAX:
      if (!check_address_object(ts_type, object)) {
        goto end;
      }
      ts = traffic_selector_create_from_rfc3779_format(ts_type, min_object,
                                                       object);
      DBG2(DBG_ASN, " %R", ts);
      this->ipAddrBlocks->insert_last(this->ipAddrBlocks, ts);
      break;
    default:
      break;
    }
  }
  success = parser->success(parser);
  this->flags |= X509_IP_ADDR_BLOCKS;
end:
  parser->destroy(parser);
  return success;
}

static Node *substitute_actual_parameters_mutator(
    Node *node, substitute_actual_parameters_context *context) {
  if (node == NULL)
    return NULL;
  if (IsA(node, Param)) {
    Param *param = (Param *)node;
    if (param->paramkind != PARAM_EXTERN)
      elog(ERROR, "unexpected paramkind: %d", (int)param->paramkind);
    if (param->paramid <= 0 || param->paramid > context->nargs)
      elog(ERROR, "invalid paramid: %d", param->paramid);
    context->usecounts[param->paramid - 1]++;
    return list_nth(context->args, param->paramid - 1);
  }
  return expression_tree_mutator(node, substitute_actual_parameters_mutator,
                                 (void *)context);
}

static bfd_boolean srec_get_section_contents(bfd *abfd, asection *section,
                                             void *location, file_ptr offset,
                                             bfd_size_type count) {
  if (count == 0)
    return TRUE;
  if (offset + count < count || offset + count > section->size) {
    bfd_set_error(bfd_error_invalid_operation);
    return FALSE;
  }
  if (section->used_by_bfd == NULL) {
    section->used_by_bfd = bfd_alloc(abfd, section->size);
    if (section->used_by_bfd == NULL)
      return FALSE;
    if (!srec_read_section(abfd, section, (bfd_byte *)section->used_by_bfd))
      return FALSE;
  }
  memcpy(location, (bfd_byte *)section->used_by_bfd + offset, (size_t)count);
  return TRUE;
}

static int SpoolssSetJob_q(tvbuff_t *tvb, int offset, packet_info *pinfo,
                           proto_tree *tree, dcerpc_info *di, guint8 *drep) {
  guint32 jobid, cmd;
  offset = dissect_nt_policy_hnd(tvb, offset, pinfo, tree, di, drep, hf_hnd,
                                 NULL, NULL, FALSE, FALSE);
  offset =
      dissect_ndr_uint32(tvb, offset, pinfo, tree, di, drep, hf_job_id, &jobid);
  offset =
      dissect_ndr_uint32(tvb, offset, pinfo, tree, di, drep, hf_level, NULL);
  offset = dissect_ndr_uint32(tvb, offset, pinfo, tree, di, drep, hf_setjob_cmd,
                              &cmd);
  col_append_fstr(pinfo->cinfo, COL_INFO, ", %s jobid %d",
                  val_to_str(cmd, setjob_commands, "Unknown (%d)"), jobid);
  return offset;
}

static int gdev_pdf_put_params_impl(gx_device *dev,
                                    const gx_device_pdf *save_dev,
                                    gs_param_list *plist) {
  int ecode, code;
  gx_device_pdf *pdev = (gx_device_pdf *)dev;
  float cl = (float)pdev->CompatibilityLevel;
  bool locked = pdev->params.LockDistillerParams, ForOPDFRead;
  gs_param_name param_name;
  pdev->pdf_memory = gs_memory_stable(pdev->memory);
  {
    gs_param_string_array ppa;
    gs_param_string pps;
    code = param_read_string_array(plist, (param_name = "pdfmark"), &ppa);
    switch (code) {
    case 0:
      code = pdfwrite_pdf_open_document(pdev);
      if (code < 0)
        return code;
      code = pdfmark_process(pdev, &ppa);
      if (code >= 0)
        return code;
    default:
      param_signal_error(plist, param_name, code);
      return code;
    case 1:
      break;
    }
    code = param_read_string_array(plist, (param_name = "DSC"), &ppa);
    switch (code) {
    case 0:
      code = pdfwrite_pdf_open_document(pdev);
      if (code < 0)
        return code;
      code = pdf_dsc_process(pdev, &ppa);
      if (code >= 0)
        return code;
    default:
      param_signal_error(plist, param_name, code);
      return code;
    case 1:
      break;
    }
    code = param_read_string(plist, (param_name = "pdfpagelabels"), &pps);
    switch (code) {
    case 0: {
      if (!pdev->ForOPDFRead) {
        cos_dict_t *const pcd = pdev->Catalog;
        code = pdfwrite_pdf_open_document(pdev);
        if (code < 0)
          return code;
        code = cos_dict_put_string(pcd, (const byte *)"/PageLabels", 11,
                                   pps.data, pps.size);
        if (code >= 0)
          return code;
      } else
        return 0;
    }
    default:
      param_signal_error(plist, param_name, code);
      return code;
    case 1:
      break;
    }
  }
  ecode = param_read_bool(plist, (param_name = "LockDistillerParams"), &locked);
  if (ecode < 0)
    param_signal_error(plist, param_name, ecode);
  {
    int efo = 1;
    ecode =
        param_put_int(plist, (param_name = ".EmbedFontObjects"), &efo, ecode);
    if (ecode < 0)
      param_signal_error(plist, param_name, ecode);
    if (efo != 1)
      param_signal_error(plist, param_name, ecode = gs_error_rangecheck);
  }
  {
    int cdv = CoreDistVersion;
    ecode = param_put_int(plist, (param_name = "CoreDistVersion"), &cdv, ecode);
    if (ecode < 0)
      return gs_note_error(ecode);
    if (cdv != CoreDistVersion)
      param_signal_error(plist, param_name, ecode = gs_error_rangecheck);
  }
  switch (code = param_read_float(plist, (param_name = "CompatibilityLevel"),
                                  &cl)) {
  default:
    ecode = code;
    param_signal_error(plist, param_name, ecode);
    break;
  case 0:
    if (!(locked && pdev->params.LockDistillerParams)) {
      if (cl < (float)1.15)
        cl = (float)1.1;
      else if (cl < (float)1.25)
        cl = (float)1.2;
      else if (cl < (float)1.35)
        cl = (float)1.3;
      else if (cl < (float)1.45)
        cl = (float)1.4;
      else if (cl < (float)1.55)
        cl = (float)1.5;
      else if (cl < (float)1.65)
        cl = (float)1.6;
      else if (cl < (float)1.75)
        cl = (float)1.7;
      else {
        cl = (float)2.0;
        if (pdev->params.TransferFunctionInfo == tfi_Preserve)
          pdev->params.TransferFunctionInfo = tfi_Apply;
      }
    }
  case 1:
    break;
  }
  {
    gs_memory_t *mem = plist->memory;
    plist->memory = pdev->pdf_memory;
    code = gs_param_read_items(plist, pdev, pdf_param_items);
    if (code < 0 ||
        (code = param_read_bool(plist, "ForOPDFRead", &ForOPDFRead)) < 0) {
    }
    if (code == 0 && !pdev->is_ps2write &&
        !(locked && pdev->params.LockDistillerParams))
      pdev->ForOPDFRead = ForOPDFRead;
    plist->memory = mem;
  }
  if (code < 0)
    ecode = code;
  {
    long fon = pdev->FirstObjectNumber;
    if (fon != save_dev->FirstObjectNumber) {
      if (fon <= 0 || fon > 0x7fff0000 ||
          (pdev->next_id != 0 && pdev->next_id != save_dev->FirstObjectNumber +
                                                      pdf_num_initial_ids)) {
        ecode = gs_error_rangecheck;
        param_signal_error(plist, "FirstObjectNumber", ecode);
      }
    }
  }
  {
    static const char *const pcm_names[] = {"DeviceGray", "DeviceRGB",
                                            "DeviceCMYK", "DeviceN", 0};
    int pcm = -1;
    ecode = param_put_enum(plist, "ProcessColorModel", &pcm, pcm_names, ecode);
    if (pcm >= 0) {
      pdf_set_process_color_model(pdev, pcm);
      rc_decrement(pdev->icc_struct,
                   "gdev_pdf_put_params_impl, ProcessColorModel changed");
      pdev->icc_struct = 0;
    }
  }
  if (ecode < 0)
    goto fail;
  if (pdev->is_ps2write &&
      (code = param_read_bool(plist, "ProduceDSC", &pdev->ProduceDSC)) < 0) {
    param_signal_error(plist, param_name, code);
  }
  if (pdev->PDFA < 0 || pdev->PDFA > 3) {
    ecode = gs_note_error(gs_error_rangecheck);
    param_signal_error(plist, "PDFA", ecode);
    goto fail;
  }
  if (pdev->PDFA != 0 && pdev->AbortPDFAX)
    pdev->PDFA = 0;
  if (pdev->PDFX && pdev->AbortPDFAX)
    pdev->PDFX = 0;
  if (pdev->PDFX && pdev->PDFA != 0) {
    ecode = gs_note_error(gs_error_rangecheck);
    param_signal_error(plist, "PDFA", ecode);
    goto fail;
  }
  if (pdev->PDFX && pdev->ForOPDFRead) {
    ecode = gs_note_error(gs_error_rangecheck);
    param_signal_error(plist, "PDFX", ecode);
    goto fail;
  }
  if (pdev->PDFA != 0 && pdev->ForOPDFRead) {
    ecode = gs_note_error(gs_error_rangecheck);
    param_signal_error(plist, "PDFA", ecode);
    goto fail;
  }
  if (pdev->PDFA == 1 || pdev->PDFX || pdev->CompatibilityLevel < 1.4) {
    pdev->HaveTransparency = false;
    pdev->PreserveSMask = false;
  }
  if (pdev->PDFX)
    cl = (float)1.3;
  if (pdev->PDFA != 0 && cl < 1.4)
    cl = (float)1.4;
  pdev->version = (cl < 1.2 ? psdf_version_level2 : psdf_version_ll3);
  if (pdev->ForOPDFRead) {
    pdev->ResourcesBeforeUsage = true;
    pdev->HaveCFF = false;
    pdev->HavePDFWidths = false;
    pdev->HaveStrokeColor = false;
    cl = (float)1.2;
    pdev->MaxInlineImageSize = max_long;
    pdev->version = psdf_version_level2;
  } else {
    pdev->ResourcesBeforeUsage = false;
    pdev->HaveCFF = true;
    pdev->HavePDFWidths = true;
    pdev->HaveStrokeColor = true;
  }
  pdev->ParamCompatibilityLevel = cl;
  if (cl < 1.2) {
    pdev->HaveCFF = false;
  }
  ecode = gdev_psdf_put_params(dev, plist);
  if (ecode < 0)
    goto fail;
  if (pdev->CompatibilityLevel > 1.7 &&
      pdev->params.TransferFunctionInfo == tfi_Preserve) {
    pdev->params.TransferFunctionInfo = tfi_Apply;
    emprintf(pdev->memory,
             "\nIt is not possible to preserve transfer functions in PDF "
             "2.0\ntransfer functions will be applied instead\n");
  }
  if (pdev->params.ConvertCMYKImagesToRGB) {
    if (pdev->params.ColorConversionStrategy == ccs_CMYK) {
      emprintf(pdev->memory, "ConvertCMYKImagesToRGB is not compatible with "
                             "ColorConversionStrategy of CMYK\n");
    } else {
      if (pdev->params.ColorConversionStrategy == ccs_Gray) {
        emprintf(pdev->memory, "ConvertCMYKImagesToRGB is not compatible with "
                               "ColorConversionStrategy of Gray\n");
      } else {
        if (pdev->icc_struct)
          rc_decrement(pdev->icc_struct, "reset default profile\n");
        pdf_set_process_color_model(pdev, 1);
        ecode = gsicc_init_device_profile_struct((gx_device *)pdev, NULL, 0);
        if (ecode < 0)
          goto fail;
      }
    }
  }
  switch (pdev->params.ColorConversionStrategy) {
  case ccs_ByObjectType:
  case ccs_LeaveColorUnchanged:
    break;
  case ccs_UseDeviceDependentColor:
  case ccs_UseDeviceIndependentColor:
  case ccs_UseDeviceIndependentColorForImages:
    pdev->params.TransferFunctionInfo = tfi_Apply;
    break;
  case ccs_CMYK:
    pdev->params.TransferFunctionInfo = tfi_Apply;
    if (pdev->icc_struct)
      rc_decrement(pdev->icc_struct, "reset default profile\n");
    pdf_set_process_color_model(pdev, 2);
    ecode = gsicc_init_device_profile_struct((gx_device *)pdev, NULL, 0);
    if (ecode < 0)
      goto fail;
    break;
  case ccs_Gray:
    pdev->params.TransferFunctionInfo = tfi_Apply;
    if (pdev->icc_struct)
      rc_decrement(pdev->icc_struct, "reset default profile\n");
    pdf_set_process_color_model(pdev, 0);
    ecode = gsicc_init_device_profile_struct((gx_device *)pdev, NULL, 0);
    if (ecode < 0)
      goto fail;
    break;
  case ccs_sRGB:
  case ccs_RGB:
    pdev->params.TransferFunctionInfo = tfi_Apply;
    if (!pdev->params.ConvertCMYKImagesToRGB) {
      if (pdev->icc_struct)
        rc_decrement(pdev->icc_struct, "reset default profile\n");
      pdf_set_process_color_model(pdev, 1);
      ecode = gsicc_init_device_profile_struct((gx_device *)pdev, NULL, 0);
      if (ecode < 0)
        goto fail;
    }
    break;
  default:
    break;
  }
  if (cl < 1.5f && pdev->params.ColorImage.Filter != NULL &&
      !strcmp(pdev->params.ColorImage.Filter, "JPXEncode")) {
    emprintf(pdev->memory, "JPXEncode requires CompatibilityLevel >= 1.5 .\n");
    ecode = gs_note_error(gs_error_rangecheck);
  }
  if (cl < 1.5f && pdev->params.GrayImage.Filter != NULL &&
      !strcmp(pdev->params.GrayImage.Filter, "JPXEncode")) {
    emprintf(pdev->memory, "JPXEncode requires CompatibilityLevel >= 1.5 .\n");
    ecode = gs_note_error(gs_error_rangecheck);
  }
  if (cl < 1.4f && pdev->params.MonoImage.Filter != NULL &&
      !strcmp(pdev->params.MonoImage.Filter, "JBIG2Encode")) {
    emprintf(pdev->memory,
             "JBIG2Encode requires CompatibilityLevel >= 1.4 .\n");
    ecode = gs_note_error(gs_error_rangecheck);
  }
  if (pdev->HaveTrueTypes && pdev->version == psdf_version_level2) {
    pdev->version = psdf_version_level2_with_TT;
  }
  if (ecode < 0)
    goto fail;
  if (pdev->FirstObjectNumber != save_dev->FirstObjectNumber) {
    if (pdev->xref.file != 0) {
      if (gp_fseek_64(pdev->xref.file, 0L, SEEK_SET) != 0) {
        ecode = gs_error_ioerror;
        goto fail;
      }
      pdf_initialize_ids(pdev);
    }
  }
  pdev->CompatibilityLevel = (int)(cl * 10 + 0.5) / 10.0;
  if (pdev->OwnerPassword.size != save_dev->OwnerPassword.size ||
      (pdev->OwnerPassword.size != 0 &&
       memcmp(pdev->OwnerPassword.data, save_dev->OwnerPassword.data,
              pdev->OwnerPassword.size) != 0)) {
    if (pdev->is_open) {
      if (pdev->PageCount == 0) {
        gs_closedevice((gx_device *)save_dev);
        return 0;
      } else
        emprintf(pdev->memory, "Owner Password changed mid-job, ignoring.\n");
    }
  }
  if (pdev->Linearise && pdev->is_ps2write) {
    emprintf(pdev->memory, "Can't linearise PostScript output, ignoring\n");
    pdev->Linearise = false;
  }
  if (pdev->Linearise && pdev->OwnerPassword.size != 0) {
    emprintf(pdev->memory, "Can't linearise encrypted PDF, ignoring\n");
    pdev->Linearise = false;
  }
  if (pdev->FlattenFonts)
    pdev->PreserveTrMode = false;
  return 0;
fail:
  pdev->version = save_dev->version;
  pdf_set_process_color_model(pdev, save_dev->pcm_color_info_index);
  pdev->saved_fill_color = save_dev->saved_fill_color;
  pdev->saved_stroke_color = save_dev->saved_fill_color;
  {
    const gs_param_item_t *ppi = pdf_param_items;
    for (; ppi->key; ++ppi)
      memcpy((char *)pdev + ppi->offset, (char *)save_dev + ppi->offset,
             gs_param_type_sizes[ppi->type]);
    pdev->ForOPDFRead = save_dev->ForOPDFRead;
  }
  return ecode;
}

