static void docmd(const char *cmdline) {
  char *tokens[1 + MAXARGS + 2];
  struct parse pcmd;
  int ntok;
  static int i;
  struct xcmd *xcmd;
  tokenize(cmdline, tokens, &ntok);
  if (ntok == 0)
    return;
  i = findcmd(tokens[0], builtins, opcmds, &xcmd);
  if (i == 0) {
    (void)fprintf(stderr, "***Command `%s' unknown\n", tokens[0]);
    return;
  } else if (i >= 2) {
    (void)fprintf(stderr, "***Command `%s' ambiguous\n", tokens[0]);
    return;
  }
  for (i = MAXARGS + 1; i < ntok; ++i) {
    fprintf(stderr, "***Extra arg `%s' ignored\n", tokens[i]);
  }
  pcmd.keyword = tokens[0];
  pcmd.nargs = 0;
  for (i = 0; i < MAXARGS && xcmd->arg[i] != NO; i++) {
    if ((i + 1) >= ntok) {
      if (!(xcmd->arg[i] & OPT)) {
        printusage(xcmd, stderr);
        return;
      }
      break;
    }
    if ((xcmd->arg[i] & OPT) && (*tokens[i + 1] == '>'))
      break;
    if (!getarg(tokens[i + 1], (int)xcmd->arg[i], &pcmd.argval[i]))
      return;
    pcmd.nargs++;
  }
  i++;
  if (i < ntok && *tokens[i] == '>') {
    char *fname;
    if (*(tokens[i] + 1) != '\0')
      fname = tokens[i] + 1;
    else if ((i + 1) < ntok)
      fname = tokens[i + 1];
    else {
      (void)fprintf(stderr, "***No file for redirect\n");
      return;
    }
    current_output = fopen(fname, "w");
    if (current_output == NULL) {
      (void)fprintf(stderr, "***Error opening %s: ", fname);
      perror("");
      return;
    }
    i = 1;
  } else {
    current_output = stdout;
    i = 0;
  }
  if (interactive && setjmp(interrupt_buf)) {
    jump = 0;
    return;
  } else {
    jump++;
    (xcmd->handler)(&pcmd, current_output);
    jump = 0;
    if (i)
      (void)fclose(current_output);
  }
  return;
}

static int64_t ticks_to_timebase_units(const vpx_rational_t *timebase,
                                       int64_t n) {
  const int64_t round = TICKS_PER_SEC * timebase->num / 2 - 1;
  return (n * timebase->den + round) / timebase->num / TICKS_PER_SEC;
}

static void fast_gray_to_cmyk(fz_context *ctx, fz_pixmap *dst, fz_pixmap *src,
                              fz_colorspace *prf,
                              const fz_default_colorspaces *default_cs,
                              const fz_color_params *color_params,
                              int copy_spots) {
  unsigned char *s = src->samples;
  unsigned char *d = dst->samples;
  size_t w = src->w;
  int h = src->h;
  int sn = src->n;
  int ss = src->s;
  int sa = src->alpha;
  int dn = dst->n;
  int ds = dst->s;
  int da = dst->alpha;
  ptrdiff_t d_line_inc = dst->stride - w * dn;
  ptrdiff_t s_line_inc = src->stride - w * sn;
  if ((copy_spots && ss != ds) || (!da && sa)) {
    assert("This should never happen" == NULL);
    fz_throw(ctx, FZ_ERROR_GENERIC,
             "Cannot convert between incompatible pixmaps");
  }
  if ((int)w < 0 || h < 0)
    return;
  if (d_line_inc == 0 && s_line_inc == 0) {
    w *= h;
    h = 1;
  }
  if (ss == 0 && ds == 0) {
    if (da) {
      if (sa) {
        while (h--) {
          size_t ww = w;
          while (ww--) {
            d[0] = 0;
            d[1] = 0;
            d[2] = 0;
            d[3] = 255 - s[0];
            d[4] = s[1];
            s += 2;
            d += 5;
          }
          d += d_line_inc;
          s += s_line_inc;
        }
      } else {
        while (h--) {
          size_t ww = w;
          while (ww--) {
            d[0] = 0;
            d[1] = 0;
            d[2] = 0;
            d[3] = 255 - s[0];
            d[4] = 255;
            s++;
            d += 5;
          }
          d += d_line_inc;
          s += s_line_inc;
        }
      }
    } else {
      while (h--) {
        size_t ww = w;
        while (ww--) {
          d[0] = 0;
          d[1] = 0;
          d[2] = 0;
          d[3] = 255 - s[0];
          s++;
          d += 4;
        }
        d += d_line_inc;
        s += s_line_inc;
      }
    }
  } else if (copy_spots) {
    int i;
    while (h--) {
      size_t ww = w;
      while (ww--) {
        d[0] = 0;
        d[1] = 0;
        d[2] = 0;
        d[3] = 255 - s[0];
        s += 1;
        d += 4;
        for (i = ss; i > 0; i--)
          *d++ = *s++;
        if (da)
          *d++ = sa ? *s++ : 255;
      }
      d += d_line_inc;
      s += s_line_inc;
    }
  } else {
    while (h--) {
      size_t ww = w;
      while (ww--) {
        d[0] = 0;
        d[1] = 0;
        d[2] = 0;
        d[3] = 255 - s[0];
        s += sn;
        d += dn;
        if (da)
          d[-1] = sa ? s[-1] : 255;
      }
      d += d_line_inc;
      s += s_line_inc;
    }
  }
}

