static void pdf_process_CS(fz_context *ctx, pdf_processor *proc, pdf_csi *csi,
                           int stroke) {
  if (!proc->op_CS || !proc->op_cs)
    return;
  if (!strcmp(csi->name, "Pattern")) {
    if (stroke)
      proc->op_CS(ctx, proc, "Pattern", NULL);
    else
      proc->op_cs(ctx, proc, "Pattern", NULL);
  } else {
    fz_colorspace *cs;
    if (!strcmp(csi->name, "DeviceGray"))
      cs = fz_keep_colorspace(ctx, fz_device_gray(ctx));
    else if (!strcmp(csi->name, "DeviceRGB"))
      cs = fz_keep_colorspace(ctx, fz_device_rgb(ctx));
    else if (!strcmp(csi->name, "DeviceCMYK"))
      cs = fz_keep_colorspace(ctx, fz_device_cmyk(ctx));
    else {
      pdf_obj *csres, *csobj;
      csres = pdf_dict_get(ctx, csi->rdb, PDF_NAME_ColorSpace);
      if (!csres)
        fz_throw(ctx, FZ_ERROR_SYNTAX, "cannot find ColorSpace dictionary");
      csobj = pdf_dict_gets(ctx, csres, csi->name);
      if (!csobj)
        fz_throw(ctx, FZ_ERROR_SYNTAX, "cannot find ColorSpace resource '%s'",
                 csi->name);
      cs = pdf_load_colorspace(ctx, csobj);
    }
    fz_try(ctx) {
      if (stroke)
        proc->op_CS(ctx, proc, csi->name, cs);
      else
        proc->op_cs(ctx, proc, csi->name, cs);
    }
    fz_always(ctx) fz_drop_colorspace(ctx, cs);
    fz_catch(ctx) fz_rethrow(ctx);
  }
}

static void send_mru_entry(mon_entry *mon, int count) {
  const char first_fmt[] = "first.%d";
  const char ct_fmt[] = "ct.%d";
  const char mv_fmt[] = "mv.%d";
  const char rs_fmt[] = "rs.%d";
  char tag[32];
  u_char sent[6];
  u_int32 noise;
  u_int which;
  u_int remaining;
  const char *pch;
  remaining = COUNTOF(sent);
  ZERO(sent);
  noise = (u_int32)(rand() ^ (rand() << 16));
  while (remaining > 0) {
    which = (noise & 7) % COUNTOF(sent);
    noise >>= 3;
    while (sent[which])
      which = (which + 1) % COUNTOF(sent);
    switch (which) {
    case 0:
      snprintf(tag, sizeof(tag), addr_fmt, count);
      pch = sptoa(&mon->rmtadr);
      ctl_putunqstr(tag, pch, strlen(pch));
      break;
    case 1:
      snprintf(tag, sizeof(tag), last_fmt, count);
      ctl_putts(tag, &mon->last);
      break;
    case 2:
      snprintf(tag, sizeof(tag), first_fmt, count);
      ctl_putts(tag, &mon->first);
      break;
    case 3:
      snprintf(tag, sizeof(tag), ct_fmt, count);
      ctl_putint(tag, mon->count);
      break;
    case 4:
      snprintf(tag, sizeof(tag), mv_fmt, count);
      ctl_putuint(tag, mon->vn_mode);
      break;
    case 5:
      snprintf(tag, sizeof(tag), rs_fmt, count);
      ctl_puthex(tag, mon->flags);
      break;
    }
    sent[which] = TRUE;
    remaining--;
  }
}

int qemuAssignDeviceChrAlias(virDomainDefPtr def, virDomainChrDefPtr chr,
                             ssize_t idx) {
  const char *prefix = NULL;
  switch ((virDomainChrDeviceType)chr->deviceType) {
  case VIR_DOMAIN_CHR_DEVICE_TYPE_PARALLEL:
    prefix = "parallel";
    break;
  case VIR_DOMAIN_CHR_DEVICE_TYPE_SERIAL:
    prefix = "serial";
    break;
  case VIR_DOMAIN_CHR_DEVICE_TYPE_CONSOLE:
    prefix = "console";
    break;
  case VIR_DOMAIN_CHR_DEVICE_TYPE_CHANNEL:
    prefix = "channel";
    break;
  case VIR_DOMAIN_CHR_DEVICE_TYPE_LAST:
    return -1;
  }
  if (idx == -1 && (idx = qemuGetNextChrDevIndex(def, chr, prefix)) < 0)
    return -1;
  return virAsprintf(&chr->info.alias, "%s%zd", prefix, idx);
}

static int sunrast_decode_frame(AVCodecContext *avctx, void *data,
                                int *got_frame, AVPacket *avpkt) {
  const uint8_t *buf = avpkt->data;
  const uint8_t *buf_end = avpkt->data + avpkt->size;
  SUNRASTContext *const s = avctx->priv_data;
  AVFrame *picture = data;
  AVFrame *const p = &s->picture;
  unsigned int w, h, depth, type, maptype, maplength, stride, x, y, len, alen;
  uint8_t *ptr;
  const uint8_t *bufstart = buf;
  int ret;
  if (avpkt->size < 32)
    return AVERROR_INVALIDDATA;
  if (AV_RB32(buf) != RAS_MAGIC) {
    av_log(avctx, AV_LOG_ERROR, "this is not sunras encoded data\n");
    return AVERROR_INVALIDDATA;
  }
  w = AV_RB32(buf + 4);
  h = AV_RB32(buf + 8);
  depth = AV_RB32(buf + 12);
  type = AV_RB32(buf + 20);
  maptype = AV_RB32(buf + 24);
  maplength = AV_RB32(buf + 28);
  buf += 32;
  if (type == RT_FORMAT_TIFF || type == RT_FORMAT_IFF ||
      type == RT_EXPERIMENTAL) {
    av_log_ask_for_sample(avctx, "unsupported (compression) type\n");
    return AVERROR_PATCHWELCOME;
  }
  if (type > RT_FORMAT_IFF) {
    av_log(avctx, AV_LOG_ERROR, "invalid (compression) type\n");
    return AVERROR_INVALIDDATA;
  }
  if (av_image_check_size(w, h, 0, avctx)) {
    av_log(avctx, AV_LOG_ERROR, "invalid image size\n");
    return AVERROR_INVALIDDATA;
  }
  if (maptype == RMT_RAW) {
    av_log_ask_for_sample(avctx, "unsupported colormap type\n");
    return AVERROR_PATCHWELCOME;
  }
  if (maptype > RMT_RAW) {
    av_log(avctx, AV_LOG_ERROR, "invalid colormap type\n");
    return AVERROR_INVALIDDATA;
  }
  switch (depth) {
  case 1:
    avctx->pix_fmt = AV_PIX_FMT_MONOWHITE;
    break;
  case 8:
    avctx->pix_fmt = maplength ? AV_PIX_FMT_PAL8 : AV_PIX_FMT_GRAY8;
    break;
  case 24:
    avctx->pix_fmt =
        (type == RT_FORMAT_RGB) ? AV_PIX_FMT_RGB24 : AV_PIX_FMT_BGR24;
    break;
  default:
    av_log(avctx, AV_LOG_ERROR, "invalid depth\n");
    return AVERROR_INVALIDDATA;
  }
  if (p->data[0])
    avctx->release_buffer(avctx, p);
  if (w != avctx->width || h != avctx->height)
    avcodec_set_dimensions(avctx, w, h);
  if ((ret = ff_get_buffer(avctx, p)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  p->pict_type = AV_PICTURE_TYPE_I;
  if (buf_end - buf < maplength)
    return AVERROR_INVALIDDATA;
  if (depth != 8 && maplength) {
    av_log(avctx, AV_LOG_WARNING,
           "useless colormap found or file is corrupted, trying to recover\n");
  } else if (maplength) {
    unsigned int len = maplength / 3;
    if (maplength % 3 || maplength > 768) {
      av_log(avctx, AV_LOG_WARNING, "invalid colormap length\n");
      return AVERROR_INVALIDDATA;
    }
    ptr = p->data[1];
    for (x = 0; x < len; x++, ptr += 4)
      *(uint32_t *)ptr =
          (buf[x] << 16) + (buf[len + x] << 8) + buf[len + len + x];
  }
  buf += maplength;
  ptr = p->data[0];
  stride = p->linesize[0];
  len = (depth * w + 7) >> 3;
  alen = len + (len & 1);
  if (type == RT_BYTE_ENCODED) {
    int value, run;
    uint8_t *end = ptr + h * stride;
    x = 0;
    while (ptr != end && buf < buf_end) {
      run = 1;
      if (buf_end - buf < 1)
        return AVERROR_INVALIDDATA;
      if ((value = *buf++) == RLE_TRIGGER) {
        run = *buf++ + 1;
        if (run != 1)
          value = *buf++;
      }
      while (run--) {
        if (x < len)
          ptr[x] = value;
        if (++x >= alen) {
          x = 0;
          ptr += stride;
          if (ptr == end)
            break;
        }
      }
    }
  } else {
    for (y = 0; y < h; y++) {
      if (buf_end - buf < len)
        break;
      memcpy(ptr, buf, len);
      ptr += stride;
      buf += alen;
    }
  }
  *picture = s->picture;
  *got_frame = 1;
  return buf - bufstart;
}

