static gboolean gst_asf_demux_activate_mode(GstPad *sinkpad, GstObject *parent,
                                            GstPadMode mode, gboolean active) {
  gboolean res;
  GstASFDemux *demux;
  demux = GST_ASF_DEMUX(parent);
  switch (mode) {
  case GST_PAD_MODE_PUSH:
    demux->state = GST_ASF_DEMUX_STATE_HEADER;
    demux->streaming = TRUE;
    res = TRUE;
    break;
  case GST_PAD_MODE_PULL:
    if (active) {
      demux->state = GST_ASF_DEMUX_STATE_HEADER;
      demux->streaming = FALSE;
      res = gst_pad_start_task(sinkpad, (GstTaskFunction)gst_asf_demux_loop,
                               demux, NULL);
    } else {
      res = gst_pad_stop_task(sinkpad);
    }
    break;
  default:
    res = FALSE;
    break;
  }
  return res;
}

static int should_include(struct commit *commit, void *_data) {
  struct bitmap *base = _data;
  if (!add_to_include_set(base, commit)) {
    struct commit_list *parent = commit->parents;
    mark_as_seen((struct object *)commit);
    while (parent) {
      parent->item->object.flags |= SEEN;
      mark_as_seen((struct object *)parent->item);
      parent = parent->next;
    }
    return 0;
  }
  return 1;
}

static double get_zero_motion_factor(const FIRSTPASS_STATS *frame) {
  const double sr_ratio =
      frame->coded_error / DOUBLE_DIVIDE_CHECK(frame->sr_coded_error);
  const double zero_motion_pct = frame->pcnt_inter - frame->pcnt_motion;
  return MIN(sr_ratio, zero_motion_pct);
}

