static int userauth_pubkey(struct ssh *ssh) {
  Authctxt *authctxt = ssh->authctxt;
  struct passwd *pw = authctxt->pw;
  struct sshbuf *b;
  struct sshkey *key = NULL;
  char *pkalg, *userstyle = NULL, *key_s = NULL, *ca_s = NULL;
  u_char *pkblob, *sig, have_sig;
  size_t blen, slen;
  int r, pktype;
  int authenticated = 0;
  struct sshauthopt *authopts = NULL;
  if (!authctxt->valid) {
    debug2("%s: disabled because of invalid user", __func__);
    return 0;
  }
  if ((r = sshpkt_get_u8(ssh, &have_sig)) != 0 ||
      (r = sshpkt_get_cstring(ssh, &pkalg, NULL)) != 0 ||
      (r = sshpkt_get_string(ssh, &pkblob, &blen)) != 0)
    fatal("%s: parse request failed: %s", __func__, ssh_err(r));
  pktype = sshkey_type_from_name(pkalg);
  if (pktype == KEY_UNSPEC) {
    verbose("%s: unsupported public key algorithm: %s", __func__, pkalg);
    goto done;
  }
  if ((r = sshkey_from_blob(pkblob, blen, &key)) != 0) {
    error("%s: could not parse key: %s", __func__, ssh_err(r));
    goto done;
  }
  if (key == NULL) {
    error("%s: cannot decode key: %s", __func__, pkalg);
    goto done;
  }
  if (key->type != pktype) {
    error("%s: type mismatch for decoded key "
          "(received %d, expected %d)",
          __func__, key->type, pktype);
    goto done;
  }
  if (sshkey_type_plain(key->type) == KEY_RSA &&
      (ssh->compat & SSH_BUG_RSASIGMD5) != 0) {
    logit("Refusing RSA key because client uses unsafe "
          "signature scheme");
    goto done;
  }
  if (auth2_key_already_used(authctxt, key)) {
    logit("refusing previously-used %s key", sshkey_type(key));
    goto done;
  }
  if (match_pattern_list(pkalg, options.pubkey_key_types, 0) != 1) {
    logit("%s: key type %s not in PubkeyAcceptedKeyTypes", __func__,
          sshkey_ssh_name(key));
    goto done;
  }
  key_s = format_key(key);
  if (sshkey_is_cert(key))
    ca_s = format_key(key->cert->signature_key);
  if (have_sig) {
    debug3("%s: have %s signature for %s%s%s", __func__, pkalg, key_s,
           ca_s == NULL ? "" : " CA ", ca_s == NULL ? "" : ca_s);
    if ((r = sshpkt_get_string(ssh, &sig, &slen)) != 0 ||
        (r = sshpkt_get_end(ssh)) != 0)
      fatal("%s: %s", __func__, ssh_err(r));
    if ((b = sshbuf_new()) == NULL)
      fatal("%s: sshbuf_new failed", __func__);
    if (ssh->compat & SSH_OLD_SESSIONID) {
      if ((r = sshbuf_put(b, session_id2, session_id2_len)) != 0)
        fatal("%s: sshbuf_put session id: %s", __func__, ssh_err(r));
    } else {
      if ((r = sshbuf_put_string(b, session_id2, session_id2_len)) != 0)
        fatal("%s: sshbuf_put_string session id: %s", __func__, ssh_err(r));
    }
    xasprintf(&userstyle, "%s%s%s", authctxt->user, authctxt->style ? ":" : "",
              authctxt->style ? authctxt->style : "");
    if ((r = sshbuf_put_u8(b, SSH2_MSG_USERAUTH_REQUEST)) != 0 ||
        (r = sshbuf_put_cstring(b, userstyle)) != 0 ||
        (r = sshbuf_put_cstring(b, authctxt->service)) != 0 ||
        (r = sshbuf_put_cstring(b, "publickey")) != 0 ||
        (r = sshbuf_put_u8(b, have_sig)) != 0 ||
        (r = sshbuf_put_cstring(b, pkalg) != 0) ||
        (r = sshbuf_put_string(b, pkblob, blen)) != 0)
      fatal("%s: build packet failed: %s", __func__, ssh_err(r));
#ifdef DEBUG_PK sshbuf_dump(b, stderr);
#endif authenticated = 0;
    if (PRIVSEP(user_key_allowed(ssh, pw, key, 1, &authopts)) &&
        PRIVSEP(
            sshkey_verify(key, sig, slen, sshbuf_ptr(b), sshbuf_len(b),
                          (ssh->compat & SSH_BUG_SIGTYPE) == 0 ? pkalg : NULL,
                          ssh->compat)) == 0) {
      authenticated = 1;
    }
    sshbuf_free(b);
    free(sig);
    auth2_record_key(authctxt, authenticated, key);
  } else {
    debug("%s: test pkalg %s pkblob %s%s%s", __func__, pkalg, key_s,
          ca_s == NULL ? "" : " CA ", ca_s == NULL ? "" : ca_s);
    if ((r = sshpkt_get_end(ssh)) != 0)
      fatal("%s: %s", __func__, ssh_err(r));
    if (PRIVSEP(user_key_allowed(ssh, pw, key, 0, NULL))) {
      if ((r = sshpkt_start(ssh, SSH2_MSG_USERAUTH_PK_OK)) != 0 ||
          (r = sshpkt_put_cstring(ssh, pkalg)) != 0 ||
          (r = sshpkt_put_string(ssh, pkblob, blen)) != 0 ||
          (r = sshpkt_send(ssh)) != 0 || (r = ssh_packet_write_wait(ssh)) != 0)
        fatal("%s: %s", __func__, ssh_err(r));
      authctxt->postponed = 1;
    }
  }
done:
  if (authenticated == 1 && auth_activate_options(ssh, authopts) != 0) {
    debug("%s: key options inconsistent with existing", __func__);
    authenticated = 0;
  }
  debug2("%s: authenticated %d pkalg %s", __func__, authenticated, pkalg);
  sshauthopt_free(authopts);
  sshkey_free(key);
  free(userstyle);
  free(pkalg);
  free(pkblob);
  free(key_s);
  free(ca_s);
  return authenticated;
}

void do_eval(DYNAMIC_STRING *query_eval, const char *query,
             const char *query_end, my_bool pass_through_escape_chars) {
  const char *p;
  register char c, next_c;
  register int escaped = 0;
  VAR *v;
  DBUG_ENTER("do_eval");
  for (p = query; (c = *p) && p < query_end; ++p) {
    switch (c) {
    case '$':
      if (escaped) {
        escaped = 0;
        dynstr_append_mem(query_eval, p, 1);
      } else {
        if (!(v = var_get(p, &p, 0, 0))) {
          report_or_die("Bad variable in eval");
          return;
        }
        dynstr_append_mem(query_eval, v->str_val, v->str_val_len);
      }
      break;
    case '\\':
      next_c = *(p + 1);
      if (escaped) {
        escaped = 0;
        dynstr_append_mem(query_eval, p, 1);
      } else if (next_c == '\\' || next_c == '$' || next_c == '"') {
        escaped = 1;
        if (pass_through_escape_chars) {
          dynstr_append_mem(query_eval, p, 1);
        }
      } else
        dynstr_append_mem(query_eval, p, 1);
      break;
    default:
      escaped = 0;
      dynstr_append_mem(query_eval, p, 1);
      break;
    }
  }
#ifdef __WIN__ fix_win_paths(query_eval->str, query_eval->length);
#endif DBUG_VOID_RETURN;
}

static int dissect_CPMGetApproximatePosition(tvbuff_t *tvb, packet_info *pinfo,
                                             proto_tree *parent_tree,
                                             gboolean in, void *data _U_) {
  gint offset = 16;
  proto_item *item;
  proto_tree *tree;
  item = proto_tree_add_item(parent_tree, hf_mswsp_msg, tvb, offset,
                             in ? 0 : -1, ENC_NA);
  tree = proto_item_add_subtree(item, ett_mswsp_msg);
  proto_item_set_text(item, "GetApproximatePosition%s", in ? "In" : "Out");
  col_append_str(pinfo->cinfo, COL_INFO, "GetApproximatePosition");
  if (in) {
    proto_tree_add_item(tree, hf_mswsp_msg_cpmgetapproxpos_hcursor, tvb, offset,
                        4, ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_mswsp_msg_cpmgetapproxpos_chapt, tvb, offset,
                        4, ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_mswsp_msg_cpmgetapproxpos_bmk, tvb, offset, 4,
                        ENC_LITTLE_ENDIAN);
  } else {
    proto_tree_add_item(tree, hf_mswsp_msg_cpmgetapproxpos_numerator, tvb,
                        offset, 4, ENC_LITTLE_ENDIAN);
    offset += 4;
    proto_tree_add_item(tree, hf_mswsp_msg_cpmgetapproxpos_denominator, tvb,
                        offset, 4, ENC_LITTLE_ENDIAN);
  }
  return tvb_reported_length(tvb);
}

