static int may_link(struct inode *dir, struct dentry *dentry, int kind) {
  struct inode_security_struct *dsec, *isec;
  struct common_audit_data ad;
  u32 sid = current_sid();
  u32 av;
  int rc;
  dsec = inode_security(dir);
  isec = backing_inode_security(dentry);
  ad.type = LSM_AUDIT_DATA_DENTRY;
  ad.u.dentry = dentry;
  av = DIR__SEARCH;
  av |= (kind ? DIR__REMOVE_NAME : DIR__ADD_NAME);
  rc = avc_has_perm(sid, dsec->sid, SECCLASS_DIR, av, &ad);
  if (rc)
    return rc;
  switch (kind) {
  case MAY_LINK:
    av = FILE__LINK;
    break;
  case MAY_UNLINK:
    av = FILE__UNLINK;
    break;
  case MAY_RMDIR:
    av = DIR__RMDIR;
    break;
  default:
    printk(KERN_WARNING "SELinux: %s: unrecognized kind %d\n", __func__, kind);
    return 0;
  }
  rc = avc_has_perm(sid, isec->sid, isec->sclass, av, &ad);
  return rc;
}

static int cert_status_cb(SSL *s, void *arg) {
  tlsextstatusctx *srctx = arg;
  BIO *err = srctx->err;
  char *host, *port, *path;
  int use_ssl;
  unsigned char *rspder = NULL;
  int rspderlen;
  STACK_OF(OPENSSL_STRING) *aia = NULL;
  X509 *x = NULL;
  X509_STORE_CTX inctx;
  X509_OBJECT obj;
  OCSP_REQUEST *req = NULL;
  OCSP_RESPONSE *resp = NULL;
  OCSP_CERTID *id = NULL;
  STACK_OF(X509_EXTENSION) * exts;
  int ret = SSL_TLSEXT_ERR_NOACK;
  int i;
#if 0 STACK_OF(OCSP_RESPID) * ids;
 SSL_get_tlsext_status_ids ( s , & ids ) ;
 BIO_printf ( err , "cert_status: received %d ids\n" , sk_OCSP_RESPID_num ( ids ) ) ;
#endif if (srctx->verbose) BIO_puts(err, "cert_status: callback called\n");
  x = SSL_get_certificate(s);
  aia = X509_get1_ocsp(x);
  if (aia) {
    if (!OCSP_parse_url(sk_OPENSSL_STRING_value(aia, 0), &host, &port, &path,
                        &use_ssl)) {
      BIO_puts(err, "cert_status: can't parse AIA URL\n");
      goto err;
    }
    if (srctx->verbose)
      BIO_printf(err, "cert_status: AIA URL: %s\n",
                 sk_OPENSSL_STRING_value(aia, 0));
  } else {
    if (!srctx->host) {
      BIO_puts(srctx->err,
               "cert_status: no AIA and no default responder URL\n");
      goto done;
    }
    host = srctx->host;
    path = srctx->path;
    port = srctx->port;
    use_ssl = srctx->use_ssl;
  }
  if (!X509_STORE_CTX_init(&inctx, SSL_CTX_get_cert_store(SSL_get_SSL_CTX(s)),
                           NULL, NULL))
    goto err;
  if (X509_STORE_get_by_subject(&inctx, X509_LU_X509, X509_get_issuer_name(x),
                                &obj) <= 0) {
    BIO_puts(err, "cert_status: Can't retrieve issuer certificate.\n");
    X509_STORE_CTX_cleanup(&inctx);
    goto done;
  }
  req = OCSP_REQUEST_new();
  if (!req)
    goto err;
  id = OCSP_cert_to_id(NULL, x, obj.data.x509);
  X509_free(obj.data.x509);
  X509_STORE_CTX_cleanup(&inctx);
  if (!id)
    goto err;
  if (!OCSP_request_add0_id(req, id))
    goto err;
  id = NULL;
  SSL_get_tlsext_status_exts(s, &exts);
  for (i = 0; i < sk_X509_EXTENSION_num(exts); i++) {
    X509_EXTENSION *ext = sk_X509_EXTENSION_value(exts, i);
    if (!OCSP_REQUEST_add_ext(req, ext, -1))
      goto err;
  }
  resp = process_responder(err, req, host, path, port, use_ssl, NULL,
                           srctx->timeout);
  if (!resp) {
    BIO_puts(err, "cert_status: error querying responder\n");
    goto done;
  }
  rspderlen = i2d_OCSP_RESPONSE(resp, &rspder);
  if (rspderlen <= 0)
    goto err;
  SSL_set_tlsext_status_ocsp_resp(s, rspder, rspderlen);
  if (srctx->verbose) {
    BIO_puts(err, "cert_status: ocsp response sent:\n");
    OCSP_RESPONSE_print(err, resp, 2);
  }
  ret = SSL_TLSEXT_ERR_OK;
done:
  if (ret != SSL_TLSEXT_ERR_OK)
    ERR_print_errors(err);
  if (aia) {
    OPENSSL_free(host);
    OPENSSL_free(path);
    OPENSSL_free(port);
    X509_email_free(aia);
  }
  if (id)
    OCSP_CERTID_free(id);
  if (req)
    OCSP_REQUEST_free(req);
  if (resp)
    OCSP_RESPONSE_free(resp);
  return ret;
err:
  ret = SSL_TLSEXT_ERR_ALERT_FATAL;
  goto done;
}
