static int32_t u_printf_string_handler(const u_printf_stream_handler *handler,
                                       void *context,
                                       ULocaleBundle *formatBundle,
                                       const u_printf_spec_info *info,
                                       const ufmt_args *args) {
  (void)formatBundle;
  UChar *s;
  UChar buffer[UFMT_DEFAULT_BUFFER_SIZE];
  int32_t len, written;
  int32_t argSize;
  const char *arg = (const char *)(args[0].ptrValue);
  if (arg) {
    argSize = (int32_t)strlen(arg) + 1;
    if (argSize >= MAX_UCHAR_BUFFER_SIZE(buffer)) {
      s = ufmt_defaultCPToUnicode(
          arg, argSize, (UChar *)uprv_malloc(MAX_UCHAR_BUFFER_NEEDED(argSize)),
          MAX_UCHAR_BUFFER_NEEDED(argSize));
      if (s == NULL) {
        return 0;
      }
    } else {
      s = ufmt_defaultCPToUnicode(arg, argSize, buffer, UPRV_LENGTHOF(buffer));
    }
  } else {
    s = (UChar *)gNullStr;
  }
  len = u_strlen(s);
  if (info->fPrecision != -1 && info->fPrecision < len) {
    len = info->fPrecision;
  }
  written = handler->pad_and_justify(context, info, s, len);
  if (gNullStr != s && buffer != s) {
    uprv_free(s);
  }
  return written;
}

static int cinaudio_decode_frame(AVCodecContext *avctx, void *data,
                                 int *got_frame_ptr, AVPacket *avpkt) {
  AVFrame *frame = data;
  const uint8_t *buf = avpkt->data;
  CinAudioContext *cin = avctx->priv_data;
  const uint8_t *buf_end = buf + avpkt->size;
  int16_t *samples;
  int delta, ret;
  frame->nb_samples = avpkt->size - cin->initial_decode_frame;
  if ((ret = ff_get_buffer(avctx, frame, 0)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  samples = (int16_t *)frame->data[0];
  delta = cin->delta;
  if (cin->initial_decode_frame) {
    cin->initial_decode_frame = 0;
    delta = sign_extend(AV_RL16(buf), 16);
    buf += 2;
    *samples++ = delta;
  }
  while (buf < buf_end) {
    delta += cinaudio_delta16_table[*buf++];
    delta = av_clip_int16(delta);
    *samples++ = delta;
  }
  cin->delta = delta;
  *got_frame_ptr = 1;
  return avpkt->size;
}

static int getarg(const char *str, int code, arg_v *argp) {
  u_long ul;
  switch (code & ~OPT) {
  case NTP_STR:
    argp->string = str;
    break;
  case NTP_ADD:
    if (!getnetnum(str, &argp->netnum, NULL, 0))
      return 0;
    break;
  case NTP_UINT:
    if ('&' == str[0]) {
      if (!atouint(&str[1], &ul)) {
        fprintf(stderr, "***Association index `%s' invalid/undecodable\n", str);
        return 0;
      }
      if (0 == numassoc) {
        dogetassoc(stdout);
        if (0 == numassoc) {
          fprintf(stderr, "***No associations found, `%s' unknown\n", str);
          return 0;
        }
      }
      ul = min(ul, numassoc);
      argp->uval = assoc_cache[ul - 1].assid;
      break;
    }
    if (!atouint(str, &argp->uval)) {
      fprintf(stderr, "***Illegal unsigned value %s\n", str);
      return 0;
    }
    break;
  case NTP_INT:
    if (!atoint(str, &argp->ival)) {
      fprintf(stderr, "***Illegal integer value %s\n", str);
      return 0;
    }
    break;
  case IP_VERSION:
    if (!strcmp("-6", str)) {
      argp->ival = 6;
    } else if (!strcmp("-4", str)) {
      argp->ival = 4;
    } else {
      fprintf(stderr, "***Version must be either 4 or 6\n");
      return 0;
    }
    break;
  }
  return 1;
}

