void vp9_pick_filter_level(const YV12_BUFFER_CONFIG *sd, VP9_COMP *cpi,
                           LPF_PICK_METHOD method) {
  VP9_COMMON *const cm = &cpi->common;
  struct loopfilter *const lf = &cm->lf;
  lf->sharpness_level = cm->frame_type == KEY_FRAME ? 0 : cpi->oxcf.sharpness;
  if (method == LPF_PICK_MINIMAL_LPF && lf->filter_level) {
    lf->filter_level = 0;
  } else if (method >= LPF_PICK_FROM_Q) {
    const int min_filter_level = 0;
    const int max_filter_level = get_max_filter_level(cpi);
    const int q = vp9_ac_quant(cm->base_qindex, 0);
    int filt_guess = ROUND_POWER_OF_TWO(q * 20723 + 1015158, 18);
    if (cm->frame_type == KEY_FRAME)
      filt_guess -= 4;
    lf->filter_level = clamp(filt_guess, min_filter_level, max_filter_level);
  } else {
    lf->filter_level =
        search_filter_level(sd, cpi, method == LPF_PICK_FROM_SUBIMAGE);
  }
}

static void dequant_lsp10r(GetBitContext *gb, double *i_lsps, const double *old,
                           double *a1, double *a2, int q_mode) {
  static const uint16_t vec_sizes[3] = {128, 64, 64};
  static const double mul_lsf[3] = {2.5807601174e-3, 1.2354460219e-3,
                                    1.1763821673e-3};
  static const double base_lsf[3] = {M_PI * -1.07448e-1, M_PI * -5.2706e-2,
                                     M_PI * -5.1634e-2};
  const float(*ipol_tab)[2][10] =
      q_mode ? wmavoice_lsp10_intercoeff_b : wmavoice_lsp10_intercoeff_a;
  uint16_t interpol, v[3];
  int n;
  dequant_lsp10i(gb, i_lsps);
  interpol = get_bits(gb, 5);
  v[0] = get_bits(gb, 7);
  v[1] = get_bits(gb, 6);
  v[2] = get_bits(gb, 6);
  for (n = 0; n < 10; n++) {
    double delta = old[n] - i_lsps[n];
    a1[n] = ipol_tab[interpol][0][n] * delta + i_lsps[n];
    a1[10 + n] = ipol_tab[interpol][1][n] * delta + i_lsps[n];
  }
  dequant_lsps(a2, 20, v, vec_sizes, 3, wmavoice_dq_lsp10r, mul_lsf, base_lsf);
}

static int mime_header_encoder_block_collector(int c, void *data) {
  int n;
  struct mime_header_encoder_data *pe = (struct mime_header_encoder_data *)data;
  switch (pe->status2) {
  case 1:
    pe->prevpos = pe->outdev.pos;
    mbfl_convert_filter_copy(pe->conv2_filter, pe->conv2_filter_backup);
    mbfl_convert_filter_copy(pe->encod_filter, pe->encod_filter_backup);
    (*pe->conv2_filter->filter_function)(c, pe->conv2_filter);
    (*pe->conv2_filter->filter_flush)(pe->conv2_filter);
    (*pe->encod_filter->filter_flush)(pe->encod_filter);
    n = pe->outdev.pos - pe->linehead + pe->firstindent;
    pe->outdev.pos = pe->prevpos;
    mbfl_convert_filter_copy(pe->conv2_filter_backup, pe->conv2_filter);
    mbfl_convert_filter_copy(pe->encod_filter_backup, pe->encod_filter);
    if (n >= 74) {
      (*pe->conv2_filter->filter_flush)(pe->conv2_filter);
      (*pe->encod_filter->filter_flush)(pe->encod_filter);
      mbfl_memory_device_strncat(&pe->outdev, "\x3f\x3d", 2);
      mbfl_memory_device_strncat(&pe->outdev, pe->lwsp, pe->lwsplen);
      pe->linehead = pe->outdev.pos;
      pe->firstindent = 0;
      mbfl_memory_device_strncat(&pe->outdev, pe->encname, pe->encnamelen);
      c = (*pe->conv2_filter->filter_function)(c, pe->conv2_filter);
    } else {
      c = (*pe->conv2_filter->filter_function)(c, pe->conv2_filter);
    }
    break;
  default:
    mbfl_memory_device_strncat(&pe->outdev, pe->encname, pe->encnamelen);
    c = (*pe->conv2_filter->filter_function)(c, pe->conv2_filter);
    pe->status2 = 1;
    break;
  }
  return c;
}

static void synth_block_hardcoded(WMAVoiceContext *s, GetBitContext *gb,
                                  int block_idx, int size,
                                  const struct frame_type_desc *frame_desc,
                                  float *excitation) {
  float gain;
  int n, r_idx;
  assert(size <= MAX_FRAMESIZE);
  if (frame_desc->fcb_type == FCB_TYPE_SILENCE) {
    r_idx = pRNG(s->frame_cntr, block_idx, size);
    gain = s->silence_gain;
  } else {
    r_idx = get_bits(gb, 8);
    gain = wmavoice_gain_universal[get_bits(gb, 6)];
  }
  memset(s->gain_pred_err, 0, sizeof(s->gain_pred_err));
  for (n = 0; n < size; n++)
    excitation[n] = wmavoice_std_codebook[r_idx + n] * gain;
}

