    goto cleanup;
  } else if (STRPREFIX(reply, "Device '") && (strstr(reply, "not found"))) {
  } else if (STRNEQ(reply, "")) {
    qemuReportError(VIR_ERR_OPERATION_FAILED, _("deleting %s drive failed: %s"),
                    drivestr, reply);
    goto cleanup;
  }
  ret = 0;
cleanup:
  VIR_FREE(cmd);
  VIR_FREE(reply);
  VIR_FREE(safedev);
