static VALUE ossl_asn1_decode0(unsigned char **pp, long length, long *offset,
                               int depth, int yield, long *num_read) {
  unsigned char *start, *p;
  const unsigned char *p0;
  long len = 0, inner_read = 0, off = *offset, hlen;
  int tag, tc, j;
  VALUE asn1data, tag_class;
  p = *pp;
  start = p;
  p0 = p;
  j = ASN1_get_object(&p0, &len, &tag, &tc, length);
  p = (unsigned char *)p0;
  if (j & 0x80)
    ossl_raise(eASN1Error, NULL);
  if (len > length)
    ossl_raise(eASN1Error, "value is too short");
  if ((tc & V_ASN1_PRIVATE) == V_ASN1_PRIVATE)
    tag_class = sym_PRIVATE;
  else if ((tc & V_ASN1_CONTEXT_SPECIFIC) == V_ASN1_CONTEXT_SPECIFIC)
    tag_class = sym_CONTEXT_SPECIFIC;
  else if ((tc & V_ASN1_APPLICATION) == V_ASN1_APPLICATION)
    tag_class = sym_APPLICATION;
  else
    tag_class = sym_UNIVERSAL;
  hlen = p - start;
  if (yield) {
    VALUE arg = rb_ary_new();
    rb_ary_push(arg, LONG2NUM(depth));
    rb_ary_push(arg, LONG2NUM(*offset));
    rb_ary_push(arg, LONG2NUM(hlen));
    rb_ary_push(arg, LONG2NUM(len));
    rb_ary_push(arg, (j & V_ASN1_CONSTRUCTED) ? Qtrue : Qfalse);
    rb_ary_push(arg, ossl_asn1_class2sym(tc));
    rb_ary_push(arg, INT2NUM(tag));
    rb_yield(arg);
  }
  if (j & V_ASN1_CONSTRUCTED) {
    *pp += hlen;
    off += hlen;
    asn1data =
        int_ossl_asn1_decode0_cons(pp, length - hlen, len, &off, depth, yield,
                                   j, tag, tag_class, &inner_read);
    inner_read += hlen;
  } else {
    if ((j & 0x01) && (len == 0))
      ossl_raise(eASN1Error, "Infinite length for primitive value");
    asn1data =
        int_ossl_asn1_decode0_prim(pp, len, hlen, tag, tag_class, &inner_read);
    off += hlen + len;
  }
  if (num_read)
    *num_read = inner_read;
  if (len != 0 && inner_read != hlen + len) {
    ossl_raise(eASN1Error,
               "Type mismatch. Bytes read: %ld Bytes available: %ld",
               inner_read, hlen + len);
  }
  *offset = off;
  return asn1data;
}

static void gather_data_for_cel(CelEvaluation *cel, RoqContext *enc,
                                RoqTempdata *tempData) {
  uint8_t mb8[8 * 8 * 3];
  int index = cel->sourceY * enc->width / 64 + cel->sourceX / 8;
  int i, j, best_dist, divide_bit_use;
  int bitsUsed[4] = {2, 10, 10, 0};
  if (enc->framesSinceKeyframe >= 1) {
    cel->motion = enc->this_motion8[index];
    cel->eval_dist[RoQ_ID_FCC] = eval_motion_dist(
        enc, cel->sourceX, cel->sourceY, enc->this_motion8[index], 8);
  } else
    cel->eval_dist[RoQ_ID_FCC] = INT_MAX;
  if (enc->framesSinceKeyframe >= 2)
    cel->eval_dist[RoQ_ID_MOT] =
        block_sse(enc->frame_to_enc->data, enc->current_frame->data,
                  cel->sourceX, cel->sourceY, cel->sourceX, cel->sourceY,
                  enc->frame_to_enc->linesize, enc->current_frame->linesize, 8);
  else
    cel->eval_dist[RoQ_ID_MOT] = INT_MAX;
  get_frame_mb(enc->frame_to_enc, cel->sourceX, cel->sourceY, mb8, 8);
  cel->eval_dist[RoQ_ID_SLD] =
      index_mb(mb8, tempData->codebooks.unpacked_cb4_enlarged,
               tempData->codebooks.numCB4, &cel->cbEntry, 8);
  gather_data_for_subcel(cel->subCels + 0, cel->sourceX + 0, cel->sourceY + 0,
                         enc, tempData);
  gather_data_for_subcel(cel->subCels + 1, cel->sourceX + 4, cel->sourceY + 0,
                         enc, tempData);
  gather_data_for_subcel(cel->subCels + 2, cel->sourceX + 0, cel->sourceY + 4,
                         enc, tempData);
  gather_data_for_subcel(cel->subCels + 3, cel->sourceX + 4, cel->sourceY + 4,
                         enc, tempData);
  cel->eval_dist[RoQ_ID_CCC] = 0;
  divide_bit_use = 0;
  for (i = 0; i < 4; i++) {
    cel->eval_dist[RoQ_ID_CCC] +=
        cel->subCels[i].eval_dist[cel->subCels[i].best_coding];
    divide_bit_use += cel->subCels[i].best_bit_use;
  }
  best_dist = INT_MAX;
  bitsUsed[3] = 2 + divide_bit_use;
  for (i = 0; i < 4; i++)
    if (ROQ_LAMBDA_SCALE * cel->eval_dist[i] + enc->lambda * bitsUsed[i] <
        best_dist) {
      cel->best_coding = i;
      best_dist =
          ROQ_LAMBDA_SCALE * cel->eval_dist[i] + enc->lambda * bitsUsed[i];
    }
  tempData->used_option[cel->best_coding]++;
  tempData->mainChunkSize += bitsUsed[cel->best_coding];
  if (cel->best_coding == RoQ_ID_SLD)
    tempData->codebooks.usedCB4[cel->cbEntry]++;
  if (cel->best_coding == RoQ_ID_CCC)
    for (i = 0; i < 4; i++) {
      if (cel->subCels[i].best_coding == RoQ_ID_SLD)
        tempData->codebooks.usedCB4[cel->subCels[i].cbEntry]++;
      else if (cel->subCels[i].best_coding == RoQ_ID_CCC)
        for (j = 0; j < 4; j++)
          tempData->codebooks.usedCB2[cel->subCels[i].subCels[j]]++;
    }
}

