static int sort_key_write(MI_SORT_PARAM *sort_param, const void *a) {
  uint diff_pos[2];
  char llbuff[22], llbuff2[22];
  SORT_INFO *sort_info = sort_param->sort_info;
  MI_CHECK *param = sort_info->param;
  int cmp;
  if (sort_info->key_block->inited) {
    cmp = ha_key_cmp(sort_param->seg, sort_info->key_block->lastkey, (uchar *)a,
                     USE_WHOLE_KEY, SEARCH_FIND | SEARCH_UPDATE, diff_pos);
    if (param->stats_method == MI_STATS_METHOD_NULLS_NOT_EQUAL)
      ha_key_cmp(sort_param->seg, sort_info->key_block->lastkey, (uchar *)a,
                 USE_WHOLE_KEY, SEARCH_FIND | SEARCH_NULL_ARE_NOT_EQUAL,
                 diff_pos);
    else if (param->stats_method == MI_STATS_METHOD_IGNORE_NULLS) {
      diff_pos[0] = mi_collect_stats_nonulls_next(
          sort_param->seg, sort_param->notnull, sort_info->key_block->lastkey,
          (uchar *)a);
    }
    sort_param->unique[diff_pos[0] - 1]++;
  } else {
    cmp = -1;
    if (param->stats_method == MI_STATS_METHOD_IGNORE_NULLS)
      mi_collect_stats_nonulls_first(sort_param->seg, sort_param->notnull,
                                     (uchar *)a);
  }
  if ((sort_param->keyinfo->flag & HA_NOSAME) && cmp == 0) {
    sort_info->dupp++;
    sort_info->info->lastpos =
        get_record_for_key(sort_info->info, sort_param->keyinfo, (uchar *)a);
    mi_check_print_warning(
        param, "Duplicate key for record at %10s against record at %10s",
        llstr(sort_info->info->lastpos, llbuff),
        llstr(get_record_for_key(sort_info->info, sort_param->keyinfo,
                                 sort_info->key_block->lastkey),
              llbuff2));
    param->testflag |= T_RETRY_WITHOUT_QUICK;
    if (sort_info->param->testflag & T_VERBOSE)
      _mi_print_key(stdout, sort_param->seg, (uchar *)a, USE_WHOLE_KEY);
    return (sort_delete_record(sort_param));
  }
#ifndef DBUG_OFF if (cmp > 0) {
  mi_check_print_error(param,
                       "Internal error: Keys are not in order from sort");
  return (1);
}
#endif return (sort_insert_key(sort_param, sort_info->key_block, (uchar *)a,   \
                               HA_OFFSET_ERROR));
}

static gcry_err_code_t pss_encode(gcry_mpi_t *r_result, unsigned int nbits,
                                  int algo, const unsigned char *value,
                                  size_t valuelen, int saltlen,
                                  const void *random_override,
                                  size_t random_override_len) {
  gcry_err_code_t rc = 0;
  gcry_error_t err;
  size_t hlen;
  unsigned char *em = NULL;
  size_t emlen = (nbits + 7) / 8;
  unsigned char *h;
  unsigned char *buf = NULL;
  size_t buflen;
  unsigned char *mhash;
  unsigned char *salt;
  unsigned char *dbmask;
  unsigned char *p;
  size_t n;
  hlen = gcry_md_get_algo_dlen(algo);
  gcry_assert(hlen);
  buflen = 8 + hlen + saltlen + (emlen - hlen - 1);
  buf = gcry_malloc(buflen);
  if (!buf) {
    rc = gpg_err_code_from_syserror();
    goto leave;
  }
  mhash = buf + 8;
  salt = mhash + hlen;
  dbmask = salt + saltlen;
  if (valuelen != hlen) {
    rc = GPG_ERR_INV_LENGTH;
    goto leave;
  }
  memcpy(mhash, value, hlen);
  if (emlen < hlen + saltlen + 2) {
    rc = GPG_ERR_TOO_SHORT;
    goto leave;
  }
  em = gcry_malloc(emlen);
  if (!em) {
    rc = gpg_err_code_from_syserror();
    goto leave;
  }
  h = em + emlen - 1 - hlen;
  if (saltlen) {
    if (random_override) {
      if (random_override_len != saltlen) {
        rc = GPG_ERR_INV_ARG;
        goto leave;
      }
      memcpy(salt, random_override, saltlen);
    } else
      gcry_randomize(salt, saltlen, GCRY_STRONG_RANDOM);
  }
  memset(buf, 0, 8);
  gcry_md_hash_buffer(algo, h, buf, 8 + hlen + saltlen);
  p = em + emlen - 1 - hlen - saltlen - 1;
  memset(em, 0, p - em);
  *p++ = 0x01;
  memcpy(p, salt, saltlen);
  mgf1(dbmask, emlen - hlen - 1, h, hlen, algo);
  for (n = 0, p = dbmask; n < emlen - hlen - 1; n++, p++)
    em[n] ^= *p;
  em[0] &= 0xFF >> (8 * emlen - nbits);
  em[emlen - 1] = 0xbc;
  err = gcry_mpi_scan(r_result, GCRYMPI_FMT_USG, em, emlen, NULL);
  if (err)
    rc = gcry_err_code(err);
  else if (DBG_CIPHER)
    log_mpidump("PSS encoded data", *r_result);
leave:
  if (em) {
    wipememory(em, emlen);
    gcry_free(em);
  }
  if (buf) {
    wipememory(buf, buflen);
    gcry_free(buf);
  }
  return rc;
}

static USBPort *xhci_lookup_uport(XHCIState *xhci, uint32_t *slot_ctx) {
  USBPort *uport;
  char path[32];
  int i, pos, port;
  port = (slot_ctx[1] >> 16) & 0xFF;
  if (port < 1 || port > xhci->numports) {
    return NULL;
  }
  port = xhci->ports[port - 1].uport->index + 1;
  pos = snprintf(path, sizeof(path), "%d", port);
  for (i = 0; i < 5; i++) {
    port = (slot_ctx[0] >> 4 * i) & 0x0f;
    if (!port) {
      break;
    }
    pos += snprintf(path + pos, sizeof(path) - pos, ".%d", port);
  }
  QTAILQ_FOREACH(uport, &xhci->bus.used, next) {
    if (strcmp(uport->path, path) == 0) {
      return uport;
    }
  }
  return NULL;
}

