int dtls1_get_record(SSL *s) {
  int ssl_major, ssl_minor;
  int i, n;
  SSL3_RECORD *rr;
  unsigned char *p = NULL;
  unsigned short version;
  DTLS1_BITMAP *bitmap;
  unsigned int is_next_epoch;
  rr = RECORD_LAYER_get_rrec(&s->rlayer);
again:
  if (!dtls1_process_buffered_records(s))
    return -1;
  if (dtls1_get_processed_record(s))
    return 1;
  if ((RECORD_LAYER_get_rstate(&s->rlayer) != SSL_ST_READ_BODY) ||
      (RECORD_LAYER_get_packet_length(&s->rlayer) < DTLS1_RT_HEADER_LENGTH)) {
    n = ssl3_read_n(s, DTLS1_RT_HEADER_LENGTH,
                    SSL3_BUFFER_get_len(&s->rlayer.rbuf), 0, 1);
    if (n <= 0)
      return (n);
    if (RECORD_LAYER_get_packet_length(&s->rlayer) != DTLS1_RT_HEADER_LENGTH) {
      RECORD_LAYER_reset_packet_length(&s->rlayer);
      goto again;
    }
    RECORD_LAYER_set_rstate(&s->rlayer, SSL_ST_READ_BODY);
    p = RECORD_LAYER_get_packet(&s->rlayer);
    if (s->msg_callback)
      s->msg_callback(0, 0, SSL3_RT_HEADER, p, DTLS1_RT_HEADER_LENGTH, s,
                      s->msg_callback_arg);
    rr->type = *(p++);
    ssl_major = *(p++);
    ssl_minor = *(p++);
    version = (ssl_major << 8) | ssl_minor;
    n2s(p, rr->epoch);
    memcpy(&(RECORD_LAYER_get_read_sequence(&s->rlayer)[2]), p, 6);
    p += 6;
    n2s(p, rr->length);
    if (!s->first_packet) {
      if (version != s->version) {
        rr->length = 0;
        RECORD_LAYER_reset_packet_length(&s->rlayer);
        goto again;
      }
    }
    if ((version & 0xff00) != (s->version & 0xff00)) {
      rr->length = 0;
      RECORD_LAYER_reset_packet_length(&s->rlayer);
      goto again;
    }
    if (rr->length > SSL3_RT_MAX_ENCRYPTED_LENGTH) {
      rr->length = 0;
      RECORD_LAYER_reset_packet_length(&s->rlayer);
      goto again;
    }
  }
  if (rr->length >
      RECORD_LAYER_get_packet_length(&s->rlayer) - DTLS1_RT_HEADER_LENGTH) {
    i = rr->length;
    n = ssl3_read_n(s, i, i, 1, 1);
    if (n != i) {
      rr->length = 0;
      RECORD_LAYER_reset_packet_length(&s->rlayer);
      goto again;
    }
  }
  RECORD_LAYER_set_rstate(&s->rlayer, SSL_ST_READ_HEADER);
  bitmap = dtls1_get_bitmap(s, rr, &is_next_epoch);
  if (bitmap == NULL) {
    rr->length = 0;
    RECORD_LAYER_reset_packet_length(&s->rlayer);
    goto again;
  }
#ifndef OPENSSL_NO_SCTP if (!BIO_dgram_is_sctp(SSL_get_rbio(s))) {
#endif if (!dtls1_record_replay_check(s, bitmap)) {
  rr->length = 0;
  RECORD_LAYER_reset_packet_length(&s->rlayer);
  goto again;
}
#ifndef OPENSSL_NO_SCTP }
#endif if (rr->length == 0) goto again;
if (is_next_epoch) {
  if ((SSL_in_init(s) || ossl_statem_get_in_handshake(s))) {
    if (dtls1_buffer_record(
            s, &(DTLS_RECORD_LAYER_get_unprocessed_rcds(&s->rlayer)),
            rr->seq_num) < 0)
      return -1;
  }
  rr->length = 0;
  RECORD_LAYER_reset_packet_length(&s->rlayer);
  goto again;
}
if (!dtls1_process_record(s, bitmap)) {
  rr->length = 0;
  RECORD_LAYER_reset_packet_length(&s->rlayer);
  goto again;
}
return (1);
}

int s390_virtio_hypercall(CPUState *env) {
  int r = 0, i;
  target_ulong mem = env->regs[2];
  dprintf("KVM hypercall: %ld\n", env->regs[1]);
  switch (env->regs[1]) {
  case KVM_S390_VIRTIO_NOTIFY:
    if (mem > ram_size) {
      VirtIOS390Device *dev = s390_virtio_bus_find_vring(s390_bus, mem, &i);
      if (dev) {
        virtio_queue_notify(dev->vdev, i);
      } else {
        r = -EINVAL;
      }
    } else {
    }
    break;
  case KVM_S390_VIRTIO_RESET: {
    break;
  }
  case KVM_S390_VIRTIO_SET_STATUS: {
    VirtIOS390Device *dev;
    dev = s390_virtio_bus_find_mem(s390_bus, mem);
    if (dev) {
      s390_virtio_device_update_status(dev);
    } else {
      r = -EINVAL;
    }
    break;
  }
  default:
    r = -EINVAL;
    break;
  }
  env->regs[2] = r;
  return 0;
}

int vp9_find_best_sub_pixel_tree_pruned(
    const MACROBLOCK *x, MV *bestmv, const MV *ref_mv, int allow_hp,
    int error_per_bit, const vp9_variance_fn_ptr_t *vfp, int forced_stop,
    int iters_per_step, int *sad_list, int *mvjcost, int *mvcost[2],
    int *distortion, unsigned int *sse1, const uint8_t *second_pred, int w,
    int h) {
  SETUP_SUBPEL_SEARCH;
  if (sad_list && sad_list[0] != INT_MAX && sad_list[1] != INT_MAX &&
      sad_list[2] != INT_MAX && sad_list[3] != INT_MAX &&
      sad_list[4] != INT_MAX) {
    unsigned int left, right, up, down, diag;
    whichdir = (sad_list[1] < sad_list[3] ? 0 : 1) +
               (sad_list[2] < sad_list[4] ? 0 : 2);
    switch (whichdir) {
    case 0:
      CHECK_BETTER(left, tr, tc - hstep);
      CHECK_BETTER(up, tr - hstep, tc);
      CHECK_BETTER(diag, tr - hstep, tc - hstep);
      break;
    case 1:
      CHECK_BETTER(right, tr, tc + hstep);
      CHECK_BETTER(up, tr - hstep, tc);
      CHECK_BETTER(diag, tr - hstep, tc + hstep);
      break;
    case 2:
      CHECK_BETTER(left, tr, tc - hstep);
      CHECK_BETTER(down, tr + hstep, tc);
      CHECK_BETTER(diag, tr + hstep, tc - hstep);
      break;
    case 3:
      CHECK_BETTER(right, tr, tc + hstep);
      CHECK_BETTER(down, tr + hstep, tc);
      CHECK_BETTER(diag, tr + hstep, tc + hstep);
      break;
    }
  } else {
    FIRST_LEVEL_CHECKS;
    if (halfiters > 1) {
      SECOND_LEVEL_CHECKS;
    }
  }
  tr = br;
  tc = bc;
  if (forced_stop != 2) {
    hstep >>= 1;
    FIRST_LEVEL_CHECKS;
    if (quarteriters > 1) {
      SECOND_LEVEL_CHECKS;
    }
    tr = br;
    tc = bc;
  }
  if (allow_hp && vp9_use_mv_hp(ref_mv) && forced_stop == 0) {
    hstep >>= 1;
    FIRST_LEVEL_CHECKS;
    if (eighthiters > 1) {
      SECOND_LEVEL_CHECKS;
    }
    tr = br;
    tc = bc;
  }
  (void)tr;
  (void)tc;
  bestmv->row = br;
  bestmv->col = bc;
  if ((abs(bestmv->col - ref_mv->col) > (MAX_FULL_PEL_VAL << 3)) ||
      (abs(bestmv->row - ref_mv->row) > (MAX_FULL_PEL_VAL << 3)))
    return INT_MAX;
  return besterr;
}

