static GList *get_trash_dirs_for_mount(GMount *mount) {
  GFile *root;
  GFile *trash;
  char *relpath;
  GList *list;
  root = g_mount_get_root(mount);
  if (root == NULL) {
    return NULL;
  }
  list = NULL;
  if (g_file_is_native(root)) {
    relpath = g_strdup_printf(".Trash/%d", getuid());
    trash = g_file_resolve_relative_path(root, relpath);
    g_free(relpath);
    list = g_list_prepend(list, g_file_get_child(trash, "files"));
    list = g_list_prepend(list, g_file_get_child(trash, "info"));
    g_object_unref(trash);
    relpath = g_strdup_printf(".Trash-%d", getuid());
    trash = g_file_get_child(root, relpath);
    g_free(relpath);
    list = g_list_prepend(list, g_file_get_child(trash, "files"));
    list = g_list_prepend(list, g_file_get_child(trash, "info"));
    g_object_unref(trash);
  }
  g_object_unref(root);
  return list;
}

static void decode_5p_track(int *out, int code, int m, int off) {
  int half_3p = BIT_POS(code, 5 * m - 1) << (m - 1);
  decode_3p_track(out, BIT_STR(code, 2 * m + 1, 3 * m - 2), m - 1,
                  off + half_3p);
  decode_2p_track(out + 3, BIT_STR(code, 0, 2 * m + 1), m, off);
}

