static HA_KEYSEG *ha_find_null(HA_KEYSEG *keyseg, uchar *a) {
  for (; (enum ha_base_keytype)keyseg->type != HA_KEYTYPE_END; keyseg++) {
    uchar *end;
    if (keyseg->null_bit) {
      if (!*a++)
        return keyseg;
    }
    end = a + keyseg->length;
    switch ((enum ha_base_keytype)keyseg->type) {
    case HA_KEYTYPE_TEXT:
    case HA_KEYTYPE_BINARY:
    case HA_KEYTYPE_BIT:
      if (keyseg->flag & HA_SPACE_PACK) {
        int a_length;
        get_key_length(a_length, a);
        a += a_length;
        break;
      } else
        a = end;
      break;
    case HA_KEYTYPE_VARTEXT1:
    case HA_KEYTYPE_VARTEXT2:
    case HA_KEYTYPE_VARBINARY1:
    case HA_KEYTYPE_VARBINARY2: {
      int a_length;
      get_key_length(a_length, a);
      a += a_length;
      break;
    }
    case HA_KEYTYPE_NUM:
      if (keyseg->flag & HA_SPACE_PACK) {
        int alength = *a++;
        end = a + alength;
      }
      a = end;
      break;
    case HA_KEYTYPE_INT8:
    case HA_KEYTYPE_SHORT_INT:
    case HA_KEYTYPE_USHORT_INT:
    case HA_KEYTYPE_LONG_INT:
    case HA_KEYTYPE_ULONG_INT:
    case HA_KEYTYPE_INT24:
    case HA_KEYTYPE_UINT24:
#ifdef HAVE_LONG_LONG case HA_KEYTYPE_LONGLONG : case HA_KEYTYPE_ULONGLONG : #endif case HA_KEYTYPE_FLOAT : case HA_KEYTYPE_DOUBLE : a =
          end;
      break;
    case HA_KEYTYPE_END:
      DBUG_ASSERT(0);
      break;
    }
  }
  return keyseg;
}

time_t mime_parse_date(const char *buf, const char *end) {
  static const int DAYS_OFFSET = 25508;
  static const int days[12] = {305, 336, -1,  30,  60,  91,
                               121, 152, 183, 213, 244, 274};
  struct tm tp;
  time_t t;
  int year;
  int month;
  int mday;
  if (!buf) {
    return (time_t)0;
  }
  while ((buf != end) && is_ws(*buf)) {
    buf += 1;
  }
  if ((buf != end) && is_digit(*buf)) {
    if (!mime_parse_mday(buf, end, &tp.tm_mday)) {
      return (time_t)0;
    }
    if (!mime_parse_month(buf, end, &tp.tm_mon)) {
      return (time_t)0;
    }
    if (!mime_parse_year(buf, end, &tp.tm_year)) {
      return (time_t)0;
    }
    if (!mime_parse_time(buf, end, &tp.tm_hour, &tp.tm_min, &tp.tm_sec)) {
      return (time_t)0;
    }
  } else if (end && (end - buf >= 29) && (buf[3] == ',')) {
    if (!mime_parse_rfc822_date_fastcase(buf, end - buf, &tp)) {
      return (time_t)0;
    }
  } else {
    if (!mime_parse_day(buf, end, &tp.tm_wday)) {
      return (time_t)0;
    }
    while ((buf != end) && is_ws(*buf)) {
      buf += 1;
    }
    if ((buf != end) && ((*buf == ',') || is_digit(*buf))) {
      if (!mime_parse_mday(buf, end, &tp.tm_mday)) {
        return (time_t)0;
      }
      if (!mime_parse_month(buf, end, &tp.tm_mon)) {
        return (time_t)0;
      }
      if (!mime_parse_year(buf, end, &tp.tm_year)) {
        return (time_t)0;
      }
      if (!mime_parse_time(buf, end, &tp.tm_hour, &tp.tm_min, &tp.tm_sec)) {
        return (time_t)0;
      }
    } else {
      if (!mime_parse_month(buf, end, &tp.tm_mon)) {
        return (time_t)0;
      }
      if (!mime_parse_mday(buf, end, &tp.tm_mday)) {
        return (time_t)0;
      }
      if (!mime_parse_time(buf, end, &tp.tm_hour, &tp.tm_min, &tp.tm_sec)) {
        return (time_t)0;
      }
      if (!mime_parse_year(buf, end, &tp.tm_year)) {
        return (time_t)0;
      }
    }
  }
  year = tp.tm_year;
  month = tp.tm_mon;
  mday = tp.tm_mday;
  if (year > 137) {
    return (time_t)INT_MAX;
  }
  if (year < 70) {
    return (time_t)0;
  }
  mday += days[month];
  if (month < 2) {
    year -= 1;
  }
  mday += (year * 365) + (year / 4) - (year / 100) + (year / 100 + 3) / 4;
  mday -= DAYS_OFFSET;
  t = ((mday * 24 + tp.tm_hour) * 60 + tp.tm_min) * 60 + tp.tm_sec;
  return t;
}

