      shell = optarg;
      break;
    case 'u':
      if (su_mode != RUNUSER_MODE)
        usage(EXIT_FAILURE);
      runuser_user = optarg;
      break;
    case 'h':
      usage(0);
    case 'V':
      printf(UTIL_LINUX_VERSION);
      exit(EXIT_SUCCESS);
