    simulate_login = true;
    ++optind;
  }
  if (simulate_login && !change_environment) {
    warnx(_("ignoring --preserve-environment, it's mutually exclusive with "
            "--login"));
    change_environment = true;
  }
  switch (su_mode) {
  case RUNUSER_MODE:
    if (runuser_user) {
      new_user = runuser_user;
      if (shell || fast_startup || command || simulate_login) {
 errx ( EXIT_FAILURE , _ ( "options --{
shell,fast,command,session-command,login
      }
      and" " --user are mutually exclusive " ) ) ;
    }
    if (optind == argc)
      errx(EXIT_FAILURE, _("no command was specified"));
