    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  if (frame_4cc == AV_RL32("ifr2")) {
    picture->pict_type = AV_PICTURE_TYPE_I;
    if ((ret = decode_i2_frame(f, picture, buf - 4, frame_size + 4)) < 0)
      return ret;
  } else if (frame_4cc == AV_RL32("ifrm")) {
    picture->pict_type = AV_PICTURE_TYPE_I;
    if ((ret = decode_i_frame(f, picture, buf, frame_size)) < 0)
      return ret;
  } else if (frame_4cc == AV_RL32("pfrm") || frame_4cc == AV_RL32("pfr2")) {
    if (!f->last_picture->data[0]) {
      if ((ret = ff_get_buffer(avctx, f->last_picture,
                               AV_GET_BUFFER_FLAG_REF)) < 0) {
        av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
        return ret;
      }
      memset(f->last_picture->data[0], 0,
             avctx->height * FFABS(f->last_picture->linesize[0]));
    }
    picture->pict_type = AV_PICTURE_TYPE_P;
    if ((ret = decode_p_frame(f, picture, buf, frame_size)) < 0)
      return ret;
  } else if (frame_4cc == AV_RL32("snd_")) {
    av_log(avctx, AV_LOG_ERROR, "ignoring snd_ chunk length:%d\n", buf_size);
  } else {
    av_log(avctx, AV_LOG_ERROR, "ignoring unknown chunk length:%d\n", buf_size);
  }
  picture->key_frame = picture->pict_type == AV_PICTURE_TYPE_I;
  av_frame_unref(f->last_picture);
  if ((ret = av_frame_ref(f->last_picture, picture)) < 0)
    return ret;
  *got_frame = 1;
  emms_c();
  return buf_size;
}

static Picture *remove_long(H264Context *h, int i, int ref_mask) {
  Picture *pic;
  pic = h->long_ref[i];
  if (pic) {
    if (unreference_pic(h, pic, ref_mask)) {
      assert(h->long_ref[i]->long_ref == 1);
      h->long_ref[i]->long_ref = 0;
      h->long_ref[i] = NULL;
      h->long_ref_count--;
    }
  }
  return pic;
}

MSG_PROCESS_RETURN tls_process_cert_verify(SSL *s, PACKET *pkt) {
  EVP_PKEY *pkey = NULL;
  const unsigned char *sig, *data;
#ifndef OPENSSL_NO_GOST unsigned char *gost_data = NULL;
#endif int al, ret = MSG_PROCESS_ERROR;
  int type = 0, j;
  unsigned int len;
  X509 *peer;
  const EVP_MD *md = NULL;
  long hdatalen = 0;
  void *hdata;
  EVP_MD_CTX *mctx = EVP_MD_CTX_new();
  if (mctx == NULL) {
    SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, ERR_R_MALLOC_FAILURE);
    al = SSL_AD_INTERNAL_ERROR;
    goto f_err;
  }
  peer = s->session->peer;
  pkey = X509_get0_pubkey(peer);
  type = X509_certificate_type(peer, pkey);
  if (!(type & EVP_PKT_SIGN)) {
    SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY,
           SSL_R_SIGNATURE_FOR_NON_SIGNING_CERTIFICATE);
    al = SSL_AD_ILLEGAL_PARAMETER;
    goto f_err;
  }
#ifndef OPENSSL_NO_GOST if (PACKET_remaining(pkt) == 64 &&                     \
                            EVP_PKEY_id(pkey) == NID_id_GostR3410_2001) {
  len = 64;
}
else #endif {
  if (SSL_USE_SIGALGS(s)) {
    int rv;
    if (!PACKET_get_bytes(pkt, &sig, 2)) {
      al = SSL_AD_DECODE_ERROR;
      goto f_err;
    }
    rv = tls12_check_peer_sigalg(&md, s, sig, pkey);
    if (rv == -1) {
      al = SSL_AD_INTERNAL_ERROR;
      goto f_err;
    } else if (rv == 0) {
      al = SSL_AD_DECODE_ERROR;
      goto f_err;
    }
#ifdef SSL_DEBUG fprintf(stderr, "USING TLSv1.2 HASH %s\n", EVP_MD_name(md));
#endif }
    else {
      int idx = ssl_cert_type(NULL, pkey);
      if (idx >= 0)
        md = s->s3->tmp.md[idx];
      if (md == NULL) {
        al = SSL_AD_INTERNAL_ERROR;
        goto f_err;
      }
    }
    if (!PACKET_get_net_2(pkt, &len)) {
      SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, SSL_R_LENGTH_MISMATCH);
      al = SSL_AD_DECODE_ERROR;
      goto f_err;
    }
  }
  j = EVP_PKEY_size(pkey);
  if (((int)len > j) || ((int)PACKET_remaining(pkt) > j) ||
      (PACKET_remaining(pkt) == 0)) {
    SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, SSL_R_WRONG_SIGNATURE_SIZE);
    al = SSL_AD_DECODE_ERROR;
    goto f_err;
  }
  if (!PACKET_get_bytes(pkt, &data, len)) {
    SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, SSL_R_LENGTH_MISMATCH);
    al = SSL_AD_DECODE_ERROR;
    goto f_err;
  }
  hdatalen = BIO_get_mem_data(s->s3->handshake_buffer, &hdata);
  if (hdatalen <= 0) {
    SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, ERR_R_INTERNAL_ERROR);
    al = SSL_AD_INTERNAL_ERROR;
    goto f_err;
  }
#ifdef SSL_DEBUG fprintf(stderr, "Using client verify alg %s\n",               \
                         EVP_MD_name(md));
#endif if (!EVP_VerifyInit_ex(mctx, md, NULL) ||                               \
           !EVP_VerifyUpdate(mctx, hdata, hdatalen)) {
  SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, ERR_R_EVP_LIB);
  al = SSL_AD_INTERNAL_ERROR;
  goto f_err;
}
#ifndef OPENSSL_NO_GOST {
int pktype = EVP_PKEY_id(pkey);
if (pktype == NID_id_GostR3410_2001 || pktype == NID_id_GostR3410_2012_256 ||
    pktype == NID_id_GostR3410_2012_512) {
  if ((gost_data = OPENSSL_malloc(len)) == NULL) {
    SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, ERR_R_MALLOC_FAILURE);
    al = SSL_AD_INTERNAL_ERROR;
    goto f_err;
  }
  BUF_reverse(gost_data, data, len);
  data = gost_data;
}
}
#endif if (s->version == SSL3_VERSION &&                                       \
           !EVP_MD_CTX_ctrl(mctx, EVP_CTRL_SSL3_MASTER_SECRET,                 \
                            s->session->master_key_length,                     \
                            s->session->master_key)) {
SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, ERR_R_EVP_LIB);
al = SSL_AD_INTERNAL_ERROR;
goto f_err;
}
if (EVP_VerifyFinal(mctx, data, len, pkey) <= 0) {
  al = SSL_AD_DECRYPT_ERROR;
  SSLerr(SSL_F_TLS_PROCESS_CERT_VERIFY, SSL_R_BAD_SIGNATURE);
  goto f_err;
}
ret = MSG_PROCESS_CONTINUE_PROCESSING;
if (0) {
f_err:
  ssl3_send_alert(s, SSL3_AL_FATAL, al);
  ossl_statem_set_error(s);
}
BIO_free(s->s3->handshake_buffer);
s->s3->handshake_buffer = NULL;
EVP_MD_CTX_free(mctx);
#ifndef OPENSSL_NO_GOST OPENSSL_free(gost_data);
#endif return ret;
}

mbfl_string *mbfl_mime_header_encode(mbfl_string *string, mbfl_string *result,
                                     enum mbfl_no_encoding outcode,
                                     enum mbfl_no_encoding encoding,
                                     const char *linefeed, int indent) {
  int n;
  unsigned char *p;
  struct mime_header_encoder_data *pe;
  mbfl_string_init(result);
  result->no_language = string->no_language;
  result->no_encoding = mbfl_no_encoding_ascii;
  pe = mime_header_encoder_new(string->no_encoding, outcode, encoding);
  if (pe == NULL) {
    return NULL;
  }
  if (linefeed != NULL) {
    n = 0;
    while (*linefeed && n < 8) {
      pe->lwsp[n++] = *linefeed++;
    }
    pe->lwsp[n++] = 0x20;
    pe->lwsp[n] = '\0';
    pe->lwsplen = n;
  }
  if (indent > 0 && indent < 74) {
    pe->firstindent = indent;
  }
  n = string->len;
  p = string->val;
  while (n > 0) {
    (*pe->conv1_filter->filter_function)(*p++, pe->conv1_filter);
    n--;
  }
  result = mime_header_encoder_result(pe, result);
  mime_header_encoder_delete(pe);
  return result;
}

static int is_a_member(int val, int *vals, int num_vals) {
  int lokke;
  for (lokke = 0; lokke < num_vals; lokke++)
    if (val == vals[lokke])
      return 1;
  return 0;
}

static gboolean ngsniffer_seek_read(wtap *wth, gint64 seek_off,
                                    struct wtap_pkthdr *phdr, Buffer *buf,
                                    int *err, gchar **err_info) {
  int ret;
  if (!ng_file_seek_rand(wth, seek_off, err, err_info))
    return FALSE;
  ret = ngsniffer_process_record(wth, TRUE, NULL, phdr, buf, err, err_info);
  if (ret < 0) {
    return FALSE;
  }
  switch (ret) {
  case REC_FRAME2:
  case REC_FRAME4:
  case REC_FRAME6:
    break;
  default:
    g_assert_not_reached();
    return FALSE;
  }
  return TRUE;
}

void vp9_predict_intra_block(const MACROBLOCKD *xd, int block_idx, int bwl_in,
                             TX_SIZE tx_size, PREDICTION_MODE mode,
                             const uint8_t *ref, int ref_stride, uint8_t *dst,
                             int dst_stride, int aoff, int loff, int plane) {
  const int bwl = bwl_in - tx_size;
  const int wmask = (1 << bwl) - 1;
  const int have_top = (block_idx >> bwl) || xd->up_available;
  const int have_left = (block_idx & wmask) || xd->left_available;
  const int have_right = ((block_idx & wmask) != wmask);
  const int x = aoff * 4;
  const int y = loff * 4;
  assert(bwl >= 0);
#if CONFIG_VP9_HIGHBITDEPTH if (xd->cur_buf->flags & YV12_FLAG_HIGHBITDEPTH) {
  build_intra_predictors_high(xd, ref, ref_stride, dst, dst_stride, mode,
                              tx_size, have_top, have_left, have_right, x, y,
                              plane, xd->bd);
  return;
}
#endif build_intra_predictors(xd, ref, ref_stride, dst, dst_stride, mode,      \
                              tx_size, have_top, have_left, have_right, x, y,  \
                              plane);
}

static int pfkey_broadcast(struct sk_buff *skb, gfp_t allocation,
                           int broadcast_flags, struct sock *one_sk,
                           struct net *net) {
  struct netns_pfkey *net_pfkey = net_generic(net, pfkey_net_id);
  struct sock *sk;
  struct hlist_node *node;
  struct sk_buff *skb2 = NULL;
  int err = -ESRCH;
  if (!skb)
    return -ENOMEM;
  rcu_read_lock();
  sk_for_each_rcu(sk, node, &net_pfkey->table) {
    struct pfkey_sock *pfk = pfkey_sk(sk);
    int err2;
    if (pfk->promisc)
      pfkey_broadcast_one(skb, &skb2, allocation, sk);
    if (sk == one_sk)
      continue;
    if (broadcast_flags != BROADCAST_ALL) {
      if (broadcast_flags & BROADCAST_PROMISC_ONLY)
        continue;
      if ((broadcast_flags & BROADCAST_REGISTERED) && !pfk->registered)
        continue;
      if (broadcast_flags & BROADCAST_ONE)
        continue;
    }
    err2 = pfkey_broadcast_one(skb, &skb2, allocation, sk);
    if ((broadcast_flags & BROADCAST_REGISTERED) && err)
      err = err2;
  }
  rcu_read_unlock();
  if (one_sk != NULL)
    err = pfkey_broadcast_one(skb, &skb2, allocation, one_sk);
  kfree_skb(skb2);
  kfree_skb(skb);
  return err;
}

static int tls_process_cke_dhe(SSL *s, PACKET *pkt, int *al) {
#ifndef OPENSSL_NO_DH EVP_PKEY *skey = NULL;
  DH *cdh;
  unsigned int i;
  BIGNUM *pub_key;
  const unsigned char *data;
  EVP_PKEY *ckey = NULL;
  int ret = 0;
  if (!PACKET_get_net_2(pkt, &i) || PACKET_remaining(pkt) != i) {
    *al = SSL_AD_HANDSHAKE_FAILURE;
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, SSL_R_DH_PUBLIC_VALUE_LENGTH_IS_WRONG);
    goto err;
  }
  skey = s->s3->tmp.pkey;
  if (skey == NULL) {
    *al = SSL_AD_HANDSHAKE_FAILURE;
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, SSL_R_MISSING_TMP_DH_KEY);
    goto err;
  }
  if (PACKET_remaining(pkt) == 0L) {
    *al = SSL_AD_HANDSHAKE_FAILURE;
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, SSL_R_MISSING_TMP_DH_KEY);
    goto err;
  }
  if (!PACKET_get_bytes(pkt, &data, i)) {
    *al = SSL_AD_INTERNAL_ERROR;
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, ERR_R_INTERNAL_ERROR);
    goto err;
  }
  ckey = EVP_PKEY_new();
  if (ckey == NULL || EVP_PKEY_copy_parameters(ckey, skey) == 0) {
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, SSL_R_BN_LIB);
    goto err;
  }
  cdh = EVP_PKEY_get0_DH(ckey);
  pub_key = BN_bin2bn(data, i, NULL);
  if (pub_key == NULL || !DH_set0_key(cdh, pub_key, NULL)) {
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, ERR_R_INTERNAL_ERROR);
    if (pub_key != NULL)
      BN_free(pub_key);
    goto err;
  }
  if (ssl_derive(s, skey, ckey) == 0) {
    *al = SSL_AD_INTERNAL_ERROR;
    SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, ERR_R_INTERNAL_ERROR);
    goto err;
  }
  ret = 1;
  EVP_PKEY_free(s->s3->tmp.pkey);
  s->s3->tmp.pkey = NULL;
err:
  EVP_PKEY_free(ckey);
  return ret;
#else *al = SSL_AD_INTERNAL_ERROR;
  SSLerr(SSL_F_TLS_PROCESS_CKE_DHE, ERR_R_INTERNAL_ERROR);
  return 0;
#endif }

static int parse_from(struct branch *b) {
  const char *from;
  struct branch *s;
  unsigned char sha1[20];
  if (!skip_prefix(command_buf.buf, "from ", &from))
    return 0;
  hashcpy(sha1, b->branch_tree.versions[1].sha1);
  s = lookup_branch(from);
  if (b == s)
    die("Can't create a branch from itself: %s", b->name);
  else if (s) {
    unsigned char *t = s->branch_tree.versions[1].sha1;
    hashcpy(b->sha1, s->sha1);
    hashcpy(b->branch_tree.versions[0].sha1, t);
    hashcpy(b->branch_tree.versions[1].sha1, t);
  } else if (*from == ':') {
    uintmax_t idnum = parse_mark_ref_eol(from);
    struct object_entry *oe = find_mark(idnum);
    if (oe->type != OBJ_COMMIT)
      die("Mark :%" PRIuMAX " not a commit", idnum);
    if (hashcmp(b->sha1, oe->idx.sha1)) {
      hashcpy(b->sha1, oe->idx.sha1);
      if (oe->pack_id != MAX_PACK_ID) {
        unsigned long size;
        char *buf = gfi_unpack_entry(oe, &size);
        parse_from_commit(b, buf, size);
        free(buf);
      } else
        parse_from_existing(b);
    }
  } else if (!get_sha1(from, b->sha1)) {
    parse_from_existing(b);
    if (is_null_sha1(b->sha1))
      b->delete = 1;
  } else
    die("Invalid ref name or SHA1 expression: %s", from);
  if (b->branch_tree.tree && hashcmp(sha1, b->branch_tree.versions[1].sha1)) {
    release_tree_content_recursive(b->branch_tree.tree);
    b->branch_tree.tree = NULL;
  }
  read_next_command();
  return 1;
}

static int delta_cacheable(unsigned long src_size, unsigned long trg_size,
                           unsigned long delta_size) {
  if (max_delta_cache_size &&
      delta_cache_size + delta_size > max_delta_cache_size)
    return 0;
  if (delta_size < cache_max_small_delta_size)
    return 1;
  if ((src_size >> 20) + (trg_size >> 21) > (delta_size >> 10))
    return 1;
  return 0;
}

static int virtio_net_handle_mac(VirtIONet *n, uint8_t cmd,
                                 VirtQueueElement *elem) {
  struct virtio_net_ctrl_mac mac_data;
  if (cmd != VIRTIO_NET_CTRL_MAC_TABLE_SET || elem->out_num != 3 ||
      elem->out_sg[1].iov_len < sizeof(mac_data) ||
      elem->out_sg[2].iov_len < sizeof(mac_data))
    return VIRTIO_NET_ERR;
  n->mac_table.in_use = 0;
  n->mac_table.first_multi = 0;
  n->mac_table.uni_overflow = 0;
  n->mac_table.multi_overflow = 0;
  memset(n->mac_table.macs, 0, MAC_TABLE_ENTRIES * ETH_ALEN);
  mac_data.entries = ldl_p(elem->out_sg[1].iov_base);
  if (sizeof(mac_data.entries) + (mac_data.entries * ETH_ALEN) >
      elem->out_sg[1].iov_len)
    return VIRTIO_NET_ERR;
  if (mac_data.entries <= MAC_TABLE_ENTRIES) {
    memcpy(n->mac_table.macs, elem->out_sg[1].iov_base + sizeof(mac_data),
           mac_data.entries * ETH_ALEN);
    n->mac_table.in_use += mac_data.entries;
  } else {
    n->mac_table.uni_overflow = 1;
  }
  n->mac_table.first_multi = n->mac_table.in_use;
  mac_data.entries = ldl_p(elem->out_sg[2].iov_base);
  if (sizeof(mac_data.entries) + (mac_data.entries * ETH_ALEN) >
      elem->out_sg[2].iov_len)
    return VIRTIO_NET_ERR;
  if (mac_data.entries) {
    if (n->mac_table.in_use + mac_data.entries <= MAC_TABLE_ENTRIES) {
      memcpy(n->mac_table.macs + (n->mac_table.in_use * ETH_ALEN),
             elem->out_sg[2].iov_base + sizeof(mac_data),
             mac_data.entries * ETH_ALEN);
      n->mac_table.in_use += mac_data.entries;
    } else {
      n->mac_table.multi_overflow = 1;
    }
  }
  return VIRTIO_NET_OK;
}

