static float *
qcms_modular_transform_data(struct qcms_modular_transform *transform,
                            float *src, float *dest, size_t len) {
  while (transform != NULL) {
    float *new_src = dest;
    const transform_module_fn_t transform_fn = transform->transform_module_fn;
    if (transform_fn != qcms_transform_module_gamma_table &&
        transform_fn != qcms_transform_module_gamma_lut &&
        transform_fn != qcms_transform_module_clut &&
        transform_fn != qcms_transform_module_clut_only &&
        transform_fn != qcms_transform_module_matrix &&
        transform_fn != qcms_transform_module_matrix_translate &&
        transform_fn != qcms_transform_module_LAB_to_XYZ &&
        transform_fn != qcms_transform_module_XYZ_to_LAB) {
      assert(0 && "Unsupported transform module");
      return NULL;
    }
    transform->transform_module_fn(transform, src, dest, len);
    dest = src;
    src = new_src;
    transform = transform->next_transform;
  }
  return src;
}

static int s302m_parse_frame_header(AVCodecContext *avctx, const uint8_t *buf,
                                    int buf_size) {
  uint32_t h;
  int frame_size, channels, bits;
  if (buf_size <= AES3_HEADER_LEN) {
    av_log(avctx, AV_LOG_ERROR, "frame is too short\n");
    return AVERROR_INVALIDDATA;
  }
  h = AV_RB32(buf);
  frame_size = (h >> 16) & 0xffff;
  channels = ((h >> 14) & 0x0003) * 2 + 2;
  bits = ((h >> 4) & 0x0003) * 4 + 16;
  if (AES3_HEADER_LEN + frame_size != buf_size || bits > 24) {
    av_log(avctx, AV_LOG_ERROR, "frame has invalid header\n");
    return AVERROR_INVALIDDATA;
  }
  avctx->bits_per_coded_sample = bits;
  if (bits > 16)
    avctx->sample_fmt = AV_SAMPLE_FMT_S32;
  else
    avctx->sample_fmt = AV_SAMPLE_FMT_S16;
  avctx->channels = channels;
  avctx->sample_rate = 48000;
  avctx->bit_rate =
      48000 * avctx->channels * (avctx->bits_per_coded_sample + 4) +
      32 * (48000 / (buf_size * 8 /
                     (avctx->channels * (avctx->bits_per_coded_sample + 4))));
  return frame_size;
}

static void alloc_raw_frame_buffers(VP9_COMP *cpi) {
  VP9_COMMON *cm = &cpi->common;
  const VP9EncoderConfig *oxcf = &cpi->oxcf;
  cpi->lookahead = vp9_lookahead_init(
      oxcf->width, oxcf->height, cm->subsampling_x, cm->subsampling_y,
      #if CONFIG_VP9_HIGHBITDEPTH cm->use_highbitdepth,
      #endif oxcf->lag_in_frames);
  if (!cpi->lookahead)
    vpx_internal_error(&cm->error, VPX_CODEC_MEM_ERROR,
                       "Failed to allocate lag buffers");
  if (vp9_realloc_frame_buffer(
          &cpi->alt_ref_buffer, oxcf->width, oxcf->height, cm->subsampling_x,
          cm->subsampling_y, #if CONFIG_VP9_HIGHBITDEPTH cm->use_highbitdepth,
          #endif VP9_ENC_BORDER_IN_PIXELS, NULL, NULL, NULL))
    vpx_internal_error(&cm->error, VPX_CODEC_MEM_ERROR,
                       "Failed to allocate altref buffer");
}

