static void tgq_decode_mb(TgqContext *s, AVFrame *frame, int mb_y, int mb_x) {
  int mode;
  int i;
  int8_t dc[6];
  mode = bytestream2_get_byte(&s->gb);
  if (mode > 12) {
    GetBitContext gb;
    init_get_bits(&gb, s->gb.buffer,
                  FFMIN(s->gb.buffer_end - s->gb.buffer, mode) * 8);
    for (i = 0; i < 6; i++)
      tgq_decode_block(s, s->block[i], &gb);
    tgq_idct_put_mb(s, s->block, frame, mb_x, mb_y);
    bytestream2_skip(&s->gb, mode);
  } else {
    if (mode == 3) {
      memset(dc, bytestream2_get_byte(&s->gb), 4);
      dc[4] = bytestream2_get_byte(&s->gb);
      dc[5] = bytestream2_get_byte(&s->gb);
    } else if (mode == 6) {
      bytestream2_get_buffer(&s->gb, dc, 6);
    } else if (mode == 12) {
      for (i = 0; i < 6; i++) {
        dc[i] = bytestream2_get_byte(&s->gb);
        bytestream2_skip(&s->gb, 1);
      }
    } else {
      av_log(s->avctx, AV_LOG_ERROR, "unsupported mb mode %i\n", mode);
    }
    tgq_idct_put_mb_dconly(s, frame, mb_x, mb_y, dc);
  }
}

static int astream_try_base64_decode_char(struct attachment_istream_part *part,
                                          size_t pos, char chr) {
  switch (part->base64_state) {
  case BASE64_STATE_0:
    if (base64_is_valid_char(chr))
      part->base64_state++;
    else if (chr == '\r')
      part->base64_state = BASE64_STATE_CR;
    else if (chr == '\n') {
      return astream_base64_decode_lf(part);
    } else {
      return -1;
    }
    break;
  case BASE64_STATE_1:
    if (!base64_is_valid_char(chr))
      return -1;
    part->base64_state++;
    break;
  case BASE64_STATE_2:
    if (base64_is_valid_char(chr))
      part->base64_state++;
    else if (chr == '=')
      part->base64_state = BASE64_STATE_EOB;
    else
      return -1;
    break;
  case BASE64_STATE_3:
    part->base64_bytes = part->temp_output->offset + pos + 1;
    if (base64_is_valid_char(chr)) {
      part->base64_state = BASE64_STATE_0;
      part->cur_base64_blocks++;
    } else if (chr == '=') {
      part->base64_state = BASE64_STATE_EOM;
      part->cur_base64_blocks++;
      if (part->cur_base64_blocks > part->base64_line_blocks &&
          part->base64_line_blocks > 0) {
        return -1;
      }
      return 0;
    } else {
      return -1;
    }
    break;
  case BASE64_STATE_CR:
    if (chr != '\n')
      return -1;
    if (!part->base64_have_crlf) {
      if (part->base64_line_blocks != 0) {
        return -1;
      }
      part->base64_have_crlf = TRUE;
    }
    return astream_base64_decode_lf(part);
  case BASE64_STATE_EOB:
    if (chr != '=')
      return -1;
    part->base64_bytes = part->temp_output->offset + pos + 1;
    part->base64_state = BASE64_STATE_EOM;
    part->cur_base64_blocks++;
    if (part->cur_base64_blocks > part->base64_line_blocks &&
        part->base64_line_blocks > 0) {
      return -1;
    }
    return 0;
  case BASE64_STATE_EOM:
    i_unreached();
  }
  return 1;
}

