int ff_mpeg_ref_picture(MpegEncContext *s, Picture *dst, Picture *src) {
  int ret;
  av_assert0(!dst->f.buf[0]);
  av_assert0(src->f.buf[0]);
  src->tf.f = &src->f;
  dst->tf.f = &dst->f;
  ret = ff_thread_ref_frame(&dst->tf, &src->tf);
  if (ret < 0)
    goto fail;
  ret = update_picture_tables(dst, src);
  if (ret < 0)
    goto fail;
  if (src->hwaccel_picture_private) {
    dst->hwaccel_priv_buf = av_buffer_ref(src->hwaccel_priv_buf);
    if (!dst->hwaccel_priv_buf)
      goto fail;
    dst->hwaccel_picture_private = dst->hwaccel_priv_buf->data;
  }
  dst->field_picture = src->field_picture;
  dst->mb_var_sum = src->mb_var_sum;
  dst->mc_mb_var_sum = src->mc_mb_var_sum;
  dst->b_frame_score = src->b_frame_score;
  dst->needs_realloc = src->needs_realloc;
  dst->reference = src->reference;
  dst->shared = src->shared;
  return 0;
fail:
  ff_mpeg_unref_picture(s, dst);
  return ret;
}

static void file_deleted_callback(GFile *file, GError *error,
                                  gpointer callback_data) {
  DeleteData *data = callback_data;
  CommonJob *job;
  SourceInfo *source_info;
  TransferInfo *transfer_info;
  GFileType file_type;
  char *primary;
  char *secondary;
  char *details = NULL;
  int response;
  job = data->job;
  source_info = data->source_info;
  transfer_info = data->transfer_info;
  data->transfer_info->num_files++;
  if (error == NULL) {
    nautilus_file_changes_queue_file_removed(file);
    report_delete_progress(data->job, data->source_info, data->transfer_info);
    return;
  }
  if (job_aborted(job) || job->skip_all_error || should_skip_file(job, file) ||
      should_skip_readdir_error(job, file)) {
    return;
  }
  primary = f(_("Error while deleting."));
  file_type = g_file_query_file_type(file, G_FILE_QUERY_INFO_NOFOLLOW_SYMLINKS,
                                     job->cancellable);
  if (file_type == G_FILE_TYPE_DIRECTORY) {
    secondary = IS_IO_ERROR(error, PERMISSION_DENIED)
                    ? f(_("There was an error deleting the folder “%B”."), file)
                    : f(_("You do not have sufficient permissions to delete "
                          "the folder “%B”."),
                        file);
  } else {
    secondary = IS_IO_ERROR(error, PERMISSION_DENIED)
                    ? f(_("There was an error deleting the file “%B”."), file)
                    : f(_("You do not have sufficient permissions to delete "
                          "the file “%B”."),
                        file);
  }
  details = error->message;
  response = run_cancel_or_skip_warning(
      job, primary, secondary, details, source_info->num_files,
      source_info->num_files - transfer_info->num_files);
  if (response == 0 || response == GTK_RESPONSE_DELETE_EVENT) {
    abort_job(job);
  } else if (response == 1) {
    job->skip_all_error = TRUE;
  }
}

static gpg_err_code_t mpi_from_keyparam(gcry_mpi_t *r_a, gcry_sexp_t keyparam,
                                        const char *name) {
  gcry_err_code_t ec = 0;
  gcry_sexp_t l1;
  l1 = gcry_sexp_find_token(keyparam, name, 0);
  if (l1) {
    *r_a = gcry_sexp_nth_mpi(l1, 1, GCRYMPI_FMT_USG);
    gcry_sexp_release(l1);
    if (!*r_a)
      ec = GPG_ERR_INV_OBJ;
  }
  return ec;
}

