static int test_in_memory(xd3_stream *stream, int ignore) {
  uint8_t ibuf[sizeof(test_text)];
  uint8_t dbuf[sizeof(test_text)];
  uint8_t obuf[sizeof(test_text)];
  usize_t size = sizeof(test_text);
  usize_t dsize, osize;
  int r1, r2;
  int eflags = SECONDARY_DJW ? XD3_SEC_DJW : 0;
  memcpy(ibuf, test_text, size);
  memset(ibuf + 128, 0, 16);
  r1 = xd3_encode_memory(ibuf, size, test_text, size, dbuf, &dsize, size,
                         eflags);
  r2 = xd3_decode_memory(dbuf, dsize, test_text, size, obuf, &osize, size, 0);
  if (r1 != 0 || r2 != 0 || dsize >= (size / 2) || dsize < 1 || osize != size) {
    stream->msg = "encode/decode size error";
    return XD3_INTERNAL;
  }
  if (memcmp(obuf, ibuf, size) != 0) {
    stream->msg = "encode/decode data error";
    return XD3_INTERNAL;
  }
  return 0;
}

static void vc2_subband_dwt_53(VC2TransformContext *t, dwtcoef *data,
                               ptrdiff_t stride, int width, int height) {
  int x, y;
  dwtcoef *synth = t->buffer, *synthl = synth, *datal = data;
  const ptrdiff_t synth_width = width << 1;
  const ptrdiff_t synth_height = height << 1;
  for (y = 0; y < synth_height; y++) {
    for (x = 0; x < synth_width; x++)
      synthl[x] = datal[x] << 1;
    synthl += synth_width;
    datal += stride;
  }
  synthl = synth;
  for (y = 0; y < synth_height; y++) {
    for (x = 0; x < width - 1; x++)
      synthl[2 * x + 1] -= (synthl[2 * x] + synthl[2 * x + 2] + 1) >> 1;
    synthl[synth_width - 1] -= (2 * synthl[synth_width - 2] + 1) >> 1;
    synthl[0] += (2 * synthl[1] + 2) >> 2;
    for (x = 1; x < width - 1; x++)
      synthl[2 * x] += (synthl[2 * x - 1] + synthl[2 * x + 1] + 2) >> 2;
    synthl[synth_width - 2] +=
        (synthl[synth_width - 3] + synthl[synth_width - 1] + 2) >> 2;
    synthl += synth_width;
  }
  synthl = synth + synth_width;
  for (x = 0; x < synth_width; x++)
    synthl[x] -= (synthl[x - synth_width] + synthl[x + synth_width] + 1) >> 1;
  synthl = synth + (synth_width << 1);
  for (y = 1; y < height - 1; y++) {
    for (x = 0; x < synth_width; x++)
      synthl[x + synth_width] -=
          (synthl[x] + synthl[x + synth_width * 2] + 1) >> 1;
    synthl += (synth_width << 1);
  }
  synthl = synth + (synth_height - 1) * synth_width;
  for (x = 0; x < synth_width; x++)
    synthl[x] -= (2 * synthl[x - synth_width] + 1) >> 1;
  synthl = synth;
  for (x = 0; x < synth_width; x++)
    synthl[x] += (2 * synthl[synth_width + x] + 2) >> 2;
  synthl = synth + (synth_width << 1);
  for (y = 1; y < height - 1; y++) {
    for (x = 0; x < synth_width; x++)
      synthl[x] += (synthl[x + synth_width] + synthl[x - synth_width] + 2) >> 2;
    synthl += (synth_width << 1);
  }
  synthl = synth + (synth_height - 2) * synth_width;
  for (x = 0; x < synth_width; x++)
    synthl[x] += (synthl[x - synth_width] + synthl[x + synth_width] + 2) >> 2;
  deinterleave(data, stride, width, height, synth);
}

