        (c[4] == 0x43) && (c[5] == 0x2b) && (c[6] == 0x1f) && (c[7] == 0x5b))
      config = 1;
    else if ((c[7] == 0x2f) && (c[6] == 0x25) && (c[5] == 0xc0) &&
             (c[4] == 0xc7) && (c[3] == 0x43) && (c[2] == 0x2b) &&
             (c[1] == 0x1f) && (c[0] == 0x5b))
