    else if ((c[4] == 0x2f) && (c[5] == 0x25) && (c[6] == 0xc0) &&
             (c[7] == 0xc7) && (c[0] == 0x43) && (c[1] == 0x2b) &&
             (c[2] == 0x1f) && (c[3] == 0x5b))
      config = 3;
