  int i;
  if (png_ptr == NULL || info_ptr == NULL || num_unknowns == 0)
    return;
  np = (png_unknown_chunkp)png_malloc_warn(
      png_ptr, (png_uint_32)((info_ptr->unknown_chunks_num + num_unknowns) *
                             png_sizeof(png_unknown_chunk)));
