static DeviceState *qbus_find_dev(BusState *bus, char *elem) {
  DeviceState *dev;
  QLIST_FOREACH(dev, &bus->children, sibling) {
    if (dev->id && strcmp(dev->id, elem) == 0) {
      return dev;
    }
  }
  QLIST_FOREACH(dev, &bus->children, sibling) {
    if (strcmp(dev->info->name, elem) == 0) {
      return dev;
    }
  }
  QLIST_FOREACH(dev, &bus->children, sibling) {
    if (dev->info->alias && strcmp(dev->info->alias, elem) == 0) {
      return dev;
    }
  }
  return NULL;
}

static int ipv4_local_port_range(ctl_table *table, int write,
                                 void __user *buffer, size_t *lenp,
                                 loff_t *ppos) {
  int ret;
  int range[2];
  ctl_table tmp = {
      .data = &range,
      .maxlen = sizeof(range),
      .mode = table->mode,
      .extra1 = &ip_local_port_range_min,
      .extra2 = &ip_local_port_range_max,
  };
  inet_get_local_port_range(range, range + 1);
  ret = proc_dointvec_minmax(&tmp, write, buffer, lenp, ppos);
  if (write && ret == 0) {
    if (range[1] < range[0])
      ret = -EINVAL;
    else
      set_local_port_range(range);
  }
  return ret;
}

static int ws_snd_decode_frame(AVCodecContext *avctx, void *data,
                               int *got_frame_ptr, AVPacket *avpkt) {
  AVFrame *frame = data;
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  int in_size, out_size, ret;
  int sample = 128;
  uint8_t *samples;
  uint8_t *samples_end;
  if (!buf_size)
    return 0;
  if (buf_size < 4) {
    av_log(avctx, AV_LOG_ERROR, "packet is too small\n");
    return AVERROR(EINVAL);
  }
  out_size = AV_RL16(&buf[0]);
  in_size = AV_RL16(&buf[2]);
  buf += 4;
  if (in_size > buf_size) {
    av_log(avctx, AV_LOG_ERROR, "Frame data is larger than input buffer\n");
    return -1;
  }
  frame->nb_samples = out_size;
  if ((ret = ff_get_buffer(avctx, frame, 0)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  samples = frame->data[0];
  samples_end = samples + out_size;
  if (in_size == out_size) {
    memcpy(samples, buf, out_size);
    *got_frame_ptr = 1;
    return buf_size;
  }
  while (samples < samples_end && buf - avpkt->data < buf_size) {
    int code, smp, size;
    uint8_t count;
    code = *buf >> 6;
    count = *buf & 0x3F;
    buf++;
    switch (code) {
    case 0:
      smp = 4 * (count + 1);
      break;
    case 1:
      smp = 2 * (count + 1);
      break;
    case 2:
      smp = (count & 0x20) ? 1 : count + 1;
      break;
    default:
      smp = count + 1;
      break;
    }
    if (samples_end - samples < smp)
      break;
    size = ((code == 2 && (count & 0x20)) || code == 3) ? 0 : count + 1;
    if ((buf - avpkt->data) + size > buf_size)
      break;
    switch (code) {
    case 0:
      for (count++; count > 0; count--) {
        code = *buf++;
        sample += (code & 0x3) - 2;
        sample = av_clip_uint8(sample);
        *samples++ = sample;
        sample += ((code >> 2) & 0x3) - 2;
        sample = av_clip_uint8(sample);
        *samples++ = sample;
        sample += ((code >> 4) & 0x3) - 2;
        sample = av_clip_uint8(sample);
        *samples++ = sample;
        sample += (code >> 6) - 2;
        sample = av_clip_uint8(sample);
        *samples++ = sample;
      }
      break;
    case 1:
      for (count++; count > 0; count--) {
        code = *buf++;
        sample += ws_adpcm_4bit[code & 0xF];
        sample = av_clip_uint8(sample);
        *samples++ = sample;
        sample += ws_adpcm_4bit[code >> 4];
        sample = av_clip_uint8(sample);
        *samples++ = sample;
      }
      break;
    case 2:
      if (count & 0x20) {
        int8_t t;
        t = count;
        t <<= 3;
        sample += t >> 3;
        sample = av_clip_uint8(sample);
        *samples++ = sample;
      } else {
        memcpy(samples, buf, smp);
        samples += smp;
        buf += smp;
        sample = buf[-1];
      }
      break;
    default:
      memset(samples, sample, smp);
      samples += smp;
    }
  }
  frame->nb_samples = samples - frame->data[0];
  *got_frame_ptr = 1;
  return buf_size;
}

