int ipv6_rcv_saddr_equal(const struct sock *sk, const struct sock *sk2) {
  const struct in6_addr *sk_rcv_saddr6 = &inet6_sk(sk)->rcv_saddr;
  const struct in6_addr *sk2_rcv_saddr6 = inet6_rcv_saddr(sk2);
  __be32 sk1_rcv_saddr = inet_sk(sk)->inet_rcv_saddr;
  __be32 sk2_rcv_saddr = inet_rcv_saddr(sk2);
  int sk_ipv6only = ipv6_only_sock(sk);
  int sk2_ipv6only = inet_v6_ipv6only(sk2);
  int addr_type = ipv6_addr_type(sk_rcv_saddr6);
  int addr_type2 =
      sk2_rcv_saddr6 ? ipv6_addr_type(sk2_rcv_saddr6) : IPV6_ADDR_MAPPED;
  if (addr_type == IPV6_ADDR_MAPPED && addr_type2 == IPV6_ADDR_MAPPED)
    return (!sk2_ipv6only && (!sk1_rcv_saddr || !sk2_rcv_saddr ||
                              sk1_rcv_saddr == sk2_rcv_saddr));
  if (addr_type2 == IPV6_ADDR_ANY &&
      !(sk2_ipv6only && addr_type == IPV6_ADDR_MAPPED))
    return 1;
  if (addr_type == IPV6_ADDR_ANY &&
      !(sk_ipv6only && addr_type2 == IPV6_ADDR_MAPPED))
    return 1;
  if (sk2_rcv_saddr6 && ipv6_addr_equal(sk_rcv_saddr6, sk2_rcv_saddr6))
    return 1;
  return 0;
}

