static bool cgroupfs_mount_cgroup(void *hdata, const char *root, int type) {
  size_t bufsz = strlen(root) + sizeof("/sys/fs/cgroup");
  char *path = NULL;
  char **parts = NULL;
  char *dirname = NULL;
  char *abs_path = NULL;
  char *abs_path2 = NULL;
  struct cgfs_data *cgfs_d;
  struct cgroup_process_info *info, *base_info;
  int r, saved_errno = 0;
  cgfs_d = hdata;
  if (!cgfs_d)
    return false;
  base_info = cgfs_d->info;
  if (type == LXC_AUTO_CGROUP_FULL_NOSPEC)
    type = LXC_AUTO_CGROUP_FULL_MIXED;
  else if (type == LXC_AUTO_CGROUP_NOSPEC)
    type = LXC_AUTO_CGROUP_MIXED;
  if (type < LXC_AUTO_CGROUP_RO || type > LXC_AUTO_CGROUP_FULL_MIXED) {
    ERROR("could not mount cgroups into container: invalid type specified "
          "internally");
    errno = EINVAL;
    return false;
  }
  path = calloc(1, bufsz);
  if (!path)
    return false;
  snprintf(path, bufsz, "%s/sys/fs/cgroup", root);
  r = safe_mount("cgroup_root", path, "tmpfs",
                 MS_NOSUID | MS_NODEV | MS_NOEXEC | MS_RELATIME,
                 "size=10240k,mode=755", root);
  if (r < 0) {
    SYSERROR("could not mount tmpfs to /sys/fs/cgroup in the container");
    return false;
  }
  for (info = base_info; info; info = info->next) {
    size_t subsystem_count, i;
    struct cgroup_mount_point *mp = info->designated_mount_point;
    if (!mp)
      mp =
          lxc_cgroup_find_mount_point(info->hierarchy, info->cgroup_path, true);
    if (!mp) {
      SYSERROR("could not find original mount point for cgroup hierarchy while "
               "trying to mount cgroup filesystem");
      goto out_error;
    }
    subsystem_count = lxc_array_len((void **)info->hierarchy->subsystems);
    parts = calloc(subsystem_count + 1, sizeof(char *));
    if (!parts)
      goto out_error;
    for (i = 0; i < subsystem_count; i++) {
      if (!strncmp(info->hierarchy->subsystems[i], "name=", 5))
        parts[i] = info->hierarchy->subsystems[i] + 5;
      else
        parts[i] = info->hierarchy->subsystems[i];
    }
    dirname = lxc_string_join(",", (const char **)parts, false);
    if (!dirname)
      goto out_error;
    abs_path = lxc_append_paths(path, dirname);
    if (!abs_path)
      goto out_error;
    r = mkdir_p(abs_path, 0755);
    if (r < 0 && errno != EEXIST) {
      SYSERROR("could not create cgroup subsystem directory /sys/fs/cgroup/%s",
               dirname);
      goto out_error;
    }
    abs_path2 = lxc_append_paths(abs_path, info->cgroup_path);
    if (!abs_path2)
      goto out_error;
    if (type == LXC_AUTO_CGROUP_FULL_RO || type == LXC_AUTO_CGROUP_FULL_RW ||
        type == LXC_AUTO_CGROUP_FULL_MIXED) {
      if (strcmp(mp->mount_prefix, "/") != 0) {
        ERROR("could not automatically mount cgroup-full to /sys/fs/cgroup/%s: "
              "host has no mount point for this cgroup filesystem that has "
              "access to the root cgroup",
              dirname);
        goto out_error;
      }
      r = mount(mp->mount_point, abs_path, "none", MS_BIND, 0);
      if (r < 0) {
        SYSERROR("error bind-mounting %s to %s", mp->mount_point, abs_path);
        goto out_error;
      }
      if (type == LXC_AUTO_CGROUP_FULL_RO ||
          type == LXC_AUTO_CGROUP_FULL_MIXED) {
        r = mount(NULL, abs_path, NULL, MS_REMOUNT | MS_BIND | MS_RDONLY, NULL);
        if (r < 0) {
          SYSERROR("error re-mounting %s readonly", abs_path);
          goto out_error;
        }
      }
      if (type == LXC_AUTO_CGROUP_FULL_MIXED) {
        r = mount(abs_path2, abs_path2, NULL, MS_BIND, NULL);
        if (r < 0) {
          SYSERROR("error bind-mounting %s onto itself", abs_path2);
          goto out_error;
        }
        r = mount(NULL, abs_path2, NULL, MS_REMOUNT | MS_BIND, NULL);
        if (r < 0) {
          SYSERROR("error re-mounting %s readwrite", abs_path2);
          goto out_error;
        }
      }
    } else {
      r = mkdir_p(abs_path2, 0755);
      if (r < 0 && errno != EEXIST) {
        SYSERROR("could not create cgroup directory /sys/fs/cgroup/%s%s",
                 dirname, info->cgroup_path);
        goto out_error;
      }
      if (type == LXC_AUTO_CGROUP_MIXED || type == LXC_AUTO_CGROUP_RO) {
        r = mount(abs_path, abs_path, NULL, MS_BIND, NULL);
        if (r < 0) {
          SYSERROR("error bind-mounting %s onto itself", abs_path);
          goto out_error;
        }
        r = mount(NULL, abs_path, NULL, MS_REMOUNT | MS_BIND | MS_RDONLY, NULL);
        if (r < 0) {
          SYSERROR("error re-mounting %s readonly", abs_path);
          goto out_error;
        }
      }
      free(abs_path);
      abs_path = NULL;
      abs_path = cgroup_to_absolute_path(mp, info->cgroup_path, NULL);
      if (!abs_path)
        goto out_error;
      r = mount(abs_path, abs_path2, "none", MS_BIND, 0);
      if (r < 0) {
        SYSERROR("error bind-mounting %s to %s", abs_path, abs_path2);
        goto out_error;
      }
      if (type == LXC_AUTO_CGROUP_RO) {
        r = mount(NULL, abs_path2, NULL, MS_REMOUNT | MS_BIND | MS_RDONLY,
                  NULL);
        if (r < 0) {
          SYSERROR("error re-mounting %s readonly", abs_path2);
          goto out_error;
        }
      }
    }
    free(abs_path);
    free(abs_path2);
    abs_path = NULL;
    abs_path2 = NULL;
    if (subsystem_count > 1) {
      for (i = 0; i < subsystem_count; i++) {
        abs_path = lxc_append_paths(path, parts[i]);
        if (!abs_path)
          goto out_error;
        r = symlink(dirname, abs_path);
        if (r < 0)
          WARN("could not create symlink %s -> %s in /sys/fs/cgroup of "
               "container",
               parts[i], dirname);
        free(abs_path);
        abs_path = NULL;
      }
    }
    free(dirname);
    free(parts);
    dirname = NULL;
    parts = NULL;
  }
  free(path);
  return true;
out_error:
  saved_errno = errno;
  free(path);
  free(dirname);
  free(parts);
  free(abs_path);
  free(abs_path2);
  errno = saved_errno;
  return false;
}

static void *_getBuffer(UEnumeration *en, int32_t capacity) {
  if (en->baseContext != NULL) {
    if (((_UEnumBuffer *)en->baseContext)->len < capacity) {
      capacity += PAD;
      en->baseContext =
          uprv_realloc(en->baseContext, sizeof(int32_t) + capacity);
      if (en->baseContext == NULL) {
        return NULL;
      }
      ((_UEnumBuffer *)en->baseContext)->len = capacity;
    }
  } else {
    capacity += PAD;
    en->baseContext = uprv_malloc(sizeof(int32_t) + capacity);
    if (en->baseContext == NULL) {
      return NULL;
    }
    ((_UEnumBuffer *)en->baseContext)->len = capacity;
  }
  return (void *)&((_UEnumBuffer *)en->baseContext)->data;
}

static int h261_decode_mb(H261Context *h) {
  MpegEncContext *const s = &h->s;
  int i, cbp, xy;
  cbp = 63;
  do {
    h->mba_diff = get_vlc2(&s->gb, h261_mba_vlc.table, H261_MBA_VLC_BITS, 2);
    if (h->mba_diff == MBA_STARTCODE) {
      h->gob_start_code_skipped = 1;
      return SLICE_END;
    }
  } while (h->mba_diff == MBA_STUFFING);
  if (h->mba_diff < 0) {
    if (get_bits_left(&s->gb) <= 7)
      return SLICE_END;
    av_log(s->avctx, AV_LOG_ERROR, "illegal mba at %d %d\n", s->mb_x, s->mb_y);
    return SLICE_ERROR;
  }
  h->mba_diff += 1;
  h->current_mba += h->mba_diff;
  if (h->current_mba > MBA_STUFFING)
    return SLICE_ERROR;
  s->mb_x = ((h->gob_number - 1) % 2) * 11 + ((h->current_mba - 1) % 11);
  s->mb_y = ((h->gob_number - 1) / 2) * 3 + ((h->current_mba - 1) / 11);
  xy = s->mb_x + s->mb_y * s->mb_stride;
  ff_init_block_index(s);
  ff_update_block_index(s);
  h->mtype = get_vlc2(&s->gb, h261_mtype_vlc.table, H261_MTYPE_VLC_BITS, 2);
  h->mtype = h261_mtype_map[h->mtype];
  if (IS_QUANT(h->mtype)) {
    ff_set_qscale(s, get_bits(&s->gb, 5));
  }
  s->mb_intra = IS_INTRA4x4(h->mtype);
  if (IS_16X16(h->mtype)) {
    if ((h->current_mba == 1) || (h->current_mba == 12) ||
        (h->current_mba == 23) || (h->mba_diff != 1)) {
      h->current_mv_x = 0;
      h->current_mv_y = 0;
    }
    h->current_mv_x = decode_mv_component(&s->gb, h->current_mv_x);
    h->current_mv_y = decode_mv_component(&s->gb, h->current_mv_y);
  } else {
    h->current_mv_x = 0;
    h->current_mv_y = 0;
  }
  if (HAS_CBP(h->mtype)) {
    cbp = get_vlc2(&s->gb, h261_cbp_vlc.table, H261_CBP_VLC_BITS, 2) + 1;
  }
  if (s->mb_intra) {
    s->current_picture.f.mb_type[xy] = MB_TYPE_INTRA;
    goto intra;
  }
  s->mv_dir = MV_DIR_FORWARD;
  s->mv_type = MV_TYPE_16X16;
  s->current_picture.f.mb_type[xy] = MB_TYPE_16x16 | MB_TYPE_L0;
  s->mv[0][0][0] = h->current_mv_x * 2;
  s->mv[0][0][1] = h->current_mv_y * 2;
intra:
  if (s->mb_intra || HAS_CBP(h->mtype)) {
    s->dsp.clear_blocks(s->block[0]);
    for (i = 0; i < 6; i++) {
      if (h261_decode_block(h, s->block[i], i, cbp & 32) < 0) {
        return SLICE_ERROR;
      }
      cbp += cbp;
    }
  } else {
    for (i = 0; i < 6; i++)
      s->block_last_index[i] = -1;
  }
  ff_MPV_decode_mb(s, s->block);
  return SLICE_OK;
}

static int getDynamicOffset(uint32_t c, uint32_t *pOffset) {
  int i;
  for (i = 0; i < 7; ++i) {
    if ((uint32_t)(c - fixedOffsets[i]) <= 0x7f) {
      *pOffset = fixedOffsets[i];
      return 0xf9 + i;
    }
  }
  if (c < 0x80) {
    return -1;
  } else if (c < 0x3400 || (uint32_t)(c - 0x10000) < (0x14000 - 0x10000) ||
             (uint32_t)(c - 0x1d000) <= (0x1ffff - 0x1d000)) {
    *pOffset = c & 0x7fffff80;
    return (int)(c >> 7);
  } else if (0xe000 <= c && c != 0xfeff && c < 0xfff0) {
    *pOffset = c & 0x7fffff80;
    return (int)((c - gapOffset) >> 7);
  } else {
    return -1;
  }
}

static int ipvideo_decode_block_opcode_0x8_16(IpvideoContext *s,
                                              AVFrame *frame) {
  int x, y;
  uint16_t P[4];
  unsigned int flags = 0;
  uint16_t *pixel_ptr = (uint16_t *)s->pixel_ptr;
  P[0] = bytestream2_get_le16(&s->stream_ptr);
  P[1] = bytestream2_get_le16(&s->stream_ptr);
  if (!(P[0] & 0x8000)) {
    for (y = 0; y < 16; y++) {
      if (!(y & 3)) {
        if (y) {
          P[0] = bytestream2_get_le16(&s->stream_ptr);
          P[1] = bytestream2_get_le16(&s->stream_ptr);
        }
        flags = bytestream2_get_le16(&s->stream_ptr);
      }
      for (x = 0; x < 4; x++, flags >>= 1)
        *pixel_ptr++ = P[flags & 1];
      pixel_ptr += s->stride - 4;
      if (y == 7)
        pixel_ptr -= 8 * s->stride - 4;
    }
  } else {
    flags = bytestream2_get_le32(&s->stream_ptr);
    P[2] = bytestream2_get_le16(&s->stream_ptr);
    P[3] = bytestream2_get_le16(&s->stream_ptr);
    if (!(P[2] & 0x8000)) {
      for (y = 0; y < 16; y++) {
        for (x = 0; x < 4; x++, flags >>= 1)
          *pixel_ptr++ = P[flags & 1];
        pixel_ptr += s->stride - 4;
        if (y == 7) {
          pixel_ptr -= 8 * s->stride - 4;
          P[0] = P[2];
          P[1] = P[3];
          flags = bytestream2_get_le32(&s->stream_ptr);
        }
      }
    } else {
      for (y = 0; y < 8; y++) {
        if (y == 4) {
          P[0] = P[2];
          P[1] = P[3];
          flags = bytestream2_get_le32(&s->stream_ptr);
        }
        for (x = 0; x < 8; x++, flags >>= 1)
          *pixel_ptr++ = P[flags & 1];
        pixel_ptr += s->line_inc;
      }
    }
  }
  return 0;
}

static pdf_gstate *pdf_flush_text(fz_context *ctx, pdf_run_processor *pr) {
  pdf_gstate *gstate = pr->gstate + pr->gtop;
  fz_text *text;
  int dofill;
  int dostroke;
  int doclip;
  int doinvisible;
  softmask_save softmask = {NULL};
  int knockout_group = 0;
  text = pdf_tos_get_text(ctx, &pr->tos);
  if (!text)
    return gstate;
  dofill = dostroke = doclip = doinvisible = 0;
  switch (pr->tos.text_mode) {
  case 0:
    dofill = 1;
    break;
  case 1:
    dostroke = 1;
    break;
  case 2:
    dofill = dostroke = 1;
    break;
  case 3:
    doinvisible = 1;
    break;
  case 4:
    dofill = doclip = 1;
    break;
  case 5:
    dostroke = doclip = 1;
    break;
  case 6:
    dofill = dostroke = doclip = 1;
    break;
  case 7:
    doclip = 1;
    break;
  }
  if (pr->super.hidden)
    dostroke = dofill = 0;
  fz_try(ctx) {
    fz_rect tb = pr->tos.text_bbox;
    fz_transform_rect(&tb, &gstate->ctm);
    if (dostroke)
      fz_adjust_rect_for_stroke(ctx, &tb, gstate->stroke_state, &gstate->ctm);
    if (!text->head)
      break;
    if (dofill || dostroke)
      gstate = pdf_begin_group(ctx, pr, &tb, &softmask);
    if (dofill && dostroke) {
      if (gstate->stroke.alpha == 0) {
      } else if (gstate->stroke.alpha == 1.0f &&
                 gstate->blendmode == FZ_BLEND_NORMAL) {
      } else {
        knockout_group = 1;
        fz_begin_group(ctx, pr->dev, &tb, NULL, 0, 1, FZ_BLEND_NORMAL, 1);
      }
    }
    if (doinvisible)
      fz_ignore_text(ctx, pr->dev, text, &gstate->ctm);
    if (dofill) {
      switch (gstate->fill.kind) {
      case PDF_MAT_NONE:
        break;
      case PDF_MAT_COLOR:
        fz_fill_text(ctx, pr->dev, text, &gstate->ctm, gstate->fill.colorspace,
                     gstate->fill.v, gstate->fill.alpha,
                     &gstate->fill.color_params);
        break;
      case PDF_MAT_PATTERN:
        if (gstate->fill.pattern) {
          fz_clip_text(ctx, pr->dev, text, &gstate->ctm, &tb);
          pdf_show_pattern(ctx, pr, gstate->fill.pattern,
                           &pr->gstate[gstate->fill.gstate_num], &tb, PDF_FILL);
          fz_pop_clip(ctx, pr->dev);
        }
        break;
      case PDF_MAT_SHADE:
        if (gstate->fill.shade) {
          fz_clip_text(ctx, pr->dev, text, &gstate->ctm, &tb);
          fz_fill_shade(ctx, pr->dev, gstate->fill.shade,
                        &pr->gstate[gstate->fill.gstate_num].ctm,
                        gstate->fill.alpha, &gstate->fill.color_params);
          fz_pop_clip(ctx, pr->dev);
        }
        break;
      }
    }
    if (dostroke) {
      switch (gstate->stroke.kind) {
      case PDF_MAT_NONE:
        break;
      case PDF_MAT_COLOR:
        fz_stroke_text(ctx, pr->dev, text, gstate->stroke_state, &gstate->ctm,
                       gstate->stroke.colorspace, gstate->stroke.v,
                       gstate->stroke.alpha, &gstate->stroke.color_params);
        break;
      case PDF_MAT_PATTERN:
        if (gstate->stroke.pattern) {
          fz_clip_stroke_text(ctx, pr->dev, text, gstate->stroke_state,
                              &gstate->ctm, &tb);
          pdf_show_pattern(ctx, pr, gstate->stroke.pattern,
                           &pr->gstate[gstate->stroke.gstate_num], &tb,
                           PDF_STROKE);
          fz_pop_clip(ctx, pr->dev);
        }
        break;
      case PDF_MAT_SHADE:
        if (gstate->stroke.shade) {
          fz_clip_stroke_text(ctx, pr->dev, text, gstate->stroke_state,
                              &gstate->ctm, &tb);
          fz_fill_shade(ctx, pr->dev, gstate->stroke.shade,
                        &pr->gstate[gstate->stroke.gstate_num].ctm,
                        gstate->stroke.alpha, &gstate->stroke.color_params);
          fz_pop_clip(ctx, pr->dev);
        }
        break;
      }
    }
    if (knockout_group)
      fz_end_group(ctx, pr->dev);
    if (dofill || dostroke)
      pdf_end_group(ctx, pr, &softmask);
    if (doclip) {
      gstate->clip_depth++;
      fz_clip_text(ctx, pr->dev, text, &gstate->ctm, &tb);
    }
  }
  fz_always(ctx) { fz_drop_text(ctx, text); }
  fz_catch(ctx) { fz_rethrow(ctx); }
  return pr->gstate + pr->gtop;
}

static void php_zip_entry_get_info(INTERNAL_FUNCTION_PARAMETERS, int opt) {
  zval *zip_entry;
  zip_read_rsrc *zr_rsrc;
  if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "r", &zip_entry) ==
      FAILURE) {
    return;
  }
  ZEND_FETCH_RESOURCE(zr_rsrc, zip_read_rsrc *, &zip_entry, -1,
                      le_zip_entry_name, le_zip_entry);
  if (!zr_rsrc->zf) {
    RETURN_FALSE;
  }
  switch (opt) {
  case 0:
    RETURN_STRING((char *)zr_rsrc->sb.name, 1);
    break;
  case 1:
    RETURN_LONG((long)(zr_rsrc->sb.comp_size));
    break;
  case 2:
    RETURN_LONG((long)(zr_rsrc->sb.size));
    break;
  case 3:
    switch (zr_rsrc->sb.comp_method) {
    case 0:
      RETURN_STRING("stored", 1);
      break;
    case 1:
      RETURN_STRING("shrunk", 1);
      break;
    case 2:
    case 3:
    case 4:
    case 5:
      RETURN_STRING("reduced", 1);
      break;
    case 6:
      RETURN_STRING("imploded", 1);
      break;
    case 7:
      RETURN_STRING("tokenized", 1);
      break;
    case 8:
      RETURN_STRING("deflated", 1);
      break;
    case 9:
      RETURN_STRING("deflatedX", 1);
      break;
    case 10:
      RETURN_STRING("implodedX", 1);
      break;
    default:
      RETURN_FALSE;
    }
    RETURN_LONG((long)(zr_rsrc->sb.comp_method));
    break;
  }
}

static int make_cdt15_entry(int p1, int p2, int16_t *cdt) {
  int r, b, lo;
  b = cdt[p2];
  r = cdt[p1] << 10;
  lo = b + r;
  return (lo + (lo << 16)) << 1;
}

