static const char *cmd_hash_engine(cmd_parms *cmd, void *_dcfg,
                                   const char *p1) {
  directory_config *dcfg = (directory_config *)_dcfg;
  if (dcfg == NULL)
    return NULL;
  if (strcasecmp(p1, "on") == 0) {
    dcfg->hash_is_enabled = HASH_ENABLED;
    dcfg->hash_enforcement = HASH_ENABLED;
  } else if (strcasecmp(p1, "off") == 0) {
    dcfg->hash_is_enabled = HASH_DISABLED;
    dcfg->hash_enforcement = HASH_DISABLED;
  } else
    return apr_psprintf(cmd->pool,
                        "ModSecurity: Invalid value for SexHashEngine: %s", p1);
  return NULL;
}

int parse_CCategSpec(tvbuff_t *tvb, packet_info *pinfo, int offset,
                     proto_tree *parent_tree, proto_tree *pad_tree,
                     const char *fmt, ...) {
  proto_item *item;
  proto_tree *tree;
  va_list ap;
  guint32 type;
  const char *txt;
  va_start(ap, fmt);
  txt = wmem_strdup_vprintf(wmem_packet_scope(), fmt, ap);
  va_end(ap);
  tree = proto_tree_add_subtree(parent_tree, tvb, offset, 0, ett_CCategSpec,
                                &item, txt);
  type = tvb_get_letohl(tvb, offset);
  proto_tree_add_uint(tree, hf_mswsp_ccategspec_type, tvb, offset, 4, type);
  proto_item_append_text(item, " Type %u", type);
  offset += 4;
  offset = parse_CSort(tvb, offset, tree, pad_tree, "CSort");
  offset = parse_CRangeCategSpec(tvb, pinfo, offset, tree, pad_tree,
                                 "CRangeCategSpec");
  proto_item_set_end(item, tvb, offset);
  return offset;
}

static void U_CALLCONV _ISCIIOpen(UConverter *cnv, UConverterLoadArgs *pArgs,
                                  UErrorCode *errorCode) {
  if (pArgs->onlyTestIsLoadable) {
    return;
  }
  cnv->extraInfo = uprv_malloc(sizeof(UConverterDataISCII));
  if (cnv->extraInfo != NULL) {
    int32_t len = 0;
    UConverterDataISCII *converterData = (UConverterDataISCII *)cnv->extraInfo;
    converterData->contextCharToUnicode = NO_CHAR_MARKER;
    cnv->toUnicodeStatus = missingCharMarker;
    converterData->contextCharFromUnicode = 0x0000;
    converterData->resetToDefaultToUnicode = FALSE;
    if ((pArgs->options & UCNV_OPTIONS_VERSION_MASK) < 9) {
      converterData->currentDeltaFromUnicode =
          converterData->currentDeltaToUnicode =
              converterData->defDeltaToUnicode =
                  (uint16_t)(lookupInitialData[pArgs->options &
                                               UCNV_OPTIONS_VERSION_MASK]
                                 .uniLang *
                             DELTA);
      converterData->currentMaskFromUnicode =
          converterData->currentMaskToUnicode =
              converterData->defMaskToUnicode =
                  lookupInitialData[pArgs->options & UCNV_OPTIONS_VERSION_MASK]
                      .maskEnum;
      converterData->isFirstBuffer = TRUE;
      (void)uprv_strcpy(converterData->name, ISCII_CNV_PREFIX);
      len = (int32_t)uprv_strlen(converterData->name);
      converterData->name[len] =
          (char)((pArgs->options & UCNV_OPTIONS_VERSION_MASK) + '0');
      converterData->name[len + 1] = 0;
      converterData->prevToUnicodeStatus = 0x0000;
    } else {
      uprv_free(cnv->extraInfo);
      cnv->extraInfo = NULL;
      *errorCode = U_ILLEGAL_ARGUMENT_ERROR;
    }
  } else {
    *errorCode = U_MEMORY_ALLOCATION_ERROR;
  }
}

static int qemuMonitorJSONHasError(virJSONValuePtr reply, const char *klass) {
  virJSONValuePtr error;
  const char *thisklass;
  if (!virJSONValueObjectHasKey(reply, "error"))
    return 0;
  error = virJSONValueObjectGet(reply, "error");
  if (!error)
    return 0;
  if (!virJSONValueObjectHasKey(error, "class"))
    return 0;
  thisklass = virJSONValueObjectGetString(error, "class");
  if (!thisklass)
    return 0;
  return STREQ(klass, thisklass);
}

static SlirpState *slirp_lookup(Monitor *mon, const char *vlan,
                                const char *stack) {
  if (vlan) {
    NetClientState *nc;
    nc = net_hub_find_client_by_name(strtol(vlan, NULL, 0), stack);
    if (!nc) {
      monitor_printf(mon, "unrecognized (vlan-id, stackname) pair\n");
      return NULL;
    }
    if (strcmp(nc->model, "user")) {
      monitor_printf(mon, "invalid device specified\n");
      return NULL;
    }
    return DO_UPCAST(SlirpState, nc, nc);
  } else {
    if (QTAILQ_EMPTY(&slirp_stacks)) {
      monitor_printf(mon, "user mode network stack not in use\n");
      return NULL;
    }
    return QTAILQ_FIRST(&slirp_stacks);
  }
}

