static void ultag_close(ULanguageTag *langtag) {
  if (langtag == NULL) {
    return;
  }
  uprv_free(langtag->buf);
  if (langtag->variants) {
    VariantListEntry *curVar = langtag->variants;
    while (curVar) {
      VariantListEntry *nextVar = curVar->next;
      uprv_free(curVar);
      curVar = nextVar;
    }
  }
  if (langtag->extensions) {
    ExtensionListEntry *curExt = langtag->extensions;
    while (curExt) {
      ExtensionListEntry *nextExt = curExt->next;
      uprv_free(curExt);
      curExt = nextExt;
    }
  }
  uprv_free(langtag);
}

void parseVariant(proto_tree *tree, tvbuff_t *tvb, packet_info *pinfo,
                  gint *pOffset, const char *szFieldName) {
  proto_item *ti;
  proto_tree *subtree =
      proto_tree_add_subtree_format(tree, tvb, *pOffset, -1, ett_opcua_variant,
                                    &ti, "%s: Variant", szFieldName);
  gint iOffset = *pOffset;
  guint8 EncodingMask;
  gint32 ArrayDimensions = 0;
  EncodingMask = tvb_get_guint8(tvb, iOffset);
  proto_tree_add_item(subtree, hf_opcua_variant_encodingmask, tvb, iOffset, 1,
                      ENC_LITTLE_ENDIAN);
  iOffset++;
  if (EncodingMask & VARIANT_ARRAYMASK) {
    switch (EncodingMask & 0x3f) {
    case OpcUaType_Null:
      break;
    case OpcUaType_Boolean:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Boolean", "Boolean",
                       hf_opcua_Boolean, parseBoolean, ett_opcua_array_Boolean);
      break;
    case OpcUaType_SByte:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "SByte", "SByte",
                       hf_opcua_SByte, parseSByte, ett_opcua_array_SByte);
      break;
    case OpcUaType_Byte:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Byte", "Byte",
                       hf_opcua_Byte, parseByte, ett_opcua_array_Byte);
      break;
    case OpcUaType_Int16:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Int16", "Int16",
                       hf_opcua_Int16, parseInt16, ett_opcua_array_Int16);
      break;
    case OpcUaType_UInt16:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "UInt16", "UInt16",
                       hf_opcua_UInt16, parseUInt16, ett_opcua_array_UInt16);
      break;
    case OpcUaType_Int32:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Int32", "Int32",
                       hf_opcua_Int32, parseInt32, ett_opcua_array_Int32);
      break;
    case OpcUaType_UInt32:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "UInt32", "UInt32",
                       hf_opcua_UInt32, parseUInt32, ett_opcua_array_UInt32);
      break;
    case OpcUaType_Int64:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Int64", "Int64",
                       hf_opcua_Int64, parseInt64, ett_opcua_array_Int64);
      break;
    case OpcUaType_UInt64:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "UInt64", "UInt64",
                       hf_opcua_UInt64, parseUInt64, ett_opcua_array_UInt64);
      break;
    case OpcUaType_Float:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Float", "Float",
                       hf_opcua_Float, parseFloat, ett_opcua_array_Float);
      break;
    case OpcUaType_Double:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Double", "Double",
                       hf_opcua_Double, parseDouble, ett_opcua_array_Double);
      break;
    case OpcUaType_String:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "String", "String",
                       hf_opcua_String, parseString, ett_opcua_array_String);
      break;
    case OpcUaType_DateTime:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "DateTime", "DateTime",
                       hf_opcua_DateTime, parseDateTime,
                       ett_opcua_array_DateTime);
      break;
    case OpcUaType_Guid:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "Guid", "Guid",
                       hf_opcua_Guid, parseGuid, ett_opcua_array_Guid);
      break;
    case OpcUaType_ByteString:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "ByteString",
                       "ByteString", hf_opcua_ByteString, parseByteString,
                       ett_opcua_array_ByteString);
      break;
    case OpcUaType_XmlElement:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "XmlElement",
                       "XmlElement", hf_opcua_XmlElement, parseXmlElement,
                       ett_opcua_array_XmlElement);
      break;
    case OpcUaType_NodeId:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "NodeId", "NodeId",
                        parseNodeId, ett_opcua_array_NodeId);
      break;
    case OpcUaType_ExpandedNodeId:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "ExpandedNodeId",
                        "ExpandedNodeId", parseExpandedNodeId,
                        ett_opcua_array_ExpandedNodeId);
      break;
    case OpcUaType_StatusCode:
      parseArraySimple(subtree, tvb, pinfo, &iOffset, "StatusCode",
                       "StatusCode", hf_opcua_StatusCode, parseStatusCode,
                       ett_opcua_array_StatusCode);
      break;
    case OpcUaType_DiagnosticInfo:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "DiagnosticInfo",
                        "DiagnosticInfo", parseDiagnosticInfo,
                        ett_opcua_array_DiagnosticInfo);
      break;
    case OpcUaType_QualifiedName:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "QualifiedName",
                        "QualifiedName", parseQualifiedName,
                        ett_opcua_array_QualifiedName);
      break;
    case OpcUaType_LocalizedText:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "LocalizedText",
                        "LocalizedText", parseLocalizedText,
                        ett_opcua_array_LocalizedText);
      break;
    case OpcUaType_ExtensionObject:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "ExtensionObject",
                        "ExtensionObject", parseExtensionObject,
                        ett_opcua_array_ExtensionObject);
      break;
    case OpcUaType_DataValue:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "DataValue", "DataValue",
                        parseDataValue, ett_opcua_array_DataValue);
      break;
    case OpcUaType_Variant:
      parseArrayComplex(subtree, tvb, pinfo, &iOffset, "Variant", "Variant",
                        parseVariant, ett_opcua_array_Variant);
      break;
    }
    if (EncodingMask & VARIANT_ARRAYDIMENSIONS) {
      proto_item *ti_2;
      proto_tree *subtree_2 = proto_tree_add_subtree(
          subtree, tvb, iOffset, -1, ett_opcua_variant_arraydims, &ti_2,
          "ArrayDimensions");
      int i;
      ArrayDimensions = tvb_get_letohl(tvb, iOffset);
      proto_tree_add_item(subtree_2, hf_opcua_ArraySize, tvb, iOffset, 4,
                          ENC_LITTLE_ENDIAN);
      if (ArrayDimensions > MAX_ARRAY_LEN) {
        proto_tree_add_expert_format(
            subtree_2, pinfo, &ei_array_length, tvb, iOffset, 4,
            "ArrayDimensions length %d too large to process", ArrayDimensions);
        return;
      }
      iOffset += 4;
      for (i = 0; i < ArrayDimensions; i++) {
        parseInt32(subtree_2, tvb, pinfo, &iOffset, hf_opcua_Int32);
      }
      proto_item_set_end(ti_2, tvb, iOffset);
    }
  } else {
    switch (EncodingMask & 0x3f) {
    case OpcUaType_Null:
      break;
    case OpcUaType_Boolean:
      parseBoolean(subtree, tvb, pinfo, &iOffset, hf_opcua_Boolean);
      break;
    case OpcUaType_SByte:
      parseSByte(subtree, tvb, pinfo, &iOffset, hf_opcua_SByte);
      break;
    case OpcUaType_Byte:
      parseByte(subtree, tvb, pinfo, &iOffset, hf_opcua_Byte);
      break;
    case OpcUaType_Int16:
      parseInt16(subtree, tvb, pinfo, &iOffset, hf_opcua_Int16);
      break;
    case OpcUaType_UInt16:
      parseUInt16(subtree, tvb, pinfo, &iOffset, hf_opcua_UInt16);
      break;
    case OpcUaType_Int32:
      parseInt32(subtree, tvb, pinfo, &iOffset, hf_opcua_Int32);
      break;
    case OpcUaType_UInt32:
      parseUInt32(subtree, tvb, pinfo, &iOffset, hf_opcua_UInt32);
      break;
    case OpcUaType_Int64:
      parseInt64(subtree, tvb, pinfo, &iOffset, hf_opcua_Int64);
      break;
    case OpcUaType_UInt64:
      parseUInt64(subtree, tvb, pinfo, &iOffset, hf_opcua_UInt64);
      break;
    case OpcUaType_Float:
      parseFloat(subtree, tvb, pinfo, &iOffset, hf_opcua_Float);
      break;
    case OpcUaType_Double:
      parseDouble(subtree, tvb, pinfo, &iOffset, hf_opcua_Double);
      break;
    case OpcUaType_String:
      parseString(subtree, tvb, pinfo, &iOffset, hf_opcua_String);
      break;
    case OpcUaType_DateTime:
      parseDateTime(subtree, tvb, pinfo, &iOffset, hf_opcua_DateTime);
      break;
    case OpcUaType_Guid:
      parseGuid(subtree, tvb, pinfo, &iOffset, hf_opcua_Guid);
      break;
    case OpcUaType_ByteString:
      parseByteString(subtree, tvb, pinfo, &iOffset, hf_opcua_ByteString);
      break;
    case OpcUaType_XmlElement:
      parseXmlElement(subtree, tvb, pinfo, &iOffset, hf_opcua_XmlElement);
      break;
    case OpcUaType_NodeId:
      parseNodeId(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_ExpandedNodeId:
      parseExpandedNodeId(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_StatusCode:
      parseStatusCode(subtree, tvb, pinfo, &iOffset, hf_opcua_StatusCode);
      break;
    case OpcUaType_DiagnosticInfo:
      parseDiagnosticInfo(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_QualifiedName:
      parseQualifiedName(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_LocalizedText:
      parseLocalizedText(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_ExtensionObject:
      parseExtensionObject(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_DataValue:
      parseDataValue(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    case OpcUaType_Variant:
      parseVariant(subtree, tvb, pinfo, &iOffset, "Value");
      break;
    }
  }
  proto_item_set_end(ti, tvb, iOffset);
  *pOffset = iOffset;
}

static int raw_decode(AVCodecContext *avctx, void *data, int *got_frame,
                      AVPacket *avpkt) {
  const AVPixFmtDescriptor *desc = av_pix_fmt_desc_get(avctx->pix_fmt);
  RawVideoContext *context = avctx->priv_data;
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  int res;
  AVFrame *frame = data;
  AVPicture *picture = data;
  frame->pict_type = avctx->coded_frame->pict_type;
  frame->interlaced_frame = avctx->coded_frame->interlaced_frame;
  frame->top_field_first = avctx->coded_frame->top_field_first;
  frame->reordered_opaque = avctx->reordered_opaque;
  frame->pkt_pts = avctx->pkt->pts;
  if (buf_size < context->length -
                     (avctx->pix_fmt == AV_PIX_FMT_PAL8 ? AVPALETTE_SIZE : 0))
    return -1;
  if (context->buffer) {
    int i;
    uint8_t *dst = context->buffer;
    buf_size = context->length - AVPALETTE_SIZE;
    if (avctx->bits_per_coded_sample == 4) {
      for (i = 0; 2 * i + 1 < buf_size; i++) {
        dst[2 * i + 0] = buf[i] >> 4;
        dst[2 * i + 1] = buf[i] & 15;
      }
    } else {
      for (i = 0; 4 * i + 3 < buf_size; i++) {
        dst[4 * i + 0] = buf[i] >> 6;
        dst[4 * i + 1] = buf[i] >> 4 & 3;
        dst[4 * i + 2] = buf[i] >> 2 & 3;
        dst[4 * i + 3] = buf[i] & 3;
      }
    }
    buf = dst;
  }
  if (avctx->codec_tag == MKTAG('A', 'V', '1', 'x') ||
      avctx->codec_tag == MKTAG('A', 'V', 'u', 'p'))
    buf += buf_size - context->length;
  if ((res = avpicture_fill(picture, buf, avctx->pix_fmt, avctx->width,
                            avctx->height)) < 0)
    return res;
  if ((avctx->pix_fmt == AV_PIX_FMT_PAL8 && buf_size < context->length) ||
      (desc->flags & PIX_FMT_PSEUDOPAL)) {
    frame->data[1] = context->palette;
  }
  if (avctx->pix_fmt == AV_PIX_FMT_PAL8) {
    const uint8_t *pal =
        av_packet_get_side_data(avpkt, AV_PKT_DATA_PALETTE, NULL);
    if (pal) {
      memcpy(frame->data[1], pal, AVPALETTE_SIZE);
      frame->palette_has_changed = 1;
    }
  }
  if (avctx->pix_fmt == AV_PIX_FMT_BGR24 &&
      ((frame->linesize[0] + 3) & ~3) * avctx->height <= buf_size)
    frame->linesize[0] = (frame->linesize[0] + 3) & ~3;
  if (context->flip)
    flip(avctx, picture);
  if (avctx->codec_tag == MKTAG('Y', 'V', '1', '2') ||
      avctx->codec_tag == MKTAG('Y', 'V', '1', '6') ||
      avctx->codec_tag == MKTAG('Y', 'V', '2', '4') ||
      avctx->codec_tag == MKTAG('Y', 'V', 'U', '9'))
    FFSWAP(uint8_t *, picture->data[1], picture->data[2]);
  if (avctx->codec_tag == AV_RL32("yuv2") &&
      avctx->pix_fmt == AV_PIX_FMT_YUYV422) {
    int x, y;
    uint8_t *line = picture->data[0];
    for (y = 0; y < avctx->height; y++) {
      for (x = 0; x < avctx->width; x++)
        line[2 * x + 1] ^= 0x80;
      line += picture->linesize[0];
    }
  }
  *got_frame = 1;
  return buf_size;
}

static int parse_audio_var(AVFormatContext *avctx, AVStream *st,
                           const char *name, int size) {
  MvContext *mv = avctx->priv_data;
  AVIOContext *pb = avctx->pb;
  if (!strcmp(name, "__DIR_COUNT")) {
    st->nb_frames = var_read_int(pb, size);
  } else if (!strcmp(name, "AUDIO_FORMAT")) {
    mv->aformat = var_read_int(pb, size);
  } else if (!strcmp(name, "COMPRESSION")) {
    mv->acompression = var_read_int(pb, size);
  } else if (!strcmp(name, "DEFAULT_VOL")) {
    var_read_metadata(avctx, name, size);
  } else if (!strcmp(name, "NUM_CHANNELS")) {
    return set_channels(avctx, st, var_read_int(pb, size));
  } else if (!strcmp(name, "SAMPLE_RATE")) {
    st->codecpar->sample_rate = var_read_int(pb, size);
    avpriv_set_pts_info(st, 33, 1, st->codecpar->sample_rate);
  } else if (!strcmp(name, "SAMPLE_WIDTH")) {
    st->codecpar->bits_per_coded_sample = var_read_int(pb, size) * 8;
  } else
    return AVERROR_INVALIDDATA;
  return 0;
}

static void U_CALLCONV T_UConverter_toUnicode_UTF32_BE_OFFSET_LOGIC(
    UConverterToUnicodeArgs *args, UErrorCode *err) {
  const unsigned char *mySource = (unsigned char *)args->source;
  UChar *myTarget = args->target;
  int32_t *myOffsets = args->offsets;
  const unsigned char *sourceLimit = (unsigned char *)args->sourceLimit;
  const UChar *targetLimit = args->targetLimit;
  unsigned char *toUBytes = args->converter->toUBytes;
  uint32_t ch, i;
  int32_t offsetNum = 0;
  if (args->converter->toUnicodeStatus && myTarget < targetLimit) {
    i = args->converter->toULength;
    args->converter->toULength = 0;
    ch = args->converter->toUnicodeStatus - 1;
    args->converter->toUnicodeStatus = 0;
    goto morebytes;
  }
  while (mySource < sourceLimit && myTarget < targetLimit) {
    i = 0;
    ch = 0;
  morebytes:
    while (i < sizeof(uint32_t)) {
      if (mySource < sourceLimit) {
        ch = (ch << 8) | (uint8_t)(*mySource);
        toUBytes[i++] = (char)*(mySource++);
      } else {
        args->converter->toUnicodeStatus = ch + 1;
        args->converter->toULength = (int8_t)i;
        goto donefornow;
      }
    }
    if (ch <= MAXIMUM_UTF && !U_IS_SURROGATE(ch)) {
      if (ch <= MAXIMUM_UCS2) {
        *(myTarget++) = (UChar)ch;
        *(myOffsets++) = offsetNum;
      } else {
        *(myTarget++) = U16_LEAD(ch);
        *myOffsets++ = offsetNum;
        ch = U16_TRAIL(ch);
        if (myTarget < targetLimit) {
          *(myTarget++) = (UChar)ch;
          *(myOffsets++) = offsetNum;
        } else {
          args->converter->UCharErrorBuffer[0] = (UChar)ch;
          args->converter->UCharErrorBufferLength = 1;
          *err = U_BUFFER_OVERFLOW_ERROR;
          break;
        }
      }
    } else {
      args->converter->toULength = (int8_t)i;
      *err = U_ILLEGAL_CHAR_FOUND;
      break;
    }
    offsetNum += i;
  }
donefornow:
  if (mySource < sourceLimit && myTarget >= targetLimit && U_SUCCESS(*err)) {
    *err = U_BUFFER_OVERFLOW_ERROR;
  }
  args->target = myTarget;
  args->source = (const char *)mySource;
  args->offsets = myOffsets;
}

