static int astream_read_next(struct attachment_istream *astream,
                             bool *retry_r) {
  struct istream_private *stream = &astream->istream;
  struct message_block block;
  size_t old_size, new_size;
  const char *error;
  int ret;
  *retry_r = FALSE;
  if (stream->pos - stream->skip >=
      i_stream_get_max_buffer_size(&stream->istream))
    return -2;
  old_size = stream->pos - stream->skip;
  switch (message_parser_parse_next_block(astream->parser, &block)) {
  case -1:
    ret = astream_end_of_part(astream, &error);
    if (ret > 0) {
      new_size = stream->pos - stream->skip;
      return new_size - old_size;
    }
    stream->istream.eof = TRUE;
    stream->istream.stream_errno = stream->parent->stream_errno;
    if (ret < 0) {
      io_stream_set_error(&stream->iostream, "%s", error);
      stream->istream.stream_errno = EIO;
    }
    astream->cur_part = NULL;
    return -1;
  case 0:
    return 0;
  default:
    break;
  }
  if (block.part != astream->cur_part && astream->cur_part != NULL) {
    if (astream_end_of_part(astream, &error) < 0) {
      io_stream_set_error(&stream->iostream, "%s", error);
      stream->istream.stream_errno = EIO;
      return -1;
    }
  }
  astream->cur_part = block.part;
  if (block.hdr != NULL) {
    astream_parse_header(astream, block.hdr);
  } else if (block.size == 0) {
    if (astream_want_attachment(astream, block.part)) {
      astream->part.state = MAIL_ATTACHMENT_STATE_MAYBE;
      astream->part.start_offset = stream->parent->v_offset;
    }
  } else {
    astream_add_body(astream, &block);
  }
  new_size = stream->pos - stream->skip;
  *retry_r = new_size == old_size;
  return new_size - old_size;
}

void vp9_init_layer_context(VP9_COMP *const cpi) {
  SVC *const svc = &cpi->svc;
  const VP9EncoderConfig *const oxcf = &cpi->oxcf;
  int layer;
  int layer_end;
  int alt_ref_idx = svc->number_spatial_layers;
  svc->spatial_layer_id = 0;
  svc->temporal_layer_id = 0;
  if (svc->number_temporal_layers > 1 && cpi->oxcf.rc_mode == VPX_CBR) {
    layer_end = svc->number_temporal_layers;
  } else {
    layer_end = svc->number_spatial_layers;
  }
  for (layer = 0; layer < layer_end; ++layer) {
    LAYER_CONTEXT *const lc = &svc->layer_context[layer];
    RATE_CONTROL *const lrc = &lc->rc;
    int i;
    lc->current_video_frame_in_layer = 0;
    lc->layer_size = 0;
    lc->frames_from_key_frame = 0;
    lc->last_frame_type = FRAME_TYPES;
    lrc->ni_av_qi = oxcf->worst_allowed_q;
    lrc->total_actual_bits = 0;
    lrc->total_target_vs_actual = 0;
    lrc->ni_tot_qi = 0;
    lrc->tot_q = 0.0;
    lrc->avg_q = 0.0;
    lrc->ni_frames = 0;
    lrc->decimation_count = 0;
    lrc->decimation_factor = 0;
    for (i = 0; i < RATE_FACTOR_LEVELS; ++i) {
      lrc->rate_correction_factors[i] = 1.0;
    }
    if (svc->number_temporal_layers > 1 && cpi->oxcf.rc_mode == VPX_CBR) {
      lc->target_bandwidth = oxcf->ts_target_bitrate[layer];
      lrc->last_q[INTER_FRAME] = oxcf->worst_allowed_q;
      lrc->avg_frame_qindex[INTER_FRAME] = oxcf->worst_allowed_q;
    } else {
      lc->target_bandwidth = oxcf->ss_target_bitrate[layer];
      lrc->last_q[KEY_FRAME] = oxcf->best_allowed_q;
      lrc->last_q[INTER_FRAME] = oxcf->best_allowed_q;
      lrc->avg_frame_qindex[KEY_FRAME] =
          (oxcf->worst_allowed_q + oxcf->best_allowed_q) / 2;
      lrc->avg_frame_qindex[INTER_FRAME] =
          (oxcf->worst_allowed_q + oxcf->best_allowed_q) / 2;
      if (oxcf->ss_play_alternate[layer])
        lc->alt_ref_idx = alt_ref_idx++;
      else
        lc->alt_ref_idx = -1;
      lc->gold_ref_idx = -1;
    }
    lrc->buffer_level =
        oxcf->starting_buffer_level_ms * lc->target_bandwidth / 1000;
    lrc->bits_off_target = lrc->buffer_level;
  }
  if (!(svc->number_temporal_layers > 1 && cpi->oxcf.rc_mode == VPX_CBR) &&
      alt_ref_idx < REF_FRAMES)
    svc->layer_context[0].gold_ref_idx = alt_ref_idx;
}

static void imlt_gain(COOKContext *q, float *inbuffer, cook_gains *gains_ptr,
                      float *previous_buffer) {
  float *buffer0 = q->mono_mdct_output;
  float *buffer1 = q->mono_mdct_output + q->samples_per_channel;
  int i;
  q->mdct_ctx.imdct_calc(&q->mdct_ctx, q->mono_mdct_output, inbuffer);
  q->imlt_window(q, buffer1, gains_ptr, previous_buffer);
  for (i = 0; i < 8; i++)
    if (gains_ptr->now[i] || gains_ptr->now[i + 1])
      q->interpolate(q, &buffer1[q->gain_size_factor * i], gains_ptr->now[i],
                     gains_ptr->now[i + 1]);
  memcpy(previous_buffer, buffer0,
         q->samples_per_channel * sizeof(*previous_buffer));
}

