static int dump_sp(struct xfrm_policy *xp, int dir, int count, void *ptr) {
  struct pfkey_sock *pfk = ptr;
  struct sk_buff *out_skb;
  struct sadb_msg *out_hdr;
  int err;
  if (!pfkey_can_dump(&pfk->sk))
    return -ENOBUFS;
  out_skb = pfkey_xfrm_policy2msg_prep(xp);
  if (IS_ERR(out_skb))
    return PTR_ERR(out_skb);
  err = pfkey_xfrm_policy2msg(out_skb, xp, dir);
  if (err < 0)
    return err;
  out_hdr = (struct sadb_msg *)out_skb->data;
  out_hdr->sadb_msg_version = pfk->dump.msg_version;
  out_hdr->sadb_msg_type = SADB_X_SPDDUMP;
  out_hdr->sadb_msg_satype = SADB_SATYPE_UNSPEC;
  out_hdr->sadb_msg_errno = 0;
  out_hdr->sadb_msg_seq = count + 1;
  out_hdr->sadb_msg_pid = pfk->dump.msg_portid;
  if (pfk->dump.skb)
    pfkey_broadcast(pfk->dump.skb, GFP_ATOMIC, BROADCAST_ONE, &pfk->sk,
                    sock_net(&pfk->sk));
  pfk->dump.skb = out_skb;
  return 0;
}

static char *var_read_string(AVIOContext *pb, int size) {
  int n;
  char *str;
  if (size < 0 || size == INT_MAX)
    return NULL;
  str = av_malloc(size + 1);
  if (!str)
    return NULL;
  n = avio_get_str(pb, size, str, size + 1);
  if (n < size)
    avio_skip(pb, size - n);
  return str;
}

static void read_sbr_envelope(SpectralBandReplication *sbr, GetBitContext *gb,
                              SBRData *ch_data, int ch) {
  int bits;
  int i, j, k;
  VLC_TYPE(*t_huff)[2], (*f_huff)[2];
  int t_lav, f_lav;
  const int delta = (ch == 1 && sbr->bs_coupling == 1) + 1;
  const int odd = sbr->n[1] & 1;
  if (sbr->bs_coupling && ch) {
    if (ch_data->bs_amp_res) {
      bits = 5;
      t_huff = vlc_sbr[T_HUFFMAN_ENV_BAL_3_0DB].table;
      t_lav = vlc_sbr_lav[T_HUFFMAN_ENV_BAL_3_0DB];
      f_huff = vlc_sbr[F_HUFFMAN_ENV_BAL_3_0DB].table;
      f_lav = vlc_sbr_lav[F_HUFFMAN_ENV_BAL_3_0DB];
    } else {
      bits = 6;
      t_huff = vlc_sbr[T_HUFFMAN_ENV_BAL_1_5DB].table;
      t_lav = vlc_sbr_lav[T_HUFFMAN_ENV_BAL_1_5DB];
      f_huff = vlc_sbr[F_HUFFMAN_ENV_BAL_1_5DB].table;
      f_lav = vlc_sbr_lav[F_HUFFMAN_ENV_BAL_1_5DB];
    }
  } else {
    if (ch_data->bs_amp_res) {
      bits = 6;
      t_huff = vlc_sbr[T_HUFFMAN_ENV_3_0DB].table;
      t_lav = vlc_sbr_lav[T_HUFFMAN_ENV_3_0DB];
      f_huff = vlc_sbr[F_HUFFMAN_ENV_3_0DB].table;
      f_lav = vlc_sbr_lav[F_HUFFMAN_ENV_3_0DB];
    } else {
      bits = 7;
      t_huff = vlc_sbr[T_HUFFMAN_ENV_1_5DB].table;
      t_lav = vlc_sbr_lav[T_HUFFMAN_ENV_1_5DB];
      f_huff = vlc_sbr[F_HUFFMAN_ENV_1_5DB].table;
      f_lav = vlc_sbr_lav[F_HUFFMAN_ENV_1_5DB];
    }
  }
  for (i = 0; i < ch_data->bs_num_env; i++) {
    if (ch_data->bs_df_env[i]) {
      if (ch_data->bs_freq_res[i + 1] == ch_data->bs_freq_res[i]) {
        for (j = 0; j < sbr->n[ch_data->bs_freq_res[i + 1]]; j++)
          ch_data->env_facs[i + 1][j] =
              ch_data->env_facs[i][j] +
              delta * (get_vlc2(gb, t_huff, 9, 3) - t_lav);
      } else if (ch_data->bs_freq_res[i + 1]) {
        for (j = 0; j < sbr->n[ch_data->bs_freq_res[i + 1]]; j++) {
          k = (j + odd) >> 1;
          ch_data->env_facs[i + 1][j] =
              ch_data->env_facs[i][k] +
              delta * (get_vlc2(gb, t_huff, 9, 3) - t_lav);
        }
      } else {
        for (j = 0; j < sbr->n[ch_data->bs_freq_res[i + 1]]; j++) {
          k = j ? 2 * j - odd : 0;
          ch_data->env_facs[i + 1][j] =
              ch_data->env_facs[i][k] +
              delta * (get_vlc2(gb, t_huff, 9, 3) - t_lav);
        }
      }
    } else {
      ch_data->env_facs[i + 1][0] = delta * get_bits(gb, bits);
      for (j = 1; j < sbr->n[ch_data->bs_freq_res[i + 1]]; j++)
        ch_data->env_facs[i + 1][j] =
            ch_data->env_facs[i + 1][j - 1] +
            delta * (get_vlc2(gb, f_huff, 9, 3) - f_lav);
    }
  }
  memcpy(ch_data->env_facs[0], ch_data->env_facs[ch_data->bs_num_env],
         sizeof(ch_data->env_facs[0]));
}

static bool lxc_cgroupfs_attach(const char *name, const char *lxcpath,
                                pid_t pid) {
  struct cgroup_meta_data *meta_data;
  struct cgroup_process_info *container_info;
  int ret;
  meta_data = lxc_cgroup_load_meta();
  if (!meta_data) {
    ERROR("could not move attached process %d to cgroup of container", pid);
    return false;
  }
  container_info = lxc_cgroup_get_container_info(name, lxcpath, meta_data);
  lxc_cgroup_put_meta(meta_data);
  if (!container_info) {
    ERROR("could not move attached process %d to cgroup of container", pid);
    return false;
  }
  ret = lxc_cgroupfs_enter(container_info, pid, false);
  lxc_cgroup_process_info_free(container_info);
  if (ret < 0) {
    ERROR("could not move attached process %d to cgroup of container", pid);
    return false;
  }
  return true;
}

