static gcry_err_code_t sexp_to_key(gcry_sexp_t sexp, int want_private, int use,
                                   const char *override_elems,
                                   gcry_mpi_t **retarray,
                                   gcry_module_t *retalgo, int *r_is_ecc) {
  gcry_err_code_t err = 0;
  gcry_sexp_t list, l2;
  char *name;
  const char *elems;
  gcry_mpi_t *array;
  gcry_module_t module;
  gcry_pk_spec_t *pubkey;
  pk_extra_spec_t *extraspec;
  int is_ecc;
  list = gcry_sexp_find_token(sexp, want_private ? "private-key" : "public-key",
                              0);
  if (!list && !want_private)
    list = gcry_sexp_find_token(sexp, "private-key", 0);
  if (!list)
    return GPG_ERR_INV_OBJ;
  l2 = gcry_sexp_cadr(list);
  gcry_sexp_release(list);
  list = l2;
  name = _gcry_sexp_nth_string(list, 0);
  if (!name) {
    gcry_sexp_release(list);
    return GPG_ERR_INV_OBJ;
  }
  if (!strcmp(name, "ecc"))
    is_ecc = 2;
  else if (!strcmp(name, "ecdsa") || !strcmp(name, "ecdh"))
    is_ecc = 1;
  else
    is_ecc = 0;
  ath_mutex_lock(&pubkeys_registered_lock);
  if (is_ecc == 2 && (use & GCRY_PK_USAGE_SIGN))
    module = gcry_pk_lookup_name("ecdsa");
  else if (is_ecc == 2 && (use & GCRY_PK_USAGE_ENCR))
    module = gcry_pk_lookup_name("ecdh");
  else
    module = gcry_pk_lookup_name(name);
  ath_mutex_unlock(&pubkeys_registered_lock);
  gcry_free(name);
  if (!module) {
    gcry_sexp_release(list);
    return GPG_ERR_PUBKEY_ALGO;
  } else {
    pubkey = (gcry_pk_spec_t *)module->spec;
    extraspec = module->extraspec;
  }
  if (override_elems)
    elems = override_elems;
  else if (want_private)
    elems = pubkey->elements_skey;
  else
    elems = pubkey->elements_pkey;
  array = gcry_calloc(strlen(elems) + 1, sizeof(*array));
  if (!array)
    err = gpg_err_code_from_syserror();
  if (!err) {
    if (is_ecc)
      err = sexp_elements_extract_ecc(list, elems, array, extraspec,
                                      want_private);
    else
      err = sexp_elements_extract(list, elems, array, pubkey->name);
  }
  gcry_sexp_release(list);
  if (err) {
    gcry_free(array);
    ath_mutex_lock(&pubkeys_registered_lock);
    _gcry_module_release(module);
    ath_mutex_unlock(&pubkeys_registered_lock);
  } else {
    *retarray = array;
    *retalgo = module;
    if (r_is_ecc)
      *r_is_ecc = is_ecc;
  }
  return err;
}

static int collector_decode_htmlnumericentity(int c, void *data) {
  struct collector_htmlnumericentity_data *pc =
      (struct collector_htmlnumericentity_data *)data;
  int f, n, s, r, d, size, *mapelm;
  switch (pc->status) {
  case 1:
    if (c == 0x23) {
      pc->status = 2;
    } else {
      pc->status = 0;
      (*pc->decoder->filter_function)(0x26, pc->decoder);
      (*pc->decoder->filter_function)(c, pc->decoder);
    }
    break;
  case 2:
    if (c == 0x78) {
      pc->status = 4;
    } else if (c >= 0x30 && c <= 0x39) {
      pc->cache = c - 0x30;
      pc->status = 3;
      pc->digit = 1;
    } else {
      pc->status = 0;
      (*pc->decoder->filter_function)(0x26, pc->decoder);
      (*pc->decoder->filter_function)(0x23, pc->decoder);
      (*pc->decoder->filter_function)(c, pc->decoder);
    }
    break;
  case 3:
    s = 0;
    f = 0;
    if (c >= 0x30 && c <= 0x39) {
      if (pc->digit > 9) {
        pc->status = 0;
        s = pc->cache;
        f = 1;
      } else {
        s = pc->cache * 10 + c - 0x30;
        pc->cache = s;
        pc->digit++;
      }
    } else {
      pc->status = 0;
      s = pc->cache;
      f = 1;
      n = 0;
      size = pc->mapsize;
      while (n < size) {
        mapelm = &(pc->convmap[n * 4]);
        d = s - mapelm[2];
        if (d >= mapelm[0] && d <= mapelm[1]) {
          f = 0;
          (*pc->decoder->filter_function)(d, pc->decoder);
          if (c != 0x3b) {
            (*pc->decoder->filter_function)(c, pc->decoder);
          }
          break;
        }
        n++;
      }
    }
    if (f) {
      (*pc->decoder->filter_function)(0x26, pc->decoder);
      (*pc->decoder->filter_function)(0x23, pc->decoder);
      r = 1;
      n = pc->digit;
      while (n > 0) {
        r *= 10;
        n--;
      }
      s %= r;
      r /= 10;
      while (r > 0) {
        d = s / r;
        s %= r;
        r /= 10;
        (*pc->decoder->filter_function)(mbfl_hexchar_table[d], pc->decoder);
      }
      (*pc->decoder->filter_function)(c, pc->decoder);
    }
    break;
  case 4:
    if (c >= 0x30 && c <= 0x39) {
      pc->cache = c - 0x30;
      pc->status = 5;
      pc->digit = 1;
    } else if (c >= 0x41 && c <= 0x46) {
      pc->cache = c - 0x41 + 10;
      pc->status = 5;
      pc->digit = 1;
    } else if (c >= 0x61 && c <= 0x66) {
      pc->cache = c - 0x61 + 10;
      pc->status = 5;
      pc->digit = 1;
    } else {
      pc->status = 0;
      (*pc->decoder->filter_function)(0x26, pc->decoder);
      (*pc->decoder->filter_function)(0x23, pc->decoder);
      (*pc->decoder->filter_function)(0x78, pc->decoder);
      (*pc->decoder->filter_function)(c, pc->decoder);
    }
    break;
  case 5:
    s = 0;
    f = 0;
    if ((c >= 0x30 && c <= 0x39) || (c >= 0x41 && c <= 0x46) ||
        (c >= 0x61 && c <= 0x66)) {
      if (pc->digit > 9) {
        pc->status = 0;
        s = pc->cache;
        f = 1;
      } else {
        if (c >= 0x30 && c <= 0x39) {
          s = pc->cache * 16 + (c - 0x30);
        } else if (c >= 0x41 && c <= 0x46) {
          s = pc->cache * 16 + (c - 0x41 + 10);
        } else {
          s = pc->cache * 16 + (c - 0x61 + 10);
        }
        pc->cache = s;
        pc->digit++;
      }
    } else {
      pc->status = 0;
      s = pc->cache;
      f = 1;
      n = 0;
      size = pc->mapsize;
      while (n < size) {
        mapelm = &(pc->convmap[n * 4]);
        d = s - mapelm[2];
        if (d >= mapelm[0] && d <= mapelm[1]) {
          f = 0;
          (*pc->decoder->filter_function)(d, pc->decoder);
          if (c != 0x3b) {
            (*pc->decoder->filter_function)(c, pc->decoder);
          }
          break;
        }
        n++;
      }
    }
    if (f) {
      (*pc->decoder->filter_function)(0x26, pc->decoder);
      (*pc->decoder->filter_function)(0x23, pc->decoder);
      (*pc->decoder->filter_function)(0x78, pc->decoder);
      r = 1;
      n = pc->digit;
      while (n > 0) {
        r *= 16;
        n--;
      }
      s %= r;
      r /= 16;
      while (r > 0) {
        d = s / r;
        s %= r;
        r /= 16;
        (*pc->decoder->filter_function)(mbfl_hexchar_table[d], pc->decoder);
      }
      (*pc->decoder->filter_function)(c, pc->decoder);
    }
    break;
  default:
    if (c == 0x26) {
      pc->status = 1;
    } else {
      (*pc->decoder->filter_function)(c, pc->decoder);
    }
    break;
  }
  return c;
}

