static int matroska_read_seek(AVFormatContext *s, int stream_index,
                              int64_t timestamp, int flags) {
  MatroskaDemuxContext *matroska = s->priv_data;
  MatroskaTrack *tracks = matroska->tracks.elem;
  AVStream *st = s->streams[stream_index];
  int i, index, index_sub, index_min;
  if (matroska->cues_parsing_deferred) {
    matroska_parse_cues(matroska);
    matroska->cues_parsing_deferred = 0;
  }
  if (!st->nb_index_entries)
    return 0;
  timestamp = FFMAX(timestamp, st->index_entries[0].timestamp);
  if ((index = av_index_search_timestamp(st, timestamp, flags)) < 0) {
    avio_seek(s->pb, st->index_entries[st->nb_index_entries - 1].pos, SEEK_SET);
    matroska->current_id = 0;
    while ((index = av_index_search_timestamp(st, timestamp, flags)) < 0) {
      matroska_clear_queue(matroska);
      if (matroska_parse_cluster(matroska) < 0)
        break;
    }
  }
  matroska_clear_queue(matroska);
  if (index < 0)
    return 0;
  index_min = index;
  for (i = 0; i < matroska->tracks.nb_elem; i++) {
    tracks[i].audio.pkt_cnt = 0;
    tracks[i].audio.sub_packet_cnt = 0;
    tracks[i].audio.buf_timecode = AV_NOPTS_VALUE;
    tracks[i].end_timecode = 0;
    if (tracks[i].type == MATROSKA_TRACK_TYPE_SUBTITLE &&
        tracks[i].stream->discard != AVDISCARD_ALL) {
      index_sub = av_index_search_timestamp(tracks[i].stream,
                                            st->index_entries[index].timestamp,
                                            AVSEEK_FLAG_BACKWARD);
      if (index_sub >= 0 &&
          st->index_entries[index_sub].pos < st->index_entries[index_min].pos &&
          st->index_entries[index].timestamp -
                  st->index_entries[index_sub].timestamp <
              30000000000 / matroska->time_scale)
        index_min = index_sub;
    }
  }
  avio_seek(s->pb, st->index_entries[index_min].pos, SEEK_SET);
  matroska->current_id = 0;
  matroska->skip_to_keyframe = !(flags & AVSEEK_FLAG_ANY);
  matroska->skip_to_timecode = st->index_entries[index].timestamp;
  matroska->done = 0;
  ff_update_cur_dts(s, st, st->index_entries[index].timestamp);
  return 0;
}

static int push_execstack(i_ctx_t *i_ctx_p, os_ptr op1, bool include_marks,
                          op_proc_t cont) {
  uint size;
  uint depth;
  if (!r_is_array(op1))
    return_op_typecheck(op1);
  size = r_size(op1);
  depth = count_exec_stack(i_ctx_p, include_marks);
  if (depth > size)
    return_error(gs_error_rangecheck);
  check_write(*op1);
  {
    int code = ref_stack_store_check(&e_stack, op1, size, 0);
    if (code < 0)
      return code;
  }
  check_estack(1);
  r_set_size(op1, depth);
  push_op_estack(cont);
  return o_push_estack;
}

static void DecoderProcessAudio(decoder_t *p_dec, block_t *p_block,
                                bool b_flush) {
  decoder_owner_sys_t *p_owner = (decoder_owner_sys_t *)p_dec->p_owner;
  if (p_owner->p_packetizer) {
    block_t *p_packetized_block;
    decoder_t *p_packetizer = p_owner->p_packetizer;
    while ((p_packetized_block = p_packetizer->pf_packetize(
                p_packetizer, p_block ? &p_block : NULL))) {
      if (p_packetizer->fmt_out.i_extra && !p_dec->fmt_in.i_extra) {
        es_format_Clean(&p_dec->fmt_in);
        es_format_Copy(&p_dec->fmt_in, &p_packetizer->fmt_out);
      }
      while (p_packetized_block) {
        block_t *p_next = p_packetized_block->p_next;
        p_packetized_block->p_next = NULL;
        DecoderDecodeAudio(p_dec, p_packetized_block);
        p_packetized_block = p_next;
      }
    }
    if (b_flush) {
      block_t *p_null = DecoderBlockFlushNew();
      if (p_null)
        DecoderDecodeAudio(p_dec, p_null);
    }
  } else {
    DecoderDecodeAudio(p_dec, p_block);
  }
  if (b_flush && p_owner->p_aout)
    aout_DecFlush(p_owner->p_aout);
}

static void get_hfi_length(header_field_info *hfinfo, tvbuff_t *tvb,
                           const gint start, gint *length, gint *item_length) {
  gint length_remaining;
  DISSECTOR_ASSERT(tvb != NULL || *length == 0);
  if (*length == -1) {
    switch (hfinfo->type) {
    case FT_PROTOCOL:
    case FT_NONE:
    case FT_BYTES:
    case FT_STRING:
    case FT_STRINGZPAD:
      *length = tvb_captured_length(tvb)
                    ? tvb_ensure_captured_length_remaining(tvb, start)
                    : 0;
      DISSECTOR_ASSERT(*length >= 0);
      break;
    case FT_STRINGZ:
      break;
    default:
      THROW(ReportedBoundsError);
      DISSECTOR_ASSERT_NOT_REACHED();
    }
    *item_length = *length;
  } else {
    *item_length = *length;
    if (hfinfo->type == FT_PROTOCOL || hfinfo->type == FT_NONE) {
      if (tvb) {
        length_remaining = tvb_captured_length_remaining(tvb, start);
        if (*item_length < 0 ||
            (*item_length > 0 && (length_remaining < *item_length)))
          *item_length = length_remaining;
      }
    }
    if (*item_length < 0) {
      THROW(ReportedBoundsError);
    }
  }
}

static int prepare_search(KEYRING_HANDLE hd) {
  if (hd->current.error) {
    if (gpg_err_code(hd->current.error) == GPG_ERR_LEGACY_KEY)
      hd->current.error = 0;
    else
      return hd->current.error;
  }
  if (hd->current.kr && !hd->current.eof) {
    if (!hd->current.iobuf)
      return GPG_ERR_GENERAL;
    return 0;
  }
  if (!hd->current.kr && hd->current.eof)
    return -1;
  if (!hd->current.kr) {
    hd->current.kr = hd->resource;
    if (!hd->current.kr) {
      hd->current.eof = 1;
      return -1;
    }
    assert(!hd->current.iobuf);
  } else {
    iobuf_close(hd->current.iobuf);
    hd->current.iobuf = NULL;
    hd->current.kr = NULL;
    hd->current.eof = 1;
    return -1;
  }
  hd->current.eof = 0;
  hd->current.iobuf = iobuf_open(hd->current.kr->fname);
  if (!hd->current.iobuf) {
    hd->current.error = gpg_error_from_syserror();
    log_error(_("can't open '%s'\n"), hd->current.kr->fname);
    return hd->current.error;
  }
  return 0;
}

