  (void)bd;
  for (r = 0; r < bs; ++r) {
    for (c = 0; c < bs; ++c) {
      dst[c] =
          r & 1
              ? ROUND_POWER_OF_TWO(above[r / 2 + c] + above[r / 2 + c + 1] * 2 +
                                       above[r / 2 + c + 2],
