static int qdev_print_devinfo(DeviceInfo *info, char *dest, int len) {
  int pos = 0;
  int ret;
  ret = snprintf(dest + pos, len - pos, "name \"%s\", bus %s", info->name,
                 info->bus_info->name);
  pos += MIN(len - pos, ret);
  if (info->alias) {
    ret = snprintf(dest + pos, len - pos, ", alias \"%s\"", info->alias);
    pos += MIN(len - pos, ret);
  }
  if (info->desc) {
    ret = snprintf(dest + pos, len - pos, ", desc \"%s\"", info->desc);
    pos += MIN(len - pos, ret);
  }
  if (info->no_user) {
    ret = snprintf(dest + pos, len - pos, ", no-user");
    pos += MIN(len - pos, ret);
  }
  return pos;
}

CURLcode Curl_http_done(struct connectdata *conn, CURLcode status,
                        bool premature) {
  struct Curl_easy *data = conn->data;
  struct HTTP *http = data->req.protop;
  infof(data, "Curl_http_done: called premature == %d\n", premature);
  Curl_unencode_cleanup(conn);
#ifdef USE_SPNEGO if (data->state.proxyneg.state == GSS_AUTHSENT ||            \
                      data->state.negotiate.state == GSS_AUTHSENT) {
  if ((data->req.httpcode != 401) && (data->req.httpcode != 407) &&
      !data->set.connect_only)
    streamclose(conn, "Negotiate transfer completed");
  Curl_cleanup_negotiate(data);
}
#endif conn->seek_func = data->set.seek_func;
conn->seek_client = data->set.seek_client;
if (!http)
  return CURLE_OK;
if (http->send_buffer) {
  Curl_add_buffer_free(http->send_buffer);
  http->send_buffer = NULL;
}
Curl_http2_done(conn, premature);
if (HTTPREQ_POST_FORM == data->set.httpreq) {
  data->req.bytecount = http->readbytecount + http->writebytecount;
  Curl_formclean(&http->sendit);
  if (http->form.fp) {
    fclose(http->form.fp);
    http->form.fp = NULL;
  }
} else if (HTTPREQ_PUT == data->set.httpreq)
  data->req.bytecount = http->readbytecount + http->writebytecount;
if (status)
  return status;
if (!premature && !conn->bits.retry && !data->set.connect_only &&
    (http->readbytecount + data->req.headerbytecount -
     data->req.deductheadercount) <= 0) {
  failf(data, "Empty reply from server");
  return CURLE_GOT_NOTHING;
}
return CURLE_OK;
}

void append_result(DYNAMIC_STRING *ds, MYSQL_RES *res) {
  MYSQL_ROW row;
  uint num_fields = mysql_num_fields(res);
  MYSQL_FIELD *fields = mysql_fetch_fields(res);
  ulong *lengths;
  while ((row = mysql_fetch_row(res))) {
    uint i;
    lengths = mysql_fetch_lengths(res);
    for (i = 0; i < num_fields; i++)
      append_field(ds, i, &fields[i], row[i], lengths[i], !row[i]);
    if (!display_result_vertically)
      dynstr_append_mem(ds, "\n", 1);
  }
}

