static int fts_build_tokenized(struct fts_mail_build_context *ctx,
                               const unsigned char *data, size_t size,
                               bool last) {
  struct mail_user *user = ctx->update_ctx->backend->ns->user;
  const struct fts_language *lang;
  int ret;
  if (ctx->cur_user_lang != NULL) {
  } else if ((ret = fts_detect_language(ctx, data, size, last, &lang)) < 0) {
    return -1;
  } else if (ret == 0) {
    return 0;
  } else {
    fts_mail_build_ctx_set_lang(ctx, fts_user_language_find(user, lang));
    if (ctx->pending_input->used > 0) {
      if (fts_build_add_tokens_with_filter(ctx, ctx->pending_input->data,
                                           ctx->pending_input->used) < 0)
        return -1;
      buffer_set_used_size(ctx->pending_input, 0);
    }
  }
  if (fts_build_add_tokens_with_filter(ctx, data, size) < 0)
    return -1;
  if (last) {
    if (fts_build_add_tokens_with_filter(ctx, NULL, 0) < 0)
      return -1;
  }
  return 0;
}

const gx_device *gs_getdevice(int index) {
  const gx_device *const *list;
  int count = gs_lib_device_list(&list, NULL);
  if (index < 0 || index >= count)
    return 0;
  return list[index];
}

static int selinux_cred_alloc_blank(struct cred *cred, gfp_t gfp) {
  struct task_security_struct *tsec;
  tsec = kzalloc(sizeof(struct task_security_struct), gfp);
  if (!tsec)
    return -ENOMEM;
  cred->security = tsec;
  return 0;
}

static gboolean fat_str_replace(char *str, char replacement) {
  gboolean success;
  int i;
  success = FALSE;
  for (i = 0; str[i] != '\0'; i++) {
    if (strchr(FAT_FORBIDDEN_CHARACTERS, str[i]) || str[i] < 32) {
      success = TRUE;
      str[i] = replacement;
    }
  }
  return success;
}

int ttfcopyfile(FILE *ttf, FILE *other, int pos, const char *tab_name) {
  int ch;
  int ret = 1;
  if (ferror(ttf) || ferror(other)) {
    IError("Disk error of some nature. Perhaps no space on device?\nGenerated "
           "font will be unusable");
  } else if (pos != ftell(ttf)) {
    IError("File Offset wrong for ttf table (%s), %d expected %d", tab_name,
           ftell(ttf), pos);
  }
  rewind(other);
  while ((ch = getc(other)) != EOF)
    putc(ch, ttf);
  if (ferror(other))
    ret = 0;
  if (fclose(other))
    ret = 0;
  return (ret);
}

static int ext_index_add_object(struct object *object, const char *name) {
  struct eindex *eindex = &bitmap_git.ext_index;
  khiter_t hash_pos;
  int hash_ret;
  int bitmap_pos;
  hash_pos = kh_put_sha1_pos(eindex->positions, object->oid.hash, &hash_ret);
  if (hash_ret > 0) {
    if (eindex->count >= eindex->alloc) {
      eindex->alloc = (eindex->alloc + 16) * 3 / 2;
      REALLOC_ARRAY(eindex->objects, eindex->alloc);
      REALLOC_ARRAY(eindex->hashes, eindex->alloc);
    }
    bitmap_pos = eindex->count;
    eindex->objects[eindex->count] = object;
    eindex->hashes[eindex->count] = pack_name_hash(name);
    kh_value(eindex->positions, hash_pos) = bitmap_pos;
    eindex->count++;
  } else {
    bitmap_pos = kh_value(eindex->positions, hash_pos);
  }
  return bitmap_pos + bitmap_git.pack->num_objects;
}

