static int decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                        AVPacket *avpkt) {
  ASV1Context *const a = avctx->priv_data;
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  AVFrame *picture = data;
  AVFrame *const p = &a->picture;
  int mb_x, mb_y, ret;
  if (p->data[0])
    avctx->release_buffer(avctx, p);
  p->reference = 0;
  if ((ret = ff_get_buffer(avctx, p)) < 0) {
    av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");
    return ret;
  }
  p->pict_type = AV_PICTURE_TYPE_I;
  p->key_frame = 1;
  av_fast_padded_malloc(&a->bitstream_buffer, &a->bitstream_buffer_size,
                        buf_size);
  if (!a->bitstream_buffer)
    return AVERROR(ENOMEM);
  if (avctx->codec_id == AV_CODEC_ID_ASV1)
    a->dsp.bswap_buf((uint32_t *)a->bitstream_buffer, (const uint32_t *)buf,
                     buf_size / 4);
  else {
    int i;
    for (i = 0; i < buf_size; i++)
      a->bitstream_buffer[i] = ff_reverse[buf[i]];
  }
  init_get_bits(&a->gb, a->bitstream_buffer, buf_size * 8);
  for (mb_y = 0; mb_y < a->mb_height2; mb_y++) {
    for (mb_x = 0; mb_x < a->mb_width2; mb_x++) {
      if ((ret = decode_mb(a, a->block)) < 0)
        return ret;
      idct_put(a, mb_x, mb_y);
    }
  }
  if (a->mb_width2 != a->mb_width) {
    mb_x = a->mb_width2;
    for (mb_y = 0; mb_y < a->mb_height2; mb_y++) {
      if ((ret = decode_mb(a, a->block)) < 0)
        return ret;
      idct_put(a, mb_x, mb_y);
    }
  }
  if (a->mb_height2 != a->mb_height) {
    mb_y = a->mb_height2;
    for (mb_x = 0; mb_x < a->mb_width; mb_x++) {
      if ((ret = decode_mb(a, a->block)) < 0)
        return ret;
      idct_put(a, mb_x, mb_y);
    }
  }
  *picture = a->picture;
  *got_frame = 1;
  emms_c();
  return (get_bits_count(&a->gb) + 31) / 32 * 4;
}

static void fdct16(const int16_t in[16], int16_t out[16]) {
  int step1[8];
  int step2[8];
  int step3[8];
  int input[8];
  int temp1, temp2;
  input[0] = in[0] + in[15];
  input[1] = in[1] + in[14];
  input[2] = in[2] + in[13];
  input[3] = in[3] + in[12];
  input[4] = in[4] + in[11];
  input[5] = in[5] + in[10];
  input[6] = in[6] + in[9];
  input[7] = in[7] + in[8];
  step1[0] = in[7] - in[8];
  step1[1] = in[6] - in[9];
  step1[2] = in[5] - in[10];
  step1[3] = in[4] - in[11];
  step1[4] = in[3] - in[12];
  step1[5] = in[2] - in[13];
  step1[6] = in[1] - in[14];
  step1[7] = in[0] - in[15];
  {
    int s0, s1, s2, s3, s4, s5, s6, s7;
    int t0, t1, t2, t3;
    int x0, x1, x2, x3;
    s0 = input[0] + input[7];
    s1 = input[1] + input[6];
    s2 = input[2] + input[5];
    s3 = input[3] + input[4];
    s4 = input[3] - input[4];
    s5 = input[2] - input[5];
    s6 = input[1] - input[6];
    s7 = input[0] - input[7];
    x0 = s0 + s3;
    x1 = s1 + s2;
    x2 = s1 - s2;
    x3 = s0 - s3;
    t0 = (x0 + x1) * cospi_16_64;
    t1 = (x0 - x1) * cospi_16_64;
    t2 = x3 * cospi_8_64 + x2 * cospi_24_64;
    t3 = x3 * cospi_24_64 - x2 * cospi_8_64;
    out[0] = fdct_round_shift(t0);
    out[4] = fdct_round_shift(t2);
    out[8] = fdct_round_shift(t1);
    out[12] = fdct_round_shift(t3);
    t0 = (s6 - s5) * cospi_16_64;
    t1 = (s6 + s5) * cospi_16_64;
    t2 = fdct_round_shift(t0);
    t3 = fdct_round_shift(t1);
    x0 = s4 + t2;
    x1 = s4 - t2;
    x2 = s7 - t3;
    x3 = s7 + t3;
    t0 = x0 * cospi_28_64 + x3 * cospi_4_64;
    t1 = x1 * cospi_12_64 + x2 * cospi_20_64;
    t2 = x2 * cospi_12_64 + x1 * -cospi_20_64;
    t3 = x3 * cospi_28_64 + x0 * -cospi_4_64;
    out[2] = fdct_round_shift(t0);
    out[6] = fdct_round_shift(t2);
    out[10] = fdct_round_shift(t1);
    out[14] = fdct_round_shift(t3);
  }
  temp1 = (step1[5] - step1[2]) * cospi_16_64;
  temp2 = (step1[4] - step1[3]) * cospi_16_64;
  step2[2] = fdct_round_shift(temp1);
  step2[3] = fdct_round_shift(temp2);
  temp1 = (step1[4] + step1[3]) * cospi_16_64;
  temp2 = (step1[5] + step1[2]) * cospi_16_64;
  step2[4] = fdct_round_shift(temp1);
  step2[5] = fdct_round_shift(temp2);
  step3[0] = step1[0] + step2[3];
  step3[1] = step1[1] + step2[2];
  step3[2] = step1[1] - step2[2];
  step3[3] = step1[0] - step2[3];
  step3[4] = step1[7] - step2[4];
  step3[5] = step1[6] - step2[5];
  step3[6] = step1[6] + step2[5];
  step3[7] = step1[7] + step2[4];
  temp1 = step3[1] * -cospi_8_64 + step3[6] * cospi_24_64;
  temp2 = step3[2] * cospi_24_64 + step3[5] * cospi_8_64;
  step2[1] = fdct_round_shift(temp1);
  step2[2] = fdct_round_shift(temp2);
  temp1 = step3[2] * cospi_8_64 - step3[5] * cospi_24_64;
  temp2 = step3[1] * cospi_24_64 + step3[6] * cospi_8_64;
  step2[5] = fdct_round_shift(temp1);
  step2[6] = fdct_round_shift(temp2);
  step1[0] = step3[0] + step2[1];
  step1[1] = step3[0] - step2[1];
  step1[2] = step3[3] + step2[2];
  step1[3] = step3[3] - step2[2];
  step1[4] = step3[4] - step2[5];
  step1[5] = step3[4] + step2[5];
  step1[6] = step3[7] - step2[6];
  step1[7] = step3[7] + step2[6];
  temp1 = step1[0] * cospi_30_64 + step1[7] * cospi_2_64;
  temp2 = step1[1] * cospi_14_64 + step1[6] * cospi_18_64;
  out[1] = fdct_round_shift(temp1);
  out[9] = fdct_round_shift(temp2);
  temp1 = step1[2] * cospi_22_64 + step1[5] * cospi_10_64;
  temp2 = step1[3] * cospi_6_64 + step1[4] * cospi_26_64;
  out[5] = fdct_round_shift(temp1);
  out[13] = fdct_round_shift(temp2);
  temp1 = step1[3] * -cospi_26_64 + step1[4] * cospi_6_64;
  temp2 = step1[2] * -cospi_10_64 + step1[5] * cospi_22_64;
  out[3] = fdct_round_shift(temp1);
  out[11] = fdct_round_shift(temp2);
  temp1 = step1[1] * -cospi_18_64 + step1[6] * cospi_14_64;
  temp2 = step1[0] * -cospi_2_64 + step1[7] * cospi_30_64;
  out[7] = fdct_round_shift(temp1);
  out[15] = fdct_round_shift(temp2);
}

static guint32 dissect_minivideopacket(tvbuff_t *tvb, guint32 offset,
                                       guint16 scallno, packet_info *pinfo,
                                       proto_tree *iax2_tree,
                                       proto_tree *main_tree) {
  guint32 ts;
  iax_packet_data *iax_packet;
  gboolean rtp_marker;
  proto_item *item;
  ts = tvb_get_ntohs(tvb, offset);
  rtp_marker = ts & 0x8000 ? TRUE : FALSE;
  ts &= ~0x8000;
  iax_packet = iax2_get_packet_data_for_minipacket(pinfo, scallno, TRUE);
  if (iax2_tree) {
    if (iax_packet->call_data) {
      item = proto_tree_add_uint(iax2_tree, hf_iax2_callno, tvb, 0, 4,
                                 iax_packet->call_data->forward_circuit_ids[0]);
      PROTO_ITEM_SET_GENERATED(item);
    }
    proto_tree_add_item(iax2_tree, hf_iax2_minividts, tvb, offset, 2,
                        ENC_BIG_ENDIAN);
    iax2_add_ts_fields(pinfo, iax2_tree, iax_packet, (guint16)ts);
    proto_tree_add_item(iax2_tree, hf_iax2_minividmarker, tvb, offset, 2,
                        ENC_BIG_ENDIAN);
  } else {
    iax2_add_ts_fields(pinfo, iax2_tree, iax_packet, (guint16)ts);
  }
  offset += 2;
  col_add_fstr(pinfo->cinfo, COL_INFO,
               "Mini video packet, source call# %d, timestamp %ums%s", scallno,
               ts, rtp_marker ? ", Mark" : "");
  dissect_payload(tvb, offset, pinfo, iax2_tree, main_tree, ts, TRUE,
                  iax_packet);
  iax_packet->first_time = FALSE;
  return offset;
}

static void extrapolate_isf(float isf[LP_ORDER_16k]) {
  float diff_isf[LP_ORDER - 2], diff_mean;
  float corr_lag[3];
  float est, scale;
  int i, j, i_max_corr;
  isf[LP_ORDER_16k - 1] = isf[LP_ORDER - 1];
  for (i = 0; i < LP_ORDER - 2; i++)
    diff_isf[i] = isf[i + 1] - isf[i];
  diff_mean = 0.0;
  for (i = 2; i < LP_ORDER - 2; i++)
    diff_mean += diff_isf[i] * (1.0f / (LP_ORDER - 4));
  i_max_corr = 0;
  for (i = 0; i < 3; i++) {
    corr_lag[i] = auto_correlation(diff_isf, diff_mean, i + 2);
    if (corr_lag[i] > corr_lag[i_max_corr])
      i_max_corr = i;
  }
  i_max_corr++;
  for (i = LP_ORDER - 1; i < LP_ORDER_16k - 1; i++)
    isf[i] = isf[i - 1] + isf[i - 1 - i_max_corr] - isf[i - 2 - i_max_corr];
  est = 7965 + (isf[2] - isf[3] - isf[4]) / 6.0;
  scale = 0.5 * (FFMIN(est, 7600) - isf[LP_ORDER - 2]) /
          (isf[LP_ORDER_16k - 2] - isf[LP_ORDER - 2]);
  for (i = LP_ORDER - 1, j = 0; i < LP_ORDER_16k - 1; i++, j++)
    diff_isf[j] = scale * (isf[i] - isf[i - 1]);
  for (i = 1; i < LP_ORDER_16k - LP_ORDER; i++)
    if (diff_isf[i] + diff_isf[i - 1] < 5.0) {
      if (diff_isf[i] > diff_isf[i - 1]) {
        diff_isf[i - 1] = 5.0 - diff_isf[i];
      } else
        diff_isf[i] = 5.0 - diff_isf[i - 1];
    }
  for (i = LP_ORDER - 1, j = 0; i < LP_ORDER_16k - 1; i++, j++)
    isf[i] = isf[i - 1] + diff_isf[j] * (1.0f / (1 << 15));
  for (i = 0; i < LP_ORDER_16k - 1; i++)
    isf[i] *= 0.8;
}

