static void set_block_thresholds(const VP9_COMMON *cm, RD_OPT *rd) {
  int i, bsize, segment_id;
  for (segment_id = 0; segment_id < MAX_SEGMENTS; ++segment_id) {
    const int qindex =
        clamp(vp9_get_qindex(&cm->seg, segment_id, cm->base_qindex) +
                  cm->y_dc_delta_q,
              0, MAXQ);
    const int q = compute_rd_thresh_factor(qindex);
    for (bsize = 0; bsize < BLOCK_SIZES; ++bsize) {
      const int t = q * rd_thresh_block_size_factor[bsize];
      const int thresh_max = INT_MAX / t;
      if (bsize >= BLOCK_8X8) {
        for (i = 0; i < MAX_MODES; ++i)
          rd->threshes[segment_id][bsize][i] = rd->thresh_mult[i] < thresh_max
                                                   ? rd->thresh_mult[i] * t / 4
                                                   : INT_MAX;
      } else {
        for (i = 0; i < MAX_REFS; ++i)
          rd->threshes[segment_id][bsize][i] =
              rd->thresh_mult_sub8x8[i] < thresh_max
                  ? rd->thresh_mult_sub8x8[i] * t / 4
                  : INT_MAX;
      }
    }
  }
}

gboolean pk_transaction_set_tid(PkTransaction *transaction, const gchar *tid) {
  static const GDBusInterfaceVTable interface_vtable = {
      pk_transaction_method_call, pk_transaction_get_property, NULL};
  g_return_val_if_fail(PK_IS_TRANSACTION(transaction), FALSE);
  g_return_val_if_fail(tid != NULL, FALSE);
  g_return_val_if_fail(transaction->priv->tid == NULL, FALSE);
  transaction->priv->tid = g_strdup(tid);
  transaction->priv->connection = g_bus_get_sync(G_BUS_TYPE_SYSTEM, NULL, NULL);
  g_assert(transaction->priv->connection != NULL);
  transaction->priv->registration_id = g_dbus_connection_register_object(
      transaction->priv->connection, tid,
      transaction->priv->introspection->interfaces[0], &interface_vtable,
      transaction, NULL, NULL);
  g_assert(transaction->priv->registration_id > 0);
  return TRUE;
}

int event_pending(struct event *ev, short event, struct timeval *tv) {
  struct timeval now, res;
  int flags = 0;
  if (ev->ev_flags & EVLIST_INSERTED)
    flags |= (ev->ev_events & (EV_READ | EV_WRITE | EV_SIGNAL));
  if (ev->ev_flags & EVLIST_ACTIVE)
    flags |= ev->ev_res;
  if (ev->ev_flags & EVLIST_TIMEOUT)
    flags |= EV_TIMEOUT;
  event &= (EV_TIMEOUT | EV_READ | EV_WRITE | EV_SIGNAL);
  if (tv != NULL && (flags & event & EV_TIMEOUT)) {
    gettime(ev->ev_base, &now);
    evutil_timersub(&ev->ev_timeout, &now, &res);
    evutil_gettimeofday(&now, NULL);
    evutil_timeradd(&now, &res, tv);
  }
  return (flags & event);
}

