if ((cpi->svc.number_temporal_layers > 1 && cpi->oxcf.rc_mode == VPX_CBR) ||
    ((cpi->svc.number_temporal_layers > 1 ||
      cpi->svc.number_spatial_layers > 1) &&
     cpi->oxcf.pass == 2)) {
  vp9_update_layer_context_change_config(cpi, (int)cpi->oxcf.target_bandwidth);
