static void report_progress(const MYSQL *mysql, uint stage, uint max_stage,
                            double progress, const char *proc_info,
                            uint proc_info_length) {
  uint length = printf("Stage: %d of %d '%.*s' %6.3g%% of stage done", stage,
                       max_stage, proc_info_length, proc_info, progress);
  if (length < last_progress_report_length)
    printf("%*s", last_progress_report_length - length, "");
  putc('\r', stdout);
  fflush(stdout);
  last_progress_report_length = length;
}

void replace_dynstr_append_mem(DYNAMIC_STRING *ds, const char *val, int len) {
  char lower[512];
#ifdef __WIN__ fix_win_paths(val, len);
#endif if (display_result_lower) {
  char *c = lower;
  for (const char *v = val; *v; v++)
    *c++ = my_tolower(charset_info, *v);
  *c = '\0';
  val = lower;
}
if (glob_replace_regex) {
  if (!multi_reg_replace(glob_replace_regex, (char *)val)) {
    val = glob_replace_regex->buf;
    len = strlen(val);
  }
}
if (glob_replace) {
  replace_strings_append(glob_replace, ds, val, len);
} else
  dynstr_append_mem(ds, val, len);
}

