static int handle_grant_table(TABLE_LIST *tables, uint table_no, bool drop,
                              LEX_USER *user_from, LEX_USER *user_to) {
  int result = 0;
  int error;
  TABLE *table = tables[table_no].table;
  Field *host_field = table->field[0];
  Field *user_field = table->field[table_no ? 2 : 1];
  char *host_str = user_from->host.str;
  char *user_str = user_from->user.str;
  const char *host;
  const char *user;
  uchar user_key[MAX_KEY_LENGTH];
  uint key_prefix_length;
  DBUG_ENTER("handle_grant_table");
  THD *thd = current_thd;
  table->use_all_columns();
  if (!table_no) {
    DBUG_PRINT("info", ("read table: '%s' search: '%s'@'%s'",
                        table->s->table_name.str, user_str, host_str));
    host_field->store(host_str, user_from->host.length, system_charset_info);
    user_field->store(user_str, user_from->user.length, system_charset_info);
    key_prefix_length = (table->key_info->key_part[0].store_length +
                         table->key_info->key_part[1].store_length);
    key_copy(user_key, table->record[0], table->key_info, key_prefix_length);
    if ((error = table->file->index_read_idx_map(table->record[0], 0, user_key,
                                                 (key_part_map)3,
                                                 HA_READ_KEY_EXACT))) {
      if (error != HA_ERR_KEY_NOT_FOUND && error != HA_ERR_END_OF_FILE) {
        table->file->print_error(error, MYF(0));
        result = -1;
      }
    } else {
      result = ((drop || user_to) &&
                modify_grant_table(table, host_field, user_field, user_to))
                   ? -1
                   : 1;
    }
    DBUG_PRINT("info", ("read result: %d", result));
  } else {
    if ((error = table->file->ha_rnd_init(1))) {
      table->file->print_error(error, MYF(0));
      result = -1;
    } else {
#ifdef EXTRA_DEBUG DBUG_PRINT("info",                                          \
                              ("scan table: '%s' search: '%s'@'%s'",           \
                               table->s->table_name.str, user_str, host_str));
#endif while ((error = table->file->rnd_next(table->record[0])) !=             \
              HA_ERR_END_OF_FILE) {
      if (error) {
        DBUG_PRINT("info", ("scan error: %d", error));
        continue;
      }
      if (!(host = get_field(thd->mem_root, host_field)))
        host = "";
      if (!(user = get_field(thd->mem_root, user_field)))
        user = "";
#ifdef EXTRA_DEBUG DBUG_PRINT(                                                 \
    "loop", ("scan fields: '%s'@'%s' '%s' '%s' '%s'", user, host,              \
             get_field(thd->mem_root, table->field[1]),                        \
             get_field(thd->mem_root, table->field[3]),                        \
             get_field(thd->mem_root, table->field[4])));
#endif if (strcmp(user_str, user) ||                                           \
           my_strcasecmp(system_charset_info, host_str, host)) continue;
      result = ((drop || user_to) &&
                modify_grant_table(table, host_field, user_field, user_to))
                   ? -1
               : result ? result
                        : 1;
      if (!drop && !user_to)
        break;
    }
    (void)table->file->ha_rnd_end();
    DBUG_PRINT("info", ("scan result: %d", result));
  }
}
DBUG_RETURN(result);
}

static int read_matrix_params(MLPDecodeContext *m, unsigned int substr,
                              GetBitContext *gbp) {
  SubStream *s = &m->substream[substr];
  unsigned int mat, ch;
  const int max_primitive_matrices = m->avctx->codec_id == AV_CODEC_ID_MLP
                                         ? MAX_MATRICES_MLP
                                         : MAX_MATRICES_TRUEHD;
  if (m->matrix_changed++ > 1) {
    av_log(m->avctx, AV_LOG_ERROR,
           "Matrices may change only once per access unit.\n");
    return AVERROR_INVALIDDATA;
  }
  s->num_primitive_matrices = get_bits(gbp, 4);
  if (s->num_primitive_matrices > max_primitive_matrices) {
    av_log(m->avctx, AV_LOG_ERROR,
           "Number of primitive matrices cannot be greater than %d.\n",
           max_primitive_matrices);
    return AVERROR_INVALIDDATA;
  }
  for (mat = 0; mat < s->num_primitive_matrices; mat++) {
    int frac_bits, max_chan;
    s->matrix_out_ch[mat] = get_bits(gbp, 4);
    frac_bits = get_bits(gbp, 4);
    s->lsb_bypass[mat] = get_bits1(gbp);
    if (s->matrix_out_ch[mat] > s->max_matrix_channel) {
      av_log(m->avctx, AV_LOG_ERROR,
             "Invalid channel %d specified as output from matrix.\n",
             s->matrix_out_ch[mat]);
      return AVERROR_INVALIDDATA;
    }
    if (frac_bits > 14) {
      av_log(m->avctx, AV_LOG_ERROR, "Too many fractional bits specified.\n");
      return AVERROR_INVALIDDATA;
    }
    max_chan = s->max_matrix_channel;
    if (!s->noise_type)
      max_chan += 2;
    for (ch = 0; ch <= max_chan; ch++) {
      int coeff_val = 0;
      if (get_bits1(gbp))
        coeff_val = get_sbits(gbp, frac_bits + 2);
      s->matrix_coeff[mat][ch] = coeff_val << (14 - frac_bits);
    }
    if (s->noise_type)
      s->matrix_noise_shift[mat] = get_bits(gbp, 4);
    else
      s->matrix_noise_shift[mat] = 0;
  }
  return 0;
}

static void *gfi_unpack_entry(struct object_entry *oe, unsigned long *sizep) {
  enum object_type type;
  struct packed_git *p = all_packs[oe->pack_id];
  if (p == pack_data && p->pack_size < (pack_size + 20)) {
    close_pack_windows(p);
    sha1flush(pack_file);
    p->pack_size = pack_size + 20;
  }
  return unpack_entry(p, oe->idx.offset, &type, sizep);
}

