static int dissect_pvfs2_request(tvbuff_t *tvb, proto_tree *tree, int offset,
                                 packet_info *pinfo, guint32 server_op) {
  proto_tree_add_item(tree, hf_pvfs_context_id, tvb, offset, 4,
                      ENC_LITTLE_ENDIAN);
  offset += 4;
  offset = dissect_pvfs_credentials(tvb, tree, offset);
  switch (server_op) {
  case PVFS_SERV_CREATE:
    offset = dissect_pvfs2_create_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_REMOVE:
    offset = dissect_pvfs2_remove_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_IO:
    offset = dissect_pvfs2_io_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_GETATTR:
    offset = dissect_pvfs2_getattr_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_SETATTR:
    offset = dissect_pvfs2_setattr_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_LOOKUP_PATH:
    offset = dissect_pvfs2_lookup_path_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_CRDIRENT:
    offset = dissect_pvfs2_crdirent_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_RMDIRENT:
    offset = dissect_pvfs2_rmdirent_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_CHDIRENT:
    offset = dissect_pvfs2_chdirent_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_TRUNCATE:
    offset = dissect_pvfs2_truncate_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MKDIR:
    offset = dissect_pvfs2_mkdir_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_READDIR:
    offset = dissect_pvfs2_readdir_request(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_GETCONFIG : break;
#endif #if 0 case PVFS_SERV_WRITE_COMPLETION : break;
#endif case PVFS_SERV_FLUSH : offset =                                         \
    dissect_pvfs2_flush_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_SETPARAM:
    offset = dissect_pvfs2_mgmt_setparam_request(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_MGMT_NOOP : break;
#endif case PVFS_SERV_STATFS : offset =                                        \
    dissect_pvfs2_statfs_request(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_PERF_UPDATE : break;
#endif case PVFS_SERV_MGMT_PERF_MON : offset =                                 \
    dissect_pvfs2_mgmt_perf_mon_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_ITERATE_HANDLES:
    offset =
        dissect_pvfs2_mgmt_iterate_handles_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_DSPACE_INFO_LIST:
    offset =
        dissect_pvfs2_mgmt_dspace_info_list_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_EVENT_MON:
    offset = dissect_pvfs2_mgmt_event_mon_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_REMOVE_OBJECT:
    offset = dissect_pvfs2_mgmt_remove_object_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_REMOVE_DIRENT:
    offset = dissect_pvfs2_mgmt_remove_dirent_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_GET_DIRDATA_HANDLE:
    offset =
        dissect_pvfs2_mgmt_get_dirdata_handle_request(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_JOB_TIMER : break;
#endif case PVFS_SERV_PROTO_ERROR : break;
  case PVFS_SERV_GETEATTR:
    offset = dissect_pvfs2_geteattr_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_SETEATTR:
    offset = dissect_pvfs2_seteattr_request(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_DELEATTR:
    offset = dissect_pvfs2_deleattr_request(tvb, tree, offset, pinfo);
    break;
  default:
    break;
  }
  return offset;
}

PCIBus *typhoon_init(ram_addr_t ram_size, ISABus **isa_bus, qemu_irq *p_rtc_irq,
                     AlphaCPU *cpus[4], pci_map_irq_fn sys_map_irq) {
  const uint64_t MB = 1024 * 1024;
  const uint64_t GB = 1024 * MB;
  MemoryRegion *addr_space = get_system_memory();
  MemoryRegion *addr_space_io = get_system_io();
  DeviceState *dev;
  TyphoonState *s;
  PCIHostState *phb;
  PCIBus *b;
  int i;
  dev = qdev_create(NULL, TYPE_TYPHOON_PCI_HOST_BRIDGE);
  qdev_init_nofail(dev);
  s = TYPHOON_PCI_HOST_BRIDGE(dev);
  phb = PCI_HOST_BRIDGE(dev);
  for (i = 0; i < 4; i++) {
    AlphaCPU *cpu = cpus[i];
    s->cchip.cpu[i] = cpu;
    if (cpu != NULL) {
      cpu->alarm_timer = qemu_new_timer_ns(rtc_clock, typhoon_alarm_timer,
                                           (void *)((uintptr_t)s + i));
    }
  }
  *p_rtc_irq = *qemu_allocate_irqs(typhoon_set_timer_irq, s, 1);
  memory_region_init_ram(&s->ram_region, OBJECT(s), "ram", ram_size);
  vmstate_register_ram_global(&s->ram_region);
  memory_region_add_subregion(addr_space, 0, &s->ram_region);
  memory_region_init_io(&s->pchip.region, OBJECT(s), &pchip_ops, s, "pchip0",
                        256 * MB);
  memory_region_add_subregion(addr_space, 0x80180000000ULL, &s->pchip.region);
  memory_region_init_io(&s->cchip.region, OBJECT(s), &cchip_ops, s, "cchip0",
                        256 * MB);
  memory_region_add_subregion(addr_space, 0x801a0000000ULL, &s->cchip.region);
  memory_region_init_io(&s->dchip_region, OBJECT(s), &dchip_ops, s, "dchip0",
                        256 * MB);
  memory_region_add_subregion(addr_space, 0x801b0000000ULL, &s->dchip_region);
  memory_region_init(&s->pchip.reg_mem, OBJECT(s), "pci0-mem", 4 * GB);
  memory_region_add_subregion(addr_space, 0x80000000000ULL, &s->pchip.reg_mem);
  memory_region_init_io(&s->pchip.reg_io, OBJECT(s), &alpha_pci_bw_io_ops, NULL,
                        "pci0-io", 32 * MB);
  memory_region_add_subregion(addr_space, 0x801fc000000ULL, &s->pchip.reg_io);
  b = pci_register_bus(dev, "pci", typhoon_set_irq, sys_map_irq, s,
                       &s->pchip.reg_mem, addr_space_io, 0, 64, TYPE_PCI_BUS);
  phb->bus = b;
  memory_region_init_io(&s->pchip.reg_iack, OBJECT(s), &alpha_pci_iack_ops, b,
                        "pci0-iack", 64 * MB);
  memory_region_add_subregion(addr_space, 0x801f8000000ULL, &s->pchip.reg_iack);
  memory_region_init_io(&s->pchip.reg_conf, OBJECT(s), &alpha_pci_conf1_ops, b,
                        "pci0-conf", 16 * MB);
  memory_region_add_subregion(addr_space, 0x801fe000000ULL, &s->pchip.reg_conf);
  {
    qemu_irq isa_pci_irq, *isa_irqs;
    *isa_bus = isa_bus_new(NULL, addr_space_io);
    isa_pci_irq = *qemu_allocate_irqs(typhoon_set_isa_irq, s, 1);
    isa_irqs = i8259_init(*isa_bus, isa_pci_irq);
    isa_bus_irqs(*isa_bus, isa_irqs);
  }
  return b;
}

static void openpic_src_write(void *opaque, hwaddr addr, uint64_t val,
                              unsigned len) {
  OpenPICState *opp = opaque;
  int idx;
  DPRINTF("%s: addr %#" HWADDR_PRIx " <= %08" PRIx64 "\n", __func__, addr, val);
  addr = addr & 0xffff;
  idx = addr >> 5;
  switch (addr & 0x1f) {
  case 0x00:
    write_IRQreg_ivpr(opp, idx, val);
    break;
  case 0x10:
    write_IRQreg_idr(opp, idx, val);
    break;
  case 0x18:
    write_IRQreg_ilr(opp, idx, val);
    break;
  }
}

