static void tupledesc_match(TupleDesc dst_tupdesc, TupleDesc src_tupdesc) {
  int i;
  if (dst_tupdesc->natts != src_tupdesc->natts)
    ereport(
        ERROR,
        (errcode(ERRCODE_DATATYPE_MISMATCH),
         errmsg(
             "function return row and query-specified return row do not match"),
         errdetail_plural(
             "Returned row contains %d attribute, but query expects %d.",
             "Returned row contains %d attributes, but query expects %d.",
             src_tupdesc->natts, src_tupdesc->natts, dst_tupdesc->natts)));
  for (i = 0; i < dst_tupdesc->natts; i++) {
    Form_pg_attribute dattr = dst_tupdesc->attrs[i];
    Form_pg_attribute sattr = src_tupdesc->attrs[i];
    if (IsBinaryCoercible(sattr->atttypid, dattr->atttypid))
      continue;
    if (!dattr->attisdropped)
      ereport(
          ERROR,
          (errcode(ERRCODE_DATATYPE_MISMATCH),
           errmsg("function return row and query-specified return row do not "
                  "match"),
           errdetail(
               "Returned type %s at ordinal position %d, but query expects %s.",
               format_type_be(sattr->atttypid), i + 1,
               format_type_be(dattr->atttypid))));
    if (dattr->attlen != sattr->attlen || dattr->attalign != sattr->attalign)
      ereport(ERROR, (errcode(ERRCODE_DATATYPE_MISMATCH),
                      errmsg("function return row and query-specified return "
                             "row do not match"),
                      errdetail("Physical storage mismatch on dropped "
                                "attribute at ordinal position %d.",
                                i + 1)));
  }
}

static char **subsystems_from_mount_options(const char *mount_options,
                                            char **kernel_list) {
  char *token, *str, *saveptr = NULL;
  char **result = NULL;
  size_t result_capacity = 0;
  size_t result_count = 0;
  int saved_errno;
  int r;
  str = alloca(strlen(mount_options) + 1);
  strcpy(str, mount_options);
  for (; (token = strtok_r(str, ",", &saveptr)); str = NULL) {
    if (!strncmp(token, "name=", 5) ||
        lxc_string_in_array(token, (const char **)kernel_list)) {
      r = lxc_grow_array((void ***)&result, &result_capacity, result_count + 1,
                         12);
      if (r < 0)
        goto out_free;
      result[result_count + 1] = NULL;
      result[result_count] = strdup(token);
      if (!result[result_count])
        goto out_free;
      result_count++;
    }
  }
  return result;
out_free:
  saved_errno = errno;
  lxc_free_array((void **)result, free);
  errno = saved_errno;
  return NULL;
}

