#if 0 case PVFS_SERV_TRUNCATE : break;
#endif case PVFS_SERV_MKDIR : offset =                                         \
    dissect_pvfs2_mkdir_response(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_READDIR:
    offset = dissect_pvfs2_readdir_response(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_GETCONFIG:
    offset = dissect_pvfs2_getconfig_response(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_WRITE_COMPLETION:
    offset = dissect_pvfs2_write_completion_response(tvb, tree, offset);
    break;
#if 0 case PVFS_SERV_FLUSH : break;
#endif case PVFS_SERV_MGMT_SETPARAM : offset =                                 \
    dissect_pvfs2_mgmt_setparam_response(tvb, tree, offset);
    break;
#if 0 case PVFS_SERV_MGMT_NOOP : break;
#endif case PVFS_SERV_STATFS : offset =                                        \
    dissect_pvfs2_statfs_response(tvb, tree, offset);
    break;
#if 0 case PVFS_SERV_PERF_UPDATE : break;
#endif case PVFS_SERV_MGMT_PERF_MON : offset =                                 \
    dissect_pvfs2_mgmt_perf_mon_response(tvb, tree, offset);
    break;
  case PVFS_SERV_MGMT_ITERATE_HANDLES:
    offset =
        dissect_pvfs2_mgmt_iterate_handles_response(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_DSPACE_INFO_LIST:
    offset =
        dissect_pvfs2_mgmt_dspace_info_list_response(tvb, tree, offset, pinfo);
    break;
  case PVFS_SERV_MGMT_EVENT_MON:
    offset = dissect_pvfs2_mgmt_event_mon_response(tvb, tree, offset);
    break;
  case PVFS_SERV_MGMT_REMOVE_OBJECT:
    offset =
        dissect_pvfs2_mgmt_remove_object_response(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_MGMT_REMOVE_DIRENT : break;
#endif case PVFS_SERV_MGMT_GET_DIRDATA_HANDLE : offset =                       \
    dissect_pvfs2_mgmt_get_dirdata_handle_response(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_JOB_TIMER : break;
#endif case PVFS_SERV_PROTO_ERROR : break;
  case PVFS_SERV_GETEATTR:
    offset = dissect_pvfs2_geteattr_response(tvb, tree, offset, pinfo);
    break;
#if 0 case PVFS_SERV_SETEATTR : break;
#endif #if 0 case PVFS_SERV_DELEATTR : break;
#endif default : break;
  }
  return offset;
}

void addToHeaderList(const char *strings[], HttpHeaderList &headers) {
  for (int i = 0; strings[i]; i += 2) {
    if (i % 4 == 0) {
      headers.push_back(HttpHeader(strings[i], -1, strings[i + 1], -1));
      headers.push_back(HttpHeader());
    } else {
      headers.push_back(HttpHeader(strings[i], strlen(strings[i]),
                                   strings[i + 1], strlen(strings[i + 1])));
    }
  }
}

