static int rtp_packetize_ac3(sout_stream_id_sys_t *id, block_t *in) {
  int i_max = rtp_mtu(id) - 2;
  int i_count = (in->i_buffer + i_max - 1) / i_max;
  uint8_t *p_data = in->p_buffer;
  int i_data = in->i_buffer;
  int i;
  for (i = 0; i < i_count; i++) {
    int i_payload = __MIN(i_max, i_data);
    block_t *out = block_Alloc(14 + i_payload);
    rtp_packetize_common(id, out, (i == i_count - 1) ? 1 : 0, in->i_pts);
    out->p_buffer[12] = 1;
    out->p_buffer[13] = 0x00;
    memcpy(&out->p_buffer[14], p_data, i_payload);
    out->i_dts = in->i_dts + i * in->i_length / i_count;
    out->i_length = in->i_length / i_count;
    rtp_packetize_send(id, out);
    p_data += i_payload;
    i_data -= i_payload;
  }
  block_Release(in);
  return VLC_SUCCESS;
}

int vp9_full_search_sad_c(const MACROBLOCK *x, const MV *ref_mv,
                          int sad_per_bit, int distance,
                          const vp9_variance_fn_ptr_t *fn_ptr,
                          const MV *center_mv, MV *best_mv) {
  int r, c;
  const MACROBLOCKD *const xd = &x->e_mbd;
  const struct buf_2d *const what = &x->plane[0].src;
  const struct buf_2d *const in_what = &xd->plane[0].pre[0];
  const int row_min = MAX(ref_mv->row - distance, x->mv_row_min);
  const int row_max = MIN(ref_mv->row + distance, x->mv_row_max);
  const int col_min = MAX(ref_mv->col - distance, x->mv_col_min);
  const int col_max = MIN(ref_mv->col + distance, x->mv_col_max);
  const MV fcenter_mv = {center_mv->row >> 3, center_mv->col >> 3};
  int best_sad =
      fn_ptr->sdf(what->buf, what->stride, get_buf_from_mv(in_what, ref_mv),
                  in_what->stride) +
      mvsad_err_cost(x, ref_mv, &fcenter_mv, sad_per_bit);
  *best_mv = *ref_mv;
  for (r = row_min; r < row_max; ++r) {
    for (c = col_min; c < col_max; ++c) {
      const MV mv = {r, c};
      const int sad =
          fn_ptr->sdf(what->buf, what->stride, get_buf_from_mv(in_what, &mv),
                      in_what->stride) +
          mvsad_err_cost(x, &mv, &fcenter_mv, sad_per_bit);
      if (sad < best_sad) {
        best_sad = sad;
        *best_mv = mv;
      }
    }
  }
  return best_sad;
}

static inline void decode_subblock(int16_t *dst, int code, const int is_block2,
                                   GetBitContext *gb, VLC *vlc, int q) {
  int flags = modulo_three_table[code];
  decode_coeff(dst + 0 * 4 + 0, (flags >> 6), 3, gb, vlc, q);
  if (is_block2) {
    decode_coeff(dst + 1 * 4 + 0, (flags >> 4) & 3, 2, gb, vlc, q);
    decode_coeff(dst + 0 * 4 + 1, (flags >> 2) & 3, 2, gb, vlc, q);
  } else {
    decode_coeff(dst + 0 * 4 + 1, (flags >> 4) & 3, 2, gb, vlc, q);
    decode_coeff(dst + 1 * 4 + 0, (flags >> 2) & 3, 2, gb, vlc, q);
  }
  decode_coeff(dst + 1 * 4 + 1, (flags >> 0) & 3, 2, gb, vlc, q);
}

