  if (gctx->ctr) {
    size_t bulk = 0;
#if defined(AES_GCM_ASM) if (len >= 16 && AES_GCM_ASM(gctx)) {
    if (CRYPTO_gcm128_decrypt(&gctx->gcm, NULL, NULL, 0))
