                            const unsigned char *in, size_t len) {
    EVP_AES_XTS_CTX *xctx = EVP_C_DATA(EVP_AES_XTS_CTX, ctx);
    if (!xctx->xts.key1 || !xctx->xts.key2)
      return 0;
    if (!out || !in || len < AES_BLOCK_SIZE)
      return 0;
    if (xctx->stream)
      (*xctx->stream)(in, out, len, xctx->xts.key1, xctx->xts.key2,
                      EVP_CIPHER_CTX_iv_noconst(ctx));
    else if (CRYPTO_xts128_encrypt(&xctx->xts, EVP_CIPHER_CTX_iv_noconst(ctx),
                                   in, out, len,
                                   EVP_CIPHER_CTX_encrypting(ctx)))
      return 0;
    return 1;
  }
#define aes_xts_cleanup                                                        \
  NULL #define XTS_FLAGS(EVP_CIPH_FLAG_DEFAULT_ASN1 | EVP_CIPH_CUSTOM_IV \ |   \
                         EVP_CIPH_ALWAYS_CALL_INIT | EVP_CIPH_CTRL_INIT \ |    \
                         EVP_CIPH_CUSTOM_COPY)                                 \
      BLOCK_CIPHER_custom(NID_aes, 128, 1, 16, xts, XTS, XTS_FLAGS)            \
          BLOCK_CIPHER_custom(NID_aes, 256, 1, 16, xts, XTS,                   \
                              XTS_FLAGS) static int                            \
          aes_ccm_ctrl(EVP_CIPHER_CTX *c, int type, int arg, void *ptr) {
  EVP_AES_CCM_CTX *cctx = EVP_C_DATA(EVP_AES_CCM_CTX, c);
  switch (type) {
  case EVP_CTRL_INIT:
    cctx->key_set = 0;
    cctx->iv_set = 0;
    cctx->L = 8;
    cctx->M = 12;
    cctx->tag_set = 0;
    cctx->len_set = 0;
    cctx->tls_aad_len = -1;
    return 1;
  case EVP_CTRL_AEAD_TLS1_AAD:
    if (arg != EVP_AEAD_TLS1_AAD_LEN)
      return 0;
    memcpy(EVP_CIPHER_CTX_buf_noconst(c), ptr, arg);
    cctx->tls_aad_len = arg;
    {
      uint16_t len = EVP_CIPHER_CTX_buf_noconst(c)[arg - 2] << 8 |
                     EVP_CIPHER_CTX_buf_noconst(c)[arg - 1];
      len -= EVP_CCM_TLS_EXPLICIT_IV_LEN;
      if (!EVP_CIPHER_CTX_encrypting(c))
        len -= cctx->M;
      EVP_CIPHER_CTX_buf_noconst(c)[arg - 2] = len >> 8;
      EVP_CIPHER_CTX_buf_noconst(c)[arg - 1] = len & 0xff;
    }
    return cctx->M;
  case EVP_CTRL_CCM_SET_IV_FIXED:
    if (arg != EVP_CCM_TLS_FIXED_IV_LEN)
      return 0;
    memcpy(EVP_CIPHER_CTX_iv_noconst(c), ptr, arg);
    return 1;
  case EVP_CTRL_AEAD_SET_IVLEN:
    arg = 15 - arg;
  case EVP_CTRL_CCM_SET_L:
    if (arg < 2 || arg > 8)
      return 0;
    cctx->L = arg;
    return 1;
  case EVP_CTRL_AEAD_SET_TAG:
    if ((arg & 1) || arg < 4 || arg > 16)
      return 0;
    if (EVP_CIPHER_CTX_encrypting(c) && ptr)
      return 0;
    if (ptr) {
      cctx->tag_set = 1;
      memcpy(EVP_CIPHER_CTX_buf_noconst(c), ptr, arg);
    }
    cctx->M = arg;
    return 1;
  case EVP_CTRL_AEAD_GET_TAG:
    if (!EVP_CIPHER_CTX_encrypting(c) || !cctx->tag_set)
      return 0;
    if (!CRYPTO_ccm128_tag(&cctx->ccm, ptr, (size_t)arg))
      return 0;
    cctx->tag_set = 0;
    cctx->iv_set = 0;
    cctx->len_set = 0;
    return 1;
  case EVP_CTRL_COPY: {
    EVP_CIPHER_CTX *out = ptr;
    EVP_AES_CCM_CTX *cctx_out = EVP_C_DATA(EVP_AES_CCM_CTX, out);
    if (cctx->ccm.key) {
      if (cctx->ccm.key != &cctx->ks)
        return 0;
      cctx_out->ccm.key = &cctx_out->ks;
    }
    return 1;
  }
  default:
    return -1;
  }
