int libevt_record_values_clone(
    libevt_record_values_t **destination_record_values,
    libevt_record_values_t *source_record_values, libcerror_error_t **error) {
  static char *function = "libevt_record_values_clone";
  if (destination_record_values == NULL) {
    libcerror_error_set(error, LIBCERROR_ERROR_DOMAIN_ARGUMENTS,
                        LIBCERROR_ARGUMENT_ERROR_INVALID_VALUE,
                        "%s: invalid destination record values.", function);
    return (-1);
  }
  if (*destination_record_values != NULL) {
    libcerror_error_set(
        error, LIBCERROR_ERROR_DOMAIN_RUNTIME,
        LIBCERROR_RUNTIME_ERROR_VALUE_ALREADY_SET,
        "%s: invalid destination record values value already set.", function);
    return (-1);
  }
  if (source_record_values == NULL) {
    *destination_record_values = NULL;
    return (1);
  }
  *destination_record_values =
      memory_allocate_structure(libevt_record_values_t);
  if (*destination_record_values == NULL) {
    libcerror_error_set(error, LIBCERROR_ERROR_DOMAIN_MEMORY,
                        LIBCERROR_MEMORY_ERROR_INSUFFICIENT,
                        "%s: unable to create destination record values.",
                        function);
    goto on_error;
  }
  if (memory_copy(*destination_record_values, source_record_values,
                  sizeof(libevt_record_values_t)) == NULL) {
    libcerror_error_set(
        error, LIBCERROR_ERROR_DOMAIN_MEMORY,
        LIBCERROR_MEMORY_ERROR_COPY_FAILED,
        "%s: unable to copy source to destination record values.", function);
    goto on_error;
  }
  return (1);
on_error:
  if (*destination_record_values != NULL) {
    memory_free(*destination_record_values);
    *destination_record_values = NULL;
  }
  return (-1);
}

static int ff_h261_resync(H261Context *h) {
  MpegEncContext *const s = &h->s;
  int left, ret;
  if (h->gob_start_code_skipped) {
    ret = h261_decode_gob_header(h);
    if (ret >= 0)
      return 0;
  } else {
    if (show_bits(&s->gb, 15) == 0) {
      ret = h261_decode_gob_header(h);
      if (ret >= 0)
        return 0;
    }
    s->gb = s->last_resync_gb;
    align_get_bits(&s->gb);
    left = get_bits_left(&s->gb);
    for (; left > 15 + 1 + 4 + 5; left -= 8) {
      if (show_bits(&s->gb, 15) == 0) {
        GetBitContext bak = s->gb;
        ret = h261_decode_gob_header(h);
        if (ret >= 0)
          return 0;
        s->gb = bak;
      }
      skip_bits(&s->gb, 8);
    }
  }
  return -1;
}

