static int iso9660_close(struct archive_write *a) {
  struct iso9660 *iso9660;
  int ret, blocks;
  iso9660 = a->format_data;
  if (wb_remaining(a) > 0) {
    ret = wb_write_out(a);
    if (ret < 0)
      return (ret);
  }
#ifdef DEBUG if (iso9660->birth_time == 0) #endif time(&(iso9660->birth_time));
  if (iso9660->opt.boot) {
    ret = isoent_find_out_boot_file(a, iso9660->primary.rootent);
    if (ret < 0)
      return (ret);
    ret = zisofs_rewind_boot_file(a);
    if (ret < 0)
      return (ret);
    if (wb_remaining(a) > 0) {
      ret = wb_write_out(a);
      if (ret < 0)
        return (ret);
    }
    ret = isoent_create_boot_catalog(a, iso9660->primary.rootent);
    if (ret < 0)
      return (ret);
  }
  if (iso9660->opt.joliet) {
    ret = isoent_clone_tree(a, &(iso9660->joliet.rootent),
                            iso9660->primary.rootent);
    if (ret < 0)
      return (ret);
    if (iso9660->sconv_to_utf16be == NULL) {
      iso9660->sconv_to_utf16be =
          archive_string_conversion_to_charset(&(a->archive), "UTF-16BE", 1);
      if (iso9660->sconv_to_utf16be == NULL)
        return (ARCHIVE_FATAL);
      iso9660->sconv_from_utf16be =
          archive_string_conversion_from_charset(&(a->archive), "UTF-16BE", 1);
      if (iso9660->sconv_from_utf16be == NULL)
        return (ARCHIVE_FATAL);
    }
  }
  ret = isoent_make_path_table(a);
  if (ret < 0)
    return (ret);
  blocks = SYSTEM_AREA_BLOCK + PRIMARY_VOLUME_DESCRIPTOR_BLOCK +
           VOLUME_DESCRIPTOR_SET_TERMINATOR_BLOCK +
           NON_ISO_FILE_SYSTEM_INFORMATION_BLOCK;
  if (iso9660->opt.boot)
    blocks += BOOT_RECORD_DESCRIPTOR_BLOCK;
  if (iso9660->opt.joliet)
    blocks += SUPPLEMENTARY_VOLUME_DESCRIPTOR_BLOCK;
  if (iso9660->opt.iso_level == 4)
    blocks += SUPPLEMENTARY_VOLUME_DESCRIPTOR_BLOCK;
  iso9660->primary.location_type_L_path_table = blocks;
  blocks += iso9660->primary.path_table_block;
  iso9660->primary.location_type_M_path_table = blocks;
  blocks += iso9660->primary.path_table_block;
  if (iso9660->opt.joliet) {
    iso9660->joliet.location_type_L_path_table = blocks;
    blocks += iso9660->joliet.path_table_block;
    iso9660->joliet.location_type_M_path_table = blocks;
    blocks += iso9660->joliet.path_table_block;
  }
  isoent_setup_directory_location(iso9660, blocks, &(iso9660->primary));
  blocks += iso9660->primary.total_dir_block;
  if (iso9660->opt.joliet) {
    isoent_setup_directory_location(iso9660, blocks, &(iso9660->joliet));
    blocks += iso9660->joliet.total_dir_block;
  }
  if (iso9660->opt.rr) {
    iso9660->location_rrip_er = blocks;
    blocks += RRIP_ER_BLOCK;
  }
  isoent_setup_file_location(iso9660, blocks);
  blocks += iso9660->total_file_block;
  if (iso9660->opt.boot && iso9660->opt.boot_info_table) {
    ret = setup_boot_information(a);
    if (ret < 0)
      return (ret);
  }
  iso9660->volume_space_size = blocks;
  if (iso9660->opt.pad)
    iso9660->volume_space_size += PADDING_BLOCK;
  iso9660->volume_sequence_number = 1;
  iso9660->wbuff_remaining = wb_buffmax();
  iso9660->wbuff_type = WB_TO_STREAM;
  iso9660->wbuff_offset = 0;
  iso9660->wbuff_written = 0;
  iso9660->wbuff_tail = 0;
  ret = write_null(a, SYSTEM_AREA_BLOCK * LOGICAL_BLOCK_SIZE);
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  ret = write_VD(a, &(iso9660->primary));
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  if (iso9660->opt.boot) {
    ret = write_VD_boot_record(a);
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  if (iso9660->opt.iso_level == 4) {
    iso9660->primary.vdd_type = VDD_ENHANCED;
    ret = write_VD(a, &(iso9660->primary));
    iso9660->primary.vdd_type = VDD_PRIMARY;
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  if (iso9660->opt.joliet) {
    ret = write_VD(a, &(iso9660->joliet));
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  ret = write_VD_terminator(a);
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  ret = write_information_block(a);
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  ret = write_path_table(a, 0, &(iso9660->primary));
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  ret = write_path_table(a, 1, &(iso9660->primary));
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  if (iso9660->opt.joliet) {
    ret = write_path_table(a, 0, &(iso9660->joliet));
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
    ret = write_path_table(a, 1, &(iso9660->joliet));
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  ret = write_directory_descriptors(a, &(iso9660->primary));
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  if (iso9660->opt.joliet) {
    ret = write_directory_descriptors(a, &(iso9660->joliet));
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  if (iso9660->opt.rr) {
    ret = write_rr_ER(a);
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  ret = write_file_descriptors(a);
  if (ret != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  if (iso9660->opt.pad) {
    ret = write_null(a, PADDING_BLOCK * LOGICAL_BLOCK_SIZE);
    if (ret != ARCHIVE_OK)
      return (ARCHIVE_FATAL);
  }
  if (iso9660->directories_too_deep != NULL) {
    archive_set_error(
        &a->archive, ARCHIVE_ERRNO_MISC, "%s: Directories too deep.",
        archive_entry_pathname(iso9660->directories_too_deep->file->entry));
    return (ARCHIVE_WARN);
  }
  ret = wb_write_out(a);
  return (ret);
}

void keydb_release(KEYDB_HANDLE hd) {
  int i;
  if (!hd)
    return;
  assert(active_handles > 0);
  active_handles--;
  unlock_all(hd);
  for (i = 0; i < hd->used; i++) {
    switch (hd->active[i].type) {
    case KEYDB_RESOURCE_TYPE_NONE:
      break;
    case KEYDB_RESOURCE_TYPE_KEYRING:
      keyring_release(hd->active[i].u.kr);
      break;
    case KEYDB_RESOURCE_TYPE_KEYBOX:
      keybox_release(hd->active[i].u.kb);
      break;
    }
  }
  xfree(hd);
}

void show_setup_info(tvbuff_t *tvb, proto_tree *tree,
                     t38_conv *p_t38_conversation) {
  proto_tree *t38_setup_tree;
  proto_item *ti;
  if (!p_t38_conversation || p_t38_conversation->setup_frame_number == 0) {
    return;
  }
  ti = proto_tree_add_string_format(
      tree, hf_t38_setup, tvb, 0, 0, "", "Stream setup by %s (frame %u)",
      p_t38_conversation->setup_method, p_t38_conversation->setup_frame_number);
  PROTO_ITEM_SET_GENERATED(ti);
  t38_setup_tree = proto_item_add_subtree(ti, ett_t38_setup);
  if (t38_setup_tree) {
    proto_item *item =
        proto_tree_add_uint(t38_setup_tree, hf_t38_setup_frame, tvb, 0, 0,
                            p_t38_conversation->setup_frame_number);
    PROTO_ITEM_SET_GENERATED(item);
    item = proto_tree_add_string(t38_setup_tree, hf_t38_setup_method, tvb, 0, 0,
                                 p_t38_conversation->setup_method);
    PROTO_ITEM_SET_GENERATED(item);
  }
}

static gpgme_error_t gpgsm_export_ext(void *engine, const char *pattern[],
                                      gpgme_export_mode_t mode,
                                      gpgme_data_t keydata, int use_armor) {
  engine_gpgsm_t gpgsm = engine;
  gpgme_error_t err = 0;
  char *line;
  int length = 7 + 1;
  char *linep;
  if (!gpgsm)
    return gpg_error(GPG_ERR_INV_VALUE);
  if (mode)
    return gpg_error(GPG_ERR_NOT_SUPPORTED);
  if (pattern && *pattern) {
    const char **pat = pattern;
    while (*pat) {
      const char *patlet = *pat;
      while (*patlet) {
        length++;
        if (*patlet == '%' || *patlet == ' ' || *patlet == '+')
          length += 2;
        patlet++;
      }
      pat++;
      length++;
    }
  }
  line = malloc(length);
  if (!line)
    return gpg_error_from_syserror();
  strcpy(line, "EXPORT ");
  linep = &line[7];
  if (pattern && *pattern) {
    while (*pattern) {
      const char *patlet = *pattern;
      while (*patlet) {
        switch (*patlet) {
        case '%':
          *(linep++) = '%';
          *(linep++) = '2';
          *(linep++) = '5';
          break;
        case ' ':
          *(linep++) = '%';
          *(linep++) = '2';
          *(linep++) = '0';
          break;
        case '+':
          *(linep++) = '%';
          *(linep++) = '2';
          *(linep++) = 'B';
          break;
        default:
          *(linep++) = *patlet;
          break;
        }
        patlet++;
      }
      pattern++;
      if (*pattern)
        *linep++ = ' ';
    }
  }
  *linep = '\0';
  gpgsm->output_cb.data = keydata;
  err =
      gpgsm_set_fd(gpgsm, OUTPUT_FD,
                   use_armor ? "--armor" : map_data_enc(gpgsm->output_cb.data));
  if (err)
    return err;
  gpgsm_clear_fd(gpgsm, INPUT_FD);
  gpgsm_clear_fd(gpgsm, MESSAGE_FD);
  gpgsm->inline_data = NULL;
  err = start(gpgsm, line);
  free(line);
  return err;
}

static int frame_is_boosted(const VP9_COMP *cpi) {
  return frame_is_intra_only(&cpi->common) || cpi->refresh_alt_ref_frame ||
         (cpi->refresh_golden_frame && !cpi->rc.is_src_frame_alt_ref) ||
         vp9_is_upper_layer_key_frame(cpi);
}

PREDICTION_MODE vp9_left_block_mode(const MODE_INFO *cur_mi,
                                    const MODE_INFO *left_mi, int b) {
  if (b == 0 || b == 2) {
    if (!left_mi || is_inter_block(&left_mi->mbmi))
      return DC_PRED;
    return get_y_mode(left_mi, b + 1);
  } else {
    assert(b == 1 || b == 3);
    return cur_mi->bmi[b - 1].as_mode;
  }
}

static GList *get_files_from_fallbacks(GList *fallbacks) {
  MoveFileCopyFallback *fallback;
  GList *res, *l;
  res = NULL;
  for (l = fallbacks; l != NULL; l = l->next) {
    fallback = l->data;
    res = g_list_prepend(res, fallback->file);
  }
  return g_list_reverse(res);
}

Oid get_opclass_input_type(Oid opclass) {
  HeapTuple tp;
  Form_pg_opclass cla_tup;
  Oid result;
  tp = SearchSysCache1(CLAOID, ObjectIdGetDatum(opclass));
  if (!HeapTupleIsValid(tp))
    elog(ERROR, "cache lookup failed for opclass %u", opclass);
  cla_tup = (Form_pg_opclass)GETSTRUCT(tp);
  result = cla_tup->opcintype;
  ReleaseSysCache(tp);
