static int best_effort_strncat_from_utf16(struct archive_string *as,
                                          const void *_p, size_t bytes,
                                          struct archive_string_conv *sc,
                                          int be) {
  const char *utf16 = (const char *)_p;
  char *mbs;
  uint32_t uc;
  int n, ret;
  (void)sc;
  ret = 0;
  if (archive_string_ensure(as, as->length + bytes + 1) == NULL)
    return (-1);
  mbs = as->s + as->length;
  while ((n = utf16_to_unicode(&uc, utf16, bytes, be)) != 0) {
    if (n < 0) {
      n *= -1;
      ret = -1;
    }
    bytes -= n;
    utf16 += n;
    if (uc > 127) {
      *mbs++ = '?';
      ret = -1;
    } else
      *mbs++ = (char)uc;
  }
  as->length = mbs - as->s;
  as->s[as->length] = '\0';
  return (ret);
}

int EVP_CipherInit_ex(EVP_CIPHER_CTX *ctx, const EVP_CIPHER *cipher,
                      ENGINE *impl, const unsigned char *key,
                      const unsigned char *iv, int enc) {
  if (enc == -1)
    enc = ctx->encrypt;
  else {
    if (enc)
      enc = 1;
    ctx->encrypt = enc;
  }
#ifndef OPENSSL_NO_ENGINE if (ctx->engine && ctx->cipher &&                    \
                              (!cipher ||                                      \
                               (cipher &&                                      \
                                (cipher->nid ==                                \
                                 ctx->cipher->nid)))) goto skip_to_init;
#endif if (cipher) {
  if (ctx->cipher) {
    unsigned long flags = ctx->flags;
    EVP_CIPHER_CTX_reset(ctx);
    ctx->encrypt = enc;
    ctx->flags = flags;
  }
#ifndef OPENSSL_NO_ENGINE if (impl) {
  if (!ENGINE_init(impl)) {
    EVPerr(EVP_F_EVP_CIPHERINIT_EX, EVP_R_INITIALIZATION_ERROR);
    return 0;
  }
}
else impl = ENGINE_get_cipher_engine(cipher->nid);
if (impl) {
  const EVP_CIPHER *c = ENGINE_get_cipher(impl, cipher->nid);
  if (!c) {
    EVPerr(EVP_F_EVP_CIPHERINIT_EX, EVP_R_INITIALIZATION_ERROR);
    return 0;
  }
  cipher = c;
  ctx->engine = impl;
} else
  ctx->engine = NULL;
#endif ctx->cipher = cipher;
if (ctx->cipher->ctx_size) {
  ctx->cipher_data = OPENSSL_zalloc(ctx->cipher->ctx_size);
  if (ctx->cipher_data == NULL) {
    EVPerr(EVP_F_EVP_CIPHERINIT_EX, ERR_R_MALLOC_FAILURE);
    return 0;
  }
} else {
  ctx->cipher_data = NULL;
}
ctx->key_len = cipher->key_len;
ctx->flags &= EVP_CIPHER_CTX_FLAG_WRAP_ALLOW;
if (ctx->cipher->flags & EVP_CIPH_CTRL_INIT) {
  if (!EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_INIT, 0, NULL)) {
    EVPerr(EVP_F_EVP_CIPHERINIT_EX, EVP_R_INITIALIZATION_ERROR);
    return 0;
  }
}
}
else if (!ctx->cipher) {
  EVPerr(EVP_F_EVP_CIPHERINIT_EX, EVP_R_NO_CIPHER_SET);
  return 0;
}
#ifndef OPENSSL_NO_ENGINE skip_to_init : #endif OPENSSL_assert(                \
    ctx->cipher->block_size == 1 || ctx->cipher->block_size == 8 ||            \
    ctx->cipher->block_size == 16);
if (!(ctx->flags & EVP_CIPHER_CTX_FLAG_WRAP_ALLOW) &&
    EVP_CIPHER_CTX_mode(ctx) == EVP_CIPH_WRAP_MODE) {
  EVPerr(EVP_F_EVP_CIPHERINIT_EX, EVP_R_WRAP_MODE_NOT_ALLOWED);
  return 0;
}
if (!(EVP_CIPHER_flags(EVP_CIPHER_CTX_cipher(ctx)) & EVP_CIPH_CUSTOM_IV)) {
  switch (EVP_CIPHER_CTX_mode(ctx)) {
  case EVP_CIPH_STREAM_CIPHER:
  case EVP_CIPH_ECB_MODE:
    break;
  case EVP_CIPH_CFB_MODE:
  case EVP_CIPH_OFB_MODE:
    ctx->num = 0;
  case EVP_CIPH_CBC_MODE:
    OPENSSL_assert(EVP_CIPHER_CTX_iv_length(ctx) <= (int)sizeof(ctx->iv));
    if (iv)
      memcpy(ctx->oiv, iv, EVP_CIPHER_CTX_iv_length(ctx));
    memcpy(ctx->iv, ctx->oiv, EVP_CIPHER_CTX_iv_length(ctx));
    break;
  case EVP_CIPH_CTR_MODE:
    ctx->num = 0;
    if (iv)
      memcpy(ctx->iv, iv, EVP_CIPHER_CTX_iv_length(ctx));
    break;
  default:
    return 0;
  }
}
if (key || (ctx->cipher->flags & EVP_CIPH_ALWAYS_CALL_INIT)) {
  if (!ctx->cipher->init(ctx, key, iv, enc))
    return 0;
}
ctx->buf_len = 0;
ctx->final_used = 0;
ctx->block_mask = ctx->cipher->block_size - 1;
return 1;
}

int vp9_rc_drop_frame(VP9_COMP *cpi) {
  const VP9EncoderConfig *oxcf = &cpi->oxcf;
  RATE_CONTROL *const rc = &cpi->rc;
  if (!oxcf->drop_frames_water_mark) {
    return 0;
  } else {
    if (rc->buffer_level < 0) {
      return 1;
    } else {
      int drop_mark =
          (int)(oxcf->drop_frames_water_mark * rc->optimal_buffer_level / 100);
      if ((rc->buffer_level > drop_mark) && (rc->decimation_factor > 0)) {
        --rc->decimation_factor;
      } else if (rc->buffer_level <= drop_mark && rc->decimation_factor == 0) {
        rc->decimation_factor = 1;
      }
      if (rc->decimation_factor > 0) {
        if (rc->decimation_count > 0) {
          --rc->decimation_count;
          return 1;
        } else {
          rc->decimation_count = rc->decimation_factor;
          return 0;
        }
      } else {
        rc->decimation_count = 0;
        return 0;
      }
    }
  }
}

