static inline int base_key_length(const cipher_type_t *cipher, int key_length) {
  switch (cipher->id) {
  case AES_128_ICM:
  case AES_192_ICM:
  case AES_256_ICM:
    return key_length - 14;
    break;
  case AES_128_GCM:
    return 16;
    break;
  case AES_256_GCM:
    return 32;
    break;
  default:
    return key_length;
    break;
  }
}

static int32_t U_CALLCONV uprv_copyArray32(const UDataSwapper *ds,
                                           const void *inData, int32_t length,
                                           void *outData,
                                           UErrorCode *pErrorCode) {
  if (pErrorCode == NULL || U_FAILURE(*pErrorCode)) {
    return 0;
  }
  if (ds == NULL || inData == NULL || length < 0 || (length & 3) != 0 ||
      outData == NULL) {
    *pErrorCode = U_ILLEGAL_ARGUMENT_ERROR;
    return 0;
  }
  if (length > 0 && inData != outData) {
    uprv_memcpy(outData, inData, length);
  }
  return length;
}

