static void setup_quantization(VP9_COMMON *const cm, MACROBLOCKD *const xd,
                               struct vp9_read_bit_buffer *rb) {
  int update = 0;
  cm->base_qindex = vp9_rb_read_literal(rb, QINDEX_BITS);
  update |= read_delta_q(rb, &cm->y_dc_delta_q);
  update |= read_delta_q(rb, &cm->uv_dc_delta_q);
  update |= read_delta_q(rb, &cm->uv_ac_delta_q);
  if (update)
    vp9_init_dequantizer(cm);
  xd->lossless = cm->base_qindex == 0 && cm->y_dc_delta_q == 0 &&
                 cm->uv_dc_delta_q == 0 && cm->uv_ac_delta_q == 0;
}

int jas_image_readcmpt(jas_image_t *image, int cmptno, jas_image_coord_t x,
                       jas_image_coord_t y, jas_image_coord_t width,
                       jas_image_coord_t height, jas_matrix_t *data) {
  jas_image_cmpt_t *cmpt;
  jas_image_coord_t i;
  jas_image_coord_t j;
  int k;
  jas_seqent_t v;
  int c;
  jas_seqent_t *dr;
  jas_seqent_t *d;
  int drs;
  if (cmptno < 0 || cmptno >= image->numcmpts_) {
    return -1;
  }
  cmpt = image->cmpts_[cmptno];
  if (x >= cmpt->width_ || y >= cmpt->height_ || x + width > cmpt->width_ ||
      y + height > cmpt->height_) {
    return -1;
  }
  if (jas_matrix_numrows(data) != height || jas_matrix_numcols(data) != width) {
    if (jas_matrix_resize(data, height, width)) {
      return -1;
    }
  }
  dr = jas_matrix_getref(data, 0, 0);
  drs = jas_matrix_rowstep(data);
  for (i = 0; i < height; ++i, dr += drs) {
    d = dr;
    if (jas_stream_seek(cmpt->stream_,
                        (cmpt->width_ * (y + i) + x) * cmpt->cps_,
                        SEEK_SET) < 0) {
      return -1;
    }
    for (j = width; j > 0; --j, ++d) {
      v = 0;
      for (k = cmpt->cps_; k > 0; --k) {
        if ((c = jas_stream_getc(cmpt->stream_)) == EOF) {
          return -1;
        }
        v = (v << 8) | (c & 0xff);
      }
      *d = bitstoint(v, cmpt->prec_, cmpt->sgnd_);
    }
  }
  return 0;
}

