    free(username_copy);
    free(password_copy);
    return (ENOMEM);
  }
  free(nb->username);
  free(nb->password);
  nb->username = username_copy;
  nb->password = password_copy;
  nb->seclevel = level;
  lcc_network_buffer_initialize(nb);
  return (0);
}

