static int parse_traffic(char *buf, int len, char *port, uint64_t *traffic) {
  char *data = get_data(buf, len);
  char error_buf[512];
  json_settings settings = {0};
  if (data == NULL) {
    LOGE("No data found");
    return -1;
  }
  json_value *obj = json_parse_ex(&settings, data, strlen(data), error_buf);
  if (obj == NULL) {
    LOGE("%s", error_buf);
    return -1;
  }
  if (obj->type == json_object) {
    int i = 0;
    for (i = 0; i < obj->u.object.length; i++) {
      char *name = obj->u.object.values[i].name;
      json_value *value = obj->u.object.values[i].value;
      if (value->type == json_integer) {
        strncpy(port, name, 8);
        *traffic = value->u.integer;
      }
    }
  }
  json_value_free(obj);
  return 0;
}

static void create_new_objects(void) {
  int dbnum;
  prep_status("Restoring database schemas in the new cluster\n");
  for (dbnum = 0; dbnum < old_cluster.dbarr.ndbs; dbnum++) {
    char sql_file_name[MAXPGPATH], log_file_name[MAXPGPATH];
    DbInfo *old_db = &old_cluster.dbarr.dbs[dbnum];
    PQExpBufferData connstr, escaped_connstr;
    initPQExpBuffer(&connstr);
    appendPQExpBuffer(&connstr, "dbname=");
    appendConnStrVal(&connstr, old_db->db_name);
    initPQExpBuffer(&escaped_connstr);
    appendShellString(&escaped_connstr, connstr.data);
    termPQExpBuffer(&connstr);
    pg_log(PG_STATUS, "%s", old_db->db_name);
    snprintf(sql_file_name, sizeof(sql_file_name), DB_DUMP_FILE_MASK,
             old_db->db_oid);
    snprintf(log_file_name, sizeof(log_file_name), DB_DUMP_LOG_FILE_MASK,
             old_db->db_oid);
    parallel_exec_prog(
        log_file_name, NULL,
        "\"%s/pg_restore\" %s --exit-on-error --verbose --dbname %s \"%s\"",
        new_cluster.bindir, cluster_conn_opts(&new_cluster),
        escaped_connstr.data, sql_file_name);
    termPQExpBuffer(&escaped_connstr);
  }
  while (reap_child(true) == true)
    ;
  end_progress_output();
  check_ok();
  if (GET_MAJOR_VERSION(old_cluster.major_version) < 903)
    set_frozenxids(true);
  get_db_and_rel_infos(&new_cluster);
}

TEST_F(BudgetDatabaseTest, SpendBudgetTest) {
base: : SimpleTestClock * clock = SetClockForTesting ( ) ;
  SetSiteEngagementScore(kEngagement);
  GetBudgetDetails();
  clock->Advance(base : : TimeDelta : : FromDays(1));
  GetBudgetDetails();
  clock->Advance(base : : TimeDelta : : FromDays(1));
  GetBudgetDetails();
  ASSERT_TRUE(SpendBudget(1));
  GetBudgetDetails();
  double daily_budget = kMaxDailyBudget * (kEngagement / SiteEngagementScore
                                           :
                                           : kMaxPoints);
  ASSERT_EQ(4U, prediction_.size());
  ASSERT_DOUBLE_EQ((2 + kDefaultExpirationInDays) * daily_budget - 1,
                   prediction_[0]->budget_at);
  ASSERT_DOUBLE_EQ(daily_budget * 2, prediction_[1]->budget_at);
  ASSERT_DOUBLE_EQ(daily_budget, prediction_[2]->budget_at);
  ASSERT_DOUBLE_EQ(0, prediction_[3]->budget_at);
  ASSERT_TRUE(SpendBudget((1 + kDefaultExpirationInDays) * daily_budget));
  GetBudgetDetails();
  ASSERT_EQ(2U, prediction_.size());
  ASSERT_DOUBLE_EQ(daily_budget - 1, prediction_[0]->budget_at);
  EXPECT_FALSE(SpendBudget(kEngagement));
  GetBudgetDetails();
  ASSERT_EQ(2U, prediction_.size());
  ASSERT_DOUBLE_EQ(daily_budget - 1, prediction_[0]->budget_at);
  clock->Advance(base : : TimeDelta : : FromDays(kDefaultExpirationInDays + 1));
  EXPECT_TRUE(SpendBudget(daily_budget * kDefaultExpirationInDays));
}

static hb_tag_t hb_ot_old_tag_from_script(hb_script_t script) {
  switch ((hb_tag_t)script) {
  case HB_SCRIPT_INVALID:
    return HB_OT_TAG_DEFAULT_SCRIPT;
  case HB_SCRIPT_HIRAGANA:
    return HB_TAG('k', 'a', 'n', 'a');
  case HB_SCRIPT_LAO:
    return HB_TAG('l', 'a', 'o', ' ');
  case HB_SCRIPT_YI:
    return HB_TAG('y', 'i', ' ', ' ');
  case HB_SCRIPT_NKO:
    return HB_TAG('n', 'k', 'o', ' ');
  case HB_SCRIPT_VAI:
    return HB_TAG('v', 'a', 'i', ' ');
  }
  return ((hb_tag_t)script) | 0x20000000u;
}

static bool_t
_xdr_kadm5_principal_ent_rec(XDR *xdrs, kadm5_principal_ent_rec *objp, int v) {
  unsigned int n;
  if (!xdr_krb5_principal(xdrs, &objp->principal)) {
    return (FALSE);
  }
  if (!xdr_krb5_timestamp(xdrs, &objp->princ_expire_time)) {
    return (FALSE);
  }
  if (!xdr_krb5_timestamp(xdrs, &objp->last_pwd_change)) {
    return (FALSE);
  }
  if (!xdr_krb5_timestamp(xdrs, &objp->pw_expiration)) {
    return (FALSE);
  }
  if (!xdr_krb5_deltat(xdrs, &objp->max_life)) {
    return (FALSE);
  }
  if (!xdr_nulltype(xdrs, (void **)&objp->mod_name, xdr_krb5_principal)) {
    return (FALSE);
  }
  if (!xdr_krb5_timestamp(xdrs, &objp->mod_date)) {
    return (FALSE);
  }
  if (!xdr_krb5_flags(xdrs, &objp->attributes)) {
    return (FALSE);
  }
  if (!xdr_krb5_kvno(xdrs, &objp->kvno)) {
    return (FALSE);
  }
  if (!xdr_krb5_kvno(xdrs, &objp->mkvno)) {
    return (FALSE);
  }
  if (!xdr_nullstring(xdrs, &objp->policy)) {
    return (FALSE);
  }
  if (!xdr_long(xdrs, &objp->aux_attributes)) {
    return (FALSE);
  }
  if (!xdr_krb5_deltat(xdrs, &objp->max_renewable_life)) {
    return (FALSE);
  }
  if (!xdr_krb5_timestamp(xdrs, &objp->last_success)) {
    return (FALSE);
  }
  if (!xdr_krb5_timestamp(xdrs, &objp->last_failed)) {
    return (FALSE);
  }
  if (!xdr_krb5_kvno(xdrs, &objp->fail_auth_count)) {
    return (FALSE);
  }
  if (!xdr_krb5_int16(xdrs, &objp->n_key_data)) {
    return (FALSE);
  }
  if (!xdr_krb5_int16(xdrs, &objp->n_tl_data)) {
    return (FALSE);
  }
  if (!xdr_nulltype(xdrs, (void **)&objp->tl_data, xdr_krb5_tl_data)) {
    return FALSE;
  }
  n = objp->n_key_data;
  if (!xdr_array(xdrs, (caddr_t *)&objp->key_data, &n, ~0,
                 sizeof(krb5_key_data), xdr_krb5_key_data_nocontents)) {
    return (FALSE);
  }
  return (TRUE);
}

static time_t xstrpisotime(const char *s, char **endptr) {
  struct tm tm;
  time_t res = (time_t)-1;
  memset(&tm, 0, sizeof(tm));
  while (*s == ' ' || *s == '\t')
    ++s;
  if ((tm.tm_year = strtoi_lim(s, &s, 1583, 4095)) < 0 || *s++ != '-') {
    goto out;
  }
  if ((tm.tm_mon = strtoi_lim(s, &s, 1, 12)) < 0 || *s++ != '-') {
    goto out;
  }
  if ((tm.tm_mday = strtoi_lim(s, &s, 1, 31)) < 0 || *s++ != 'T') {
    goto out;
  }
  if ((tm.tm_hour = strtoi_lim(s, &s, 0, 23)) < 0 || *s++ != ':') {
    goto out;
  }
  if ((tm.tm_min = strtoi_lim(s, &s, 0, 59)) < 0 || *s++ != ':') {
    goto out;
  }
  if ((tm.tm_sec = strtoi_lim(s, &s, 0, 60)) < 0 || *s++ != 'Z') {
    goto out;
  }
  tm.tm_year -= 1900;
  tm.tm_mon--;
  res = time_from_tm(&tm);
out:
  if (endptr != NULL) {
    *endptr = deconst(s);
  }
  return res;
}

static char *strippath(const char *fullfile) {
  char *filename;
  char *base;
  filename = strdup(fullfile);
  if (!filename)
    return NULL;
  base = strdup(basename(filename));
  free(filename);
  return base;
}

