    case SIGCOMP_INSTR_MULTILOAD:
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_address, udvm_tvb,
                          start_offset, len, value);
      offset = dissect_udvm_literal_operand(udvm_tvb, sigcomp_udvm_tree, offset,
                                            &start_offset, &value);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_literal_num, udvm_tvb,
