      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_ret_pri, udvm_tvb,
                          start_offset, len, value);
      break;
    case SIGCOMP_INSTR_STATE_FREE:
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_partial_identifier_start,
                          udvm_tvb, start_offset, len, value);
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_partial_identifier_length,
                          udvm_tvb, start_offset, len, value);
      break;
    case SIGCOMP_INSTR_OUTPUT:
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      if (is_memory_address) {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_addr_output_start,
                            udvm_tvb, start_offset, len, value);
      } else {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_output_start, udvm_tvb,
                            start_offset, len, value);
      }
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      if (is_memory_address) {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_output_length_addr,
                            udvm_tvb, start_offset, len, value);
      } else {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_output_length, udvm_tvb,
                            start_offset, len, value);
      }
      break;
    case SIGCOMP_INSTR_END_MESSAGE:
      if ((msg_length - 1) < offset) {
        proto_tree_add_expert(sigcomp_udvm_tree, pinfo,
                              &ei_sigcomp_all_remaining_parameters_zero,
                              udvm_tvb, 0, -1);
        return;
      }
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_req_feedback_loc, udvm_tvb,
                          start_offset, len, value);
      if ((msg_length - 1) < offset) {
        proto_tree_add_expert(sigcomp_udvm_tree, pinfo,
                              &ei_sigcomp_all_remaining_parameters_zero,
                              udvm_tvb, offset - 1, -1);
        return;
      }
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_ret_param_loc, udvm_tvb,
                          start_offset, len, value);
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      if (is_memory_address) {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_length_addr,
                            udvm_tvb, start_offset, len, value);
      } else {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_length, udvm_tvb,
                            start_offset, len, value);
      }
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      if (is_memory_address) {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_address_addr,
                            udvm_tvb, start_offset, len, value);
      } else {
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_address, udvm_tvb,
                            start_offset, len, value);
      }
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_instr, udvm_tvb,
                          start_offset, len, value);
      offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                              offset, TRUE, &start_offset,
                                              &value, &is_memory_address);
      len = offset - start_offset;
      proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_min_acc_len, udvm_tvb,
                          start_offset, len, value);
      if (tvb_reported_length_remaining(udvm_tvb, offset) != 0) {
        offset = dissect_udvm_multitype_operand(udvm_tvb, sigcomp_udvm_tree,
                                                offset, TRUE, &start_offset,
                                                &value, &is_memory_address);
        len = offset - start_offset;
        proto_tree_add_uint(sigcomp_udvm_tree, hf_udvm_state_ret_pri, udvm_tvb,
                            start_offset, len, value);
      } else {
        item2 = proto_tree_add_uint_format_value(
            sigcomp_udvm_tree, hf_udvm_state_ret_pri, udvm_tvb, offset, 1, 0,
            "0 (Not in the uploaded code as UDVM buffer initialized to Zero");
        PROTO_ITEM_SET_GENERATED(item2);
      }
      if (tvb_reported_length_remaining(udvm_tvb, offset) != 0) {
        len = tvb_reported_length_remaining(udvm_tvb, offset);
        UDVM_address = start_address + offset;
        proto_tree_add_bytes_format(sigcomp_udvm_tree,
                                    hf_sigcomp_remaining_bytes, udvm_tvb,
                                    offset, len, NULL,
                                    "Remaining %u bytes starting at UDVM addr "
                                    "%u (0x%x)- State information ?",
                                    len, UDVM_address, UDVM_address);
      }
      offset = offset + tvb_reported_length_remaining(udvm_tvb, offset);
      break;
    default:
      offset = offset + tvb_reported_length_remaining(udvm_tvb, offset);
      break;
    }
  }
  return;
}

static int dissect_mswsp_smb2(tvbuff_t *tvb, packet_info *pinfo,
                              proto_tree *tree, void *data) {
  smb2_info_t *si = (smb2_info_t *)data;
  gboolean in;
  char *fid_name = NULL;
  guint32 open_frame = 0, close_frame = 0;
  if (!si) {
    return 0;
  }
  if (si->saved) {
    dcerpc_fetch_polhnd_data(&si->saved->policy_hnd, &fid_name, NULL,
                             &open_frame, &close_frame, pinfo->num);
  }
  if (!fid_name || strcmp(fid_name, "File: MsFteWds") != 0) {
    return 0;
  }
  in = !(si->flags & SMB2_FLAGS_RESPONSE);
  p_add_proto_data(wmem_file_scope(), pinfo, proto_mswsp, 0, (void *)&SMB2);
  return dissect_mswsp(tvb, pinfo, tree, in, data);
}

static Datum ExecEvalCoalesce(CoalesceExprState *coalesceExpr,
                              ExprContext *econtext, bool *isNull,
                              ExprDoneCond *isDone) {
  ListCell *arg;
  if (isDone)
    *isDone = ExprSingleResult;
  foreach (arg, coalesceExpr->args) {
    ExprState *e = (ExprState *)lfirst(arg);
    Datum value;
    value = ExecEvalExpr(e, econtext, isNull, NULL);
    if (!*isNull)
      return value;
  }
  *isNull = true;
  return (Datum)0;
}

