static FT_Error parse_dict(T1_Face face, T1_Loader loader, FT_Byte *base,
                           FT_Long size) {
  T1_Parser parser = &loader->parser;
  FT_Byte *limit, *start_binary = NULL;
  FT_Bool have_integer = 0;
  parser->root.cursor = base;
  parser->root.limit = base + size;
  parser->root.error = FT_Err_Ok;
  limit = parser->root.limit;
  T1_Skip_Spaces(parser);
  while (parser->root.cursor < limit) {
    FT_Byte *cur;
    cur = parser->root.cursor;
    if (IS_PS_TOKEN(cur, limit, "eexec"))
      break;
    else if (IS_PS_TOKEN(cur, limit, "closefile"))
      break;
    else if (IS_PS_TOKEN(cur, limit, "FontDirectory")) {
      if (loader->keywords_encountered & T1_PRIVATE)
        loader->keywords_encountered |= T1_FONTDIR_AFTER_PRIVATE;
      parser->root.cursor += 13;
    } else if (ft_isdigit(*cur)) {
      start_binary = cur;
      T1_Skip_PS_Token(parser);
      if (parser->root.error)
        goto Exit;
      have_integer = 1;
    } else if (*cur == 'R' && cur + 6 < limit && *(cur + 1) == 'D' &&
               have_integer) {
      FT_Long s;
      FT_Byte *b;
      parser->root.cursor = start_binary;
      if (!read_binary_data(parser, &s, &b, IS_INCREMENTAL))
        return FT_THROW(Invalid_File_Format);
      have_integer = 0;
    } else if (*cur == '-' && cur + 6 < limit && *(cur + 1) == '|' &&
               have_integer) {
      FT_Long s;
      FT_Byte *b;
      parser->root.cursor = start_binary;
      if (!read_binary_data(parser, &s, &b, IS_INCREMENTAL))
        return FT_THROW(Invalid_File_Format);
      have_integer = 0;
    } else if (*cur == '/' && cur + 2 < limit) {
      FT_PtrDist len;
      cur++;
      parser->root.cursor = cur;
      T1_Skip_PS_Token(parser);
      if (parser->root.error)
        goto Exit;
      len = parser->root.cursor - cur;
      if (len > 0 && len < 22 && parser->root.cursor < limit) {
        T1_Field keyword = (T1_Field)t1_keywords;
        for (;;) {
          FT_Byte *name;
          name = (FT_Byte *)keyword->ident;
          if (!name)
            break;
          if (cur[0] == name[0] &&
              len == (FT_PtrDist)ft_strlen((const char *)name) &&
              ft_memcmp(cur, name, len) == 0) {
            const FT_UInt dict = (loader->keywords_encountered & T1_PRIVATE)
                                     ? T1_FIELD_DICT_PRIVATE
                                     : T1_FIELD_DICT_FONTDICT;
            if (!(dict & keyword->dict)) {
              FT_TRACE1(("parse_dict: found `%s' but ignoring it"
                         " since it is in the wrong dictionary\n",
                         keyword->ident));
              break;
            }
            if (!(loader->keywords_encountered & T1_FONTDIR_AFTER_PRIVATE) ||
                ft_strcmp((const char *)name, "CharStrings") == 0) {
              parser->root.error = t1_load_keyword(face, loader, keyword);
              if (parser->root.error != FT_Err_Ok) {
                if (FT_ERR_EQ(parser->root.error, Ignore))
                  parser->root.error = FT_Err_Ok;
                else
                  return parser->root.error;
              }
            }
            break;
          }
          keyword++;
        }
      }
      have_integer = 0;
    } else {
      T1_Skip_PS_Token(parser);
      if (parser->root.error)
        goto Exit;
      have_integer = 0;
    }
    T1_Skip_Spaces(parser);
  }
Exit:
  return parser->root.error;
}

