  for (i = 0; i < smp_cpus; i++) {
    cpu = cpu_ppc_init(cpu_model);
    if (cpu == NULL) {
      fprintf(stderr, "Unable to find PowerPC CPU definition\n");
      exit(1);
    }
    env = &cpu->env;
    if (env->flags & POWERPC_FLAG_RTC_CLK) {
      cpu_ppc_tb_init(env, 7812500UL);
    } else {
      cpu_ppc_tb_init(env, 100UL * 1000UL * 1000UL);
    }
    qemu_register_reset(ppc_prep_reset, cpu);
  }
  memory_region_init_ram(ram, NULL, "ppc_prep.ram", ram_size);
  vmstate_register_ram_global(ram);
  memory_region_add_subregion(sysmem, 0, ram);
  memory_region_init_ram(bios, NULL, "ppc_prep.bios", BIOS_SIZE);
  memory_region_set_readonly(bios, true);
  memory_region_add_subregion(sysmem, (uint32_t)(-BIOS_SIZE), bios);
  vmstate_register_ram_global(bios);
  if (bios_name == NULL)
    bios_name = BIOS_FILENAME;
  filename = qemu_find_file(QEMU_FILE_TYPE_BIOS, bios_name);
  if (filename) {
    bios_size =
        load_elf(filename, NULL, NULL, NULL, NULL, NULL, 1, ELF_MACHINE, 0);
    if (bios_size < 0) {
      bios_size = get_image_size(filename);
      if (bios_size > 0 && bios_size <= BIOS_SIZE) {
        hwaddr bios_addr;
        bios_size = (bios_size + 0xfff) & ~0xfff;
        bios_addr = (uint32_t)(-bios_size);
        bios_size = load_image_targphys(filename, bios_addr, bios_size);
      }
      if (bios_size > BIOS_SIZE) {
        fprintf(stderr, "qemu: PReP bios '%s' is too large (0x%x)\n", bios_name,
                bios_size);
        exit(1);
      }
    }
  } else {
    bios_size = -1;
  }
  if (bios_size < 0 && !qtest_enabled()) {
    fprintf(stderr, "qemu: could not load PPC PReP bios '%s'\n", bios_name);
    exit(1);
  }
  if (filename) {
    g_free(filename);
  }
  if (linux_boot) {
    kernel_base = KERNEL_LOAD_ADDR;
    kernel_size = load_image_targphys(kernel_filename, kernel_base,
                                      ram_size - kernel_base);
    if (kernel_size < 0) {
      hw_error("qemu: could not load kernel '%s'\n", kernel_filename);
      exit(1);
    }
    if (initrd_filename) {
      initrd_base = INITRD_LOAD_ADDR;
      initrd_size = load_image_targphys(initrd_filename, initrd_base,
                                        ram_size - initrd_base);
      if (initrd_size < 0) {
        hw_error("qemu: could not load initial ram disk '%s'\n",
                 initrd_filename);
      }
    } else {
      initrd_base = 0;
      initrd_size = 0;
    }
    ppc_boot_device = 'm';
  } else {
    kernel_base = 0;
    kernel_size = 0;
    initrd_base = 0;
    initrd_size = 0;
    ppc_boot_device = '\0';
    for (i = 0; boot_device[i] != '\0'; i++) {
      if (boot_device[i] >= 'a' && boot_device[i] <= 'f') {
        ppc_boot_device = boot_device[i];
        break;
      }
    }
    if (ppc_boot_device == '\0') {
      fprintf(stderr, "No valid boot device for Mac99 machine\n");
      exit(1);
    }
  }
  if (PPC_INPUT(env) != PPC_FLAGS_INPUT_6xx) {
    hw_error("Only 6xx bus is supported on PREP machine\n");
  }
  dev = qdev_create(NULL, "raven-pcihost");
  pcihost = PCI_HOST_BRIDGE(dev);
  object_property_add_child(qdev_get_machine(), "raven", OBJECT(dev), NULL);
  qdev_init_nofail(dev);
  pci_bus = (PCIBus *)qdev_get_child_bus(dev, "pci.0");
  if (pci_bus == NULL) {
    fprintf(stderr, "Couldn't create PCI host controller.\n");
    exit(1);
  }
  pci = pci_create_simple(pci_bus, PCI_DEVFN(1, 0), "i82378");
  cpu_exit_irq = qemu_allocate_irqs(cpu_request_exit, NULL, 1);
  qdev_connect_gpio_out(&pci->qdev, 0, first_cpu->irq_inputs[PPC6xx_INPUT_INT]);
  qdev_connect_gpio_out(&pci->qdev, 1, *cpu_exit_irq);
  sysbus_connect_irq(&pcihost->busdev, 0, qdev_get_gpio_in(&pci->qdev, 9));
  sysbus_connect_irq(&pcihost->busdev, 1, qdev_get_gpio_in(&pci->qdev, 11));
  sysbus_connect_irq(&pcihost->busdev, 2, qdev_get_gpio_in(&pci->qdev, 9));
  sysbus_connect_irq(&pcihost->busdev, 3, qdev_get_gpio_in(&pci->qdev, 11));
  isa_bus = ISA_BUS(qdev_get_child_bus(DEVICE(pci), "isa.0"));
  isa = isa_create(isa_bus, TYPE_PC87312);
  dev = DEVICE(isa);
  qdev_prop_set_uint8(dev, "config", 13);
  qdev_init_nofail(dev);
  memory_region_init_io(PPC_io_memory, NULL, &PPC_prep_io_ops, sysctrl,
                        "ppc-io", 0x00800000);
  memory_region_add_subregion(sysmem, 0x80000000, PPC_io_memory);
  pci_vga_init(pci_bus);
  nb_nics1 = nb_nics;
  if (nb_nics1 > NE2000_NB_MAX)
    nb_nics1 = NE2000_NB_MAX;
  for (i = 0; i < nb_nics1; i++) {
    if (nd_table[i].model == NULL) {
      nd_table[i].model = g_strdup("ne2k_isa");
    }
    if (strcmp(nd_table[i].model, "ne2k_isa") == 0) {
      isa_ne2000_init(isa_bus, ne2000_io[i], ne2000_irq[i], &nd_table[i]);
    } else {
      pci_nic_init_nofail(&nd_table[i], pci_bus, "ne2k_pci", NULL);
    }
  }
  ide_drive_get(hd, MAX_IDE_BUS);
  for (i = 0; i < MAX_IDE_BUS; i++) {
    isa_ide_init(isa_bus, ide_iobase[i], ide_iobase2[i], ide_irq[i], hd[2 * i],
                 hd[2 * i + 1]);
  }
  isa_create_simple(isa_bus, "i8042");
  sysctrl->reset_irq = first_cpu->irq_inputs[PPC6xx_INPUT_HRESET];
  portio_list_init(port_list, NULL, prep_portio_list, sysctrl, "prep");
  portio_list_add(port_list, get_system_io(), 0x0);
#if 0 memory_region_init_io(xcsr, NULL, &PPC_XCSR_ops, NULL, "ppc-xcsr",       \
                            0x1000);
 memory_region_add_subregion ( sysmem , 0xFEFF0000 , xcsr ) ;
#endif if (usb_enabled(false)) {
  pci_create_simple(pci_bus, -1, "pci-ohci");
}
m48t59 = m48t59_init_isa(isa_bus, 0x0074, NVRAM_SIZE, 59);
if (m48t59 == NULL)
  return;
sysctrl->nvram = m48t59;
nvram.opaque = m48t59;
nvram.read_fn = &m48t59_read;
nvram.write_fn = &m48t59_write;
PPC_NVRAM_set_params(&nvram, NVRAM_SIZE, "PREP", ram_size, ppc_boot_device,
                     kernel_base, kernel_size, kernel_cmdline, initrd_base,
                     initrd_size, 0, graphic_width, graphic_height,
                     graphic_depth);
}

