    printformat(server, NULL, MSGLEVEL_CLIENTERROR, TXT_CANT_CONNECT,
                server->connrec->address, server->connrec->port, msg);
  }
}

static gint dissect_u3v_descriptors(tvbuff_t *tvb, packet_info *pinfo _U_,
                                    proto_tree *tree, void *data _U_) {
  guint8 type;
  gint offset = 0;
  proto_item *ti;
  proto_tree *sub_tree;
  guint32 version;
  if (tvb_reported_length(tvb) < 2) {
    return 0;
  }
  type = tvb_get_guint8(tvb, 1);
  if (type != DESCRIPTOR_TYPE_U3V_INTERFACE) {
    return 0;
  }
  ti = proto_tree_add_item(tree, hf_u3v_device_info_descriptor, tvb, offset, -1,
                           ENC_NA);
  tree = proto_item_add_subtree(ti, ett_u3v_device_info_descriptor);
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_bLength, tvb, offset,
                      1, ENC_LITTLE_ENDIAN);
  offset++;
  ti = proto_tree_add_item(tree, hf_u3v_device_info_descriptor_bDescriptorType,
                           tvb, offset, 1, ENC_LITTLE_ENDIAN);
  proto_item_append_text(ti, " (U3V INTERFACE)");
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_bDescriptorSubtype,
                      tvb, offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  if (!tvb_bytes_exist(tvb, offset, 4)) {
    return offset;
  }
  version = tvb_get_letohl(tvb, offset);
  ti = proto_tree_add_item(tree, hf_u3v_device_info_descriptor_bGenCPVersion,
                           tvb, offset, 4, ENC_NA);
  proto_item_append_text(ti, ": %u.%u", version >> 16, version & 0xFFFF);
  sub_tree =
      proto_item_add_subtree(ti, ett_u3v_device_info_descriptor_gencp_version);
  proto_tree_add_item(sub_tree,
                      hf_u3v_device_info_descriptor_bGenCPVersion_minor, tvb,
                      offset, 4, ENC_LITTLE_ENDIAN);
  proto_tree_add_item(sub_tree,
                      hf_u3v_device_info_descriptor_bGenCPVersion_major, tvb,
                      offset, 4, ENC_LITTLE_ENDIAN);
  offset += 4;
  if (!tvb_bytes_exist(tvb, offset, 4)) {
    return offset;
  }
  version = tvb_get_letohl(tvb, offset);
  ti = proto_tree_add_item(tree, hf_u3v_device_info_descriptor_bU3VVersion, tvb,
                           offset, 4, ENC_NA);
  proto_item_append_text(ti, ": %u.%u", version >> 16, version & 0xFFFF);
  sub_tree =
      proto_item_add_subtree(ti, ett_u3v_device_info_descriptor_u3v_version);
  proto_tree_add_item(sub_tree, hf_u3v_device_info_descriptor_bU3VVersion_minor,
                      tvb, offset, 4, ENC_LITTLE_ENDIAN);
  proto_tree_add_item(sub_tree, hf_u3v_device_info_descriptor_bU3VVersion_major,
                      tvb, offset, 4, ENC_LITTLE_ENDIAN);
  offset += 4;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iDeviceGUID, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iVendorName, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iModelName, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iFamilyName, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iDeviceVersion, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iManufacturerInfo,
                      tvb, offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iSerialNumber, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_item(tree, hf_u3v_device_info_descriptor_iUserDefinedName, tvb,
                      offset, 1, ENC_LITTLE_ENDIAN);
  offset++;
  proto_tree_add_bitmask(tree, tvb, offset,
                         hf_u3v_device_info_descriptor_bmSpeedSupport,
                         ett_u3v_device_info_descriptor_speed_support,
                         speed_support_fields, ENC_LITTLE_ENDIAN);
  offset++;
  return offset;
}

static int dissect_nlm_test_res(tvbuff_t *tvb, int offset,
                                packet_info *pinfo _U_, proto_tree *tree,
                                int version, rpc_call_info_value *rpc_call) {
  proto_item *lock_item = NULL;
  proto_tree *lock_tree = NULL;
  if (nlm_match_msgres) {
    if (rpc_call->proc == 11) {
      if ((!pinfo->fd->flags.visited)) {
        nlm_register_unmatched_res(pinfo, tvb, offset);
      } else {
        nlm_print_msgres_reply(pinfo, tree, tvb);
      }
      if (nfs_fhandle_reqrep_matching) {
        nlm_match_fhandle_reply(pinfo, tree);
      }
    }
  }
  offset = dissect_rpc_data(tvb, tree, hf_nlm_cookie, offset);
  if (tree) {
    lock_item =
        proto_tree_add_item(tree, hf_nlm_test_stat, tvb, offset, -1, ENC_NA);
    lock_tree = proto_item_add_subtree(lock_item, ett_nlm_lock);
  }
  offset = dissect_rpc_uint32(tvb, lock_tree, hf_nlm_test_stat_stat, offset);
  if (tvb_reported_length_remaining(tvb, offset) == 0) {
    return offset;
  }
  if (tree) {
    lock_item =
        proto_tree_add_item(lock_tree, hf_nlm_holder, tvb, offset, -1, ENC_NA);
    if (lock_item)
      lock_tree = proto_item_add_subtree(lock_item, ett_nlm_lock);
  }
  offset = dissect_rpc_bool(tvb, lock_tree, hf_nlm_exclusive, offset);
  offset = dissect_rpc_uint32(tvb, lock_tree, hf_nlm_lock_svid, offset);
  offset = dissect_rpc_data(tvb, lock_tree, hf_nlm_lock_owner, offset);
  if (version == 4) {
    offset = dissect_rpc_uint64(tvb, lock_tree, hf_nlm_lock_l_offset64, offset);
    offset = dissect_rpc_uint64(tvb, lock_tree, hf_nlm_lock_l_len64, offset);
  } else {
    offset = dissect_rpc_uint32(tvb, lock_tree, hf_nlm_lock_l_offset, offset);
    offset = dissect_rpc_uint32(tvb, lock_tree, hf_nlm_lock_l_len, offset);
  }
  return offset;
}

enum nss_status _nss_dns_gethostbyname4_r(const char *name,
                                          struct gaih_addrtuple **pat,
                                          char *buffer, size_t buflen,
                                          int *errnop, int *herrnop,
                                          int32_t *ttlp) {
  if (__res_maybe_init(&_res, 0) == -1)
    return NSS_STATUS_UNAVAIL;
  if (strchr(name, '.') == NULL) {
    char *tmp = alloca(NS_MAXDNAME);
    const char *cp = res_hostalias(&_res, name, tmp, NS_MAXDNAME);
    if (cp != NULL)
      name = cp;
  }
  union {
    querybuf *buf;
    u_char *ptr;
  } host_buffer;
  querybuf *orig_host_buffer;
  host_buffer.buf = orig_host_buffer = (querybuf *)alloca(2048);
  u_char *ans2p = NULL;
  int nans2p = 0;
  int resplen2 = 0;
  int ans2p_malloced = 0;
  int olderr = errno;
  enum nss_status status;
  int n = __libc_res_nsearch(&_res, name, C_IN, T_UNSPEC, host_buffer.buf->buf,
                             2048, &host_buffer.ptr, &ans2p, &nans2p, &resplen2,
                             &ans2p_malloced);
  if (n >= 0) {
    status =
        gaih_getanswer(host_buffer.buf, n, (const querybuf *)ans2p, resplen2,
                       name, pat, buffer, buflen, errnop, herrnop, ttlp);
  } else {
    switch (errno) {
    case ESRCH:
      status = NSS_STATUS_TRYAGAIN;
      h_errno = TRY_AGAIN;
      break;
    case EMFILE:
    case ENFILE:
      h_errno = NETDB_INTERNAL;
    case ECONNREFUSED:
    case ETIMEDOUT:
      status = NSS_STATUS_UNAVAIL;
      break;
    default:
      status = NSS_STATUS_NOTFOUND;
      break;
    }
    *herrnop = h_errno;
    if (h_errno == TRY_AGAIN)
      *errnop = EAGAIN;
    else
      __set_errno(olderr);
  }
  if (ans2p_malloced)
    free(ans2p);
  if (host_buffer.buf != orig_host_buffer)
    free(host_buffer.buf);
  return status;
}

void dissect_zcl_basic_attr_data(proto_tree *tree, tvbuff_t *tvb, guint *offset,
                                 guint16 attr_id, guint data_type) {
  static const int *alarm_mask[] = {&hf_zbee_zcl_basic_alarm_mask_gen_hw_fault,
                                    &hf_zbee_zcl_basic_alarm_mask_gen_sw_fault,
                                    &hf_zbee_zcl_basic_alarm_mask_reserved,
                                    NULL};
  static const int *local_cfg[] = {
      &hf_zbee_zcl_basic_disable_local_cfg_reset,
      &hf_zbee_zcl_basic_disable_local_cfg_device_cfg,
      &hf_zbee_zcl_basic_disable_local_cfg_reserved, NULL};
  switch (attr_id) {
  case ZBEE_ZCL_ATTR_ID_BASIC_POWER_SOURCE:
    proto_tree_add_item(tree, hf_zbee_zcl_basic_pwr_src, tvb, *offset, 1,
                        ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_BASIC_DEVICE_ENABLED:
    proto_tree_add_item(tree, hf_zbee_zcl_basic_dev_en, tvb, *offset, 1,
                        ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_BASIC_ALARM_MASK:
    proto_tree_add_bitmask(tree, tvb, *offset, hf_zbee_zcl_basic_alarm_mask,
                           ett_zbee_zcl_basic_alarm_mask, alarm_mask, ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_BASIC_DISABLE_LOCAL_CFG:
    proto_tree_add_bitmask(tree, tvb, *offset,
                           hf_zbee_zcl_basic_disable_local_cfg,
                           ett_zbee_zcl_basic_dis_local_cfg, local_cfg, ENC_NA);
    *offset += 1;
    break;
  case ZBEE_ZCL_ATTR_ID_BASIC_ZCL_VERSION:
  case ZBEE_ZCL_ATTR_ID_BASIC_APPL_VERSION:
  case ZBEE_ZCL_ATTR_ID_BASIC_STACK_VERSION:
  case ZBEE_ZCL_ATTR_ID_BASIC_HW_VERSION:
  case ZBEE_ZCL_ATTR_ID_BASIC_MANUFACTURER_NAME:
  case ZBEE_ZCL_ATTR_ID_BASIC_MODEL_ID:
  case ZBEE_ZCL_ATTR_ID_BASIC_DATE_CODE:
  case ZBEE_ZCL_ATTR_ID_BASIC_PHY_ENVIRONMENT:
  case ZBEE_ZCL_ATTR_ID_BASIC_LOCATION_DESCR:
  default:
    dissect_zcl_attr_data(tvb, tree, offset, data_type);
    break;
  }
}

