int av_image_fill_linesizes(int linesizes[4], enum PixelFormat pix_fmt,
                            int width) {
  int i;
  const AVPixFmtDescriptor *desc = &av_pix_fmt_descriptors[pix_fmt];
  int max_step[4];
  int max_step_comp[4];
  memset(linesizes, 0, 4 * sizeof(linesizes[0]));
  if ((unsigned)pix_fmt >= PIX_FMT_NB || desc->flags & PIX_FMT_HWACCEL)
    return AVERROR(EINVAL);
  if (desc->flags & PIX_FMT_BITSTREAM) {
    if (width > (INT_MAX - 7) / (desc->comp[0].step_minus1 + 1))
      return AVERROR(EINVAL);
    linesizes[0] = (width * (desc->comp[0].step_minus1 + 1) + 7) >> 3;
    return 0;
  }
  av_image_fill_max_pixsteps(max_step, max_step_comp, desc);
  for (i = 0; i < 4; i++) {
    int s = (max_step_comp[i] == 1 || max_step_comp[i] == 2)
                ? desc->log2_chroma_w
                : 0;
    int shifted_w = ((width + (1 << s) - 1)) >> s;
    if (max_step[i] > INT_MAX / shifted_w)
      return AVERROR(EINVAL);
    linesizes[i] = max_step[i] * shifted_w;
  }
  return 0;
}

static void _slurm_rpc_complete_prolog(slurm_msg_t *msg) {
  int error_code = SLURM_SUCCESS;
  DEF_TIMERS;
  complete_prolog_msg_t *comp_msg = (complete_prolog_msg_t *)msg->data;
  slurmctld_lock_t job_write_lock = {NO_LOCK, WRITE_LOCK, NO_LOCK, NO_LOCK,
                                     NO_LOCK};
  START_TIMER;
  debug2("Processing RPC: REQUEST_COMPLETE_PROLOG from JobId=%u",
         comp_msg->job_id);
  lock_slurmctld(job_write_lock);
  error_code = prolog_complete(comp_msg->job_id, comp_msg->prolog_rc);
  unlock_slurmctld(job_write_lock);
  END_TIMER2("_slurm_rpc_complete_prolog");
  if (error_code) {
    info("_slurm_rpc_complete_prolog JobId=%u: %s ", comp_msg->job_id,
         slurm_strerror(error_code));
    slurm_send_rc_msg(msg, error_code);
  } else {
    debug2("_slurm_rpc_complete_prolog JobId=%u %s", comp_msg->job_id,
           TIME_STR);
    slurm_send_rc_msg(msg, SLURM_SUCCESS);
  }
}

