}

static int xan_unpack(XanContext *s, uint8_t *dest, const int dest_len) {
  uint8_t opcode;
  int size;
  uint8_t *orig_dest = dest;
  const uint8_t *dest_end = dest + dest_len;
  while (dest < dest_end) {
    if (bytestream2_get_bytes_left(&s->gb) <= 0)
      return AVERROR_INVALIDDATA;
    opcode = bytestream2_get_byteu(&s->gb);
    if (opcode < 0xe0) {
      int size2, back;
      if ((opcode & 0x80) == 0) {
        size = opcode & 3;
        back = ((opcode & 0x60) << 3) + bytestream2_get_byte(&s->gb) + 1;
        size2 = ((opcode & 0x1c) >> 2) + 3;
      } else if ((opcode & 0x40) == 0) {
        size = bytestream2_peek_byte(&s->gb) >> 6;
        back = (bytestream2_get_be16(&s->gb) & 0x3fff) + 1;
        size2 = (opcode & 0x3f) + 4;
      } else {
        size = opcode & 3;
        back = ((opcode & 0x10) << 12) + bytestream2_get_be16(&s->gb) + 1;
        size2 = ((opcode & 0x0c) << 6) + bytestream2_get_byte(&s->gb) + 5;
        if (size + size2 > dest_end - dest)
          break;
      }
      if (dest + size + size2 > dest_end || dest - orig_dest + size < back)
        return AVERROR_INVALIDDATA;
      bytestream2_get_buffer(&s->gb, dest, size);
      dest += size;
      av_memcpy_backptr(dest, back, size2);
      dest += size2;
    } else {
      int finish = opcode >= 0xfc;
      size = finish ? opcode & 3 : ((opcode & 0x1f) << 2) + 4;
      if (dest_end - dest < size)
        return AVERROR_INVALIDDATA;
      bytestream2_get_buffer(&s->gb, dest, size);
      dest += size;
      if (finish)
        break;
    }
  }
  return dest - orig_dest;
}

MIMEField *mime_field_create(HdrHeap *heap, MIMEHdrImpl *mh) {
  MIMEField *field;
  MIMEFieldBlockImpl *tail_fblock, *new_fblock;
  tail_fblock = mh->m_fblock_list_tail;
  if (tail_fblock->m_freetop >= MIME_FIELD_BLOCK_SLOTS) {
    new_fblock = (MIMEFieldBlockImpl *)heap->allocate_obj(
        sizeof(MIMEFieldBlockImpl), HDR_HEAP_OBJ_FIELD_BLOCK);
    _mime_hdr_field_block_init(new_fblock);
    tail_fblock->m_next = new_fblock;
    tail_fblock = new_fblock;
    mh->m_fblock_list_tail = new_fblock;
  }
  field = &(tail_fblock->m_field_slots[tail_fblock->m_freetop]);
  ++tail_fblock->m_freetop;
  mime_field_init(field);
  return field;
}

static int find_fp_qindex(vpx_bit_depth_t bit_depth) {
