static GstFlowReturn gst_asf_demux_process_header(GstASFDemux *demux,
                                                  guint8 *data, guint64 size) {
  GstFlowReturn ret = GST_FLOW_OK;
  guint32 i, num_objects;
  guint8 unknown G_GNUC_UNUSED;
  if (size < (4 + 1 + 1))
    goto not_enough_data;
  num_objects = gst_asf_demux_get_uint32(&data, &size);
  unknown = gst_asf_demux_get_uint8(&data, &size);
  unknown = gst_asf_demux_get_uint8(&data, &size);
  GST_INFO_OBJECT(demux, "object is a header with %u parts", num_objects);
  demux->saw_file_header = FALSE;
  for (i = 0; i < num_objects; ++i) {
    GST_INFO_OBJECT(demux, "reading header part %u", i);
    ret = gst_asf_demux_process_object(demux, &data, &size);
    if (ret != GST_FLOW_OK) {
      GST_WARNING("process_object returned %s", gst_asf_get_flow_name(ret));
      break;
    }
  }
  if (!demux->saw_file_header) {
    GST_ELEMENT_ERROR(demux, STREAM, DEMUX, (NULL),
                      ("Header does not have mandatory FILE section"));
    return GST_FLOW_ERROR;
  }
  return ret;
not_enough_data : {
  GST_ELEMENT_ERROR(demux, STREAM, DEMUX, (NULL),
                    ("short read parsing HEADER object"));
  return GST_FLOW_ERROR;
}
}

static void find_enclosing_mount_callback(GObject *source_object,
                                          GAsyncResult *res,
                                          gpointer user_data) {
  GMount *mount;
  MountState *state;
  GFile *location, *root;
  state = user_data;
  if (state->directory == NULL) {
    mount_state_free(state);
    return;
  }
  mount = g_file_find_enclosing_mount_finish(G_FILE(source_object), res, NULL);
  if (mount) {
    root = g_mount_get_root(mount);
    location = nautilus_file_get_location(state->file);
    if (!g_file_equal(location, root)) {
      g_object_unref(mount);
      mount = NULL;
    }
    g_object_unref(root);
    g_object_unref(location);
  }
  got_mount(state, mount);
  if (mount) {
    g_object_unref(mount);
  }
}

static int ir2_decode_frame(AVCodecContext *avctx, void *data, int *got_frame,
                            AVPacket *avpkt) {
  Ir2Context *const s = avctx->priv_data;
  const uint8_t *buf = avpkt->data;
  int buf_size = avpkt->size;
  AVFrame *picture = data;
  AVFrame *const p = &s->picture;
  int start, ret;
  if (p->data[0])
    avctx->release_buffer(avctx, p);
  p->reference = 1;
  p->buffer_hints = FF_BUFFER_HINTS_VALID | FF_BUFFER_HINTS_PRESERVE |
                    FF_BUFFER_HINTS_REUSABLE;
  if ((ret = avctx->reget_buffer(avctx, p)) < 0) {
    av_log(s->avctx, AV_LOG_ERROR, "reget_buffer() failed\n");
    return ret;
  }
  start = 48;
  if (start >= buf_size) {
    av_log(s->avctx, AV_LOG_ERROR, "input buffer size too small (%d)\n",
           buf_size);
    return AVERROR_INVALIDDATA;
  }
  s->decode_delta = buf[18];
#ifndef BITSTREAM_READER_LE for (i = 0;
  i < buf_size;
 i ++ ) buf [ i ] = ff_reverse [ buf [ i ] ] ;
#endif init_get_bits(&s->gb, buf + start, (buf_size - start) * 8);
 if (s->decode_delta) {
   if ((ret =
            ir2_decode_plane(s, avctx->width, avctx->height, s->picture.data[0],
                             s->picture.linesize[0], ir2_luma_table)) < 0)
     return ret;
   if ((ret = ir2_decode_plane(s, avctx->width >> 2, avctx->height >> 2,
                               s->picture.data[2], s->picture.linesize[2],
                               ir2_luma_table)) < 0)
     return ret;
   if ((ret = ir2_decode_plane(s, avctx->width >> 2, avctx->height >> 2,
                               s->picture.data[1], s->picture.linesize[1],
                               ir2_luma_table)) < 0)
     return ret;
 } else {
   if ((ret = ir2_decode_plane_inter(s, avctx->width, avctx->height,
                                     s->picture.data[0], s->picture.linesize[0],
                                     ir2_luma_table)) < 0)
     return ret;
   if ((ret = ir2_decode_plane_inter(s, avctx->width >> 2, avctx->height >> 2,
                                     s->picture.data[2], s->picture.linesize[2],
                                     ir2_luma_table)) < 0)
     return ret;
   if ((ret = ir2_decode_plane_inter(s, avctx->width >> 2, avctx->height >> 2,
                                     s->picture.data[1], s->picture.linesize[1],
                                     ir2_luma_table)) < 0)
     return ret;
 }
 *picture = s->picture;
 *got_frame = 1;
 return buf_size;
}

