static int zisofs_init(struct archive_write *a, struct isofile *file) {
  struct iso9660 *iso9660 = a->format_data;
#ifdef HAVE_ZLIB_H uint64_t tsize;
  size_t _ceil, bpsize;
  int r;
#endif iso9660->zisofs.detect_magic = 0;
  iso9660->zisofs.making = 0;
  if (!iso9660->opt.rr || !iso9660->opt.zisofs)
    return (ARCHIVE_OK);
  if (archive_entry_size(file->entry) >= 24 &&
      archive_entry_size(file->entry) < MULTI_EXTENT_SIZE) {
    iso9660->zisofs.detect_magic = 1;
    iso9660->zisofs.magic_cnt = 0;
  }
  if (!iso9660->zisofs.detect_magic)
    return (ARCHIVE_OK);
#ifdef HAVE_ZLIB_H if (archive_entry_size(file->entry) <=                      \
                       LOGICAL_BLOCK_SIZE) return (ARCHIVE_OK);
  r = zisofs_init_zstream(a);
  if (r != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  file->zisofs.header_size = ZF_HEADER_SIZE >> 2;
  file->zisofs.log2_bs = ZF_LOG2_BS;
  file->zisofs.uncompressed_size = (uint32_t)archive_entry_size(file->entry);
  _ceil = (file->zisofs.uncompressed_size + ZF_BLOCK_SIZE - 1) >>
          file->zisofs.log2_bs;
  iso9660->zisofs.block_pointers_cnt = (int)_ceil + 1;
  iso9660->zisofs.block_pointers_idx = 0;
  bpsize = iso9660->zisofs.block_pointers_cnt *
           sizeof(iso9660->zisofs.block_pointers[0]);
  if (iso9660->zisofs.block_pointers_allocated < bpsize) {
    free(iso9660->zisofs.block_pointers);
    iso9660->zisofs.block_pointers = malloc(bpsize);
    if (iso9660->zisofs.block_pointers == NULL) {
      archive_set_error(&a->archive, ENOMEM, "Can't allocate data");
      return (ARCHIVE_FATAL);
    }
    iso9660->zisofs.block_pointers_allocated = bpsize;
  }
  tsize = ZF_HEADER_SIZE + bpsize;
  if (write_null(a, (size_t)tsize) != ARCHIVE_OK)
    return (ARCHIVE_FATAL);
  archive_le32enc(&(iso9660->zisofs.block_pointers[0]), (uint32_t)tsize);
  iso9660->zisofs.remaining = file->zisofs.uncompressed_size;
  iso9660->zisofs.making = 1;
  iso9660->zisofs.allzero = 1;
  iso9660->zisofs.block_offset = tsize;
  iso9660->zisofs.total_size = tsize;
  iso9660->cur_file->cur_content->size = tsize;
#endif return (ARCHIVE_OK);
}

int ff_mpeg4_set_direct_mv(MpegEncContext *s, int mx, int my) {
  const int mb_index = s->mb_x + s->mb_y * s->mb_stride;
  const int colocated_mb_type = s->next_picture.f.mb_type[mb_index];
  uint16_t time_pp;
  uint16_t time_pb;
  int i;
  if (IS_8X8(colocated_mb_type)) {
    s->mv_type = MV_TYPE_8X8;
    for (i = 0; i < 4; i++) {
      ff_mpeg4_set_one_direct_mv(s, mx, my, i);
    }
    return MB_TYPE_DIRECT2 | MB_TYPE_8x8 | MB_TYPE_L0L1;
  } else if (IS_INTERLACED(colocated_mb_type)) {
    s->mv_type = MV_TYPE_FIELD;
    for (i = 0; i < 2; i++) {
      int field_select = s->next_picture.f.ref_index[0][4 * mb_index + 2 * i];
      s->field_select[0][i] = field_select;
      s->field_select[1][i] = i;
      if (s->top_field_first) {
        time_pp = s->pp_field_time - field_select + i;
        time_pb = s->pb_field_time - field_select + i;
      } else {
        time_pp = s->pp_field_time + field_select - i;
        time_pb = s->pb_field_time + field_select - i;
      }
      s->mv[0][i][0] =
          s->p_field_mv_table[i][0][mb_index][0] * time_pb / time_pp + mx;
      s->mv[0][i][1] =
          s->p_field_mv_table[i][0][mb_index][1] * time_pb / time_pp + my;
      s->mv[1][i][0] =
          mx ? s->mv[0][i][0] - s->p_field_mv_table[i][0][mb_index][0]
             : s->p_field_mv_table[i][0][mb_index][0] * (time_pb - time_pp) /
                   time_pp;
      s->mv[1][i][1] =
          my ? s->mv[0][i][1] - s->p_field_mv_table[i][0][mb_index][1]
             : s->p_field_mv_table[i][0][mb_index][1] * (time_pb - time_pp) /
                   time_pp;
    }
    return MB_TYPE_DIRECT2 | MB_TYPE_16x8 | MB_TYPE_L0L1 | MB_TYPE_INTERLACED;
  } else {
    ff_mpeg4_set_one_direct_mv(s, mx, my, 0);
    s->mv[0][1][0] = s->mv[0][2][0] = s->mv[0][3][0] = s->mv[0][0][0];
    s->mv[0][1][1] = s->mv[0][2][1] = s->mv[0][3][1] = s->mv[0][0][1];
    s->mv[1][1][0] = s->mv[1][2][0] = s->mv[1][3][0] = s->mv[1][0][0];
    s->mv[1][1][1] = s->mv[1][2][1] = s->mv[1][3][1] = s->mv[1][0][1];
    if ((s->avctx->workaround_bugs & FF_BUG_DIRECT_BLOCKSIZE) ||
        !s->quarter_sample)
      s->mv_type = MV_TYPE_16X16;
    else
      s->mv_type = MV_TYPE_8X8;
    return MB_TYPE_DIRECT2 | MB_TYPE_16x16 | MB_TYPE_L0L1;
  }
}

static int checkday(const char *check, size_t len) {
